# child (nat_ip), e.g. a host behind 1:1 NAT whose primary NIC carries a private
# address but is reachable from outside on the NAT IP.
_CMDB_IFACE_RE      = re.compile(r'^[A-Za-z0-9._:\-]{0,32}$')

