def _config():
    """Load config with merged defaults — call when you need a current value."""
    cfg = load(CONFIG_FILE)
    return cfg


def get_online_ttl():
    """Effective online TTL value, clamped to MIN_ONLINE_TTL."""
    try:
        v = int(_config().get('online_ttl', DEFAULT_ONLINE_TTL))
    except (TypeError, ValueError):
        v = DEFAULT_ONLINE_TTL
    return max(MIN_ONLINE_TTL, v)


def _agentless_online(dev):
    """Online state for an agentless device (no heartbeat).

    v3.3.4: agentless devices default to an ICMP reachability check —
    `reachable` is set by run_agentless_reachability_if_due. The 'manual'
    mode keeps the operator-set `manual_status` (for hosts that block
    ping). Both default to up so a freshly-added device isn't shown down
    before its first probe.
    """
    if dev.get('reachability', 'icmp') == 'manual':
        return bool(dev.get('manual_status', True))
    return bool(dev.get('reachable', True))


# v3.3.4: agentless ICMP reachability sweep tuning.
AGENTLESS_PING_INTERVAL = 60          # seconds between sweeps
AGENTLESS_PING_FAIL_THRESHOLD = 2     # consecutive fails before OFFLINE (debounce)


def _icmp_socket_ping(host, timeout=2):
    """One ICMP echo via an UNPRIVILEGED datagram socket — no ping binary, no
    CAP_NET_RAW (allowed by net.ipv4.ping_group_range, which systemd defaults
    wide since v247, incl. Debian 12 / Ubuntu 22.04+ / inside Docker).

    Returns True (reply), False (no reply / no route / no resolution), or
    None when the MECHANISM is unavailable (kernel forbids the socket) so the
    caller can distinguish "host is down" from "can't probe from here"."""
    host = str(host or '').strip()
    if not host:
        return False
    try:
        infos = socket.getaddrinfo(host, None, proto=socket.IPPROTO_UDP)
    except OSError:
        return False                      # unresolvable → effectively down
    info = next((i for i in infos if i[0] == socket.AF_INET), None) or \
           next((i for i in infos if i[0] == socket.AF_INET6), None)
    if info is None:
        return False
    fam = info[0]
    addr = info[4]
    v6 = fam == socket.AF_INET6
    proto = socket.IPPROTO_ICMPV6 if v6 else socket.IPPROTO_ICMP
    # Echo request: type/code/checksum/id/seq + payload. The kernel rewrites
    # the id on dgram-icmp sockets (that's how replies are demuxed back to
    # this socket) and computes the ICMPv6 checksum; the v4 checksum we
    # compute ourselves.
    import struct
    payload = b'remotepower-reach'
    pkt = struct.pack('!BBHHH', 128 if v6 else 8, 0, 0, 0, 1) + payload
    if not v6:
        s = 0
        buf = pkt if len(pkt) % 2 == 0 else pkt + b'\x00'
        for i in range(0, len(buf), 2):
            s += (buf[i] << 8) + buf[i + 1]
            s = (s & 0xFFFF) + (s >> 16)
        pkt = pkt[:2] + struct.pack('!H', ~s & 0xFFFF) + pkt[4:]
    try:
        sock = socket.socket(fam, socket.SOCK_DGRAM, proto)
    except (PermissionError, OSError):
        return None                       # ping_group_range forbids → N/A
    try:
        sock.settimeout(max(0.2, float(timeout)))
        sock.connect(addr[:2] if not v6 else addr)
        sock.send(pkt)
        while True:
            data = sock.recv(2048)
            if data and data[0] == (129 if v6 else 0):   # echo reply
                return True
    except socket.timeout:
        return False
    except OSError:
        return False
    finally:
        sock.close()


def _tcp_reach_ping(host, timeout=2, ports=(443, 80, 22)):
    """Zero-privilege reachability of last resort: a TCP connect that either
    SUCCEEDS or is REFUSED (RST) proves the host is up — only timeouts and
    unreachable-network errors count as down. Used only when neither the ping
    binary nor the unprivileged ICMP socket is available (e.g. a container
    without iputils and with a restricted ping_group_range)."""
    per_port = max(0.3, min(1.0, float(timeout) / max(1, len(ports))))
    for port in ports:
        try:
            with socket.create_connection((str(host), port), timeout=per_port):
                return True
        except ConnectionRefusedError:
            return True                   # RST — somebody answered
        except OSError:
            continue
    return False


_PING_FALLBACK_LOGGED = False


def _ping_host(host, timeout=2):
    """True if `host` answers a reachability probe. Tiered (v5.8.0, issue #20):

    1. the system `ping` binary — argv only (`--` guards against a hostname
       that looks like a flag), no shell;
    2. an unprivileged ICMP datagram socket — covers installs WITHOUT
       iputils-ping (the stock Docker image, minimal Debian) or where
       NoNewPrivileges blocks ping's caps;
    3. a TCP connect probe (success OR refused = up) — only when no ICMP
       mechanism exists at all, so a working install keeps pure-ICMP
       semantics.

    Before the fallbacks existed, a missing/blocked ping binary made every
    ICMP-mode agentless device flip offline forever ~2 sweeps after being
    added — while the netscan that found them worked fine."""
    if not host:
        return False
    icmp_ran = False
    try:
        r = subprocess.run(
            ['ping', '-c', '1', '-W', str(int(timeout)), '--', str(host)],
            capture_output=True, timeout=timeout + 3)
        if r.returncode == 0:
            return True
        if r.returncode == 1:
            icmp_ran = True               # probe worked; host didn't answer
    except Exception:
        pass
    res = _icmp_socket_ping(host, timeout)
    if res is True:
        return True
    if res is False:
        icmp_ran = True
    if icmp_ran:
        return False                      # a real ICMP probe said down
    global _PING_FALLBACK_LOGGED
    if not _PING_FALLBACK_LOGGED:
        _PING_FALLBACK_LOGGED = True
        sys.stderr.write(
            '[remotepower] no ICMP mechanism available (ping binary missing/blocked '
            'and unprivileged ICMP sockets forbidden) — agentless reachability '
            'falling back to TCP probes; install iputils-ping for real ICMP\n')
    return _tcp_reach_ping(host, timeout)


def run_agentless_reachability_if_due():
    """Ping every ICMP-mode agentless device once per AGENTLESS_PING_INTERVAL
    and flip its `reachable` bit, firing device_offline / device_online on
    the edge (debounced by AGENTLESS_PING_FAIL_THRESHOLD consecutive fails).

    Same cheap-when-not-due pattern as run_snmp_polls_if_due; marker in
    CONFIG_FILE under `last_agentless_ping`. check_offline_webhooks skips
    agentless devices, so this is the only place agentless up/down is
    decided — no double-firing.
    """
    _ro = _config_ro()   # v5.8.0 (PERF): no-deepcopy not-due gate
    now = int(time.time())
    last = int(_ro.get('last_agentless_ping', 0))
    interval = max(30, int(_ro.get('agentless_ping_interval', AGENTLESS_PING_INTERVAL)))
    if (now - last) < interval:
        return
    devs = load(DEVICES_FILE)
    targets = [did for did, d in devs.items()
               if d.get('agentless') and d.get('reachability', 'icmp') != 'manual'
               and (d.get('ip') or d.get('hostname') or d.get('host'))]
    if not targets:
        return
    cfg = load(CONFIG_FILE)
    cfg['last_agentless_ping'] = now
    save(CONFIG_FILE, cfg)

    transitions = []   # (dev_id, name, online_bool) → fire webhook after the lock
    states = []        # (dev_id, name, online_bool) for EVERY probed device
    with _LockedUpdate(DEVICES_FILE) as store:
        for dev_id in targets:
            dev = store.get(dev_id)
            if not dev:
                continue
            host = dev.get('ip') or dev.get('hostname') or dev.get('host')
            was_reachable = bool(dev.get('reachable', True))
            if _ping_host(host):
                dev['reachable'] = True
                dev['reach_fails'] = 0
                dev['last_seen'] = now            # so "last seen" reflects the probe
                if not was_reachable:
                    transitions.append((dev_id, dev.get('name', dev_id), True))
            else:
                fails = int(dev.get('reach_fails', 0)) + 1
                dev['reach_fails'] = fails
                if was_reachable and fails >= AGENTLESS_PING_FAIL_THRESHOLD:
                    dev['reachable'] = False
                    transitions.append((dev_id, dev.get('name', dev_id), False))
            states.append((dev_id, dev.get('name', dev_id), bool(dev.get('reachable', True))))

    # Record the current state for every probed device — not just transitions —
    # so an agentless / SNMP host that's been continuously reachable still gets a
    # baseline uptime event and shows real history in the 7-day roster stripe
    # (instead of being absent and rendering as all-"unknown"). _record_uptime
    # de-dupes: it only writes when the state actually changes.
    for dev_id, name, online in states:
        try:
            _record_uptime(dev_id, name, online)
        except Exception:
            pass

    for dev_id, name, online in transitions:
        d = device_get(dev_id) or {}   # v4.6.0: O(1) single-row (was a full-store reload per transition)
        if not d.get('monitored', True):
            continue            # unmonitored: track status, stay silent
        event = 'device_online' if online else 'device_offline'
        try:
            fire_webhook(event, {'device_id': dev_id, 'device_name': name, 'name': name})
        except Exception as e:
            sys.stderr.write(f'[remotepower] agentless {event} fire failed {dev_id}: {e}\n')


ROUTEROS_UPDATE_INTERVAL = 12 * 3600   # how often to re-check RouterOS firmware


def run_routeros_update_check_if_due():
    """v3.3.4: periodically refresh RouterOS firmware-update state for
    routeros-enabled devices, so the Patches page shows it without a live
    fetch. Cheap-when-not-due; bounded per run. check-for-updates is safe
    (no reboot)."""
    _ro = _config_ro()   # v5.8.0 (PERF): no-deepcopy not-due gate
    now = int(time.time())
    last = int(_ro.get('last_routeros_update_check', 0))
    interval = max(3600, int(_ro.get('routeros_update_interval', ROUTEROS_UPDATE_INTERVAL)))
    if (now - last) < interval:
        return
    devs = load(DEVICES_FILE)
    targets = [(did, d) for did, d in devs.items()
               if (d.get('routeros') or {}).get('enabled')]
    if not targets:
        return
    cfg = load(CONFIG_FILE)
    cfg['last_routeros_update_check'] = now
    save(CONFIG_FILE, cfg)
    import routeros as routeros_mod
    results = {}   # dev_id -> update dict
    started = time.time()
    for dev_id, dev in targets[:25]:
        if (time.time() - started) > 25:
            break
        tgt = _routeros_target(dev)
        if not tgt:
            continue
        host, user, password, verify = tgt
        try:
            res = routeros_mod.action(host, user, password, 'check_update', verify=verify)
            if isinstance(res, dict) and res.get('update'):
                results[dev_id] = {**res['update'], 'last_checked': now}
        except Exception as e:
            sys.stderr.write(f'[remotepower] routeros update check failed {dev_id}: {e}\n')
    if results:
        with _LockedUpdate(DEVICES_FILE) as store:
            for dev_id, upd in results.items():
                d = store.get(dev_id)
                if d is not None:
                    d['routeros_update'] = upd


def _offline_thresholds(dev, ttl):
    """Per-device OFFLINE tuning used by check_offline_webhooks.

    Returns (offline_after_s, debounce_s):

      offline_after_s — silence beyond this makes the device a *candidate*
        for OFFLINE. It is the larger of the operator's global online TTL
        and OFFLINE_MISSED_POLLS of the device's own poll interval, plus a
        fixed jitter grace. So a 30s poller and a 600s poller don't share
        one cutoff, and a device that legitimately polls slower than the
        global TTL isn't perpetually flagged offline.

      debounce_s — once a candidate, the device must stay silent at least
        this long (one of its own poll intervals, floored at the grace)
        across a *second* sweep before OFFLINE actually fires. A live but
        jittery device heartbeats within this window and clears the
        candidate — that's what kills the OFFLINE/ONLINE flap.
    """
    try:
        poll = int(dev.get('poll_interval', DEFAULT_POLL_INTERVAL))
    except (TypeError, ValueError):
        poll = DEFAULT_POLL_INTERVAL
    poll = max(1, poll)
    offline_after = max(ttl, poll * OFFLINE_MISSED_POLLS) + OFFLINE_GRACE_S
    # v4.3.0: operator-configurable per-device extra grace before a silent host
    # is even a candidate for OFFLINE. Lets a box on a flaky link or a known-
    # slow poller avoid noisy offline alerts without raising the global TTL.
    # 0 (default) leaves behaviour exactly as before; capped at 24h.
    try:
        extra_min = int(dev.get('offline_alert_delay_min', 0) or 0)
    except (TypeError, ValueError):
        extra_min = 0
    offline_after += max(0, min(1440, extra_min)) * 60
    debounce = max(OFFLINE_GRACE_S, poll)
    return offline_after, debounce


def get_default_poll_interval():
    """Default poll interval used when enrolling new agents."""
    try:
        v = int(_config().get('default_poll_interval', DEFAULT_POLL_INTERVAL))
    except (TypeError, ValueError):
        v = DEFAULT_POLL_INTERVAL
    return max(10, min(3600, v))


def get_session_ttl(remember_me=False):
    """Session lifetime in seconds — short by default, long with 'remember me'."""
    cfg = _config()
    if remember_me:
        try:
            return int(cfg.get('session_ttl_long', DEFAULT_TOKEN_TTL_LONG))
        except (TypeError, ValueError):
            return DEFAULT_TOKEN_TTL_LONG
    try:
        return int(cfg.get('session_ttl_short', DEFAULT_TOKEN_TTL_SHORT))
    except (TypeError, ValueError):
        return DEFAULT_TOKEN_TTL_SHORT


def get_remember_me_default():
    """Whether the 'remember me' checkbox should be pre-ticked on the login page."""
    return bool(_config().get('remember_me_default', False))


def get_cve_cache_seconds():
    """How long to cache OSV vulnerability details before re-fetching."""
    try:
        days = int(_config().get('cve_cache_days', DEFAULT_CVE_CACHE_DAYS))
    except (TypeError, ValueError):
        days = DEFAULT_CVE_CACHE_DAYS
    return max(1, min(90, days)) * 86400


def is_webhook_event_enabled(event):
    """Check the per-event webhook toggle. Backward compatible with legacy keys."""
    cfg = _config()

    # New (v1.8.4): explicit per-event dict
    events = cfg.get('webhook_events') or {}
    if event in events:
        return bool(events[event])

    # Legacy: device_offline/device_online controlled by offline_webhook_enabled,
    # monitor_down/monitor_up by monitor_webhook_enabled, etc.
    if event in ('device_offline', 'device_online'):
        return cfg.get('offline_webhook_enabled', True)
    if event in ('monitor_down', 'monitor_up'):
        return cfg.get('monitor_webhook_enabled', True)
    if event == 'cve_found':
        return cfg.get('cve_webhook_enabled', True)
    if event in ('service_down', 'service_up'):
        return cfg.get('service_webhook_enabled', True)
    # Default ON for everything else not explicitly disabled
    return True


def get_cve_severity_filter():
    """Severity levels that fire cve_found webhooks."""
    cfg = _config()
    raw = cfg.get('cve_severity_filter')
    if isinstance(raw, list) and raw:
        clean = tuple(s for s in raw if s in CVE_SEVERITIES_ALL)
        if clean:
            return clean
    return CVE_SEVERITY_FILTER_DEFAULT


def get_server_name():
    """Display name for this server — webhook payloads, page title, etc."""
    name = _config().get('server_name', '').strip()
    return name or 'RemotePower'

