def handle_user_create():
    require_admin_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    username = _sanitize_str(body.get('username', ''), 32)
    password = body.get('password', '')
    role     = body.get('role', 'admin')
    # v3.1.0: USER_ROLES = {'admin', 'viewer'}. The 'mcp' role is for API
    # keys consumed by AI hosts — humans never log in as MCP. Rejecting
    # it here keeps the human-vs-machine separation crisp.
    if not _assignable_role(role):
        respond(400, {'error': "role must be 'admin', 'viewer', or a defined custom role "
                               "(the 'mcp' role is reserved for API keys)"})
    if role == 'admin':
        require_step_up()   # v6.1.1 (#33): minting a new ADMIN account is the classic privilege-escalation step-up target
    if not username or not re.match(r'^[a-zA-Z0-9_\-]{2,32}$', username):
        respond(400, {'error': 'Invalid username (2-32 chars, alphanumeric/_/-)'})
    if not isinstance(password, str) or not password or len(password) > 1024:
        respond(400, {'error': 'Password required (max 1024 chars)'})
    _pp_ok, _pp_msg = _validate_password_policy(password, username)   # v5.4.1 (D1)
    if not _pp_ok:
        respond(400, {'error': _pp_msg})
    users = load(USERS_FILE)
    if username in users: respond(400, {'error': 'User already exists'})
    users[username] = {'password_hash': hash_password(password), 'created': int(time.time()),
                       'password_changed_at': int(time.time()), 'role': role}
    save(USERS_FILE, users)
    respond(201, {'ok': True, 'username': username, 'role': role})


def handle_user_delete(username):
    requester = require_admin_auth()
    if method() != 'DELETE': respond(405, {'error': 'Method not allowed'})
    if not re.match(r'^[a-zA-Z0-9_\-]{2,32}$', username):
        respond(404, {'error': 'User not found'})
    if username == requester: respond(400, {'error': 'Cannot delete yourself'})
    users = load(USERS_FILE)
    if username not in users: respond(404, {'error': 'User not found'})
    admins = [u for u, d in users.items() if d.get('role', 'admin') == 'admin']
    if len(admins) <= 1 and users[username].get('role', 'admin') == 'admin':
        respond(400, {'error': 'Cannot delete last admin'})
    del users[username]; save(USERS_FILE, users)
    respond(200, {'ok': True})


def handle_user_update(username):
    """PATCH /api/users/<username> — admin-only role update.

    v3.3.0: lets operators flip an existing user between admin and
    viewer without delete+recreate. Refuses to demote the last admin.
    Body: {role: "admin"|"viewer"}.
    """
    requester = require_admin_auth()
    if method() != 'PATCH': respond(405, {'error': 'Method not allowed'})
    if not re.match(r'^[a-zA-Z0-9_\-]{2,32}$', username):
        respond(404, {'error': 'User not found'})
    body = get_json_obj()
    new_role = (body.get('role') or '').strip().lower()
    if not _assignable_role(new_role):
        respond(400, {'error': 'role must be admin, viewer, or a defined custom role'})
    if new_role == 'admin':
        require_step_up()   # v6.1.1 (#33): promoting a user to admin is the classic privilege-escalation step-up target
    with _LockedUpdate(USERS_FILE) as users:
        if username not in users:
            respond(404, {'error': 'User not found'})
        cur_role = users[username].get('role', 'admin')
        # Self-protection: refuse to demote the last admin.
        if cur_role == 'admin' and new_role != 'admin':
            other_admins = [u for u, d in users.items()
                            if u != username and d.get('role', 'admin') == 'admin']
            if not other_admins:
                respond(400, {'error': 'Cannot demote the last admin'})
        users[username]['role'] = new_role
    audit_log(requester, 'user_role_update',
              detail=f'username={username} {cur_role}→{new_role}')
    respond(200, {'ok': True, 'username': username, 'role': new_role})


# ── v3.4.2: custom RBAC role management (admin-only) ─────────────────────────
def _custom_role_names():
    return {r.get('name') for r in (load(ROLES_FILE) or {}).get('roles', [])}


def _assignable_role(role):
    """A role a user account may hold: built-in admin/viewer or a custom role."""
    return role in USER_ROLES or role in _custom_role_names()


def _clean_role_body(body):
    """Validate a custom-role payload → clean dict, or (None, error)."""
    if not isinstance(body, dict): body = {}  # non-dict (e.g. JSON array) → empty, not a 500
    name = _sanitize_str((body.get('name') or '').strip(), 32)
    if not name or not re.match(r'^[a-z0-9_\-]{2,32}$', name):
        return None, 'name must be 2-32 chars (lowercase letters, digits, _ or -)'
    if name in ('admin', 'viewer', 'mcp'):
        return None, "name collides with a built-in role"
    perms = [p for p in (body.get('permissions') or []) if p in _VALID_ROLE_PERMS]
    sc = body.get('scope') or {'type': 'all'}
    stype = sc.get('type', 'all')
    if stype not in _RBAC_SCOPE_TYPES:
        return None, "scope.type must be all, groups, tags, or sites"
    vals = []
    if stype != 'all':
        vals = [_sanitize_str(v, 64) for v in (sc.get('values') or []) if _sanitize_str(v, 64)][:100]
        if not vals:
            return None, f"scope.type '{stype}' requires at least one value"
    return {'name': name, 'permissions': perms,
            'scope': {'type': stype, 'values': vals}}, None


def handle_roles_list():
    """GET /api/roles — built-in + custom roles (admin-only)."""
    require_admin_auth()
    builtin = [
        {'name': 'admin', 'builtin': True, 'permissions': list(_RBAC_PERMS), 'scope': {'type': 'all'}},
        {'name': 'auditor', 'builtin': True, 'permissions': [], 'scope': {'type': 'all'}},
        {'name': 'finance', 'builtin': True, 'permissions': [], 'scope': {'type': 'all'}},
        {'name': 'viewer', 'builtin': True, 'permissions': [], 'scope': {'type': 'all'}},
    ]
    custom = (load(ROLES_FILE) or {}).get('roles', [])
    respond(200, {'roles': builtin + custom, 'permissions': list(_RBAC_PERMS)})


def handle_role_create():
    """POST /api/roles — create a custom role."""
    actor = require_admin_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    clean, err = _clean_role_body(get_json_obj())
    if err: respond(400, {'error': err})
    with _LockedUpdate(ROLES_FILE) as store:
        roles = store.setdefault('roles', [])
        if any(r.get('name') == clean['name'] for r in roles):
            respond(400, {'error': 'role already exists'})
        if len(roles) >= 50:
            respond(400, {'error': 'too many roles (max 50)'})
        roles.append(clean)
    audit_log(actor, 'role_create', f"name={clean['name']} perms={','.join(clean['permissions'])}")
    respond(200, {'ok': True, 'role': clean})


def handle_role_update(name):
    """PUT /api/roles/<name> — replace a custom role's permissions/scope."""
    actor = require_admin_auth()
    if method() != 'PUT': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    body['name'] = name   # name comes from the path; not renamable
    clean, err = _clean_role_body(body)
    if err: respond(400, {'error': err})
    with _LockedUpdate(ROLES_FILE) as store:
        roles = store.get('roles', [])
        if not any(r.get('name') == name for r in roles):
            respond(404, {'error': 'role not found'})
        store['roles'] = [clean if r.get('name') == name else r for r in roles]
    audit_log(actor, 'role_update', f"name={name}")
    respond(200, {'ok': True, 'role': clean})


def handle_role_delete(name):
    """DELETE /api/roles/<name> — remove a custom role (refused if assigned)."""
    actor = require_admin_auth()
    users = load(USERS_FILE)
    assigned = [u for u, d in users.items() if d.get('role') == name]
    if assigned:
        respond(400, {'error': f'role is assigned to {len(assigned)} user(s); reassign them first'})
    with _LockedUpdate(ROLES_FILE) as store:
        roles = store.get('roles', [])
        remaining = [r for r in roles if r.get('name') != name]
        if len(remaining) == len(roles):
            respond(404, {'error': 'role not found'})
        store['roles'] = remaining
    audit_log(actor, 'role_delete', f"name={name}")
    respond(200, {'ok': True})


def handle_user_passwd():
    requester = require_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    username = _sanitize_str(body.get('username', requester), 32)
    old_pw   = body.get('old_password', '')
    new_pw   = body.get('new_password', '')

    if not isinstance(new_pw, str) or not new_pw or len(new_pw) > 1024:
        respond(400, {'error': 'new_password required (max 1024 chars)'})
    _pp_ok, _pp_msg = _validate_password_policy(new_pw, username)   # v5.4.1 (D1)
    if not _pp_ok:
        respond(400, {'error': _pp_msg})

    users = load(USERS_FILE)
    _, requester_role = verify_token(get_token_from_request())

    # Non-admins can only change their own password. Gate on the resolved
    # role's admin flag (not a literal 'admin' string) so a custom admin-
    # equivalent role can't be misread as non-admin — and the denylist shape
    # can't drift into a bypass.
    if username != requester and not _resolve_role(requester_role).get('admin'):
        respond(403, {'error': 'Cannot change another user\'s password'})

    user = users.get(username)
    if not user: respond(404, {'error': 'User not found'})

    # Changing own password always requires old password
    if username == requester:
        if not verify_password(old_pw, user['password_hash']):
            respond(401, {'error': 'Old password incorrect'})

    users[username]['password_hash'] = hash_password(new_pw)
    users[username]['password_changed_at'] = int(time.time())   # v5.4.1 (D1)
    # v2.3.2: once the password is changed, clear the default-password
    # warning flag so the UI banner stops showing.
    users[username].pop('must_change_password', None)
    save(USERS_FILE, users)

    # Invalidate all existing sessions for this user on password change
    tokens = load(TOKENS_FILE)
    tokens = {k: v for k, v in tokens.items() if v.get('user') != username}
    save(TOKENS_FILE, tokens)

    respond(200, {'ok': True})


# ─── v1.11.5: per-user UI preferences ────────────────────────────────────────
#
# Stored under users[username]['ui_prefs'] as a dict keyed by table name. Each
# table entry can carry:
#
#   density   — 'compact' / 'comfortable' / 'spacious'
#   filter    — string, the live filter input value
#   sort      — list of {col: str, dir: 'asc'|'desc'}, in priority order
#
# Schema enforced by :func:`_sanitise_ui_prefs` — the client can send anything,
# but we strip everything we don't recognise so a future field rename or
# malicious payload can't blow up users.json. Stored together with the user
# record (rather than a separate file) so password changes / user deletes
# automatically clean up the prefs too.


def _sanitise_ui_prefs(raw):
    """Validate and trim a UI prefs payload before persisting.

    Args:
        raw: Whatever the client sent. Expected to be a dict keyed by
            table name. Anything else returns an empty dict.

    Returns:
        A clean dict safe to drop into ``users[username]['ui_prefs']``.
        Drops unknown keys silently — old clients sending now-removed
        fields don't break, new clients sending unknown fields don't
        bloat the store.
    """
    if not isinstance(raw, dict):
        return {}
    out = {}

    # v2.4.2: a per-user default SSH username — a single top-level
    # string, not a per-table pref. Reused by the Devices-page quick
    # SSH link so the operator doesn't retype their login each time.
    # Validated as an SSH-safe username (letters, digits, dot, dash,
    # underscore; max 32) — this value is interpolated into an ssh://
    # URL, so the character set is deliberately strict.
    ssh_user = raw.get('default_ssh_username')
    if isinstance(ssh_user, str) and ssh_user:
        if re.fullmatch(r'[A-Za-z0-9._-]{1,32}', ssh_user):
            out['default_ssh_username'] = ssh_user

    # Post-it: a per-account freeform dashboard sticky note (the 'postit' widget).
    postit = raw.get('postit')
    if isinstance(postit, str):
        out['postit'] = _sanitize_str(postit, 2000)

    # Per-user email signature (HTML) appended to outbound ticket emails.
    signature = raw.get('signature')
    if isinstance(signature, str):
        out['signature'] = _sanitize_str(signature, 8000)

    # Team membership — used by the Tickets "My team's open tickets" view.
    team = raw.get('team')
    if isinstance(team, str):
        out['team'] = _sanitize_str(team, 64)

    # v3.14.0: saved & shareable views — named snapshots of a page's filter
    # controls. A top-level list, not a per-table pref. Each entry is
    # {name, page, state:{<control>: <value>}}; values are short strings.
    raw_views = raw.get('views')
    if isinstance(raw_views, list):
        views = []
        for v in raw_views[:MAX_UI_PREFS_VIEWS]:
            if not isinstance(v, dict):
                continue
            name = _sanitize_str(str(v.get('name', '')), 48).strip()
            page = re.sub(r'[^a-zA-Z0-9_-]', '', str(v.get('page', '')))[:32]
            st = v.get('state')
            if not name or not page or not isinstance(st, dict):
                continue
            clean_state = {}
            for k, val in list(st.items())[:20]:
                ck = re.sub(r'[^a-zA-Z0-9_]', '', str(k))[:32]
                if ck and isinstance(val, (str, int, float, bool)):
                    clean_state[ck] = _sanitize_str(str(val), 256)
            views.append({'name': name, 'page': page, 'state': clean_state})
        if views:
            out['views'] = views

    # v3.14.0 (#22): customizable dashboard — an ordered list of widget
    # visibility toggles, [{key, on}]. Keys are validated against the known
    # widget set; unknown keys are dropped so a stale client can't wedge junk.
    raw_dash = raw.get('dashboard')
    if isinstance(raw_dash, list):
        dash = []
        seen = set()
        for e in raw_dash[:len(DASHBOARD_WIDGETS)]:
            if not isinstance(e, dict):
                continue
            k = e.get('key')
            if k not in DASHBOARD_WIDGETS or k in seen:
                continue
            seen.add(k)
            entry = {'key': k, 'on': bool(e.get('on', True))}
            # v4.1.0: per-widget size (column span). Validated; default md.
            sz = e.get('size')
            entry['size'] = sz if sz in DASHBOARD_WIDGET_SIZES else 'md'
            dash.append(entry)
        if dash:
            out['dashboard'] = dash

    # Cap how many distinct table prefs we'll persist for one user. Stops
    # a misbehaving client from filling users.json with junk keys.
    for table_name, prefs in list(raw.items())[:MAX_UI_PREFS_TABLES]:
        if table_name in ('default_ssh_username', 'views', 'dashboard'):
            continue   # handled above — not a table
        # Table names are short alphanumeric identifiers (e.g. 'devices',
        # 'cves_overview'). Strip anything not in that vocabulary.
        clean_name = re.sub(r'[^a-zA-Z0-9_]', '', str(table_name))[:64]
        if not clean_name or not isinstance(prefs, dict):
            continue
        clean = {}

        density = prefs.get('density')
        if density in UI_DENSITY_VALUES:
            clean['density'] = density

        filt = prefs.get('filter')
        if isinstance(filt, str) and filt:
            clean['filter'] = filt[:MAX_UI_PREFS_FILTER_LEN]

        sort = prefs.get('sort')
        if isinstance(sort, list):
            clean_sort = []
            for entry in sort[:MAX_UI_PREFS_SORT_KEYS]:
                if not isinstance(entry, dict):
                    continue
                col = entry.get('col')
                dirn = entry.get('dir')
                if not isinstance(col, str) or not col:
                    continue
                # Column identifiers are short alphanumeric strings — same
                # rule as table names above.
                clean_col = re.sub(r'[^a-zA-Z0-9_]', '', col)[:64]
                if not clean_col:
                    continue
                if dirn not in ('asc', 'desc'):
                    dirn = 'asc'
                clean_sort.append({'col': clean_col, 'dir': dirn})
            if clean_sort:
                clean['sort'] = clean_sort

        if clean:
            out[clean_name] = clean

    # Final size enforcement — JSON-encode and check. Cheap insurance
    # against pathological payloads that pass field-level checks but
    # bloat the file.
    encoded = json.dumps(out)
    if len(encoded) > MAX_UI_PREFS_BYTES:
        # Bail out cleanly rather than silently truncating — easier to debug.
        return {}
    return out


def handle_ui_prefs_get():
    """``GET /api/ui-prefs`` — return current user's stored UI prefs.

    Returns ``{}`` if the user has none yet (fresh sign-up). Never errors
    on missing data — UI prefs are best-effort cosmetics, the page must
    work without them.
    """
    username = require_auth()
    users = load(USERS_FILE)
    user = users.get(username) or {}
    prefs = user.get('ui_prefs') or {}
    if not isinstance(prefs, dict):
        prefs = {}
    respond(200, prefs)


def handle_ui_prefs_set():
    """``POST /api/ui-prefs`` — overwrite current user's UI prefs.

    Whole-document replacement, not patch. The client is the source of
    truth (it has the latest filter strings, sort orders, etc.); the
    server just stores. This avoids the merge-conflict trap of partial
    updates when the same user has two tabs open.
    """
    username = require_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_body()
    if not isinstance(body, dict):
        respond(400, {'error': 'body must be a JSON object'})

    clean = _sanitise_ui_prefs(body)
    users = load(USERS_FILE)
    if username not in users:
        # Should be impossible — auth just succeeded — but defend anyway.
        respond(404, {'error': 'User not found'})
    users[username]['ui_prefs'] = clean
    save(USERS_FILE, users)
    respond(200, {'ok': True, 'prefs': clean})


# v3.14.0: per-account sidebar favorites. Keys come from the client's _favKey()
# — 'p:<page>' (a data-page), 'a:<action>:<arg>' (a section-jump button), or
# 'h:<href>' (an external link). We store them on the user record so they sync
# across devices instead of living only in browser localStorage.
MAX_FAVORITES = 50


def _clean_favorites(raw):
    """Validate + dedupe a favorites list. Tolerant: bad entries are dropped,
    never raises — favorites are cosmetic and must never break /api/me."""
    if not isinstance(raw, list):
        return []
    out = []
    seen = set()
    for item in raw:
        if not isinstance(item, str):
            continue
        key = item.strip()
        # Shape: a 1-char kind prefix (p/a/h), a colon, then a non-empty body.
        if len(key) < 3 or len(key) > 200 or key[0] not in 'pah' or key[1] != ':':
            continue
        if key in seen:
            continue
        seen.add(key)
        out.append(key)
        if len(out) >= MAX_FAVORITES:
            break
    return out


def handle_favorites_set():
    """``POST /api/favorites`` — overwrite the current user's favorites list.

    Whole-list replacement (same model as UI prefs): the client holds the
    authoritative ordered list and POSTs it after every star toggle.
    """
    username = require_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_body()
    # Accept either a bare list or {"favorites": [...]} for forward-compat.
    raw = body.get('favorites') if isinstance(body, dict) else body
    clean = _clean_favorites(raw)
    with _LockedUpdate(USERS_FILE) as users:
        if username not in users:
            respond(404, {'error': 'User not found'})
        users[username]['favorites'] = clean
    respond(200, {'ok': True, 'favorites': clean})


# v3.14.0 (#26): interface language. UI-only i18n — the server just stores the
# user's choice so it follows them across devices. Allowlist is the set the
# front-end ships translations for; anything else (incl. missing) means English.
SUPPORTED_LANGS = ('en', 'zh', 'hi', 'es', 'ar', 'de', 'fr')


def handle_me_lang():
    """``POST /api/me/lang`` — set the current user's interface language.

    Body: ``{"lang": "es"}``. Validated against SUPPORTED_LANGS; an unknown or
    missing value is rejected rather than silently stored, so the client and
    server never disagree about what's persisted."""
    username = require_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    lang = (body.get('lang') if isinstance(body, dict) else None) or ''
    if lang not in SUPPORTED_LANGS:
        respond(400, {'error': f'lang must be one of {", ".join(SUPPORTED_LANGS)}'})
    with _LockedUpdate(USERS_FILE) as users:
        if username not in users:
            respond(404, {'error': 'User not found'})
        users[username]['lang'] = lang
    respond(200, {'ok': True, 'lang': lang})


def handle_ui_prefs_clear():
    """``DELETE /api/ui-prefs`` — wipe current user's UI prefs.

    Useful for "reset to defaults" buttons in the UI without forcing the
    client to know what 'defaults' means.
    """
    username = require_auth()
    if method() != 'DELETE':
        respond(405, {'error': 'Method not allowed'})
    users = load(USERS_FILE)
    if username in users and 'ui_prefs' in users[username]:
        users[username].pop('ui_prefs', None)
        save(USERS_FILE, users)
    respond(200, {'ok': True})


# ── v3.7.0: TOTP recovery (backup) codes ────────────────────────────────────
# One-time codes that stand in for the authenticator if it's lost. Stored only
# as password-hashes (reusing hash_password/verify_password), shown in plaintext
# exactly once — at enrollment or regeneration.
_RECOVERY_CODE_COUNT = 10


def _generate_recovery_codes(n=_RECOVERY_CODE_COUNT):
    """Return (plaintext_list, hashed_list). Codes are 10 hex chars, hyphenated
    for readability (e.g. 'a1b2c-3d4e5')."""
    plain, hashed = [], []
    for _ in range(n):
        raw = secrets.token_hex(5)              # 10 hex chars
        code = f'{raw[:5]}-{raw[5:]}'
        plain.append(code)
        hashed.append(hash_password(code))
    return plain, hashed


def _consume_recovery_code(user, submitted):
    """If `submitted` matches an unused recovery-code hash, remove that hash and
    return True (mutates user['recovery_codes']). Constant-ish: checks all."""
    submitted = (submitted or '').strip().lower().replace(' ', '')
    codes = user.get('recovery_codes') or []
    for i, h in enumerate(codes):
        if verify_password(submitted, h):
            codes.pop(i)
            user['recovery_codes'] = codes
            return True
    return False


def handle_totp_setup():
    """Generate a TOTP secret for the current user. Does NOT enable until confirmed."""
    username = require_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    secret = _generate_totp_secret()
    uri = _totp_provisioning_uri(secret, username)
    # Store pending secret — not active until confirmed
    users = load(USERS_FILE)
    if username not in users: respond(404, {'error': 'User not found'})
    users[username]['totp_pending'] = secret
    save(USERS_FILE, users)
    audit_log(username, 'totp_setup', 'generated new TOTP secret')
    respond(200, {'ok': True, 'secret': secret, 'uri': uri,
                  'note': 'Scan the QR code or enter the secret in your authenticator app, then confirm with /api/totp/confirm'})


def handle_totp_confirm():
    """Confirm TOTP setup by verifying a code from the authenticator app."""
    username = require_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    code = str(body.get('code', '')).strip()
    users = load(USERS_FILE)
    if username not in users: respond(404, {'error': 'User not found'})
    pending = users[username].get('totp_pending')
    if not pending: respond(400, {'error': 'No pending TOTP setup — call /api/totp/setup first'})
    valid_codes = _totp(pending)
    if code not in valid_codes:
        respond(400, {'error': 'Invalid code — check your authenticator app and try again'})
    # Activate TOTP
    users[username]['totp_secret'] = pending
    del users[username]['totp_pending']
    # v3.7.0: mint recovery codes at activation; return plaintext once.
    plain, hashed = _generate_recovery_codes()
    users[username]['recovery_codes'] = hashed
    save(USERS_FILE, users)
    audit_log(username, 'totp_enabled', '2FA activated; recovery codes generated')
    respond(200, {'ok': True, 'recovery_codes': plain,
                  'message': '2FA is now enabled. Save these recovery codes somewhere safe — '
                             'each works once if you lose your authenticator. They will not be shown again.'})


def handle_totp_regenerate_codes():
    """POST /api/totp/recovery-codes — regenerate recovery codes (password-gated).
    Invalidates any previous codes."""
    username = require_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    users = load(USERS_FILE)
    if username not in users: respond(404, {'error': 'User not found'})
    if not users[username].get('totp_secret'):
        respond(400, {'error': '2FA is not enabled'})
    if not verify_password(body.get('password', ''), users[username].get('password_hash', '')):
        respond(401, {'error': 'Password incorrect'})
    plain, hashed = _generate_recovery_codes()
    users[username]['recovery_codes'] = hashed
    save(USERS_FILE, users)
    audit_log(username, 'totp_recovery_regenerated', 'recovery codes regenerated')
    respond(200, {'ok': True, 'recovery_codes': plain})


def handle_totp_disable():
    """Disable 2FA for the current user (requires password confirmation)."""
    username = require_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    password = body.get('password', '')
    users = load(USERS_FILE)
    if username not in users: respond(404, {'error': 'User not found'})
    if not verify_password(password, users[username].get('password_hash', '')):
        respond(401, {'error': 'Password incorrect'})
    users[username].pop('totp_secret', None)
    users[username].pop('totp_pending', None)
    users[username].pop('recovery_codes', None)   # v3.7.0
    save(USERS_FILE, users)
    audit_log(username, 'totp_disabled', '2FA deactivated')
    respond(200, {'ok': True, 'message': '2FA has been disabled.'})


def handle_totp_status():
    """Check if 2FA is enabled for the current user."""
    username = require_auth()
    users = load(USERS_FILE)
    if username not in users: respond(404, {'error': 'User not found'})
    enabled = bool(users[username].get('totp_secret'))
    respond(200, {'enabled': enabled, 'username': username,
                  'recovery_codes_remaining': len(users[username].get('recovery_codes') or [])})


_AGENT_BINARY_PATH = Path('/var/www/remotepower/agent/remotepower-agent')


def _get_agent_sha256():
    """Return sha256 of the canonical agent binary, cached on disk.

    v3.3.0: hash is the primary identity signal for agent updates (the
    version string is informational only). Each CGI request would
    otherwise re-hash the binary; cached to a sidecar file so the cost
    is one mtime check per request after the first call following a
    new agent push. Returns None if no agent binary is published."""
    if not _AGENT_BINARY_PATH.exists():
        return None
    cache = _AGENT_BINARY_PATH.with_suffix(_AGENT_BINARY_PATH.suffix + '.sha256')
    try:
        if cache.exists() and cache.stat().st_mtime >= _AGENT_BINARY_PATH.stat().st_mtime:
            sha = cache.read_text().strip()
            # Sanity check — must be 64 hex chars
            if len(sha) == 64 and all(c in '0123456789abcdef' for c in sha.lower()):
                return sha.lower()
    except Exception:
        pass
    sha = hashlib.sha256(_AGENT_BINARY_PATH.read_bytes()).hexdigest()
    try:
        cache.write_text(sha + '\n')
    except Exception:
        pass
    return sha


_AGENT_VERSION_RE = re.compile(r"^VERSION\s*=\s*'([0-9][^']*)'", re.M)


def _read_agent_version(path):
    """Parse the VERSION constant out of a served agent binary so the advertised
    version ALWAYS matches the bytes we serve (and the sha256 we advertise),
    instead of a separately-stored config value that can drift. The version is
    only informational for the update decision, but a stale string here shows up
    as a confusing "v3.14.0 → v3.12.0" in the agent's upgrade log. Returns None
    if the file is missing/unreadable so callers can fall back to config."""
    try:
        head = path.read_text(errors='replace')[:8000]
    except Exception:
        return None
    m = _AGENT_VERSION_RE.search(head)
    return m.group(1) if m else None


# v3.14.0 #38: agent release channels. A published beta binary lives beside the
# stable one. Channel resolution TRIPLE-defaults to stable, so the update path
# only diverges when (a) the caller is explicitly on beta AND (b) a beta binary
# is actually published — otherwise every agent gets the stable binary exactly
# as before (the feature is inert until an operator publishes a beta release).
_AGENT_BETA_PATH = _AGENT_BINARY_PATH.parent / 'remotepower-agent-beta'


def _sha256_file(path):
    try:
        return hashlib.sha256(path.read_bytes()).hexdigest() if path.exists() else None
    except Exception:
        return None


def _resolve_agent_channel():
    """Resolve the release channel for the current agent/version request from
    ?channel= or the requesting ?device_id='s assigned update_channel. Returns
    'beta' ONLY when beta is requested AND a beta binary exists on disk; else
    'stable'. Never raises."""
    try:
        qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
        ch = (qs.get('channel') or [''])[0].lower()
        if ch not in ('stable', 'beta'):
            did = (qs.get('device_id') or [''])[0]
            if did:
                dev = device_get(did) or {}
                ch = (dev.get('update_channel') or 'stable').lower()
            else:
                ch = 'stable'
        if ch == 'beta' and _AGENT_BETA_PATH.exists():
            return 'beta'
    except Exception:
        pass
    return 'stable'


def handle_agent_version():
    """GET /api/agent/version — agent canonical identity.

    Returns sha256 (primary), version string (informational), and size.
    Agents compare their own sha256 against `sha256` here to decide
    whether to self-update; version is logged but not used for the
    decision (a re-build with the same version still has a different
    hash and SHOULD trigger an update).
    """
    # v3.14.0 #38: serve the beta identity to beta-channel callers when a beta
    # binary is published; otherwise stable (the default for everyone).
    channel = _resolve_agent_channel()
    if channel == 'beta':
        sha = _sha256_file(_AGENT_BETA_PATH)
        bin_path = _AGENT_BETA_PATH
    else:
        sha = _get_agent_sha256()
        bin_path = _AGENT_BINARY_PATH
    if sha is None:
        respond(200, {'version': None, 'sha256': None, 'size': None, 'channel': channel})
    cfg = load(CONFIG_FILE)
    try:
        size = bin_path.stat().st_size
    except OSError:
        size = None
    # Read the version from the SERVED binary so it can't drift from the bytes /
    # sha256 we advertise; fall back to the stored config value only if the file
    # can't be parsed.
    _ver_key = 'agent_beta_version' if channel == 'beta' else 'agent_version'
    _ver = _read_agent_version(bin_path) or cfg.get(_ver_key, cfg.get('agent_version', 'unknown'))
    respond(200, {
        'version': _ver,
        'sha256':  sha,
        'size':    size,
        'channel': channel,
        # v3.4.2: cryptographic release signing. Advertise whether a detached
        # signature is published and the expected signing-key fingerprint so an
        # agent with a pinned key knows to require + check it.
        'signed':          _AGENT_SIG_PATH.exists(),
        'key_fingerprint': (cfg.get('release_key_fingerprint') or '').upper(),
    })


# v3.4.2: detached release signature lives next to the served binary.
_AGENT_SIG_PATH = _AGENT_BINARY_PATH.parent / 'remotepower-agent.asc'


def handle_agent_signature():
    """GET /api/agent/signature — the armored detached signature over the
    canonical agent binary, or 404 if the release isn't signed. Public-ish like
    the binary download; the signature itself is not a secret."""
    require_auth()
    if not _AGENT_SIG_PATH.exists():
        respond(404, {'error': 'agent release is not signed'})
    try:
        sig = _AGENT_SIG_PATH.read_text()
    except OSError:
        respond(404, {'error': 'agent release is not signed'})
    respond(200, {'signature': sig,
                  'key_fingerprint': (load(CONFIG_FILE).get('release_key_fingerprint') or '').upper()})


def _release_signature_status(with_detail=False):
    """Server-side self-check: is the published agent signature valid against the
    configured release public key? Returns 'valid' | 'invalid' | 'unsigned' |
    'unverifiable' (no key/gpg). With with_detail=True returns (status, detail)
    where detail explains an 'invalid' result (almost always: the published
    binary was re-baked/redeployed after it was signed, so its hash no longer
    matches the signature — the fix is to re-sign). Surfaced so the UI can tell
    the operator WHY rather than just 'INVALID'."""
    def ret(status, detail=''):
        return (status, detail) if with_detail else status
    if not _AGENT_SIG_PATH.exists():
        return ret('unsigned')
    cfg = load(CONFIG_FILE) or {}
    pubkey = cfg.get('release_pubkey') or ''
    gpg = shutil.which('gpg')
    if not pubkey or not gpg or not _AGENT_BINARY_PATH.exists():
        return ret('unverifiable')
    ok, detail = _gpg_verify_detached(_AGENT_BINARY_PATH.read_bytes(),
                                      _AGENT_SIG_PATH.read_text(), pubkey,
                                      (cfg.get('release_key_fingerprint') or ''))
    if ok:
        return ret('valid')
    # Most common cause: the binary changed since it was signed. Say so.
    hint = ('the published agent binary changed since it was signed — re-sign it '
            f'(detail: {detail})') if detail else 'signature does not verify'
    return ret('invalid', hint)


def _gpg_verify_detached(data_bytes, sig_text, pubkey_armored, expected_fpr=''):
    """Verify a detached signature over data_bytes using an ephemeral gpg
    keyring seeded only with the pinned public key. Returns (ok, detail).

    Shared by the server self-check and (vendored copy) the agent. Uses the gpg
    binary — no Python crypto dependency. Fails closed on any error."""
    import tempfile
    gpg = shutil.which('gpg')
    if not gpg:
        return False, 'gpg not available'
    home = tempfile.mkdtemp(prefix='rp-gpgv-')
    try:
        os.chmod(home, 0o700)
        env = dict(os.environ, GNUPGHOME=home)
        imp = subprocess.run([gpg, '--batch', '--import'],
                             input=(pubkey_armored or '').encode(),
                             env=env, capture_output=True, timeout=20)
        if imp.returncode != 0:
            return False, 'public key import failed'
        art = os.path.join(home, 'art')
        sig = os.path.join(home, 'art.asc')
        with open(art, 'wb') as f:
            f.write(data_bytes)
        with open(sig, 'w') as f:
            f.write(sig_text or '')
        r = subprocess.run([gpg, '--batch', '--status-fd', '1', '--verify', sig, art],
                           env=env, capture_output=True, timeout=20)
        out = r.stdout.decode('utf-8', 'replace')
        valid = [ln for ln in out.splitlines() if ln.startswith('[GNUPG:] VALIDSIG')]
        if not valid:
            return False, 'signature not valid'
        if expected_fpr:
            want = expected_fpr.upper().replace(' ', '')
            got = valid[0].split()[2].upper()
            if got != want:
                return False, f'signing key {got[:16]}… != pinned {want[:16]}…'
        return True, 'verified'
    except Exception as e:
        return False, f'verify error: {e}'
    finally:
        shutil.rmtree(home, ignore_errors=True)


# ── v3.4.2: server-side "bake & sign" (convenience mode) ───────────────────────
# A server-held signing key signs the published agent on demand. Convenient
# (one click in the UI) but the private key lives on the server, so it protects
# against tampering at rest, NOT a full server compromise — the UI says so. For
# the strongest guarantee, sign off-server in CI (tools/sign-agent-release.sh).
_SIGNING_GNUPGHOME = DATA_DIR / 'signing-gpg'


def _signing_key_info():
    """(fingerprint, armored_public_key) of the server signing key, or (None, None)."""
    gpg = shutil.which('gpg')
    if not gpg or not _SIGNING_GNUPGHOME.exists():
        return None, None
    try:
        env = dict(os.environ, GNUPGHOME=str(_SIGNING_GNUPGHOME))
        cols = subprocess.run([gpg, '--batch', '--list-secret-keys', '--with-colons'],
                              env=env, capture_output=True, text=True, timeout=15).stdout
        fpr = next((ln.split(':')[9] for ln in cols.splitlines()
                    if ln.startswith('fpr:')), None)
        if not fpr:
            return None, None
        pub = subprocess.run([gpg, '--batch', '--armor', '--export', fpr],
                             env=env, capture_output=True, text=True, timeout=15).stdout
        return fpr, pub
    except Exception:
        return None, None


def handle_signing_status():
    """GET /api/signing/status — server-side signing state for the UI."""
    require_auth()
    cfg = load(CONFIG_FILE) or {}
    fpr, pub = _signing_key_info()
    _sig_status, _sig_detail = _release_signature_status(with_detail=True)
    respond(200, {
        'gpg_available':    bool(shutil.which('gpg')),
        'enabled':          bool(cfg.get('agent_signing_enabled')),
        'has_key':          bool(fpr),
        'fingerprint':      (fpr or '').upper(),
        'public_key':       pub or '',
        'agent_signed':     _AGENT_SIG_PATH.exists(),
        'signature_status': _sig_status,
        'signature_detail': _sig_detail,
    })


def handle_signing_generate():
    """POST /api/signing/generate — generate a server-held Ed25519 signing key
    (no passphrase, so the server can sign non-interactively), export its public
    key + fingerprint into config, and enable signing. Admin-only. `force`
    replaces an existing key."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    gpg = shutil.which('gpg')
    if not gpg:
        respond(400, {'error': 'gpg is not installed on the server'})
    fpr, _ = _signing_key_info()
    if fpr and not (get_json_obj()).get('force'):
        respond(400, {'error': 'a signing key already exists; pass force=true to replace it'})
    if fpr:
        shutil.rmtree(_SIGNING_GNUPGHOME, ignore_errors=True)
    _SIGNING_GNUPGHOME.mkdir(parents=True, exist_ok=True)
    os.chmod(_SIGNING_GNUPGHOME, 0o700)
    env = dict(os.environ, GNUPGHOME=str(_SIGNING_GNUPGHOME))
    params = ("%no-protection\nKey-Type: eddsa\nKey-Curve: ed25519\n"
              "Key-Usage: sign\nName-Real: RemotePower Release\n"
              "Expire-Date: 0\n%commit\n")
    r = subprocess.run([gpg, '--batch', '--gen-key'], input=params.encode(),
                       env=env, capture_output=True, timeout=120)
    if r.returncode != 0:
        respond(500, {'error': 'key generation failed: '
                               + r.stderr.decode('utf-8', 'replace')[:200]})
    fpr, pub = _signing_key_info()
    with _LockedUpdate(CONFIG_FILE) as cfg:
        cfg['release_pubkey'] = pub or ''
        cfg['release_key_fingerprint'] = (fpr or '').upper()
        cfg['agent_signing_enabled'] = True
    audit_log(actor, 'signing_key_generate', f'fingerprint={fpr}')
    respond(200, {'ok': True, 'fingerprint': (fpr or '').upper(), 'public_key': pub or ''})


def handle_signing_sign():
    """POST /api/signing/sign — sign the currently-published agent binary with the
    server key (writes the detached signature). Admin-only."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    # v3.4.2: signing the release is security-sensitive (it's what agents trust)
    # — re-verify the admin password, mirroring handle_signing_toggle. Externally
    # authenticated admins (OIDC/LDAP, no local hash) are exempt but audited.
    _body = get_json_obj()
    _stored = ((load(USERS_FILE) or {}).get(actor) or {}).get('password_hash') or ''
    if _stored and not verify_password(str(_body.get('password') or ''), _stored):
        respond(403, {'error': 'password required to sign the agent release'})
    gpg = shutil.which('gpg')
    fpr, pub = _signing_key_info()
    if not gpg or not fpr:
        respond(400, {'error': 'no server signing key — generate one first'})
    if not _AGENT_BINARY_PATH.exists():
        respond(400, {'error': 'no published agent binary to sign'})
    env = dict(os.environ, GNUPGHOME=str(_SIGNING_GNUPGHOME))
    r = subprocess.run([gpg, '--batch', '--yes', '--armor', '--detach-sign',
                        '-u', fpr, '-o', str(_AGENT_SIG_PATH), str(_AGENT_BINARY_PATH)],
                       env=env, capture_output=True, timeout=60)
    if r.returncode != 0:
        respond(500, {'error': 'signing failed: '
                               + r.stderr.decode('utf-8', 'replace')[:200]})
    # Re-sync the configured release public key + fingerprint to the key we just
    # signed with. The self-check (and the verify status) compares the signature
    # against cfg['release_pubkey']; if that ever drifted from the actual signing
    # key (an earlier key, a half-finished generate, or an externally-set CI
    # pubkey), the freshly-made server signature would never verify and the UI
    # would stay "signed but INVALID" no matter how many times you re-sign. Make
    # signing authoritative for the server-side pin so re-sign always converges.
    if pub:
        with _LockedUpdate(CONFIG_FILE) as cfg:
            cfg['release_pubkey'] = pub
            cfg['release_key_fingerprint'] = (fpr or '').upper()
    audit_log(actor, 'agent_release_signed',
              f'fingerprint={fpr} sha={(_get_agent_sha256() or "")[:12]}')
    respond(200, {'ok': True, 'signature_status': _release_signature_status()})


def handle_signing_toggle():
    """POST /api/signing/toggle — enable/disable signing advertisement. Admin-only.

    Disabling is a security downgrade, so it re-verifies the admin's password
    (body `password`). Externally-authenticated admins (OIDC/LDAP, no local
    password hash) can't re-verify a password, so the check is skipped for them
    — they're already authenticated as admin and the action is audited."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    enabled = bool(body.get('enabled'))
    if not enabled:
        urec = (load(USERS_FILE) or {}).get(actor) or {}
        stored = urec.get('password_hash') or ''
        if stored:   # local-password admin → must re-verify
            if not verify_password(str(body.get('password') or ''), stored):
                respond(403, {'error': 'password required to disable signing enforcement'})
    with _LockedUpdate(CONFIG_FILE) as cfg:
        cfg['agent_signing_enabled'] = enabled
    audit_log(actor, 'signing_toggle', f'enabled={enabled}')
    respond(200, {'ok': True, 'enabled': enabled})


def _agent_integrity_status(dev, canonical_sha, canonical_ver):
    """Per-device agent integrity verdict against the canonical served binary.

    - 'verified': the agent's self-reported hash equals the canonical hash.
    - 'mismatch': the agent claims the current version but reports a DIFFERENT
      hash — tamper, corruption, or a partial update. A security signal.
    - 'unknown': no reported hash yet, or the agent is on a different version
      (we only hold the canonical hash for the currently-published agent)."""
    reported = (dev.get('agent_sha256') or '').lower()
    if not reported or not canonical_sha:
        return 'unknown'
    if reported == canonical_sha:
        return 'verified'
    if canonical_ver and (dev.get('version') or '') == canonical_ver:
        return 'mismatch'
    return 'unknown'


def handle_agent_integrity():
    """GET /api/fleet/agent-integrity — per-device agent integrity attestation:
    does each agent's running binary hash match the canonical copy the server
    serves? Mismatches (same version, different hash) flag tamper / corruption.
    Auth: require_auth."""
    require_auth()
    canonical = _get_agent_sha256()
    devices = load(DEVICES_FILE) or {}
    devices = _scope_filter_devices(devices)  # v3.5.0 RBAC v2
    counts = {'verified': 0, 'mismatch': 0, 'unknown': 0}
    rows = []
    for dev_id, dev in devices.items():
        if not isinstance(dev, dict) or dev.get('agentless') or dev.get('monitored') is False:
            continue
        st = _agent_integrity_status(dev, canonical, SERVER_VERSION)
        counts[st] += 1
        rows.append({'device_id': dev_id, 'name': dev.get('name', dev_id),
                     'version': dev.get('version', ''), 'status': st,
                     'agent_sha256': (dev.get('agent_sha256') or '')[:12],
                     'update_rejected': dev.get('agent_update_rejected') or ''})
    order = {'mismatch': 0, 'unknown': 1, 'verified': 2}
    rows.sort(key=lambda r: (order.get(r['status'], 3), r['name'].lower()))
    respond(200, {
        'canonical_sha256':  (canonical or '')[:12],
        'server_version':    SERVER_VERSION,
        'counts':            counts,
        'devices':           rows,
        # v3.4.2: is the served release cryptographically signed + valid?
        'release_signature': _release_signature_status(),
    })


def handle_agent_download():
    # v3.14.0 #38: serve the beta binary to beta-channel callers when published;
    # _resolve_agent_channel returns 'beta' only if the beta file exists, so
    # stable callers (the default) always get the canonical stable binary.
    agent_path = _AGENT_BETA_PATH if _resolve_agent_channel() == 'beta' \
        else Path('/var/www/remotepower/agent/remotepower-agent')
    if not agent_path.exists(): respond(404, {'error': 'Agent binary not found'})
    data = agent_path.read_bytes()
    print("Status: 200 OK"); print("Content-Type: application/octet-stream")
    print("Content-Disposition: attachment; filename=remotepower-agent")
    print(f"Content-Length: {len(data)}"); print("Cache-Control: no-store"); print()
    sys.stdout.flush(); sys.stdout.buffer.write(data); sys.stdout.buffer.flush(); sys.exit(0)


# v4.8.0: a one-line, self-hosted agent installer with THIS server's URL baked
# in. The whole point of the rewrite — "Add device" hands the operator one line:
#     curl -fsSL <server>/install | sh -s -- --token <enrollment-token>
# and SSH-push just runs that same line on a remote host. POSIX sh (dash-safe).
# @@SERVER@@ is replaced per-request. No secret is embedded — the caller supplies
# the one-time --token; the server URL is public — so this stays auth-exempt like
# the agent binary download it pulls.
_AGENT_INSTALL_SH = r'''#!/bin/sh
# RemotePower agent installer  ·  served by @@SERVER@@
#   curl -fsSL @@SERVER@@/install | sh -s -- --token <enrollment-token> [--ca-fingerprint FP] [--name NAME]
set -eu
RP_SERVER="@@SERVER@@"
RP_TOKEN="@@TOKEN@@"   # baked one-time enrolment token (empty if not a baked link)
# Uninstall:  curl -fsSL @@SERVER@@/install | sudo sh -s -- --uninstall
if [ "${1:-}" = "--uninstall" ]; then
  [ "$(id -u)" = "0" ] || { echo "[!] run as root (use sudo)"; exit 1; }
  echo "[*] Uninstalling RemotePower agent ..."
  systemctl disable --now remotepower-agent 2>/dev/null || true
  rm -f /etc/systemd/system/remotepower-agent.service /usr/local/bin/remotepower-agent
  rm -rf /etc/remotepower
  systemctl daemon-reload 2>/dev/null || true
  echo "[+] Agent uninstalled (this host stops reporting; remove it from the dashboard)."
  exit 0
fi
TOKEN=""; CA_FP=""; NAME=""
while [ $# -gt 0 ]; do
  case "$1" in
    --token) TOKEN="${2:-}"; shift 2;;
    --ca-fingerprint) CA_FP="${2:-}"; shift 2;;
    --name) NAME="${2:-}"; shift 2;;
    -h|--help) echo "usage: ... | sh -s -- --token <t> [--ca-fingerprint FP] [--name NAME]"; exit 0;;
    *) echo "unknown arg: $1" >&2; exit 2;;
  esac
done
[ "$(id -u)" = "0" ] || { echo "[!] run as root (use sudo)"; exit 1; }
[ -n "$TOKEN" ] || TOKEN="$RP_TOKEN"   # fall back to the baked token
[ -n "$TOKEN" ] || { echo "[!] no enrolment token — use a baked link (Add device → Quick install) or pass --token"; exit 1; }
_fetch() { if command -v curl >/dev/null 2>&1; then curl -fsSL "$1" -o "$2"; else wget -qO "$2" "$1"; fi; }
_get()   { if command -v curl >/dev/null 2>&1; then curl -fsSL "$1"; else wget -qO- "$1"; fi; }

mkdir -p /etc/remotepower
# Optional self-signed CA pin: fetch over the same server, verify the SHA-256
# BEFORE trusting it (so a plain-HTTP fetch can't be substituted by a MITM).
if [ -n "$CA_FP" ]; then
  echo "[*] Pinning server CA ..."
  _fetch "$RP_SERVER/ca.crt" /etc/remotepower/ca.crt
  got="$(openssl x509 -in /etc/remotepower/ca.crt -noout -fingerprint -sha256 | sed 's/^.*=//;s/://g' | tr 'A-F' 'a-f')"
  want="$(printf '%s' "$CA_FP" | sed 's/://g' | tr 'A-F' 'a-f')"
  [ "$got" = "$want" ] || { echo "[!] CA fingerprint mismatch — refusing"; exit 1; }
  echo "RP_CA_BUNDLE=/etc/remotepower/ca.crt" > /etc/remotepower/agent.env
fi

BIN=/usr/local/bin/remotepower-agent
echo "[*] Downloading agent from $RP_SERVER ..."
_fetch "$RP_SERVER/api/agent/download" "$BIN"
chmod 755 "$BIN"

# Integrity: verify the binary against the SHA-256 the server publishes (over the
# same trusted HTTPS) before running it — refuse a tampered/corrupt download.
_want="$(_get "$RP_SERVER/api/agent/version" | sed -n 's/.*"sha256"[[:space:]]*:[[:space:]]*"\([0-9a-fA-F]\{64\}\)".*/\1/p' | head -1)"
if [ -n "$_want" ]; then
  if command -v sha256sum >/dev/null 2>&1; then _got="$(sha256sum "$BIN" | awk '{print $1}')"
  else _got="$(shasum -a 256 "$BIN" | awk '{print $1}')"; fi
  [ "$(printf '%s' "$_got" | tr 'A-F' 'a-f')" = "$(printf '%s' "$_want" | tr 'A-F' 'a-f')" ] || {
    echo "[!] agent checksum mismatch — refusing to run a tampered binary"; rm -f "$BIN"; exit 1; }
  echo "[+] integrity verified (sha256)"
fi

echo "[*] Enrolling ..."
if [ -n "$NAME" ]; then "$BIN" enroll-token --server "$RP_SERVER" --name "$NAME" --token "$TOKEN"
else "$BIN" enroll-token --server "$RP_SERVER" --token "$TOKEN"; fi

cat > /etc/systemd/system/remotepower-agent.service <<UNIT
[Unit]
Description=RemotePower agent
After=network-online.target
Wants=network-online.target
[Service]
ExecStart=$BIN run
EnvironmentFile=-/etc/remotepower/agent.env
Restart=always
RestartSec=10
[Install]
WantedBy=multi-user.target
UNIT
systemctl daemon-reload 2>/dev/null || true
systemctl enable --now remotepower-agent 2>/dev/null || "$BIN" run &
echo "[+] Done — this host appears in the dashboard within ~60s."
'''


def _render_agent_install(environ):
    """Build the agent-install script with the server URL (and optionally a baked
    enrolment token from `?t=`) derived from the request. Pure — unit-testable."""
    host = environ.get('HTTP_HOST') or environ.get('SERVER_NAME') or 'localhost'
    host = re.sub(r'[^A-Za-z0-9.:\[\]\-]', '', host)[:255]   # defensive
    proto = (environ.get('HTTP_X_FORWARDED_PROTO')
             or environ.get('REQUEST_SCHEME')
             or ('https' if environ.get('HTTPS') in ('on', '1') else 'https'))
    if proto not in ('http', 'https'):
        proto = 'https'
    # Baked token: "Add device" mints a one-time token and links
    # <server>/install?t=<token>, so the operator runs a SINGLE wget|sh with NO
    # args — the device enrols itself and shows up by hostname.
    qs = urllib.parse.parse_qs(environ.get('QUERY_STRING', ''))
    token = (qs.get('t') or qs.get('token') or [''])[0]
    token = re.sub(r'[^A-Za-z0-9._\-]', '', token)[:128]
    return (_AGENT_INSTALL_SH
            .replace('@@SERVER@@', f"{proto}://{host}")
            .replace('@@TOKEN@@', token))


def handle_agent_install():
    """GET /api/agent/install (and /install) — serve the one-line agent
    installer with this server's URL baked in. Auth-exempt: it embeds no secret
    (the caller passes a one-time --token) and the server URL is public, exactly
    like the agent binary it downloads."""
    # v6.1.0: os.environ is process-global — correct under CGI (fresh process
    # per request) but WRONG under the persistent gunicorn/Flask tier (now the
    # default), where it would read another thread's or no request's data.
    # Use the thread-local per-request environ when one is active, same as _env().
    body = _render_agent_install(getattr(_RCTX, 'environ', None) or os.environ).encode()
    print("Status: 200 OK")
    print("Content-Type: text/x-shellscript; charset=utf-8")
    print(f"Content-Length: {len(body)}")
    print("Cache-Control: no-store")
    print()
    sys.stdout.flush(); sys.stdout.buffer.write(body); sys.stdout.buffer.flush(); sys.exit(0)


def _backup_rpo_status(bcfg, backup_state, now):
    """Pure: grade the backup state against a declared RPO/RTO target
    (docs/master-improvement-scoping-internal.md #56). RPO is measured
    (hours since the last successful run vs. the target — a target with no
    measurement to compare against is treated as breached, not silently
    "fine"). RTO is declared alongside the closest real measurement
    available (handle_backup_test_restore's timing, a decrypt+decompress+
    structure-check lower bound, NOT a full service restore) rather than a
    computed breach, since no automatic full-restore timing exists. Returns
    a dict of fields to merge into the 'backup' block of /api/self/status."""
    rpo_hours = int(bcfg.get('rpo_hours') or 0)
    rto_hours = int(bcfg.get('rto_hours') or 0)
    out = {'rpo_hours': rpo_hours, 'rto_hours': rto_hours}
    last_run = int((backup_state or {}).get('last_run') or 0)
    if rpo_hours and last_run:
        hours_since = (now - last_run) / 3600.0
        out['hours_since_last_backup'] = round(hours_since, 1)
        out['rpo_breached'] = hours_since > rpo_hours
    elif rpo_hours:
        out['rpo_breached'] = True
    return out


def handle_self_status():
    """GET /api/self/status — RemotePower watching itself.

    v3.0.2: addresses the "who monitors the monitor?" gap. Returns:
      - server_version, uptime estimate (from CONFIG_FILE mtime)
      - DATA_DIR disk usage breakdown (top-level files >100KB)
      - last_seen per device and how many are offline
      - fleet_events file + archive sizes
      - webhook delivery rate (last 24h, last 7d)
      - audit log entry count + retention setting
      - process info (pid, mem if available without psutil)
    """
    require_auth()
    now = int(time.time())
    out = {'now': now, 'server_version': SERVER_VERSION}
    # v5.6.x: how the server is actually being served (storage backend, request
    # tier, scheduler) — rendered as the "Serving / Runtime" table on the page.
    out['runtime'] = _runtime_serving_info()
    # DATA_DIR disk usage
    try:
        total_bytes = 0
        files_info = []
        _sb_diag = _storage_backend()
        if _sb_diag in ('sqlite', 'postgres'):
            # No per-file .json artifacts — report logical document sizes from
            # the decomposed store (plus the actual .db file, SQLite only).
            # v5.7.0: the Postgres backend used to fall through to the DATA_DIR
            # filesystem walk below, where no .json files exist → the Server-
            # Status page reported total_bytes=0 and an empty big-files list.
            _smod = storage if _sb_diag == 'sqlite' else storage_pg
            for name in _smod.iter_files(DATA_DIR):
                try:
                    sz = _smod.doc_size(DATA_DIR / name)
                except Exception:
                    sz = 0
                total_bytes += sz
                if sz >= 100 * 1024:
                    files_info.append({'name': name, 'bytes': sz})
            if _sb_diag == 'sqlite':
                try:
                    dbp = storage.db_path(DATA_DIR)
                    if dbp.exists():
                        files_info.append({'name': dbp.name,
                                           'bytes': dbp.stat().st_size})
                except OSError:
                    pass
        else:
            for p in DATA_DIR.iterdir():
                if not p.is_file():
                    continue
                try:
                    sz = p.stat().st_size
                    total_bytes += sz
                    if sz >= 100 * 1024:
                        files_info.append({'name': p.name, 'bytes': sz})
                except OSError:
                    pass
        files_info.sort(key=lambda x: x['bytes'], reverse=True)
        out['data_dir'] = {
            'path':      str(DATA_DIR),
            'total_bytes': total_bytes,
            'big_files': files_info[:20],
        }
        # v3.12.0: storage-backend health (SQLite only).
        if _storage_backend() == 'sqlite':
            _m = load(SQLITE_MAINT_FILE) or {}
            out['storage_backend'] = {
                'backend':        'sqlite',
                'db_bytes':       _m.get('db_bytes'),
                'last_integrity': _m.get('last_integrity'),
                'last_integrity_at': _m.get('last_integrity_at'),
                'last_checkpoint':   _m.get('last_checkpoint'),
            }
        else:
            # v5.6.x: report the real backend (was hard-coded 'json', so Postgres
            # showed as json here). The sqlite-maintenance detail above only
            # applies to sqlite; json/postgres just carry the name.
            out['storage_backend'] = {'backend': _storage_backend()}
        # Free-space (statvfs)
        try:
            st = os.statvfs(str(DATA_DIR))
            out['data_dir']['fs_free_bytes']  = st.f_bavail * st.f_frsize
            out['data_dir']['fs_total_bytes'] = st.f_blocks * st.f_frsize
        except OSError:
            pass
    except Exception as e:
        out['data_dir'] = {'error': str(e)}
    # Device freshness
    try:
        devs = load(DEVICES_FILE)
        ttl = get_online_ttl()
        offline_ct = 0; oldest_ts = None; freshest_ts = 0; monitored = 0
        for d in devs.values():
            if not d.get('monitored', True):
                continue
            monitored += 1
            ls = d.get('last_seen') or 0
            if ls and (oldest_ts is None or ls < oldest_ts): oldest_ts = ls
            if ls > freshest_ts: freshest_ts = ls
            if (now - (ls or 0)) > ttl:
                offline_ct += 1
        out['devices'] = {
            'monitored':     monitored,
            'offline':       offline_ct,
            'oldest_seen':   oldest_ts,
            'freshest_seen': freshest_ts,
            'online_ttl_s':  ttl,
        }
    except Exception as e:
        out['devices'] = {'error': str(e)}
    # Webhook delivery rate
    try:
        wl = load(WEBHOOK_LOG_FILE)
        entries = wl.get('entries') or []
        # v3.2.0 fix: only count true delivery *attempts* in the rate
        # calculation. Entries with status='disabled' / 'suppressed' /
        # 'filtered' are operator-side decisions NOT to deliver — they
        # don't represent webhook failures and shouldn't drag the rate
        # toward zero. A successful attempt has a numeric 2xx status;
        # a failed attempt has either a numeric non-2xx or the literal
        # string 'error' (which the dispatcher uses for network/TLS
        # failures with no HTTP status to report).
        _NON_ATTEMPT_STATUSES = {'disabled', 'suppressed', 'filtered'}
        def _is_attempt(e):
            s = str(e.get('status', ''))
            return s and s.lower() not in _NON_ATTEMPT_STATUSES
        def _is_success(e):
            s = str(e.get('status', ''))
            return s.startswith('2')
        def _rate(window_s):
            recent = [e for e in entries if e.get('ts', 0) >= now - window_s]
            if not recent:
                return None
            attempts = [e for e in recent if _is_attempt(e)]
            if not attempts:
                # We logged something but nothing was sent. Return a clear
                # zero-attempt shape so the UI can render "no deliveries"
                # rather than 0%.
                return {'attempts': 0, 'success': 0, 'rate': None,
                        'skipped': len(recent)}
            ok = sum(1 for e in attempts if _is_success(e))
            return {'attempts': len(attempts),
                    'success':  ok,
                    'rate':     round(ok / len(attempts), 3),
                    'skipped':  len(recent) - len(attempts)}
        out['webhooks'] = {
            'last_24h': _rate(86400),
            'last_7d':  _rate(7 * 86400),
            'total_logged': len(entries),
        }
    except Exception as e:
        out['webhooks'] = {'error': str(e)}

    # v3.2.0 (B-followup): inbound webhook + syslog hit rate. Mirrors the
    # outbound shape so the dashboard can render them side-by-side.
    try:
        iwl = load(INBOUND_WEBHOOK_LOG_FILE)
        ientries = iwl.get('entries') or []
        def _inb_rate(window_s):
            recent = [e for e in ientries if e.get('ts', 0) >= now - window_s]
            if not recent:
                return None
            ok = sum(1 for e in recent if str(e.get('status', '')).startswith('2'))
            by_kind = {}
            for e in recent:
                k = e.get('kind', 'alert')
                by_kind[k] = by_kind.get(k, 0) + 1
            return {
                'attempts': len(recent),
                'success':  ok,
                'rate':     round(ok / len(recent), 3),
                'by_kind':  by_kind,
            }
        out['inbound_webhooks'] = {
            'last_24h':     _inb_rate(86400),
            'last_7d':      _inb_rate(7 * 86400),
            'total_logged': len(ientries),
        }
    except Exception as e:
        out['inbound_webhooks'] = {'error': str(e)}
    # Audit log size
    try:
        al = load(AUDIT_LOG_FILE)
        out['audit_log'] = {
            'entries':         len(al.get('entries') or []),
            'retention_days':  int(_config_ro().get('audit_log_retention_days') or 90),
        }
        arch = DATA_DIR / 'audit_log_archive.jsonl.gz'
        if arch.exists():
            out['audit_log']['archive_bytes'] = arch.stat().st_size
    except Exception as e:
        out['audit_log'] = {'error': str(e)}
    # fleet_events
    try:
        if backend_exists(FLEET_EVENTS_FILE):
            out['fleet_events'] = {'bytes': _data_file_bytes(FLEET_EVENTS_FILE)}
        arch = DATA_DIR / 'fleet_events_archive.jsonl.gz'
        if arch.exists():
            out['fleet_events'] = out.get('fleet_events') or {}
            out['fleet_events']['archive_bytes'] = arch.stat().st_size
    except Exception:
        pass
    # Process info
    try:
        out['process'] = {'pid': os.getpid()}
        try:
            with open('/proc/self/status') as f:
                for line in f:
                    if line.startswith('VmRSS:'):
                        out['process']['vmrss_kb'] = int(line.split()[1])
                        break
        except OSError:
            pass
    except Exception:
        pass

    # v3.2.0: performance snapshot for the Server Status page.
    # All four parts are best-effort — if /proc is unavailable (e.g. macOS
    # dev box), the field is omitted rather than failing the response.
    perf = {}
    try:
        with open('/proc/loadavg') as f:
            parts = f.read().split()
            perf['load_avg'] = {
                '1m':  float(parts[0]),
                '5m':  float(parts[1]),
                '15m': float(parts[2]),
            }
    except OSError:
        pass
    try:
        meminfo = {}
        with open('/proc/meminfo') as f:
            for line in f:
                k, _, v = line.partition(':')
                v = v.strip().split()
                if v:
                    meminfo[k] = int(v[0])  # all values are in kB
        total = meminfo.get('MemTotal', 0)
        avail = meminfo.get('MemAvailable') or meminfo.get('MemFree', 0)
        if total > 0:
            perf['memory'] = {
                'total_kb':     total,
                'available_kb': avail,
                'used_pct':     round((total - avail) * 100.0 / total, 1),
            }
    except OSError:
        pass
    # Active sessions (TOKENS_FILE) — excluding expired ones the
    # cleanup_tokens sweep hasn't reached yet.
    try:
        tokens = load(TOKENS_FILE)
        active = 0
        for t, meta in tokens.items():
            if not isinstance(meta, dict):
                continue
            ttl = meta.get('ttl', 0)
            created = meta.get('created', 0)
            if not ttl or (now - created) <= ttl:
                active += 1
        perf['sessions'] = {'active': active}
    except Exception:
        pass
    # Devices online/offline percentage — pulled from the freshness block
    if isinstance(out.get('devices'), dict) and out['devices'].get('monitored'):
        mon = out['devices']['monitored']
        off = out['devices'].get('offline', 0)
        perf['devices_online_pct'] = round((mon - off) * 100.0 / mon, 1)
    # Site health: 'ok' if no scary signals, otherwise list the reasons
    flags = []
    # v3.3.0: was `> os.cpu_count() * 2 if os.cpu_count() else 999` —
    # Python parsed that as `(x > y) if cpu_count else 999`, so when
    # os.cpu_count() returned None/0 the whole expression evaluated to
    # 999 (truthy) and 'high load' fired on every status response.
    _cpu_n = os.cpu_count() or 0
    _load_5m = perf.get('load_avg', {}).get('5m', 0)
    if _cpu_n and _load_5m > _cpu_n * 2:
        flags.append('high load')
    if perf.get('memory', {}).get('used_pct', 0) > 90:
        flags.append('memory > 90%')
    if isinstance(out.get('devices'), dict) and out['devices'].get('monitored'):
        if perf.get('devices_online_pct', 100) < 80:
            flags.append('< 80% devices online')
    if isinstance(out.get('webhooks', {}).get('last_24h'), dict):
        rate = out['webhooks']['last_24h'].get('rate')
        # rate is None when every event was suppressed/disabled/filtered —
        # NOT a delivery failure, so don't flag it.
        if rate is not None and rate < 0.9:
            flags.append(f'webhook delivery rate {int(rate*100)}%')
    perf['health'] = 'ok' if not flags else 'warn'
    perf['health_flags'] = flags
    out['performance'] = perf
    # Backup state
    try:
        bs_file = DATA_DIR / 'self_backup_state.json'
        if backend_exists(bs_file):   # v5.0.0: DB-backed key, not a file
            out['backup'] = load(bs_file)
        # v5.0.0 (#C2): surface whether at-rest encryption is armed (passphrase
        # present in the env) + whether the crypto lib is available — without ever
        # echoing the passphrase itself.
        out.setdefault('backup', {})
        out['backup']['encryption_armed'] = bool(_backup_passphrase())
        out['backup']['encryption_available'] = backup_crypto.available()
        # v5.0.0: archive counts so the UI can offer "encrypt existing backups".
        try:
            _bcfg = (load(CONFIG_FILE) or {}).get('backup') or {}
            _bdir = Path(_bcfg.get('path') or '/var/lib/remotepower/backups')
            out['backup']['plaintext_archives'] = sum(
                1 for f in _bdir.glob('remotepower_data_*.tar.gz')
                if not f.name.endswith('.enc'))
            out['backup']['encrypted_archives'] = sum(
                1 for _ in _bdir.glob('remotepower_data_*.tar.gz.enc'))
        except Exception:
            pass
        # master-improvement-scoping #56: grade the backup state against a
        # declared RPO/RTO, not just pass/fail.
        try:
            _bcfg2 = (load(CONFIG_FILE) or {}).get('backup') or {}
            out['backup'].update(_backup_rpo_status(_bcfg2, out['backup'], now))
        except Exception:
            pass
    except Exception:
        pass
    # v4.3.0: cadence-job staleness. A job that quietly stops looks identical to
    # one that simply isn't due — surface the last-ran time + a stale flag (last
    # run older than 3× its interval) so an operator can SEE a wedged job.
    try:
        out['cadence_jobs'] = _cadence_job_status(now)
    except Exception as e:
        out['cadence_jobs'] = {'error': str(e)[:200]}
    # v4.3.0: recent slow requests (handlers past the slow threshold).
    try:
        slow = (load(SLOW_HANDLERS_FILE) or {}).get('entries', [])
        out['slow_handlers'] = {
            'threshold_ms': _slow_handler_threshold_ms(),
            'count': len(slow),
            'recent': list(reversed(slow[-15:])),   # newest first
        }
    except Exception as e:
        out['slow_handlers'] = {'error': str(e)[:200]}
    respond(200, out)


def _cadence_job_status(now):
    """Per-job {last_run, interval_s, stale, never_ran} for the recurring jobs
    that record a timestamp. 'stale' = last run older than 3× the interval (and
    the job has run at least once). Cheap — a couple of small reads."""
    cfg = load(CONFIG_FILE) or {}

    def entry(last, interval, enabled=True):
        last = int(last or 0)
        return {
            'last_run': last,
            'interval_s': int(interval),
            'never_ran': last == 0,
            'enabled': bool(enabled),
            # Only flag stale once it HAS run; a never-run disabled job isn't a
            # fault, just unconfigured.
            'stale': bool(enabled and last and (now - last) > 3 * int(interval)),
        }

    mon_interval = max(60, int(cfg.get('monitor_interval', 300)))
    jobs = {
        'kev_epss_refresh': entry(cfg.get('last_kev_epss_refresh'),
                                  KEV_EPSS_INTERVAL),
        'monitors': entry(cfg.get('last_monitor_run'), mon_interval,
                          enabled=bool(cfg.get('monitors'))),
    }
    # Scheduled scans: the soonest-overdue enabled schedule (each carries its
    # own last_run); report the most-stale one.
    try:
        scheds = [s for s in (load(SCAN_SCHEDULES_FILE) or {}).values()
                  if isinstance(s, dict) and s.get('enabled')]
        if scheds:
            worst = max(scheds, key=lambda s: now - int(s.get('last_run') or 0))
            jobs['scheduled_scans'] = {
                'last_run': int(worst.get('last_run') or 0),
                'interval_s': 86400, 'enabled': True,
                'never_ran': not worst.get('last_run'),
                'count': len(scheds),
                # A cron scan that hasn't fired in 8 days is almost certainly wedged.
                'stale': bool(worst.get('last_run') and
                              (now - int(worst.get('last_run'))) > 8 * 86400),
            }
    except Exception:
        pass
    return jobs


def _record_self_alive():
    """v5.4.1 (G3): note that the control plane served a request this hour. Runs
    once per request but writes at most once per hour (cheap mtime-gated path) —
    a gap in the bucket list means the server served NO request that hour. NEVER
    raises into the request pipeline."""
    try:
        now = int(time.time())
        hr = now - (now % 3600)
        mt = backend_mtime(CONTROL_UPTIME_FILE)
        if mt and int(mt) >= hr:
            return  # already recorded an hour-bucket this hour — stat-only path
        with _LockedUpdate(CONTROL_UPTIME_FILE) as st:
            # st is the yielded load() result (a dict, {} for a missing key);
            # mutate IN PLACE so __exit__ persists it (rebinding would not save).
            hrs = st.get('hours')
            if not isinstance(hrs, list):
                hrs = []
            if not hrs or hrs[-1] != hr:
                hrs.append(hr)
            st['hours'] = hrs[-2208:]            # ~92 days of hourly buckets
            st.setdefault('since', hrs[0] if hrs else hr)
    except Exception:
        pass


def _control_uptime():
    """v5.4.1 (G3): observed control-plane availability over rolling windows.
    HONEST by construction: the denominator starts at the first tracked hour
    (never counts pre-deployment time), and a missing hour means the server
    served zero requests that hour — which is downtime OR simply a quiet period
    with no traffic. Returned to /api/self-test + the Prometheus exporter."""
    try:
        st = load(CONTROL_UPTIME_FILE) or {}
    except Exception:
        st = {}
    hrs = st.get('hours') if isinstance(st, dict) else None
    if not isinstance(hrs, list) or not hrs:
        return {'tracking': False, 'windows': {}}
    seen = set(int(h) for h in hrs if isinstance(h, (int, float)))
    if not seen:
        return {'tracking': False, 'windows': {}}
    now = int(time.time())
    cur = now - (now % 3600)
    first = min(seen)
    out = {}
    for label, days in (('24h', 1), ('7d', 7), ('30d', 30)):
        start = max(cur - days * 86400, first)
        total = (cur - start) // 3600 + 1
        if total <= 0:
            continue
        got = sum(1 for h in seen if start <= h <= cur)
        out[label] = {
            'percent': round(100.0 * got / total, 3),
            'hours_observed': got,
            'hours_total': int(total),
        }
    return {
        'tracking': True,
        'since': int(st.get('since', first)),
        'windows': out,
        'note': 'Observed availability: hours the control plane served at least '
                'one request, over hours since tracking began. A gap is downtime '
                'OR an hour with zero traffic.',
    }


def handle_self_test():
    """v5.0.0 (#U9): ``GET /api/self-test`` — a fast green/red health summary the
    UI shows on one click: storage reachable, config loads, disk headroom, audit
    chain intact, and agent reachability. Admin only."""
    require_admin_auth()
    now = int(time.time())
    checks = []

    def _add(name, ok, detail=''):
        checks.append({'name': name, 'ok': bool(ok), 'detail': str(detail)[:200]})

    # Storage backend + config readable
    try:
        cfg = load(CONFIG_FILE) or {}
        _add('Storage backend', True, _storage_backend())
        _add('Config readable', isinstance(cfg, dict), f'{len(cfg)} keys')
    except Exception as e:
        cfg = {}
        _add('Storage backend', False, str(e))
    # Disk headroom on the data dir
    try:
        st = os.statvfs(str(DATA_DIR))
        total = st.f_blocks * st.f_frsize
        free = st.f_bavail * st.f_frsize
        used_pct = round((1 - free / total) * 100, 1) if total else 0
        try:                                          # 0 = off (mirrors _disk_watchdog)
            thr = int(cfg.get('disk_watchdog_pct', 85))
        except (TypeError, ValueError):               # malformed stored value → default, don't red the check
            thr = 85
        off = thr <= 0
        _add('Disk space', off or used_pct < thr,
             f'{used_pct}% used ({"watchdog off" if off else f"alert at {thr}%"}), '
             f'{round(free/1e9,1)} GB free')
    except Exception as e:
        _add('Disk space', False, str(e))
    # Audit chain integrity
    try:
        entries = (load(AUDIT_LOG_FILE) or {}).get('entries', [])
        checked, broken_at = _audit_chain_walk(entries)
        _add('Audit chain', broken_at is None,
             'intact' if broken_at is None else f'broken at entry {broken_at}')
    except Exception as e:
        _add('Audit chain', False, str(e))
    # Agent reachability (informational — ok if at least one agent online, or none enrolled)
    try:
        devs = load(DEVICES_FILE) or {}
        ttl = get_online_ttl()
        agents = [d for d in devs.values() if isinstance(d, dict) and not d.get('agentless')]
        online = sum(1 for d in agents if d.get('last_seen', 0) and (now - d['last_seen']) < ttl)
        _add('Agent reachability', (not agents) or online > 0,
             f'{online}/{len(agents)} agents online')
    except Exception as e:
        _add('Agent reachability', False, str(e))
    # AI / API keys configured (informational, never fails the suite)
    try:
        ai_ok = bool((cfg.get('ai') or {}).get('api_key'))
        _add('AI provider key', True, 'configured' if ai_ok else 'not configured (optional)')
    except Exception:
        pass

    # G3: observed control-plane availability (informational — never reds the suite).
    try:
        up = _control_uptime()
        if up.get('tracking'):
            w24 = (up.get('windows') or {}).get('24h') or {}
            _add('Control-plane uptime', True,
                 f"{w24.get('percent', 0)}% observed (24h, "
                 f"{w24.get('hours_observed', 0)}/{w24.get('hours_total', 0)} h)")
        else:
            up = None
    except Exception:
        up = None

    # v5.5.0 (Stage D): on a (networked) Postgres backend, running the maintenance
    # cadence on the request path adds ~33 DB round-trips per request — measured
    # ~25× request-latency overhead vs running it out-of-band. Nudge operators to
    # the scheduler. Informational only (never reds the suite).
    try:
        if _storage_backend() == 'postgres' and not _external_scheduler_active():
            _add('Maintenance scheduler', True,
                 'cadence runs on the request path — on Postgres, enable the '
                 'out-of-band scheduler (RP_EXTERNAL_SCHEDULER=1 + remotepower-scheduler) '
                 'for much lower request latency')
        elif _external_scheduler_active():
            _add('Maintenance scheduler', True, 'out-of-band (RP_EXTERNAL_SCHEDULER)')
    except Exception:
        pass

    overall = all(c['ok'] for c in checks)
    respond(200, {'ok': overall, 'checks': checks, 'server_version': SERVER_VERSION,
                  'uptime': up, 'generated_at': now})


def handle_diagnostics_bundle():
    """GET /api/diagnostics — v4.3.0: one downloadable JSON support bundle so an
    operator can attach "everything you'd ask for" in a single file instead of
    a back-and-forth. Admin only; audited. Deliberately contains NO secrets —
    the config is deep-scrubbed with the same _scrub_config_secrets used by the
    /api/config GET view."""
    actor = require_admin_auth()
    now = int(time.time())
    cfg = load(CONFIG_FILE) or {}
    import copy as _copy
    scrubbed = _copy.deepcopy(cfg)
    _scrub_config_secrets(scrubbed)
    # v5.0.1 (SECURITY): _scrub_config_secrets is NAME-based (matches keys ending
    # password/secret/token/…), so it misses secrets whose key doesn't. The
    # /api/config GET view strips these explicitly; mirror that here or the
    # downloadable "contains NO secrets" support bundle leaks them.
    scrubbed.pop('agentless_ssh_key', None)            # SSH private key
    scrubbed.pop('webhook_url', None)                  # legacy URL w/ token in path
    scrubbed.pop('healthchecks_url', None)             # v5.6.0: hc.io ping UUID = credential
    if isinstance(scrubbed.get('metrics_push'), dict):
        scrubbed['metrics_push'].pop('url', None)      # v5.6.0: may embed basic-auth userinfo
    if isinstance(scrubbed.get('gitops'), dict):
        scrubbed['gitops'].pop('auth_header', None)    # git PAT / bearer
    for _wh in (scrubbed.get('webhook_urls') or []):
        if isinstance(_wh, dict):
            _wh.pop('url', None)                       # Slack/Discord/Teams token-in-path
            _wh.pop('pushover_user', None)             # Pushover user key
    # Drop the noisy per-device bookkeeping maps — not useful for support and
    # they bloat the bundle.
    for noisy in ('offline_notified', 'offline_pending', 'patch_alerted',
                  'monitor_notified', 'containers_stale_notified'):
        scrubbed.pop(noisy, None)

    bundle = {
        'generated_at': now,
        'generated_by': actor,
        'server_version': SERVER_VERSION,
        'storage_backend': _storage_backend(),
        'python': sys.version.split()[0],
        'config_scrubbed': scrubbed,
    }
    # Best-effort enrichments — each isolated so one failure can't blank the bundle.
    try:
        devices = load(DEVICES_FILE) or {}
        ttl = get_online_ttl()
        online = sum(1 for d in devices.values()
                     if isinstance(d, dict) and not d.get('agentless')
                     and d.get('last_seen', 0) and (now - d['last_seen']) < ttl)
        bundle['fleet'] = {'total': len(devices), 'online': online,
                           'agentless': sum(1 for d in devices.values()
                                            if isinstance(d, dict) and d.get('agentless'))}
    except Exception as e:
        bundle['fleet'] = {'error': str(e)[:200]}
    try:
        bundle['cadence_jobs'] = _cadence_job_status(now)
    except Exception as e:
        bundle['cadence_jobs'] = {'error': str(e)[:200]}
    try:
        entries = (load(AUDIT_LOG_FILE) or {}).get('entries', [])
        checked, broken_at = _audit_chain_walk(entries)
        bundle['audit'] = {'entries': len(entries), 'chain_ok': broken_at is None,
                           'chain_verified': checked,
                           'retention_days': int(cfg.get('audit_log_retention_days') or 90)}
    except Exception as e:
        bundle['audit'] = {'error': str(e)[:200]}
    # v4.3.0: database integrity (SQLite backend only) — quick_check catches
    # page-level corruption that otherwise only surfaces as weird reads later.
    try:
        if _storage_backend() == 'sqlite':
            bundle['database'] = {'backend': 'sqlite',
                                  'quick_check': storage.integrity_check()}
        else:
            bundle['database'] = {'backend': _storage_backend()}
    except Exception as e:
        bundle['database'] = {'error': str(e)[:200]}
    # Optional-dependency presence — the #1 "why is X unavailable?" question.
    deps = {}
    for mod in ('webauthn', 'saml2', 'psycopg2', 'snmp', 'ldap3'):
        try:
            __import__(mod)
            deps[mod] = True
        except Exception:
            deps[mod] = False
    bundle['optional_deps'] = deps

    audit_log(actor, 'diagnostics_download', f'bundle v{SERVER_VERSION}')
    stamp = time.strftime('%Y%m%d-%H%M%S', time.gmtime(now))
    fname = f'remotepower-diagnostics-{stamp}.json'
    print("Status: 200 OK")
    print("Content-Type: application/json")
    print(f'Content-Disposition: attachment; filename="{fname}"')
    print("Cache-Control: no-store")
    print("X-Content-Type-Options: nosniff")
    print()
    sys.stdout.write(json.dumps(bundle, indent=2, default=str))
    sys.stdout.flush()


def _valid_tls_host(h):
    """A DNS hostname or an IP literal — strict, so arbitrary input can't reach
    the certificate SAN."""
    import ipaddress
    h = (h or '').strip()
    if not h or len(h) > 253:
        return False
    try:
        ipaddress.ip_address(h)
        return True
    except ValueError:
        pass
    # v4.6.1 (SECURITY): validate label-by-label with a fixed-shape per-label
    # regex. The old single-regex form `([a-z0-9](?:[a-z0-9-]{0,62})\.?)+`
    # backtracks catastrophically on a long run of letters/hyphens (py/redos) —
    # the per-label matcher below has no nested-quantifier ambiguity, so it's
    # linear. A trailing dot (FQDN root) is allowed; empty labels are not.
    host = h[:-1] if h.endswith('.') else h
    if not host or '..' in host:
        return False
    _label = re.compile(r'^[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?$')
    return all(_label.match(lbl) for lbl in host.split('.'))


def _tls_gen_self_signed(hosts, out_dir):
    """Create (or reuse) a private CA and (re)issue a server leaf for `hosts`,
    in Python via the cryptography library — the web user needs no root and no
    openssl CLI. Mirrors tools/gen-ca.sh: ECDSA P-256, SAN (DNS+IP), serverAuth
    EKU, CA ~10y / leaf 397d. Reusing the CA keeps enrolled agents' trust across
    a re-issue. Returns the CA SHA-256 fingerprint + the written paths."""
    import datetime
    import ipaddress
    from cryptography import x509
    from cryptography.x509.oid import NameOID, ExtendedKeyUsageOID
    from cryptography.hazmat.primitives import hashes, serialization
    from cryptography.hazmat.primitives.asymmetric import ec

    out_dir = Path(out_dir)
    out_dir.mkdir(parents=True, exist_ok=True)
    try:
        os.chmod(out_dir, 0o750)
    except OSError:
        pass
    ca_crt_p, ca_key_p = out_dir / 'ca.crt', out_dir / 'ca.key'
    leaf_crt_p, leaf_key_p = out_dir / 'server.crt', out_dir / 'server.key'
    now = datetime.datetime.now(datetime.timezone.utc)

    def _write(path, data, mode):
        with open(path, 'wb') as f:
            f.write(data)
        try:
            os.chmod(path, mode)
        except OSError:
            pass

    renewed = ca_crt_p.exists() and ca_key_p.exists()
    if renewed:
        ca_cert = x509.load_pem_x509_certificate(ca_crt_p.read_bytes())
        ca_key = serialization.load_pem_private_key(ca_key_p.read_bytes(), password=None)
    else:
        ca_key = ec.generate_private_key(ec.SECP256R1())
        ca_name = x509.Name([
            x509.NameAttribute(NameOID.COMMON_NAME, 'RemotePower Internal CA'),
            x509.NameAttribute(NameOID.ORGANIZATION_NAME, 'RemotePower')])
        ca_cert = (x509.CertificateBuilder()
            .subject_name(ca_name).issuer_name(ca_name)
            .public_key(ca_key.public_key())
            .serial_number(x509.random_serial_number())
            .not_valid_before(now - datetime.timedelta(minutes=5))
            .not_valid_after(now + datetime.timedelta(days=3650))
            .add_extension(x509.BasicConstraints(ca=True, path_length=0), critical=True)
            .add_extension(x509.KeyUsage(
                digital_signature=False, content_commitment=False, key_encipherment=False,
                data_encipherment=False, key_agreement=False, key_cert_sign=True,
                crl_sign=True, encipher_only=False, decipher_only=False), critical=True)
            .add_extension(x509.SubjectKeyIdentifier.from_public_key(ca_key.public_key()), critical=False)
            .sign(ca_key, hashes.SHA256()))
        _write(ca_crt_p, ca_cert.public_bytes(serialization.Encoding.PEM), 0o644)
        _write(ca_key_p, ca_key.private_bytes(
            serialization.Encoding.PEM, serialization.PrivateFormat.PKCS8,
            serialization.NoEncryption()), 0o600)

    san, cn = [], None
    for h in hosts:
        try:
            san.append(x509.IPAddress(ipaddress.ip_address(h)))
        except ValueError:
            san.append(x509.DNSName(h))
            if cn is None:
                cn = h
    if cn is None:
        cn = hosts[0]

    leaf_key = ec.generate_private_key(ec.SECP256R1())
    leaf_cert = (x509.CertificateBuilder()
        .subject_name(x509.Name([
            x509.NameAttribute(NameOID.COMMON_NAME, cn),
            x509.NameAttribute(NameOID.ORGANIZATION_NAME, 'RemotePower')]))
        .issuer_name(ca_cert.subject)
        .public_key(leaf_key.public_key())
        .serial_number(x509.random_serial_number())
        .not_valid_before(now - datetime.timedelta(minutes=5))
        .not_valid_after(now + datetime.timedelta(days=397))
        .add_extension(x509.BasicConstraints(ca=False, path_length=None), critical=True)
        .add_extension(x509.SubjectAlternativeName(san), critical=False)
        .add_extension(x509.ExtendedKeyUsage([ExtendedKeyUsageOID.SERVER_AUTH]), critical=False)
        .add_extension(x509.KeyUsage(
            digital_signature=True, content_commitment=False, key_encipherment=True,
            data_encipherment=False, key_agreement=False, key_cert_sign=False,
            crl_sign=False, encipher_only=False, decipher_only=False), critical=True)
        .sign(ca_key, hashes.SHA256()))
    _write(leaf_crt_p, leaf_cert.public_bytes(serialization.Encoding.PEM), 0o644)
    _write(leaf_key_p, leaf_key.private_bytes(
        serialization.Encoding.PEM, serialization.PrivateFormat.PKCS8,
        serialization.NoEncryption()), 0o600)

    fp_hex = ca_cert.fingerprint(hashes.SHA256()).hex().upper()
    fp = ':'.join(fp_hex[i:i + 2] for i in range(0, len(fp_hex), 2))
    return {'ok': True, 'fingerprint': fp, 'cn': cn, 'renewed': renewed,
            'dir': str(out_dir), 'ca_crt': str(ca_crt_p),
            'server_crt': str(leaf_crt_p), 'server_key': str(leaf_key_p)}


def handle_tls_gen_self_signed():
    """POST /api/tls/gen-self-signed {hosts:[...]} — generate a self-signed CA +
    server leaf into DATA_DIR/tls (admin-only, audited). The web user can't reload
    nginx (needs root), so this returns the paths + the CA fingerprint and the
    operator points nginx at server.crt/server.key and enrols agents with the
    fingerprint. See docs/tls-selfsigned.md."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'}); return
    body = get_json_obj()
    raw = body.get('hosts')
    if isinstance(raw, str):
        raw = re.split(r'[,\s]+', raw)
    hosts = [str(h).strip() for h in (raw or []) if str(h).strip()]
    if not hosts:
        respond(400, {'error': 'Provide at least one hostname or IP'}); return
    if len(hosts) > 16 or any(not _valid_tls_host(h) for h in hosts):
        respond(400, {'error': 'Invalid hostname or IP in the list'}); return
    try:
        out = _tls_gen_self_signed(hosts, DATA_DIR / 'tls')
    except ImportError:
        respond(500, {'error': 'The cryptography library is not installed on the server'}); return
    except Exception as e:
        respond(500, {'error': f'Certificate generation failed: {e}'}); return
    audit_log(actor, 'tls_gen_self_signed',
              f"hosts={','.join(hosts)} fingerprint={out['fingerprint']}")
    respond(200, out)


def handle_tls_import_p12():
    """POST /api/tls/import-p12 {p12:<base64>, password:<optional>} — import a
    PKCS#12 (.p12/.pfx) bundle: extract the cert (+ any chain) and private key and
    write them to DATA_DIR/tls/server.{crt,key} for nginx to use. Admin-only,
    audited. The password is optional and never stored. The operator still points
    nginx at the files and reloads (needs root)."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'}); return
    import base64
    body = get_json_obj()
    b64 = body.get('p12') or body.get('p12_b64') or ''
    password = body.get('password') or ''
    try:
        raw = base64.b64decode(str(b64), validate=True)
    except Exception:
        respond(400, {'error': 'Invalid file data'}); return
    if not raw:
        respond(400, {'error': 'Empty file'}); return
    if len(raw) > 1024 * 1024:
        respond(400, {'error': 'File too large (max 1 MB)'}); return
    try:
        from cryptography.hazmat.primitives.serialization import (
            pkcs12, Encoding, PrivateFormat, NoEncryption)
        from cryptography.x509.oid import NameOID
        pw = password.encode('utf-8') if password else None
        key, cert, chain = pkcs12.load_key_and_certificates(raw, pw)
    except ImportError:
        respond(500, {'error': 'The cryptography library is not installed on the server'}); return
    except Exception:
        respond(400, {'error': 'Could not read the .p12 — wrong password, or not a PKCS#12 file'}); return
    if not key or not cert:
        respond(400, {'error': 'The bundle must contain both a private key and a certificate'}); return
    out_dir = DATA_DIR / 'tls'
    try:
        out_dir.mkdir(parents=True, exist_ok=True)
        os.chmod(out_dir, 0o750)
    except OSError:
        pass
    crt_pem = cert.public_bytes(Encoding.PEM)
    for c in (chain or []):
        crt_pem += c.public_bytes(Encoding.PEM)
    key_pem = key.private_bytes(Encoding.PEM, PrivateFormat.PKCS8, NoEncryption())
    crt_p, key_p = out_dir / 'server.crt', out_dir / 'server.key'
    try:
        with open(crt_p, 'wb') as f:
            f.write(crt_pem)
        os.chmod(crt_p, 0o644)
        with open(key_p, 'wb') as f:
            f.write(key_pem)
        os.chmod(key_p, 0o600)
    except OSError as e:
        respond(500, {'error': f'Could not write the certificate: {e}'}); return
    try:
        cn = cert.subject.get_attributes_for_oid(NameOID.COMMON_NAME)[0].value
    except Exception:
        cn = ''
    expires = getattr(cert, 'not_valid_after_utc', None) or cert.not_valid_after
    audit_log(actor, 'tls_import_p12', f"cn={cn or '?'}")
    respond(200, {'ok': True, 'cn': cn, 'expires': expires.strftime('%Y-%m-%d'),
                  'chain': len(chain or []), 'server_crt': str(crt_p), 'server_key': str(key_p)})






def handle_storage_backend_status():
    """GET /api/storage-backend/status — current storage backend + inventory.

    v3.12.0: backs the Settings → Advanced storage-backend card. Reports the
    active backend, how it was selected, per-backend file counts, the SQLite DB
    size when present, and whether the data dir is on a network filesystem
    (where SQLite WAL is unsafe)."""
    require_admin_auth()
    active = _storage_backend()
    forced_by_env = os.environ.get('RP_STORAGE_BACKEND') in STORAGE_BACKENDS
    marker = storage.read_marker(DATA_DIR)
    # v3.14.0 (#1): is the Postgres backend usable here? (psycopg installed)
    pg_available = False
    try:
        storage_pg._pg()
        pg_available = True
    except Exception:
        pg_available = False
    out = {
        'active': active,
        'selected_by': 'env' if forced_by_env else 'marker',
        'env_override': forced_by_env,
        'marker': marker,
        'pg_available': pg_available,
        # whether a DSN is already configured (marker or env) — never returned raw
        'pg_configured': bool(marker.get('dsn') or os.environ.get('RP_PG_DSN')),
    }
    # v3.14.0: HA status — connected primary host(s) + whether a read replica is
    # configured (host only, never credentials). Only meaningful on Postgres.
    if active == 'postgres':
        try:
            out['pg_ha'] = storage_pg.pg_status()
        except Exception:
            pass
    try:
        out['json_files'] = len(storage.json_inventory(DATA_DIR))
    except Exception:
        out['json_files'] = None
    try:
        dbp = storage.db_path(DATA_DIR)
        out['sqlite_present'] = dbp.exists()
        out['sqlite_db_bytes'] = dbp.stat().st_size if dbp.exists() else 0
        out['sqlite_files'] = (len(storage.iter_files(DATA_DIR))
                               if dbp.exists() else 0)
    except Exception:
        out['sqlite_present'] = False
    try:
        out['network_fs'] = storage._is_network_fs(DATA_DIR)
    except Exception:
        out['network_fs'] = False
    respond(200, out)


def _migrate_storage_pg(target, dsn, dry_run=False, verify_only=False, log=lambda m: None,
                        dsn_read=''):
    """Migrate to/from the Postgres backend (the shared storage.migrate_run only
    covers JSON↔SQLite). Reads every logical file from the CURRENT backend via
    load() and writes it to the target backend, verifies the round-trip, then
    flips the marker (carrying the DSN for postgres). target or source is
    'postgres'; the other side is json/sqlite."""
    src = _storage_backend()
    if target == 'postgres':
        if not dsn:
            raise ValueError('a Postgres DSN is required to switch to Postgres')
        storage_pg.configure_dsn(dsn)
        storage_pg._connect(DATA_DIR)            # fail fast if unreachable / bad DSN
    elif src == 'postgres':
        storage_pg._connect(DATA_DIR)            # source must be reachable

    files = backend_iter_files()                 # logical files in the source backend
    if dry_run:
        log(f"dry-run: would migrate {len(files)} files to {target}")
        return {'ok': True, 'dry_run': True, 'files': files}

    def _write(name, data):
        p = DATA_DIR / name
        if target == 'sqlite':
            storage.save(p, data, clamp_last_seen=False)
        elif target == 'postgres':
            storage_pg.save(p, data, clamp_last_seen=False)
        else:
            storage._write_json_atomic(p, data)
    def _read_target(name):
        p = DATA_DIR / name
        if target == 'sqlite':
            return storage.load(p)
        if target == 'postgres':
            return storage_pg.load(p)
        return storage._read_json(p)

    if not verify_only:
        for name in files:
            _write(name, load(DATA_DIR / name))   # load() = current/source backend
            log(f"  {src} -> {target}  {name}")

    # Verify: source reconstruction must equal target reconstruction.
    problems = []
    for name in files:
        if storage._norm(load(DATA_DIR / name)) != storage._norm(_read_target(name)):
            problems.append(f"{name}: content differs after migrate")
    if problems:
        return {'ok': False, 'problems': problems,
                'error': 'verification failed — backend NOT switched'}
    if verify_only:
        return {'ok': True, 'verified': True, 'problems': []}

    # Flip the marker (carry the DSN for postgres so the next process reconnects).
    if target == 'postgres':
        _marker = {'backend': 'postgres', 'dsn': dsn, 'migrated_at': int(time.time())}
        if dsn_read:                              # v3.14.0: optional read replica
            _marker['dsn_read'] = dsn_read
            storage_pg.configure_read_dsn(dsn_read)
        storage._write_json_atomic(STORAGE_MARKER_FILE, _marker)
    else:
        storage.write_marker(DATA_DIR, target)
    log(f"marker: active backend is now '{target}'")
    return {'ok': True, 'target': target, 'files': len(files)}


def handle_storage_backend_migrate():
    """POST /api/storage-backend/migrate — migrate data + switch backend.

    Body: {"target": "json"|"sqlite"|"postgres", "dsn"?: str (postgres),
    "dry_run"?: bool, "verify_only"?: bool}. Pre-migration snapshot (where
    applicable) → copy/decompose every file → verify round-trip → flip the
    active-backend marker only if verification passes. Read-only/demo mode and
    non-admins are rejected upstream."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'}); return
    body = get_json_obj()
    target = body.get('target')
    if target not in STORAGE_BACKENDS:
        respond(400, {'error': "target must be 'json', 'sqlite' or 'postgres'"}); return
    if os.environ.get('RP_STORAGE_BACKEND') in STORAGE_BACKENDS:
        respond(409, {'error': 'storage backend is pinned by the '
                      'RP_STORAGE_BACKEND environment variable and cannot be '
                      'switched from the UI'}); return
    dry_run = bool(body.get('dry_run'))
    verify_only = bool(body.get('verify_only'))
    dsn = _sanitize_str(str(body.get('dsn', '')).strip(), 1024)
    dsn_read = _sanitize_str(str(body.get('dsn_read', '')).strip(), 1024)
    lines = []
    try:
        if target == 'postgres' or _storage_backend() == 'postgres':
            if not storage_pg_available():
                respond(409, {'error': 'the Postgres backend is unavailable on '
                              'this server (psycopg is not installed)'}); return
            result = _migrate_storage_pg(target, dsn, dry_run=dry_run,
                                         verify_only=verify_only, log=lines.append,
                                         dsn_read=dsn_read)
        else:
            result = storage.migrate_run(
                DATA_DIR, target, dry_run=dry_run, verify_only=verify_only,
                do_snapshot=not dry_run and not verify_only,
                flip=not dry_run and not verify_only,
                log=lines.append)
    except Exception as e:
        respond(500, {'error': f'migration failed: {e}'}); return
    result['log'] = lines
    # A real (non-dry, non-verify) switch must take effect for the rest of THIS
    # request and all subsequent ones: drop the cached backend so the marker is
    # re-read, and drop the per-request load cache built against the old store.
    if result.get('ok') and not dry_run and not verify_only:
        _invalidate_backend_cache()
        _LOAD_CACHE.clear()
        audit_log(actor, 'storage_backend_migrate',
                  detail=f"target={target} files={result.get('files','?')}")
    status = 200 if result.get('ok') else 500
    respond(status, result)












def _maybe_check_disk_space():
    """v5.0.0 (#R1): server self disk-space watchdog. Called from the heartbeat
    hot path, gated to once per 30 min. Fires `server_disk_low` (high) when the
    DATA_DIR filesystem crosses the configured used% threshold, and the
    `server_disk_ok` recover (with 3-point hysteresis) when it drops back —
    catching the failure mode where the controller's own disk fills and flock
    writes start to fail. Threshold: `disk_watchdog_pct` (default 85; 0 = off).
    """
    cfg = load(CONFIG_FILE) or {}
    try:
        threshold = int(cfg.get('disk_watchdog_pct', 85))
    except (TypeError, ValueError):
        threshold = 85
    if threshold <= 0:
        return
    state_file = DATA_DIR / 'disk_watchdog_state.json'
    state = load(state_file) if backend_exists(state_file) else {}
    now = int(time.time())
    if now - int(state.get('last_check') or 0) < 1800:
        return  # checked within the last 30 min
    try:
        st = os.statvfs(str(DATA_DIR))
        total = st.f_blocks * st.f_frsize
        free = st.f_bavail * st.f_frsize
        used_pct = round((1 - free / total) * 100, 1) if total else 0
    except Exception:
        return
    alerted = bool(state.get('alerted'))
    pending = None  # (event, payload) fired AFTER we persist state (no lock here)
    if used_pct >= threshold and not alerted:
        alerted = True
        pending = ('server_disk_low', {
            'target': 'server', 'name': 'RemotePower server',
            'used_pct': used_pct, 'threshold': threshold,
            'free_gb': round(free / 1e9, 1), 'total_gb': round(total / 1e9, 1),
            'path': str(DATA_DIR),
        })
    elif alerted and used_pct < threshold - 3:
        alerted = False
        pending = ('server_disk_ok', {
            'target': 'server', 'name': 'RemotePower server',
            'used_pct': used_pct, 'threshold': threshold,
        })
    state.update(last_check=now, used_pct=used_pct, alerted=alerted)
    try:
        save(state_file, state)
    except Exception:
        pass
    if pending:
        fire_webhook(pending[0], pending[1])


def handle_version_check():
    require_auth()
    cfg   = load(CONFIG_FILE)
    # v2.1.3: read the *actually running* version from SERVER_VERSION, not
    # from CONFIG_FILE. The previous code (`cfg.get('server_version',
    # SERVER_VERSION)`) returned a stale value whenever an old upgrade
    # had stamped the version into config.json and the next upgrade
    # forgot to refresh it. That's why the About page showed "Latest
    # release 2.0.0 ✓ up to date" on a 2.1.2 box: `local` was the
    # cached 2.0.0 from a year ago, and the comparison against GitHub's
    # 2.0.0 release tag came out equal.
    local = SERVER_VERSION
    now   = int(time.time())
    cached_latest = cfg.get('_github_latest_version')
    cached_ts     = cfg.get('_github_latest_ts', 0)
    if cached_latest and (now - cached_ts) < 3600:
        latest = cached_latest
    else:
        try:
            req = urllib.request.Request(
                'https://api.github.com/repos/tyxak/remotepower/releases/latest',
                headers={'User-Agent': 'RemotePower'})
            opener = _ssrf_safe_opener(allow_loopback=False,
                                       ssl_ctx=_get_ssl_context(),
                                       no_redirect=True, enforce_ip=True)
            with opener.open(req, timeout=5) as r:
                data = json.loads(r.read(65536))  # cap response size
            # Strictly validate: tag must match semver pattern
            raw_tag = data.get('tag_name', '').lstrip('v')
            if re.match(r'^\d{1,4}\.\d{1,4}\.\d{1,4}$', raw_tag):
                latest = raw_tag
            else:
                latest = cached_latest
            if latest:
                cfg['_github_latest_version'] = latest
                cfg['_github_latest_ts']      = now
                save(CONFIG_FILE, cfg)
        except Exception:
            latest = cached_latest

    def vt(v):
        try: return tuple(int(x) for x in v.split('.'))
        except Exception: return (0,)

    # v2.1.3: the "Latest release" on About is conceptually "the latest
    # version you should consider running". If GitHub's tagged latest is
    # *older* than what we're actually running (true on dev builds, true
    # during the gap between cutting a release and publishing it), the
    # latest you should run is the version you have. So clamp:
    #   latest = max(github_tag, local)
    # The `update_available` flag stays accurate (false when running
    # ahead), and the UI no longer confusingly displays an older
    # version as "Latest release".
    if latest is None or vt(latest) < vt(local):
        latest = local

    update_available = vt(latest) > vt(local)
    respond(200, {
        'current': local, 'latest': latest,
        'update_available': update_available,
        'release_url': 'https://github.com/tyxak/remotepower/releases/latest',
        # v5.0.0: whether a guided self-update script is configured (Settings → Install).
        'self_update_configured': bool((cfg.get('self_update_command') or '').strip()),
    })


def handle_server_self_update():
    """v5.0.0: POST /api/server/self-update — run the operator-configured update
    script (Settings → Install). Disabled until an admin sets an absolute script
    path in `self_update_command`; the script is responsible for pulling the new
    version and restarting the service the way this install expects. Admin-only,
    audited, no arguments are passed (the path is run directly, never via a shell)."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'}); return
    cfg = load(CONFIG_FILE) or {}
    cmd = (cfg.get('self_update_command') or '').strip()
    if not cmd:
        respond(400, {'error': 'self-update is not configured — set an update-script '
                               'path in Settings → Install first', 'configured': False}); return
    p = Path(cmd)
    if not p.is_absolute() or not p.exists():
        respond(400, {'error': f'update script not found or not an absolute path: {cmd}'}); return
    audit_log(actor, 'server_self_update', detail=f'cmd={cmd}')
    try:
        proc = subprocess.run([cmd], capture_output=True, text=True, timeout=600)
        out = (proc.stdout + proc.stderr)[-4000:]
        respond(200, {'ok': proc.returncode == 0, 'returncode': proc.returncode, 'output': out})
    except subprocess.TimeoutExpired:
        respond(200, {'ok': False, 'error': 'update timed out after 10 min — it may still '
                                            'be running; check the server logs'})
    except Exception as e:
        respond(500, {'error': str(e)})


def _record_uptime(dev_id, name, is_online):
    # v5.0.0 (perf): per-device entity read/write — runs every heartbeat, so it
    # no longer loads + rewrites the whole-fleet uptime blob.
    entry = _entity_read_one(UPTIME_FILE, dev_id, None) or {'name': name, 'events': []}
    events = entry.get('events', [])
    last_state = events[-1]['online'] if events else None
    if last_state != is_online:
        events.append({'ts': int(time.time()), 'online': is_online})
        entry['events'] = events[-500:]
        entry['name'] = name
        _entity_write_one(UPTIME_FILE, dev_id, entry)


def handle_uptime(dev_id):
    require_auth()
    if not _validate_id(dev_id): respond(404, {'error': 'Device not found'})
    uptime = load(UPTIME_FILE); dev = uptime.get(dev_id, {})
    respond(200, {'device_id': dev_id, 'name': dev.get('name', dev_id), 'events': dev.get('events', [])})


def _overlap_secs(intervals, lo, hi):
    """Total seconds of the (start,end) `intervals` that fall within [lo, hi]."""
    tot = 0
    for s, e in intervals or []:
        s2, e2 = max(s, lo), min(e, hi)
        if e2 > s2:
            tot += e2 - s2
    return tot


def _uptime_pct(events, window_start, now, maint_intervals=None):
    """Integrate online time from a device's uptime transition events.
    Returns (uptime_pct, downtime_seconds, covered); covered=False means
    RemotePower has no record covering the window (unknown — NOT 0%, and not
    100%). Each event is a state *transition*.

    Coverage starts at window_start when the device's state there is known,
    otherwise at the first in-window event: the prefix before RemotePower had
    any data (e.g. before the host was enrolled) is UNKNOWN and is excluded, not
    counted as downtime — a brand-new deployment must never read as "N days
    down". Maintenance-window seconds (`maint_intervals`: a list of
    (start_ts, end_ts)) are removed from BOTH the covered window and the
    downtime, so planned maintenance never burns the SLA."""
    if now <= window_start:
        return None, 0, False
    events = sorted(events or [], key=lambda e: e.get('ts', 0))
    state = None
    for e in events:
        if e.get('ts', 0) <= window_start:
            state = bool(e.get('online'))
        else:
            break
    in_window = [e for e in events if window_start < e.get('ts', 0) <= now]
    if state is None and not in_window:
        return None, 0, False
    # Effective coverage start: the pre-data prefix is unknown, not down.
    if state is None:
        cov_start = int(in_window[0].get('ts', window_start))
        cur = bool(in_window[0].get('online'))
        rest = in_window[1:]
    else:
        cov_start = window_start
        cur = state
        rest = in_window
    down_intervals = []
    cursor = cov_start
    for e in rest:
        ts = int(e.get('ts', cov_start))
        if not cur and ts > cursor:
            down_intervals.append((cursor, ts))
        cursor = ts
        cur = bool(e.get('online'))
    if not cur and now > cursor:
        down_intervals.append((cursor, now))
    covered = now - cov_start
    # Exclude planned-maintenance time from downtime AND the covered window.
    maint = [(int(s), int(e)) for (s, e) in (maint_intervals or []) if e > s]
    down = sum(e - s for (s, e) in down_intervals)
    down -= sum(_overlap_secs(maint, s, e) for (s, e) in down_intervals)
    eff_total = covered - _overlap_secs(maint, cov_start, now)
    if eff_total <= 0:
        return None, 0, False
    down = max(0, down)
    pct = round(100.0 * (eff_total - down) / eff_total, 3)
    return pct, int(down), True


def _as_pct(v):
    """Coerce a configured SLA target to a float in (0, 100], else None."""
    try:
        f = float(v)
    except (TypeError, ValueError):
        return None
    return f if 0 < f <= 100 else None


def _maint_oneshot_intervals(windows, dev_id, dev_group, lo, hi):
    """One-shot (start+end) maintenance windows applicable to a device, as
    (start_ts, end_ts) tuples. Recurring (cron) windows are not subtracted from
    the SLA — only explicitly-scheduled one-shot maintenance is."""
    out = []
    for w in windows or []:
        scope = (w.get('scope') or 'device').lower()
        if scope == 'global':
            applies = True
        elif scope == 'group':
            applies = bool(dev_group) and w.get('target') == dev_group
        elif scope == 'device':
            applies = w.get('target') == dev_id
        else:
            applies = False
        if not applies:
            continue
        s, e = w.get('start'), w.get('end')
        if not (s and e):
            continue
        try:
            s2, e2 = _parse_iso(s), _parse_iso(e)
        except (ValueError, TypeError):
            continue
        if e2 > s2:
            out.append((s2, e2))
    return out


def _resolve_sla_target(targets, dev_id, dev):
    """Resolve a device's SLA target %, most-specific first:
    device → tag → group → fleet default. None if none is configured."""
    if not isinstance(targets, dict):
        return None
    devmap = targets.get('devices') or {}
    # v5.6.0: device-scoped overrides are keyed by HOSTNAME (device name), which is
    # what the operator sees and types. Fall back to matching by the internal
    # device_id so any override saved under the old id-keyed scheme still resolves.
    dname = str(dev.get('name') or '')
    if dname and dname in devmap:
        return _as_pct(devmap[dname])
    if dev_id in devmap:
        return _as_pct(devmap[dev_id])
    tagmap = targets.get('tags') or {}
    for tag in dev.get('tags') or []:
        if tag in tagmap:
            return _as_pct(tagmap[tag])
    grp = dev.get('group')
    if grp and grp in (targets.get('groups') or {}):
        return _as_pct(targets['groups'][grp])
    return _as_pct(targets.get('default'))


def _error_budget(target_pct, down_seconds, window_seconds):
    """v3.14.0 (#40): error budget for an uptime SLO. The budget is the downtime
    the target *allows* over the window; `used` is what's been spent, `remaining`
    what's left (negative = breached). Returns None when no target is set. Pure."""
    if target_pct is None or window_seconds <= 0:
        return None
    allowed = (1.0 - min(100.0, max(0.0, float(target_pct))) / 100.0) * window_seconds
    used = max(0, int(down_seconds or 0))
    remaining = int(allowed) - used
    if allowed > 0:
        used_pct = round((used / allowed) * 100.0, 1)
    else:
        used_pct = 0.0 if used == 0 else 100.0
    return {'budget_seconds': int(allowed), 'used_seconds': used,
            'remaining_seconds': remaining, 'used_pct': used_pct}


def handle_fleet_sla():
    """GET /api/fleet/sla?days=N — per-device + per-group uptime % over a window.

    Computed from the uptime transition log. Time before RemotePower had any
    record for a device (e.g. before enrollment) is reported as *unknown*, never
    as downtime; one-shot maintenance windows are excluded; and a configurable
    SLA target (per device / tag / group / default) is resolved per row.
    Auth: require_auth."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    try:
        days = int((qs.get('days') or ['30'])[0])
    except ValueError:
        days = 30
    days = max(1, min(365, days))
    now = int(time.time())
    window_start = now - days * 86400
    uptime = load(UPTIME_FILE) or {}
    devices = load(DEVICES_FILE) or {}
    devices = _scope_filter_devices(devices)  # v3.5.0 RBAC v2
    windows = (load(MAINT_FILE) or {}).get('windows') or []
    targets = (load(CONFIG_FILE) or {}).get('sla_targets') or {}
    rows = []
    groups = {}
    covered_pcts = []
    for dev_id, dev in devices.items():
        if not isinstance(dev, dict) or dev.get('monitored') is False:
            continue
        ev = (uptime.get(dev_id) or {}).get('events') or []
        maint = _maint_oneshot_intervals(windows, dev_id, dev.get('group') or '',
                                         window_start, now)
        pct, down, covered = _uptime_pct(ev, window_start, now, maint_intervals=maint)
        target = _resolve_sla_target(targets, dev_id, dev)
        met = (pct >= target) if (covered and pct is not None and target is not None) else None
        grp = dev.get('group') or 'ungrouped'
        rows.append({'device_id': dev_id, 'name': dev.get('name', dev_id),
                     'group': grp, 'uptime_pct': pct,
                     'downtime_seconds': down, 'covered': covered,
                     'sla_target': target, 'sla_met': met,
                     'error_budget': _error_budget(target, down, days * 86400)
                                     if covered else None})
        if covered and pct is not None:
            covered_pcts.append(pct)
            g = groups.setdefault(grp, [])
            g.append(pct)
    group_rows = [{'group': g, 'uptime_pct': round(sum(v) / len(v), 3),
                   'devices': len(v)}
                  for g, v in sorted(groups.items())]
    fleet_pct = round(sum(covered_pcts) / len(covered_pcts), 3) if covered_pcts else None
    fleet_target = _as_pct(targets.get('default'))
    fleet_met = (fleet_pct >= fleet_target) if (fleet_pct is not None and fleet_target is not None) else None
    rows.sort(key=lambda r: (r['uptime_pct'] if r['uptime_pct'] is not None else 101))
    fleet_down = int((1.0 - fleet_pct / 100.0) * days * 86400) if fleet_pct is not None else 0
    respond(200, {
        'days': days, 'generated_ts': now,
        'fleet_uptime_pct': fleet_pct,
        'fleet_sla_target': fleet_target, 'fleet_sla_met': fleet_met,
        'fleet_error_budget': _error_budget(fleet_target, fleet_down, days * 86400),
        'devices': rows, 'groups': group_rows,
    })


def handle_sla_targets_get():
    """GET /api/fleet/sla-targets — the configured SLA targets (default / per
    group / tag / device). Auth: require_auth."""
    require_auth()
    targets = (load(CONFIG_FILE) or {}).get('sla_targets') or {}
    respond(200, {
        'default': targets.get('default'),
        'groups':  targets.get('groups') or {},
        'tags':    targets.get('tags') or {},
        'devices': targets.get('devices') or {},
    })


def handle_sla_targets_put():
    """PUT /api/fleet/sla-targets — set SLA targets. Admin-only. Body accepts
    {default, groups:{name:pct}, tags:{name:pct}, devices:{id:pct}}; each pct is
    validated to (0,100]. A null/absent value clears that level."""
    actor = require_admin_auth()
    if method() != 'PUT':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    clean = {}
    d = _as_pct(body.get('default'))
    if d is not None:
        clean['default'] = d
    for level in ('groups', 'tags', 'devices'):
        src = body.get(level) or {}
        if not isinstance(src, dict):
            continue
        out = {}
        for k, v in list(src.items())[:500]:
            p = _as_pct(v)
            if p is not None:
                out[_sanitize_str(str(k), 128)] = p
        if out:
            clean[level] = out
    with _LockedUpdate(CONFIG_FILE) as cfg:
        cfg['sla_targets'] = clean
    audit_log(actor, 'sla_targets_set',
              f"default={clean.get('default')} groups={len(clean.get('groups') or {})} "
              f"tags={len(clean.get('tags') or {})} devices={len(clean.get('devices') or {})}")
    respond(200, {'ok': True, 'sla_targets': clean})


def handle_fleet_capacity():
    """GET /api/fleet/capacity — fleet-wide CPU / memory / disk rollup from the
    latest sysinfo of currently-online monitored devices, plus the top
    consumers. Auth: require_auth."""
    require_auth()
    devices = load(DEVICES_FILE) or {}
    devices = _scope_filter_devices(devices)  # v3.5.0 RBAC v2
    now = int(time.time())
    ttl = get_online_ttl()
    cpu, mem, swap = [], [], []
    disk_used = disk_total = 0.0
    top_cpu, top_mem, top_disk = [], [], []
    counted = 0
    for dev_id, dev in devices.items():
        if not isinstance(dev, dict) or dev.get('monitored') is False:
            continue
        if (now - dev.get('last_seen', 0)) >= ttl:
            continue  # only reporting devices contribute
        si = dev.get('sysinfo') or {}
        name = dev.get('name', dev_id)
        counted += 1
        c, m, s = si.get('cpu_percent'), si.get('mem_percent'), si.get('swap_percent')
        if isinstance(c, (int, float)): cpu.append(c); top_cpu.append((name, c, dev_id))
        if isinstance(m, (int, float)): mem.append(m); top_mem.append((name, m, dev_id))
        if isinstance(s, (int, float)): swap.append(s)
        worst = None
        for mnt in (si.get('mounts') or []):
            if not isinstance(mnt, dict):
                continue
            ug, tg, pc = mnt.get('used_gb'), mnt.get('total_gb'), mnt.get('percent')
            if isinstance(ug, (int, float)): disk_used += ug
            if isinstance(tg, (int, float)): disk_total += tg
            if isinstance(pc, (int, float)) and (worst is None or pc > worst):
                worst = pc
        if worst is not None:
            top_disk.append((name, worst, dev_id))

    def _agg(vals):
        return ({'avg': round(sum(vals) / len(vals), 1), 'max': round(max(vals), 1)}
                if vals else {'avg': None, 'max': None})

    def _top(lst, n=5):
        return [{'device_id': d, 'name': nm, 'value': round(v, 1)}
                for nm, v, d in sorted(lst, key=lambda x: -x[1])[:n]]

    respond(200, {
        'generated_ts':    now,
        'devices_counted': counted,
        'cpu':    _agg(cpu),
        'memory': _agg(mem),
        'swap':   _agg(swap),
        'disk':   {'used_gb': round(disk_used, 1), 'total_gb': round(disk_total, 1),
                   'percent': round(100.0 * disk_used / disk_total, 1) if disk_total > 0 else None},
        'top_cpu':    _top(top_cpu),
        'top_memory': _top(top_mem),
        'top_disk':   _top(top_disk),
    })


def handle_fleet_anomalies():
    """GET /api/fleet/anomalies?z=N — statistical resource anomalies across the
    fleet. For each monitored device, fits a mean/stdev baseline over its daily
    metric history and flags the latest value when it deviates >= z standard
    deviations. A model-free complement to the AI anomaly scan. Auth:
    require_auth."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    try:
        z = float((qs.get('z') or ['2.5'])[0])
    except ValueError:
        z = 2.5
    z = max(1.5, min(6.0, z))
    # W4-18: seasonal=1 scores against the matching day-of-week × 4-hour bucket
    # instead of a flat all-week baseline (falls back to flat until warmed up).
    seasonal = (qs.get('seasonal') or ['0'])[0] in ('1', 'true', 'yes')
    hist = load(METRICS_HIST_FILE) or {}
    devices = load(DEVICES_FILE) or {}
    devices = _scope_filter_devices(devices)  # v3.5.0 RBAC v2
    out = []
    _detect = anomaly_stats.detect_device_seasonal if seasonal else anomaly_stats.detect_device
    for dev_id, rec in hist.items():
        dev = devices.get(dev_id)
        if not isinstance(dev, dict) or dev.get('monitored') is False:
            continue
        for a in _detect((rec or {}).get('samples') or [], z=z):
            a = dict(a)
            a['device_id'] = dev_id
            a['device_name'] = dev.get('name', dev_id)
            out.append(a)
    out.sort(key=lambda a: -abs(a['z']))
    respond(200, {'threshold_z': z, 'seasonal': seasonal,
                  'generated_ts': int(time.time()), 'anomalies': out})


def _day_status_from_events(events, day_start, day_end):
    """Derive a single day's status from a device's uptime events.

    `events` is the sorted [{ts, online}] transition list. A day is:
      - 'down'    if the device entered the day offline, or went
                  offline at any point during it;
      - 'up'      if the device had data covering the day and was
                  never offline in it;
      - 'unknown' if there is no event at or before the day's end —
                  RemotePower genuinely has no record for that day.
    """
    state_at_start = None     # state as of day_start
    state_seen = None         # any state with ts < day_end
    saw_down = False
    for e in events:
        ts = e.get('ts', 0)
        online = bool(e.get('online'))
        if ts < day_start:
            state_at_start = online
            state_seen = online
        elif ts < day_end:
            state_seen = online
            if not online:
                saw_down = True
        else:
            break
    if state_seen is None:
        return 'unknown'
    if state_at_start is False or saw_down:
        return 'down'
    return 'up'


def handle_fleet_uptime7d():
    """GET /api/fleet/uptime7d — a real 7-day daily up/down status per
    device, derived from uptime.json.

    Days with no recorded data come back 'unknown' — RemotePower does
    not invent history it never recorded. The array is oldest-first;
    the last element is today.

    Only monitored devices are included: a device explicitly set to
    `monitored: false` (decommissioned, dev box, being rebuilt) is
    silenced everywhere else — the attention digest, the alert
    pipeline — and must not appear in the fleet roster stripe either.
    """
    require_auth()
    uptime = load(UPTIME_FILE) or {}
    devices = load(DEVICES_FILE) or {}
    now = int(time.time())
    DAY = 86400
    # Midnight (local) of today, then the 7 day-windows ending with it.
    today_start = now - (now % DAY)
    windows = [(today_start - (6 - i) * DAY,
                today_start - (6 - i) * DAY + DAY) for i in range(7)]
    out = {}
    for dev_id, rec in uptime.items():
        dev = devices.get(dev_id)
        # Skip unmonitored devices, and any uptime record with no
        # matching device entry (stale leftover).
        if dev is None or not dev.get('monitored', True):
            continue
        events = sorted((rec or {}).get('events') or [],
                        key=lambda e: e.get('ts', 0))
        out[dev_id] = [_day_status_from_events(events, s, e)
                       for (s, e) in windows]
    respond(200, {'uptime': out})


def handle_monitor_history(label):
    require_auth()
    label = _sanitize_str(label, 128)
    mh = load(MON_HIST_FILE)
    respond(200, {'label': label, 'history': mh.get(label, [])})


def _slo_target():
    """v5.4.1 (F3): the configured availability SLO target (percent), default 99.9."""
    try:
        t = float(_config_ro().get('slo_target_percent') or 0)
    except (TypeError, ValueError):
        t = 0.0
    return t if 0 < t < 100 else 99.9


def _compute_slo():
    """v5.4.1 (F3): per-monitor availability vs the SLO target + error-budget
    remaining, computed over each monitor's recent check history (count-bounded by
    MAX_MON_HISTORY — so this is "availability over the recent check window", which
    we label honestly). Error budget = the allowed downtime (100 - target); remaining
    is what's left of it; burn > 1 means the budget is blown."""
    target = _slo_target()
    budget = 100.0 - target            # allowed downtime %
    mh = load(MON_HIST_FILE) or {}
    out = []
    for label, hist in mh.items():
        if not isinstance(hist, list) or not hist:
            continue
        checks = [h for h in hist if isinstance(h, dict) and 'ok' in h]
        if not checks:
            continue
        up = sum(1 for h in checks if h.get('ok'))
        avail = 100.0 * up / len(checks)
        consumed = max(0.0, 100.0 - avail)   # actual downtime %
        remaining = 100.0 if budget <= 0 else max(0.0, min(100.0, (budget - consumed) / budget * 100.0))
        burn = 0.0 if budget <= 0 else round(consumed / budget, 3)
        out.append({
            'label':                _sanitize_str(str(label), 128),
            'checks':               len(checks),
            'availability':         round(avail, 4),
            'target':               target,
            'budget_remaining_pct': round(remaining, 2),
            'burn_rate':            burn,
            'meeting_slo':          avail >= target,
        })
    out.sort(key=lambda x: x['budget_remaining_pct'])   # worst budget first
    return {'target': target, 'window': 'recent checks', 'monitors': out}


def handle_slo():
    """GET /api/slo — v5.4.1 (F3): availability SLO + error-budget per monitor.
    The same numbers are exported as Prometheus gauges for Grafana SLO dashboards."""
    require_auth()
    respond(200, _compute_slo())


