def handle_proxmox_snapshot_action() -> None:
    """``POST /api/proxmox/snapshot`` — create / rollback / delete a
    snapshot.

    Body: {"type": "qemu"|"lxc", "vmid": N, "action": "...",
           "name": "...", "description": "...", "confirm": "..." (rollback only)}

    `rollback` and `delete` are destructive. The UI additionally gates
    rollback behind a type-the-guest-name confirmation dialog; `confirm`
    is that typed value, and the server itself checks it against the
    guest's real name (via proxmox_client.guest_name) before rolling back
    — previously this check was UI-only, so a direct API call could roll
    back with no confirmation at all (docs/master-improvement-scoping-
    internal.md #77). The action set is validated here regardless.
    """
    require_admin_auth()
    body = get_json_obj()
    guest_type = body.get('type')
    action = body.get('action')
    name = (body.get('name') or '').strip()
    if guest_type not in ('qemu', 'lxc'):
        respond(400, {'error': 'type must be qemu or lxc'})
        return
    try:
        vmid = int(body.get('vmid'))
    except (ValueError, TypeError):
        respond(400, {'error': 'numeric vmid required'})
        return
    if action not in ('create', 'rollback', 'delete'):
        respond(400, {'error': 'action must be create, rollback or delete'})
        return
    cfg = load(CONFIG_FILE)
    pc = proxmox_client.config_from(cfg)
    if not (pc['enabled'] and proxmox_client.is_configured(pc)):
        respond(400, {'error': 'Proxmox is not configured.'})
        return
    try:
        _pc = {**pc, 'node': proxmox_client.find_guest_node(pc, vmid, guest_type)}
        if action == 'rollback':
            confirm = str(body.get('confirm') or '').strip()
            real_name = proxmox_client.guest_name(_pc, guest_type, vmid)
            if not confirm or not hmac.compare_digest(confirm, real_name):
                respond(400, {'error': 'confirm must exactly match the guest name'})
                return
        if action == 'create':
            result = proxmox_client.create_snapshot(
                _pc, guest_type, vmid, name, body.get('description', '') or '')
        elif action == 'rollback':
            result = proxmox_client.rollback_snapshot(_pc, guest_type, vmid, name)
        else:
            result = proxmox_client.delete_snapshot(_pc, guest_type, vmid, name)
    except proxmox_client.ProxmoxError as e:
        code = 400 if 'invalid' in str(e).lower() else 502
        respond(code, {'error': str(e)})
        return
    try:
        _record_fleet_event('proxmox_action', {
            'guest_type': guest_type, 'vmid': vmid,
            'action': f'snapshot_{action}',
        })
    except Exception:
        pass
    respond(200, result)


def handle_containers_overview() -> None:
    """``GET /api/containers`` — fleet-wide container overview.

    Returns one entry per device that has reported containers, with
    summary counts. The Containers page uses this for the "all
    containers across the fleet" landing view.

    v1.11.4: each entry now carries an ``is_stale`` flag, set when the
    device's last container report is older than the configured TTL
    (``container_stale_ttl``, default 900s). The UI uses this to badge
    stale rows.
    """
    require_auth()
    devices = load(DEVICES_FILE)
    devices = _scope_filter_devices(devices)  # v3.5.0 RBAC v2
    store = load(CONTAINERS_FILE)
    ttl = get_container_stale_ttl()
    now = int(time.time())
    # v3.0.1: respect per-device ignores set by the user from the Containers page
    ignored_devs = _ignored_keys('devices')
    ignored_stale = _ignored_keys('stale_containers')
    out = []
    for dev_id, entry in store.items():
        if dev_id not in devices:
            continue
        # If the user has ignored this device entirely, skip it.
        if dev_id in ignored_devs:
            continue
        items = entry.get('items', []) if isinstance(entry, dict) else []
        ts = entry.get('ts', 0) if isinstance(entry, dict) else 0
        is_stale = containers_mod.is_stale(ts, now, ttl)
        # If the device is stale AND the user has ignored its stale state, skip.
        # We use a `<device_id>/<empty>` key to mark "ignore this device when stale".
        if is_stale and f"{dev_id}/" in ignored_stale:
            continue
        out.append({
            'device_id':   dev_id,
            'name':        devices[dev_id].get('name', dev_id),
            'os':          devices[dev_id].get('os', ''),
            'reported_at': ts,
            'is_stale':    is_stale,
            'summary':     containers_mod.summarise(items),
        })
    out.sort(key=lambda r: r['name'].lower())
    respond(200, out)


def handle_device_containers_clear(dev_id: str) -> None:
    """``DELETE /api/devices/{id}/containers`` — clear stored container data.

    v1.11.4: useful in two scenarios:

    1. **Decommissioning a host** but you want to keep the device record
       around (e.g. agentless conversion). The container entry would
       otherwise sit forever in ``containers.json`` and keep showing up
       with whatever its last-known list was.
    2. **You ran ``docker rm`` on a container and don't want to wait the
       ~5 minutes for the next heartbeat.** Clearing forces the
       Containers page to show "no data" until the next report rebuilds
       the list with current state.

    This is *not* a way to suppress webhooks — the
    ``container_stopped`` / ``container_restarting`` webhooks have
    already fired by the time you'd hit this. It's purely a cosmetic /
    cleanup operation against the stored snapshot. If a live agent is
    still polling, the next heartbeat will repopulate the list within
    one ``CONTAINER_CHECK_EVERY`` window.

    Also clears the ``containers_stale_notified`` flag so the next
    staleness can fire a fresh webhook (without this you'd have to
    wait for a fresh report → stale again before re-firing).

    Args:
        dev_id: Enrolled device ID.
    """
    actor = require_admin_auth()
    if method() != 'DELETE':
        respond(405, {'error': 'Method not allowed'})
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    devices = load(DEVICES_FILE)
    if dev_id not in devices:
        respond(404, {'error': 'Device not found'})

    store = load(CONTAINERS_FILE)
    had_entry = dev_id in store
    store.pop(dev_id, None)
    save(CONTAINERS_FILE, store)

    # Also clear any lingering stale-notified flag so the next time this
    # device goes stale we generate a fresh webhook rather than thinking
    # we already notified.
    cfg = load(CONFIG_FILE)
    notified = cfg.get('containers_stale_notified') or {}
    if isinstance(notified, dict) and dev_id in notified:
        notified.pop(dev_id, None)
        cfg['containers_stale_notified'] = notified
        save(CONFIG_FILE, cfg)

    audit_log(actor, 'containers_clear',
              f'cleared container data for {dev_id} (had_entry={had_entry})')
    respond(200, {'ok': True, 'cleared': had_entry})


# ─── v2.1.0: docker-compose dropdown ────────────────────────────────────────
#
# GET    /api/devices/<id>/compose          — list reported compose projects
# POST   /api/devices/<id>/compose/action   — queue compose:<action>:<dir>
#
# Projects are reported by the agent in its heartbeat (see
# get_compose_projects in client/remotepower-agent). We never read directly
# from a path the operator typed — the action endpoint verifies the
# requested `dir` is one of the paths the agent itself reported, so a
# stale or malicious admin POST can't ask the agent to run compose against
# arbitrary directories.

def handle_device_compose_list(dev_id):
    """List the compose projects this device reported in its heartbeat."""
    require_auth()
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    devices = load(DEVICES_FILE)
    dev = devices.get(dev_id)
    if not dev:
        respond(404, {'error': 'Device not found'})
    projects = dev.get('compose_projects', []) or []
    respond(200, {
        'device_id': dev_id,
        'projects':  projects,
        'reported_at': dev.get('compose_projects_ts', 0),
        # If docker is installed but no projects were found, the agent
        # still reports an empty list — letting the UI distinguish "we
        # checked, none found" from "we never checked, no data".
        'docker_seen': bool(dev.get('compose_projects_ts')),
    })


def handle_device_compose_action(dev_id):
    """Queue a compose:<action>:<dir> command after validating both halves.

    The `dir` is required to be one of the paths the agent itself reported.
    This is the critical security boundary: even an admin token can't ask
    a device to run docker compose against /etc/passwd or some other
    arbitrary directory. The action is restricted to the small fixed set
    COMPOSE_ALLOWED_ACTIONS (also enforced agent-side as belt-and-braces).
    """
    actor = require_perm('containers', [dev_id])   # v3.12.0 RBAC: was admin-only
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    body = get_json_obj()
    action = str(body.get('action', '')).strip().lower()
    project_dir = str(body.get('dir', '')).strip()

    if action not in COMPOSE_ALLOWED_ACTIONS:
        respond(400, {'error': f'action must be one of {list(COMPOSE_ALLOWED_ACTIONS)}'})
    if not project_dir or len(project_dir) > MAX_COMPOSE_PATH_LEN:
        respond(400, {'error': 'dir required'})

    devices = load(DEVICES_FILE)
    dev = devices.get(dev_id)
    if not dev:
        respond(404, {'error': 'Device not found'})
    if dev.get('agentless'):
        respond(400, {'error': 'cannot run compose on agentless device'})

    # Path must match a project the agent reported. This is *the* security
    # check — if it weren't here, a stolen admin token could ask any
    # device for `compose:up:/etc` (which the agent would reject anyway,
    # but defence-in-depth: belt-and-braces).
    reported = dev.get('compose_projects', []) or []
    reported_dirs = {p.get('dir') for p in reported if isinstance(p, dict)}
    # v3.9.0: also accept a compose working dir the agent reported via a
    # running container's label (the Image Updates "Update" button uses these).
    # Still agent-reported — the agent re-validates the path on dequeue.
    for c in ((load(CONTAINERS_FILE) or {}).get(dev_id) or {}).get('items', []) or []:
        cd = isinstance(c, dict) and c.get('compose_dir')
        if cd:
            reported_dirs.add(cd)
    if project_dir not in reported_dirs:
        respond(400, {
            'error': 'dir not in this device\'s reported compose projects '
                     '(refresh the listing if you just added the project)'
        })

    # Queue the command. The agent re-validates everything when it dequeues.
    cmd_payload = f'compose:{action}:{project_dir}'
    cmds = load(CMDS_FILE)
    cmds.setdefault(dev_id, [])
    if cmd_payload not in cmds[dev_id]:
        cmds[dev_id].append(cmd_payload)
    save(CMDS_FILE, cmds)

    log_command(actor, dev_id, dev.get('name', dev_id), cmd_payload)
    audit_log(actor, 'compose_action',
              detail=f'device={dev_id} action={action} dir={project_dir!r}')
    fire_webhook('command_queued', {
        'device_id': dev_id, 'name': dev.get('name', dev_id),
        'command':   cmd_payload, 'actor': actor,
    })
    respond(200, {'ok': True, 'queued': cmd_payload})


# v2.1.1: per-container action endpoint. Matches compose semantics:
# action is allowlisted, container ID is validated against the agent's
# reported listing so the server can't ask the agent to act on an
# arbitrary container. Agent re-validates everything when it dequeues.
# v5.8.0 (B1.1): 'update' pulls the image + recreates a STANDALONE container
# with the same config (compose-managed containers are refused agent-side —
# they update via the compose stack action). Rides the same RBAC + 4-eyes
# ('container' approval kind) + reported-id check as the other verbs.
CONTAINER_ACTION_ALLOWED = ('start', 'stop', 'restart', 'pause', 'unpause',
                            'logs', 'update')


def handle_device_container_action(dev_id):
    actor = require_perm('containers', [dev_id])   # v3.12.0 RBAC: was admin-only
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    body = get_json_obj()
    action = str(body.get('action', '')).strip().lower()
    container_id = str(body.get('container_id', '')).strip()
    runtime = str(body.get('runtime', '')).strip().lower() or 'docker'

    if action not in CONTAINER_ACTION_ALLOWED:
        respond(400, {'error': f'action must be one of {list(CONTAINER_ACTION_ALLOWED)}'})
    if runtime not in ('docker', 'podman'):
        respond(400, {'error': 'runtime must be docker or podman'})
    # Tight ID validation here too — defence in depth even though agent
    # re-validates. Blocks anyone shoving a path-traversal or argv
    # injection through the dashboard before the command ever reaches
    # the wire.
    if not re.match(r'^[a-zA-Z0-9][a-zA-Z0-9_.-]{0,127}$', container_id):
        respond(400, {'error': 'invalid container_id'})

    devices = load(DEVICES_FILE)
    dev = devices.get(dev_id)
    if not dev:
        respond(404, {'error': 'Device not found'})
    if dev.get('agentless'):
        respond(400, {'error': 'cannot run container actions on agentless device'})

    # Verify the container ID matches one this device reported in its
    # last heartbeat. Same security boundary as compose: even an admin
    # token can't ask any device to act on arbitrary container IDs.
    store = load(CONTAINERS_FILE)
    reported = (store.get(dev_id) or {}).get('items', []) or []
    reported_ids = set()
    for c in reported:
        if isinstance(c, dict):
            cid = c.get('id') or c.get('container_id') or c.get('name')
            if cid:
                reported_ids.add(str(cid))
            # Container IDs are reported as 12-char short IDs OR full
            # 64-char IDs depending on runtime. Accept either by also
            # adding any longer ID's 12-char prefix.
            full = c.get('id_full') or c.get('full_id')
            if full and isinstance(full, str):
                reported_ids.add(full)
                reported_ids.add(full[:12])
    if container_id not in reported_ids:
        respond(400, {'error':
                      'container_id not in this device\'s reported container '
                      'list (refresh the listing if you just started it)'})

    cmd_payload = f'container:{runtime}:{action}:{container_id}'
    # v3.14.0: 4-eyes — park container actions for a second admin when enabled.
    if _needs_approval('container'):
        cid = _park_for_approval(dev_id, cmd_payload, actor, 'container')
        respond(202, {'ok': True, 'approval_required': True, 'confirmation_id': cid,
                      'detail': 'Parked — a second admin must approve it.'})
    cmds = load(CMDS_FILE)
    cmds.setdefault(dev_id, [])
    if cmd_payload not in cmds[dev_id]:
        cmds[dev_id].append(cmd_payload)
    save(CMDS_FILE, cmds)

    log_command(actor, dev_id, dev.get('name', dev_id), cmd_payload)
    audit_log(actor, 'container_action',
              detail=f'device={dev_id} runtime={runtime} action={action} '
                     f'container={container_id!r}')
    fire_webhook('command_queued', {
        'device_id': dev_id, 'name': dev.get('name', dev_id),
        'command':   cmd_payload, 'actor': actor,
    })
    respond(200, {'ok': True, 'queued': cmd_payload})



# ─── v1.11.0: TLS/DANE expiry monitor + W1-17 CT (crt.sh) watch ─────────────
# The implementation (watchlist CRUD, sync + cadence probes, edge-triggered
# expiry alerting, and the CT new-certificate watch) lives in the bound module
# tls_ct_handlers.py — see the loader block near the top of this file. The
# TLS_*/CT_*/MAX_TLS_TARGETS constants stay here so tests + other readers
# resolve them as api globals.


# ─── v4.8.0: DMARC posture monitor (DNS-only) ────────────────────────────────

def _dmarc_targets() -> dict:
    s = load(DMARC_TARGETS_FILE)
    return s if isinstance(s, dict) else {}


def _dmarc_results() -> dict:
    s = load(DMARC_RESULTS_FILE)
    return s if isinstance(s, dict) else {}


def handle_dmarc_list() -> None:
    """``GET /api/dmarc/targets`` — domains + last posture result in one round-trip."""
    require_auth()
    targets = _dmarc_targets()
    results = _dmarc_results()
    out = []
    for tid, t in targets.items():
        if not isinstance(t, dict):
            continue
        r = results.get(tid) or {}
        out.append({
            'id':            tid,
            'domain':        t.get('domain', ''),
            'dkim_selector': t.get('dkim_selector', ''),
            'label':         t.get('label', ''),
            'status':        r.get('status', 'unknown'),
            'reasons':       r.get('reasons', []),
            'dmarc':         r.get('dmarc', {}),
            'spf':           r.get('spf', {}),
            'dkim':          r.get('dkim', {}),
            'errors':        r.get('errors', {}),
            'checked_at':    r.get('checked_at', 0),
        })
    rank = {'fail': 0, 'weak': 1, 'unknown': 2, 'ok': 3}
    out.sort(key=lambda x: (rank.get(x['status'], 2), x['domain']))
    respond(200, out)


def handle_dmarc_add() -> None:
    """``POST /api/dmarc/targets`` — add a domain to the watchlist. Admin only."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    parsed = dmarc_monitor.parse_target(get_json_body())
    if parsed is None:
        respond(400, {'error': 'invalid — a valid domain is required'})
    targets = _dmarc_targets()
    if len(targets) >= MAX_DMARC_TARGETS:
        respond(400, {'error': f'max {MAX_DMARC_TARGETS} DMARC domains'})
    new_id = 'dmarc_' + secrets.token_hex(6)
    targets[new_id] = parsed
    save(DMARC_TARGETS_FILE, targets)
    audit_log(actor, 'dmarc_target_add', detail=f'domain={parsed["domain"]}')
    respond(200, {'ok': True, 'id': new_id})


def handle_dmarc_delete(target_id: str) -> None:
    """``DELETE /api/dmarc/targets/{id}`` — remove a domain. Admin only."""
    actor = require_admin_auth()
    if not target_id.startswith('dmarc_'):
        respond(404, {'error': 'target not found'})
    targets = _dmarc_targets()
    if target_id not in targets:
        respond(404, {'error': 'target not found'})
    domain = targets[target_id].get('domain', '?')
    del targets[target_id]
    save(DMARC_TARGETS_FILE, targets)
    results = _dmarc_results()
    results.pop(target_id, None)
    save(DMARC_RESULTS_FILE, results)
    audit_log(actor, 'dmarc_target_delete', detail=f'domain={domain}')
    respond(200, {'ok': True})


def handle_dmarc_scan() -> None:
    """``POST /api/dmarc/scan`` — re-check every domain now (synchronous; DNS is
    fast). Admin only because it makes outbound DNS queries from the server."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    targets = _dmarc_targets()
    results = _dmarc_results()
    for tid, t in targets.items():
        if not isinstance(t, dict):
            continue
        try:
            results[tid] = dmarc_monitor.check_domain(
                t.get('domain', ''), t.get('dkim_selector', ''))
        except Exception as e:
            sys.stderr.write(f'[remotepower] dmarc check failed {t.get("domain")}: {e}\n')
    save(DMARC_RESULTS_FILE, results)
    audit_log(actor, 'dmarc_scan', detail=f'domains={len(targets)}')
    respond(200, {'ok': True, 'scanned': len(targets)})


# ── DMARC aggregate-report (RUA) ingestion via IMAP + mailbox monitor ────────
# The IMAP creds are admin-configured; the report XML is SEMI-UNTRUSTED (anyone
# can email the RUA address), so the parse is DOCTYPE/ENTITY-guarded and the
# decompression is capped in dmarc_monitor. The password is stored under the
# `password` key so _scrub_config_secrets auto-redacts it from /api/config.

def _dmarc_imap_cfg() -> dict:
    c = (load(CONFIG_FILE) or {}).get('dmarc_imap')
    return c if isinstance(c, dict) else {}


def _dmarc_reports_state() -> dict:
    s = load(DMARC_REPORTS_FILE)
    return s if isinstance(s, dict) else {}


def _accumulate_dmarc_report(rep, reports, sources, seen_ids) -> bool:
    """Fold one parsed aggregate report into the running list + per-source
    pass/fail tallies. Skips a report_id already ingested. Returns True if new."""
    m = rep['meta']
    rid = m.get('report_id') or ''
    if rid and rid in seen_ids:
        return False
    if rid:
        seen_ids.add(rid)
    reports.append({
        'org_name': m.get('org_name', ''), 'domain': m.get('domain', ''),
        'report_id': rid, 'policy': m.get('policy', ''),
        'date_begin': m.get('date_begin', 0), 'date_end': m.get('date_end', 0),
        'summary': rep.get('summary', {}), 'received_at': int(time.time()),
    })
    now = int(time.time())
    for r in rep.get('records', []):
        ip = r.get('source_ip') or ''
        if not ip:
            continue
        src = sources.setdefault(ip, {'pass': 0, 'fail': 0, 'domains': [], 'last_seen': 0})
        src['pass' if r.get('pass') else 'fail'] += r.get('count', 0)
        src['last_seen'] = now
        hf = r.get('header_from') or ''
        if hf and hf not in src.get('domains', []):
            src['domains'] = (src.get('domains', []) + [hf])[:10]
    return True


def _fetch_dmarc_reports() -> dict:
    """Connect to the configured IMAP mailbox, ingest NEW RUA reports, and record
    mailbox health. Never raises — failures land in the stored mailbox status."""
    import imaplib
    import email as _email
    import ssl as _ssl
    c = _dmarc_imap_cfg()
    state = _dmarc_reports_state()
    mb = {'checked_at': int(time.time()), 'error': '', 'messages': 0, 'unseen': 0}
    if not c.get('enabled') or not c.get('host'):
        state['mailbox'] = {**mb, 'error': 'IMAP not configured'}
        save(DMARC_REPORTS_FILE, state)
        return {'ok': False, 'error': 'IMAP not configured', 'ingested': 0}
    reports = state.get('reports') or []
    sources = state.get('sources') or {}
    seen_ids = {r.get('report_id') for r in reports if isinstance(r, dict)}
    use_ssl = c.get('use_ssl', True) is not False
    verify_tls = c.get('verify_tls', True) is not False
    host = str(c.get('host'))[:255]
    port = int(c.get('port') or (993 if use_ssl else 143))
    folder = str(c.get('folder') or 'INBOX')[:128]
    last_uid = int(state.get('last_uid') or 0)
    ingested = 0
    M = None
    try:
        _ctx = _ssl.create_default_context()
        if not verify_tls:
            # operator opted out — internal / self-signed IMAP cert (e.g. a
            # Dovecot box with a private CA). Skips hostname + chain verification.
            _ctx.check_hostname = False
            _ctx.verify_mode = _ssl.CERT_NONE
        M = (imaplib.IMAP4_SSL(host, port, ssl_context=_ctx, timeout=20)
             if use_ssl else imaplib.IMAP4(host, port, timeout=20))
        M.login(str(c.get('username') or ''), str(c.get('password') or ''))
        M.select(folder, readonly=False)
        try:
            typ, sd = M.status(folder, '(MESSAGES UNSEEN)')
            if typ == 'OK' and sd and sd[0]:
                txt = sd[0].decode('utf-8', 'replace')
                _mm = re.search(r'MESSAGES\s+(\d+)', txt)
                _uu = re.search(r'UNSEEN\s+(\d+)', txt)
                mb['messages'] = int(_mm.group(1)) if _mm else 0
                mb['unseen'] = int(_uu.group(1)) if _uu else 0
        except Exception:
            pass
        typ, data = M.uid('search', None, 'ALL')
        uids = [int(x) for x in data[0].split() if x.isdigit()] if (typ == 'OK' and data and data[0]) else []
        for uid in [u for u in sorted(uids) if u > last_uid][:300]:
            try:
                typ, md = M.uid('fetch', str(uid), '(RFC822)')
                raw = next((it[1] for it in (md or []) if isinstance(it, tuple) and len(it) == 2), None)
                if raw:
                    for part in _email.message_from_bytes(raw).walk():
                        fn = (part.get_filename() or '').lower()
                        if not (fn.endswith('.gz') or fn.endswith('.zip') or fn.endswith('.xml')):
                            continue
                        payload = part.get_payload(decode=True)
                        if not payload:
                            continue
                        rep = dmarc_monitor.parse_aggregate_report(
                            dmarc_monitor.extract_report_xml(payload, fn))
                        if rep and _accumulate_dmarc_report(rep, reports, sources, seen_ids):
                            ingested += 1
            except Exception as e:
                sys.stderr.write(f'[remotepower] dmarc report uid {uid} failed: {e}\n')
            last_uid = max(last_uid, uid)
    except Exception as e:
        mb['error'] = str(e)[:160]
    finally:
        try:
            if M is not None:
                M.logout()
        except Exception:
            pass
    state.update({'reports': reports[-300:], 'sources': sources, 'mailbox': mb,
                  'last_uid': last_uid, 'last_fetch': int(time.time()),
                  'updated': int(time.time())})
    save(DMARC_REPORTS_FILE, state)
    return {'ok': not mb['error'], 'ingested': ingested, 'mailbox': mb}


def run_dmarc_imap_if_due() -> None:
    """Periodic RUA-report poll (modeled on the integrations cadence). Cheap when
    disabled / not due."""
    c = _dmarc_imap_cfg()
    if not c.get('enabled') or not c.get('host'):
        return
    s = _dmarc_reports_state()
    if int(time.time()) - int(s.get('last_fetch', 0) or 0) < max(300, int(c.get('interval', 900) or 900)):
        return
    try:
        _fetch_dmarc_reports()
    except Exception as e:
        sys.stderr.write(f'[remotepower] dmarc imap poll failed: {e}\n')


def handle_dmarc_reports() -> None:
    """``GET /api/dmarc/reports`` — ingested RUA reports + per-source tallies +
    mailbox status."""
    require_auth()
    s = _dmarc_reports_state()
    reports = sorted((s.get('reports') or []),
                     key=lambda r: r.get('received_at', 0), reverse=True)[:100]
    src = s.get('sources') or {}
    sources = sorted(([{'ip': ip, **v} for ip, v in src.items() if isinstance(v, dict)]),
                     key=lambda x: x.get('fail', 0) + x.get('pass', 0), reverse=True)[:200]
    respond(200, {'reports': reports, 'sources': sources,
                  'mailbox': s.get('mailbox') or {}, 'updated': s.get('updated', 0)})


def handle_dmarc_fetch() -> None:
    """``POST /api/dmarc/fetch`` — pull new RUA reports from IMAP now. Admin only."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    res = _fetch_dmarc_reports()
    audit_log(actor, 'dmarc_fetch',
              detail=f"ingested={res.get('ingested', 0)} err={res.get('error') or 'none'}")
    respond(200, res)


def handle_dmarc_imap_get() -> None:
    """``GET /api/dmarc/imap`` — IMAP config, password redacted. Admin only."""
    require_admin_auth()
    c = _dmarc_imap_cfg()
    respond(200, {
        'enabled':  bool(c.get('enabled')),
        'host':     c.get('host', ''),
        'port':     int(c.get('port') or 993),
        'username': c.get('username', ''),
        'folder':   c.get('folder', 'INBOX'),
        'use_ssl':  c.get('use_ssl', True) is not False,
        'verify_tls': c.get('verify_tls', True) is not False,
        'interval': int(c.get('interval', 900) or 900),
        'password_set': bool(c.get('password')),
    })


def handle_dmarc_imap_save() -> None:
    """``POST /api/dmarc/imap`` — save IMAP config (admin). A blank password keeps
    the stored one."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    host = _no_ctrl(_sanitize_str(body.get('host', ''), 255)).strip()
    try:
        port = int(body.get('port') or 993)
    except (TypeError, ValueError):
        port = 993
    if not (1 <= port <= 65535):
        respond(400, {'error': 'port must be 1-65535'})
    try:
        interval = max(300, int(body.get('interval', 900) or 900))
    except (TypeError, ValueError):
        interval = 900
    with _LockedUpdate(CONFIG_FILE) as cfg:
        cur = cfg.get('dmarc_imap') if isinstance(cfg.get('dmarc_imap'), dict) else {}
        new_pw = body.get('password')
        cfg['dmarc_imap'] = {
            'enabled':  bool(body.get('enabled')),
            'host':     host, 'port': port,
            'username': _no_ctrl(_sanitize_str(body.get('username', ''), 255)),
            'folder':   _no_ctrl(_sanitize_str(body.get('folder', 'INBOX') or 'INBOX', 128)),
            'use_ssl':  body.get('use_ssl', True) is not False,
            'verify_tls': body.get('verify_tls', True) is not False,
            'interval': interval,
            'password': (str(new_pw)[:512] if new_pw else cur.get('password', '')),
        }
    audit_log(actor, 'dmarc_imap_save', detail=f'host={host} enabled={bool(body.get("enabled"))}')
    respond(200, {'ok': True})


def handle_dmarc_clear() -> None:
    """``DELETE /api/dmarc/reports`` — wipe ingested RUA reports, per-source
    tallies and mailbox state, and reset the IMAP UID cursor so a later fetch
    re-ingests from scratch. Admin only. The IMAP *config* is left untouched."""
    actor = require_admin_auth()
    if method() != 'DELETE':
        respond(405, {'error': 'Method not allowed'})
    save(DMARC_REPORTS_FILE, {})
    audit_log(actor, 'dmarc_reports_clear',
              detail='cleared ingested DMARC reports + sources + mailbox state')
    respond(200, {'ok': True})


def handle_mailflow_get() -> None:
    """``GET /api/mailflow`` — W4-16 mail round-trip config, IMAP password
    redacted to a boolean. Admin only. Also returns the last probe result."""
    require_admin_auth()
    c = (load(CONFIG_FILE) or {}).get('mailflow')
    c = c if isinstance(c, dict) else {}
    st = load(MAILFLOW_STATE_FILE) or {}
    respond(200, {
        'enabled':       bool(c.get('enabled')),
        'to_address':    c.get('to_address', ''),
        'imap_host':     c.get('imap_host', ''),
        'imap_port':     int(c.get('imap_port') or 993),
        'imap_user':     c.get('imap_user', ''),
        'imap_folder':   c.get('imap_folder', 'INBOX'),
        'imap_ssl':      c.get('imap_ssl', True) is not False,
        'imap_verify_tls': c.get('imap_verify_tls', True) is not False,
        'max_latency_seconds': int(c.get('max_latency_seconds') or 300),
        'imap_password_set': bool(c.get('imap_password')),
        'last_latency':  st.get('last_latency'),
        'last_ok_ts':    st.get('last_ok_ts'),
        'pending':       bool(st.get('pending_token')),
        'alerted':       bool(st.get('alerted')),
    })


def handle_mailflow_save() -> None:
    """``POST /api/mailflow`` — save the round-trip config (admin). Blank IMAP
    password keeps the stored one."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    to_addr = _no_ctrl(_sanitize_str(body.get('to_address', ''), 255)).strip()
    imap_host = _no_ctrl(_sanitize_str(body.get('imap_host', ''), 255)).strip()
    try:
        port = int(body.get('imap_port') or 993)
    except (TypeError, ValueError):
        port = 993
    if not (1 <= port <= 65535):
        respond(400, {'error': 'imap_port must be 1-65535'})
    try:
        max_lat = max(30, int(body.get('max_latency_seconds') or 300))
    except (TypeError, ValueError):
        max_lat = 300
    if body.get('enabled') and (not to_addr or '@' not in to_addr):
        respond(400, {'error': 'a valid to_address is required to enable'})
    with _LockedUpdate(CONFIG_FILE) as cfg:
        cur = cfg.get('mailflow') if isinstance(cfg.get('mailflow'), dict) else {}
        new_pw = body.get('imap_password')
        cfg['mailflow'] = {
            'enabled':     bool(body.get('enabled')),
            'to_address':  to_addr,
            'imap_host':   imap_host,
            'imap_port':   port,
            'imap_user':   _no_ctrl(_sanitize_str(body.get('imap_user', ''), 255)),
            'imap_folder': _no_ctrl(_sanitize_str(body.get('imap_folder', 'INBOX') or 'INBOX', 128)),
            'imap_ssl':    body.get('imap_ssl', True) is not False,
            'imap_verify_tls': body.get('imap_verify_tls', True) is not False,
            'max_latency_seconds': max_lat,
            'imap_password': (str(new_pw)[:512] if new_pw else cur.get('imap_password', '')),
        }
    audit_log(actor, 'mailflow_save', detail=f'to={to_addr} enabled={bool(body.get("enabled"))}')
    respond(200, {'ok': True})


# ─── v4.8.0: IP reputation (DNSBL / blocklist) monitor ───────────────────────

def _ip_rep_targets() -> dict:
    s = load(IP_REP_TARGETS_FILE)
    return s if isinstance(s, dict) else {}


def _ip_rep_results() -> dict:
    s = load(IP_REP_RESULTS_FILE)
    return s if isinstance(s, dict) else {}


def _ip_rep_dnsbls():
    """Configured blocklist zones, or the built-in defaults."""
    z = (load(CONFIG_FILE) or {}).get('ip_reputation_dnsbls')
    out = []
    if isinstance(z, list):
        for e in z:
            if isinstance(e, dict) and e.get('zone') and ip_reputation.valid_zone(e['zone']):
                out.append({'name': str(e.get('name') or e['zone'])[:60],
                            'zone': str(e['zone'])[:120]})
    return out or ip_reputation.DEFAULT_DNSBLS


def _scan_ip_reputation(targets, results, min_recheck=0, max_ips=None,
                        delay=0.0, budget=None):
    """Check the DUE IP targets and return ``(pending, scanned)``.

    Rate-limit safeguards so the server's resolver is never hammered (DNSBLs
    rate-limit / block bursty queriers):
      - oldest-checked (and never-checked) IPs first, so a large fleet rotates;
      - skip an IP whose last check is younger than ``min_recheck`` seconds;
      - check at most ``max_ips`` IPs per call;
      - stop after ``budget`` wall-clock seconds (keeps a big fleet off the
        heartbeat's back);
      - pause ``delay`` seconds between IPs (politeness spacing).
    Updates ``results`` in place. ``pending`` are (event, payload) tuples to fire
    AFTER this returns — never while holding a lock.
    """
    zones = _ip_rep_dnsbls()
    order = sorted(targets.items(),
                   key=lambda kv: (results.get(kv[0]) or {}).get('checked_at', 0))
    pending, scanned = [], 0
    start = time.monotonic()
    for tid, t in order:
        if not isinstance(t, dict):
            continue
        now = int(time.time())
        last = int((results.get(tid) or {}).get('checked_at', 0) or 0)
        if min_recheck and now - last < min_recheck:
            continue
        if max_ips is not None and scanned >= max_ips:
            break
        if budget is not None and time.monotonic() - start > budget:
            break
        if scanned and delay:
            time.sleep(delay)
        ip = t.get('ip', '')
        prev = results.get(tid) or {}
        was_alerted = bool(prev.get('alerted'))
        streak = int(prev.get('listed_streak', 0) or 0)
        try:
            res = ip_reputation.check_ip(ip, zones)
        except Exception as e:
            sys.stderr.write(f'[remotepower] ip reputation check failed {ip}: {e}\n')
            continue
        res['checked_at'] = int(time.time())
        scanned += 1
        if 'error' in res:
            res['alerted'], res['listed_streak'] = was_alerted, streak
            results[tid] = res
            continue
        new_listed = int(res.get('listed_count', 0) or 0)
        ok = bool(res.get('ok'))
        # Flap dampening: only a CONFIRMED listing (>= IP_REP_CONFIRM consecutive
        # scans) raises an alert, and we only CLEAR on a fully-successful clean
        # scan. A scan with zone errors (e.g. a public-resolver refusal) leaves the
        # streak/alerted state untouched — so transient DNS errors never fire or
        # clear an alert (the source of the earlier spam). No 'name' in the payload
        # (it's not a device) so the inbox/feed don't render the IP twice.
        if new_listed > 0:
            streak += 1
        elif ok:
            streak = 0
        res['listed_streak'] = streak
        res['alerted'] = was_alerted
        names = ', '.join(z['name'] for z in res.get('listed_on', [])) or '—'
        if new_listed > 0 and not was_alerted and streak >= IP_REP_CONFIRM:
            res['alerted'] = True
            pending.append(('ip_blacklisted', {
                'ip': ip, 'label': t.get('label', ''),
                'listed_count': new_listed, 'blocklists': names}))
        elif new_listed == 0 and ok and was_alerted:
            res['alerted'] = False
            pending.append(('ip_blacklist_cleared', {
                'ip': ip, 'label': t.get('label', ''),
                'listed_count': 0, 'blocklists': '—'}))
        results[tid] = res
    return pending, scanned


def handle_reputation_list() -> None:
    """``GET /api/reputation/targets`` — IP targets + last DNSBL result."""
    require_auth()
    targets = _ip_rep_targets()
    results = _ip_rep_results()
    out = []
    for tid, t in targets.items():
        if not isinstance(t, dict):
            continue
        r = results.get(tid) or {}
        out.append({
            'id': tid, 'ip': t.get('ip', ''), 'label': t.get('label', ''),
            'listed_count': r.get('listed_count', 0), 'listed_on': r.get('listed_on', []),
            'errors': r.get('errors', {}), 'error': r.get('error', ''),
            'checked_at': r.get('checked_at', 0),
        })
    out.sort(key=lambda x: (-(x['listed_count'] or 0), x['ip']))
    respond(200, {'targets': out, 'dnsbls': _ip_rep_dnsbls()})


def handle_reputation_add() -> None:
    """``POST /api/reputation/targets`` — monitor an IPv4 address. Admin only."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    parsed = ip_reputation.parse_target(get_json_body())
    if parsed is None:
        respond(400, {'error': 'invalid — a valid IPv4 address is required'})
