    if len(targets) >= MAX_RESOLVER_TARGETS:
        respond(400, {'error': f'max {MAX_RESOLVER_TARGETS} targets'})
    new_id = 'rslv_' + secrets.token_hex(6)
    targets[new_id] = {'name': name, 'type': rtype, 'label': label}
