def handle_ai_anomaly():
    """POST /api/ai/anomaly — on-demand AI scan of the fleet for anomalies."""
    actor = require_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    devices = load(DEVICES_FILE) or {}
    ttl = get_online_ttl()
    now = int(time.time())
    lines = []
    for dev_id, dev in list(devices.items())[:200]:
        si = dev.get('sysinfo') or {}
        online = (now - dev.get('last_seen', 0)) <= ttl
        parts = [f"name={dev.get('name', dev_id)}",
                 f"os={dev.get('os','?')}",
                 f"online={online}"]
        for k in ('cpu_percent', 'mem_percent', 'disk_percent', 'swap_percent'):
            if isinstance(si.get(k), (int, float)):
                parts.append(f"{k}={si[k]}")
        if si.get('loadavg_1m') is not None:
            parts.append(f"load1={si.get('loadavg_1m')}")
        if si.get('failed_units'):
            parts.append(f"failed_units={len(si['failed_units'])}")
        if si.get('reboot_required'):
            parts.append("reboot_required=true")
        pend = (si.get('packages') or {}).get('upgradable')
        if isinstance(pend, int):
            parts.append(f"pending_updates={pend}")
        lines.append(' '.join(parts))
    summary = '\n'.join(lines) if lines else 'No devices.'
    system, messages = ai_insights.anomaly_prompt(summary)
    result, used, cap = _ai_run(actor, system, messages, 'anomaly')
    anomalies = ai_insights.parse_anomaly_response(result['text'])
    respond(200, {'ok': True, 'anomalies': anomalies, 'scanned': len(lines),
                  'used_today': used, 'daily_cap': cap})


def _compliance_facts():
    """Assemble the fleet 'facts' the compliance checks evaluate, drawn
    entirely from data RemotePower already collects."""
    devices = load(DEVICES_FILE) or {}
    cfg = load(CONFIG_FILE) or {}
    now = int(time.time())

    facts = {'devices': len(devices)}

    # Patches / reboots from sysinfo + config threshold.
    patch_thresh = int((cfg.get('thresholds') or {}).get('patch_alert', 50) or 50)
    pending_bad, reboot = [], []
    for dev in devices.values():
        si = dev.get('sysinfo') or {}
        up = (si.get('packages') or {}).get('upgradable')
        if isinstance(up, int) and up >= patch_thresh:
            pending_bad.append(dev.get('name', '?'))
        if si.get('reboot_required'):
            reboot.append(dev.get('name', '?'))
    facts['pending_patches_devices'] = pending_bad
    facts['reboot_required'] = reboot

    # CVEs (critical+high) from the findings store. Match the CVE Findings page
    # exactly so Compliance can't disagree with it: (1) skip findings for devices
    # that no longer exist (deleted hosts leave stale findings behind), and
    # (2) EXCLUDE findings the operator has ignored/accepted (global or
    # per-device) — an accepted-risk CVE is not "outstanding". Both the CVE page
    # and the Needs-Attention banner already do this; the compliance fact didn't,
    # which made it read e.g. 140 where the page read 76.
    try:
        cve_all = load(CVE_FINDINGS_FILE) or {}
        cve_ignore = load(CVE_IGNORE_FILE) or {}
        cnt = 0
        for did, rec in cve_all.items():
            if did not in devices:          # stale findings for a removed host
                continue
            for f in cve_scanner.apply_ignore_list((rec or {}).get('findings') or [],
                                                   cve_ignore, did):
                if not f.get('ignored') \
                        and str(f.get('severity', '')).lower() in ('critical', 'high'):
                    cnt += 1
        facts['cve_critical_high'] = cnt
    except Exception:
        facts['cve_critical_high'] = 0

    # TLS expiry from the TLS monitor results (≤21 days remaining = expiring).
    try:
        tls_targets = load(TLS_TARGETS_FILE) or {}
        tls_results = load(TLS_RESULTS_FILE) or {}
        expiring = []
        for tid, t in tls_targets.items():
            r = tls_results.get(tid) or {}
            if not r:
                continue
            days = tls_monitor.days_until_expiry(r)
            if isinstance(days, (int, float)) and days <= 21:
                expiring.append(f"{t.get('host', tid)}:{t.get('port', 443)}")
        facts['tls_expiring'] = expiring
        facts['tls_monitored'] = len(tls_targets)
    except Exception:
        facts['tls_expiring'] = []
        facts['tls_monitored'] = 0

    # Backups.
    try:
        bak = load(DATA_DIR / 'backup_state.json') if backend_exists(DATA_DIR / 'backup_state.json') else {}
        facts['failed_backups'] = [k for k, v in bak.items() if not v.get('ok', True)]
        facts['backup_monitors'] = len((cfg.get('backup_monitors') or []))
    except Exception:
        facts['failed_backups'] = []
        facts['backup_monitors'] = 0

    # v3.4.1: end-of-life operating systems (no longer receiving patches).
    try:
        _eol_pkg = load(PACKAGES_FILE) or {}
        eol_hosts = []
        for _did, _d in devices.items():
            if not isinstance(_d, dict) or _d.get('monitored') is False:
                continue
            _v = _device_os_eol(_d, _eol_pkg.get(_did) or {})
            if _v and _v['status'] == 'eol':
                eol_hosts.append(f"{_d.get('name', _did)} ({_v['label']})")
        facts['eol_os'] = eol_hosts
    except Exception:
        facts['eol_os'] = []

    # Console posture.
    facts['mfa_enabled'] = bool(cfg.get('oidc_enabled') and cfg.get('oidc_issuer')) or _any_user_has_totp()
    facts['audit_log_enabled'] = True       # always on in this build
    facts['encrypted_vault'] = True         # cmdb_vault is always encrypted

    # Recent security events (last 30 days) from the immutable fleet-event
    # log. These controls are edge-triggered, so "did this fire recently?"
    # is the honest compliance signal — a clean 30-day window is a genuine
    # pass, not a hardcoded one.
    facts['new_ports'] = []
    facts['ssh_key_changes'] = []
    facts['brute_force'] = []
    # How many devices have a listening-port baseline — i.e. is change
    # detection actually running. (The CC7.1 control passes on capability, not
    # on the raw count of changes.)
    try:
        facts['ports_monitored'] = len(load(PORT_BASELINE_FILE) or {}) \
            if backend_exists(PORT_BASELINE_FILE) else 0
    except Exception:
        facts['ports_monitored'] = 0
    try:
        cutoff = now - 30 * 86400
        events = (load(FLEET_EVENTS_FILE) or {}).get('events', [])
        recent = [e for e in events
                  if isinstance(e, dict) and e.get('ts', 0) >= cutoff]

        def _ev_label(e, with_port=False):
            p = e.get('payload') or {}
            nm = p.get('name') or p.get('device_id') or '?'
            if with_port and p.get('port') is not None:
                return f"{nm}:{p.get('port')}"
            return nm

        facts['new_ports'] = list(dict.fromkeys(
            _ev_label(e, True) for e in recent
            if e.get('event') == 'new_port_detected'))[:50]
        facts['ssh_key_changes'] = list(dict.fromkeys(
            _ev_label(e) for e in recent if e.get('event') == 'ssh_key_added'))
        facts['brute_force'] = list(dict.fromkeys(
            _ev_label(e) for e in recent if e.get('event') == 'brute_force_detected'))
    except Exception:
        pass
    return facts


def _any_user_has_totp():
    try:
        users = load(USERS_FILE) if 'USERS_FILE' in globals() else {}
        return any(u.get('totp_secret') for u in (users or {}).values())
    except Exception:
        return False


def handle_compliance():
    """GET /api/compliance?frameworks=pci,hipaa,soc2 — control-mapped report."""
    require_auth()
    if method() != 'GET':
        respond(405, {'error': 'Method not allowed'})
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    fw_raw = (qs.get('frameworks', [''])[0] or '').strip()
    frameworks = [f for f in fw_raw.split(',') if f in compliance.FRAMEWORKS] or None
    facts = _compliance_facts()
    report = compliance.build_report(facts, frameworks)
    report['generated_ts'] = int(time.time())
    respond(200, report)


