# ── v2.1.7: Device runbooks ───────────────────────────────────────────────
#
# An AI-generated operations document per device. Storage is a single
# JSON file keyed by device ID; small payload (~3-10 KB per runbook),
# small fleet, no need for separate per-device files.
#
# Generation builds a structured snapshot from what we already have —
# sysinfo, watched services, containers, recent commands, journal, CVE
# findings, patch status — and hands it to the model with the
# 'generate_runbook' system prompt. No new agent-side discovery: we
# work with what the heartbeat already brings in. A future Phase 2
# can fire batch-exec discovery scripts before generation if we need
# fuller data.
#
# The endpoint is sync — the request stays open for the model
# round-trip (15-90 s typical). Same nginx fastcgi_read_timeout
# requirement as /api/ai/chat applies.

RUNBOOKS_FILE = DATA_DIR / 'runbooks.json'

# v3.4.0: RAG index. The lexical postings, the corpus chunks, and the
# embedding cache (keyed by content hash) all live in one file, persisted
# via load()/save() so it inherits the same locking + .bak durability as
# every other store. RAG_DOCS_DIR is where deploy-server.sh installs the
# product Markdown docs so the CGI can index them ("how do I do X in
# RemotePower"); it's outside the web root and read-only at runtime. If
# the directory is absent (dev box, fresh install) the docs source is
# simply skipped — never an error.
RAG_INDEX_FILE = DATA_DIR / 'rag_index.json'
RAG_DOCS_DIR   = Path(os.environ.get('RP_DOCS_DIR', str(DATA_DIR / 'docs')))
# v4.1.0: cross-request status for the (synchronous) index-backend migration, so
# the UI / other tabs can see "a migration is running" and a second click is
# rejected instead of corrupting a half-built index.
RAG_MIGRATE_STATUS_FILE = DATA_DIR / 'rag_migrate_status.json'


def _build_runbook_snapshot(dev_id, devices):
    """Assemble the structured snapshot we send to the model.

    Returns a dict that gets JSON-stringified into the user message.
    Compact-ish — bounded to avoid blowing the context budget when
    a device has years of accumulated journal entries.

    `devices` may be either a dict (id → device record, the canonical
    shape) or a list of records. Handle both.
    """
    if isinstance(devices, dict):
        dev = devices.get(dev_id)
    else:
        dev = next((d for d in (devices or [])
                    if isinstance(d, dict) and d.get('id') == dev_id), None)
    if not dev:
        return None

    # v2.1.9: bound the snapshot total to ~8 KB / 2K tokens. The
    # v2.1.7-2.1.8 version was 20-25 KB at the high end — fine for a
    # 32K-context cloud model, fatal for an Ollama 14B-coder default
    # whose context cap of 2048-4096 tokens silently truncated mid-data
    # and left the model with garbage to invent around. The hard caps
    # below are the result of trial; if you're sending to a real
    # frontier model that wants more data, it can have it via direct
    # AI chat (which uses larger budgets), not the runbook generator.

    # Sysinfo: keep but trim to essentials. Full sysinfo can have
    # ~3-5 KB of nested data; we only need the operator-relevant bits.
    si_full = dev.get('sysinfo') or {}
    si = {}
    # v4.6.0 (BUGFIX): read the field names the sanitizer actually persists.
    # The old list ('hostname','load','memory','disks','os_pretty') never
    # existed in safe_si, so the runbook got almost no host context. The
    # sanitizer stores cpu/cpu_count/cpu_percent, loadavg_1m, mem_percent,
    # mem_total_mb, disk_percent, disk_total_gb, swap_percent and mounts.
    for k in ('uptime', 'platform', 'kernel', 'cpu', 'cpu_count', 'cpu_percent',
              'loadavg_1m', 'mem_percent', 'mem_total_mb', 'disk_percent',
              'disk_total_gb', 'swap_percent', 'mounts'):
        if k in si_full:
            si[k] = si_full[k]
    # mounts can be a list with many entries — keep top 5 by usage
    if isinstance(si.get('mounts'), list):
        si['mounts'] = sorted(
            si['mounts'],
            key=lambda d: d.get('percent', 0) if isinstance(d, dict) else 0,
            reverse=True,
        )[:5]

    # Journal: 20 most recent lines (was 40)
    journal = (dev.get('journal') or [])[-20:]
    # Watched services — agent reports state under services_watched_state,
    # but if it hasn't reported yet, fall back to the configured list.
    services = (dev.get('services_watched_state')
                or dev.get('services')
                or [{'name': s} for s in (dev.get('services_watched') or [])])
    # Containers live in CONTAINERS_FILE (the /devices/:id/containers endpoint),
    # not in the device record. Without this lookup the runbook would always
    # say "No containers reported".
    try:
        ctr_store = load(CONTAINERS_FILE) or {}
        ctr_entry = ctr_store.get(dev_id) or {}
        containers = (ctr_entry.get('items') or ctr_entry.get('containers') or [])[:10]
    except Exception:
        containers = []
    last_seen = dev.get('last_seen')

    # Recent command output — last 5 (was 15), output capped to 200 chars
    try:
        # v4.6.0 (BUGFIX): CMD_OUTPUT_FILE[dev_id] is a LIST, not a dict — the
        # old out.get('outputs') raised AttributeError every call (caught below),
        # so recent_commands was always empty in the runbook snapshot.
        out = load(CMD_OUTPUT_FILE).get(dev_id) or []
        recent_cmds = out[-5:] if isinstance(out, list) else []
    except Exception:
        recent_cmds = []
    recent_cmds = [{
        'ts':     c.get('ts'),
        'cmd':    (c.get('cmd') or '')[:120],
        'rc':     c.get('rc'),
        'output': (c.get('output') or '')[:200],
    } for c in recent_cmds]

    # CVE findings: top 10 (was 20), summary capped to 100 chars (was 200)
    try:
        cve = load(CVE_FINDINGS_FILE).get(dev_id) or {}
        cve_findings = (cve.get('findings') or [])[:10]
    except Exception:
        cve_findings = []
    cve_findings = [{
        'id':       f.get('vuln_id'),
        'severity': f.get('severity'),
        'pkg':      f.get('package'),
        'fixed':    f.get('fixed_version'),
        'summary':  (f.get('summary') or '')[:100],
    } for f in cve_findings if not f.get('ignored')]

    # Patch status — inline in the device dict.
    patches = {
        'patch_status': dev.get('patch_status'),
        'upgradable':   dev.get('upgradable'),
        'last_check':   dev.get('last_patch_check'),
    }

    return {
        'name':           dev.get('name'),
        'os':             dev.get('os'),
        'pkg_manager':    dev.get('pkg_manager'),
        'agent_version':  dev.get('version'),
        'last_seen':      last_seen,
        'group':          dev.get('group'),
        'tags':           dev.get('tags') or [],
        # Notes capped at 500 (was 1000) — runbooks aren't biographies
        'notes':          (dev.get('notes') or '')[:500],
        'ip':             dev.get('ip'),
        'mac':            dev.get('mac'),
        'sysinfo':        si,
        'services':       services,
        'containers':     [{
            'name':    c.get('name'),
            'image':   c.get('image'),
            'state':   c.get('state'),
        } for c in containers],
        'recent_commands': recent_cmds,
        'recent_journal':  journal,
        'cve_findings':   cve_findings,
        'patch_status':   patches,
    }


def handle_runbook_get(dev_id):
    """Return the stored runbook for a device (if any)."""
    require_auth()
    if method() != 'GET':
        respond(405, {'error': 'Method not allowed'})
    runbooks = load(RUNBOOKS_FILE)
    entry = runbooks.get(dev_id)
    if not entry:
        respond(200, {'exists': False})
    respond(200, {'exists': True, **entry})


def handle_runbook_generate(dev_id):
    """Generate a fresh runbook for the device. Sync — model round-trip
    happens during the request, can take 15-90 s. Saves on success."""
    # v5.8.0 (SECURITY): generating a runbook overwrites the shared per-device
    # RUNBOOKS_FILE entry AND spends AI/cost budget (a 15-90s paid LLM call), so it
    # must be gated on a write-capable role — bare require_auth() admitted the
    # read-only roles (viewer/mcp/auditor/finance). Matches handle_runbook_delete.
    actor = require_write_role('generate a runbook')
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})

    cfg = _ai_cfg()
    if not cfg.get('enabled'):
        respond(400, {'error': 'AI is disabled — enable in Settings → AI assistant'})

    # Rate limit (same per-user-per-day cap as /api/ai/chat)
    allowed, used, cap = _ai_rate_limit_check(actor, cfg)
    if not allowed:
        respond(429, {'error': f'Daily AI request cap reached ({used}/{cap}).'})

    # Build the snapshot
    devices = load(DEVICES_FILE)
    snapshot = _build_runbook_snapshot(dev_id, devices)
    if not snapshot:
        respond(404, {'error': 'Device not found'})

    # Prepend project + fleet context if the operator has it enabled.
    # Runbook quality benefits a lot from fleet awareness ("this is
    # one of N webservers" rather than "this is a Linux box").
    base_system = _resolve_system_prompt('generate_runbook')
    ctx_opts = cfg.get('context') or {}
    fleet = list(devices.values()) if isinstance(devices, dict) else (devices or [])
    system_prompt = ai_context.build_combined_system_prompt(
        base_system,
        devices=fleet,
        include_project=bool(ctx_opts.get('include_project_context', True)),
        include_fleet=bool(ctx_opts.get('include_fleet_context', True)),
        now=int(time.time()),
        ttl=get_online_ttl(),
    )

    # v2.1.9: dump snapshot as compact JSON (no indent — wastes tokens)
    # and cap at 12 KB. The snapshot is already trimmed to ~8 KB by
    # _build_runbook_snapshot; the cap here is belt-and-braces in case
    # an unusual device has extra-large sysinfo fields we didn't trim.
    user_msg = (
        f"Generate a runbook for device '{snapshot['name']}'. "
        f"Use only the fields present in the snapshot below — do not "
        f"infer or invent.\n\n"
        f"```json\n{json.dumps(snapshot, default=str)[:12000]}\n```"
    )

    t0 = time.monotonic()
    _rb_params = _resolve_ai_params('generate_runbook')
    _rb_kwargs = {
        'system':     system_prompt,
        'max_tokens': (_rb_params.get('max_tokens') or 4000),
    }
    for _p in ('temperature', 'top_p', 'num_ctx'):
        if _rb_params.get(_p) is not None:
            _rb_kwargs[_p] = _rb_params[_p]
    result = ai_provider.chat(
        cfg,
        messages=[{'role': 'user', 'content': user_msg}],
        **_rb_kwargs,
    )
    elapsed_ms = int((time.monotonic() - t0) * 1000)

    audit_log(actor, 'runbook_generate',
              detail=f"device={dev_id} ok={result.get('ok')} "
                     f"tokens_in={result.get('tokens_in', 0)} "
                     f"tokens_out={result.get('tokens_out', 0)} "
                     f"elapsed_ms={elapsed_ms}")
    if not result.get('ok'):
        respond(502, {'error': result.get('error', 'AI provider error')})

    # Save under the device ID
    entry = {
        'content':       result['text'],
        'generated_at':  int(time.time()),
        'generated_by':  actor,
        'model':         result.get('model'),
        'tokens_in':     result.get('tokens_in', 0),
        'tokens_out':    result.get('tokens_out', 0),
        'elapsed_ms':    elapsed_ms,
    }
    with _locked_update(RUNBOOKS_FILE) as runbooks:
        runbooks[dev_id] = entry
    respond(200, {'ok': True, 'exists': True, **entry})


def handle_runbook_delete(dev_id):
    """Remove the stored runbook for a device. Idempotent."""
    actor = require_write_role('delete runbooks')
    if method() != 'DELETE':
        respond(405, {'error': 'Method not allowed'})
    existed = False
    with _locked_update(RUNBOOKS_FILE) as runbooks:
        if dev_id in runbooks:
            del runbooks[dev_id]
            existed = True
    audit_log(actor, 'runbook_delete', detail=f"device={dev_id} existed={existed}")
    respond(200, {'ok': True, 'deleted': existed})


# ── v2.2.0: Configuration drift detection ─────────────────────────────────
#
# Per-device file integrity monitoring. The agent computes SHA-256 hashes
# of a watched-files list every DRIFT_EVERY heartbeats and ships them in
# the heartbeat payload. The server compares against the stored baseline
# and emits a `drift_detected` webhook event when hashes diverge.
#
# DESIGN DECISION: agent ships HASHES ONLY, never file contents. Storing
# /etc/sshd_config or /etc/sudoers contents in RemotePower's JSON files
# would be a real secrets-leak surface. To see what changed, the operator
# clicks "Show current" which queues a `cat <path>` command through the
# existing exec mechanism — the diff is then reconstructed from the two
# command outputs.
#
# STORAGE: drift_state.json
# {
#   "<device_id>": {
#     "files": {
#       "<path>": {
#         "current_hash":     "sha256...",
#         "current_size":     12345,
#         "current_mtime":    1700000000,
#         "baseline_hash":    "sha256...",
#         "baseline_size":    12345,
#         "baseline_set_at":  1700000000,
#         "baseline_set_by":  "admin",
#         "first_seen":       1700000000,
#         "last_check":       1700000000,
#         "drift_count":      0,          # incremented each time baseline != current
#         "exists":           true,        # false if agent reported the file missing
#         "history": [
#           {"ts": ..., "hash": "sha256...", "size": ...},
#           ...                            # bounded to last 20 entries
#         ]
#       }
#     }
#   }
# }

DRIFT_STATE_FILE = DATA_DIR / 'drift_state.json'

# v2.2.1: drift content fetch — operator-triggered retrieval of the
# actual file contents on a drifted host, for the diff viewer. By
# default, drift detection ships hashes only. When the operator
# explicitly clicks "Show diff" on a drifted file, the server queues
# `cat <path>` as a regular exec command. When its output comes back
# via the normal output-ingest path, we ALSO mirror it into
# drift_contents.json so the diff viewer can pull it without scanning
# the whole command-output log.
#
# Storage: {device_id: {path: [{ts, content, rc}, ...]}} — last 2
# captures per path kept; older ones evicted so the diff is always
# baseline-capture vs current-capture without unbounded growth.
DRIFT_CONTENTS_FILE = DATA_DIR / 'drift_contents.json'
MAX_DRIFT_CONTENT_CAPTURES = 2          # rolling buffer per path
MAX_DRIFT_CONTENT_BYTES    = 256 * 1024 # cap per capture to bound disk
                                        # /etc/sshd_config is ~3KB,
                                        # /etc/sudoers ~1KB, even
                                        # bloated /etc/hosts <16KB —
                                        # 256KB is generous.

# DRIFT_CONTENT_DENYLIST — paths whose content is NEVER retrievable,
# regardless of operator role. /etc/shadow contains password hashes;
# even a "viewer" operator with drift-fetch permission must not be
# able to pull it. Drift hashes still work for these — the hash tells
# you something changed without revealing what.
DRIFT_CONTENT_DENYLIST = frozenset({
    '/etc/shadow', '/etc/gshadow',
    '/etc/shadow-', '/etc/gshadow-',    # the rotated copies
})

# Default watched files. Operators can override per-device via the UI.
# Conservative list — config files that should rarely change without
# the operator's knowledge, and where a change is operationally
# significant. We deliberately don't watch /etc/passwd or /etc/shadow
# directly because those legitimately change often (every user login
# can update lastlog metadata adjacent to it on some distros). The
# operator can add them via the watched-files override if they want.
DEFAULT_WATCHED_FILES = [
    # ── SSH ──────────────────────────────────────────────────────
    '/etc/ssh/sshd_config',
    # ── Identity / auth ──────────────────────────────────────────
    '/etc/sudoers',
    '/etc/passwd',           # v2.2.6: account list — additions/removals
    '/etc/group',            # v2.2.6: group membership changes
    '/etc/login.defs',       # v2.2.6: password-policy / UID range config
    '/etc/pam.d/sshd',
    '/etc/pam.d/common-auth',# v2.2.6: PAM auth stack
    # ── System / boot ────────────────────────────────────────────
    '/etc/fstab',
    '/etc/crontab',
    '/etc/hosts',
    '/etc/resolv.conf',
    '/etc/nsswitch.conf',
    # ── Package sources ──────────────────────────────────────────
    '/etc/apt/sources.list', # v2.2.6: a changed apt source is a
                             # supply-chain red flag
]

# v2.2.6: how many consecutive heartbeats a watched file must report
# `exists: false` before it's marked dormant. One missed sighting can
# be a transient (file mid-rotation, agent race) — three in a row
# means it's genuinely gone. A dormant file stops counting as drift
# and drops out of the "files with drift" total, but is NOT deleted —
# it's kept with a `dormant` flag so the operator can still see it was
# being watched, and it auto-revives if the file reappears.
DRIFT_MISSING_DORMANT_AFTER = 3

# Maximum history entries kept per file
DRIFT_HISTORY_CAP = 20


# ── v2.4.3: mailbox-count monitor ──────────────────────────────────────────
#
# A lightweight mailbox monitor. The agent counts the regular files in
# one or more directories (the Maildir 'new' folder convention — one
# file per unread message) and reports the numbers in its heartbeat.
# No IMAP, no SMTP, no email content — just counts. A device can be
# "promoted" so its mailbox counts show as a dashboard widget.
MAX_MAILBOX_PATHS    = 20      # paths counted per device
MAX_MAILBOX_PATH_LEN = 512

# ── v2.5.0: custom monitoring scripts ────────────────────────────────────────
#
# Admin-defined bash scripts that run on enrolled devices every 5 minutes.
# Exit code 0 = OK, anything else = FAIL (binary — no MRPE severity levels).
# Scripts are defined server-side, assigned to devices, pushed via heartbeat
# response, executed by the agent with a timeout, and results reported back.
CUSTOM_SCRIPTS_FILE     = DATA_DIR / 'custom_scripts.json'
MAX_CUSTOM_SCRIPTS      = 50       # fleet-wide script definitions
MAX_CUSTOM_SCRIPTS_PER_DEVICE = 10 # scripts assigned to one device
MAX_CUSTOM_SCRIPT_NAME  = 80
MAX_CUSTOM_SCRIPT_DESC  = 256
MAX_CUSTOM_SCRIPT_BODY  = 32 * 1024   # 32 KB per script body
MAX_SCRIPT_OUTPUT       = 4096        # bytes captured from stdout+stderr
CUSTOM_SCRIPT_TIMEOUT   = 30          # seconds; hard cap, not configurable

# ── v2.6.0: Host configuration management ─────────────────────────────────
# Sections the server can push to agents and agents report current state of.
HOST_CONFIG_TEXT_SECTIONS = [
    'repos', 'netplan', 'nmcli', 'resolv_conf', 'hosts', 'sudoers', 'motd',
    'logrotate', 'cron',
]
HOST_CONFIG_STRUCT_SECTIONS = ['services', 'users', 'groups']
HOST_CONFIG_ALL_SECTIONS    = HOST_CONFIG_TEXT_SECTIONS + HOST_CONFIG_STRUCT_SECTIONS
MAX_HOST_CONFIG_SECTION_SIZE = 65536   # 64 KB per text section
HOST_CONFIG_AUDIT_EVERY      = 15      # drift audit cadence in polls (~15 min)
# Current state is stored in separate per-device files, NOT in devices.json,
# to keep devices.json small and fast to read on every API call.
HOST_CONFIG_CURRENT_DIR = DATA_DIR / 'host_config_current'
# v2.7.0: Proxmox snapshot age cache — written when guests are listed,
# read by _compute_attention() to flag stale snapshots.
PROXMOX_SNAPSHOT_CACHE  = DATA_DIR / 'proxmox_snapshot_cache.json'
# v2.8.0: port, SSH key, and brute-force detection state
PORT_BASELINE_FILE      = DATA_DIR / 'port_baseline.json'
SSH_KEY_BASELINE_FILE   = DATA_DIR / 'ssh_key_baseline.json'
BRUTE_FORCE_FILE        = DATA_DIR / 'brute_force.json'
# v3.11.0: edge-trigger state for storage/firewall/timer/new-source-login
# detections, and the fleet software-policy ruleset + evaluated violations.
POSTURE_STATE_FILE        = DATA_DIR / 'posture_state.json'
SOFTWARE_POLICY_FILE      = DATA_DIR / 'software_policy.json'
SOFTWARE_VIOLATIONS_FILE  = DATA_DIR / 'software_violations.json'


def _ingest_mailbox_counts(dev_id, counts):
    """Store the mailbox file counts reported by an agent heartbeat.

    `counts` maps directory path → {count, exists, error}. We store
    the latest snapshot plus a timestamp on the device record under
    `mailbox_state`. Latest-wins; no history kept (a count is a
    point-in-time number, not an event stream).

    v2.4.7: if the device has a mailbox alert threshold set, each
    path's count is compared against it. The check is EDGE-triggered
    — the `mailbox_threshold` webhook fires once when a count crosses
    from below the threshold to at-or-above it, not on every
    heartbeat while it stays high. A per-path `alerted` flag remembers
    the state; it clears when the count drops back below, re-arming
    the alert. This is the same anti-fatigue pattern the metric and
    service alerts use.
    """
    if not isinstance(counts, dict):
        return
    clean = {}
    for path, info in list(counts.items())[:MAX_MAILBOX_PATHS]:
        if not isinstance(path, str) or not isinstance(info, dict):
            continue
        c = info.get('count')
        clean[path[:MAX_MAILBOX_PATH_LEN]] = {
            'count':  int(c) if isinstance(c, int) and c >= 0 else None,
            'exists': bool(info.get('exists')),
            'error':  str(info.get('error'))[:100] if info.get('error') else None,
        }
    # Crossings to fire are collected inside the lock, then the
    # webhooks are fired AFTER the lock is released — fire_webhook does
    # its own file I/O and must never run while we hold the device lock.
    # v5.7.0 perf: single-row _DeviceUpdate, not a whole-store
    # _LockedUpdate(DEVICES_FILE) — this only mutates devices[dev_id], and the
    # whole-store form did an O(fleet) read + full reconcile-save every beat from
    # an MTA host (the sibling ingests were moved off it in b69fb5e; this was
    # missed).
    to_fire = []
    with _DeviceUpdate(dev_id) as devices:
        dev = devices.get(dev_id)
        if dev is None:
            return
        prev_state = dev.get('mailbox_state') or {}
        prev_alerted = prev_state.get('alerted') or {}
        threshold = dev.get('mailbox_threshold')
        alerted = {}
        if isinstance(threshold, int) and threshold > 0:
            for path, info in clean.items():
                cnt = info.get('count')
                was = bool(prev_alerted.get(path))
                if not isinstance(cnt, int):
                    # No usable count (error/missing) — carry the old
                    # state, don't fire and don't re-arm.
                    alerted[path] = was
                    continue
                now_over = cnt >= threshold
                alerted[path] = now_over
                if now_over and not was:
                    to_fire.append({
                        'name':      dev.get('name', dev_id),
                        'device_id': dev_id,
                        'path':      path,
                        'count':     cnt,
                        'threshold': threshold,
                    })
        dev['mailbox_state'] = {
            'counts':      clean,
            'reported_at': int(time.time()),
            'alerted':     alerted,
        }
    for payload in to_fire:
        try:
            fire_webhook('mailbox_threshold', payload)
        except Exception:
            pass


def handle_mailwatch_set(dev_id):
    """POST /api/devices/<id>/mailwatch — configure the mailbox monitor.

    Body: {"paths": ["/var/mail/.../new", ...], "dashboard": true|false}

    `paths` is the list of directories the agent should count files in
    (replaces any existing list — whole-list semantics, like the drift
    watch list). `dashboard` promotes this device so its mailbox counts
    appear as a widget on the Home dashboard.
    """
    require_admin_auth()
    if not _validate_id(dev_id):
        respond(400, {'error': 'invalid device id'})
        return
    body = get_json_obj()
    raw_paths = body.get('paths')
    if not isinstance(raw_paths, list):
        respond(400, {'error': 'paths must be a list'})
        return
    # Normalise: absolute paths only, trimmed, capped, de-duplicated.
    clean_paths = []
    for p in raw_paths[:MAX_MAILBOX_PATHS]:
        if not isinstance(p, str):
            continue
        p = p.strip()
        if not p or not p.startswith('/') or len(p) > MAX_MAILBOX_PATH_LEN:
            continue
        if p not in clean_paths:
            clean_paths.append(p)
    with _LockedUpdate(DEVICES_FILE) as devices:
        dev = devices.get(dev_id)
        if dev is None:
            respond(404, {'error': 'device not found'})
            return
        dev['mailbox_paths'] = clean_paths
        if 'dashboard' in body:
            dev['mailbox_dashboard'] = bool(body['dashboard'])
        # v2.4.7: optional alert threshold. A positive integer arms
        # the mailbox_threshold webhook; 0, null or absent disarms it.
        if 'threshold' in body:
            t = body.get('threshold')
            if isinstance(t, int) and t > 0:
                dev['mailbox_threshold'] = t
            else:
                dev.pop('mailbox_threshold', None)
        # Clearing all paths also clears any stored counts so a stale
        # number doesn't linger on the dashboard.
        if not clean_paths:
            dev.pop('mailbox_state', None)
    respond(200, {'ok': True, 'paths': clean_paths,
                  'dashboard': bool(body.get('dashboard'))})


def handle_mailwatch_overview():
    """GET /api/mailwatch — mailbox monitor state across the fleet.

    Returns one entry per device that has the mailbox monitor
    configured, with its latest counts. The Home dashboard widget
    uses the `dashboard`-promoted subset; the full list backs a
    management view.
    """
    require_auth()
    devices = load(DEVICES_FILE)
    rows = []
    for dev_id, dev in (devices or {}).items():
        paths = dev.get('mailbox_paths') or []
        if not paths:
            continue
        state = dev.get('mailbox_state') or {}
        rows.append({
            'device_id':   dev_id,
            'device_name': dev.get('name', dev_id),
            'paths':       paths,
            'dashboard':   bool(dev.get('mailbox_dashboard')),
            'threshold':   dev.get('mailbox_threshold') or 0,
            'counts':      state.get('counts') or {},
            'reported_at': state.get('reported_at', 0),
        })
    rows.sort(key=lambda r: r['device_name'].lower())
    respond(200, {'devices': rows})


# ── v2.5.0: custom monitoring scripts ─────────────────────────────────────────
#
# Admin-defined bash scripts pushed to enrolled devices and executed every
# 5 minutes by the agent. Exit 0 = OK, anything else = FAIL.
# Storage: custom_scripts.json holds definitions; results land on the device
# record in devices.json so queries don't need a separate join.

def _cs_id():
    """Generate a collision-resistant custom script ID."""
    return 'cs_' + secrets.token_hex(8)


def _load_custom_scripts():
    """Return {id: script_dict}. Missing file → empty dict."""
    return load(CUSTOM_SCRIPTS_FILE) or {}


def _get_custom_scripts_for_device(dev_id):
    """Return list of {id, name, body, timeout} for scripts assigned to dev_id.

    Called from the heartbeat handler; failure must never break heartbeat,
    so the caller wraps it in try/except.
    """
    scripts = _load_custom_scripts()
    result = []
    for s in scripts.values():
        if dev_id in (s.get('assigned_devices') or []):
            result.append({
                'id':      s['id'],
                'name':    s['name'],
                'body':    s['body'],
                'timeout': s.get('timeout', CUSTOM_SCRIPT_TIMEOUT),
            })
    # Enforce per-device cap — return the first N by creation order
    result.sort(key=lambda x: x['id'])
    return result[:MAX_CUSTOM_SCRIPTS_PER_DEVICE]


# ─── v3.4.0: hardware health ingestion (SMART / kernel / inventory) ──────────
# Bound on how much per-disk / per-DIMM data we keep, and the sanitiser caps.
MAX_SMART_DISKS = 32
MAX_DIMMS       = 64
MAX_TEMPS       = 64
# v3.14.0: caps for the new hardware-record sections (match the agent).
MAX_GPUS        = 16
MAX_CERT_FILES  = 256
MAX_ACCOUNTS    = 1024
MAX_UPS         = 8


def _smart_disk_failed(d):
    """The single source of truth for "is this disk failing?" — used by the
    alert (smart_failure event), the home Needs-Attention digest, and the
    device-card badge so all three agree.

    A disk counts as failed when SMART explicitly says so (any health that
    isn't PASSED / OK / UNKNOWN / empty) OR it has non-zero pre-fail sector
    counts. **UNKNOWN is NOT a failure** — it means smartctl couldn't assess
    the drive (USB bridge, virtual disk, no SMART support), which is common and
    must not raise an alert or a Needs-Attention card.
    """
    if not isinstance(d, dict):
        return False
    health = str(d.get('health', '')).upper()
    if health not in ('PASSED', 'OK', 'UNKNOWN', ''):
        return True
    for k in ('reallocated_sectors', 'pending_sectors', 'offline_uncorrectable'):
        v = d.get(k)
        if isinstance(v, (int, float)) and v > 0:
            return True
    return False


# ── v3.6.0: endpoint AV/malware posture ─────────────────────────────────────

def _ingest_av(dev_id, av, now, dev_name=None):
    """Persist the agent's AV posture report. Sanitised, last-writer-wins per
    device. Drives the av-posture attention items AND fires av_infected (v5.1.0)
    on the rising edge of an active infection (ClamAV/rkhunter ``infected``
    count climbing from 0). Edge-triggered against the previously-stored rec so
    it doesn't re-fire every heartbeat; coalescing keeps repeats to one alert."""
    def _clean_tool(t):
        if not isinstance(t, dict):
            return None
        out = {'installed': bool(t.get('installed'))}
        for k in ('db_age_days', 'last_scan_ts', 'infected', 'warnings', 'last_run_ts'):
            v = t.get(k)
            if isinstance(v, (int, float)):
                out[k] = int(v)
        return out
    rec = {'collected_at': now}
    for tool in ('clamav', 'rkhunter'):
        c = _clean_tool(av.get(tool))
        if c is not None:
            rec[tool] = c
    prev = _entity_read_one(AV_FILE, dev_id, None) or {}
    _entity_write_one(AV_FILE, dev_id, rec)
    # Edge-trigger av_infected: fire only when a tool's infected count rises
    # above its previously-seen value (so re-reports of a known infection don't
    # re-fire, and a first sighting on a never-seen host still alerts). This is
    # the post-lock heartbeat ingest section (like _ingest_hardware), so a
    # direct fire_webhook is safe — no enclosing _DeviceUpdate lock.
    try:
        nm = dev_name or (device_get(dev_id) or {}).get('name') or dev_id
        for tool in ('clamav', 'rkhunter'):
            new_inf = int((rec.get(tool) or {}).get('infected') or 0)
            old_inf = int((prev.get(tool) or {}).get('infected') or 0)
            if new_inf > 0 and new_inf > old_inf:
                fire_webhook('av_infected', {
                    'device_id': dev_id, 'name': nm,
                    'tool': tool, 'infected': new_inf,
                })
            # v5.4.1: edge-trigger av_warning on the rising warnings count
            # (rkhunter [Warning] lines; ClamAV has no warnings field so it is a
            # no-op for that tool). Same rising-edge + coalesce model so a steady
            # warning count doesn't re-fire every heartbeat. Suppressed when the
            # same tool also reports an active infection this beat (the
            # higher-severity av_infected already alerts — don't double-fire).
            new_w = int((rec.get(tool) or {}).get('warnings') or 0)
            old_w = int((prev.get(tool) or {}).get('warnings') or 0)
            if new_w > 0 and new_w > old_w and new_inf == 0:
                fire_webhook('av_warning', {
                    'device_id': dev_id, 'name': nm,
                    'tool': tool, 'warnings': new_w,
                })
        # v5.6.x: a scan reporting zero infections AND zero warnings across both
        # tools, after a prior scan that had some, auto-resolves the open av
        # alert (av_clean clears av_infected + av_warning via _ALERT_RECOVER_EXTRA).
        new_bad = sum(int((rec.get(t) or {}).get('infected') or 0)
                      + int((rec.get(t) or {}).get('warnings') or 0)
                      for t in ('clamav', 'rkhunter'))
        old_bad = sum(int((prev.get(t) or {}).get('infected') or 0)
                      + int((prev.get(t) or {}).get('warnings') or 0)
                      for t in ('clamav', 'rkhunter'))
        if old_bad > 0 and new_bad == 0:
            fire_webhook('av_clean', {'device_id': dev_id, 'name': nm})
    except Exception as e:
        sys.stderr.write(f"[remotepower] av_infected fire failed dev={dev_id}: {e}\n")


def handle_av_status(dev_id):
    """GET /api/devices/{id}/av — stored AV/malware posture for one host."""
    require_auth()
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    respond(200, {'ok': True, 'av': _entity_read_one(AV_FILE, dev_id, None) or {}})


def handle_av_scan(dev_id):
    """POST /api/devices/{id}/av-scan — queue an on-demand AV scan.

    Body: {tool: clamav|rkhunter}. Gated on the `exec` permission."""
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    actor = require_perm('command', [dev_id])
    tool = str((get_json_obj()).get('tool', 'clamav')).strip().lower()
    if tool == 'clamav':
        cmd = ('which freshclam >/dev/null 2>&1 && freshclam >/dev/null 2>&1; '
               'clamscan -r -i /home /etc /usr/local /tmp 2>&1 | tail -n 60')
    elif tool == 'rkhunter':
        cmd = ('rkhunter --update >/dev/null 2>&1; '
               'rkhunter -c --sk --rwo 2>&1 | tail -n 80')
    else:
        respond(400, {'error': 'tool must be clamav or rkhunter'})
    audit_log(actor, 'av_scan', detail=f'device={dev_id} tool={tool}')
    _queue_command(dev_id, f'exec:{cmd}', actor)   # responds 200 + exits


def _ingest_hardware(dev_id, dev_name, body, now):
    """Persist the agent's SMART / kernel / hardware report and fire
    edge-triggered events (smart_failure, kernel_outdated).

    Stored in hardware.json keyed by device id:
        { dev_id: {smart: [...], kernel: {...}, hardware: {...},
                   ts: <epoch>, _smart_failed: bool, _kernel_old: bool} }
    The two underscore-prefixed booleans are the previous alert states so we
    only fire on a transition (matching every other monitor in this file).
    """
    # v5.0.0: trend/history samples are captured INSIDE the lock but written
    # AFTER it. _maybe_sample_{temp,smart,gpu} each take their own *_HIST_FILE
    # lock, and DATA_DIR shares one SQLite connection — calling them in here
    # nests BEGIN IMMEDIATE and the write is lost (previously swallowed by a
    # try/except). Stash the data, write once the HARDWARE_FILE lock exits.
    temp_sample = None
    smart_sample = None
    gpu_sample = None
    # v5.6.x perf: O(1) per-device read+write via the entity helpers —
    # hardware.json is ENTITY-promoted, and this locked whole-fleet load
    # was the last hot-path whole-blob read on the heartbeat. Only this
    # device's own (serialized) heartbeats write its row; the write is
    # best-effort per _entity_write_one's contract, and the history
    # samples below still land AFTER the row write, outside any lock.
    rec = _entity_read_one(HARDWARE_FILE, dev_id, None) or {}
    events = []

    # ── SMART ────────────────────────────────────────────────────
    if isinstance(body.get('smart'), list):
        disks = []
        failed_devs = []
        for d in body['smart'][:MAX_SMART_DISKS]:
            if not isinstance(d, dict):
                continue
            health = _sanitize_str(str(d.get('health', 'UNKNOWN')), 16).upper()
            entry = {
                'device': _sanitize_str(str(d.get('device', '')), 64),
                'health': health,
                'model':  _sanitize_str(str(d.get('model', '')), 64),
                'serial': _sanitize_str(str(d.get('serial', '')), 64),
            }
            # Numeric SMART attributes — clamp to sane ints.
            for k in ('reallocated_sectors', 'pending_sectors',
                      'offline_uncorrectable', 'reported_uncorrect',
                      'crc_errors', 'temperature_c', 'power_on_hours'):
                v = d.get(k)
                if isinstance(v, (int, float)) and -1 < v < 1e12:
                    entry[k] = int(v)
            # v3.14.0: SSD/NVMe wear (used %, 0–100).
            w = d.get('wear_pct')
            if isinstance(w, (int, float)) and 0 <= w <= 100:
                entry['wear_pct'] = int(w)
            # Persist the verdict so the UI (and any consumer) reads one
            # authoritative `failed` flag instead of re-deriving the rule
            # client-side — they drifted once already (UNKNOWN handling).
            entry['failed'] = _smart_disk_failed(entry)
            if entry['failed']:
                failed_devs.append(entry['device'])
            disks.append(entry)
        rec['smart'] = disks
        # v3.14.0: snapshot per-disk SMART counters once/UTC-day for trend
        # prediction. Captured here, written after the lock (see top note).
        smart_sample = disks
        # Edge-trigger on the *set* of failed disks, not a single device-level
        # bool: fire when a disk newly enters the failed set. This re-arms as
        # /dev/sdb, /dev/sdc fail after /dev/sda, and — because the key didn't
        # exist before this change — fires once for hosts that were already
        # failing when this shipped (so a pre-existing failure still alerts).
        cur_failed = sorted(set(failed_devs))
        prev_failed = set(rec.get('_smart_failed_devs') or [])
        if set(cur_failed) - prev_failed:
            events.append(('smart_failure', {
                'device_id': dev_id, 'name': dev_name,
                'disks': ', '.join(cur_failed) or 'unknown',
            }))
        elif prev_failed and not cur_failed:
            # v5.6.x: every previously-failing disk is healthy again (or was
            # replaced) — auto-resolve the open smart_failure alert.
            events.append(('smart_recovered', {
                'device_id': dev_id, 'name': dev_name,
            }))
        rec['_smart_failed_devs'] = cur_failed
        rec['_smart_failed'] = bool(cur_failed)   # kept for back-compat

    # ── kernel / livepatch ───────────────────────────────────────
    if isinstance(body.get('kernel'), dict):
        k = body['kernel']
        kern = {
            'running':          _sanitize_str(str(k.get('running', '')), 80),
            'latest_installed': _sanitize_str(str(k.get('latest_installed', '')), 80),
            'reboot_for_kernel': bool(k.get('reboot_for_kernel', False)),
        }
        lp = k.get('livepatch')
        if isinstance(lp, dict):
            kern['livepatch'] = {
                'provider': _sanitize_str(str(lp.get('provider', '')), 40),
                'state':    _sanitize_str(str(lp.get('state', '')), 40),
                'patched':  bool(lp.get('patched', False)),
            }
        rec['kernel'] = kern
        prev_old = rec.get('_kernel_old', False)
        if kern['reboot_for_kernel'] and not prev_old:
            events.append(('kernel_outdated', {
                'device_id': dev_id, 'name': dev_name,
                'running': kern['running'],
                'latest':  kern['latest_installed'],
            }))
        elif prev_old and not kern['reboot_for_kernel']:
            # v5.6.x: rebooted into the current kernel — auto-resolve the
            # open kernel_outdated alert (falling edge, symmetric to above).
            events.append(('kernel_current', {
                'device_id': dev_id, 'name': dev_name,
                'running': kern['running'],
            }))
        rec['_kernel_old'] = kern['reboot_for_kernel']

    # ── passive hardware inventory ───────────────────────────────
    if isinstance(body.get('hardware'), dict):
        hw = body['hardware']
        safe = {}
        sysd = hw.get('system')
        if isinstance(sysd, dict):
            safe['system'] = {kk: _sanitize_str(str(sysd.get(kk, '')), 128)
                              for kk in ('manufacturer', 'product', 'serial')
                              if sysd.get(kk)}
        mem = hw.get('memory')
        if isinstance(mem, list):
            dimms = []
            for d in mem[:MAX_DIMMS]:
                if isinstance(d, dict):
                    dimms.append({kk: _sanitize_str(str(v), 64)
                                  for kk, v in d.items()
                                  if kk in ('locator', 'size', 'type',
                                            'speed', 'serial', 'manufacturer')})
            safe['memory'] = dimms
        temps = hw.get('temps')
        if isinstance(temps, list):
            safe['temps'] = [
                {'label': _sanitize_str(str(t.get('label', '')), 64),
                 'current_c': round(float(t['current_c']), 1)}
                for t in temps[:MAX_TEMPS]
                if isinstance(t, dict) and isinstance(t.get('current_c'), (int, float))
            ]
        raid = hw.get('raid')
        if isinstance(raid, list):
            safe['raid'] = [
                {kk: _sanitize_str(str(r.get(kk, '')), 80)
                 for kk in ('name', 'level', 'state', 'devices')}
                for r in raid[:32] if isinstance(r, dict)
            ]
        rec['hardware'] = safe
        # v4.1.0: temperature alerting — edge-triggered temp_high → temp_normal
        # (temp_normal auto-resolves the open temp_high). Threshold is
        # configurable (default 85 C); fires once when any sensor crosses it.
        try:
            _t_thresh = float(_config_ro().get('temp_alert_threshold_c', 85))
        except (TypeError, ValueError):
            _t_thresh = 85.0
        _hot = [t for t in (safe.get('temps') or [])
                if isinstance(t.get('current_c'), (int, float))
                and t['current_c'] >= _t_thresh]
        # v4.7.0: GPU temperatures participate in the SAME thermal alert — a
        # hot GPU fires temp_high (sensor labelled "GPU: <name>") and cooling
        # back down auto-resolves it via temp_normal, exactly like a board
        # sensor. No separate event/threshold to manage.
        for _g in (body.get('gpus') or []):
            if isinstance(_g, dict) and isinstance(_g.get('temp_c'), (int, float)) \
                    and _g['temp_c'] >= _t_thresh:
                _hot.append({'label': 'GPU: ' + str(_g.get('name') or 'GPU'),
                             'current_c': _g['temp_c']})
        was_hot = bool(rec.get('_temp_high'))
        if _hot and not was_hot:
            _h0 = max(_hot, key=lambda t: t['current_c'])
            events.append(('temp_high', {
                'device_id': dev_id, 'name': dev_name,
                'sensor': _h0.get('label', ''), 'temp_c': _h0.get('current_c'),
                'threshold_c': _t_thresh}))
        elif was_hot and not _hot:
            events.append(('temp_normal', {'device_id': dev_id, 'name': dev_name}))
        rec['_temp_high'] = bool(_hot)
        # v5.0.0: stash the hottest reading across board sensors + SMART disks
        # + GPUs. We sample it AFTER this lock exits — _maybe_sample_temp takes
        # its own THERMAL_HIST_FILE lock, and DATA_DIR shares one SQLite
        # connection, so calling it in here would nest BEGIN IMMEDIATE → abort.
        _tvals = [t['current_c'] for t in (safe.get('temps') or [])
                  if isinstance(t.get('current_c'), (int, float))]
        for _sd in (body.get('smart') or []):
            if isinstance(_sd, dict) and isinstance(_sd.get('temperature_c'), (int, float)):
                _tvals.append(_sd['temperature_c'])
        for _gg in (body.get('gpus') or []):
            if isinstance(_gg, dict) and isinstance(_gg.get('temp_c'), (int, float)):
                _tvals.append(_gg['temp_c'])
        if _tvals:
            temp_sample = max(_tvals)

    # ── v3.14.0: GPU telemetry ───────────────────────────────────
    if isinstance(body.get('gpus'), list):
        gpus = []
        for g in body['gpus'][:MAX_GPUS]:
            if not isinstance(g, dict):
                continue
            entry = {'vendor': _sanitize_str(str(g.get('vendor', '')), 16),
                     'name':   _sanitize_str(str(g.get('name', '')), 96)}
            for k in ('util_pct', 'mem_used_mb', 'mem_total_mb', 'temp_c', 'power_w', 'fan_pct'):
                v = g.get(k)
                if isinstance(v, (int, float)) and -1 < v < 1e9:
                    entry[k] = round(float(v), 1)
            gpus.append(entry)
        rec['gpus'] = gpus
        gpu_sample = gpus   # v4.7.0: trend sparklines — written after the lock

    # ── v3.14.0: local x509 cert-file expiry inventory ───────────
    if isinstance(body.get('cert_files'), list):
        certs = []
        for c in body['cert_files'][:MAX_CERT_FILES]:
            if not isinstance(c, dict):
                continue
            na = c.get('not_after')
            certs.append({
                'path':      _sanitize_str(str(c.get('path', '')), 256),
                'subject':   _sanitize_str(str(c.get('subject', '')), 256),
                'issuer':    _sanitize_str(str(c.get('issuer', '')), 256),
                'not_after': int(na) if isinstance(na, (int, float)) and na >= 0 else 0,
            })
        rec['cert_files'] = certs
        # v3.14.0 / v6.0.1: cert-expiry alerting is ON by default now that it's
        # coalesced to ONE alert per host (soonest cert + a count), edge-triggered
        # and auto-resolving on renewal — the original "noisy" rationale predated
        # that coalescing. Still only the host's OWN service certs, never the CA
        # trust bundle. An operator who explicitly turned it off keeps it off.
        if _config_ro().get('cert_expiry_alerts_enabled', True):
            soon = now + 21 * 86400
            _ca = ('/etc/ssl/certs/', '/etc/pki/ca-trust',
                   '/usr/share/ca-certificates', '/etc/ca-certificates')
            expiring = sorted((c for c in certs
                               if 0 < c['not_after'] <= soon
                               and not str(c['path']).startswith(_ca)),
                              key=lambda c: c['not_after'])
            paths = [c['path'] for c in expiring]
            prev_cert = set(rec.get('_cert_alerted') or [])
            if expiring and any(p not in prev_cert for p in paths):
                s = expiring[0]
                events.append(('cert_file_expiring', {
                    'device_id': dev_id, 'name': dev_name, 'path': s['path'],
                    'days': max(0, int((s['not_after'] - now) / 86400)),
                    'count': len(expiring)}))
            elif prev_cert and not paths:
                # v5.6.x: no host cert is expiring any more (renewed) —
                # auto-resolve the open cert_file_expiring alert.
                events.append(('cert_file_renewed', {
                    'device_id': dev_id, 'name': dev_name}))
            rec['_cert_alerted'] = paths

    # ── v3.14.0: local account posture ───────────────────────────
    if isinstance(body.get('accounts'), list):
        accts = []
        for a in body['accounts'][:MAX_ACCOUNTS]:
            if not isinstance(a, dict):
                continue
            uid = a.get('uid')
            age = a.get('age_days')
            flags = a.get('flags')
            accts.append({
                'user':     _sanitize_str(str(a.get('user', '')), 64),
                'uid':      int(uid) if isinstance(uid, (int, float)) and -1 < uid < 1e9 else -1,
                'shell':    _sanitize_str(str(a.get('shell', '')), 64),
                'home':     _sanitize_str(str(a.get('home', '')), 128),
                'login':    bool(a.get('login')),
                'locked':   bool(a.get('locked')),
                'sudo':     bool(a.get('sudo')),
                'age_days': int(age) if isinstance(age, (int, float)) else None,
                'flags':    [_sanitize_str(str(x), 24) for x in flags[:8]]
                            if isinstance(flags, list) else [],
            })
        rec['accounts'] = accts
        # Alert on unexpected UID-0 accounts (edge-triggered per user).
        rogue = {a['user'] for a in accts if 'uid0' in (a.get('flags') or [])}
        prev_uid0 = set(rec.get('_uid0_alerted') or [])
        for u in (rogue - prev_uid0):
            events.append(('rogue_uid0', {'device_id': dev_id, 'name': dev_name, 'user': u}))
        if prev_uid0 and not rogue:
            # v5.6.x: every unexpected UID-0 account is gone — auto-resolve
            # the open rogue_uid0 alert(s) for this host.
            events.append(('rogue_uid0_cleared', {'device_id': dev_id, 'name': dev_name}))
        rec['_uid0_alerted'] = sorted(rogue)

    # ── v3.14.0: UPS / power ─────────────────────────────────────
    ups_critical_source = None   # (dev_id, ups_name, dev_name) if this heartbeat trips critical
    if isinstance(body.get('ups'), list):
        upses = []
        for u in body['ups'][:MAX_UPS]:
            if not isinstance(u, dict):
                continue
            entry = {'name':   _sanitize_str(str(u.get('name', '')), 64),
                     'driver': _sanitize_str(str(u.get('driver', '')), 16),
                     'status': _sanitize_str(str(u.get('status', '')), 32)}
            for k in ('battery_pct', 'load_pct', 'runtime_s', 'input_v', 'power_w'):
                v = u.get(k)
                if isinstance(v, (int, float)) and -1 < v < 1e7:
                    entry[k] = round(float(v), 1)
            upses.append(entry)
        rec['ups'] = upses
        # Edge-triggered UPS on-battery → on-line (ups_on_line auto-resolves).
        def _ob(u):
            s = (u.get('status') or '')
            return 'OB' in s or 'BATT' in s.upper()
        on_batt = any(_ob(u) for u in upses)
        was_on_batt = bool(rec.get('_ups_on_battery'))
        if on_batt and not was_on_batt:
            u0 = next((u for u in upses if _ob(u)), {})
            events.append(('ups_on_battery', {'device_id': dev_id, 'name': dev_name,
                'ups': u0.get('name', ''), 'battery_pct': u0.get('battery_pct')}))
        elif was_on_batt and not on_batt:
            events.append(('ups_on_line', {'device_id': dev_id, 'name': dev_name,
                'ups': (upses[0].get('name') if upses else '')}))
        rec['_ups_on_battery'] = on_batt

        # v6.1.1: edge-triggered "critical" battery — a THRESHOLD on top of the
        # plain on-battery alert above (battery_pct/runtime_s were always
        # collected but nothing read them for a severity decision). Crossing
        # into critical is what _ups_shutdown_dependents keys off of.
        _ups_cfg = _config_ro()
        batt_thr = int(_ups_cfg.get('ups_critical_battery_pct', 20) or 20)
        runtime_thr = int(_ups_cfg.get('ups_critical_runtime_s', 180) or 180)

        def _crit(u):
            if not _ob(u):
                return False
            bp, rt = u.get('battery_pct'), u.get('runtime_s')
            return ((isinstance(bp, (int, float)) and bp <= batt_thr) or
                    (isinstance(rt, (int, float)) and rt <= runtime_thr))
        is_crit = any(_crit(u) for u in upses)
        was_crit = bool(rec.get('_ups_critical'))
        if is_crit and not was_crit:
            uc = next((u for u in upses if _crit(u)), {})
            events.append(('ups_critical', {'device_id': dev_id, 'name': dev_name,
                'ups': uc.get('name', ''), 'battery_pct': uc.get('battery_pct'),
                'runtime_s': uc.get('runtime_s')}))
            ups_critical_source = (dev_id, uc.get('name', ''), dev_name)
        rec['_ups_critical'] = is_crit

    rec['ts'] = now

    _entity_write_one(HARDWARE_FILE, dev_id, rec)
    # v5.0.0: write the trend/history samples outside the HARDWARE_FILE lock —
    # each self-locks its own *_HIST_FILE and DATA_DIR shares one SQLite
    # connection, so doing this inside the lock nests BEGIN IMMEDIATE and the
    # write is lost. (SMART/GPU previously sampled in-lock under try/except —
    # silently dropped on the SQLite backend.)
    if smart_sample is not None:
        _maybe_sample_smart(dev_id, smart_sample, now)
    if gpu_sample is not None:
        _maybe_sample_gpu(dev_id, gpu_sample, now)
    if temp_sample is not None:
        _maybe_sample_temp(dev_id, temp_sample, now)

    # Fire events outside the lock (fire_webhook does its own I/O).
    for event, payload in events:
        try:
            fire_webhook(event, payload)
        except Exception:
            pass

    if ups_critical_source is not None:
        try:
            _ups_shutdown_dependents(*ups_critical_source)
        except Exception:
            pass


def _ingest_helm(dev_id, dev_name, releases, now):
    """Persist the agent's Helm release listing (visibility only)."""
    if not isinstance(releases, list):
        return
    safe = []
    for rel in releases[:500]:
        if not isinstance(rel, dict):
            continue
        safe.append({
            'name':        _sanitize_str(str(rel.get('name', '')), 128),
            'namespace':   _sanitize_str(str(rel.get('namespace', '')), 128),
            'revision':    _sanitize_str(str(rel.get('revision', '')), 16),
            'status':      _sanitize_str(str(rel.get('status', '')), 32),
            'chart':       _sanitize_str(str(rel.get('chart', '')), 128),
            'app_version': _sanitize_str(str(rel.get('app_version', '')), 64),
            'updated':     _sanitize_str(str(rel.get('updated', '')), 64),
        })
    # v5.6.x perf: single-row entity write (store is ENTITY-promoted).
    _entity_write_one(HELM_FILE, dev_id, {'releases': safe, 'ts': now})


def _ingest_speedtest(dev_id, dev_name, result, now):
    """Store an on-demand speedtest result (most-recent-N per device)."""
    if not isinstance(result, dict):
        return
    entry = {'ts': now}
    if result.get('ok'):
        for k in ('download_mbps', 'upload_mbps', 'ping_ms', 'jitter_ms'):
            v = result.get(k)
            if isinstance(v, (int, float)):
                entry[k] = round(float(v), 2)
        entry['server'] = _sanitize_str(str(result.get('server', '')), 80)
        entry['ok'] = True
    else:
        entry['ok'] = False
        entry['error'] = _sanitize_str(str(result.get('error', 'failed')), 200)
    # v5.6.x perf: single-row entity read+write (store is ENTITY-promoted);
    # only this device's own serialized heartbeats append to its row.
    lst = _entity_read_one(SPEEDTEST_FILE, dev_id, None) or []
    lst.append(entry)
    _entity_write_one(SPEEDTEST_FILE, dev_id, lst[-50:])


def _ingest_netscan(dev_id, dev_name, result, now):
    """Store the latest LAN-discovery result for a device. Cross-reference
    against known device IPs so the UI can flag which hosts are unmanaged."""
    if not isinstance(result, dict) or not result.get('ok'):
        return
    known_ips = set()
    try:
        for d in (load(DEVICES_FILE) or {}).values():
            if d.get('ip'):
                known_ips.add(d['ip'])
    except Exception:
        pass
    hosts = []
    for h in (result.get('hosts') or [])[:512]:
        if not isinstance(h, dict):
            continue
        ip = _sanitize_ip(h.get('ip', ''))
        if not ip:
            continue
        hosts.append({
            'ip':       ip,
            'mac':      _sanitize_mac(h.get('mac', '')),
            'hostname': _sanitize_str(str(h.get('hostname', '')), 128),
            'managed':  ip in known_ips,
        })
    # v5.6.x perf: single-row entity write (store is ENTITY-promoted).
    _entity_write_one(DISCOVERY_FILE, dev_id, {
        'ts':     now,
        'method': _sanitize_str(str(result.get('method', '')), 40),
        'hosts':  hosts,
        })


# Keep ~6 months of daily samples per device — enough for a year-over-year
# feel without unbounded growth (a 50-device fleet ≈ a few MB).
MAX_METRIC_SAMPLES = 185
# Refresh today's already-recorded metrics point at most this often. The
# forecaster fits over one-point-per-UTC-day, so intra-day precision finer than
# this buys nothing — and refreshing on every heartbeat was a full per-device
# entity-row rewrite each beat (write amplification, worst on Postgres).
_METRIC_SAMPLE_REFRESH_SEC = 1800   # 30 min


def _maybe_sample_metrics(dev_id, sysinfo, now):
    """Record at most one metrics sample per device per UTC day.

    Each sample carries the numeric series the forecaster fits over (per-mount
    used/total GB, memory, swap) plus a small state fingerprint the
    "what changed" diff compares (upgradable package count, listening ports,
    reboot-required). Re-running on the same day overwrites that day's sample
    with the latest values, so the series stays one-point-per-day.
    """
    if not sysinfo:
        return
    import datetime as _dt
    day = _dt.datetime.fromtimestamp(now, _dt.timezone.utc).strftime('%Y-%m-%d')

    mounts = []
    for mnt in (sysinfo.get('mounts') or [])[:50]:
        if not isinstance(mnt, dict):
            continue
        pct = mnt.get('percent')
        # v3.13.0: skip stalled / no-usage network shares — recording them as 0%
        # would inject false drops that wreck disk-fill slope forecasting.
        if not isinstance(pct, (int, float)):
            continue
        m = {
            'path':     mnt.get('path', ''),
            'used_gb':  mnt.get('used_gb', 0),
            'total_gb': mnt.get('total_gb', 0),
            'percent':  pct,
        }
        if mnt.get('network'):
            m['network'] = True   # so Trends/forecast can label NFS/SMB shares
        mounts.append(m)

    ports = sorted({f"{p.get('proto','')}/{p.get('port','')}"
                    for p in (sysinfo.get('listening_ports') or [])
                    if isinstance(p, dict)})
    pkgs = ((sysinfo.get('packages') or {}).get('upgradable'))

    sample = {
        'date':         day,
        'ts':           now,
        'mounts':       mounts,
        'mem_percent':  sysinfo.get('mem_percent'),
        'swap_percent': sysinfo.get('swap_percent'),
        # v3.9.0: keep raw loadavg + core count so the Trends page can plot a
        # CPU-load saturation series (load average had no history before this).
        'loadavg_1m':   sysinfo.get('loadavg_1m'),
        'cpu_count':    sysinfo.get('cpu_count'),
        'state': {
            'pkg_upgradable':  pkgs if isinstance(pkgs, int) else None,
            'ports':           ports,
            'reboot_required': bool(sysinfo.get('reboot_required', False)),
            'failed_units':    sorted(sysinfo.get('failed_units') or [])[:50],
        },
    }

    # v5.6.x perf: O(1) single-row read/write (metrics_history is an ENTITY file)
    # instead of a whole-fleet _locked_update that reconstructed EVERY device's
    # sample window per heartbeat just to touch one. Mirrors _record_metrics; the
    # per-device point is refreshed every beat, so a rare lost update under the
    # unlocked RMW self-heals on the next heartbeat.
    rec = _entity_read_one(METRICS_HIST_FILE, dev_id, None) or {'samples': []}
    samples = rec.setdefault('samples', [])
    if samples and samples[-1].get('date') == day:
        # Today's point exists — refresh it at most every ~30 min, not every
        # heartbeat (see _METRIC_SAMPLE_REFRESH_SEC). Skipping avoids a full
        # per-device entity-row rewrite on each beat with no forecast benefit.
        try:
            last_ts = float(samples[-1].get('ts') or 0)
        except (TypeError, ValueError):
            last_ts = 0
        if (now - last_ts) < _METRIC_SAMPLE_REFRESH_SEC:
            return
        samples[-1] = sample          # refresh today's point
    else:
        samples.append(sample)
    rec['samples'] = samples[-MAX_METRIC_SAMPLES:]
    _entity_write_one(METRICS_HIST_FILE, dev_id, rec)


# ─── v3.14.0: predictive disk maintenance (SMART trend) ──────────────────────
MAX_SMART_SAMPLES = 185   # ~6 months of daily per-disk snapshots
_REALLOC_CRIT = 100       # reallocated/pending sectors we treat as "critical"


def _disk_key(d):
    """Stable identity for a disk across samples — serial preferred (device
    path can shuffle across reboots)."""
    return (d.get('serial') or '').strip() or (d.get('device') or '').strip()


MAX_GPU_SAMPLES = 288   # ~24h at the ~5-min hardware cadence


def _maybe_sample_gpu(dev_id, gpus, now):
    """Append a per-GPU telemetry sample (temp / util / mem%) for the GPU-page
    trend sparklines. Keyed by GPU index (the stable nvidia-smi / rocm-smi
    ordering). One sample per hardware-cycle ingest (~5 min), bounded to
    MAX_GPU_SAMPLES. Never prunes a GPU key on a single short report — a host
    can transiently report fewer GPUs — so the trend survives a blip."""
    if not gpus:
        return
    with _locked_update(GPU_HIST_FILE) as store:
        rec = store.setdefault(dev_id, {})
        for idx, g in enumerate(gpus):
            if not isinstance(g, dict):
                continue
            mu, mt = g.get('mem_used_mb'), g.get('mem_total_mb')
            mem_pct = (round(100.0 * mu / mt, 1)
                       if isinstance(mu, (int, float)) and isinstance(mt, (int, float)) and mt
                       else None)
            entry = rec.setdefault(str(idx),
                                   {'name': g.get('name', ''),
                                    'vendor': g.get('vendor', ''), 'samples': []})
            entry['name'] = g.get('name', entry.get('name', ''))
            entry['vendor'] = g.get('vendor', entry.get('vendor', ''))
            entry['samples'].append({'ts': now, 'temp': g.get('temp_c'),
                                     'util': g.get('util_pct'), 'mem': mem_pct})
            entry['samples'] = entry['samples'][-MAX_GPU_SAMPLES:]


MAX_TEMP_SAMPLES = 288   # ~24h at the ~5-min hardware cadence


def _maybe_sample_temp(dev_id, max_c, now):
    """Append the host's hottest temperature reading for the Thermal-page trend
    sparkline. One sample per hardware-cycle ingest (~5 min), bounded to
    MAX_TEMP_SAMPLES. Mirrors `_maybe_sample_gpu`; a no-op when the host
    reported no usable temperature this cycle."""
    if not isinstance(max_c, (int, float)):
        return
    with _locked_update(THERMAL_HIST_FILE) as store:
        entry = store.setdefault(dev_id, {'samples': []})
        entry.setdefault('samples', []).append({'ts': now, 'temp': round(float(max_c), 1)})
        entry['samples'] = entry['samples'][-MAX_TEMP_SAMPLES:]


def _maybe_sample_smart(dev_id, disks, now):
    """Record at most one per-disk SMART snapshot per device per UTC day."""
    if not disks:
        return
    import datetime as _dt
    day = _dt.datetime.fromtimestamp(now, _dt.timezone.utc).strftime('%Y-%m-%d')
    with _locked_update(SMART_HIST_FILE) as store:
        rec = store.setdefault(dev_id, {})
        for d in disks:
            if not isinstance(d, dict):
                continue
            key = _disk_key(d)
            if not key:
                continue
            disk = rec.setdefault(key, {'device': d.get('device', ''),
                                        'model': d.get('model', ''), 'samples': []})
            disk['device'] = d.get('device', disk.get('device', ''))
            disk['model'] = d.get('model', disk.get('model', ''))
            snap = {'date': day, 'ts': now,
                    'realloc': d.get('reallocated_sectors'),
                    'pending': d.get('pending_sectors'),
                    'wear': d.get('wear_pct'),
                    'temp': d.get('temperature_c')}
            s = disk['samples']
            if s and s[-1].get('date') == day:
                s[-1] = snap
            else:
                s.append(snap)
            disk['samples'] = s[-MAX_SMART_SAMPLES:]


def _smart_trend(samples, field):
    """(slope_per_day, latest) for a numeric SMART field across daily samples,
    using the same least-squares fit as the disk-fill forecast. slope is 0 when
    there isn't enough signal."""
    pts = [(s['ts'], s[field]) for s in samples
           if isinstance(s.get(field), (int, float)) and s[field] >= 0]
    if not pts:
        return 0.0, None
    latest = pts[-1][1]
    if len(pts) < 3:
        return 0.0, latest
    t0 = pts[0][0]
    xs = [(t - t0) / 86400.0 for t, _v in pts]
    ys = [v for _t, v in pts]
    slope, _intercept = forecast.linear_fit(xs, ys)
    return slope, latest


def _disk_health_view():
    """Per-disk failure-risk rows from SMART history + the latest hardware rec.

    Combines the reactive verdict (failed / bad sectors present) with a
    predictive trend (growing reallocated/pending sectors, wear trajectory)."""
    hist = load(SMART_HIST_FILE) or {}
    hw_all = load(HARDWARE_FILE) or {}
    devices = _scope_filter_devices(load(DEVICES_FILE) or {})
    rows = []
    for dev_id, dev in devices.items():
        # Telemetry view — show unmonitored hosts' disks too (alerting suppressed).
        disks = (hw_all.get(dev_id) or {}).get('smart') or []
        dhist = hist.get(dev_id) or {}
        for d in disks:
            if not isinstance(d, dict):
                continue
            key = _disk_key(d)
            samples = (dhist.get(key) or {}).get('samples') or []
            reasons = []
            risk = 'low'
            eta_days = None

            realloc = d.get('reallocated_sectors')
            pending = d.get('pending_sectors')
            if d.get('failed') or str(d.get('health', '')).upper() not in ('PASSED', 'OK', 'UNKNOWN', ''):
                risk = 'critical'
                reasons.append('SMART reports failed/pre-fail')

            # Predictive: growing bad sectors.
            for fld, label in (('realloc', 'reallocated'), ('pending', 'pending')):
                slope, latest = _smart_trend(samples, fld)
                if latest and latest > 0:
                    if risk == 'low':
                        risk = 'high'
                    reasons.append(f'{label} sectors = {int(latest)}')
                    if slope > 0:
                        to_crit = (_REALLOC_CRIT - latest) / slope
                        if to_crit > 0:
                            eta = int(to_crit)
                            eta_days = eta if eta_days is None else min(eta_days, eta)
                            reasons.append(f'{label} +{slope:.1f}/day')

            # Predictive: wear trajectory.
            w_slope, w_latest = _smart_trend(samples, 'wear')
            if w_latest is not None and w_latest >= 80:
                if risk == 'low':
                    risk = 'high' if w_latest >= 90 else 'medium'
                reasons.append(f'wear {int(w_latest)}%')
            if w_slope and w_slope > 0 and w_latest is not None and w_latest < 100:
                wear_eta = int((100 - w_latest) / w_slope)
                if wear_eta >= 0:
                    eta_days = wear_eta if eta_days is None else min(eta_days, wear_eta)
                    if risk == 'low':
                        risk = 'medium'
                    reasons.append('wearing out')

            if risk == 'low':
                continue  # only surface at-risk disks
            rows.append({
                'device_id': dev_id, 'device': dev.get('name', dev_id),
                'monitored': dev.get('monitored') is not False,
                'disk': d.get('device', key), 'model': d.get('model', ''),
                'serial': d.get('serial', ''),
                'risk': risk, 'eta_days': eta_days,
                'reallocated': realloc, 'pending': pending,
                'wear_pct': d.get('wear_pct'), 'temperature_c': d.get('temperature_c'),
                'reasons': reasons, 'samples': len((dhist.get(key) or {}).get('samples') or []),
            })
    _order = {'critical': 0, 'high': 1, 'medium': 2, 'low': 3}
    rows.sort(key=lambda r: (_order.get(r['risk'], 9),
                             r['eta_days'] if r['eta_days'] is not None else 1e9,
                             r['device'].lower()))
    return rows


def _disk_tracked_view():
    """Every monitored disk with its current SMART snapshot — so the page can
    show healthy disks (wear %, sector counts, samples accumulating) instead of
    an empty 'nothing at risk' screen. Best-effort, scope-filtered."""
    hist = load(SMART_HIST_FILE) or {}
    hw_all = load(HARDWARE_FILE) or {}
    devices = _scope_filter_devices(load(DEVICES_FILE) or {})
    rows = []
    for dev_id, dev in devices.items():
        # Telemetry view — include unmonitored hosts' disks (alerting suppressed).
        disks = (hw_all.get(dev_id) or {}).get('smart') or []
        dhist = hist.get(dev_id) or {}
        for d in disks:
            if not isinstance(d, dict):
                continue
            key = _disk_key(d)
            rows.append({
                'device_id': dev_id, 'device': dev.get('name', dev_id),
                'monitored': dev.get('monitored') is not False,
                'disk': d.get('device', key), 'model': d.get('model', ''),
                'serial': d.get('serial', ''), 'failed': bool(d.get('failed')),
                'reallocated': d.get('reallocated_sectors'),
                'pending': d.get('pending_sectors'),
                'wear_pct': d.get('wear_pct'), 'temperature_c': d.get('temperature_c'),
                'samples': len((dhist.get(key) or {}).get('samples') or []),
            })
    rows.sort(key=lambda r: (r['device'].lower(), str(r['disk'])))
    return rows


def _unstable_hosts_view(days=7, threshold=3):
    """v3.14.0: hosts that returned-to-online unusually often in the window —
    a reboot/flap-trend proxy from the uptime transition events."""
    uptime = load(UPTIME_FILE) or {}
    devices = _scope_filter_devices(load(DEVICES_FILE) or {})
    now = int(time.time())
    win = now - days * 86400
    rows = []
    for dev_id, dev in devices.items():
        # Telemetry/inventory view — show unmonitored hosts too (alerting suppressed).
        events = (uptime.get(dev_id) or {}).get('events') or []
        prev_online = None
        returns = 0
        for e in events:
            ts = int(e.get('ts', 0))
            online = bool(e.get('online'))
            if prev_online is False and online and ts >= win:
                returns += 1
            prev_online = online
        if returns >= threshold:
            rows.append({
                'device_id': dev_id, 'device': dev.get('name', dev_id),
                'monitored': dev.get('monitored') is not False,
                'restarts': returns, 'days': days,
                'last_boot_reason': dev.get('last_boot_reason', ''),
                'last_boot_reason_at': dev.get('last_boot_reason_at', 0),
            })
    rows.sort(key=lambda r: -r['restarts'])
    return rows


def handle_disk_health():
    """GET /api/fleet/disk-health — predictive health: at-risk disks (SMART
    trend) + hosts restarting unusually often (uptime trend)."""
    require_auth()
    rows = _disk_health_view()
    by = {'critical': 0, 'high': 0, 'medium': 0}
    for r in rows:
        by[r['risk']] = by.get(r['risk'], 0) + 1
    unstable = _unstable_hosts_view()
    tracked = _disk_tracked_view()
    respond(200, {'disks': rows, 'count': len(rows),
                  'critical': by.get('critical', 0), 'high': by.get('high', 0),
                  'medium': by.get('medium', 0),
                  'tracked': tracked, 'tracked_count': len(tracked),
                  'unstable': unstable, 'unstable_count': len(unstable)})


def _maybe_check_disk_predictions():
    """v3.14.0: every ~6h, fire disk_predict_fail for disks newly PREDICTED to
    fail (a SMART trend that projected an ETA) — edge-triggered. Reactive
    failures are already covered by smart_failure; this is the look-ahead."""
    cfg = load(CONFIG_FILE)
    now = int(time.time())
    if now - int(cfg.get('last_disk_predict_check', 0)) < 6 * 3600:
        return
    cfg['last_disk_predict_check'] = now
    save(CONFIG_FILE, cfg)
    try:
        rows = _disk_health_view()
    except Exception:
        return
    state_file = DATA_DIR / 'disk_predict_state.json'
    prev = set((load(state_file) or {}).get('alerted') or [])
    cur, fresh = set(), []
    for r in rows:
        if r.get('eta_days') is None:
            continue  # predictive (has an ETA), not just reactive-critical
        # v4.6.0: don't alert on a disk that's years from failing. A 'medium'
        # disk is only "wearing out" on a slow trajectory; only fire when it's
        # genuinely urgent — reactive high/critical, or a near-term ETA (≤180d).
        # (e.g. 27% SSD wear with a ~700-day ETA should not raise an alert.)
        if r.get('risk') == 'medium' and (r.get('eta_days') or 0) > 180:
            continue
        key = f"{r['device_id']}|{r.get('serial') or r.get('disk')}"
        cur.add(key)
        if key not in prev:
            fresh.append(r)
    save(state_file, {'alerted': sorted(cur)})
    for r in fresh:
        try:
            fire_webhook('disk_predict_fail', {
                'device_id': r['device_id'], 'name': r['device'],
                'disk': r.get('disk', ''), 'eta_days': r.get('eta_days'),
                'reason': '; '.join(r.get('reasons') or [])[:200]})
        except Exception:
            pass


def _ingest_custom_script_results(dev_id, dev_name, results):
    """Store custom script results from a heartbeat and fire edge-triggered alerts.

    `results` is the raw dict from the agent:
        {script_id: {ok: bool, output: str, ran_at: int, duration_ms: int, rc: int}}

    We store results on the device record (devices.json) so the fleet results
    view can read everything in one pass. Alert state (prev_ok) is also stored
    there so we survive server restarts without re-firing alerts.
    """
    scripts = _load_custom_scripts()

    # v4.6.0 (BUGFIX): fire_webhook() opens its own _LockedUpdate on the
    # alerts/fleet-events files. Under the SQLite backend those share one
    # per-directory connection with DEVICES_FILE, so firing inside this lock
    # raises "cannot start a transaction within a transaction" — swallowed by
    # the recorders' try/except, silently dropping every OK↔FAIL alert + event.
    # Collect transitions inside the lock; fire after it exits.
    pending_webhooks = []

    # v5.6.x perf: single-row _DeviceUpdate — mutates only devices[dev_id], so the
    # whole-fleet DEVICES_FILE lock (O(fleet) read + reconcile-save on Postgres)
    # was pure overhead on every heartbeat carrying script results.
    with _DeviceUpdate(dev_id) as devices:
        dev = devices.get(dev_id)
        if not dev:
            return  # device vanished between heartbeat auth and here

        stored = dev.setdefault('custom_script_results', {})
        now = int(time.time())

        for script_id, raw in list(results.items())[:MAX_CUSTOM_SCRIPTS_PER_DEVICE]:
            # Validate the script ID actually belongs to this device
            s = scripts.get(script_id)
            if not s or dev_id not in (s.get('assigned_devices') or []):
                continue  # reject results for unassigned scripts

            ok    = bool(raw.get('ok', False))
            out   = str(raw.get('output', ''))[:MAX_SCRIPT_OUTPUT]
            rc    = int(raw['rc']) if isinstance(raw.get('rc'), int) else (0 if ok else 1)
            ran_at = int(raw['ran_at']) if isinstance(raw.get('ran_at'), int) else now
            dur   = int(raw['duration_ms']) if isinstance(raw.get('duration_ms'), int) else 0

            prev  = stored.get(script_id, {})
            prev_ok = prev.get('ok')   # None on first run

            changed_at = prev.get('changed_at', ran_at)
            if prev_ok is not None and ok != prev_ok:
                changed_at = now

            stored[script_id] = {
                'ok':          ok,
                'output':      out,
                'rc':          rc,
                'ran_at':      ran_at,
                'duration_ms': dur,
                'prev_ok':     prev_ok,
                'changed_at':  changed_at,
            }

            # Fire edge-triggered alerts — only on state transitions, not
            # every failing heartbeat.
            if prev_ok is None:
                # First result — no alert on initial acquisition
                pass
            elif not ok and prev_ok:
                # Transition OK → FAIL
                pending_webhooks.append(('custom_script_fail', {
                    'device_id':   dev_id,
                    'name':        dev_name,
                    'script_id':   script_id,
                    'script_name': s['name'],
                    'output':      out,
                    'rc':          rc,
                }))
            elif ok and not prev_ok:
                # Transition FAIL → OK
                pending_webhooks.append(('custom_script_recover', {
                    'device_id':   dev_id,
                    'name':        dev_name,
                    'script_id':   script_id,
                    'script_name': s['name'],
                }))

        devices[dev_id] = dev
        # devices auto-saved by _locked_update.__exit__

    # Fire transitions now that the DEVICES_FILE lock has been released, so the
    # alert/fleet-event recorders can take their own locks safely.
    for event, payload in pending_webhooks:
        fire_webhook(event, payload)


def _ingest_custom_check_results(dev_id, dev_name):
    """Edge-trigger custom_check_failed / custom_check_recovered from the heartbeat.

    Custom checks (Check catalog: process/port server-side, file/job/log/unit
    agent-side) are otherwise only evaluated when the Checks page is loaded, so a
    failure never paged anyone. Here we evaluate every applicable check against
    the device's freshly-stored sysinfo on each heartbeat and fire on the state
    transition — exactly like _ingest_custom_script_results. Last-known status is
    stored on the device record (dev['custom_check_state']) so we survive a server
    restart without re-firing, and only definitive states ('ok'/'warning'/
    'critical') move the state — 'unknown' (no data yet) is ignored, not a failure.
    """
    defs = (_config_ro() or {}).get('custom_checks') or []
    if not defs:
        return   # zero overhead on the hot path when no custom checks exist

    FAILING = ('critical', 'warning')
    # fire_webhook opens its own alert/fleet-event locks; collect inside the
    # DEVICES_FILE lock and fire after it exits (same nesting rule as scripts).
    pending_webhooks = []
    # v5.6.x perf: single-row _DeviceUpdate, not _locked_update(DEVICES_FILE).
    # This only ever mutates devices[dev_id]; the whole-fleet lock forced an
    # O(fleet) read + reconcile-save on the Postgres backend every heartbeat that
    # has any custom check defined. _DeviceUpdate is a single-row upsert.
    with _DeviceUpdate(dev_id) as devices:
        dev = devices.get(dev_id)
        if not dev:
            return
        prev_state = dev.get('custom_check_state') or {}
        now = int(time.time())
        new_state = {}
        for cdef in defs:
            if not isinstance(cdef, dict) or not _custom_check_applies(cdef, dev_id, dev):
                continue
            cid = str(cdef.get('id') or '')
            if not cid:
                continue
            status, output = _eval_custom_check(cdef, dev)
            if status == 'unknown':
                # No signal this beat — carry the last known state forward so an
                # agent that briefly stops reporting doesn't look like a recovery.
                if cid in prev_state:
                    new_state[cid] = prev_state[cid]
                continue
            prev = prev_state.get(cid) or {}
            prev_status = prev.get('status')
            changed_at = prev.get('changed_at', now) if prev_status == status else now
            new_state[cid] = {'status': status, 'output': str(output)[:200],
                              'changed_at': changed_at}
            cname = cdef.get('name') or cid
            if prev_status is None:
                pass   # first definitive observation — seed silently, no alert
            elif status in FAILING and prev_status == 'ok':
                pending_webhooks.append(('custom_check_failed', {
                    'device_id': dev_id, 'name': dev_name,
                    'check_id': cid, 'check_name': cname,
                    'status': status, 'output': str(output)[:200],
                }))
            elif status == 'ok' and prev_status in FAILING:
                pending_webhooks.append(('custom_check_recovered', {
                    'device_id': dev_id, 'name': dev_name,
                    'check_id': cid, 'check_name': cname,
                }))
        dev['custom_check_state'] = new_state   # bounded to currently-applicable checks
        devices[dev_id] = dev

    for event, payload in pending_webhooks:
        fire_webhook(event, payload)


MAX_MONITORING_PROFILES = 50


def handle_monitoring_profiles():
    """GET /api/monitoring-profiles (list) or POST (create a named bundle of
    custom-script ids). Bundles live in CONFIG_FILE['monitoring_profiles']."""
    if method() == 'GET':
        require_auth()
        cfg = load(CONFIG_FILE) or {}
        respond(200, {'ok': True, 'profiles': cfg.get('monitoring_profiles') or []})
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    actor = require_admin_auth()
    body = get_json_obj()
    name = _sanitize_str(str(body.get('name', '')), 64).strip()
    if not name:
        respond(400, {'error': 'name required'})
    raw_ids = body.get('script_ids') if isinstance(body.get('script_ids'), list) else []
    scripts = _load_custom_scripts()
    script_ids = [str(x) for x in raw_ids if str(x) in scripts][:50]
    if not script_ids:
        respond(400, {'error': 'select at least one valid script'})
    pid = 'mp_' + secrets.token_hex(4)
    with _LockedUpdate(CONFIG_FILE) as cfg:
        profs = cfg.setdefault('monitoring_profiles', [])
        if len(profs) >= MAX_MONITORING_PROFILES:
            respond(400, {'error': f'profile limit reached (max {MAX_MONITORING_PROFILES})'})
        profs.append({'id': pid, 'name': name, 'script_ids': script_ids,
                      'created': int(time.time()), 'created_by': actor})
    audit_log(actor, 'monitoring_profile_create', f'id={pid} name={name} scripts={len(script_ids)}')
    respond(200, {'ok': True, 'id': pid})


def handle_monitoring_profile_delete(pid):
    """DELETE /api/monitoring-profiles/{id}."""
    actor = require_admin_auth()
    if method() != 'DELETE':
        respond(405, {'error': 'Method not allowed'})
    found = False
    with _LockedUpdate(CONFIG_FILE) as cfg:
        profs = cfg.get('monitoring_profiles') or []
        kept = [p for p in profs if p.get('id') != pid]
        found = len(kept) != len(profs)
        cfg['monitoring_profiles'] = kept
    if not found:
        respond(404, {'error': 'profile not found'})
    audit_log(actor, 'monitoring_profile_delete', f'id={pid}')
    respond(200, {'ok': True})


def handle_monitoring_profile_apply():
    """POST /api/monitoring-profiles/apply {profile_id, device_ids} — assign every
    script in the profile to the selected devices (append to assigned_devices)."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    pid = str(body.get('profile_id', ''))
    device_ids = [str(x) for x in (body.get('device_ids') or []) if _validate_id(str(x))][:500]
    if not device_ids:
        respond(400, {'error': 'select at least one device'})
    cfg = load(CONFIG_FILE) or {}
    prof = next((p for p in (cfg.get('monitoring_profiles') or []) if p.get('id') == pid), None)
    if not prof:
        respond(404, {'error': 'profile not found'})
    devices = load(DEVICES_FILE)
    valid = [d for d in device_ids if d in devices]
    applied = 0
    with _LockedUpdate(CUSTOM_SCRIPTS_FILE) as scripts:
        for sid in (prof.get('script_ids') or []):
            sc = scripts.get(sid)
            if not isinstance(sc, dict):
                continue
            assigned = set(sc.get('assigned_devices') or [])
            assigned.update(valid)
            sc['assigned_devices'] = sorted(assigned)
            applied += 1
    audit_log(actor, 'monitoring_profile_apply', f'id={pid} scripts={applied} devices={len(valid)}')
    respond(200, {'ok': True, 'scripts_applied': applied, 'devices': len(valid)})


def handle_custom_scripts_list():
    """GET /api/custom-scripts — list all script definitions (admin + viewer)."""
    require_auth()
    scripts = _load_custom_scripts()
    # Strip body from list view to keep payload small; body is in the detail endpoint
    out = []
    for s in sorted(scripts.values(), key=lambda x: x.get('created_at', 0)):
        out.append({
            'id':               s['id'],
            'name':             s['name'],
            'description':      s.get('description', ''),
            'assigned_devices': s.get('assigned_devices', []),
            'timeout':          s.get('timeout', CUSTOM_SCRIPT_TIMEOUT),
            'created_at':       s.get('created_at', 0),
            'updated_at':       s.get('updated_at', 0),
            'created_by':       s.get('created_by', ''),
        })
    respond(200, {'scripts': out})


def handle_custom_script_get(script_id):
    """GET /api/custom-scripts/:id — full script detail including body."""
    require_auth()
    scripts = _load_custom_scripts()
    s = scripts.get(script_id)
    if not s:
        respond(404, {'error': 'Script not found'})
    respond(200, s)


def handle_custom_script_create():
    """POST /api/custom-scripts — create a new script definition (admin)."""
    actor = require_admin_auth()
    body = get_json_obj()
    scripts = _load_custom_scripts()

    if len(scripts) >= MAX_CUSTOM_SCRIPTS:
        respond(400, {'error': f'Fleet limit of {MAX_CUSTOM_SCRIPTS} scripts reached'})

    name = _sanitize_str(str(body.get('name', '')).strip(), MAX_CUSTOM_SCRIPT_NAME)
    if not name:
        respond(400, {'error': 'name is required'})

    script_body = str(body.get('body', '')).strip()
    if not script_body:
        respond(400, {'error': 'body is required'})
    if len(script_body.encode()) > MAX_CUSTOM_SCRIPT_BODY:
        respond(400, {'error': f'Script body exceeds {MAX_CUSTOM_SCRIPT_BODY // 1024} KB limit'})
    # Reject NUL bytes — they break shell execution
    if '\x00' in script_body:
        respond(400, {'error': 'Script body must not contain NUL bytes'})

    desc = _sanitize_str(str(body.get('description', '')), MAX_CUSTOM_SCRIPT_DESC)

    # Validate assigned_devices: must be strings that look like known device IDs
    raw_devs = body.get('assigned_devices', [])
    if not isinstance(raw_devs, list):
        respond(400, {'error': 'assigned_devices must be a list'})
    devices = load(DEVICES_FILE)
    assigned = []
    for d in raw_devs[:MAX_CUSTOM_SCRIPTS_PER_DEVICE * 10]:
        d = str(d).strip()
        if _validate_id(d) and d in devices:
            assigned.append(d)

    now = int(time.time())
    sid = _cs_id()
    scripts[sid] = {
        'id':               sid,
        'name':             name,
        'description':      desc,
        'body':             script_body,
        'assigned_devices': assigned,
        'timeout':          CUSTOM_SCRIPT_TIMEOUT,
        'created_at':       now,
        'updated_at':       now,
        'created_by':       actor,
    }
    save(CUSTOM_SCRIPTS_FILE, scripts)
    audit_log(actor, 'custom_script_create', f'script_id={sid} name={name}')
    _record_fleet_event('custom_script_create', {
        'name': name, 'script_id': sid, 'device_count': len(assigned)})
    respond(201, scripts[sid])


def handle_custom_script_update(script_id):
    """PUT /api/custom-scripts/:id — update name, body, description, or assignments."""
    actor = require_admin_auth()
    body = get_json_body()
    scripts = _load_custom_scripts()
    s = scripts.get(script_id)
    if not s:
        respond(404, {'error': 'Script not found'})

    if 'name' in body:
        s['name'] = _sanitize_str(str(body['name']).strip(), MAX_CUSTOM_SCRIPT_NAME) or s['name']
    if 'description' in body:
        s['description'] = _sanitize_str(str(body['description']), MAX_CUSTOM_SCRIPT_DESC)
    if 'body' in body:
        new_body = str(body['body']).strip()
        if '\x00' in new_body:
            respond(400, {'error': 'Script body must not contain NUL bytes'})
        if len(new_body.encode()) > MAX_CUSTOM_SCRIPT_BODY:
            respond(400, {'error': f'Script body exceeds {MAX_CUSTOM_SCRIPT_BODY // 1024} KB limit'})
        s['body'] = new_body
    if 'assigned_devices' in body:
        raw_devs = body['assigned_devices']
        if not isinstance(raw_devs, list):
            respond(400, {'error': 'assigned_devices must be a list'})
        devices = load(DEVICES_FILE)
        assigned = []
        for d in raw_devs[:MAX_CUSTOM_SCRIPTS_PER_DEVICE * 10]:
            d = str(d).strip()
            if _validate_id(d) and d in devices:
                assigned.append(d)
        s['assigned_devices'] = assigned

    s['updated_at'] = int(time.time())
    scripts[script_id] = s
    save(CUSTOM_SCRIPTS_FILE, scripts)
    audit_log(actor, 'custom_script_update', f'script_id={script_id} name={s["name"]}')
    respond(200, s)


def handle_custom_script_delete(script_id):
    """DELETE /api/custom-scripts/:id — remove script and clear stored results."""
    actor = require_admin_auth()
    scripts = _load_custom_scripts()
    if script_id not in scripts:
        respond(404, {'error': 'Script not found'})

    name = scripts[script_id].get('name', script_id)
    del scripts[script_id]
    save(CUSTOM_SCRIPTS_FILE, scripts)

    # Remove stored results from every device that had them
    with _locked_update(DEVICES_FILE) as devices:
        for dev in devices.values():
            dev.get('custom_script_results', {}).pop(script_id, None)

    audit_log(actor, 'custom_script_delete', f'script_id={script_id} name={name}')
    _record_fleet_event('custom_script_delete', {'name': name, 'script_id': script_id})
    respond(200, {'ok': True})


def handle_custom_scripts_results():
    """GET /api/custom-scripts/results — fleet-wide current results per device."""
    require_auth()
    scripts   = _load_custom_scripts()
    devices   = load(DEVICES_FILE)
    now       = int(time.time())

    # Build index: script_id → script meta (name, assigned_devices)
    script_meta = {sid: {
        'id':               sid,
        'name':             s['name'],
        'description':      s.get('description', ''),
        'assigned_devices': s.get('assigned_devices', []),
    } for sid, s in scripts.items()}

    rows = []
    for dev_id, dev in devices.items():
        if dev.get('agentless'):
            continue
        results = dev.get('custom_script_results', {})
        if not results:
            continue
        online = (now - dev.get('last_seen', 0)) < get_online_ttl()
        for script_id, r in results.items():
            meta = script_meta.get(script_id, {'name': script_id, 'description': ''})
            rows.append({
                'device_id':   dev_id,
                'device_name': dev.get('name', dev_id),
                'group':       dev.get('group', ''),
                'online':      online,
                'script_id':   script_id,
                'script_name': meta['name'],
                'description': meta['description'],
                'ok':          r.get('ok', False),
                'output':      r.get('output', ''),
                'rc':          r.get('rc', 0),
                'ran_at':      r.get('ran_at', 0),
                'duration_ms': r.get('duration_ms', 0),
                'changed_at':  r.get('changed_at', 0),
            })

    rows.sort(key=lambda r: (r['ok'], r['device_name'].lower(), r['script_name'].lower()))
    respond(200, {'results': rows, 'scripts': list(script_meta.values())})



#
# Both the dashboard digest and the machine-readable status endpoint
# read from one place: _compute_attention(). It merges signals that
# already exist — offline devices, pending-patch pileups, CVE
# findings, drift, mailbox threshold breaches — into a single list of
# items, each with a severity so the caller can rank them.

# Severity rank — higher = more urgent. Used to sort the digest.
_ATTN_RANK = {'critical': 3, 'warning': 2, 'info': 1}


# v3.4.1: end-of-life OS table. Keyed by os-release ID → {VERSION_ID: eol_date}.
# Dates are the end of *standard* vendor support (ESM/paid extensions ignored —
# the point is "no more free security patches"). Approximate by design; this is
# a nudge, not an SLA. Unknown distro/version → no signal (fail-quiet).
_OS_EOL = {
    'ubuntu':    {'16.04': '2021-04-30', '18.04': '2023-05-31', '20.04': '2025-05-29',
                  '22.04': '2027-06-01', '23.04': '2024-01-25', '23.10': '2024-07-11',
                  '24.04': '2029-05-31'},
    'debian':    {'9': '2022-06-30', '10': '2024-06-30', '11': '2026-08-15',
                  '12': '2028-06-30'},
    'centos':    {'7': '2024-06-30', '8': '2021-12-31'},
    'rhel':      {'7': '2024-06-30', '8': '2029-05-31', '9': '2032-05-31'},
    'fedora':    {'37': '2023-12-05', '38': '2024-05-21', '39': '2024-11-12',
                  '40': '2025-05-13', '41': '2025-11-01'},
    'rocky':     {'8': '2029-05-31', '9': '2032-05-31'},
    'almalinux': {'8': '2029-05-31', '9': '2032-05-31'},
}

# Map common PRETTY_NAME words → our _OS_EOL keys, for the fallback parse path.
_OS_EOL_NAME_HINTS = (
    ('ubuntu', 'ubuntu'), ('debian', 'debian'), ('centos', 'centos'),
    ('red hat', 'rhel'), ('rhel', 'rhel'), ('rocky', 'rocky'),
    ('almalinux', 'almalinux'), ('alma', 'almalinux'), ('fedora', 'fedora'),
)


def _device_distro_version(dev, pkg_entry):
    """Best (distro_id, version) for a device. Prefers the structured os-release
    ID/VERSION_ID captured at package-scan time; falls back to parsing the
    PRETTY_NAME string in dev['os']. Returns ('', '') when undeterminable."""
    oid = (pkg_entry or {}).get('os_id') or ''
    ver = (pkg_entry or {}).get('version_id') or ''
    if oid and ver:
        return oid.strip().lower(), ver.strip()
    pretty = (dev.get('os') or '').lower()
    if not pretty:
        return '', ''
    distro = ''
    for needle, key in _OS_EOL_NAME_HINTS:
        if needle in pretty:
            distro = key
            break
    if not distro:
        return '', ''
    import re as _re
    if distro == 'ubuntu':
        m = _re.search(r'(\d+\.\d+)', pretty)
        return ('ubuntu', m.group(1)) if m else ('ubuntu', '')
    m = _re.search(r'(\d+)', pretty)
    return (distro, m.group(1)) if m else (distro, '')


def _device_os_eol(dev, pkg_entry):
    """EOL verdict for a device, or None when unknown. Status is 'eol' (past),
    'soon' (≤90 days), or 'ok'."""
    distro, version = _device_distro_version(dev, pkg_entry)
    if not distro or not version:
        return None
    eol_date = (_OS_EOL.get(distro) or {}).get(version)
    if not eol_date:
        return None
    import datetime as _dt
    try:
        eol_dt = _dt.date.fromisoformat(eol_date)
    except ValueError:
        return None
    days = (eol_dt - _dt.date.today()).days
    label = f"{distro.capitalize()} {version}"
    status = 'eol' if days < 0 else ('soon' if days <= 90 else 'ok')
    return {'distro': distro, 'version': version, 'label': label,
            'eol_date': eol_date, 'days': days, 'status': status}


# v3.5.0: lifecycle contract expiry (warranty / license / support). Mirrors the
# os_eol pattern — a date-based NA verdict. Reads the dates an operator entered
# in the CMDB. Thresholds: expired → warning, ≤30d → warning, ≤90d → info.
_CONTRACT_FIELDS = (
    ('warranty_expiry',         'warranty_expiry',  'Warranty'),
    ('license_expiry',          'license_expiry',   'License'),
    ('support_contract_expiry', 'support_expiry',   'Support contract'),
)
_CONTRACT_WARN_DAYS = 30
_CONTRACT_SOON_DAYS = 90


def _device_contract_status(cmdb_rec):
    """List of expiry verdicts for one device's CMDB record. Only fields with a
    parseable date and a non-'ok' status are returned. Each verdict:
    {kind, label, date, days, status} where status is expired|warn|soon."""
    import datetime as _dt
    out = []
    today = _dt.date.today()
    for field, kind, label in _CONTRACT_FIELDS:
        raw = (cmdb_rec or {}).get(field) or ''
        if not raw:
            continue
        try:
            d = _dt.date.fromisoformat(raw)
        except (ValueError, TypeError):
            continue
        days = (d - today).days
        if days < 0:
            status = 'expired'
        elif days <= _CONTRACT_WARN_DAYS:
            status = 'warn'
        elif days <= _CONTRACT_SOON_DAYS:
            status = 'soon'
        else:
            continue  # ok — nothing to surface
        out.append({'kind': kind, 'label': label, 'date': raw,
                    'days': days, 'status': status})
    # v3.12.0: also scan the richer contracts[] / licenses[] business lists,
    # reusing the existing support/license NA kinds (no new kind to register).
    for _lkey, _lkind, _llabel, _namef in (
            ('contracts', 'support_expiry', 'Contract', 'vendor'),
            ('licenses',  'license_expiry', 'License',  'product')):
        for item in (cmdb_rec or {}).get(_lkey) or []:
            if not isinstance(item, dict):
                continue
            raw = item.get('expiry') or ''
            if not raw:
                continue
            try:
                d = _dt.date.fromisoformat(raw)
            except (ValueError, TypeError):
                continue
            days = (d - today).days
            if days < 0:
                status = 'expired'
            elif days <= _CONTRACT_WARN_DAYS:
                status = 'warn'
            elif days <= _CONTRACT_SOON_DAYS:
                status = 'soon'
            else:
                continue
            nm = item.get(_namef) or item.get('number') or ''
            out.append({'kind': _lkind, 'date': raw, 'days': days, 'status': status,
                        'label': (f'{_llabel}: {nm}' if nm else _llabel)[:80]})
    return out


# ── Per-host Checks engine now lives in checks.py ──────────────────────────
# (_host_checks + _custom_checks_for/_eval_custom_check/_custom_check_applies
# + _exposure_muted + SERVER/AGENT_CHECK_TYPES — pure, imported at the top.
# Thread new check inputs through the api-side callers: handle_device_checks,
# handle_fleet_checks and the checksrollup widget.)


def _host_check_summary(checks):
    """Roll a check list up to per-status counts + a worst-status word."""
    counts = {'ok': 0, 'warning': 0, 'critical': 0, 'unknown': 0}
    for c in checks:
        if c.get('enabled', True):
            counts[c['status']] = counts.get(c['status'], 0) + 1
    worst = ('critical' if counts['critical'] else 'warning' if counts['warning']
             else 'unknown' if counts['unknown'] else 'ok')
    return {'counts': counts, 'worst': worst, 'total': len(checks)}


def _cve_high_counts():
    """Per-device count of critical+high CVE findings (for the checks view)."""
    out = {}
    try:
        for did, rec in (load(CVE_FINDINGS_FILE) or {}).items():
            out[did] = sum(1 for f in (rec or {}).get('findings') or []
                           if str(f.get('severity', '')).lower() in ('critical', 'high'))
    except Exception:
        pass
    return out


def _disk_fill_eta(devices, min_percent=60.0, horizon_days=60):
    """Predict days-to-full per device from the disk% time-series (linear fit).

    Returns {device_id: days_to_full} only for devices that are (a) already
    past ``min_percent`` used and (b) trending up fast enough to fill within
    ``horizon_days`` — so the fleet checks view stays cheap (we only query the
    DB time-series for near-full hosts) and only flags genuine risks. Reads the
    same store as _rag_metric_summaries (DB metric_range, else the JSON window).
    """
    out = {}
    dbm = _dbmod()
    json_metrics = (load(METRICS_FILE) or {}) if dbm is None else None
    since = int(time.time()) - 14 * 86400
    for did, dev in devices.items():
        if not isinstance(dev, dict) or dev.get('agentless'):
            continue
        # Cheap gate: only bother if the latest reported disk is already high.
        cur = None
        for m in (dev.get('sysinfo', {}).get('mounts') or []):
            if isinstance(m.get('percent'), (int, float)):
                cur = max(cur or 0, m['percent'])
        if cur is None or cur < min_percent:
            continue
        try:
            if dbm is not None:
                samples = dbm.metric_range(DATA_DIR, did, since, max_points=200) or []
            else:
                samples = [s for s in (json_metrics.get(did) or [])
                           if isinstance(s, dict) and (s.get('ts') or 0) >= since]
        except Exception:
            samples = []
        pts = [(s['ts'], s['disk']) for s in samples
               if isinstance(s.get('ts'), (int, float))
               and isinstance(s.get('disk'), (int, float))]
        if len(pts) < 4:
            continue
        n = len(pts)
        mt = sum(t for t, _ in pts) / n
        md = sum(d for _, d in pts) / n
        var = sum((t - mt) ** 2 for t, _ in pts)
        if var <= 0:
            continue
        slope = sum((t - mt) * (d - md) for t, d in pts) / var  # %/sec
        if slope <= 0:
            continue
        per_day = slope * 86400.0
        days = (100.0 - pts[-1][1]) / per_day if per_day > 0 else None
        if days is not None and 0 <= days <= horizon_days:
            out[did] = round(days, 1)
    return out


def handle_device_checks(dev_id):
    """GET /api/devices/<id>/checks — the unified check list + summary for one host."""
    require_auth()
    # v4.3.0: single-row read + per-device scope check, instead of scope-
    # filtering the whole fleet just to pull one host.
    dev = device_get(dev_id)
    _scope = _caller_scope()
    if not dev or (_scope is not None and not _device_in_scope(_scope, dev)):
        respond(404, {'error': 'device not found'})
    cfg = load(CONFIG_FILE) or {}
    disabled = (cfg.get('host_checks_disabled') or {}).get(dev_id) or []
    hw = (load(HARDWARE_FILE) or {}).get(dev_id) if backend_exists(HARDWARE_FILE) else {}
    cve = _cve_high_counts().get(dev_id)
    eta = _disk_fill_eta({dev_id: dev}).get(dev_id)
    custom_defs = cfg.get('custom_checks') or []
    scripts = _load_custom_scripts()
    exposure_mutes = cfg.get('exposure_mutes') or []
    ttl = get_online_ttl()
    checks = _host_checks(dev_id, dev, hw, disabled, int(time.time()), ttl,
                          cve_high=cve, disk_eta=eta, custom_defs=custom_defs,
                          scripts=scripts, exposure_mutes=exposure_mutes)
    respond(200, {'device_id': dev_id, 'name': dev.get('name', dev_id),
                  'checks': checks, 'summary': _host_check_summary(checks)})


# v4.3.0 perf: file-backed cache for the fleet-checks matrix. _host_checks is
# O(fleet) pure-Python work per request and the Checks page + the checksrollup
# widget poll it. Layout of the guard:
#   * the cache stores the UNSCOPED host rows — RBAC scope and the ?status
#     filter are applied per request AFTER the cache, so a viewer can never
#     be served another scope's hosts from a cache an admin warmed.
#   * `fp` fingerprints the admin-tunable inputs (check toggles, custom
#     checks, exposure mutes, custom scripts) — toggling a mute busts the
#     cache instantly instead of waiting out the TTL.
#   * on the JSON backend the underlying files' mtimes also bust it (same
#     trick as _attention_payload — keeps tests deterministic). Under
#     SQLite those logical paths don't exist on disk, so staleness is
#     bounded by the TTL alone.
_FLEET_CHECKS_CACHE_TTL = 15


def _fleet_checks_cache_file():
    return DATA_DIR / 'fleet_checks_cache.json'


def _fleet_checks_rows(devices_all, cfg, scripts, fp):
    """Return the full (unscoped) computed host rows, from cache if fresh."""
    cache_file = _fleet_checks_cache_file()
    try:
        cached = load(cache_file)
        # v4.4.0 (PERF): honor the cache for its full 15s TTL. The old code also
        # busted it whenever DEVICES_FILE/CVE/HARDWARE mtime advanced — but on any
        # fleet larger than ~15 hosts a heartbeat rewrites DEVICES_FILE more often
        # than every 15s, so the cache NEVER hit and every Checks-page poll +
        # checksrollup widget re-ran the full _host_checks fleet loop. The `fp`
        # fingerprint still busts the cache instantly on the changes operators
        # make and expect reflected (config / scripts / custom-check defs); device
        # telemetry being ≤15s stale on a rollup view is the intended contract.
        if (isinstance(cached, dict) and cached.get('fp') == fp
                and isinstance(cached.get('hosts'), list)
                and time.time() - cached.get('ts', 0) < _FLEET_CHECKS_CACHE_TTL):
            return cached['hosts']
    except Exception:
        pass
    disabled_all = cfg.get('host_checks_disabled') or {}
    hw_all = (load(HARDWARE_FILE) or {}) if backend_exists(HARDWARE_FILE) else {}
    cve_all = _cve_high_counts()
    eta_all = _disk_fill_eta(devices_all)
    custom_defs = cfg.get('custom_checks') or []
    exposure_mutes = cfg.get('exposure_mutes') or []
    now = int(time.time())
    ttl = get_online_ttl()
    hosts = []
    for did, dev in devices_all.items():
        if not isinstance(dev, dict):
            continue
        checks = _host_checks(did, dev, hw_all.get(did) or {},
                              disabled_all.get(did) or [], now, ttl,
                              cve_high=cve_all.get(did), disk_eta=eta_all.get(did),
                              custom_defs=custom_defs, scripts=scripts,
                              exposure_mutes=exposure_mutes)
        summ = _host_check_summary(checks)
        hosts.append({'device_id': did, 'name': dev.get('name', did),
                      'group': dev.get('group', ''),
                      'monitored': dev.get('monitored', True),
                      'summary': summ, 'checks': checks})
    try:
        save(_fleet_checks_cache_file(), {'ts': time.time(), 'fp': fp, 'hosts': hosts})
    except Exception:
        pass
    return hosts


def handle_fleet_checks():
    """GET /api/checks — CheckMK-style fleet matrix: every host with its check
    list + roll-up summary. Scope-filtered. Optional ?status=critical|warning to
    pre-filter hosts to those with a check at that level."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    want = (qs.get('status', [''])[0] or '').strip().lower()
    devices_all = load(DEVICES_FILE) or {}
    allowed = set(_scope_filter_devices(devices_all).keys())
    cfg = load(CONFIG_FILE) or {}
    scripts = _load_custom_scripts()
    # Non-security cache-key fingerprint (checks-config change detection),
    # not a credential digest — usedforsecurity=False silences CodeQL's
    # weak-hash query (see docs/security-review-4.4.1.md).
    fp = hashlib.md5(json.dumps(
        [cfg.get('host_checks_disabled') or {}, cfg.get('custom_checks') or [],
         cfg.get('exposure_mutes') or [], scripts],
        sort_keys=True, default=str).encode(), usedforsecurity=False).hexdigest()
    rows = _fleet_checks_rows(devices_all, cfg, scripts, fp)
    hosts = [h for h in rows if h.get('device_id') in allowed]
    if want in ('critical', 'warning'):
        hosts = [h for h in hosts if h['summary']['counts'].get(want)]
    hosts.sort(key=lambda h: h['name'].lower())
    return respond(200, {'hosts': hosts, 'total': len(hosts)})


def handle_checks_toggle():
    """POST /api/checks/toggle {device_id, check, enabled} — enable/disable a
    single check on a host (persisted to config.host_checks_disabled). Admin-only."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    did = _sanitize_str(str(body.get('device_id', '')), 64).strip()
    chk = _sanitize_str(str(body.get('check', '')), 128).strip()
    enabled = bool(body.get('enabled'))
    if not did or not chk:
        respond(400, {'error': 'device_id and check are required'})
    with _LockedUpdate(CONFIG_FILE) as cfg:
        d = cfg.setdefault('host_checks_disabled', {})
        cur = set(d.get(did) or [])
        if enabled:
            cur.discard(chk)
        else:
            cur.add(chk)
        if cur:
            d[did] = sorted(cur)
        else:
            d.pop(did, None)
    audit_log(actor, 'check_toggle', f'device={did} check={chk} enabled={enabled}')
    respond(200, {'ok': True, 'device_id': did, 'check': chk, 'enabled': enabled})


CUSTOM_CHECK_TYPES = SERVER_CHECK_TYPES + AGENT_CHECK_TYPES


def handle_custom_checks_list():
    """GET /api/checks/custom — list custom-check definitions."""
    require_auth()
    cfg = load(CONFIG_FILE) or {}
    respond(200, {'checks': cfg.get('custom_checks') or [],
                  'types': list(CUSTOM_CHECK_TYPES)})


def handle_custom_checks_save():
    """POST /api/checks/custom — add or update a custom-check definition. Admin."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    ctype = body.get('type')
    if ctype not in CUSTOM_CHECK_TYPES:
        respond(400, {'error': f'type must be one of {", ".join(CUSTOM_CHECK_TYPES)}'})
    name = _sanitize_str(str(body.get('name', '')), 128).strip()
    # Param semantics vary by type: a path (file/job), a regex (log), a process
    # name or port (server-side). Keep control chars out but don't mangle paths.
    param = re.sub(r'[\x00-\x1f\x7f]', '', str(body.get('param', '')))[:256].strip()
    if not param:
        respond(400, {'error': 'param is required'})
    if ctype in ('file_present', 'file_absent', 'job_fresh') and not param.startswith('/'):
        respond(400, {'error': 'an absolute path is required'})
    tk = body.get('target_kind', 'all')
    if tk not in ('all', 'host', 'tag', 'group'):
        respond(400, {'error': 'invalid target_kind'})
    tv = _sanitize_str(str(body.get('target', '')), 128).strip()
    if tk != 'all' and not tv:
        respond(400, {'error': f'a {tk} target is required'})
    # Per-type optional extras (validated to sane ranges).
    def _iarg(key, default, lo, hi):
        try:
            return max(lo, min(int(body.get(key) or default), hi))
        except (TypeError, ValueError):
            respond(400, {'error': f'{key} must be a number'})
    extras = {}
    if ctype == 'log_errors':
        extras['window_min'] = _iarg('window_min', 15, 1, 1440)
        extras['warn'] = _iarg('warn', 1, 1, 100000)
        extras['crit'] = max(extras['warn'], _iarg('crit', 10, 1, 100000))
        unit = re.sub(r'[^a-zA-Z0-9_.@\-]', '', str(body.get('unit', '')))[:128]
        if unit:
            extras['unit'] = unit
    if ctype == 'job_fresh':
        extras['max_age_hours'] = _iarg('max_age_hours', 24, 1, 8760)
    cid = _sanitize_str(str(body.get('id', '')), 64).strip()
    with _LockedUpdate(CONFIG_FILE) as cfg:
        checks = cfg.setdefault('custom_checks', [])
        if not cid:
            n = 1 + max([0] + [int(re.sub(r'\D', '', c.get('id', '')) or 0)
                               for c in checks if isinstance(c, dict)])
            cid = f'ck_{n:05d}'
        entry = {'id': cid, 'name': name or f'{ctype} {param}', 'type': ctype,
                 'param': param, 'target_kind': tk, 'target': tv, **extras}
        for i, c in enumerate(checks):
            if isinstance(c, dict) and c.get('id') == cid:
                checks[i] = entry
                break
        else:
            checks.append(entry)
    # v5.6.0: wire a systemd_unit host check to the Services page — also add the
    # unit to that device's watch-list so it shows there too. Done AFTER the
    # CONFIG_FILE lock so the device lock never nests (SQLite shares one conn).
    watched_ok = False
    if ctype == 'systemd_unit' and tk == 'host' and body.get('watch_service') and tv:
        try:
            with _LockedUpdate(DEVICES_FILE) as devices:
                d = devices.get(tv)
                if isinstance(d, dict):
                    watched = d.setdefault('services_watched', [])
                    if param not in watched:
                        watched.append(param)
                    watched_ok = True
        except Exception:
            pass
    audit_log(actor, 'custom_check_save', f'id={cid} type={ctype} param={param}')
    respond(200, {'ok': True, 'check': entry, 'watched': watched_ok})


def handle_custom_checks_delete():
    """POST /api/checks/custom/delete {id} — remove a custom-check definition. Admin."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    cid = _sanitize_str(str((get_json_obj()).get('id', '')), 64).strip()
    if not cid:
        respond(400, {'error': 'id is required'})
    with _LockedUpdate(CONFIG_FILE) as cfg:
        checks = cfg.get('custom_checks') or []
        cfg['custom_checks'] = [c for c in checks
                                if not (isinstance(c, dict) and c.get('id') == cid)]
    audit_log(actor, 'custom_check_delete', f'id={cid}')
    respond(200, {'ok': True, 'id': cid})


def _compute_attention():
    """Build the fleet-wide list of things needing attention.

    Returns a list of dicts: {severity, kind, device, summary}. Pure
    aggregation over data RemotePower already stores — no new probing.

    Unmonitored devices (operator set `monitored: false` — decommissioned
    hosts, dev boxes) are skipped entirely: the same gate the webhook
    pipeline and the old dashboard digest applied.
    """
    items = []
    devices = load(DEVICES_FILE) or {}
    # v3.3.0: load CONFIG_FILE once here and pass through. Previously
    # this function loaded it 4× during a single call.
    cfg = load(CONFIG_FILE) or {}
    now = int(time.time())
    try:
        ttl = get_online_ttl()
    except Exception:
        ttl = 180

    # The set of devices the digest considers at all.
    def _watched(dev):
        return not dev.get('agentless') and dev.get('monitored', True)

    monitored = {dev_id: dev for dev_id, dev in devices.items()
                 if _watched(dev)}

    # Offline devices (has heartbeated before).
    for dev_id, dev in monitored.items():
        last = dev.get('last_seen', 0)
        if last and (now - last) > ttl:
            mins = (now - last) // 60
            items.append({
                'severity': 'critical', 'kind': 'offline',
                'device': dev.get('name', dev_id),
                'summary': f'Offline for {mins} min — last seen '
                           f'{time.strftime("%H:%M", time.localtime(last))}',
            })

    # Pending-patch pileups. The upgradable count lives at
    # sysinfo.packages.upgradable (what the agent reports and the heatmap reads);
    # reading only a top-level `dev['upgradable']` (never populated in practice)
    # meant pending updates never dented the health score. Prefer the nested
    # count, fall back to a top-level value if present.
    for dev_id, dev in monitored.items():
        up = ((dev.get('sysinfo') or {}).get('packages') or {}).get('upgradable')
        if up is None:
            up = dev.get('upgradable')
        if isinstance(up, int) and up > 0:
            sev = 'warning' if up >= 20 else 'info'
            items.append({
                'severity': sev, 'kind': 'patches',
                'device': dev.get('name', dev_id),
                'summary': f'{up} pending package update'
                           f'{"s" if up != 1 else ""}',
            })

    # CVE findings — excluding any vuln on the ignore list. An
    # operator who has accepted a CVE as a risk (globally or for that
    # device) does not want it back on the Needs Attention list.
    cve_all = load(CVE_FINDINGS_FILE) or {}
    cve_ignore = load(CVE_IGNORE_FILE) or {}
    for dev_id, rec in cve_all.items():
        if dev_id not in monitored:
            continue
        findings = (rec or {}).get('findings') or []
        if not findings:
            continue
        # apply_ignore_list marks each finding with an `ignored` flag
        # (scope 'global' or this device); drop the ignored ones.
        findings = [f for f in cve_scanner.apply_ignore_list(
                        findings, cve_ignore, dev_id)
                    if not f.get('ignored')]
        if not findings:
            continue
        crit = sum(1 for f in findings if f.get('severity') == 'critical')
        high = sum(1 for f in findings if f.get('severity') == 'high')
        # How many of these have a known fixed version — i.e. a package upgrade
        # would actually clear them. Surfaced in the summary so the operator can
        # see at a glance whether there's anything actionable to patch. Counted
        # over critical/high findings only, matching _cve_fixable_by_device (the
        # Patches↔CVE cross-link) so the two numbers agree.
        fixable = sum(1 for f in findings
                      if str(f.get('severity', '')).lower() in ('critical', 'high')
                      and f.get('fixed_version'))
        name = monitored[dev_id].get('name', dev_id)
        if crit:
            summary = f'{crit} critical CVE{"s" if crit != 1 else ""}'
            if fixable:
                summary += f' · {fixable} fixable'
            items.append({'severity': 'critical', 'kind': 'cve',
                           'device': name, 'summary': summary})
        elif high:
            summary = f'{high} high-severity CVE{"s" if high != 1 else ""}'
            if fixable:
                summary += f' · {fixable} fixable'
            items.append({'severity': 'warning', 'kind': 'cve',
                           'device': name, 'summary': summary})

    # Configuration drift.
    for dev_id, dev in monitored.items():
        drift = dev.get('drift_state') or {}
        drifted = [f for f, st in drift.items()
                   if isinstance(st, dict) and st.get('status') == 'drifted'
                   and not st.get('ignored')]
        if drifted:
            items.append({
                'severity': 'warning', 'kind': 'drift',
                'device': dev.get('name', dev_id),
                'summary': f'{len(drifted)} config file'
                           f'{"s" if len(drifted) != 1 else ""} drifted '
                           f'from baseline',
            })

    # Mailbox threshold breaches (re-uses the alerted flags set by
    # _ingest_mailbox_counts — no recomputation).
    for dev_id, dev in monitored.items():
        state = dev.get('mailbox_state') or {}
        alerted = state.get('alerted') or {}
        counts = state.get('counts') or {}
        for path, is_over in alerted.items():
            if is_over:
                cnt = (counts.get(path) or {}).get('count')
                items.append({
                    'severity': 'warning', 'kind': 'mailbox',
                    'device': dev.get('name', dev_id),
                    'summary': f'Mailbox {path} at {cnt} '
                               f'(over threshold)',
                })

    # v2.8.1: backup file staleness.
    bak_state_file = DATA_DIR / 'backup_state.json'
    if backend_exists(bak_state_file):   # v5.0.0: DB-backed key, not a file
        try:
            bak_state = load(bak_state_file) or {}
            bak_mons  = {m['path']: m for m in (cfg.get('backup_monitors') or []) if m.get('path')}
            for state_key, entry in bak_state.items():
                if ':' not in state_key:
                    continue
                dev_id_s, bak_path = state_key.split(':', 1)
                if not entry.get('ok', True):
                    dev = monitored.get(dev_id_s, {})
                    mon = bak_mons.get(bak_path, {})
                    label   = mon.get('label', bak_path)
                    age_h   = entry.get('age_h')
                    max_h   = mon.get('max_age_hours', 24)
                    age_str = f'{age_h:.0f}h old' if age_h else 'missing'
                    items.append({'severity': 'critical', 'kind': 'backup',
                                  'device': dev.get('name', dev_id_s),
                                  'summary': f'Backup "{label}" is {age_str} (threshold: {max_h:.0f}h)'})
        except Exception:
            pass

    # v2.8.0: disk space threshold breaches (reads from sysinfo stored in devices.json).
    default_warn = cfg.get('disk_warn_percent', 80)
    default_crit = cfg.get('disk_crit_percent', 90)
    for dev_id, dev in monitored.items():
        si = dev.get('sysinfo') or {}
        mounts = si.get('mounts') or []
        overrides = dev.get('metric_thresholds') or {}
        for mnt in mounts:
            pct  = mnt.get('percent', 0)
            path = mnt.get('path', '?')
            # v3.0.2: was `_get_disk_thresholds(path, overrides)` guarded by
            # `callable(globals().get(...))` — that helper never existed, so
            # the fallback (per-device override only) always ran and the
            # per-mount override map was ignored. _resolve_metric_thresholds
            # is the canonical resolver and handles per-mount entries.
            w, c = _resolve_metric_thresholds(dev, 'disk', path)
            if pct >= c:
                items.append({'severity': 'critical', 'kind': 'disk',
                              'device': dev.get('name', dev_id),
                              'summary': f'{path}: {pct:.0f}% used (critical ≥ {c:.0f}%)'})
            elif pct >= w:
                items.append({'severity': 'warning', 'kind': 'disk',
                              'device': dev.get('name', dev_id),
                              'summary': f'{path}: {pct:.0f}% used (warn ≥ {w:.0f}%)'})

    # v3.12.0: mount-point problems (fstab-vs-mount + stalled NFS/SMB). The agent
    # reports these in sysinfo.mount_issues and a mount_issue event fires; surface
    # them here too so they actually show up on Needs Attention (and dent health).
    for dev_id, dev in monitored.items():
        for mi in ((dev.get('sysinfo') or {}).get('mount_issues') or []):
            if not isinstance(mi, dict):
                continue
            issue = (mi.get('issue') or 'problem')
            path  = mi.get('path', '?')
            fstype = mi.get('fstype') or ''
            stalled = issue == 'stalled'
            items.append({
                'severity': 'critical' if stalled else 'warning',
                'kind': 'mount',
                'device': dev.get('name', dev_id),
                'summary': (f'{path} {"is not responding (stalled" if stalled else "is not mounted (missing"}'
                            f'{" " + fstype if fstype else ""})'),
            })

    # v3.0.2: surface memory/swap/cpu warnings + criticals from metric_state.
    # Previously only disk made it to Needs Attention even though metric_warning
    # webhooks fired for every kind. Inconsistent — operator gets a Pushover
    # ping about swap usage but the dashboard insists nothing needs attention.
    # The metric_state dict is keyed by f"{kind}:{target}" with values
    # 'ok'/'warning'/'critical'; surface every non-ok entry that isn't disk
    # (which we already did above with full percent context).
    for dev_id, dev in monitored.items():
        mstate = dev.get('metric_state') or {}
        if not isinstance(mstate, dict):
            continue
        si = dev.get('sysinfo') or {}
        for key, level in mstate.items():
            if level not in ('warning', 'critical') or ':' not in key:
                continue
            kind, target = key.split(':', 1)
            if kind == 'disk':
                continue  # handled above with mount path + pct
            # Pull current value for the summary line. memory/swap come
            # from sysinfo top-level fields; cpu from loadavg.
            val_str = ''
            try:
                if kind == 'memory':
                    pct = si.get('mem_percent')
                    if pct is not None: val_str = f'{pct:.0f}% used'
                elif kind == 'swap':
                    pct = si.get('swap_percent')
                    if pct is not None: val_str = f'{pct:.0f}% used'
                elif kind == 'cpu':
                    # sysinfo stores the scalar `loadavg_1m`, not a `loadavg`
                    # list — reading the wrong key left the cpu item's value
                    # blank ("cpu: (warning ≥ 2)"). (v3.8.0 fix.)
                    la = si.get('loadavg_1m')
                    cpu_count = (si.get('cpu_count') or 1) or 1
                    if isinstance(la, (int, float)):
                        val_str = f'load {la:.2f} (ratio {la/cpu_count:.2f})'
            except Exception:
                pass
            w, c = _resolve_metric_thresholds(dev, kind, target)
            severity = 'critical' if level == 'critical' else 'warning'
            thresh = c if level == 'critical' else w
            unit = '%' if kind in ('memory', 'swap') else ''
            items.append({
                'severity': severity, 'kind': kind,
                'device': dev.get('name', dev_id),
                'summary': f'{kind}: {val_str} ({level} ≥ {thresh:.0f}{unit})'.strip(),
            })

    # v3.0.2: container state surfaced into Needs Attention. A stopped
    # container on a host that's still up is an actionable signal —
    # docker_inspect crash, OOM-killed, exited non-zero — and we'd fire
    # container_stopped webhooks for it anyway. Stale container data
    # (no recent heartbeat report) is a warning rather than info.
    try:
        cstore   = load(CONTAINERS_FILE) or {}
        ig_stale = _ignored_keys('stale_containers')
        ig_devs  = _ignored_keys('devices')
        c_now    = int(time.time())
        c_ttl    = get_container_stale_ttl() if 'get_container_stale_ttl' in globals() else 600
        for dev_id, entry in cstore.items():
            if dev_id not in monitored:
                continue
            if dev_id in ig_devs:
                continue
            if not isinstance(entry, dict):
                continue
            ts = entry.get('ts', 0)
            its = entry.get('items', [])
            summary = containers_mod.summarise(its) if its else {}
            stopped    = (summary or {}).get('stopped', 0)
            restarting = (summary or {}).get('restarting', 0)
            is_stale   = bool(ts) and (c_now - ts) > c_ttl
            if is_stale and f'{dev_id}/' not in ig_stale:
                mins = (c_now - ts) // 60
                items.append({
                    'severity': 'warning', 'kind': 'container',
                    'device': monitored[dev_id].get('name', dev_id),
                    'summary': f'Container data stale — last reported {mins} min ago',
                })
                continue  # skip stopped/restarting items if data is stale
            if stopped > 0:
                items.append({
                    'severity': 'warning', 'kind': 'container',
                    'device': monitored[dev_id].get('name', dev_id),
                    'summary': f'{stopped} container{"s" if stopped != 1 else ""} stopped',
                })
            if restarting > 0:
                items.append({
                    'severity': 'warning', 'kind': 'container',
                    'device': monitored[dev_id].get('name', dev_id),
                    'summary': f'{restarting} container{"s" if restarting != 1 else ""} restarting',
                })
    except Exception as _e:
        # v4.1.0 (#33): stay resilient (a bad containers file must not break the
        # whole digest) but don't fail silently — the v3.0.4 lesson.
        sys.stderr.write(f'[remotepower] _compute_attention containers: '
                         f'{type(_e).__name__}: {_e}\n')

    # v3.0.2: ACME certificate renewal failures. tls_expiry above surfaces
    # any cert nearing expiry regardless of whether RemotePower is managing
    # it via acme.sh — this complements with the acme-specific signal that
    # the LAST renewal attempt actually failed. Status field comes from
    # the agent's parse of acme.sh's account.conf / renewal log.
    try:
        acme_state = load(ACME_STATE_FILE) or {}
        for dev_id, dev_acme in (acme_state.get('devices') or {}).items():
            if dev_id not in monitored:
                continue
            if not isinstance(dev_acme, dict) or not dev_acme.get('available'):
                continue
            for cert in (dev_acme.get('certs') or []):
                status = (cert.get('status') or 'ok').lower()
                if status not in ('ok', '', None):
                    items.append({
                        'severity': 'warning' if status not in ('failed', 'expired') else 'critical',
                        'kind': 'acme',
                        'device': monitored[dev_id].get('name', dev_id),
                        'summary': f'{cert.get("domain", "?")}: {status}',
                    })
    except Exception as _e:
        # v4.1.0 (#33): resilient but not silent (see v3.0.4 note above).
        sys.stderr.write(f'[remotepower] _compute_attention acme: '
                         f'{type(_e).__name__}: {_e}\n')

    # v2.8.0: active brute-force state.
    if backend_exists(BRUTE_FORCE_FILE):
        try:
            _bf_enabled, _bf_thresh, _bf_window = _brute_config()
            if _bf_enabled:
                bf_data = load(BRUTE_FORCE_FILE) or {}
                cutoff  = now - _bf_window
                for dev_id, units in bf_data.items():
                    dev_name = monitored.get(dev_id, {}).get('name', dev_id)
                    for unit, ips in units.items():
                        for src_ip, timestamps in ips.items():
                            recent = [t for t in timestamps if t >= cutoff]
                            if len(recent) > _bf_thresh:
                                items.append({
                                    'severity': 'critical', 'kind': 'brute_force',
                                    'device': dev_name,
                                    'summary': (f'{len(recent)} failed login attempts from '
                                                f'{src_ip} on {unit} (last 5 min)'),
                                })
        except Exception:
            pass

    # v2.7.0: stale Proxmox snapshots.
    if backend_exists(PROXMOX_SNAPSHOT_CACHE):
        try:
            snap_cache = load(PROXMOX_SNAPSHOT_CACHE) or {}
            warn_days  = int(cfg.get('proxmox_snapshot_warn_days', 7))
            for key, entry in snap_cache.items():
                snaps = entry.get('snapshots') or []
                vm    = entry.get('vm_name', key)
                for s in snaps:
                    age_days = (now - s.get('snaptime', now)) // 86400
                    if age_days >= warn_days:
                        items.append({
                            'severity': 'warning', 'kind': 'snapshot',
                            'device': vm,
                            'summary': (f'Snapshot "{s["name"]}" is '
                                        f'{age_days}d old (threshold: {warn_days}d)'),
                        })
        except Exception:
            pass

    # v2.6.1: TLS/DANE certificate expiry (reads tls_results.json).
    tls_targets = load(TLS_TARGETS_FILE) or {}
    tls_results = load(TLS_RESULTS_FILE) or {}
    try:
        import tls_monitor as _tls_mod
        for tid, t in tls_targets.items():
            r = tls_results.get(tid) or {}
            if not r:
                continue
            days = _tls_mod.days_until_expiry(r)
            host = t.get('host', tid)
            port = t.get('port', 443)
            label = f'{host}:{port}'
            if days <= 0:
                items.append({'severity': 'critical', 'kind': 'tls',
                              'device': label, 'summary': 'Certificate EXPIRED'})
            elif days <= 7:
                items.append({'severity': 'critical', 'kind': 'tls', 'device': label,
                              'summary': f'Certificate expires in {days} day{"s" if days != 1 else ""}'})
            elif days <= 30:
                items.append({'severity': 'warning', 'kind': 'tls', 'device': label,
                              'summary': f'Certificate expires in {days} days'})
            if t.get('dane_check') and r.get('dane_status') not in ('ok', 'not_checked', None, ''):
                items.append({'severity': 'warning', 'kind': 'tls', 'device': label,
                              'summary': f'DANE check failed: {r.get("dane_status","error")}'})
    except Exception:
        pass

    # v2.6.1: pending reboot (Debian/Ubuntu /run/reboot-required).
    for dev_id, dev in monitored.items():
        si = dev.get('sysinfo') or {}
        if si.get('reboot_required'):
            items.append({'severity': 'warning', 'kind': 'reboot',
                          'device': dev.get('name', dev_id),
                          'summary': 'Pending reboot — /run/reboot-required exists'})

    # v3.8.0: failed systemd units. The agent has always shipped failed_units
    # in sysinfo; v3.8.0 finally persists it, so surface it as an attention
    # signal (it also feeds the fleet health score, like every NA item, and
    # is AI-investigable via the failed_units playbook).
    for dev_id, dev in monitored.items():
        si = dev.get('sysinfo') or {}
        fu = si.get('failed_units') or []
        if isinstance(fu, list) and fu:
            shown = ', '.join(str(u) for u in fu[:4])
            more = f' (+{len(fu) - 4} more)' if len(fu) > 4 else ''
            items.append({'severity': 'warning', 'kind': 'failed_units',
                          'device': dev.get('name', dev_id),
                          'summary': f'{len(fu)} failed systemd unit'
                                     f'{"s" if len(fu) != 1 else ""}: {shown}{more}'})

    # v2.6.1: stale agent version.
    for dev_id, dev in monitored.items():
        agent_ver = dev.get('agent_version') or dev.get('version') or ''
        if agent_ver and agent_ver != SERVER_VERSION:
            items.append({'severity': 'info', 'kind': 'agent_version',
                          'device': dev.get('name', dev_id),
                          'summary': f'Agent v{agent_ver} — server is v{SERVER_VERSION}'})

    # v3.4.1: end-of-life OS. Past-EOL → warning; within 90 days → info. Flows
    # into the fleet health score (same as every NA item) and the EOL count
    # also feeds a compliance control.
    try:
        _eol_pkg_store = load(PACKAGES_FILE) or {}
    except Exception:
        _eol_pkg_store = {}
    for dev_id, dev in monitored.items():
        eol = _device_os_eol(dev, _eol_pkg_store.get(dev_id) or {})
        if not eol or eol['status'] == 'ok':
            continue
        if eol['status'] == 'eol':
            items.append({'severity': 'warning', 'kind': 'os_eol',
                          'device': dev.get('name', dev_id),
                          'summary': f"{eol['label']} reached end-of-life {eol['eol_date']}"})
        else:  # soon
            items.append({'severity': 'info', 'kind': 'os_eol',
                          'device': dev.get('name', dev_id),
                          'summary': f"{eol['label']} end-of-life in ~{eol['days']}d ({eol['eol_date']})"})

    # v3.5.0: lifecycle contract expiry (warranty / license / support). Reads
    # the dates operators set in the CMDB. Expired/≤30d → warning, ≤90d → info.
    try:
        _cmdb_store = _cmdb_load() or {}
    except Exception:
        _cmdb_store = {}
    for dev_id, dev in monitored.items():
        for v in _device_contract_status(_cmdb_store.get(dev_id) or {}):
            sev = 'info' if v['status'] == 'soon' else 'warning'
            if v['status'] == 'expired':
                summary = f"{v['label']} expired {v['date']} (~{abs(v['days'])}d ago)"
            else:
                summary = f"{v['label']} expires in ~{v['days']}d ({v['date']})"
            items.append({'severity': sev, 'kind': v['kind'],
                          'device': dev.get('name', dev_id), 'summary': summary})

    # v3.6.0: endpoint AV/malware posture. Infections → critical; a very stale
    # ClamAV signature DB (>7d) or rkhunter warnings → warning.
    try:
        _av_store = load(AV_FILE) or {}
    except Exception:
        _av_store = {}
    for dev_id, dev in monitored.items():
        av = _av_store.get(dev_id) or {}
        clam = av.get('clamav') or {}
        rk = av.get('rkhunter') or {}
        name = dev.get('name', dev_id)
        if isinstance(clam.get('infected'), int) and clam['infected'] > 0:
            items.append({'severity': 'critical', 'kind': 'av_posture', 'device': name,
                          'summary': f"ClamAV reported {clam['infected']} infected file(s)"})
        elif isinstance(clam.get('db_age_days'), int) and clam['db_age_days'] > 7:
            items.append({'severity': 'warning', 'kind': 'av_posture', 'device': name,
                          'summary': f"ClamAV signature DB is {clam['db_age_days']}d old"})
        if isinstance(rk.get('warnings'), int) and rk['warnings'] > 0:
            items.append({'severity': 'warning', 'kind': 'av_posture', 'device': name,
                          'summary': f"rkhunter reported {rk['warnings']} warning(s)"})

    # v3.6.0: Proxmox per-guest backup recency. Reads the backup cache refreshed
    # opportunistically by the Proxmox list endpoint.
    try:
        _pbk = load(PROXMOX_BACKUP_CACHE) or {}
    except Exception:
        _pbk = {}
    _pbk_guests = _pbk.get('guests') if isinstance(_pbk, dict) else None
    if _pbk_guests:
        try:
            _warn_days = int(_config_ro().get('proxmox_backup_warn_days', 7))
        except Exception:
            _warn_days = 7
        for g in _pbk_guests:
            age = g.get('age_days')
            label = g.get('name') or f"guest {g.get('vmid')}"
            if age is None:
                items.append({'severity': 'warning', 'kind': 'proxmox_backup', 'device': label,
                              'summary': 'No Proxmox backup found for this guest'})
            elif isinstance(age, int) and age > _warn_days:
                items.append({'severity': 'warning', 'kind': 'proxmox_backup', 'device': label,
                              'summary': f'Newest Proxmox backup is {age}d old (threshold {_warn_days}d)'})

    # v3.7.0: CMDB credential rotation due. Reads the per-credential
    # rotate_after_days policy; flags any whose age since last rotation exceeds
    # it. Device name resolved from the device record.
    try:
        _cmdb_rot = _cmdb_load() or {}
        _devs_rot = load(DEVICES_FILE) or {}
    except Exception:
        _cmdb_rot = {}; _devs_rot = {}
    for _dev_id, _rec in _cmdb_rot.items():
        if _dev_id not in monitored:
            continue
        dname = _devs_rot.get(_dev_id, {}).get('name', _dev_id)
        for c in (_rec.get('credentials') or []):
            rad = int(c.get('rotate_after_days', 0) or 0)
            if not rad:
                continue
            anchor = int(c.get('rotated_at') or c.get('created_at') or 0)
            if not anchor:
                continue
            age = int((now - anchor) / 86400)
            if age > rad:
                items.append({'severity': 'info', 'kind': 'cred_rotation', 'device': dname,
                              'summary': f"Credential '{c.get('label','?')}' is {age}d old "
                                         f"(rotate every {rad}d)"})

    # v6.1.1: API keys past their rotate_after_days policy — surfaced, never
    # auto-rotated (see handle_apikeys_rotate; the one-click Rotate action lives
    # in Settings -> API keys). Skips already-inactive/rotated-out keys.
    try:
        _keys_rot = load(APIKEYS_FILE) or {}
    except Exception:
        _keys_rot = {}
    for _kid, _k in _keys_rot.items():
        if not _k.get('active', True):
            continue
        rad = int(_k.get('rotate_after_days', 0) or 0)
        if not rad:
            continue
        age = int((now - int(_k.get('created', 0) or 0)) / 86400)
        if age > rad:
            items.append({'severity': 'info', 'kind': 'apikey_rotation_due',
                          'device': _k.get('name') or _kid,
                          'summary': f"API key '{_k.get('name','?')}' is {age}d old "
                                     f"(rotate every {rad}d)"})

    # v3.4.2: agent integrity — a running agent whose binary hash differs from
    # the canonical published build on the current version (tamper / partial
    # update / corruption). Critical: it's a security signal.
    _canonical_agent_sha = _get_agent_sha256()
    if _canonical_agent_sha:
        for dev_id, dev in monitored.items():
            if dev.get('agentless'):
                continue
            if _agent_integrity_status(dev, _canonical_agent_sha, SERVER_VERSION) == 'mismatch':
                items.append({'severity': 'critical', 'kind': 'agent_integrity',
                              'device': dev.get('name', dev_id),
                              'summary': 'Agent binary hash does not match the published build'})

    # v3.4.2: after-hours activity (fleet-level security signal, last 24h). No
    # device_id, so it shows in NA without dinging any single device's health.
    if (cfg.get('after_hours') or {}).get('enabled'):
        try:
            ah_hits = (load(AFTER_HOURS_FILE) or {}).get('hits') or []
            recent_ah = [h for h in ah_hits if h.get('ts', 0) >= now - 86400]
        except Exception:
            recent_ah = []
        if recent_ah:
            items.append({'severity': 'warning', 'kind': 'after_hours', 'device': '',
                          'summary': f'{len(recent_ah)} event(s) fired outside business hours (last 24h)'})

    # v3.0.1 (attention audit): services_watched that are NOT active right now.
    # Recent Activity gets a `service_down` event when the transition happens,
    # but the previous version of this function never surfaced the ongoing
    # condition — so a stopped service sat in event history but never showed
    # up as "fix this now". Now they do. service_down also gets a mitigation
    # target so the 🩺 button opens the right playbook (status + journal +
    # restart). systemd's `failed` and `inactive` states both qualify.
    try:
        services_store = load(SERVICES_FILE) or {}
    except Exception:
        services_store = {}
    for dev_id, dev in monitored.items():
        entry = services_store.get(dev_id) or {}
        for svc in (entry.get('services') or []):
            active = svc.get('active')
            unit   = svc.get('unit') or svc.get('name')
            if not unit or active == 'active' or active == 'activating':
                continue
            # Skip units that haven't been loaded — those are agent-side
            # config issues, not "service down" alerts.
            if active in (None, 'unknown'):
                continue
            sev = 'critical' if active == 'failed' else 'warning'
            items.append({
                'severity': sev, 'kind': 'service_down',
                'device':   dev.get('name', dev_id),
                'summary':  f'{unit} — {active}{(" / " + svc["sub"]) if svc.get("sub") else ""}',
                # `target` propagates into mitigation_target via the
                # decorator below so the diagnostic playbook can substitute it
                'target':   unit,
            })

    # v3.0.1 (attention audit): monitor targets currently DOWN. monitor_down
    # fires a webhook on transition but had no NA item — meaning a service
    # behind a check that stayed down between dashboard loads would only be
    # noticed via webhook alerts.
    try:
        mon_hist = load(MON_HIST_FILE) or {}
    except Exception:
        mon_hist = {}
    for mon in (cfg.get('monitors') or []):
        label = mon.get('label') or mon.get('target') or ''
        if not label:
            continue
        history = mon_hist.get(label) or []
        if not history:
            continue
        last = history[-1] if isinstance(history, list) else {}
        if last and last.get('ok') is False:
            items.append({
                'severity': 'critical', 'kind': 'monitor_down',
                'device':   label,
                'summary':  f'Monitor probe failing — {mon.get("type","?")} {mon.get("target","")[:80]}',
            })

    # v3.0.1 (attention audit): custom_script_fail. Failing scripts show in
    # Recent Activity but not in NA — flip that. Results are stored inside
    # each device record under `custom_script_results: {script_id: {...}}`.
    for dev_id, dev in monitored.items():
        script_results = dev.get('custom_script_results') or {}
        if not isinstance(script_results, dict):
            continue
        for script_id, r in script_results.items():
            if not isinstance(r, dict):
                continue
            # exit_code is reported as `rc` or `exit_code` depending on
            # vintage; accept both.
            rc = r.get('rc')
            if rc is None: rc = r.get('exit_code')
            if rc is None or rc == 0:
                continue
            ran = r.get('ran_at') or r.get('ts') or 0
            items.append({
                'severity': 'warning', 'kind': 'custom_script_fail',
                'device':   dev.get('name', dev_id),
                'summary':  f'{r.get("script_name", script_id)} failed '
                            f'(rc={rc})' + (f' at {time.strftime("%H:%M", time.localtime(ran))}' if ran else ''),
            })

    # v3.0.1 (attention audit, iteration 3): transient critical events from
    # fleet_events.json. Some alerts are events, not states — a log pattern
    # fires once per match, there's no "currently broken" file to consult.
    # Per Jakob's directive ("warning -> needs attention"), surface recent
    # ones as NA items keyed deterministically so the × ignore button can
    # silence them per-rule. After ATTENTION_EVENT_TTL they auto-expire and
    # disappear from NA (still visible in Recent Activity, which is what
    # that surface is for).
    ATTENTION_EVENT_TTL = 24 * 3600    # 24h window
    cutoff_ts = now - ATTENTION_EVENT_TTL
    # Dedup by stable key so a noisy rule firing 50 times in a day produces
    # exactly one NA card the user can dismiss with one click.
    seen_event_keys = set()
    try:
        # v5.8.0 FIX: fleet_events is written {events:[...]}; this reader used to
        # do `load() or []`, which returns the DICT and then iterates its KEYS —
        # so it silently processed zero events, and log-alert / new-port / ssh-key
        # NA cards were dropped. Read the wrapped list correctly.
        events = (load(FLEET_EVENTS_FILE) or {}).get('events') or []
    except Exception:
        events = []
    for ev in events:
        if not isinstance(ev, dict): continue
        ts = ev.get('ts', 0)
        if ts < cutoff_ts: continue
        ev_type = ev.get('event', '')
        payload = ev.get('payload') or {}
        did     = payload.get('device_id', '')
        # Only events tied to devices we still monitor
        if did and did not in monitored: continue
        dev_name = payload.get('name') or (monitored.get(did) or {}).get('name', did)
        if ev_type == 'log_alert':
            sev_raw = (payload.get('severity') or 'WARN').upper()
            # OK severities never get here (silenced earlier in fire path),
            # but defend anyway
            if sev_raw == 'OK': continue
            sev = 'critical' if sev_raw == 'CRIT' else 'warning'
            unit    = payload.get('unit', '')
            pattern = payload.get('pattern', '')
            dedup_key = f'log_alert|{did}|{unit}|{pattern[:60]}'
            if dedup_key in seen_event_keys: continue
            seen_event_keys.add(dedup_key)
            # v3.2.3: surface the actual matched line, not the rule regex.
            # Previously the card showed `matched 'warning|error|FATAL'`
            # which is useless — the operator already knows the rule.
            # They need to see WHAT MATCHED. Sample comes from the
            # webhook payload (first 3 matches captured at fire time).
            samples = payload.get('sample') or []
            count = payload.get('count', '?')
            count_label = f'{count} hit{"s" if count != 1 else ""}'
            # v3.2.3 (#3): per-rule display_template renders first when
            # the operator wrote one. Falls back to the default sample
            # text when the rule has no template.
            tmpl = payload.get('display_template')
            tmpl_text = _render_log_template(tmpl, payload, dev_name)
            if tmpl_text:
                summary_text = tmpl_text
            elif samples:
                first = str(samples[0])[:140]
                summary_text = f'{unit} matched ({count_label}): {first}'
            else:
                summary_text = f'{unit} matched pattern {pattern!r} ({count_label})'
            items.append({
                'severity': sev, 'kind': 'log_alert',
                'device':   dev_name,
                'unit':     unit,
                'summary':  summary_text,
                'samples':  [str(s)[:200] for s in samples[:3]],
                'pattern':  pattern,
            })
        elif ev_type == 'new_port_detected':
            # Security signal — surface as warning. User dismisses to
            # acknowledge.
            port = payload.get('port', '?')
            proto = payload.get('proto', 'tcp')
            dedup_key = f'new_port|{did}|{proto}|{port}'
            if dedup_key in seen_event_keys: continue
            seen_event_keys.add(dedup_key)
            items.append({
                'severity': 'warning', 'kind': 'new_port',
                'device':   dev_name,
                'summary':  f'New listening port {proto}/{port} — '
                            f'{payload.get("process", "unknown process")}',
            })
        elif ev_type == 'ssh_key_added':
            fp = (payload.get('fingerprint') or '')[:24]
            user = payload.get('user', '?')
            dedup_key = f'ssh_key|{did}|{user}|{fp}'
            if dedup_key in seen_event_keys: continue
            seen_event_keys.add(dedup_key)
            items.append({
                'severity': 'critical', 'kind': 'ssh_key',
                'device':   dev_name,
                'summary':  f'New SSH key for {user} — fingerprint {fp}',
            })

    # v3.4.0: hardware health (SMART / kernel) + disk-fill forecast. Same
    # data the device drawer's Health & Hardware card shows; surfaced here so
    # a dying disk or an imminent full filesystem lands on the home dashboard,
    # not just in the drawer. Agent hosts only (hardware isn't reported for
    # agentless devices), so iterate `monitored`.
    try:
        hw_all = load(HARDWARE_FILE) or {}
        for dev_id, dev in monitored.items():
            rec = hw_all.get(dev_id) or {}
            bad = [d for d in (rec.get('smart') or []) if _smart_disk_failed(d)]
            if bad:
                items.append({
                    'severity': 'critical', 'kind': 'hardware',
                    'device':   dev.get('name', dev_id),
                    'summary':  'SMART failure on '
                                + ', '.join(d.get('device', '?') for d in bad[:3]),
                })
            kern = rec.get('kernel') or {}
            if kern.get('reboot_for_kernel'):
                items.append({
                    'severity': 'warning', 'kind': 'hardware',
                    'device':   dev.get('name', dev_id),
                    'summary':  f'Newer kernel installed ({kern.get("latest_installed", "?")}) '
                                f'— reboot to apply',
                })
    except Exception:
        pass

    try:
        mh_all = load(METRICS_HIST_FILE) or {}
        for dev_id, dev in monitored.items():
            samples = (mh_all.get(dev_id) or {}).get('samples') or []
            for m in forecast.forecast_mounts(samples):
                d2f = m.get('days_to_full')
                if d2f is None:
                    continue
                if d2f <= 7:
                    sev = 'critical'
                elif d2f <= 21:
                    sev = 'warning'
                else:
                    continue
                items.append({
                    'severity': sev, 'kind': 'disk',
                    'device':   dev.get('name', dev_id),
                    'summary':  f'{m["path"]} fills in ~{int(round(d2f))} days at current '
                                f'growth ({m["current_percent"]}% now)',
                })
    except Exception:
        pass

    items.sort(key=lambda i: _ATTN_RANK.get(i['severity'], 0), reverse=True)

    # v3.2.3: routing matrix gate — NA shows only kinds whose
    # needs_attention channel is enabled. Legacy
    # dashboard_hidden_attention_kinds is migrated into channel_routing
    # by _channel_routing() so both old and new configs work.
    # NA_KIND_ALIAS resolves the few cases where _compute_attention's
    # emitted kind name diverges from the routing kind name
    # (service_down → service, etc.) so the matrix toggle actually
    # silences the items the operator expects.
    routing = _channel_routing()
    def _na_routing_key(item_kind):
        return NA_KIND_ALIAS.get(item_kind, item_kind)
    items = [i for i in items
             if (routing.get(_na_routing_key(i.get('kind'))) or CHANNEL_DEFAULT).get('needs_attention', True)]

    # v3.0.1: filter per-item ignores. Annotate each surviving item with
    # its stable key so the frontend can render an × button.
    ignored = _ignored_keys('needs_attention')
    filtered = []
    for i in items:
        key = _attention_item_key(i)
        if key in ignored:
            continue
        i['_ignore_key'] = key
        filtered.append(i)
    items = filtered

    # v3.0.1: decorate with device_id (looked up by device-name reverse map)
    # and mitigation_kind iff the alert kind has a playbook. Pre-existing
    # items.append calls don't include device_id — adding it here keeps the
    # change in one place. TLS items use a URL host for `device` (no real
    # device behind it) so they don't get a device_id, which is fine —
    # they're not mitigable anyway (covered by the ACME page).
    name_to_id = {}
    for did, dev in devices.items():
        nm = dev.get('name')
        if nm and nm not in name_to_id:
            name_to_id[nm] = did
    _mitigable_kinds = set(_MITIGATE_PLAYBOOKS.keys()) if '_MITIGATE_PLAYBOOKS' in globals() else set()
    for i in items:
        i['device_id'] = name_to_id.get(i.get('device'))
        if i.get('kind') in _mitigable_kinds and i.get('device_id'):
            i['mitigation_kind'] = i['kind']
            # service_down would also carry a target (the unit name); other
            # kinds don't need one. Keep target out of items for now since
            # service_down isn't yet emitted — added in a later iteration.
            if i.get('target'):
                i['mitigation_target'] = i['target']

    return items


_ATTENTION_CACHE_TTL = 10


def _attention_cache_file():
    # Computed lazily so tests that patch DATA_DIR see the right path.
    return DATA_DIR / 'attention_cache.json'


def _attention_payload(use_cache=True):
    """Build the {items, counts, total} payload, optionally from a 10s
    file-backed cache. CGI = no in-process cache, so the cache file's
    mtime is the only way to share work across requests. Falls back to
    a fresh compute if the cache file is missing, stale, or corrupt.

    The cache is busted when devices.json or alerts-affecting state
    files are newer than the cache — any heartbeat that wrote new
    sysinfo or transitioned a service updates devices.json, so the NA
    digest must recompute. This also makes tests deterministic without
    every test fixture having to clear an implementation-specific
    cache file."""
    cache_file = _attention_cache_file()
    if use_cache:
        try:
            if backend_exists(cache_file):
                cache_mtime = backend_mtime(cache_file)
                age = time.time() - cache_mtime
                if age < _ATTENTION_CACHE_TTL:
                    # Bust the cache if any underlying data file has been
                    # written more recently than the cache. backend_mtime()
                    # works under SQLite/Postgres too (these are storage keys,
                    # not on-disk files) — a raw .exists()/.stat() left the
                    # cache permanently cold on the DB backend.
                    fresher = False
                    for src in (DEVICES_FILE, FLEET_EVENTS_FILE,
                                CVE_FINDINGS_FILE, DRIFT_STATE_FILE,
                                IGNORED_ITEMS_FILE):
                        try:
                            if backend_mtime(src) > cache_mtime:
                                fresher = True
                                break
                        except Exception:
                            pass
                    if not fresher:
                        cached = load(cache_file)
                        if isinstance(cached, dict) and 'items' in cached:
                            return cached
        except Exception:
            pass
    items = _compute_attention()
    counts = {'critical': 0, 'warning': 0, 'info': 0}
    for i in items:
        counts[i['severity']] = counts.get(i['severity'], 0) + 1
    payload = {'items': items, 'counts': counts, 'total': len(items)}
    try:
        save(cache_file, payload)
    except Exception:
        pass
    return payload


def handle_attention():
    """GET /api/attention — the unified Needs Attention digest."""
    require_auth()
    respond(200, _attention_payload())


# v3.4.1: fleet health score. A single 0-100 rollup per device (and fleet-wide)
# derived from the SAME Needs Attention signals — so there is exactly one source
# of truth for "what's wrong" and the score can never disagree with the NA list.
# Each device starts at 100 and loses points per attention item by severity;
# the fleet score is the mean of per-device scores.
_HEALTH_WEIGHTS = {'critical': 25, 'warning': 8, 'info': 2}


def _health_grade(score):
    if score >= 90: return 'good'
    if score >= 70: return 'fair'
    if score >= 40: return 'poor'
    return 'critical'


# ── v3.12.0: per-asset risk score ────────────────────────────────────────────
# Weighted aggregation of the security/posture signals RemotePower already
# collects (no new probing). Higher = worse; capped at 100. Explainable: every
# point is attributed to a named factor.
_RISK_WEIGHTS = {
    'offline': 25, 'cve_critical': 8, 'cve_high': 3, 'pending_updates': 1,
    'exposed_world': 4, 'policy_violation': 6, 'expiry_expired': 10,
    'expiry_soon': 3, 'mount_issue': 12, 'reboot_required': 4,
    # v3.12.0: firewall posture + hardware/software health
    'firewall_off': 14, 'storage_degraded': 12, 'smart_failure': 12,
    'kernel_outdated': 6, 'failed_units': 3,
    # v4.10.0: more posture/health signals already collected (no new probing)
    'os_eol': 14, 'os_eol_soon': 4, 'overheating': 10, 'config_drift': 3,
    'clock_skew': 4, 'gateway_down': 10, 'oom_recent': 6,
}
_RISK_CAPS = {'cve_critical': 30, 'cve_high': 15, 'pending_updates': 15,
              'exposed_world': 20, 'policy_violation': 18, 'expiry_expired': 20,
              'mount_issue': 24, 'storage_degraded': 24, 'smart_failure': 24,
              'failed_units': 15, 'config_drift': 12}
# states (substring match) that mean a storage pool / RAID array is unhealthy
_RISK_STORAGE_BAD = ('degraded', 'faulted', 'offline', 'unavail', 'removed',
                     'suspended', 'error', 'fail')


def _risk_level(score):
    if score >= 80:
        return 'critical'
    if score >= 50:
        return 'high'
    if score >= 20:
        return 'medium'
    return 'low'


def _device_risk(dev_id, dev, cmdb_rec, cve_rec, sv_rec, now, ttl, hw_rec=None,
                 cve_ignore=None, exposure_mutes=None, pkg_entry=None):
    si = dev.get('sysinfo') or {}
    hw_rec = hw_rec or {}
    factors = []

    def _add(kind, pts, detail):
        pts = int(pts)
        if pts > 0:
            factors.append({'kind': kind, 'points': pts, 'detail': detail})

    last = dev.get('last_seen', 0)
    if last and (now - last) > ttl:
        _add('offline', _RISK_WEIGHTS['offline'], 'host is offline')
    finds = cve_rec.get('findings') if isinstance(cve_rec, dict) else cve_rec
    # v3.13.0: respect the CVE ignore list (accepted-risk findings) — an ignored
    # CVE shouldn't keep driving the asset's risk score.
    if finds and cve_ignore is not None:
        try:
            finds = [f for f in cve_scanner.apply_ignore_list(list(finds), cve_ignore, dev_id)
                     if not f.get('ignored')]
        except Exception:
            pass
    crit = sum(1 for f in (finds or []) if isinstance(f, dict) and (f.get('severity') or '').lower() == 'critical')
    high = sum(1 for f in (finds or []) if isinstance(f, dict) and (f.get('severity') or '').lower() == 'high')
    if crit:
        _add('cve_critical', min(_RISK_CAPS['cve_critical'], crit * _RISK_WEIGHTS['cve_critical']), f'{crit} critical CVE(s)')
    if high:
        _add('cve_high', min(_RISK_CAPS['cve_high'], high * _RISK_WEIGHTS['cve_high']), f'{high} high CVE(s)')
    try:
        up = int(((si.get('packages') or {}).get('upgradable')) or 0)
    except (TypeError, ValueError):
        up = 0
    if up:
        _add('pending_updates', min(_RISK_CAPS['pending_updates'], up * _RISK_WEIGHTS['pending_updates']), f'{up} pending update(s)')
    # v3.13.0: don't count world-reachable sockets the operator has muted on the
    # Exposure page (surgical mute, or a host-level mute).
    world = sum(1 for p in (si.get('listening_ports') or [])
                if isinstance(p, dict) and p.get('scope') == 'world'
                and not _exposure_muted(p.get('process'), p.get('proto'), p.get('port'),
                                        exposure_mutes or [], dev_id))
    if world:
        _add('exposed_world', min(_RISK_CAPS['exposed_world'], world * _RISK_WEIGHTS['exposed_world']), f'{world} world-reachable service(s)')
    viol = len(sv_rec.get('violations') or []) if isinstance(sv_rec, dict) else 0
    if viol:
        _add('policy_violation', min(_RISK_CAPS['policy_violation'], viol * _RISK_WEIGHTS['policy_violation']), f'{viol} software-policy violation(s)')
    expired = soon = 0
    for v in _device_contract_status(cmdb_rec):
        if v.get('status') == 'expired':
            expired += 1
        else:
            soon += 1
    if expired:
        _add('expiry_expired', min(_RISK_CAPS['expiry_expired'], expired * _RISK_WEIGHTS['expiry_expired']), f'{expired} expired contract/license/warranty')
    if soon:
        _add('expiry_soon', soon * _RISK_WEIGHTS['expiry_soon'], f'{soon} expiring soon')
    mi = len([m for m in (si.get('mount_issues') or []) if isinstance(m, dict)])
    if mi:
        _add('mount_issue', min(_RISK_CAPS['mount_issue'], mi * _RISK_WEIGHTS['mount_issue']), f'{mi} mount issue(s)')
    if si.get('reboot_required'):
        _add('reboot_required', _RISK_WEIGHTS['reboot_required'], 'reboot required')
    # ── v3.12.0: firewall posture ────────────────────────────────────────────
    fwsum = si.get('firewall')
    if isinstance(fwsum, dict) and fwsum.get('backends'):
        # Richer per-backend view (nftables/iptables/ufw/ebtables). active is
        # True / False / None(=couldn't read). Only penalise an EXPLICIT False —
        # never when the agent couldn't read the ruleset (e.g. not root).
        if fwsum.get('active') is False:
            _add('firewall_off', _RISK_WEIGHTS['firewall_off'],
                 'no active host firewall (nftables/iptables/ufw/ebtables)')
        elif fwsum.get('active'):
            for b in fwsum['backends']:
                if (b.get('active') and not b.get('rules')
                        and (b.get('policy') or '').upper() == 'ACCEPT'):
                    _add('firewall_off', max(1, _RISK_WEIGHTS['firewall_off'] // 2),
                         f"{b.get('name')} defaults to ACCEPT with no rules")
                    break
    else:
        # Fallback for agents that only ship the drift fingerprint.
        fw = si.get('firewall_fp')
        if isinstance(fw, dict):
            fwb = (fw.get('backend') or '').lower()
            if fwb == 'none':
                _add('firewall_off', _RISK_WEIGHTS['firewall_off'], 'no host firewall active')
            elif fwb and not fw.get('rules'):
                _add('firewall_off', _RISK_WEIGHTS['firewall_off'], 'host firewall has no rules')
    # ── v3.12.0: storage / RAID health ───────────────────────────────────────
    bad_pools = [p for p in (si.get('storage_health') or [])
                 if isinstance(p, dict)
                 and any(b in (p.get('state') or '').lower() for b in _RISK_STORAGE_BAD)]
    if bad_pools:
        names = ', '.join(p.get('name', '?') for p in bad_pools[:3])
        _add('storage_degraded',
             min(_RISK_CAPS['storage_degraded'], len(bad_pools) * _RISK_WEIGHTS['storage_degraded']),
             f'{len(bad_pools)} degraded pool/array ({names})')
    # ── v3.12.0: disk SMART + kernel currency (from hardware.json) ────────────
    smart_bad = sum(1 for d in (hw_rec.get('smart') or []) if _smart_disk_failed(d))
    if smart_bad:
        _add('smart_failure',
             min(_RISK_CAPS['smart_failure'], smart_bad * _RISK_WEIGHTS['smart_failure']),
             f'{smart_bad} disk(s) reporting SMART failure')
    if (hw_rec.get('kernel') or {}).get('reboot_for_kernel'):
        _add('kernel_outdated', _RISK_WEIGHTS['kernel_outdated'],
             'running kernel older than newest installed')
    # ── v3.12.0: failed systemd services (what software is broken) ────────────
    fu = len([u for u in (si.get('failed_units') or []) if isinstance(u, str)])
    if fu:
        _add('failed_units',
             min(_RISK_CAPS['failed_units'], fu * _RISK_WEIGHTS['failed_units']),
             f'{fu} failed system service(s)')
    # ── v4.10.0: more posture/health signals (all already collected) ─────────
    # OS end-of-life — no security updates is a real, durable risk.
    eol = _device_os_eol(dev, pkg_entry or {})
    if eol and eol.get('status') == 'eol':
        _add('os_eol', _RISK_WEIGHTS['os_eol'],
             f"{eol.get('label', 'OS')} is past end-of-life — no security updates")
    elif eol and eol.get('status') == 'soon':
        _add('os_eol_soon', _RISK_WEIGHTS['os_eol_soon'],
             f"{eol.get('label', 'OS')} reaches end-of-life in {eol.get('days', 0)}d")
    # Overheating — hottest board/disk/GPU sensor vs the thermal thresholds.
    hottest_c = None
    for _src, _key in ((hw_rec.get('temps') or [], 'current_c'),
                       (hw_rec.get('smart') or [], 'temperature_c'),
                       (hw_rec.get('gpus') or [], 'temp_c')):
        for _e in _src:
            _c = _e.get(_key) if isinstance(_e, dict) else None
            if isinstance(_c, (int, float)) and (hottest_c is None or _c > hottest_c):
                hottest_c = float(_c)
    if hottest_c is not None and hottest_c >= THERMAL_HOT_C:
        _crit_t = hottest_c >= THERMAL_CRIT_C
        _add('overheating',
             _RISK_WEIGHTS['overheating'] if _crit_t else _RISK_WEIGHTS['overheating'] // 2,
             f"hottest sensor at {round(hottest_c, 1)} °C ({'critical' if _crit_t else 'hot'})")
    # Config drift from the tracked baseline.
    drifted = [f for f, s in (dev.get('drift_state') or {}).items()
               if isinstance(s, dict) and s.get('status') == 'drifted' and not s.get('ignored')]
    if drifted:
        _add('config_drift',
             min(_RISK_CAPS['config_drift'], len(drifted) * _RISK_WEIGHTS['config_drift']),
             f'{len(drifted)} config file(s) drifted from baseline')
    if isinstance(si.get('clock'), dict) and si['clock'].get('skewed'):
        _add('clock_skew', _RISK_WEIGHTS['clock_skew'], 'system clock skewed / NTP out of sync')
    if isinstance(si.get('gateway'), dict) and si['gateway'].get('reachable') is False:
        _add('gateway_down', _RISK_WEIGHTS['gateway_down'], 'default gateway unreachable')
    _lo = si.get('last_oom_ts')
    if isinstance(_lo, (int, float)) and _lo > 0 and (now - _lo) < 86400:
        _add('oom_recent', _RISK_WEIGHTS['oom_recent'], 'OOM killer fired in last 24h')
    score = min(100, sum(f['points'] for f in factors))
    return {'device_id': dev_id, 'device_name': dev.get('name', dev_id),
            'score': score, 'level': _risk_level(score),
            'factors': sorted(factors, key=lambda f: -f['points'])}


_FLEET_RISK_CACHE_TTL = 10


def _fleet_risk_cache_file():
    return DATA_DIR / 'fleet_risk_cache.json'


def _fleet_risk_cached(use_cache=True):
    """File-backed 10s cache around ``_compute_fleet_risk`` — mirrors
    ``_attention_payload``. CGI spawns a fresh process per request, so a file
    cache is the only way to avoid recomputing the full-fleet risk (with its
    per-device date parsing) on both ``/api/risk`` and the ``/api/home`` path
    within the same few seconds. The cached value is the scope-independent full
    fleet list; callers scope-filter afterwards, so it's safe to share.

    Busted whenever any source file is newer than the cache (a heartbeat that
    rewrote devices.json, a fresh CVE scan, a policy/inventory update)."""
    cache_file = _fleet_risk_cache_file()
    if use_cache:
        try:
            if backend_exists(cache_file):
                cache_mtime = backend_mtime(cache_file)
                if (time.time() - cache_mtime) < _FLEET_RISK_CACHE_TTL:
                    fresher = False
                    for src in (DEVICES_FILE, CMDB_FILE, CVE_FINDINGS_FILE,
                                SOFTWARE_VIOLATIONS_FILE, HARDWARE_FILE,
                                CVE_IGNORE_FILE, CONFIG_FILE, PACKAGES_FILE):
                        try:
                            if backend_mtime(src) > cache_mtime:
                                fresher = True
                                break
                        except Exception:
                            pass
                    if not fresher:
                        cached = load(cache_file)
                        if isinstance(cached, dict) and isinstance(cached.get('devices'), list):
                            return cached['devices']
        except Exception:
            pass
    out = _compute_fleet_risk()
    try:
        save(cache_file, {'devices': out})
    except Exception:
        pass
    return out


def _compute_fleet_risk():
    """Per-asset risk for every monitored device. Pure aggregation over stored
    data — safe to call on demand."""
    devices = load(DEVICES_FILE) or {}
    cmdb = _cmdb_load()
    cve = (load(CVE_FINDINGS_FILE) or {}) if backend_exists(CVE_FINDINGS_FILE) else {}
    sv = (load(SOFTWARE_VIOLATIONS_FILE) or {}) if backend_exists(SOFTWARE_VIOLATIONS_FILE) else {}
    hw = (load(HARDWARE_FILE) or {}) if backend_exists(HARDWARE_FILE) else {}
    # v3.13.0: ignored CVEs + muted exposure must not contribute to risk.
    cve_ignore = (load(CVE_IGNORE_FILE) or {}) if backend_exists(CVE_IGNORE_FILE) else {}
    exposure_mutes = (load(CONFIG_FILE) or {}).get('exposure_mutes') or []
    # v4.10.0: structured os_id/version_id for the OS end-of-life factor.
    pkgs = (load(PACKAGES_FILE) or {}) if backend_exists(PACKAGES_FILE) else {}
    now = int(time.time())
    try:
        ttl = get_online_ttl()
    except Exception:
        ttl = 180
    out = []
    for dev_id, dev in devices.items():
        if not isinstance(dev, dict) or dev.get('monitored') is False or dev.get('agentless'):
            continue
        out.append(_device_risk(dev_id, dev, cmdb.get(dev_id) or {},
                                cve.get(dev_id) or {}, sv.get(dev_id) or {}, now, ttl,
                                hw.get(dev_id) or {},
                                cve_ignore=cve_ignore, exposure_mutes=exposure_mutes,
                                pkg_entry=pkgs.get(dev_id) or {}))
    out.sort(key=lambda r: -r['score'])
    return out


def handle_risk_overview():
    """GET /api/risk — per-asset risk score (0-100) with an explainable factor
    breakdown, plus a fleet summary. Built purely from already-stored data."""
    require_auth()
    risks = _fleet_risk_cached()
    scope = _caller_scope()
    if scope is not None:
        devs = load(DEVICES_FILE) or {}
        risks = [r for r in risks if _device_in_scope(scope, devs.get(r['device_id'], {}))]
    counts = {'low': 0, 'medium': 0, 'high': 0, 'critical': 0}
    for r in risks:
        counts[r['level']] = counts.get(r['level'], 0) + 1
    avg = round(sum(r['score'] for r in risks) / len(risks)) if risks else 0
    # master-improvement-scoping #10: conditional GET keyed off the same
    # cache-freshness marker _fleet_risk_cached() already maintains (mtime of
    # fleet_risk_cache.json, bumped exactly when the underlying data actually
    # changed) — a poller re-fetching this dashboard endpoint every N seconds
    # gets a bodyless 304 on every call where nothing changed.
    try:
        etag_source = (backend_mtime(_fleet_risk_cache_file()), scope)
    except Exception:
        etag_source = None
    if etag_source is not None:
        _respond_with_etag(
            {'devices': risks, 'counts': counts, 'avg': avg, 'total': len(risks)},
            etag_source)
    respond(200, {'devices': risks, 'counts': counts, 'avg': avg, 'total': len(risks)})


def _fleet_health(use_cache=True):
    payload = _attention_payload(use_cache=use_cache)
    items = payload.get('items') or []
    devices = load(DEVICES_FILE) or {}
    # Only score monitored devices. An unmonitored host is intentionally absent
    # from NA, so scoring it a perfect 100 would inflate the fleet average with
    # hosts the operator explicitly told us to ignore.
    per = {}
    for did, d in devices.items():
        if not isinstance(d, dict) or d.get('monitored') is False:
            continue
        per[did] = {'device_id': did, 'device_name': d.get('name', did),
                    'score': 100, 'critical': 0, 'warning': 0, 'info': 0}
    for it in items:
        did = it.get('device_id')
        sev = it.get('severity')
        rec = per.get(did)
        if rec is None or sev not in _HEALTH_WEIGHTS:
            continue
        rec['score'] = max(0, rec['score'] - _HEALTH_WEIGHTS[sev])
        rec[sev] += 1
    # v3.13.0: fleet health is now derived purely from Needs-Attention signals.
    # The per-asset risk score is a SEPARATE lens (security posture) and no
    # longer blends into / caps health — they're independent on purpose.
    # Worst first (lowest score; ties broken by critical count) so the UI can
    # slice the top N "needs attention most" devices without re-sorting.
    devs = sorted(per.values(), key=lambda r: (r['score'], -r['critical']))
    fleet = round(sum(r['score'] for r in devs) / len(devs)) if devs else 100
    return {
        'score':         fleet,
        'grade':         _health_grade(fleet),
        'devices':       devs,
        'counts':        payload.get('counts') or {},
        'total_devices': len(devs),
    }


def handle_fleet_health():
    """GET /api/fleet/health — 0-100 health score per device + fleet aggregate.

    Built on the Needs Attention digest, so it's cheap (shares the 10s NA cache)
    and always consistent with the NA list. Auth: require_auth."""
    require_auth()
    h = _fleet_health()
    # v3.5.0 RBAC v2: filter per-device rows to the caller's scope and recompute
    # the headline score/total over just those devices.
    scope = _caller_scope()
    if scope is not None:
        devs = load(DEVICES_FILE) or {}
        rows = [d for d in (h.get('devices') or [])
                if _device_in_scope(scope, devs.get(d.get('device_id'), {}))]
        scores = [d['score'] for d in rows if isinstance(d.get('score'), (int, float))]
        h = {**h, 'devices': rows, 'total_devices': len(rows),
             'score': round(sum(scores) / len(scores)) if scores else None}
    respond(200, h)


_HEALTH_HIST_MAX = 180   # keep ~6 months of daily samples per series


def _maybe_sample_health(now=None):
    """Record at most one health-score sample per UTC day (fleet + per device).

    Daily-gated like _maybe_sample_metrics: the first heartbeat of a new day
    computes _fleet_health() once and appends {date, ts, score} to the fleet
    series and each device's series; later heartbeats that day exit after a
    single date comparison. Stored in health_history.json:
        {'fleet': [{date, ts, score, grade}, ...],
         'devices': {dev_id: [{date, ts, score}, ...]}}
    Series are trimmed to _HEALTH_HIST_MAX. Failures never raise (best-effort,
    called from the heartbeat hot path)."""
    now = int(now or time.time())
    import datetime as _dt
    day = _dt.datetime.fromtimestamp(now, _dt.timezone.utc).strftime('%Y-%m-%d')
    # v5.8.0 (PERF): cheap read-only pre-gate BEFORE taking the write lock. This
    # runs from main() on every request; health_history.json is a cold blob, so
    # entering _LockedUpdate unconditionally did a BEGIN IMMEDIATE + full-blob
    # rewrite on every heartbeat/poll just to re-confirm "already sampled today".
    # The in-lock check below still guards the race (two requests racing the gate).
    _hh = load(HEALTH_HIST_FILE) or {}
    _hf = _hh.get('fleet') or []
    if _hf and _hf[-1].get('date') == day:
        return
    try:
        with _LockedUpdate(HEALTH_HIST_FILE) as store:
            fleet = store.setdefault('fleet', [])
            if fleet and fleet[-1].get('date') == day:
                return  # already sampled today
            health = _fleet_health()
            fleet.append({'date': day, 'ts': now,
                          'score': health['score'], 'grade': health['grade']})
            store['fleet'] = fleet[-_HEALTH_HIST_MAX:]
            devices = store.setdefault('devices', {})
            for d in health.get('devices', []):
                did = d['device_id']
                series = devices.setdefault(did, [])
                if series and series[-1].get('date') == day:
                    continue
                series.append({'date': day, 'ts': now, 'score': d['score']})
                devices[did] = series[-_HEALTH_HIST_MAX:]
            # Drop series only for devices that no longer EXIST (deleted hosts),
            # NOT ones merely set monitored:false. _fleet_health() omits
            # unmonitored devices, so pruning by the sampled set would wipe an
            # unmonitored host's accumulated history — and it would restart from
            # zero when re-monitored. Keep any id still present in the store.
            existing_ids = set(load(DEVICES_FILE) or {})
            for gone in [k for k in devices if k not in existing_ids]:
                del devices[gone]
    except Exception as e:
        sys.stderr.write(f'[remotepower] health sample failed: {e}\n')


def handle_fleet_health_history():
    """GET /api/fleet/health/history?device=<id> — health-score time series.

    Without ?device, returns the fleet series. With it, that device's series.
    Auth: require_auth."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    dev_id = (qs.get('device') or [''])[0].strip()
    store = load(HEALTH_HIST_FILE) or {}
    if dev_id:
        _scope_block_device(dev_id)   # v3.5.0 RBAC v2: per-device series
        series = (store.get('devices') or {}).get(dev_id) or []
        respond(200, {'device_id': dev_id, 'series': series})
    respond(200, {'series': store.get('fleet') or []})


def handle_device_metrics_history(dev_id):
    """GET /api/devices/<id>/metrics-history — daily memory / swap / busiest-mount
    series for the Trends charts. Reuses the forecaster's metrics_history samples.
    Auth: require_auth, scoped (a scoped role only sees its own devices)."""
    require_auth()
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    scope = _caller_scope()
    if scope is not None:
        dev = device_get(dev_id) or {}
        if not _device_in_scope(scope, dev):
            respond(403, {'error': 'Device outside your role scope'})
    # v3.13.0: the store shape is {dev_id: {'samples': [...]}} — the old
    # `.get(dev_id) or []` handed a dict to `samples[-120:]` (a no-op/throw), so
    # the per-device Trends chart was effectively broken. Read 'samples'.
    rec = (load(METRICS_HIST_FILE) or {}).get(dev_id) or {}
    samples = rec.get('samples') or []
    mem, swap, disk, load_sat = [], [], [], []
    # v3.13.0: per-mount disk series (incl. NFS/SMB shares) so each filesystem —
    # not just the busiest — can be trended on the chart.
    mount_pts, mount_net = {}, set()
    for s in samples[-120:]:
        ts = s.get('ts')
        if isinstance(s.get('mem_percent'), (int, float)):
            mem.append({'ts': ts, 'v': s['mem_percent']})
        if isinstance(s.get('swap_percent'), (int, float)):
            swap.append({'ts': ts, 'v': s['swap_percent']})
        sm = s.get('mounts') or []
        busiest = max((m.get('percent', 0) for m in sm), default=None)
        if isinstance(busiest, (int, float)):
            disk.append({'ts': ts, 'v': busiest})
        for m in sm:
            p, v = m.get('path'), m.get('percent')
            if not p or not isinstance(v, (int, float)):
                continue
            mount_pts.setdefault(p, []).append({'ts': ts, 'v': v})
            if m.get('network'):
                mount_net.add(p)
        # CPU-load saturation: loadavg_1m as a percentage of core count
        # (100% = load equals cores). Pre-v3.9.0 samples lack these fields.
        lv = s.get('loadavg_1m'); cores = s.get('cpu_count')
        if isinstance(lv, (int, float)) and lv >= 0 and isinstance(cores, (int, float)) and cores > 0:
            load_sat.append({'ts': ts, 'v': round(lv / cores * 100, 1)})
    series = [{'name': 'memory %', 'points': mem},
              {'name': 'swap %', 'points': swap},
              {'name': 'disk % (busiest)', 'points': disk}]
    if load_sat:
        series.append({'name': 'cpu load %', 'points': load_sat})
    # Per-mount series, ordered by the most recent sample, capped so the chart
    # stays readable. Network shares are labelled so the SMB/NFS line stands out.
    recent_paths, seen_p = [], set()
    for m in ((samples[-1].get('mounts') if samples else []) or []):
        p = m.get('path')
        if p and p in mount_pts and p not in seen_p:
            seen_p.add(p); recent_paths.append(p)
    for p in recent_paths[:8]:
        label = f'disk {p}' + (' (net)' if p in mount_net else '')
        series.append({'name': label, 'points': mount_pts[p]})
    respond(200, {'device_id': dev_id, 'series': series})


def _check_health_webhooks():
    """Edge-triggered health-score alerting (heartbeat hook).

    Opt-in: does nothing unless `health_alert_threshold` is a positive int in
    config. Fires `health_degraded` the first beat a device's score drops below
    the threshold and `health_recovered` when it climbs back — tracked in a
    per-device state file so each transition fires exactly once, not on every
    heartbeat. Only monitored devices are scored (via _fleet_health)."""
    cfg = load(CONFIG_FILE) or {}
    try:
        threshold = int(cfg.get('health_alert_threshold') or 0)
    except (TypeError, ValueError):
        threshold = 0
    if threshold <= 0:
        return
    health = _fleet_health()
    state = load(HEALTH_ALERT_STATE_FILE) or {}
    prev = state.get('degraded') or {}
    new_degraded = {}
    for d in health.get('devices', []):
        did = d['device_id']
        is_deg = d['score'] < threshold
        was_deg = bool(prev.get(did))
        if is_deg:
            new_degraded[did] = True
            if not was_deg:
                fire_webhook('health_degraded', {
                    'device_id':   did,
                    'device_name': d['device_name'],
                    'score':       d['score'],
                    'grade':       _health_grade(d['score']),
                    'threshold':   threshold,
                    'critical':    d.get('critical', 0),
                    'warning':     d.get('warning', 0),
                })
        elif was_deg:
            fire_webhook('health_recovered', {
                'device_id':   did,
                'device_name': d['device_name'],
                'score':       d['score'],
                'threshold':   threshold,
            })
    if new_degraded != prev:
        state['degraded'] = new_degraded
        save(HEALTH_ALERT_STATE_FILE, state)


def _dashboard_upcoming(limit=3, horizon_days=45):
    """Next upcoming-or-ongoing events for the dashboard, merged across the
    calendar, scheduled power/script jobs, and maintenance windows. Each item:
    {title, when (epoch), ongoing (bool), kind}. Sorted by start, capped."""
    now = int(time.time())
    horizon = now + horizon_days * 86400
    items = []
    # Calendar events (recurrence-aware via _expand_event). Include those that
    # started recently and are still running (ongoing) plus future ones.
    try:
        for ev in (load(CALENDAR_FILE) or {}).get('events') or []:
            for occ in _expand_event(ev, now - 86400, horizon):
                try:
                    s = _parse_iso(occ['start'])
                except (ValueError, KeyError):
                    continue
                e = s
                if occ.get('end'):
                    try:
                        e = _parse_iso(occ['end'])
                    except ValueError:
                        e = s
                if e < now:
                    continue   # already finished
                items.append({'title': (occ.get('title') or 'Event')[:120],
                              'when': s, 'ongoing': s <= now <= e, 'kind': 'calendar'})
    except Exception:
        pass
    # Scheduled power actions / scripts (one-shot run_at, or recurring cron).
    try:
        for j in (load(SCHEDULE_FILE) or []):
            if not isinstance(j, dict):
                continue
            ts = None
            if j.get('run_at'):
                ts = int(j['run_at'])
            elif j.get('cron'):
                ts = _cron_next(j['cron'], now, horizon_days)
            if not ts or ts < now or ts > horizon:
                continue
            cmd = str(j.get('command', 'job'))
            label = cmd.replace('_', ' ')
            if j.get('device_name'):
                label = f"{label} · {j['device_name']}"
            items.append({'title': label[:120], 'when': ts, 'ongoing': False,
                          'kind': 'job'})
    except Exception:
        pass
    # Maintenance windows — currently active (ongoing) or upcoming one-shot/cron.
    try:
        for w in (load(MAINT_FILE) or {}).get('windows') or []:
            if not isinstance(w, dict):
                continue
            title = ('Maintenance: ' + (w.get('reason') or 'window'))[:120]
            if _window_active(w, now):
                items.append({'title': title, 'when': now, 'ongoing': True,
                              'kind': 'maintenance'})
                continue
            ts = None
            if w.get('start'):
                try:
                    ts = _parse_iso(w['start'])
                except ValueError:
                    ts = None
            elif w.get('cron'):
                ts = _cron_next(w['cron'], now, horizon_days)
            if ts and now <= ts <= horizon:
                items.append({'title': title, 'when': ts, 'ongoing': False,
                              'kind': 'maintenance'})
    except Exception:
        pass
    items.sort(key=lambda x: (not x['ongoing'], x['when']))
    return items[:limit]




def _dashboard_extra_widgets(devices_raw, cfg, now, want=None):
    """Cheap server-side summaries for the server-backed catalog widgets:
    open-alerts-by-severity, maintenance windows, monitor up/down, container
    issues, disk-fill ETA. All best-effort; a bad source yields an empty datum
    so the dashboard never breaks. Most catalog widgets render client-side from
    the devices/drift/cves payload and need nothing here.

    `want` (a set of enabled widget keys, or None for "all") gates the two
    genuinely expensive widgets — disk-fill ETA and the fleet checks roll-up —
    so they're only computed when an operator actually displays them."""
    def _g(k):
        return want is None or k in want
    out = {}
    # Load the hardware record once and share it across the smart/ups/temp, tls
    # and checks-roll-up widgets — avoids re-deep-copying hardware.json per
    # consumer. Only read it at all when one of those widgets is enabled.
    hw_all = (load(HARDWARE_FILE) or {}) \
        if any(_g(k) for k in ('smart', 'ups', 'temp', 'tls', 'checksrollup')) else {}
    # Open alerts by severity
    try:
        sev = {'critical': 0, 'high': 0, 'medium': 0, 'low': 0}
        for a in (load(ALERTS_FILE) or {}).get('alerts') or []:
            if a.get('acknowledged_at') or a.get('resolved_at'):
                continue
            s = a.get('severity')
            if s in sev:
                sev[s] += 1
        out['alertsev'] = sev
    except Exception:
        out['alertsev'] = {}
    # Maintenance windows: active now + upcoming
    try:
        active = upcoming = 0
        for w in (load(MAINT_FILE) or {}).get('windows') or []:
            if not isinstance(w, dict):
                continue
            if _window_active(w, now):
                active += 1
            elif w.get('start'):
                try:
                    if _parse_iso(w['start']) > now:
                        upcoming += 1
                except ValueError:
                    pass
            elif w.get('cron'):
                upcoming += 1
        out['maintenance'] = {'active': active, 'upcoming': upcoming}
    except Exception:
        out['maintenance'] = {}
    # Monitor up/down — from the latest result per target (monitor_history),
    # not len(cfg.monitors) vs monitor_notified, which double-counted tag/group
    # fan-out and stale flags (could report down > total). Recency-filtered so
    # deleted monitors' lingering history drops off.
    try:
        mh = load(MON_HIST_FILE) or {}
        cut = now - 3600
        latest = [v[-1] for v in mh.values()
                  if isinstance(v, list) and v and isinstance(v[-1], dict)
                  and (v[-1].get('ts') or 0) >= cut]
        if latest:
            up = sum(1 for e in latest if e.get('ok'))
            out['monitors'] = {'total': len(latest), 'up': up,
                               'down': len(latest) - up}
        else:
            n = len(cfg.get('monitors') or [])
            out['monitors'] = {'total': n, 'up': n, 'down': 0}
    except Exception:
        out['monitors'] = {}
    # Container issues (not-running across all reported hosts). Gated — reads
    # CONTAINERS_FILE and walks every container, so skip it when not displayed.
    if _g('containers'):
        try:
            stopped = 0
            store = load(CONTAINERS_FILE) or {}
            for dev_id, entry in store.items():
                if dev_id not in devices_raw or not isinstance(entry, dict):
                    continue
                for it in (entry.get('items') or []):
                    if isinstance(it, dict) and not _container_is_running(it.get('status')):
                        stopped += 1
            out['containers'] = {'stopped': stopped}
        except Exception:
            out['containers'] = {}
    # Disk-fill ETA (near-full hosts only — bounded). Computed once and shared
    # with the checks roll-up; only when one of those widgets is displayed.
    eta_shared = {}
    if _g('diskfill') or _g('checksrollup'):
        try:
            eta_shared = _disk_fill_eta(devices_raw)
        except Exception:
            eta_shared = {}
    if _g('diskfill'):
        try:
            rows = sorted(({'name': (devices_raw.get(d) or {}).get('name', d),
                            'days': v} for d, v in eta_shared.items()),
                          key=lambda r: r['days'])
            out['diskfill'] = rows[:6]
        except Exception:
            out['diskfill'] = []
    # Posture from the full device records (devices_raw already in hand).
    # v5.0.0 (perf): GATED behind the ?w= hint — this is an O(fleet) loop over
    # every device's sysinfo and previously ran on every /api/home poll even when
    # no posture widget was on the dashboard. We iterate nothing when none of the
    # posture widgets are enabled (computes-all when no hint is sent).
    _posture_keys = ('rebootreq', 'worldports', 'failedunits', 'timers', 'mounts',
                     'clockskew', 'gateway', 'oom', 'storagedeg')
    _posture_src = devices_raw.items() if any(_g(k) for k in _posture_keys) else []
    try:
        reboot, worldp, failedu, timersf = [], 0, 0, 0
        mounts = clockskew = gw_unreach = oom_recent = storagedeg = 0
        for did, d in _posture_src:
            if not isinstance(d, dict) or d.get('monitored') is False:
                continue
            si = d.get('sysinfo') or {}
            if si.get('reboot_required'):
                reboot.append(d.get('name', did))
            if any((p or {}).get('scope') == 'world' for p in (si.get('listening_ports') or [])):
                worldp += 1
            failedu += len(si.get('failed_units') or [])
            timersf += sum(1 for t in (si.get('timers') or [])
                           if isinstance(t, dict) and t.get('failed'))
            if si.get('mount_issues'):
                mounts += 1
            clk = si.get('clock')
            if isinstance(clk, dict) and clk.get('skewed'):
                clockskew += 1
            gwd = si.get('gateway')
            if isinstance(gwd, dict) and gwd.get('reachable') is False:
                gw_unreach += 1
            lo = si.get('last_oom_ts')
            if isinstance(lo, (int, float)) and lo > 0 and (now - lo) < 86400:
                oom_recent += 1
            for pool in (si.get('storage_health') or []):
                if isinstance(pool, dict) and (pool.get('state') or '').lower() not in (
                        'online', 'active', 'clean', 'healthy', 'ok'):
                    storagedeg += 1
                    break
        out['rebootreq'] = {'count': len(reboot), 'hosts': reboot[:8]}
        out['worldports'] = {'count': worldp}
        out['failedunits'] = {'count': failedu}
        out['timers'] = {'count': timersf}
        out['mounts'] = {'count': mounts}
        out['clockskew'] = {'count': clockskew}
        out['gateway'] = {'count': gw_unreach}
        out['oom'] = {'count': oom_recent}
        out['storagedeg'] = {'count': storagedeg}
    except Exception:
        out['rebootreq'] = out['worldports'] = {}
        out['failedunits'] = out['timers'] = {}
        out['mounts'] = out['clockskew'] = out['gateway'] = {}
        out['oom'] = out['storagedeg'] = {}
    # Hardware flags (shared hw_all)
    if any(_g(k) for k in ('smart', 'ups', 'temp')):
        try:
            cnt = lambda flag: sum(1 for r in hw_all.values()
                                   if isinstance(r, dict) and r.get(flag))
            out['smart'] = {'count': cnt('_smart_failed')}
            out['ups'] = {'count': cnt('_ups_on_battery')}
            out['temp'] = {'count': cnt('_temp_high')}
        except Exception:
            out['smart'] = out['ups'] = out['temp'] = {}
    # Backups: scheduled jobs (total + ran in 24h) AND backup-file-age monitors
    # (configured + currently stale, from the edge-trigger state file). So the
    # widget reflects "are backups healthy", not just "are jobs scheduled".
    try:
        store = load(BACKUP_JOBS_FILE) or {}
        jobs = store.get('jobs') if isinstance(store, dict) else store
        jobs = jobs or []
        ran = sum(1 for j in jobs if isinstance(j, dict)
                  and (now - (j.get('last_run') or 0)) < 86400)
        mons = cfg.get('backup_monitors') or []
        bstate = (load(DATA_DIR / 'backup_state.json') or {}) \
            if backend_exists(DATA_DIR / 'backup_state.json') else {}
        stale = sum(1 for v in bstate.values()
                    if isinstance(v, dict) and v.get('ok') is False)
        out['backups'] = {'total': len(jobs), 'ran24h': ran,
                          'monitors': len(mons), 'monitors_stale': stale}
    except Exception:
        out['backups'] = {}
    # ── wave 5: data-backed widgets ───────────────────────────────────────────
    # TLS / cert expiry (from the hardware record's cert_files inventory; non-CA)
    if _g('tls'):
        try:
            soon = now + 30 * 86400
            _ca = ('/etc/ssl/certs/', '/etc/pki/ca-trust',
                   '/usr/share/ca-certificates', '/etc/ca-certificates')
            rows = []
            for did, rec in hw_all.items():
                if not isinstance(rec, dict):
                    continue
                nm = (devices_raw.get(did) or {}).get('name', did)
                for c in (rec.get('cert_files') or []):
                    na = c.get('not_after') or 0
                    if 0 < na <= soon and not str(c.get('path', '')).startswith(_ca):
                        rows.append({'name': nm, 'days': max(0, int((na - now) / 86400))})
            rows.sort(key=lambda r: r['days'])
            out['tls'] = rows[:6]
        except Exception:
            out['tls'] = []
    # Active brute-force sources (BRUTE_FORCE_FILE + per-host _bf_active). Gated.
    if _g('bruteforce'):
        try:
            _, thr, win = _brute_config()
            cut = now - win
            bf = load(BRUTE_FORCE_FILE) or {}
            hosts = []
            for did, d in devices_raw.items():
                if not isinstance(d, dict):
                    continue
                if _bf_active(bf.get(did, {}) or {}, cut, thr):
                    hosts.append(d.get('name', did))
            out['bruteforce'] = {'count': len(hosts), 'hosts': hosts[:8]}
        except Exception:
            out['bruteforce'] = {}
    # Top bandwidth (sum of per-iface rx+tx bps from the device sysinfo).
    # v5.0.0 (perf): GATED — another O(fleet) sysinfo loop that previously ran on
    # every dashboard poll regardless of whether the bandwidth widget was shown.
    _bw_src = devices_raw.items() if _g('bandwidth') else []
    try:
        rows = []
        for did, d in _bw_src:
            if not isinstance(d, dict):
                continue
            nio = (d.get('sysinfo') or {}).get('network_io') or []
            bps = sum((n.get('rx_bps', 0) or 0) + (n.get('tx_bps', 0) or 0)
                      for n in nio if isinstance(n, dict))
            if bps > 0:
                rows.append({'name': d.get('name', did), 'bps': int(bps)})
        rows.sort(key=lambda r: -r['bps'])
        out['bandwidth'] = rows[:6]
    except Exception:
        out['bandwidth'] = []
    # Host-checks roll-up (OK/WARN/CRIT/UNKNOWN across the fleet). The one
    # genuinely heavy widget — only run it when it's actually on a dashboard.
    if _g('checksrollup'):
        try:
            # v4.3.0 perf: share _fleet_checks_rows' 15s cache with the
            # Checks page instead of re-running the O(fleet) _host_checks
            # loop inside every /api/home poll that shows this widget.
            scripts_all = _load_custom_scripts()
            # Non-security cache-key fingerprint (see docs/security-review-4.4.1.md).
            fp = hashlib.md5(json.dumps(
                [cfg.get('host_checks_disabled') or {},
                 cfg.get('custom_checks') or [],
                 cfg.get('exposure_mutes') or [], scripts_all],
                sort_keys=True, default=str).encode(), usedforsecurity=False).hexdigest()
            rows = _fleet_checks_rows(devices_raw, cfg, scripts_all, fp)
            roll = {'ok': 0, 'warning': 0, 'critical': 0, 'unknown': 0}
            for h in rows:
                if h.get('monitored') is False:
                    continue
                counts = (h.get('summary') or {}).get('counts') or {}
                for k in roll:
                    roll[k] += counts.get(k, 0)
            out['checksrollup'] = roll
        except Exception:
            out['checksrollup'] = {}
    # v4.7.0: homelab software integration health rollup (cheap — one file read).
    if _g('integrations'):
        try:
            latest = (load(INTEG_STATE_FILE) or {}).get('latest') or {}
            roll = {'ok': 0, 'warning': 0, 'critical': 0, 'unknown': 0, 'total': len(latest)}
            items = []
            for r in latest.values():
                st = r.get('status', 'unknown')
                if st in roll:
                    roll[st] += 1
                # v4.7.0: rich tiles — per-integration card with formatted stats.
                items.append({'id': r.get('id'), 'label': r.get('label'), 'type': r.get('type'),
                              'status': st, 'detail': r.get('detail'), 'version': r.get('version'),
                              'checked': r.get('checked'),
                              'stats': integrations_mod.format_stats(r.get('type'), r.get('metrics'))})
            # worst-first so the unhealthy tiles lead.
            _order = {'critical': 0, 'warning': 1, 'unknown': 2, 'ok': 3}
            items.sort(key=lambda x: (_order.get(x['status'], 9), str(x.get('label') or '')))
            roll['items'] = items
            out['integrations'] = roll
        except Exception:
            out['integrations'] = {}
    return out


def _server_tz_label():
    """Human label for the server's local timezone, e.g. 'CEST (UTC+02:00)'. Cron
    expressions are matched in server-local time (_cron_match -> localtime), so the
    UI shows this next to cron inputs to avoid TZ confusion."""
    try:
        now = time.localtime()
        tzname = time.strftime('%Z', now) or 'local'
        offs = -(time.altzone if (now.tm_isdst and time.daylight) else time.timezone)
        sign = '+' if offs >= 0 else '-'
        hh, mm = divmod(abs(offs) // 60, 60)
        return f'{tzname} (UTC{sign}{hh:02d}:{mm:02d})'
    except Exception:
        return 'server local time'


def handle_home():
    """GET /api/home — single round-trip for the Home dashboard.

    v3.3.0 consolidation: the dashboard previously fired 7 parallel
    requests on every 60s refresh (devices, drift, cves, fleet_events,
    mailwatch, config, links) plus a separate attention call. Under CGI,
    each request is a fresh Python process (~100–200 ms startup), so a
    50-device fleet with 5 operators on the Home page generated ~35
    CGI spawns per minute just for the dashboard. /api/home bundles
    everything into one process and trims devices to the slim shape
    Home actually renders.
    """
    require_auth()
    # Slim devices: omit sysinfo + listening_ports + brute_force_active
    # + snmp_status. Home only renders id/name/online/group/icon.
    # Inline the slim flag the same way ?slim=1 does in handle_devices_list,
    # but we can't call that handler directly (it calls respond() which
    # exits). Reproduce the slim path here.
    devices_raw = load(DEVICES_FILE)
    now = int(time.time())
    devices = []
    try:
        ttl = get_online_ttl()
    except Exception:
        ttl = 180
    for dev_id, dev in devices_raw.items():
        last_ping = dev.get('last_seen', 0)
        agentless = bool(dev.get('agentless', False))
        if agentless:
            is_online = _agentless_online(dev)
            missed = None
            offline_reason = None
        else:
            is_online = (now - last_ping) < ttl
            missed = max(0, (now - last_ping) // 60) if last_ping else None
            offline_reason = None
            if not is_online and last_ping:
                offline_reason = 'missed_polls' if (now - last_ping) < 300 else 'offline'
        # Home tile renderer reads d.sysinfo.packages.upgradable for the
        # pending-updates count. Include only that nested field; skip the
        # heavyweight rest (listening_ports, top_processes, etc.).
        pkgs = (dev.get('sysinfo') or {}).get('packages') or {}
        upgradable = pkgs.get('upgradable', 0)
        devices.append({
            'id': dev_id, 'name': dev.get('name', dev_id),
            'hostname': dev.get('hostname', ''),
            'os': dev.get('os', ''), 'ip': dev.get('ip', ''),
            'version': dev.get('version', ''), 'tags': dev.get('tags', []),
            'group': dev.get('group', ''), 'icon': dev.get('icon', ''),
            'monitored': dev.get('monitored', True),
            'metric_state': dev.get('metric_state') or {},
            'last_seen': last_ping, 'online': is_online,
            'offline_reason': offline_reason, 'missed_polls': missed,
            'agentless': agentless, 'device_type': dev.get('device_type', ''),
            'sysinfo': {'packages': {'upgradable': upgradable}},
        })

    # Fleet events (already small, server filters unmonitored + routing)
    try:
        store = load(FLEET_EVENTS_FILE) or {}
        events = (store.get('events') or [])
        unmonitored = {dev_id for dev_id, d in devices_raw.items()
                       if isinstance(d, dict) and d.get('monitored') is False}
        if unmonitored:
            events = [e for e in events
                      if (e.get('payload') or {}).get('device_id') not in unmonitored]
        events = [e for e in events
                  if _channel_allowed(e.get('event', ''), 'recent_activity')]
        fleet_events = list(reversed(events))[:50]
    except Exception:
        fleet_events = []

    # Drift summary — only the per-device drift count the Home tile
    # renderer reads. Mirror handle_drift_overview's row shape minimally.
    # v3.3.0 bugfix: iterate devices.json keys, not drift_state.json,
    # so deleted devices' lingering drift records don't inflate the
    # tile. handle_drift_overview already does it this way.
    drift_rows = []
    try:
        drift_state = load(DRIFT_STATE_FILE) or {}
        for ddev_id in devices_raw:
            dev_state = drift_state.get(ddev_id) or {}
            files = dev_state.get('files') or {}
            n_drifted = sum(1 for f in files.values()
                            if not f.get('dormant') and not f.get('ignored')
                            and f.get('exists', True)
                            and f.get('current_hash') != f.get('baseline_hash'))
            drift_rows.append({'device_id': ddev_id, 'drifted': n_drifted})
    except Exception:
        pass
    drift = {'devices': drift_rows}

    # CVE summary — Home only reads per-device counts (critical/high/medium/low).
    # v3.3.0 bugfix #1: apply the CVE ignore filter so the dashboard
    # tile matches the CVE page exactly.
    # v3.3.0 bugfix #2 (this commit): iterate devices.json keys, not
    # cve_findings.json. Otherwise findings from deleted devices that
    # still linger in the findings file inflate the tile. CVE page
    # already iterates devices.items().
    cve_devs = []
    try:
        findings_all = load(CVE_FINDINGS_FILE) or {}
        ignore_data  = load(CVE_IGNORE_FILE) or {}
        for cdev_id in devices_raw:
            entry = findings_all.get(cdev_id) or {}
            findings = entry.get('findings') or []
            counts = {'critical': 0, 'high': 0, 'medium': 0, 'low': 0}
            for f in findings:
                vid = f.get('vuln_id')
                ig = ignore_data.get(vid) if vid else None
                if ig and (ig.get('scope') == 'global' or ig.get('scope') == cdev_id):
                    continue
                sev = (f.get('severity') or '').lower()
                if sev in counts:
                    counts[sev] += 1
            cve_devs.append({'device_id': cdev_id, 'counts': counts})
    except Exception:
        pass
    cves = {'devices': cve_devs}

    # Mailwatch overview — derived from devices_raw (same shape as
    # handle_mailwatch_overview returns), inlined to avoid a second
    # DEVICES_FILE read.
    mailwatch_rows = []
    for dev_id, dev in (devices_raw or {}).items():
        paths = dev.get('mailbox_paths') or []
        if not paths:
            continue
        state = dev.get('mailbox_state') or {}
        mailwatch_rows.append({
            'device_id':   dev_id,
            'device_name': dev.get('name', dev_id),
            'paths':       paths,
            'dashboard':   bool(dev.get('mailbox_dashboard')),
            'threshold':   dev.get('mailbox_threshold') or 0,
            'counts':      state.get('counts') or {},
            'reported_at': state.get('reported_at', 0),
        })
    mailwatch_rows.sort(key=lambda r: r['device_name'].lower())
    mailwatch = {'devices': mailwatch_rows}

    # Config (full — Home only reads a handful of keys but cost is
    # negligible vs. shipping 7 parallel CGI requests)
    cfg = load(CONFIG_FILE) or {}

    # Links — operator-curated bookmarks
    links = (cfg.get('links') or [])

    # v4.1.0: which widgets the operator actually has enabled (?w=key1,key2),
    # so _dashboard_extra_widgets can skip the heavy ones. Absent param → all.
    _qs = _env('QUERY_STRING', '') or ''
    _want = None
    if 'w=' in _qs:
        _want = set(filter(None, urllib.parse.parse_qs(_qs).get('w', [''])[0].split(',')))

    respond(200, {
        'devices':      devices,
        'drift':        drift,
        'cves':         cves,
        'fleet_events': fleet_events,
        'mailwatch':    mailwatch,
        'links':        links,
        'server_tz':    _server_tz_label(),
        'fleet_note':   cfg.get('fleet_note', ''),
        # v6.0.0: tickets/billing/provisioning are ALWAYS-ON modules now (the
        # Settings → Advanced opt-in toggles are gone); flags kept for older
        # frontends, permanently true.
        'tickets_enabled': True,
        'billing_enabled': True,
        'ticket_devices': _open_ticket_device_ids(),
        'tickets_open': sum(1 for t in ((load(TICKETS_FILE) or {}).get('tickets') or [])
                            if t.get('status') in ('ongoing', 'pending_customer', 'pending_internal')),
        'ticket_sla': {str(k): _ticket_sla_policy()[k] for k in (1, 2, 3, 4)},
        # v4.7.0: instance-wide "Show Homelab software" flag → gates the homelab
        # integration widget in the dashboard.
        'show_homelab': cfg.get('show_homelab', True) is not False,
        'show_provisioning': True,   # v6.0.0: always-on module
        # v5.6.0: extra gate to allow server-side terraform plan/apply/destroy.
        'iac_execute_enabled': bool(cfg.get('iac_execute_enabled')),
        'attention':    _attention_payload(),
        # v4.1.0: dashboard cards — next events + tickets (open quick-ack + acked).
        'upcoming':     _dashboard_upcoming(),
        'tickets':      _dashboard_tickets(),
        # v4.1.0: on-call widget (cheap — cfg already loaded). Other add-on
        # widgets render client-side from the devices/drift/cves payload above.
        'oncall':       {'current': _oncall_now(cfg, now),
                         'enabled': bool((cfg.get('oncall') or {}).get('enabled'))},
        # v4.1.0: server-backed catalog widgets (cheap summaries, best-effort).
        # The heavy ones (checks roll-up, disk-fill ETA) are skipped unless _want
        # lists them — see ?w= above.
        'widgets':      _dashboard_extra_widgets(devices_raw, cfg, now, want=_want),
        # v3.4.1: fleet health score. Reuses the cached attention payload above
        # (same 10s cache) so it adds one cheap DEVICES_FILE read, not a recompute.
        'health':       _fleet_health(),
        # v3.4.1: compact fleet score trend (last 30 daily samples) for the
        # home health panel's sparkline — one cheap file read, no recompute.
        'health_history': (load(HEALTH_HIST_FILE) or {}).get('fleet', [])[-30:],
        # Echo the few config flags the Home renderer reads, so the page
        # doesn't need a separate /api/config round-trip.
        'config': {
            'brute_force_threshold': cfg.get('brute_force_threshold', 20),
            'dashboard_hidden_attention_kinds':
                cfg.get('dashboard_hidden_attention_kinds') or [],
            'dashboard_hidden_activity_events':
                cfg.get('dashboard_hidden_activity_events') or [],
            'channel_routing':       cfg.get('channel_routing') or {},
        },
    })


def handle_dashboard_kinds():
    """GET /api/dashboard/kinds — canonical kind roster + current routing.

    Powers the Settings → Dashboard matrix UI. Returns the static kind list
    (kind, label, group, events) merged with the live channel_routing
    config so the frontend can render a single source of truth without
    duplicating ATTENTION_KINDS in JS."""
    require_auth()
    routing = _channel_routing()
    items = []
    for kind, label, group, events in CHANNEL_KINDS:
        items.append({
            'kind':     kind,
            'label':    label,
            'group':    group,
            'events':   list(events),
            'channels': routing.get(kind, dict(CHANNEL_DEFAULT)),
        })
    respond(200, {'kinds': items, 'channels': list(CHANNELS)})


def handle_dashboard_kinds_set():
    """POST /api/dashboard/kinds — update channel_routing.

    Body: {channel_routing: {kind: {channel: bool, ...}, ...}}. Unknown
    kinds and unknown channels are silently dropped. Missing kinds keep
    their existing value (read-modify-write semantics, but a single POST
    can replace a whole row by sending all 4 channels)."""
    require_admin_auth()
    body = get_json_obj()
    incoming = body.get('channel_routing') or body
    if not isinstance(incoming, dict):
        respond(400, {'error': 'channel_routing must be a dict'})
    valid_kinds = {k for k, *_ in CHANNEL_KINDS}
    current = _channel_routing()
    for kind, slot in incoming.items():
        if kind not in valid_kinds or not isinstance(slot, dict):
            continue
        merged = dict(current.get(kind) or CHANNEL_DEFAULT)
        for ch in CHANNELS:
            if ch in slot:
                merged[ch] = bool(slot[ch])
        current[kind] = merged
    with _LockedUpdate(CONFIG_FILE) as cfg:
        cfg['channel_routing'] = current
    respond(200, {'ok': True, 'channel_routing': current})


def _ct_token_eq(given, expected):
    """Constant-time token comparison that never raises. hmac.compare_digest
    raises TypeError on a non-ASCII str (Python requires an ASCII-only str or
    bytes), and query-string tokens decode to arbitrary Unicode — so a token
    like `%E2%80%A6` used to 500 the public status/calendar endpoints. Compare
    on UTF-8 bytes instead: a non-ASCII or malformed token simply fails the
    check (its bytes can't equal an ASCII token's) rather than crashing."""
    if not given or not expected:
        return False
    try:
        gb = given.encode('utf-8', 'strict') if isinstance(given, str) else bytes(given)
        eb = expected.encode('utf-8', 'strict') if isinstance(expected, str) else bytes(expected)
        return hmac.compare_digest(gb, eb)
    except (UnicodeError, TypeError, ValueError):
        return False


def _status_page_component_state(comp, devices, now, ttl, mon_last):
    """Derive a public component status from its member devices + monitors.
    Returns (status, down, total) where status is operational|degraded|major_outage.
    v5.1.0."""
    total = down = 0
    for did in comp.get('device_ids') or []:
        d = devices.get(did)
        if not isinstance(d, dict) or d.get('monitored') is False:
            continue
        total += 1
        if d.get('agentless'):
            up = _agentless_online(d)
        else:
            last = d.get('last_seen', 0)
            up = bool(last) and (now - last) < ttl
        if not up:
            down += 1
    for lbl in comp.get('monitors') or []:
        last = mon_last.get(lbl)
        if last is None:
            continue
        total += 1
        if not bool(last.get('up', last.get('ok', True))):
            down += 1
    if total == 0:
        return 'operational', 0, 0
    if down == 0:
        return 'operational', 0, total
    if down >= total:
        return 'major_outage', down, total
    return 'degraded', down, total


def _status_page_projection(cfg, devices, now, ttl):
    """Build the public status-page projection (component groups + sanitized
    incident history) for /api/public/status. Returns None when the status page
    is not enabled. Output carries ONLY admin-chosen component/group names and
    derived statuses/timestamps — never device names, IPs or alert payloads.
    v5.1.0."""
    sp = cfg.get('status_page') or {}
    if not sp.get('enabled'):
        return None
    try:
        window_days = max(1, min(90, int(sp.get('incident_days', 30))))
    except (TypeError, ValueError):
        window_days = 30
    window_s = window_days * 86400
    mon_hist = load(MON_HIST_FILE) or {}
    mon_last = {lbl: ents[-1] for lbl, ents in mon_hist.items() if ents}
    dev_to_comp = {}
    out_comps = []
    for c in sp.get('components') or []:
        status, _down, _total = _status_page_component_state(c, devices, now, ttl, mon_last)
        comp = {'id': str(c.get('id') or ''), 'group': str(c.get('group') or ''),
                'name': str(c.get('name') or ''), 'status': status}
        out_comps.append(comp)
        for did in c.get('device_ids') or []:
            dev_to_comp.setdefault(did, []).append(comp)
    incidents = []
    comp_downtime = {}
    if sp.get('show_incidents', True):
        alerts = (load(ALERTS_FILE) or {}).get('alerts', [])
        cutoff = now - window_s
        for a in alerts:
            ts = int(a.get('ts') or 0)
            if ts < cutoff:
                continue
            comps = dev_to_comp.get(a.get('device_id')) if a.get('device_id') else None
            if not comps:
                continue
            st = 'major_outage' if a.get('severity') == 'critical' else 'degraded'
            resolved = a.get('resolved_at')
            dur = max(0, (int(resolved) if resolved else now) - ts)
            for comp in comps:
                incidents.append({'component': comp['name'], 'group': comp['group'],
                                  'status': st, 'started_ts': ts,
                                  'resolved_ts': int(resolved) if resolved else None,
                                  'duration_s': dur})
                comp_downtime[comp['id']] = comp_downtime.get(comp['id'], 0) + dur
        incidents.sort(key=lambda i: i['started_ts'], reverse=True)
        incidents = incidents[:30]
    for comp in out_comps:
        dt = min(comp_downtime.get(comp['id'], 0), window_s)
        comp['uptime_pct'] = round(max(0.0, min(100.0, 100.0 * (1 - dt / window_s))), 2)
    if any(c['status'] == 'major_outage' for c in out_comps):
        overall = 'major_outage'
    elif any(c['status'] == 'degraded' for c in out_comps):
        overall = 'degraded'
    else:
        overall = 'operational'
    # W2-25: operator-posted incidents (independent of the auto-derived downtime
    # above). Unresolved ones also darken the overall banner.
    posted = []
    for inc in ((load(INCIDENTS_FILE) or {}).get('incidents') or []):
        if int(inc.get('updated_at') or inc.get('created_at') or 0) < now - window_s \
                and inc.get('status') == 'resolved':
            continue     # keep resolved ones only within the window
        posted.append(_incident_public(inc, admin=False))
    posted.sort(key=lambda i: i.get('created_at', 0), reverse=True)
    posted = posted[:50]
    open_posted = [p for p in posted if p['status'] != 'resolved']
    if open_posted and overall == 'operational':
        overall = 'major_outage' if any(
            p['impact'] == 'major' for p in open_posted) else 'degraded'
    return {'title': _sanitize_str(str(sp.get('title') or ''), 128) or get_server_name(),
            'overall': overall, 'window_days': window_days,
            'components': out_comps, 'incidents': incidents,
            'posted_incidents': posted,
            'status_page_enabled': True}


_INCIDENT_STATUSES = ('investigating', 'identified', 'monitoring', 'resolved')
_INCIDENT_IMPACTS = ('minor', 'major', 'maintenance')


def _incident_public(inc, *, admin):
    """Sanitized incident for the public status page (operator-authored text is
    safe to show; escaping happens client-side via textContent). Admin view adds
    the id."""
    out = {
        'title':   inc.get('title', ''),
        'impact':  inc.get('impact', 'minor'),
        'status':  inc.get('status', 'investigating'),
        'created_at': inc.get('created_at'),
        'updated_at': inc.get('updated_at'),
        'updates': [{'ts': u.get('ts'), 'status': u.get('status', ''),
                     'body': u.get('body', '')}
                    for u in (inc.get('updates') or [])],
    }
    if admin:
        out['id'] = inc.get('id')
    return out


def _notify_incident_subscribers(inc, cfg, *, event):
    """Email status-page subscribers on incident open / resolve. Best-effort."""
    raw = (cfg.get('status_incident_recipients') or '').strip()
    if not raw or not (cfg.get('smtp_host') or '').strip():
        return
    recips = [p.strip() for p in re.split(r'[,;\s]+', raw) if p and '@' in p]
    if not recips:
        return
    title = inc.get('title', 'Status update')
    verb = 'Resolved' if event == 'resolved' else 'New incident'
    subject = f'[{get_server_name()} status] {verb}: {title}'[:200]
    latest = (inc.get('updates') or [{}])[-1]
    body = (f'{verb}: {title}\n\nStatus: {inc.get("status", "")}\n'
            f'Impact: {inc.get("impact", "")}\n\n{latest.get("body", "")}')
    try:
        smtp_notifier.send_email(cfg, recips, subject, body,
                                 html_body=smtp_notifier.brand_html(cfg, subject, body),
                                 extra_headers={'Auto-Submitted': 'auto-generated'})
    except Exception as e:
        sys.stderr.write(f'[remotepower] incident subscriber notify failed: {e}\n')


def handle_incidents():
    """GET /api/incidents — operator-posted status-page incidents (admin). POST —
    create one (admin). An incident is {title, impact, status, body} with a
    running update log; it renders on the public status page independently of the
    auto-derived downtime history."""
    if method() == 'GET':
        require_admin_auth()
        incs = (load(INCIDENTS_FILE) or {}).get('incidents') or []
        incs = sorted(incs, key=lambda i: i.get('created_at', 0), reverse=True)
        respond(200, {'ok': True,
                      'incidents': [_incident_public(i, admin=True) for i in incs]})
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    actor = require_admin_auth()
    body = get_json_obj()
    title = _sanitize_str(str(body.get('title', '')), 160).strip()
    if not title:
        respond(400, {'error': 'title required'})
    impact = str(body.get('impact', 'minor')).strip().lower()
    if impact not in _INCIDENT_IMPACTS:
        impact = 'minor'
    status = str(body.get('status', 'investigating')).strip().lower()
    if status not in _INCIDENT_STATUSES:
        status = 'investigating'
    now = int(time.time())
    msg = _sanitize_str(str(body.get('body', '')), 4000)
    iid = 'inc_' + secrets.token_hex(5)
    rec = {'id': iid, 'title': title, 'impact': impact, 'status': status,
           'created_at': now, 'updated_at': now,
           'updates': [{'ts': now, 'status': status, 'body': msg}] if msg or status else []}
    with _LockedUpdate(INCIDENTS_FILE) as store:
        incs = store.setdefault('incidents', [])
        if len(incs) >= 500:
            respond(400, {'error': 'incident limit reached'})
        incs.append(rec)
    audit_log(actor, 'incident_create', f'id={iid} {title}')
    _notify_incident_subscribers(rec, load(CONFIG_FILE) or {}, event='created')
    respond(200, {'ok': True, 'id': iid})


def handle_incident_update(iid):
    """PATCH /api/incidents/{id} — post an update / change status (admin).
    DELETE — remove the incident (admin)."""
    if method() == 'DELETE':
        actor = require_admin_auth()
        removed = False
        with _LockedUpdate(INCIDENTS_FILE) as store:
            before = store.get('incidents') or []
            after = [i for i in before if i.get('id') != iid]
            removed = len(after) != len(before)
            store['incidents'] = after
        if not removed:
            respond(404, {'error': 'incident not found'})
        audit_log(actor, 'incident_delete', f'id={iid}')
        respond(200, {'ok': True})
    if method() not in ('PATCH', 'POST'):
        respond(405, {'error': 'Method not allowed'})
    actor = require_admin_auth()
    body = get_json_obj()
    now = int(time.time())
    new_status = str(body.get('status', '')).strip().lower()
    if new_status and new_status not in _INCIDENT_STATUSES:
        respond(400, {'error': f'status must be one of {", ".join(_INCIDENT_STATUSES)}'})
    msg = _sanitize_str(str(body.get('body', '')), 4000)
    resolved_now = False
    snapshot = None
    found = False
    with _LockedUpdate(INCIDENTS_FILE) as store:
        inc = next((i for i in (store.get('incidents') or []) if i.get('id') == iid), None)
        if inc:
            found = True
            was = inc.get('status')
            if new_status:
                inc['status'] = new_status
            if msg or new_status:
                inc.setdefault('updates', []).append(
                    {'ts': now, 'status': inc.get('status', ''), 'body': msg})
            inc['updated_at'] = now
            resolved_now = (new_status == 'resolved' and was != 'resolved')
            snapshot = dict(inc)
    if not found:
        respond(404, {'error': 'incident not found'})
    audit_log(actor, 'incident_update', f'id={iid} status={new_status or "-"}')
    if resolved_now and snapshot:
        _notify_incident_subscribers(snapshot, load(CONFIG_FILE) or {}, event='resolved')
    respond(200, {'ok': True})


def handle_public_status():
    """GET /api/public/status?token=<status_token> — read-only snapshot for a
    public status page. No session. Gated by the status token. Deliberately
    minimal: fleet health score + grade, device online/offline counts, and
    monitor up/down — no device names, IPs, or any other detail."""
    cfg = load(CONFIG_FILE) or {}
    token = cfg.get('status_token') or ''
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    given = (qs.get('token') or [''])[0]
    if not _ct_token_eq(given, token):
        respond(401, {'error': 'invalid or missing status token'})
        return
    now = int(time.time())
    ttl = get_online_ttl()
    devices = load(DEVICES_FILE) or {}
    mon_devs = [d for d in devices.values()
                if isinstance(d, dict) and d.get('monitored') is not False]
    online = sum(1 for d in mon_devs if (now - d.get('last_seen', 0)) < ttl)
    health = _fleet_health()
    mon_hist = load(MON_HIST_FILE) or {}
    mons = []
    for label, entries in mon_hist.items():
        if entries:
            last = entries[-1]
            mons.append({'label': str(label)[:64],
                         'up': bool(last.get('up', last.get('ok', True)))})
    mon_up = sum(1 for m in mons if m['up'])
    resp = {
        'server_name':  get_server_name(),
        'generated_ts': now,
        'health':       {'score': health['score'], 'grade': health['grade']},
        'devices':      {'total': len(mon_devs), 'online': online,
                         'offline': len(mon_devs) - online},
        'monitors':     {'total': len(mons), 'up': mon_up,
                         'down': len(mons) - mon_up,
                         'items': sorted(mons, key=lambda m: (m['up'], m['label']))},
        'status_page_enabled': False,
    }
    # master-improvement-scoping #51: RemotePower's OWN observed availability
    # (distinct from the fleet health/monitors above) on the public page too —
    # the data already existed (_control_uptime, GET /api/self-test, admin-
    # only) but had no public-facing surface. Public-safe: just a rolling
    # percentage + tracking-since timestamp, no operational detail.
    try:
        cu = _control_uptime()
        if cu.get('tracking'):
            resp['control_plane'] = {'windows': cu.get('windows') or {},
                                      'since': cu.get('since')}
    except Exception:
        pass
    # v5.1.0: merge the public status-page projection (component groups + sanitized
    # incident history) when the operator has enabled it. Existing flat fields stay
    # for back-compat (Uptime Kuma / Homepage / Grafana consumers).
    try:
        _sp = _status_page_projection(cfg, devices, now, ttl)
    except Exception:
        _sp = None
    if _sp:
        resp.update(_sp)
    respond(200, resp)


def handle_status():
    """GET /api/status?token=<status_token> — machine-readable fleet
    summary for external dashboards (Uptime Kuma, Homepage, Grafana).

    Auth is a dedicated status token, NOT a session — so a monitoring
    tool can poll it — but it is not public: without the token, 403.
    The token is generated in Settings.
    """
    cfg = load(CONFIG_FILE)
    token = cfg.get('status_token')
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    given = (qs.get('token') or [''])[0]
    if not token:
        respond(403, {'error': 'status endpoint not enabled — generate a '
                               'status token in Settings'})
        return
    if not _ct_token_eq(given, token):
        respond(403, {'error': 'invalid or missing status token'})
        return

    devices = load(DEVICES_FILE) or {}
    now = int(time.time())
    try:
        ttl = get_online_ttl()
    except Exception:
        ttl = 180
    online = offline = 0
    for dev_id, dev in devices.items():
        if dev.get('agentless') or not dev.get('monitored', True):
            continue
        last = dev.get('last_seen', 0)
        if not last:
            continue
        if (now - last) > ttl:
            offline += 1
        else:
            online += 1

    # v4.1.0 (#18): serve the cached Needs-Attention digest (status endpoints
    # are polled often; this avoids recomputing the full aggregation each time).
    _att = _attention_payload()
    items, counts = _att['items'], _att['counts']

    # A single rolled-up health word, so a dashboard can show one dot.
    if counts['critical']:
        health = 'critical'
    elif counts['warning']:
        health = 'warning'
    else:
        health = 'ok'

    respond(200, {
        'health':           health,
        'devices_online':   online,
        'devices_offline':  offline,
        'devices_total':    online + offline,
        'attention': {
            'critical': counts['critical'],
            'warning':  counts['warning'],
            'info':     counts['info'],
            'total':    len(items),
        },
        'version':   SERVER_VERSION,
        'generated': now,
    })


def handle_ha_bridge():
    """GET /api/ha?token=<status_token> — Home Assistant bridge.

    A READ-ONLY, flat JSON snapshot shaped for Home Assistant's REST sensor:
    a top-level `state` (the rolled-up health word HA uses as the sensor
    state) plus flat scalar attributes (no nesting) so HA templates stay
    trivial — e.g.

        sensor:
          - platform: rest
            resource: https://rp.example/api/ha?token=XXX
            value_template: "{{ value_json.state }}"
            json_attributes: [devices_online, devices_offline,
                              alerts_critical, alerts_warning, health_score]

    Deliberately one-way: there is NO control surface here — operators act in
    the web UI. Reuses the status token (enable the status endpoint in
    Settings); without it, 403. Mirrors handle_status's computation."""
    cfg = load(CONFIG_FILE) or {}
    token = cfg.get('status_token')
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    given = (qs.get('token') or [''])[0]
    if not token:
        respond(403, {'error': 'status endpoint not enabled — generate a '
                               'status token in Settings'})
        return
    if not _ct_token_eq(given, token):
        respond(403, {'error': 'invalid or missing status token'})
        return

    devices = load(DEVICES_FILE) or {}
    now = int(time.time())
    try:
        ttl = get_online_ttl()
    except Exception:
        ttl = 180
    online = offline = 0
    for dev in devices.values():
        if not isinstance(dev, dict) or dev.get('agentless') or not dev.get('monitored', True):
            continue
        last = dev.get('last_seen', 0)
        if not last:
            continue
        if (now - last) > ttl:
            offline += 1
        else:
            online += 1

    # v4.1.0 (#18): serve the cached Needs-Attention digest (HA polls this
    # endpoint regularly; reuse the cache instead of recomputing each scrape).
    _att = _attention_payload()
    items, counts = _att['items'], _att['counts']
    if counts['critical']:
        state = 'critical'
    elif counts['warning']:
        state = 'warning'
    else:
        state = 'ok'
    try:
        health = _fleet_health()
    except Exception:
        health = {'score': None, 'grade': ''}

    # Flat scalars only — HA's json_attributes can't descend into nested objects.
    respond(200, {
        'state':            state,
        'problem':          'on' if state != 'ok' else 'off',  # HA binary_sensor
        'server_name':      get_server_name(),
        'devices_total':    online + offline,
        'devices_online':   online,
        'devices_offline':  offline,
        'alerts_total':     len(items),
        'alerts_critical':  counts['critical'],
        'alerts_warning':   counts['warning'],
        'alerts_info':      counts['info'],
        'health_score':     health.get('score'),
        'health_grade':     health.get('grade', ''),
        'version':          SERVER_VERSION,
        'generated':        now,
    })


def handle_status_token():
    """POST /api/status-token — generate (or rotate) the status token.
    Body {"enabled": false} clears it, disabling the status endpoint."""
    require_admin_auth()
    body = get_json_obj()
    with _LockedUpdate(CONFIG_FILE) as cfg:
        if body.get('enabled') is False:
            cfg.pop('status_token', None)
            token = None
        else:
            token = secrets.token_urlsafe(24)
            cfg['status_token'] = token
    respond(200, {'ok': True, 'status_token': token})


def handle_force_package_scan(dev_id):
    """POST /api/devices/<id>/scan-packages — request an immediate
    package scan.

    The agent normally submits its full package inventory (for CVE
    scanning) and the patch/upgradable count only every few hundred
    heartbeats. This sets a one-shot flag; the device's next
    heartbeat response carries `force_package_scan`, the agent then
    sends a fresh package list and patch count on the heartbeat after
    that. The flag is cleared the moment it's handed to the agent —
    it fires exactly once.
    """
    require_admin_auth()
    if not _validate_id(dev_id):
        respond(400, {'error': 'invalid device id'})
        return
    with _LockedUpdate(DEVICES_FILE) as devices:
        dev = devices.get(dev_id)
        if dev is None:
            respond(404, {'error': 'device not found'})
            return
        dev['force_package_scan'] = True
    respond(200, {'ok': True,
                  'message': 'Package scan queued — the device sends a '
                             'fresh inventory within the next minute or two.'})


def _resolve_drift_profile_files(dev_id, dev, drift_cfg):
    """v3.13.0: resolve an assigned drift profile to its watched-file list.

    A profile is a named, reusable set of watched files
    (``drift_cfg['profiles']``). Assignments (``drift_cfg['assignments']``) map a
    profile onto a device, tag, or group. Precedence within profiles:
    device assignment > tag assignment > group assignment. Returns the file list
    or None if no profile applies."""
    profiles = {p['id']: p for p in (drift_cfg.get('profiles') or [])
                if isinstance(p, dict) and p.get('id')}
    if not profiles:
        return None
    by_device, by_tag, by_group = {}, {}, {}
    for a in (drift_cfg.get('assignments') or []):
        if not isinstance(a, dict):
            continue
        pid = a.get('profile_id')
        if pid not in profiles:
            continue
        t, v = a.get('scope_type'), a.get('scope_value')
        if t == 'device':
            by_device[v] = pid
        elif t == 'tag':
            by_tag[v] = pid
        elif t == 'group':
            by_group[v] = pid
    pid = by_device.get(dev_id)
    if not pid:
        for tg in (dev.get('tags') or []):
            if tg in by_tag:
                pid = by_tag[tg]
                break
    if not pid:
        g = dev.get('group')
        if g and g in by_group:
            pid = by_group[g]
    if pid and pid in profiles and isinstance(profiles[pid].get('files'), list):
        return list(profiles[pid]['files'])
    return None


def get_watched_files_for(dev_id, devices=None):
    """Return the list of files this device should watch.

    Precedence: an explicit per-device ``watched_files`` override (set manually
    from the device drawer) wins; else an assigned drift profile (v3.13.0); else
    the global default (``drift.default_watched_files`` / DEFAULT_WATCHED_FILES).
    """
    cfg = _config()
    drift_cfg = cfg.get('drift') or {}
    if not drift_cfg.get('enabled', True):
        return []
    defaults = drift_cfg.get('default_watched_files') or DEFAULT_WATCHED_FILES
    if devices is None:
        devices = load(DEVICES_FILE)
    dev = devices.get(dev_id) if isinstance(devices, dict) else None
    if dev and isinstance(dev.get('watched_files'), list):
        # Explicit per-device override completely replaces everything else.
        return list(dev['watched_files'])
    if dev:
        prof = _resolve_drift_profile_files(dev_id, dev, drift_cfg)
        if prof is not None:
            return prof
    return list(defaults)


def _ingest_drift_report(dev_id, drift_payload, actor='agent'):
    """Process a drift report submitted by the agent. Called from
    handle_heartbeat when payload['drift'] is present.

    drift_payload is a dict mapping file path → {hash, size, mtime,
    exists}. We compare each against the stored baseline; on the first
    sighting of a file we accept the current value as the baseline
    (operator can re-baseline at any time). On a change, we increment
    drift_count, push to history, and fire a webhook.
    """
    if not isinstance(drift_payload, dict):
        return

    fired_events = []
    now = int(time.time())
    with _LockedUpdate(DRIFT_STATE_FILE) as state:
        dev_state = state.setdefault(dev_id, {})
        files = dev_state.setdefault('files', {})
        for path, info in drift_payload.items():
            if not isinstance(info, dict):
                continue
            cur_hash  = info.get('hash')
            cur_size  = info.get('size')
            cur_mtime = info.get('mtime')
            exists    = bool(info.get('exists', True))

            existing = files.get(path)
            if existing is None:
                # First sighting — accept as baseline.
                files[path] = {
                    'current_hash':    cur_hash,
                    'current_size':    cur_size,
                    'current_mtime':   cur_mtime,
                    'baseline_hash':   cur_hash,
                    'baseline_size':   cur_size,
                    'baseline_set_at': now,
                    'baseline_set_by': actor,
                    'first_seen':      now,
                    'last_check':      now,
                    'drift_count':     0,
                    'exists':          exists,
                    'history':         [],
                }
                continue

            existing['current_hash']  = cur_hash
            existing['current_size']  = cur_size
            existing['current_mtime'] = cur_mtime
            existing['last_check']    = now
            existing['exists']        = exists

            # v2.2.6: dormant handling for files that aren't on the host.
            # A watched file reporting exists:false used to count as
            # drift forever (missing hash != baseline hash), nagging the
            # operator about a file that simply isn't there. Now: after
            # DRIFT_MISSING_DORMANT_AFTER consecutive missing sightings
            # the file is marked dormant — it stops counting as drift.
            # If the file comes back, dormant clears and normal drift
            # comparison resumes. The file is never deleted, so the
            # operator can still see it in the per-device detail.
            if not exists:
                miss = existing.get('missing_streak', 0) + 1
                existing['missing_streak'] = miss
                if miss >= DRIFT_MISSING_DORMANT_AFTER and not existing.get('dormant'):
                    existing['dormant']      = True
                    existing['dormant_since'] = now
                    # Fire one event so the operator knows — once, not
                    # every poll. After this the file is quiet.
                    fired_events.append({
                        'path':           path,
                        'baseline_hash':  existing.get('baseline_hash'),
                        'current_hash':   None,
                        'exists':         False,
                        'reason':         'file_absent',
                    })
                # While missing (dormant or not yet) skip drift compare —
                # a missing file's None hash must not trip the change path.
                continue
            else:
                # File present (again). Clear any missing state.
                if existing.get('missing_streak') or existing.get('dormant'):
                    existing['missing_streak'] = 0
                    if existing.get('dormant'):
                        existing['dormant'] = False
                        existing['revived_at'] = now

            # Is this a change from the prior known state?
            prior_hash = existing.get('prior_hash') or existing.get('baseline_hash')
            if cur_hash != prior_hash:
                # Push to history
                hist = existing.setdefault('history', [])
                hist.append({
                    'ts':   now,
                    'hash': cur_hash,
                    'size': cur_size,
                    'exists': exists,
                })
                if len(hist) > DRIFT_HISTORY_CAP:
                    del hist[:-DRIFT_HISTORY_CAP]
                # Update prior_hash so we don't re-fire on the next poll
                # if the file stays at the new hash.
                existing['prior_hash'] = cur_hash

                # If different from baseline, increment drift_count + queue webhook
                if cur_hash != existing.get('baseline_hash'):
                    existing['drift_count'] = existing.get('drift_count', 0) + 1
                    fired_events.append({
                        'path':           path,
                        'baseline_hash':  existing.get('baseline_hash'),
                        'current_hash':   cur_hash,
                        'exists':         exists,
                    })

    # Fire webhooks outside the lock
    if fired_events:
        # v5.6.x perf: single-device read (only the name is needed) instead of
        # load(DEVICES_FILE) reconstructing the whole fleet on the DB backend.
        dev = device_get(dev_id) or {}
        for ev in fired_events:
            try:
                fire_webhook('drift_detected', {
                    'device_id':   dev_id,
                    'device_name': dev.get('name', dev_id),
                    'path':        ev['path'],
                    'exists':      ev['exists'],
                    'baseline_hash': ev['baseline_hash'],
                    'current_hash':  ev['current_hash'],
                })
            except Exception as e:
                sys.stderr.write(f"[remotepower] drift webhook failed: {e}\n")


# ── v3.13.0: named drift profiles (reusable watched-file sets) ───────────────
# A profile is {id, name, files:[paths], created, updated}. Assignments map a
# profile onto a device / tag / group ({scope_type, scope_value, profile_id}).
# get_watched_files_for() resolves them (device override > profile > default).
def _drift_effective(dev_id, dev, drift_cfg=None):
    """Explain how a device's watched-file list is resolved (for the Drift UI):
    {files, source, profile}. source ∈ device-override | profile:device |
    profile:tag | profile:group | default | disabled."""
    dc = drift_cfg if drift_cfg is not None else ((_config().get('drift')) or {})
    if not dc.get('enabled', True):
        return {'files': [], 'source': 'disabled', 'profile': None}
    if isinstance(dev.get('watched_files'), list):
        return {'files': list(dev['watched_files']),
                'source': 'device-override', 'profile': None}
    profiles = {p['id']: p for p in (dc.get('profiles') or [])
                if isinstance(p, dict) and p.get('id')}
    if profiles:
        by = {'device': {}, 'tag': {}, 'group': {}}
        for a in (dc.get('assignments') or []):
            if isinstance(a, dict) and a.get('profile_id') in profiles and a.get('scope_type') in by:
                by[a['scope_type']][a.get('scope_value')] = a['profile_id']
        pid = scope = None
        if dev_id in by['device']:
            pid, scope = by['device'][dev_id], 'device'
        if not pid:
            for tg in (dev.get('tags') or []):
                if tg in by['tag']:
                    pid, scope = by['tag'][tg], 'tag'
                    break
        if not pid:
            g = dev.get('group')
            if g and g in by['group']:
                pid, scope = by['group'][g], 'group'
        if pid:
            p = profiles[pid]
            return {'files': list(p.get('files') or []),
                    'source': f'profile:{scope}', 'profile': p.get('name')}
    return {'files': list(dc.get('default_watched_files') or DEFAULT_WATCHED_FILES),
            'source': 'default', 'profile': None}


def _validate_drift_files(raw):
    """Sanitise a watched-files list: absolute paths, ≤512 chars, ≤50 entries,
    deduped, order preserved."""
    files, seen = [], set()
    if isinstance(raw, list):
        for p in raw[:80]:
            s = str(p).strip()
            if s.startswith('/') and len(s) <= 512 and s not in seen:
                seen.add(s)
                files.append(s)
    return files[:50]


def handle_drift_profiles():
    """GET  /api/drift/profiles — list profiles + assignments.
       POST /api/drift/profiles — create {name, files:[...]} (admin)."""
    m = method()
    if m == 'GET':
        require_auth()
        drift_cfg = (load(CONFIG_FILE) or {}).get('drift') or {}
        respond(200, {'profiles': drift_cfg.get('profiles') or [],
                      'assignments': drift_cfg.get('assignments') or []})
    if m == 'POST':
        actor = require_admin_auth()
        body = get_json_obj()   # coerce non-dict body → {} (a JSON array must not 500)
        name = _sanitize_str(body.get('name', ''), 80).strip()
        if not name:
            respond(400, {'error': 'name is required'})
        files = _validate_drift_files((body or {}).get('files'))
        pid = 'dp_' + secrets.token_urlsafe(8)
        now = int(time.time())
        with _LockedUpdate(CONFIG_FILE) as cfg:
            dr = cfg.setdefault('drift', {})
            profs = dr.setdefault('profiles', [])
            if any(isinstance(p, dict) and p.get('name', '').lower() == name.lower()
                   for p in profs):
                respond(409, {'error': 'a profile with that name already exists'})
            if len(profs) >= 100:
                respond(400, {'error': 'too many drift profiles (max 100)'})
            profs.append({'id': pid, 'name': name, 'files': files,
                          'created': now, 'updated': now})
        audit_log(actor, 'drift_profile_create', f'{name} ({len(files)} files)')
        respond(201, {'ok': True, 'id': pid})
    respond(405, {'error': 'method not allowed'})


def handle_drift_profile_edit(pid):
    """PUT    /api/drift/profiles/<id> — update {name?, files?} (admin).
       DELETE /api/drift/profiles/<id> — delete the profile + its assignments."""
    actor = require_admin_auth()
    m = method()
    if m == 'PUT':
        body = get_json_obj()
        with _LockedUpdate(CONFIG_FILE) as cfg:
            dr = cfg.setdefault('drift', {})
            profs = dr.setdefault('profiles', [])
            prof = next((p for p in profs if isinstance(p, dict) and p.get('id') == pid), None)
            if not prof:
                respond(404, {'error': 'profile not found'})
            if 'name' in body:
                nm = _sanitize_str(body.get('name', ''), 80).strip()
                if not nm:
                    respond(400, {'error': 'name cannot be empty'})
                if any(isinstance(p, dict) and p.get('id') != pid
                       and p.get('name', '').lower() == nm.lower() for p in profs):
                    respond(409, {'error': 'a profile with that name already exists'})
                prof['name'] = nm
            if 'files' in body:
                prof['files'] = _validate_drift_files(body.get('files'))
            prof['updated'] = int(time.time())
            nfiles = len(prof.get('files') or [])
        audit_log(actor, 'drift_profile_edit', f'{pid} ({nfiles} files)')
        respond(200, {'ok': True})
    if m == 'DELETE':
        with _LockedUpdate(CONFIG_FILE) as cfg:
            dr = cfg.setdefault('drift', {})
            profs = dr.get('profiles') or []
            if not any(isinstance(p, dict) and p.get('id') == pid for p in profs):
                respond(404, {'error': 'profile not found'})
            dr['profiles'] = [p for p in profs
                              if not (isinstance(p, dict) and p.get('id') == pid)]
            # Drop any assignments that referenced it.
            dr['assignments'] = [a for a in (dr.get('assignments') or [])
                                 if not (isinstance(a, dict) and a.get('profile_id') == pid)]
        audit_log(actor, 'drift_profile_delete', pid)
        respond(200, {'ok': True})
    respond(405, {'error': 'method not allowed'})


def handle_drift_assign():
    """POST /api/drift/assign — assign/unassign a profile to a scope (admin).
    Body: {scope_type: device|tag|group, scope_value, profile_id|null}. A null
    profile_id clears the assignment for that scope."""
    actor = require_admin_auth()
    body = get_json_obj()
    st = _sanitize_str(body.get('scope_type', ''), 16)
    sv = _sanitize_str(body.get('scope_value', ''), 128).strip()
    pid = body.get('profile_id')
    if st not in ('device', 'tag', 'group') or not sv:
        respond(400, {'error': 'scope_type (device|tag|group) and scope_value required'})
    with _LockedUpdate(CONFIG_FILE) as cfg:
        dr = cfg.setdefault('drift', {})
        assigns = [a for a in (dr.get('assignments') or [])
                   if not (isinstance(a, dict) and a.get('scope_type') == st
                           and a.get('scope_value') == sv)]
        if pid:
            if not any(isinstance(p, dict) and p.get('id') == pid
                       for p in (dr.get('profiles') or [])):
                respond(404, {'error': 'profile not found'})
            assigns.append({'scope_type': st, 'scope_value': sv, 'profile_id': pid})
        dr['assignments'] = assigns
    audit_log(actor, 'drift_profile_assign',
              f'{st}:{sv} -> {pid or "(cleared)"}')
    respond(200, {'ok': True})


# ── v3.13.0: controller backup / restore (disaster recovery for the data dir) ─
# Snapshot the ENTIRE RemotePower data dir (config, devices, all state, the
# encrypted credentials vault) as a gzip tarball; restore it the same way. The
# operator already needs the vault passphrase to decrypt secrets, so the
# encrypted vault is safe to include in the backup.
_BACKUP_EXCLUDE_NAMES = {'attention_cache.json', 'fleet_risk_cache.json'}
_BACKUP_SNAPSHOT_DIR = 'restore-snapshots'




def _write_data_dir_tar(tar):
    """Add every backup-eligible file under DATA_DIR to an open tarfile."""
    base = str(DATA_DIR)
    for root, dirs, fnames in os.walk(base):
        # Don't descend into the snapshot dir.
        dirs[:] = [d for d in dirs if not (root == base and d == _BACKUP_SNAPSHOT_DIR)]
        for fn in fnames:
            full = os.path.join(root, fn)
            rel = os.path.relpath(full, base)
            if not _backup_include(rel):
                continue
            try:
                tar.add(full, arcname=rel, recursive=False)
            except Exception:
                pass






def handle_drift_overview():
    """GET /api/drift — fleet-wide overview. Returns one row per device with
    summary counts (total files watched, files with drift, files missing)."""
    require_auth()
    state = load(DRIFT_STATE_FILE)
    devices = load(DEVICES_FILE)
    devices = _scope_filter_devices(devices)  # v3.5.0 RBAC v2
    rows = []
    for dev_id, dev_state in state.items():
        if dev_id not in devices:
            continue   # v3.5.0 RBAC v2: out of caller scope
        files = (dev_state or {}).get('files') or {}
        n_total   = len(files)
        # v2.2.6: a dormant file (one that's been absent from the host
        # for several heartbeats) no longer counts as drift — its
        # missing hash != baseline hash is expected, not a change to
        # alarm on. Counted separately as `dormant` so the operator
        # can still see it.
        # v2.3.4: an explicitly IGNORED file (operator marked it — e.g.
        # a /etc/pam.d/common-auth that's legitimately absent on this
        # host) is non-critical. It drops out of the drift/missing
        # counts (so it doesn't drive a red status) but is still
        # counted as `ignored` and remains visible in the per-device
        # detail. This is the explicit-decision counterpart to the
        # automatic time-based `dormant` state.
        n_drifted = sum(1 for f in files.values()
                        if not f.get('dormant') and not f.get('ignored')
                        and f.get('exists', True)
                        and f.get('current_hash') != f.get('baseline_hash'))
        n_missing = sum(1 for f in files.values()
                        if not f.get('exists', True) and not f.get('ignored'))
        n_dormant = sum(1 for f in files.values() if f.get('dormant'))
        n_ignored = sum(1 for f in files.values() if f.get('ignored'))
        dev = devices.get(dev_id) or {}
        rows.append({
            'device_id':   dev_id,
            'device_name': dev.get('name', dev_id),
            'group':       dev.get('group', ''),
            'total':       n_total,
            'drifted':     n_drifted,
            'missing':     n_missing,
            'dormant':     n_dormant,
            'ignored':     n_ignored,
            'last_check':  max((f.get('last_check') or 0 for f in files.values()),
                               default=0),
        })
    rows.sort(key=lambda r: (-r['drifted'], r['device_name'].lower()))
    respond(200, {'devices': rows})


def handle_drift_ignore(dev_id):
    """POST /api/devices/<id>/drift/ignore — toggle the ignore flag on
    one watched file.

    Body: {"path": "/etc/...", "ignored": true|false, "reason": "..."}

    An ignored file is non-critical: it no longer counts toward the
    device's drift / missing totals and doesn't drive a red status,
    but it stays visible in the drift detail (marked "ignored"). This
    is the fix for drift false positives — e.g. a watched file that is
    legitimately absent on a particular host.
    """
    require_admin_auth()
    if not _validate_id(dev_id):
        respond(400, {'error': 'invalid device id'})
        return
    body = get_json_obj()
    path = (body.get('path') or '').strip()
    if not path:
        respond(400, {'error': 'path is required'})
        return
    ignored = bool(body.get('ignored', True))
    reason = (body.get('reason') or '')[:500]
    with _LockedUpdate(DRIFT_STATE_FILE) as state:
        dev_state = state.get(dev_id)
        if not dev_state or path not in (dev_state.get('files') or {}):
            respond(404, {'error': 'no drift record for that file'})
            return
        fentry = dev_state['files'][path]
        if ignored:
            fentry['ignored'] = True
            fentry['ignore_reason'] = reason
            fentry['ignored_at'] = int(time.time())
        else:
            fentry.pop('ignored', None)
            fentry.pop('ignore_reason', None)
            fentry.pop('ignored_at', None)
    respond(200, {'ok': True, 'path': path, 'ignored': ignored})


def handle_device_drift_get(dev_id):
    """GET /api/devices/<id>/drift — full drift state for one device."""
    require_auth()
    state = load(DRIFT_STATE_FILE)
    entry = state.get(dev_id) or {'files': {}}
    devices = load(DEVICES_FILE)
    watched = get_watched_files_for(dev_id, devices)
    # v3.13.0: explain WHERE the watched list came from (override / profile / default).
    effective = _drift_effective(dev_id, (devices or {}).get(dev_id) or {})
    respond(200, {
        'device_id':     dev_id,
        'watched_files': watched,
        'files':         entry.get('files') or {},
        'source':        effective['source'],
        'profile':       effective['profile'],
    })


def handle_device_drift_baseline(dev_id):
    """POST /api/devices/<id>/drift/baseline — accept current as new baseline.
    Body: {"paths": ["/etc/..."]} or {"all": true}."""
    # v4.8.0 (authz): accepting a file-integrity baseline silences future tamper
    # alerts — a mutation, not a read. Gate on 'mitigate' + device scope so a
    # read-only viewer can't re-baseline (was require_auth, CWE-862).
    actor = require_perm('mitigate', [dev_id])
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    target_paths = body.get('paths')
    target_all = bool(body.get('all'))

    updated = []
    now = int(time.time())
    with _LockedUpdate(DRIFT_STATE_FILE) as state:
        dev_state = state.get(dev_id) or {}
        files = dev_state.get('files') or {}
        for path, entry in files.items():
            if not target_all and target_paths is not None and path not in target_paths:
                continue
            if entry.get('current_hash') == entry.get('baseline_hash'):
                continue   # nothing to update
            entry['baseline_hash']   = entry.get('current_hash')
            entry['baseline_size']   = entry.get('current_size')
            entry['baseline_set_at'] = now
            entry['baseline_set_by'] = actor
            entry['drift_count']     = 0
            entry['prior_hash']      = entry.get('current_hash')
            updated.append(path)
    audit_log(actor, 'drift_baseline',
              detail=f"device={dev_id} paths={updated}")
    respond(200, {'ok': True, 'updated': updated})


def handle_device_drift_reset(dev_id):
    """DELETE /api/devices/<id>/drift — wipe drift state for a device.
    Used when re-baselining or removing a device from drift monitoring."""
    # v4.8.0 (authz): wiping drift state clears tamper history — gate on
    # 'mitigate' + device scope, not bare require_auth (CWE-862).
    actor = require_perm('mitigate', [dev_id])
    if method() != 'DELETE':
        respond(405, {'error': 'Method not allowed'})
    existed = False
    with _LockedUpdate(DRIFT_STATE_FILE) as state:
        if dev_id in state:
            del state[dev_id]
            existed = True
    audit_log(actor, 'drift_reset', detail=f"device={dev_id} existed={existed}")
    respond(200, {'ok': True, 'deleted': existed})


# ── v2.2.1: drift content fetch (for the diff visualisation) ──────────────
#
# Three pieces:
#   1. _maybe_mirror_drift_content() — hook called from the heartbeat
#      output-ingest path. Detects `exec:cat <watched_path>` outputs and
#      mirrors the content into drift_contents.json (capped to last 2
#      captures per path).
#   2. handle_drift_fetch_content() — POST endpoint that queues a
#      `exec:cat <path>` command for each requested path. The agent
#      picks it up on next heartbeat, runs it, output mirrors via (1).
#   3. handle_drift_get_content() — GET endpoint that returns stored
#      captures for a given path. UI uses this to fetch baseline +
#      current and feed them to the JS diff renderer.
#
# DRIFT_CONTENT_DENYLIST is checked on BOTH endpoints — fetch refuses to
# queue, get refuses to return. Defense in depth.

# Used by _maybe_mirror_drift_content: parses `exec:cat <path>` and
# `exec:cat '/path with spaces'` forms. The agent emits the same
# command string we queued, so we can match by prefix.
_CAT_CMD_RE = __import__('re').compile(
    r"^exec:\s*cat\s+(?:'([^']+)'|\"([^\"]+)\"|(\S+))\s*$"
)


def _maybe_mirror_drift_content(dev_id, cmd_text, output, rc, ts):
    """Mirror a `cat <watched>` output into drift_contents.json. No-op
    if the command isn't a cat, the path isn't watched, or the path is
    on the denylist. Bounded write — drops anything >MAX_DRIFT_CONTENT_BYTES.
    """
    m = _CAT_CMD_RE.match(cmd_text or '')
    if not m:
        return
    path = m.group(1) or m.group(2) or m.group(3)
    if not path or not path.startswith('/'):
        return
    if path in DRIFT_CONTENT_DENYLIST:
        # Belt-and-braces — should never reach here because the fetch
        # endpoint refuses to queue these. If a malicious agent forged
        # an output for a denylisted path we still drop it.
        return
    # Is this path even being watched for drift on this device?
    watched = get_watched_files_for(dev_id)
    if path not in watched:
        return

    safe_output = (output or '')[:MAX_DRIFT_CONTENT_BYTES]
    with _LockedUpdate(DRIFT_CONTENTS_FILE) as store:
        dev = store.setdefault(dev_id, {})
        captures = dev.setdefault(path, [])
        captures.append({
            'ts':      ts,
            'rc':      rc,
            'content': safe_output,
        })
        # Keep only the last N — older captures don't help the
        # baseline-vs-current diff and they grow the file.
        if len(captures) > MAX_DRIFT_CONTENT_CAPTURES:
            del captures[:-MAX_DRIFT_CONTENT_CAPTURES]


def handle_drift_fetch_content(dev_id):
    """POST /api/devices/<id>/drift/fetch_content
       body: {"paths": ["/etc/...", ...]}

    Queue a `cat` command for each requested path. The agent picks it
    up on its next heartbeat (typically within a poll interval, usually
    60s). When the output comes back, _maybe_mirror_drift_content
    mirrors it into drift_contents.json for the diff viewer.

    Denylist enforcement: requests for /etc/shadow or other denylisted
    paths are dropped silently from the queue list (returned in
    `denied`). Other paths in the same request still get queued.
    """
    # v5.5.0 (H1): this queues an `exec:cat <path>` on the device, so it must
    # require the `command` permission AND device-scope — not bare auth. A bare
    # require_auth() let a viewer/mcp token (or a scoped operator targeting an
    # out-of-scope device) make a host execute a command and exfiltrate the
    # watched file's contents. Mirrors the sibling drift baseline/reset handlers.
    actor = require_perm('command', [dev_id])
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    devices = load(DEVICES_FILE)
    if dev_id not in devices:
        respond(404, {'error': 'Device not found'})
    body = get_json_obj()
    paths = body.get('paths') or []
    if not isinstance(paths, list):
        respond(400, {'error': 'paths must be a list'})

    watched = set(get_watched_files_for(dev_id, devices))
    queued, denied, not_watched = [], [], []
    cmds = load(CMDS_FILE)
    if dev_id not in cmds:
        cmds[dev_id] = []

    for p in paths:
        if not isinstance(p, str) or not p.startswith('/'):
            continue
        if p in DRIFT_CONTENT_DENYLIST:
            denied.append(p)
            continue
        if p not in watched:
            # Only allow content fetch for files we're actively
            # watching — otherwise this endpoint is just an
            # arbitrary file-read primitive.
            not_watched.append(p)
            continue
        # v4.4.0 (SECURITY): shell-quote the path with shlex.quote — the old
        # naive f"…'{p}'" broke out of the single quotes if a watched path
        # contained a quote (watched_files ingestion has no metachar filter),
        # turning this watch-only `cat` into agent RCE. shlex.quote is the
        # correct POSIX-shell escaping the agent's exec dispatcher expects.
        cmd = f"exec:cat {shlex.quote(p)}"
        if cmd not in cmds[dev_id]:
            cmds[dev_id].append(cmd)
            queued.append(p)
        log_command(actor, dev_id, devices[dev_id].get('name', dev_id), cmd)

    save(CMDS_FILE, cmds)
    audit_log(actor, 'drift_fetch_content',
              detail=f"device={dev_id} queued={queued} denied={denied}")
    respond(200, {
        'ok': True,
        'queued':      queued,
        'denied':      denied,
        'not_watched': not_watched,
        'note': 'Captures arrive after the next agent heartbeat. '
                'Poll /drift/content?path=... to retrieve.',
    })


def handle_drift_get_content(dev_id):
    """GET /api/devices/<id>/drift/content?path=...

    Returns stored captures for a single path. Up to
    MAX_DRIFT_CONTENT_CAPTURES (currently 2) chronologically — when the
    operator has fetched the path twice, the UI gets baseline+current
    and can render a diff.

    Response: {captures: [{ts, rc, content, sha256}], path, denied}
    """
    require_auth()
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    path = (qs.get('path') or [''])[0]
    if not path or not path.startswith('/'):
        respond(400, {'error': 'path query parameter required'})
    if path in DRIFT_CONTENT_DENYLIST:
        respond(403, {
            'error':  'Path is on the drift-content denylist '
                      '(/etc/shadow and similar). Hash tracking continues; '
                      'content retrieval is refused regardless of role.',
            'denied': True, 'path': path,
        })
    store = load(DRIFT_CONTENTS_FILE)
    captures = (store.get(dev_id) or {}).get(path) or []
    # Add sha256 of each capture so the UI can confirm which capture
    # matches which baseline/current hash from the drift state.
    enriched = []
    for c in captures:
        sha = hashlib.sha256((c.get('content') or '').encode('utf-8',
                                                              'replace')).hexdigest()
        enriched.append({
            'ts':      c.get('ts'),
            'rc':      c.get('rc'),
            'content': c.get('content', ''),
            'sha256':  f"sha256:{sha}",
        })
    respond(200, {'path': path, 'captures': enriched})


def handle_export():
    """Export backup ZIP.

    Secrets are redacted: apikeys.json key values, and (v2.3.1) the
    password / token fields in config.json — the Proxmox API token
    secret, the SMTP password, and the LDAP bind password. Before
    v2.3.1 config.json went into the ZIP verbatim, so a backup file
    carried live credentials; that's the leak this closes.

    Also triggers _run_data_backup(triggered_by='export') so the
    server-status backup state is updated and a tar.gz snapshot is
    written to the backup directory on every manual export.
    """
    actor = require_admin_auth()
    try:
        _run_data_backup(triggered_by='export')
    except Exception:
        pass  # export itself must not fail if backup path is misconfigured
    audit_log(actor, 'backup_export')
    import zipfile, io
    buf = io.BytesIO()
    exclude = {'tokens.json', 'longpoll.json', 'ratelimit.json'}
    with zipfile.ZipFile(buf, 'w', zipfile.ZIP_DEFLATED) as zf:
        # v3.12.0: iterate logical files via the backend seam (not glob), so the
        # ZIP is complete under SQLite too. Every entry is written as
        # re-serialised JSON via load(), which is also the SQLite→JSON rollback
        # representation.
        for name in backend_iter_files():
            if name in exclude:
                continue
            f = DATA_DIR / name
            if name == 'apikeys.json':
                # Redact key values in backup
                raw = load(f)
                redacted = {kid: {**v, 'key': '(redacted)'}
                            for kid, v in raw.items()}
                zf.writestr('apikeys.json', json.dumps(redacted, indent=2))
            elif name == 'config.json':
                # v5.7.0 (SECURITY): the previous 3-key redaction
                # (proxmox_token_secret / smtp_password / ldap_bind_password)
                # leaked nearly every OTHER config secret into the "shareable"
                # backup ZIP — SSH private key, ai.api_key, oidc_client_secret,
                # vapid_private_key, status/SIEM/OTLP/audit-forward/SCIM tokens,
                # webhook URLs with tokens-in-path, cloud secret keys, registry
                # passwords. Apply the SAME recursive secret-named scrub as
                # /api/config (handles the *_password/_secret/_token/api_key/
                # private_key/credentials families, incl. nested registry creds),
                # then explicitly redact the credential-bearing keys whose NAMES
                # are not secret-shaped so the regex misses them.
                raw = load(f)
                if isinstance(raw, dict):
                    _redact_config_secrets_inplace(raw)
                    for k in ('agentless_ssh_key', 'webhook_url',
                              'healthchecks_url'):
                        if raw.get(k):
                            raw[k] = '(redacted)'
                    # webhook_urls[].url embeds Slack/Discord/Teams tokens in the
                    # path; pushover creds live here too.
                    if isinstance(raw.get('webhook_urls'), list):
                        for e in raw['webhook_urls']:
                            if not isinstance(e, dict):
                                continue
                            for ek in ('url', 'pushover_token', 'pushover_user'):
                                if e.get(ek):
                                    e[ek] = '(redacted)'
                    mp = raw.get('metrics_push')
                    if isinstance(mp, dict) and mp.get('url'):
                        mp['url'] = '(redacted)'
                    gi = raw.get('gitops')
                    if isinstance(gi, dict) and gi.get('auth_header'):
                        gi['auth_header'] = '(redacted)'
                    # cloud_accounts[].secret_key ends '_key' but isn't matched by
                    # the secret-name regex (only api_key/private_key are).
                    if isinstance(raw.get('cloud_accounts'), list):
                        for a in raw['cloud_accounts']:
                            if isinstance(a, dict) and a.get('secret_key'):
                                a['secret_key'] = '(redacted)'
                zf.writestr('config.json', json.dumps(raw, indent=2))
            else:
                zf.writestr(name, json.dumps(load(f), indent=2))
    data = buf.getvalue(); ts = time.strftime('%Y%m%d-%H%M%S')
    print("Status: 200 OK"); print("Content-Type: application/zip")
    print(f"Content-Disposition: attachment; filename=remotepower-backup-{ts}.zip")
    print(f"Content-Length: {len(data)}"); print("Cache-Control: no-store")
    print("X-Content-Type-Options: nosniff"); print()
    sys.stdout.flush(); sys.stdout.buffer.write(data); sys.stdout.buffer.flush(); sys.exit(0)


def handle_revoke_sessions():
    """Revoke all sessions for a specific user or all users."""
    requester = require_admin_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    target_user = _sanitize_str(body.get('username', ''), 32)
    tokens = load(TOKENS_FILE)
    if target_user:
        pruned = {k: v for k, v in tokens.items() if v.get('user') != target_user}
        count = len(tokens) - len(pruned)
    else:
        # Revoke all except requester's current session
        current_token = get_token_from_request()
        _cur_keys = {_token_hash(current_token), current_token}
        pruned = {k: v for k, v in tokens.items() if k in _cur_keys}
        count = len(tokens) - len(pruned)
    save(TOKENS_FILE, pruned)
    audit_log(requester, 'revoke_sessions', f'target={target_user or "all"}, revoked={count}')
    respond(200, {'ok': True, 'revoked': count})


# ── v3.12.0: relay satellites (authenticated agent → satellite → server) ─────

def _satellite_token_hash(tok):
    return hashlib.sha256(tok.encode('utf-8')).hexdigest()


def _record_satellite():
    """A request carrying an X-RP-Satellite header arrived via a relay
    satellite. Validate the token against the registry (reject if unknown) and
    stamp last_seen. Direct requests (no header) are untouched. Runs in main()
    before dispatch, so the device's own auth still applies on top."""
    tok = _env('HTTP_X_RP_SATELLITE', '').strip()
    if not tok:
        return
    h = _satellite_token_hash(tok)
    matched = None
    for sid, s in (load(SATELLITES_FILE) or {}).items():
        if isinstance(s, dict) and s.get('token_hash') and \
                hmac.compare_digest(s.get('token_hash', ''), h):
            matched = sid
            break
    if not matched:
        respond(401, {'error': 'invalid satellite token'})
    try:
        with _locked_update(SATELLITES_FILE, non_blocking=True) as st:
            if matched in st:
                st[matched]['last_seen'] = int(time.time())
                ip = _env('REMOTE_ADDR', '')
                if ip:
                    st[matched]['last_ip'] = _sanitize_ip(ip)
    except Exception:
        pass


def handle_satellites_list():
    """GET /api/satellites — list relay satellites (no secrets)."""
    require_admin_auth()
    respond(200, [{'id': sid, 'name': s.get('name', ''),
                   'created': s.get('created', 0),
                   'last_seen': s.get('last_seen'),
                   'last_ip': s.get('last_ip', ''),
                   'scanner': bool(s.get('scanner'))}   # v4.2.0 (B5)
                  for sid, s in (load(SATELLITES_FILE) or {}).items()])


def handle_satellites_create():
    """POST /api/satellites — mint a new satellite + token (shown once).
    Body: {name, scanner?}. `scanner:true` marks it a v4.2.0 (B5) scan worker
    (may claim/complete scan jobs via the satellite token)."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    name = _sanitize_str(body.get('name', ''), 64)
    if not name:
        respond(400, {'error': 'name required'})
    scanner = bool(body.get('scanner'))
    sats = load(SATELLITES_FILE)
    if len(sats) >= 50:
        respond(400, {'error': 'satellite limit reached (max 50)'})
    token = secrets.token_urlsafe(32)
    sid = secrets.token_hex(8)
    sats[sid] = {'name': name, 'token_hash': _satellite_token_hash(token),
                 'created': int(time.time()), 'last_seen': None, 'last_ip': '',
                 'scanner': scanner}
    save(SATELLITES_FILE, sats)
    audit_log(actor, 'satellite_create',
              detail=f'name={name} id={sid} scanner={scanner}')
    respond(201, {'ok': True, 'id': sid, 'token': token, 'scanner': scanner,
                  'note': 'Set this as RP_SATELLITE_TOKEN on the satellite — shown once.'})


def handle_satellites_update(sid):
    """PATCH /api/satellites/<id> — toggle the scanner capability. Body:
    {scanner: bool}."""
    actor = require_admin_auth()
    if method() != 'PATCH':
        respond(405, {'error': 'Method not allowed'})
    sid = _sanitize_str(sid, 32)
    scanner = bool((get_json_obj()).get('scanner'))
    found = False
    with _LockedUpdate(SATELLITES_FILE) as sats:
        if sid in sats and isinstance(sats[sid], dict):
            sats[sid]['scanner'] = scanner
            found = True
    if not found:
        respond(404, {'error': 'satellite not found'})
    audit_log(actor, 'satellite_update', detail=f'id={sid} scanner={scanner}')
    respond(200, {'ok': True, 'scanner': scanner})


def handle_satellites_delete(sid):
    """DELETE /api/satellites/<id> — revoke a satellite."""
    actor = require_admin_auth()
    sid = _sanitize_str(sid, 32)
    sats = load(SATELLITES_FILE)
    if sid in sats:
        nm = sats[sid].get('name', '')
        del sats[sid]
        save(SATELLITES_FILE, sats)
        audit_log(actor, 'satellite_delete', detail=f'id={sid} name={nm}')
    respond(200, {'ok': True})


# ── v4.2.0 (B5): authorized scan orchestration ──────────────────────────────
# White-hat only. The CARDINAL control is server-side: a scan target is DERIVED
# from an enrolled device the caller can see (require_perm('scan', [id]) — RBAC
# permission + role scope), never taken from client input, and re-validated
# against the SSRF-class denylist (`_ip_class_blocked`). P1 = enrolled hosts
# only, one safe tool (nuclei passive), executed by a scanner-enabled relay
# satellite that long-polls /api/scans/claim and posts normalised findings back.
# The `scan_finding` webhook event + non-enrolled (domain-verified) targets are
# P2 — deliberately NOT wired here.

def _scan_target_for_device(dev):
    """The address a scan job will probe for an enrolled device. Derived
    server-side from the device's reported IP (never client-supplied) and
    refused if it lands on an SSRF-class address (metadata/link-local/etc).
    Returns (target, error); target is '' when unusable."""
    ip = _sanitize_ip(dev.get('ip', '') or '')
    if not ip:
        return '', 'device has no known address to scan'
    try:
        if _ip_class_blocked(ip, allow_loopback=False):
            return '', 'device address is in a blocked class (metadata/link-local/loopback)'
    except ValueError:
        return '', 'device address is not a valid IP'
    return ip, ''


def require_satellite_scanner():
    """Authenticate a scanner-satellite worker via its X-RP-Satellite token and
    require the scanner capability. Returns the satellite id. _record_satellite()
    already 401s globally on an unknown token; this REQUIRES the header and that
    the satellite is scanner-enabled."""
    tok = _env('HTTP_X_RP_SATELLITE', '').strip()
    if not tok:
        respond(401, {'error': 'satellite token required'})
    h = _satellite_token_hash(tok)
    for sid, s in (load(SATELLITES_FILE) or {}).items():
        if isinstance(s, dict) and s.get('token_hash') and \
                hmac.compare_digest(s.get('token_hash', ''), h):
            if not s.get('scanner'):
                respond(403, {'error': 'satellite is not scanner-enabled'})
            return sid
    respond(401, {'error': 'invalid satellite token'})


def require_satellite():
    """W4-14: authenticate ANY relay satellite via its X-RP-Satellite token
    (no scanner capability required). Returns the satellite id, or 401s."""
    tok = _env('HTTP_X_RP_SATELLITE', '').strip()
    if not tok:
        respond(401, {'error': 'satellite token required'})
    h = _satellite_token_hash(tok)
    for sid, s in (load(SATELLITES_FILE) or {}).items():
        if isinstance(s, dict) and s.get('token_hash') and \
                hmac.compare_digest(s.get('token_hash', ''), h):
            return sid
    respond(401, {'error': 'invalid satellite token'})


def handle_satellite_monitor_work():
    """GET /api/satellite/monitor-work — a relay satellite fetches the monitor
    specs assigned to it (`via_satellite == <this id>`). It runs the probes on
    its own side of the network and POSTs results to /monitor-results.
    Auth: the satellite's X-RP-Satellite token."""
    sid = require_satellite()
    cfg = _config_ro()
    jobs = []
    for m in (cfg.get('monitors') or []):
        if not isinstance(m, dict) or m.get('via_satellite') != sid:
            continue
        jobs.append({
            'label':  _sanitize_str(m.get('label', m.get('target', '')), 128),
            'type':   m.get('type', 'ping'),
            'target': m.get('target', ''),
            'port':   m.get('port'),
            'expect_status': m.get('expect_status'),
            'expect_contains': m.get('body_value') if m.get('body_mode') == 'contains' else None,
            'timeout': 10,
        })
    respond(200, {'satellite_id': sid, 'monitors': jobs,
                  'interval': max(60, int(cfg.get('monitor_interval', 300) or 300))})


def handle_satellite_monitor_results():
    """POST /api/satellite/monitor-results — a relay satellite reports the results
    of the monitors assigned to it. Body {results:[{label,type,target,ok,detail,
    latency_ms?}]}. Only labels that are actually assigned to THIS satellite are
    accepted (an authed satellite can't spoof another's monitor). Auth: token."""
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    sid = require_satellite()
    body = get_json_obj()
    raw = body.get('results')
    if not isinstance(raw, list):
        respond(400, {'error': 'results must be a list'})
    cfg = _config_ro()
    # Labels legitimately owned by THIS satellite.
    owned = {_sanitize_str(m.get('label', m.get('target', '')), 128)
             for m in (cfg.get('monitors') or [])
             if isinstance(m, dict) and m.get('via_satellite') == sid}
    now = int(time.time())
    results, store = [], (load(SATELLITE_MON_FILE) or {})
    for r in raw[:200]:
        if not isinstance(r, dict):
            continue
        label = _sanitize_str(str(r.get('label', '')), 128)
        if label not in owned:
            continue
        res = {
            'label':  label,
            'type':   _sanitize_str(str(r.get('type', 'ping')), 16),
            'target': _sanitize_str(str(r.get('target', '')), 256),
            'ok':     bool(r.get('ok')),
            'detail': _sanitize_str(str(r.get('detail', '')), 256),
            'checked': now,
        }
        if isinstance(r.get('latency_ms'), (int, float)):
            res['latency_ms'] = round(float(r['latency_ms']), 1)
        results.append(res)
        store[label] = res
    if results:
        _persist_monitor_results(results)     # history + monitor_down/up transitions
        save(SATELLITE_MON_FILE, store)
    respond(200, {'ok': True, 'accepted': len(results)})


def _scan_sev_counts(findings):
    out = {'critical': 0, 'high': 0, 'medium': 0, 'low': 0, 'info': 0, 'unknown': 0}
    for f in (findings or []):
        sv = str((f or {}).get('severity', 'unknown')).lower()
        out[sv if sv in out else 'unknown'] += 1
    return out


def _scan_public(s):
    """Public (metadata) view of a scan record — no findings body."""
    return {
        'id': s.get('id'), 'status': s.get('status'),
        'target': s.get('target'), 'target_device_id': s.get('target_device_id'),
        'target_name': s.get('target_name', ''),
        'tool': s.get('tool'), 'profile': s.get('profile'),
        'intensity': s.get('intensity', 'quick'),
        'runner': s.get('runner', 'satellite'),
        'satellite_id': s.get('satellite_id', ''),
        'actor': s.get('actor'), 'created': s.get('created'),
        'claimed_by': s.get('claimed_by'), 'claimed_at': s.get('claimed_at'),
        'finished_at': s.get('finished_at'), 'error': s.get('error', ''),
        'attested': bool(s.get('attested')),
        'window_overridden': bool(s.get('window_overridden')),
        'finding_count': len(s.get('findings') or []),
        'severity_counts': _scan_sev_counts(s.get('findings') or []),
        # v4.2.0 sweep: lynis 0–100 host-hardening score (host scans only).
        'hardening_index': s.get('hardening_index'),
    }


def _scan_window_active(dev_id, dev):
    """True if an active maintenance window currently covers this device. Used
    to gate active/intrusive scans away from peak hours (reuses _window_active,
    the same predicate the alert-suppression path uses)."""
    try:
        windows = (load(MAINT_FILE) or {}).get('windows') or []
    except Exception:
        return False
    now = int(time.time())
    dev_group = (dev or {}).get('group') or ''
    for w in windows:
        scope = (w.get('scope') or 'device').lower()
        applies = (scope == 'global'
                   or (scope == 'group' and dev_group and w.get('target') == dev_group)
                   or (scope == 'device' and dev_id and w.get('target') == dev_id))
        if applies and _window_active(w, now):
            return True
    return False


def handle_scans_list():
    """GET /api/scans — scans visible to the caller (filtered to role scope by
    target device). Newest first."""
    require_perm('scan')
    scope = _caller_scope()
    devices = load(DEVICES_FILE) if scope is not None else None
    scans = load(SCANS_FILE) or {}
    out = []
    for s in scans.values():
        if not isinstance(s, dict):
            continue
        if scope is not None:
            dev = (devices or {}).get(s.get('target_device_id') or '')
            if not dev or not _device_in_scope(scope, dev):
                continue
        out.append(_scan_public(s))
    out.sort(key=lambda r: r.get('created') or 0, reverse=True)
    # scanner satellites the operator can target (bounded ≤50 — a dropdown is
    # fine here, unlike device pickers). Empty list = no scanner satellite yet.
    sats = [{'id': sid, 'name': s.get('name', '')}
            for sid, s in (load(SATELLITES_FILE) or {}).items()
            if isinstance(s, dict) and s.get('scanner')]
    respond(200, {'scans': out, 'tools': list(SCAN_TOOLS),
                  'active_tools': list(SCAN_ACTIVE_TOOLS),
                  'profiles': list(SCAN_PROFILES),
                  'intensities': list(SCAN_INTENSITIES), 'satellites': sats})


def handle_scan_detail(scan_id):
    """GET /api/scans/<id> — one scan incl. full findings (scope-checked)."""
    require_perm('scan')
    scan_id = _sanitize_str(scan_id, 32)
    s = (load(SCANS_FILE) or {}).get(scan_id)
    if not isinstance(s, dict):
        respond(404, {'error': 'scan not found'})
    scope = _caller_scope()
    if scope is not None:
        dev = device_get(s.get('target_device_id') or '')
        if not dev or not _device_in_scope(scope, dev):
            respond(404, {'error': 'scan not found'})
    pub = _scan_public(s)
    pub['findings'] = s.get('findings') or []
    respond(200, pub)


def handle_scans_create():
    """POST /api/scans — queue an authorized scan. Two target forms:
      • {device_id} — an ENROLLED host; target derived server-side from the
        device record; RBAC scope enforced via require_perm('scan',[id]).
      • {scan_target_id} — a VERIFIED non-enrolled target (B5 P2). Requires the
        'scan' perm AND an all-scope caller (scoped roles only scan their hosts).
    The target string is never taken from raw client input."""
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    dev_id = _sanitize_str(str(body.get('device_id', '')), 64)
    st_id  = _sanitize_str(str(body.get('scan_target_id', '')), 64)
    # Profile + tool first — the allowed tool set is profile-dependent.
    tool = _sanitize_str(str(body.get('tool', 'nuclei')), 32) or 'nuclei'
    is_all = (tool == 'all')   # v4.2.0 (#6): fan out to every network tool
    is_host = (not is_all) and tool in HOST_SCAN_TOOLS
    if is_host:
        # On-host audit (lynis) — run by the device's own agent, read-only; the
        # passive/active profile axis (network intensity) doesn't apply.
        profile = 'host'
    else:
        profile = _sanitize_str(str(body.get('profile', 'passive')), 32) or 'passive'
        if profile not in SCAN_PROFILES:
            respond(400, {'error': f'unsupported profile (supported: {", ".join(SCAN_PROFILES)})'})
        allowed_tools = SCAN_ACTIVE_TOOLS if profile == 'active' else SCAN_TOOLS
        if not is_all and tool not in allowed_tools:
            respond(400, {'error': f'tool {tool!r} not available in the {profile} '
                                   f'profile (supported: {", ".join(allowed_tools)}, or "all")'})
    # v4.2.0 (#6): depth knob. quick = fast/shallow, full = thorough (worker tunes
    # per-tool flags). Host audits ignore it.
    intensity = _sanitize_str(str(body.get('intensity', 'quick')), 16) or 'quick'
    if intensity not in SCAN_INTENSITIES:
        respond(400, {'error': f'unsupported intensity (supported: {", ".join(SCAN_INTENSITIES)})'})
    dev = None
    if dev_id:
        # RBAC: 'scan' permission AND the target must be inside the caller's scope.
        actor = require_perm('scan', [dev_id])
        dev = device_get(dev_id)
        if not isinstance(dev, dict):
            respond(404, {'error': 'Device not found'})
        # CARDINAL CONTROL: target derived from the enrolled device, server-side.
        target, terr = _scan_target_for_device(dev)
        if terr:
            respond(400, {'error': terr})
        target_device_id, target_name = dev_id, dev.get('name', dev_id)
        # v4.2.0 (#1): optional vhost — scan a hostname (the right Host header /
        # vhost on this device) instead of its bare IP. Gated by ownership: the
        # vhost must be an already-VERIFIED scan target, so this can't be abused
        # to scan an arbitrary third-party host via a device you happen to own.
        vhost = _sanitize_str(str(body.get('vhost', '')), 253).lower()
        if vhost and not is_host:
            vt = next((t for t in (load(SCAN_TARGETS_FILE) or {}).values()
                       if isinstance(t, dict) and t.get('verified') and t.get('target') == vhost), None)
            if not vt:
                respond(400, {'error': f'vhost {vhost!r} must be an ownership-verified web target first'})
            target, target_name = vhost, f'{vhost} (on {dev.get("name", dev_id)})'
        elif vhost and is_host:
            respond(400, {'error': 'vhost does not apply to on-host audits'})
    elif st_id:
        if is_host:
            respond(400, {'error': 'host-audit tools (lynis) run on an enrolled host — use device_id'})
        actor = require_perm('scan')
        if _caller_scope() is not None:
            respond(403, {'error': 'scoped roles can only scan enrolled hosts in their scope'})
        t = (load(SCAN_TARGETS_FILE) or {}).get(st_id)
        if not isinstance(t, dict) or not t.get('verified'):
            respond(400, {'error': 'scan target not found or not ownership-verified'})
        target, target_device_id, target_name = t['target'], '', t['target']
        # IP targets still honour the SSRF-class denylist (verified or not).
        if t.get('kind') == 'ip':
            try:
                if _ip_class_blocked(target, allow_loopback=False):
                    respond(400, {'error': 'target address is in a blocked class'})
            except ValueError:
                respond(400, {'error': 'invalid target address'})
    else:
        respond(400, {'error': 'device_id or scan_target_id required'})
    # v4.2.0 P3: active/intrusive tier safety harness. Active scans send attack
    # traffic, so they require (1) an explicit authorization ATTESTATION, and
    # (2) for enrolled hosts, an active maintenance window (overridable) — so a
    # fragile prod box isn't fuzzed at peak. Both are recorded on the scan.
    attest_meta = {}
    if profile == 'active':
        if body.get('attestation') is not True:
            respond(403, {'error': 'active scans require "attestation": true — '
                          'affirm you are authorized to actively scan this target'})
        overrode = False
        if dev_id and not _scan_window_active(dev_id, dev):
            if not body.get('override_window'):
                respond(409, {'error': 'active scan needs an active maintenance '
                              'window for this host — open one (Monitoring → '
                              'Maintenance) or pass "override_window": true'})
            overrode = True
        attest_meta = {'attested': True, 'attested_by': actor,
                       'attested_at': int(time.time()),
                       'window_overridden': overrode}
    # v4.2.0: optional satellite targeting (network scans only). Empty = any
    # scanner satellite picks it up; a value pins it to that satellite — e.g.
    # the one on the target's network segment. Host scans run on the agent, so
    # a satellite assignment is meaningless there.
    sat_id = '' if is_host else _sanitize_str(str(body.get('satellite_id', '')), 32)
    if sat_id:
        _sats = load(SATELLITES_FILE) or {}
        if sat_id not in _sats or not _sats[sat_id].get('scanner'):
            respond(400, {'error': 'unknown or non-scanner satellite'})
    # v4.2.0 (#6): tool="all" fans out to one scan per network tool in the profile.
    tools_to_run = list(allowed_tools) if is_all else [tool]
    now = int(time.time())
    created = []
    with _LockedUpdate(SCANS_FILE) as scans:
        # ring-buffer: make room for the whole batch
        need = len(tools_to_run)
        if len(scans) + need > MAX_SCANS:
            terminal = sorted(
                [k for k, v in scans.items()
                 if isinstance(v, dict) and v.get('status') in ('done', 'failed', 'cancelled')],
                key=lambda k: scans[k].get('created') or 0)
            for k in terminal[:max(0, len(scans) + need - MAX_SCANS)]:
                del scans[k]
        for tl in tools_to_run:
            sid = secrets.token_hex(8)
            rec = {
                'id': sid, 'target_device_id': target_device_id,
                'target_name': target_name, 'target': target,
                'tool': tl, 'profile': profile, 'intensity': intensity, 'status': 'queued',
                'runner': 'agent' if is_host else 'satellite', 'satellite_id': sat_id,
                'created': now, 'actor': actor, 'claimed_by': None,
                'claimed_at': None, 'finished_at': None, 'findings': [], 'error': '',
                **attest_meta,
            }
            scans[sid] = rec
            created.append(rec)
    for rec in created:
        audit_log(actor, 'scan_create',
                  f'id={rec["id"]} device={target_device_id or "-"} tool={rec["tool"]} '
                  f'profile={profile} intensity={intensity} target={target}'
                  + (f' attested window_overridden={attest_meta.get("window_overridden")}'
                     if profile == 'active' else ''))
    if is_all:
        respond(201, {'ok': True, 'count': len(created),
                      'ids': [r['id'] for r in created],
                      'scans': [_scan_public(r) for r in created]})
    respond(201, {'ok': True, 'id': created[0]['id'], 'scan': _scan_public(created[0])})


def handle_scan_delete(scan_id):
    """DELETE /api/scans/<id> — remove a scan record and its findings
    (scope-checked). Removing a queued/running scan also stops it: the worker
    gets a 409 when it tries to report, since the record is gone."""
    if method() != 'DELETE':
        respond(405, {'error': 'Method not allowed'})
    scan_id = _sanitize_str(scan_id, 32)
    s0 = (load(SCANS_FILE) or {}).get(scan_id)
    if not isinstance(s0, dict):
        respond(404, {'error': 'scan not found'})
    actor = require_perm('scan', [s0.get('target_device_id') or ''])
    removed = False
    with _LockedUpdate(SCANS_FILE) as scans:
        if scan_id in scans:
            del scans[scan_id]
            removed = True
    if removed:
        audit_log(actor, 'scan_delete', f'id={scan_id}')
    respond(200, {'ok': True, 'removed': removed})


def handle_scans_clear():
    """POST /api/scans/clear — remove all FINISHED scans (done/failed/cancelled)
    the caller can see; running/queued are kept. Clears their findings too."""
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    actor = require_perm('scan')
    scope = _caller_scope()
    devices = load(DEVICES_FILE) if scope is not None else None
    removed = 0
    with _LockedUpdate(SCANS_FILE) as scans:
        for k in list(scans.keys()):
            v = scans.get(k)
            if not isinstance(v, dict) or v.get('status') not in ('done', 'failed', 'cancelled'):
                continue
            if scope is not None:
                dev = (devices or {}).get(v.get('target_device_id') or '')
                if not dev or not _device_in_scope(scope, dev):
                    continue
            del scans[k]
            removed += 1
    audit_log(actor, 'scans_clear', f'removed={removed}')
    respond(200, {'ok': True, 'removed': removed})


def handle_scan_claim():
    """POST /api/scans/claim — a scanner satellite claims the next queued scan.
    Authenticated by the satellite's (scanner-enabled) X-RP-Satellite token.
    Returns {scan: {id,target,tool,profile}} or {scan: null}."""
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    sid_sat = require_satellite_scanner()
    claimed = None
    with _LockedUpdate(SCANS_FILE) as scans:
        queued = sorted(
            [v for v in scans.values()
             if isinstance(v, dict) and v.get('status') == 'queued'
             and v.get('runner') != 'agent'      # agent-run host scans go via heartbeat
             # targeted to THIS satellite, or unassigned ('any satellite')
             and (not v.get('satellite_id') or v.get('satellite_id') == sid_sat)],
            key=lambda v: v.get('created') or 0)
        if queued:
            job = queued[0]
            job['status'] = 'running'
            job['claimed_by'] = sid_sat
            job['claimed_at'] = int(time.time())
            claimed = {'id': job['id'], 'target': job['target'],
                       'tool': job['tool'], 'profile': job['profile'],
                       'intensity': job.get('intensity', 'quick')}
    if claimed:
        audit_log(f'satellite:{sid_sat}', 'scan_claim',
                  f"id={claimed['id']} target={claimed['target']}")
    respond(200, {'scan': claimed})


def _validate_scan_finding(f):
    """Normalise + bound one worker-supplied finding to the stored shape."""
    sev = str((f or {}).get('severity', 'unknown')).lower()
    if sev not in ('critical', 'high', 'medium', 'low', 'info', 'unknown'):
        sev = 'unknown'
    return {
        'rule_id':   _sanitize_str(str((f or {}).get('rule_id', '')), 200),
        'title':     _sanitize_str(str((f or {}).get('title', '')), 300),
        'severity':  sev,
        'evidence':  _sanitize_str(str((f or {}).get('evidence', '')), 1000),
        'reference': _sanitize_str(str((f or {}).get('reference', '')), 500),
    }


def _apply_scan_results(scan_id, status, findings_raw, error, by, restrict_device=None,
                        hardening_index=None):
    """Shared results-ingest for BOTH the satellite endpoint and the agent
    heartbeat path. Moves a running scan → terminal and edge-fires scan_finding
    on high/critical. Returns (ok, http_code).

    `by` is the reporter (satellite id or 'agent:<dev>'). With restrict_device
    set (agent path) the scan's target_device_id must match it — a host can only
    complete ITS OWN scan. Otherwise claimed_by must match `by` (satellite path).
    fire_webhook + audit run AFTER the lock commits."""
    scan_id = _sanitize_str(str(scan_id), 32)
    status = str(status).lower()
    if status not in ('done', 'failed'):
        status = 'done'
    if not isinstance(findings_raw, list):
        findings_raw = []
    findings = [_validate_scan_finding(f) for f in findings_raw[:MAX_SCAN_FINDINGS]]
    err = _sanitize_str(str(error or ''), 500)
    fire_info = None
    code = 409
    with _LockedUpdate(SCANS_FILE) as scans:
        s = scans.get(scan_id)
        if not isinstance(s, dict) or s.get('status') != 'running':
            code = 409
        elif restrict_device is not None and s.get('target_device_id') != restrict_device:
            code = 403
        elif restrict_device is None and s.get('claimed_by') and s.get('claimed_by') != by:
            code = 403
        else:
            s['status'] = status
            s['findings'] = findings
            s['error'] = err
            s['finished_at'] = int(time.time())
            # v4.2.0 sweep: lynis 0–100 host-hardening score — the natural
            # per-host headline for an on-host audit (was parsed out and
            # discarded by the agent before).
            if isinstance(hardening_index, int) and 0 <= hardening_index <= 100:
                s['hardening_index'] = hardening_index
            fire_info = {'device_id': s.get('target_device_id'),
                         'name': s.get('target_name', ''),
                         'target': s.get('target', ''),
                         'actor': s.get('actor', '')}
            code = 200
    if code != 200:
        return False, code
    counts = _scan_sev_counts(findings)
    # v4.2.0 (#7): fire ONLY for SCHEDULED scans (actor "schedule:<id>"), and on
    # ANY findings — a quiet INFO dashboard notice. On-demand scans you launched
    # yourself never alert (you're already looking at the results).
    scheduled = str(fire_info.get('actor', '')).startswith('schedule:')
    if status == 'done' and scheduled and findings:
        fire_webhook('scan_finding', {
            'device_id':   fire_info['device_id'],
            'device_name': fire_info['name'], 'name': fire_info['name'],
            'target':      fire_info['target'], 'scan_id': scan_id,
            'total': len(findings),
            'critical': counts['critical'], 'high': counts['high'],
            'medium': counts['medium'], 'low': counts['low'],
        })
    audit_log(by, 'scan_results',
              f'id={scan_id} status={status} findings={len(findings)}')
    return True, 200


def _claim_agent_scan(dev_id):
    """Claim (queued→running) the oldest agent-run host scan for this device.
    Returns {id, tool} to hand the agent, or None. Called POST-lock in the
    heartbeat — SCANS_FILE has its own lock, so no nesting with DEVICES."""
    # v4.2.0 sweep (perf): lock-free peek first. This runs on every heartbeat,
    # and _LockedUpdate rewrites the whole scans store (which can hold 500
    # scans × 1000 findings) on exit even when nothing was claimed. Only take
    # the lock when a matching queued job actually exists.
    peek = load(SCANS_FILE) or {}
    if not any(isinstance(v, dict) and v.get('status') == 'queued'
               and v.get('runner') == 'agent'
               and v.get('target_device_id') == dev_id
               for v in peek.values()):
        return None
    claimed = None
    with _LockedUpdate(SCANS_FILE) as scans:
        cands = sorted(
            [v for v in scans.values()
             if isinstance(v, dict) and v.get('status') == 'queued'
             and v.get('runner') == 'agent'
             and v.get('target_device_id') == dev_id],
            key=lambda v: v.get('created') or 0)
        if cands:
            j = cands[0]
            j['status'] = 'running'
            j['claimed_by'] = f'agent:{dev_id}'
            j['claimed_at'] = int(time.time())
            claimed = {'id': j['id'], 'tool': j['tool']}
    return claimed


def handle_scan_results(scan_id):
    """POST /api/scans/<id>/results — scanner satellite posts SARIF-normalised
    findings + terminal status. Only the satellite that claimed the job may
    complete it (agent-run host scans report via the heartbeat instead)."""
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    sid_sat = require_satellite_scanner()
    body = get_json_obj()
    raw = body.get('findings')
    if raw is not None and not isinstance(raw, list):
        respond(400, {'error': 'findings must be a list'})
    ok, code = _apply_scan_results(scan_id, body.get('status', 'done'),
                                   raw or [], body.get('error', ''), by=sid_sat)
    if not ok:
        respond(code, {'error': ('scan claimed by another worker' if code == 403
                                 else 'scan not in a running state')})
    respond(200, {'ok': True})


# ── v4.2.0 (B5 P2): ownership-verified scan targets (non-enrolled) ───────────
# Enrolled hosts get free ownership proof via enrollment. To scan a domain/IP
# that ISN'T a fleet host, the operator must first PROVE control of it — ACME
# style — before it enters the scan allowlist. Two proofs: a DNS TXT record, or
# a file at /.well-known/. Until `verified`, a target can never be scanned.

def _classify_scan_target(s):
    """('domain'|'ip', cleaned) for a scannable target, else (None, '').
    Tolerates a pasted URL (scheme/path/port stripped)."""
    s = (s or '').strip().lower()
    if '://' in s:
        s = s.split('://', 1)[1]
    s = s.split('/', 1)[0].split('?', 1)[0]
    # strip a :port suffix (but not part of an IPv6 literal)
    if s.count(':') == 1:
        s = s.split(':', 1)[0]
    if not s:
        return None, ''
    try:
        import ipaddress
        ipaddress.ip_address(s)
        return 'ip', s
    except ValueError:
        pass
    if re.match(r'^(?=.{1,253}$)([a-z0-9_](-?[a-z0-9_]){0,62}\.)+[a-z]{2,}$', s):
        return 'domain', s
    return None, ''


def _verify_scan_target_dns(target, token):
    """Look for the proof token in a TXT record at _remotepower-scan-auth.<t>."""
    try:
        import dns.resolver
    except ImportError:
        return False, 'DNS verification unavailable (dnspython not installed)'
    name = f'_remotepower-scan-auth.{target}'
    try:
        answers = dns.resolver.resolve(name, 'TXT')
    except Exception:
        return False, f'no TXT record found at {name}'
    for rdata in answers:
        parts = getattr(rdata, 'strings', None)
        txt = (b''.join(parts).decode('utf-8', 'ignore') if parts
               else str(rdata).strip('"'))
        if token in txt:
            return True, ''
    return False, f'proof token not present in {name} TXT'


def _verify_scan_target_file(target, token):
    """Look for the proof token in /.well-known/remotepower-scan-authorization.txt,
    fetched through the anti-rebinding, no-redirect SSRF-safe opener."""
    path = '/.well-known/remotepower-scan-authorization.txt'
    for scheme in ('https', 'http'):
        url = f'{scheme}://{target}{path}'
        try:
            _ctx = _get_ssl_context() if scheme == 'https' else None
            # allow_loopback=False — matches the scan-time denylist. A target
            # resolving to 127.0.0.0/8 would otherwise turn ownership
            # verification into a blind SSRF oracle against the server itself.
            opener = _ssrf_safe_opener(allow_loopback=False, ssl_ctx=_ctx,
                                       no_redirect=True)
            req = urllib.request.Request(url, headers={'Accept': 'text/plain'})
            with opener.open(req, timeout=8) as resp:
                body = resp.read(4096).decode('utf-8', 'ignore')
            if token in body:
                return True, ''
        except Exception:
            continue
    return False, f'proof token not found at {path}'


def _scan_target_public(t):
    return {'id': t.get('id'), 'target': t.get('target'), 'kind': t.get('kind'),
            'verified': bool(t.get('verified')), 'verified_at': t.get('verified_at'),
            'method': t.get('method', ''), 'created': t.get('created'),
            'actor': t.get('actor', '')}


def handle_scan_targets_list():
    """GET /api/scan-targets — registered non-enrolled targets (no tokens)."""
    require_perm('scan')
    targets = load(SCAN_TARGETS_FILE) or {}
    out = sorted((_scan_target_public(t) for t in targets.values()
                  if isinstance(t, dict)),
                 key=lambda r: r.get('created') or 0, reverse=True)
    respond(200, {'targets': out})


def handle_scan_targets_create():
    """POST /api/scan-targets — register a domain/IP to verify ownership of.
    Returns the proof (DNS TXT + /.well-known file). Admin-only; the target is
    NOT scannable until /verify succeeds."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    raw = _sanitize_str(str((get_json_obj()).get('target', '')), 253)
    kind, target = _classify_scan_target(raw)
    if not kind:
        respond(400, {'error': 'target must be a valid domain or IP address'})
    targets = load(SCAN_TARGETS_FILE) or {}
    for t in targets.values():
        if isinstance(t, dict) and t.get('target') == target:
            respond(409, {'error': 'target already registered'})
    if len(targets) >= 200:
        respond(400, {'error': 'scan-target limit reached (max 200)'})
    tid = secrets.token_hex(8)
    token = 'rpscan-' + secrets.token_urlsafe(24)
    rec = {'id': tid, 'target': target, 'kind': kind, 'token': token,
           'verified': False, 'verified_at': None, 'method': '',
           'created': int(time.time()), 'actor': actor}
    targets[tid] = rec
    save(SCAN_TARGETS_FILE, targets)
    audit_log(actor, 'scan_target_create', f'target={target} kind={kind}')
    respond(201, {
        'ok': True, 'id': tid, 'target': target, 'kind': kind, 'token': token,
        'dns': ({'name': f'_remotepower-scan-auth.{target}', 'type': 'TXT',
                 'value': token} if kind == 'domain' else None),
        'file': {'path': '/.well-known/remotepower-scan-authorization.txt',
                 'content': token},
        'note': 'Publish EITHER proof, then POST /verify. Until verified, this '
                'target cannot be scanned.',
    })


def handle_scan_target_verify(tid):
    """POST /api/scan-targets/<id>/verify — attempt DNS then file proof."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    tid = _sanitize_str(tid, 32)
    t = (load(SCAN_TARGETS_FILE) or {}).get(tid)
    if not isinstance(t, dict):
        respond(404, {'error': 'scan target not found'})
    ok, used, err = False, '', ''
    if t.get('kind') == 'domain':
        ok, err = _verify_scan_target_dns(t['target'], t['token'])
        if ok:
            used = 'dns'
    if not ok:
        ok2, err2 = _verify_scan_target_file(t['target'], t['token'])
        if ok2:
            ok, used = True, 'file'
        else:
            err = err or err2
    if ok:
        with _LockedUpdate(SCAN_TARGETS_FILE) as st:
            if tid in st:
                st[tid]['verified'] = True
                st[tid]['verified_at'] = int(time.time())
                st[tid]['method'] = used
        audit_log(actor, 'scan_target_verify', f'target={t["target"]} method={used}')
        respond(200, {'ok': True, 'verified': True, 'method': used})
    audit_log(actor, 'scan_target_verify_fail', f'target={t["target"]}')
    respond(200, {'ok': False, 'verified': False, 'error': err or 'verification failed'})


def handle_scan_target_delete(tid):
    """DELETE /api/scan-targets/<id> — drop a registered target."""
    actor = require_admin_auth()
    if method() != 'DELETE':
        respond(405, {'error': 'Method not allowed'})
    tid = _sanitize_str(tid, 32)
    targets = load(SCAN_TARGETS_FILE)
    if tid in targets:
        tg = targets[tid].get('target', '')
        del targets[tid]
        save(SCAN_TARGETS_FILE, targets)
        audit_log(actor, 'scan_target_delete', f'id={tid} target={tg}')
    respond(200, {'ok': True})


# ── v4.2.0 (#4): scheduled scans ─────────────────────────────────────────────
# A schedule stores a scan spec + a 5-field cron. run_scheduled_scans_if_due()
# is called opportunistically from the heartbeat (cheap 60s gate) and enqueues
# the scan(s) when due — they're ordinary scan records, so the existing
# scan_finding alert fires automatically on high/critical results.

def _store_scan_records(recs):
    """Insert built scan records under the SCANS lock, with ring-buffer trim."""
    with _LockedUpdate(SCANS_FILE) as scans:
        need = len(recs)
        if len(scans) + need > MAX_SCANS:
            terminal = sorted(
                [k for k, v in scans.items()
                 if isinstance(v, dict) and v.get('status') in ('done', 'failed', 'cancelled')],
                key=lambda k: scans[k].get('created') or 0)
            for k in terminal[:max(0, len(scans) + need - MAX_SCANS)]:
                del scans[k]
        for r in recs:
            scans[r['id']] = r


def _scan_sched_public(s):
    return {'id': s.get('id'), 'name': s.get('name', ''),
            'device_id': s.get('device_id', ''), 'scan_target_id': s.get('scan_target_id', ''),
            'tool': s.get('tool'), 'profile': s.get('profile'),
            'intensity': s.get('intensity', 'quick'), 'cron': s.get('cron', ''),
            'enabled': bool(s.get('enabled')), 'last_run': s.get('last_run', 0),
            'next_run': s.get('next_run', 0), 'created': s.get('created'),
            'actor': s.get('actor', '')}


def _create_scheduled_scan(sc):
    """Enqueue the scan(s) for a fired schedule. Re-resolves the target so a
    device's current address is used; pre-authorised (the operator attested at
    schedule-creation time)."""
    profile = sc.get('profile', 'passive')
    intensity = sc.get('intensity', 'quick')
    tool = sc.get('tool', 'nuclei')
    is_host = (tool != 'all') and tool in HOST_SCAN_TOOLS
    dev_id, st_id = sc.get('device_id', ''), sc.get('scan_target_id', '')
    if dev_id:
        dev = device_get(dev_id)
        if not isinstance(dev, dict):
            return
        target, terr = _scan_target_for_device(dev)
        if terr:
            return
        target_device_id, target_name = dev_id, dev.get('name', dev_id)
    elif st_id:
        t = (load(SCAN_TARGETS_FILE) or {}).get(st_id)
        if not isinstance(t, dict) or not t.get('verified'):
            return
        target, target_device_id, target_name = t['target'], '', t['target']
    else:
        return
    tools = (list(SCAN_ACTIVE_TOOLS if profile == 'active' else SCAN_TOOLS)
             if tool == 'all' else [tool])
    actor = f'schedule:{sc.get("id", "")}'
    attest = ({'attested': True, 'attested_by': actor, 'attested_at': int(time.time()),
               'window_overridden': True} if profile == 'active' and not is_host else {})
    now = int(time.time())
    recs = [{
        'id': secrets.token_hex(8), 'target_device_id': target_device_id,
        'target_name': target_name, 'target': target, 'tool': tl,
        'profile': profile, 'intensity': intensity, 'status': 'queued',
        'runner': 'agent' if is_host else 'satellite',
        'satellite_id': '' if is_host else sc.get('satellite_id', ''),
        'created': now, 'actor': actor, 'claimed_by': None, 'claimed_at': None,
        'finished_at': None, 'findings': [], 'error': '', **attest,
    } for tl in tools]
    _store_scan_records(recs)
    audit_log(actor, 'scheduled_scan_fire',
              f'schedule={sc.get("id")} tools={",".join(tools)} target={target} count={len(recs)}')


def run_scheduled_scans_if_due():
    """Heartbeat hook: fire any due scan schedule. Cheap 60s check-gate; the
    per-schedule next_run is the real throttle."""
    try:
        scheds = load(SCAN_SCHEDULES_FILE)
    except Exception:
        scheds = {}
    now = int(time.time())
    gate = DATA_DIR / '.scan_sched_check'
    try:
        if gate.exists() and now - int(gate.stat().st_mtime) < 60:
            return
        gate.write_text(str(now))
    except OSError:
        pass
    due = []
    if scheds:
        with _LockedUpdate(SCAN_SCHEDULES_FILE) as st:
            for s in st.values():
                if not isinstance(s, dict) or not s.get('enabled'):
                    continue
                nr = s.get('next_run') or 0
                if nr and nr <= now:
                    # _cron_next has a ~45-day search horizon, so a yearly/
                    # quarterly cron returns None right after firing. next_run=0
                    # is never re-evaluated (the due test skips it) — the schedule
                    # would silently die after one run. Instead we park a re-check
                    # ~30 days out, flagged so it only re-runs this search and
                    # never fires a scan itself.
                    if s.pop('_park', False):
                        nxt = _cron_next(s.get('cron', ''), now)
                        s['next_run'] = nxt or (now + 30 * 86400)
                        if not nxt:
                            s['_park'] = True
                        continue
                    due.append(dict(s))
                    s['last_run'] = now
                    nxt = _cron_next(s.get('cron', ''), now)
                    s['next_run'] = nxt or (now + 30 * 86400)
                    if not nxt:
                        s['_park'] = True
    for s in due:
        try:
            _create_scheduled_scan(s)
        except Exception as e:
            sys.stderr.write(f'[remotepower] scheduled scan failed: {e}\n')
    # v4.2.0 sweep: age out stuck scans (same 60s gate as the schedules above).
    # A satellite that dies mid-scan, a scanner exception that posts nothing,
    # or a lost agent result left status='running' forever — claimed_at was
    # recorded but never compared anywhere. 4h is far past every tool timeout.
    try:
        cutoff = now - 4 * 3600
        scans_peek = load(SCANS_FILE) or {}
        if any(isinstance(sc, dict) and sc.get('status') == 'running'
               and 0 < (sc.get('claimed_at') or 0) < cutoff
               for sc in scans_peek.values()):
            with _LockedUpdate(SCANS_FILE) as sc_st:
                for sc in sc_st.values():
                    if (isinstance(sc, dict) and sc.get('status') == 'running'
                            and 0 < (sc.get('claimed_at') or 0) < cutoff):
                        sc['status'] = 'failed'
                        sc['error'] = 'timed out — no result from the runner within 4h'
                        sc['finished_at'] = now
    except Exception as e:
        sys.stderr.write(f'[remotepower] scan timeout sweep failed: {e}\n')


def _scan_sched_in_scope(sched, scope):
    """v4.2.0 finalize (authz): may a caller with `scope` (from _caller_scope())
    act on this schedule? Mirrors handle_scan_schedules_create's rule — an
    all-scope caller (scope is None) sees everything; a scoped caller may only
    touch device-targeted schedules whose host is inside their scope (never a
    domain/scan-target schedule, which is all-scope only)."""
    if scope is None:
        return True
    dev_id = sched.get('device_id')
    if not dev_id:
        return False   # target-only schedules are all-scope only
    dev = device_get(dev_id)
    return isinstance(dev, dict) and _device_in_scope(scope, dev)


def handle_scan_schedules_list():
    """GET /api/scan-schedules — recurring scan schedules (scope-filtered)."""
    require_perm('scan')
    scope = _caller_scope()
    scheds = load(SCAN_SCHEDULES_FILE) or {}
    out = sorted((_scan_sched_public(s) for s in scheds.values()
                  if isinstance(s, dict) and _scan_sched_in_scope(s, scope)),
                 key=lambda r: r.get('created') or 0, reverse=True)
    respond(200, {'schedules': out})


def handle_scan_schedules_create():
    """POST /api/scan-schedules — create a recurring scan (cron). Same target +
    tool/profile/intensity options as a one-off scan; active needs attestation."""
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    dev_id = _sanitize_str(str(body.get('device_id', '')), 64)
    st_id  = _sanitize_str(str(body.get('scan_target_id', '')), 64)
    tool = _sanitize_str(str(body.get('tool', 'nuclei')), 32) or 'nuclei'
    is_host = (tool != 'all') and tool in HOST_SCAN_TOOLS
    if is_host:
        profile = 'host'
    else:
        profile = _sanitize_str(str(body.get('profile', 'passive')), 32) or 'passive'
        if profile not in SCAN_PROFILES:
            respond(400, {'error': f'unsupported profile (supported: {", ".join(SCAN_PROFILES)})'})
        if tool != 'all' and tool not in (SCAN_ACTIVE_TOOLS if profile == 'active' else SCAN_TOOLS):
            respond(400, {'error': f'tool {tool!r} not available in the {profile} profile'})
    intensity = _sanitize_str(str(body.get('intensity', 'quick')), 16) or 'quick'
    if intensity not in SCAN_INTENSITIES:
        respond(400, {'error': f'unsupported intensity (supported: {", ".join(SCAN_INTENSITIES)})'})
    cron = _sanitize_str(str(body.get('cron', '')), 64)
    if len(cron.split()) != 5 or _cron_next(cron, int(time.time())) is None:
        respond(400, {'error': 'cron must be a valid 5-field expression that fires within ~45 days'})
    if dev_id:
        actor = require_perm('scan', [dev_id])
        if not isinstance(load(DEVICES_FILE).get(dev_id), dict):
            respond(404, {'error': 'Device not found'})
    elif st_id:
        if is_host:
            respond(400, {'error': 'host-audit tools run on an enrolled host — use device_id'})
        actor = require_perm('scan')
        if _caller_scope() is not None:
            respond(403, {'error': 'scoped roles can only schedule scans on enrolled hosts in their scope'})
        t = (load(SCAN_TARGETS_FILE) or {}).get(st_id)
        if not isinstance(t, dict) or not t.get('verified'):
            respond(400, {'error': 'scan target not found or not ownership-verified'})
    else:
        respond(400, {'error': 'device_id or scan_target_id required'})
    if profile == 'active' and body.get('attestation') is not True:
        respond(403, {'error': 'scheduled active scans require "attestation": true at creation'})
    sat_id = '' if is_host else _sanitize_str(str(body.get('satellite_id', '')), 32)
    if sat_id:
        _sats = load(SATELLITES_FILE) or {}
        if sat_id not in _sats or not _sats[sat_id].get('scanner'):
            respond(400, {'error': 'unknown or non-scanner satellite'})
    scheds = load(SCAN_SCHEDULES_FILE) or {}
    if len(scheds) >= 100:
        respond(400, {'error': 'schedule limit reached (max 100)'})
    now = int(time.time())
    sid = secrets.token_hex(8)
    name = _sanitize_str(str(body.get('name', '')), 80) or f'{tool} {profile}'
    rec = {'id': sid, 'name': name, 'device_id': dev_id, 'scan_target_id': st_id,
           'tool': tool, 'profile': profile, 'intensity': intensity,
           'satellite_id': sat_id, 'cron': cron, 'enabled': True,
           'created': now, 'actor': actor, 'last_run': 0,
           'next_run': _cron_next(cron, now) or 0}
    with _LockedUpdate(SCAN_SCHEDULES_FILE) as st:
        st[sid] = rec
    audit_log(actor, 'scan_schedule_create', f'id={sid} cron={cron!r} tool={tool} profile={profile}')
    respond(201, {'ok': True, 'id': sid, 'schedule': _scan_sched_public(rec)})


def handle_scan_schedule_delete(sid):
    """DELETE /api/scan-schedules/<id> — remove a schedule."""
    if method() != 'DELETE':
        respond(405, {'error': 'Method not allowed'})
    actor = require_perm('scan')
    sid = _sanitize_str(sid, 32)
    deleted = False
    with _LockedUpdate(SCAN_SCHEDULES_FILE) as scheds:
        if sid in scheds:
            if not _scan_sched_in_scope(scheds[sid], _caller_scope()):
                respond(403, {'error': 'This schedule is outside your role scope'})
            del scheds[sid]
            deleted = True
    if deleted:
        audit_log(actor, 'scan_schedule_delete', f'id={sid}')
    respond(200, {'ok': True})


def handle_scan_schedule_run(sid):
    """POST /api/scan-schedules/<id>/run — fire a schedule NOW (test/on-demand
    of a saved schedule), without waiting for its cron. Stamps last_run."""
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    actor = require_perm('scan')
    sid = _sanitize_str(sid, 32)
    sched = (load(SCAN_SCHEDULES_FILE) or {}).get(sid)
    if not isinstance(sched, dict):
        respond(404, {'error': 'schedule not found'})
    if not _scan_sched_in_scope(sched, _caller_scope()):
        respond(403, {'error': 'This schedule is outside your role scope'})
    _create_scheduled_scan(sched)
    with _LockedUpdate(SCAN_SCHEDULES_FILE) as st:
        if sid in st:
            st[sid]['last_run'] = int(time.time())
    audit_log(actor, 'scan_schedule_run_now', f'id={sid}')
    respond(200, {'ok': True})


def handle_scan_schedule_toggle(sid):
    """POST /api/scan-schedules/<id>/toggle — pause/resume a schedule. The
    runner auto-disables a schedule on repeated failures; without this the only
    way back (or to pause one) was delete-and-recreate."""
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    actor = require_perm('scan')
    sid = _sanitize_str(sid, 32)
    new_state = None
    with _LockedUpdate(SCAN_SCHEDULES_FILE) as st:
        sched = st.get(sid)
        if not isinstance(sched, dict):
            respond(404, {'error': 'schedule not found'})
        if not _scan_sched_in_scope(sched, _caller_scope()):
            respond(403, {'error': 'This schedule is outside your role scope'})
        sched['enabled'] = not sched.get('enabled', True)
        if sched['enabled']:
            sched['next_run'] = _cron_next(sched.get('cron', ''), int(time.time())) or 0
        new_state = sched['enabled']
    audit_log(actor, 'scan_schedule_toggle', f'id={sid} enabled={new_state}')
    respond(200, {'ok': True, 'enabled': new_state})


def handle_client_error():
    """v5.4.1 (F4): frontend error beacon. POST {message,source,line,col,stack,url}
    from window.onerror / unhandledrejection so client-side failures are visible to
    operators instead of dying silently in a browser console. IP-rate-limited,
    field-capped, capped ring. GET (admin) lists recent entries for Server Status."""
    if method() == 'GET':
        require_admin_auth()
        store = load(CLIENT_ERRORS_FILE) or {}
        # v5.4.1 (E3): newest-first, through the shared list convention (?q/?sort/
        # ?limit/?offset/?meta). Default cap stays 100 when unpaginated.
        errs = list(reversed(store.get('errors') or []))
        respond(200, _paginate_list(errs) if _env('QUERY_STRING') else {'ok': True, 'errors': errs[:100]})
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    if not _ip_ratelimit('clienterr', _get_client_ip(), 30, window=60):
        respond(429, {'error': 'rate limited'})
    body = get_json_obj()
    def _int(v):
        return v if isinstance(v, int) and 0 <= v < 10_000_000 else 0
    entry = {
        'ts':      int(time.time()),
        'message': _sanitize_str(str(body.get('message', '')), 500),
        'source':  _sanitize_str(str(body.get('source', '')), 300),
        'line':    _int(body.get('line')),
        'col':     _int(body.get('col')),
        'stack':   _sanitize_str(str(body.get('stack', '')), 2000),
        'page':    _sanitize_str(str(body.get('url', '')), 300),
        'ua':      _sanitize_str(_env('HTTP_USER_AGENT', ''), 256),
        'ip':      _get_client_ip(),
    }
    if not entry['message']:
        respond(200, {'ok': True})
    with _LockedUpdate(CLIENT_ERRORS_FILE) as store:
        errs = store.setdefault('errors', [])
        errs.append(entry)
        if len(errs) > MAX_CLIENT_ERRORS:
            del errs[:len(errs) - MAX_CLIENT_ERRORS]
    respond(200, {'ok': True})


def handle_apikeys_list():
    require_admin_auth()
    apikeys = load(APIKEYS_FILE)
    # v6.1.1 (#16): tenant-scope the roster the same way device listings are --
    # a tenant admin sees only their own tenant's keys; a superadmin (or
    # tenancy off) sees everything. A pre-fix key with no stored tenant_id
    # (never rotated since) is treated as DEFAULT_TENANT, matching how
    # _user_tenant's own unset/unknown fallback already behaves.
    gate = _tenant_gate()
    if gate is not None:
        apikeys = {kid: v for kid, v in apikeys.items()
                   if (v.get('tenant_id') or DEFAULT_TENANT) == gate}
    respond(200, _paginate_list([{'id': kid, 'name': v.get('name', ''), 'user': v.get('user', ''),
                   'role': v.get('role', 'admin'), 'created': v.get('created', 0),
                   'active': v.get('active', True),
                   'rate_limit': int(v.get('rate_limit') or 0),
                   'scope': v.get('scope'),            # v5.4.1 (D6): per-key device scope (or null)
                   'ip_allow': v.get('ip_allow'),      # v5.4.1 (D7): per-key source-IP allowlist (or null)
                   'expires_at': v.get('expires_at'),
                   'rotate_after_days': v.get('rotate_after_days'),   # v6.1.1
                   'rotated_from': v.get('rotated_from'),             # v6.1.1
                   'rotated_to': v.get('rotated_to'),                 # v6.1.1
                   'tenant_id': v.get('tenant_id')}                   # v6.1.1 (#16)
                  for kid, v in apikeys.items()]))   # v5.4.1 (E3): list convention


def handle_apikeys_create():
    actor = require_admin_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    name = _sanitize_str(body.get('name', ''), 64)
    role = body.get('role', 'admin')
    user = _sanitize_str(body.get('user', 'api'), 32)
    if not name: respond(400, {'error': 'name required'})
    # v3.1.0: APIKEY_ROLES = {'admin', 'viewer', 'mcp'}. The 'mcp' role
    # grants read-only access PLUS the set of vetted write actions in
    # MCP_ACTION_ALLOWLIST — intended for MCP keys consumed by AI hosts.
    # Until Stage 4 lands those tools the allowlist is empty, so an 'mcp'
    # key behaves like 'viewer' for now.
    if role not in APIKEY_ROLES:
        respond(400, {'error': "role must be 'admin', 'viewer', or 'mcp'"})
    # v5.0.0 (#C4): optional per-key rate limit (requests/minute, 0 = unlimited).
    try:
        rate_limit = int(body.get('rate_limit') or 0)
    except (TypeError, ValueError):
        respond(400, {'error': 'rate_limit must be an integer (requests/minute, 0 = unlimited)'})
    if rate_limit < 0 or rate_limit > 100000:
        respond(400, {'error': 'rate_limit must be 0..100000'})
    key_scope = _validate_key_scope(body.get('scope'))   # v5.4.1 (D6)
    key_ipallow = _validate_ip_allow(body.get('ip_allow'))   # v5.4.1 (D7)
    # v6.1.1: optional rotation-due policy (mirrors the CMDB credential field of
    # the same name) — surfaced as an attention item, never auto-rotated silently.
    try:
        rotate_after_days = int(body.get('rotate_after_days') or 0)
    except (TypeError, ValueError):
        respond(400, {'error': 'rotate_after_days must be an integer'})
    if rotate_after_days < 0 or rotate_after_days > 3650:
        respond(400, {'error': 'rotate_after_days must be 0..3650 (0 = no policy)'})
    apikeys = load(APIKEYS_FILE)
    if len(apikeys) >= 50: respond(400, {'error': 'API key limit reached (max 50)'})
    key_value = secrets.token_urlsafe(40)
    kid       = secrets.token_hex(8)
    expires_at = body.get('expires_at')
    if expires_at is not None:
        try:
            expires_at = int(expires_at)
            if expires_at <= int(time.time()):
                respond(400, {'error': 'expires_at must be in the future'})
        except (ValueError, TypeError):
            respond(400, {'error': 'expires_at must be a unix timestamp'})
    # v4.2.0 (A5): default-expiry policy — if the operator set
    # apikey_default_expiry_days and no explicit expiry was given, apply it so
    # keys aren't created immortal by default.
    if expires_at is None:
        try:
            dd = int(_config_ro().get('apikey_default_expiry_days') or 0)
        except (TypeError, ValueError):
            dd = 0
        if dd > 0:
            expires_at = int(time.time()) + dd * 86400
    # v5.4.1 (C1): store only the SHA-256 hash; the raw key is shown once here and
    # never persisted in cleartext.
    apikeys[kid] = {'name': name, 'key_hash': _apikey_hash(key_value),
                    'user': user, 'role': role,
                    'created': int(time.time()), 'active': True,
                    'rate_limit': rate_limit,
                    'expires_at': expires_at,
                    # v6.1.1 (#16): the key's REAL tenant is the creating admin's own
                    # tenant -- not derived from the free-text `user` display field
                    # above, which doesn't have to correspond to any real account.
                    # See _caller_effective_tenant's docstring for why this matters.
                    'tenant_id': _user_tenant(actor)}
    if key_scope:                                        # v5.4.1 (D6)
        apikeys[kid]['scope'] = key_scope
    if key_ipallow:                                      # v5.4.1 (D7)
        apikeys[kid]['ip_allow'] = key_ipallow
    if rotate_after_days:                                 # v6.1.1
        apikeys[kid]['rotate_after_days'] = rotate_after_days
    save(APIKEYS_FILE, apikeys)
    respond(201, {'ok': True, 'id': kid, 'key': key_value,
                  'note': 'Store this key securely — it will not be shown again.'})


def handle_apikeys_delete(kid):
    require_admin_auth()
    if method() != 'DELETE': respond(405, {'error': 'Method not allowed'})
    if not _validate_id(kid): respond(404, {'error': 'API key not found'})
    apikeys = load(APIKEYS_FILE)
    if kid not in apikeys: respond(404, {'error': 'API key not found'})
    del apikeys[kid]; save(APIKEYS_FILE, apikeys)
    respond(200, {'ok': True})


def handle_apikeys_update(kid):
    """v5.0.1: PATCH /api/apikeys/{kid} — edit a key's metadata in place
    (name / role / rate_limit / expiry). The secret itself is immutable and
    never touched, so consumers keep working — you no longer have to delete +
    regenerate (which mints a new secret and breaks scripts) just to extend an
    expiry or change the rate limit. Only the fields present in the body change."""
    require_admin_auth()
    if method() not in ('PATCH', 'POST'): respond(405, {'error': 'Method not allowed'})
    if not _validate_id(kid): respond(404, {'error': 'API key not found'})
    apikeys = load(APIKEYS_FILE)
    if kid not in apikeys: respond(404, {'error': 'API key not found'})
    body = get_json_obj()
    rec = apikeys[kid]
    if 'name' in body:
        name = _sanitize_str(body.get('name', ''), 64)
        if not name: respond(400, {'error': 'name required'})
        rec['name'] = name
    if 'role' in body:
        role = body.get('role', 'admin')
        if role not in APIKEY_ROLES:
            respond(400, {'error': "role must be 'admin', 'viewer', or 'mcp'"})
        rec['role'] = role
    if 'rate_limit' in body:
        try:
            rate_limit = int(body.get('rate_limit') or 0)
        except (TypeError, ValueError):
            respond(400, {'error': 'rate_limit must be an integer (requests/minute, 0 = unlimited)'})
        if rate_limit < 0 or rate_limit > 100000:
            respond(400, {'error': 'rate_limit must be 0..100000'})
        rec['rate_limit'] = rate_limit
    if 'expires_at' in body:
        expires_at = body.get('expires_at')
        if expires_at in (None, '', 0):
            rec['expires_at'] = None          # clear → never expires
        else:
            try:
                expires_at = int(expires_at)
            except (ValueError, TypeError):
                respond(400, {'error': 'expires_at must be a unix timestamp'})
            if expires_at <= int(time.time()):
                respond(400, {'error': 'expires_at must be in the future'})
            rec['expires_at'] = expires_at
    if 'scope' in body:                                  # v5.4.1 (D6)
        ks = _validate_key_scope(body.get('scope'))
        if ks:
            rec['scope'] = ks
        else:
            rec.pop('scope', None)                       # {type:all}/null clears it
    if 'ip_allow' in body:                               # v5.4.1 (D7)
        ia = _validate_ip_allow(body.get('ip_allow'))
        if ia:
            rec['ip_allow'] = ia
        else:
            rec.pop('ip_allow', None)                    # empty/null clears it
    if 'rotate_after_days' in body:                       # v6.1.1
        try:
            rad = int(body.get('rotate_after_days') or 0)
        except (TypeError, ValueError):
            respond(400, {'error': 'rotate_after_days must be an integer'})
        if rad < 0 or rad > 3650:
            respond(400, {'error': 'rotate_after_days must be 0..3650 (0 = no policy)'})
        if rad:
            rec['rotate_after_days'] = rad
        else:
            rec.pop('rotate_after_days', None)
    save(APIKEYS_FILE, apikeys)
    respond(200, {'ok': True})


def handle_apikeys_rotate(kid):
    """POST /api/apikeys/{kid}/rotate — mint a REPLACEMENT key carrying the same
    name/role/scope/rate_limit/ip_allow/expires_at/rotate_after_days, deactivate
    the old one, and return the new plaintext secret once (same "shown once,
    never persisted" contract as create). v6.1.1: closes gap C9
    (docs/feature-buildout-scoping-internal.md #3) — a guided one-click
    rotation instead of delete+recreate+reconfigure-every-consumer by hand.
    Deliberately does NOT auto-deliver the new secret anywhere (no email/
    webhook of a credential) — the admin doing the rotation sees it, exactly
    like at creation time; that's why this stays a human-triggered action
    (surfaced as an attention item) rather than a silent background job."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    if not _validate_id(kid):
        respond(404, {'error': 'API key not found'})
    new_kid = secrets.token_hex(8)
    key_value = secrets.token_urlsafe(40)
    with _LockedUpdate(APIKEYS_FILE) as apikeys:
        old = apikeys.get(kid)
        if not old:
            respond(404, {'error': 'API key not found'})
        new_rec = {'name': old.get('name', ''), 'key_hash': _apikey_hash(key_value),
                   'user': old.get('user', 'api'), 'role': old.get('role', 'admin'),
                   'created': int(time.time()), 'active': True,
                   'rate_limit': int(old.get('rate_limit') or 0),
                   'expires_at': old.get('expires_at'), 'rotated_from': kid,
                   # v6.1.1 (#16): preserve the ORIGINAL tenant on rotation (a
                   # superadmin rotating a tenant's key on their behalf must not
                   # shift it to the superadmin's own tenant). A pre-fix key with
                   # no stored tenant_id backfills from the rotating actor here --
                   # rotation is a natural, safe point to pick up the fix.
                   'tenant_id': old.get('tenant_id') or _user_tenant(actor)}
        if old.get('scope'):
            new_rec['scope'] = old['scope']
        if old.get('ip_allow'):
            new_rec['ip_allow'] = old['ip_allow']
        if old.get('rotate_after_days'):
            new_rec['rotate_after_days'] = old['rotate_after_days']
        apikeys[new_kid] = new_rec
        old['active'] = False
        old['rotated_to'] = new_kid
        old['rotated_at'] = int(time.time())
    audit_log(actor, 'apikey_rotate', detail=f'{kid} -> {new_kid}')
    respond(201, {'ok': True, 'id': new_kid, 'key': key_value, 'replaced': kid,
                  'note': 'Store this key securely — it will not be shown again. '
                          'The rotated-out key is now inactive.'})


def _longpoll_wait(dev_id, timeout):
    """Block up to `timeout`s for the agent to return this device's queued
    longpoll command output (set by _resolve_longpoll on the next heartbeat).
    Returns ('ok', output_dict) | ('timeout', None) | ('shutdown', None).
    Used by the file manager round-trip (v5.1.0)."""
    import signal as _signal
    _sd = {'flag': False}
    _prev = None
    try:
        _prev = _signal.signal(_signal.SIGTERM, lambda *_a: _sd.__setitem__('flag', True))
    except (ValueError, OSError):
        _prev = None
    try:
        deadline = time.time() + timeout
        while time.time() < deadline:
            if _sd['flag']:
                lp = load(LONGPOLL_FILE); lp.pop(dev_id, None); save(LONGPOLL_FILE, lp)
                return ('shutdown', None)
            time.sleep(1)
            # CRITICAL: the agent's follow-up heartbeat writes `ready:True` from a
            # DIFFERENT process, but load() memoises per request — without busting
            # the cache each poll we'd keep re-reading our own stale `ready:False`
            # snapshot for the whole timeout and ALWAYS report "no response". Drop
            # the cached copy so this read actually re-hits disk / the DB row.
            _invalidate_load_cache(LONGPOLL_FILE)
            slot = load(LONGPOLL_FILE).get(dev_id, {})
            if slot.get('ready'):
                output = slot.get('output', {})
                lp = load(LONGPOLL_FILE); lp.pop(dev_id, None); save(LONGPOLL_FILE, lp)
                return ('ok', output)
        lp = load(LONGPOLL_FILE); lp.pop(dev_id, None); save(LONGPOLL_FILE, lp)
        return ('timeout', None)
    finally:
        if _prev is not None:
            try:
                _signal.signal(_signal.SIGTERM, _prev)
            except (ValueError, OSError):
                pass


def _resolve_longpoll(dev_id, cmd_output):
    lp = load(LONGPOLL_FILE)
    if dev_id in lp:
        lp[dev_id]['output'] = cmd_output
        lp[dev_id]['ready']  = True
        save(LONGPOLL_FILE, lp)


def handle_longpoll_exec():
    actor = require_admin_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    body    = get_json_obj()
    dev_id  = str(body.get('device_id', '')).strip()
    cmd_str = str(body.get('cmd', '')).strip()

    try:
        timeout = int(body.get('timeout', 90))
        timeout = max(10, min(timeout, 120))
    except (ValueError, TypeError):
        timeout = 90

    if not _validate_id(dev_id): respond(404, {'error': 'Device not found'})
    if not cmd_str: respond(400, {'error': 'cmd required'})
    if len(cmd_str) > 512: respond(400, {'error': 'cmd too long'})

    devices = load(DEVICES_FILE)
    if dev_id not in devices: respond(404, {'error': 'Device not found'})

    # Apply the same allowlist check as handle_custom_cmd
    ok, reason = _check_exec_allowlist(dev_id, cmd_str, devices)
    if not ok: respond(403, {'error': reason})

    lp = load(LONGPOLL_FILE)
    lp[dev_id] = {'cmd': cmd_str, 'ready': False, 'output': None, 'ts': int(time.time())}
    save(LONGPOLL_FILE, lp)

    cmds = load(CMDS_FILE)
    if dev_id not in cmds: cmds[dev_id] = []
    cmds[dev_id].append(f'exec:{cmd_str}')
    save(CMDS_FILE, cmds)
    log_command(actor, dev_id, devices[dev_id].get('name', dev_id), f'exec(wait):{cmd_str[:40]}')

    # v5.0.0 (#R4): graceful shutdown. On SIGTERM (controller restart/upgrade)
    # the worker would otherwise kill this child mid-sleep, orphaning the waiting
    # HTTP client. Install a SIGTERM handler that flips a flag so the loop exits
    # cleanly, clears the slot, and returns a "retry" response. signal.signal only
    # works on the main thread — under a threaded worker it raises, so we just
    # skip the graceful path there (the command is already queued either way).
    import signal as _signal
    _shutting_down = {'flag': False}
    _prev_handler = None
    try:
        _prev_handler = _signal.signal(_signal.SIGTERM,
                                       lambda *_a: _shutting_down.__setitem__('flag', True))
    except (ValueError, OSError):
        _prev_handler = None

    def _restore_signal():
        if _prev_handler is not None:
            try:
                _signal.signal(_signal.SIGTERM, _prev_handler)
            except (ValueError, OSError):
                pass

    try:
        deadline = time.time() + timeout
        while time.time() < deadline:
            if _shutting_down['flag']:
                lp = load(LONGPOLL_FILE); lp.pop(dev_id, None); save(LONGPOLL_FILE, lp)
                respond(503, {'ok': False, 'shutdown': True,
                              'message': 'Server is restarting — the command is queued; '
                                         'poll the /output endpoint shortly.'})
            time.sleep(1)
            # Bust the per-request load cache each poll — the agent's follow-up
            # heartbeat writes `ready:True` from another process, which our own
            # memoised snapshot would otherwise never reflect (see _longpoll_wait).
            _invalidate_load_cache(LONGPOLL_FILE)
            lp   = load(LONGPOLL_FILE)
            slot = lp.get(dev_id, {})
            if slot.get('ready'):
                output = slot.get('output', {})
                del lp[dev_id]; save(LONGPOLL_FILE, lp)
                respond(200, {'ok': True, 'output': output})

        lp = load(LONGPOLL_FILE); lp.pop(dev_id, None); save(LONGPOLL_FILE, lp)
        respond(200, {'ok': False, 'timeout': True,
                      'message': 'Output not received within timeout — poll /output endpoint'})
    finally:
        _restore_signal()


def handle_digest():
    require_auth()
    devices = load(DEVICES_FILE); now = int(time.time())
    online  = sum(1 for d in devices.values() if (now - d.get('last_seen', 0)) < get_online_ttl())
    patches = sum(
        (d.get('sysinfo', {}).get('packages', {}).get('upgradable') or 0)
        for d in devices.values()
        if isinstance(d.get('sysinfo', {}).get('packages', {}).get('upgradable'), int)
    )
    recent_cmds = load(HISTORY_FILE).get('entries', [])[-10:]
    respond(200, {
        'ts': now, 'total': len(devices), 'online': online,
        'offline': len(devices) - online, 'pending_patches': patches,
        'recent_commands': recent_cmds,
    })


# ── Patch report ─────────────────────────────────────────────────────────────
def _cve_fixable_by_device():
    """v3.4.1: per-device count of outstanding critical/high CVE findings that
    carry a known fixed version — i.e. CVEs a pending patch would resolve.

    Powers the Patches↔CVE cross-link. The scanner already suppresses findings
    whose installed version is past the fix, so a remaining finding with a
    fixed_version is genuinely 'patch this to clear it'. Honours CVE ignores."""
    findings_all = load(CVE_FINDINGS_FILE) or {}
    ignore_data  = load(CVE_IGNORE_FILE) or {}
    out = {}
    for dev_id, entry in findings_all.items():
        n = 0
        for f in (entry or {}).get('findings') or []:
            if str(f.get('severity', '')).lower() not in ('critical', 'high'):
                continue
            if not f.get('fixed_version'):
                continue
            vid = f.get('vuln_id')
            ig = ignore_data.get(vid) if vid else None
            if ig and ig.get('scope') in ('global', dev_id):
                continue
            n += 1
        if n:
            out[dev_id] = n
    return out


def _inventory_version_match(installed, op, target, eco):
    """Best-effort version comparison for inventory search. Uses dpkg ordering
    for Debian/Ubuntu when the binary is present, else the CVE scanner's tuple
    comparator (unlike CVE suppression, which fail-safe *keeps* findings, here
    an unparseable version is shown rather than silently hidden). `op` ∈
    lt|le|eq|ge|gt; unknown ops / blank target match everything."""
    if not target or op == 'any':
        return True

    def _ge(a, b):
        """a >= b, or None if genuinely uncomparable."""
        try:
            is_deb = eco == 'Ubuntu' or (eco or '').startswith('Debian')
            if is_deb:
                try:
                    return cve_scanner._dpkg_ge(a, b)
                except Exception:
                    return cve_scanner._tuple_ge(a, b)
            return cve_scanner._tuple_ge(a, b)
        except Exception:
            return None

    ge_it = _ge(installed, target)   # installed >= target
    ge_ti = _ge(target, installed)   # target >= installed
    if ge_it is None or ge_ti is None:
        return True                  # uncomparable → don't hide it
    if op == 'lt':  return not ge_it
    if op == 'le':  return ge_ti
    if op == 'ge':  return ge_it
    if op == 'gt':  return not ge_ti
    if op == 'eq':  return ge_it and ge_ti
    return True


def _meter_needles(m):
    """All lower-cased match strings for a meter: its name plus any aliases
    (v3.4.2 normalization — map name variations onto one catalog entry, e.g.
    'openssl' also matching 'libssl3' / 'openssl-libs')."""
    needles = [(m.get('name') or '').strip().lower()]
    for a in (m.get('aliases') or [])[:20]:
        a = str(a).strip().lower()
        if a:
            needles.append(a)
    return [n for n in needles if n]


def _software_in_use(dev, needles):
    """Heuristic: is any of the meter's software actively in use on this device?
    True if a needle appears in a running process name or a listening-port
    process. Used to flag reclamation candidates (installed but idle)."""
    sysinfo = dev.get('sysinfo') or {}
    for p in (sysinfo.get('top_processes') or []):
        nm = (p.get('name') or '').lower()
        if any(n in nm for n in needles):
            return True
    for lp in (sysinfo.get('listening_ports') or []):
        nm = (lp.get('process') or '').lower()
        if any(n in nm for n in needles):
            return True
    return False


def handle_inventory_metering():
    """GET /api/inventory/metering — installed count vs allowance for tracked
    software (config `software_meters`: [{name, limit, aliases?}]); flags
    over-deployment. Matches package names (substring, plus normalization
    aliases) in the collected inventory, and flags reclamation candidates —
    hosts where the software is installed but not seen running. Auth:
    require_auth."""
    require_auth()
    meters = (load(CONFIG_FILE) or {}).get('software_meters') or []
    store = load(PACKAGES_FILE) or {}
    devices = load(DEVICES_FILE) or {}
    devices = _scope_filter_devices(devices)  # v3.5.0 RBAC v2
    out = []
    for m in meters[:100]:
        raw = (m.get('name') or '').strip()
        if not raw:
            continue
        needles = _meter_needles(m)
        try:
            limit = int(m.get('limit') or 0)
        except (TypeError, ValueError):
            limit = 0
        hosts = []
        reclaimable = []
        for did, entry in store.items():
            if did not in devices:
                continue   # v3.5.0 RBAC v2: out of caller scope
            if not any(any(n in (p.get('name') or '').lower() for n in needles)
                       for p in (entry or {}).get('packages') or []):
                continue
            dev = devices.get(did) or {}
            label = dev.get('name', did)
            hosts.append(label)
            # Reclamation: installed but not seen running. Only judge it when we
            # actually have process/port telemetry, else it's not a candidate.
            sysinfo = dev.get('sysinfo') or {}
            if (sysinfo.get('top_processes') or sysinfo.get('listening_ports')) \
                    and not _software_in_use(dev, needles):
                reclaimable.append(label)
        cnt = len(hosts)
        out.append({'name': raw, 'limit': limit, 'installed': cnt,
                    'over': bool(limit and cnt > limit),
                    'aliases': [a for a in (m.get('aliases') or []) if str(a).strip()][:20],
                    'reclaimable': len(reclaimable),
                    'reclaim_hosts': sorted(reclaimable)[:60],
                    'devices': sorted(hosts)[:60]})
    out.sort(key=lambda r: (not r['over'], -r['installed']))
    respond(200, {'meters': out})


def handle_fleet_query():
    """GET /api/fleet/query — filter devices by ad-hoc criteria over the JSON
    stores. All params are ANDed:
      group, tag, os (substr), version (agent, substr), pkg_manager (substr),
      has_package (substr of an installed package name),
      online=1|0, monitored=1|0, agentless=1|0, quarantined=1|0,
      reboot=1 (reboot-required), failed=1 (failed systemd units),
      tp_pending=1 (flatpak/snap/pip/npm updates), kernel_outdated=1,
      pending_gt=<n>, cve_min=<n> (critical+high),
      disk_gt=<pct> (busiest mount), mem_gt=<pct>, offline_days=<n>,
      integrity=verified|mismatch|unknown.
      v4.1.0: cpu_gt=<pct>, swap_gt=<pct>, load_gt=<float> (1-min loadavg),
      kernel=<substr>, platform=<substr>, drift=1 (config drift present),
      mount_issue=1, port_world=1 (a world-exposed listening port),
      storage_degraded=1 (a pool/array not in a healthy state),
      uptime_gt=<days>, uptime_lt=<days> (from last_boot),
      cores_gt=<n>, cores_lt=<n> (cpu_count),
      container_stopped=1, container_restarting=1, timer_failed=1,
      brute_force=1 (active brute-force), smart_failure=1 (a disk SMART-failed),
      ups_on_battery=1.
      format=csv|xml downloads the filtered set (JSON otherwise; the print/PDF
      view fetches the JSON). Auth: require_auth (scoped to the caller's devices)."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    def q(k):
        return (qs.get(k) or [''])[0].strip()
    def qi(k):
        try:
            return int(q(k)) if q(k) else None
        except ValueError:
            return None
    def qbool(k):
        v = q(k).lower()
        return True if v in ('1', 'true') else False if v in ('0', 'false') else None
    def qf(k):
        try:
            return float(q(k)) if q(k) else None
        except ValueError:
            return None
    group, tag, os_q = q('group'), q('tag').lower(), q('os').lower()
    version_q, pkgmgr_q, has_pkg = q('version').lower(), q('pkg_manager').lower(), q('has_package').lower()
    online_q, integ = q('online'), q('integrity')
    monitored_q, agentless_q, quar_q = qbool('monitored'), qbool('agentless'), qbool('quarantined')
    reboot_q = q('reboot') in ('1', 'true')
    failed_q = q('failed') in ('1', 'true')
    tp_q = q('tp_pending') in ('1', 'true')
    kernel_q = q('kernel_outdated') in ('1', 'true')
    pending_gt, cve_min = qi('pending_gt'), qi('cve_min')
    disk_gt, mem_gt, offline_days = qi('disk_gt'), qi('mem_gt'), qi('offline_days')
    # v4.1.0: more resource + posture + identity filters.
    cpu_gt, swap_gt = qi('cpu_gt'), qi('swap_gt')
    load_gt = qf('load_gt')
    inode_gt, fd_gt, conntrack_gt = qi('inode_gt'), qi('fd_gt'), qi('conntrack_gt')
    kernel_sub, platform_sub = q('kernel').lower(), q('platform').lower()
    drift_q = q('drift') in ('1', 'true')
    mount_q = q('mount_issue') in ('1', 'true')
    portworld_q = q('port_world') in ('1', 'true')
    storage_q = q('storage_degraded') in ('1', 'true')
    clock_q = q('clock_skew') in ('1', 'true')
    gw_q = q('gateway_unreachable') in ('1', 'true')
    oom_q = q('oom_recent') in ('1', 'true')
    _STORAGE_OK = {'online', 'active', 'clean', 'healthy', 'ok'}
    # v4.1.0: uptime (days, from last_boot), core count, container state, timers.
    uptime_gt, uptime_lt = qf('uptime_gt'), qf('uptime_lt')
    cores_gt, cores_lt = qi('cores_gt'), qi('cores_lt')
    cstopped_q = q('container_stopped') in ('1', 'true')
    crestart_q = q('container_restarting') in ('1', 'true')
    timer_q = q('timer_failed') in ('1', 'true')
    cstore = (load(CONTAINERS_FILE) or {}) if (cstopped_q or crestart_q) else {}
    # v4.1.0: security/hardware posture (separate stores, loaded only when used).
    brute_q = q('brute_force') in ('1', 'true')
    smart_q = q('smart_failure') in ('1', 'true')
    ups_q = q('ups_on_battery') in ('1', 'true')
    temp_q = q('temp_high') in ('1', 'true')
    fmt = q('format').lower()   # '', 'csv', 'xml' — JSON when empty
    now = int(time.time())
    ttl = get_online_ttl()
    devices = load(DEVICES_FILE) or {}
    devices = _scope_filter_devices(devices)  # v3.5.0 RBAC v2
    canonical = _get_agent_sha256() if integ else None
    pkg_store = (load(PACKAGES_FILE) or {}) if has_pkg else {}
    cve = None
    if cve_min is not None:
        cve = {}
        for did, rec in (load(CVE_FINDINGS_FILE) or {}).items():
            cve[did] = sum(1 for f in (rec or {}).get('findings') or []
                           if str(f.get('severity', '')).lower() in ('critical', 'high'))
    # v4.1.0: hardware posture (SMART/UPS flags) + active brute-force set.
    hw_store = (load(HARDWARE_FILE) or {}) if (smart_q or ups_q or temp_q) else {}
    brute_active = set()
    if brute_q and backend_exists(BRUTE_FORCE_FILE):
        try:
            _bf_en, _bf_thresh, _bf_win = _brute_config()
            if _bf_en:
                _cut = now - _bf_win
                for _bdid, _units in (load(BRUTE_FORCE_FILE) or {}).items():
                    if any(len([t for t in (_ts or []) if t >= _cut]) > _bf_thresh
                           for _ips in (_units or {}).values()
                           for _ts in (_ips or {}).values()):
                        brute_active.add(_bdid)
        except Exception:
            pass
    # v4.6.0 (BUGFIX): the kernel_outdated flag is NOT persisted into sysinfo —
    # it lives in the hardware record as kernel.reboot_for_kernel. Load the
    # store once (only when the filter is active) so the lookup stays O(1).
    _kernel_hw = (load(HARDWARE_FILE) or {}) if kernel_q else {}
    rows = []
    for did, d in devices.items():
        if not isinstance(d, dict):
            continue
        si = d.get('sysinfo') or {}
        pkg = si.get('packages') or {}
        if group and d.get('group') != group:
            continue
        if tag and tag not in [t.lower() for t in (d.get('tags') or [])]:
            continue
        if os_q and os_q not in (d.get('os') or '').lower():
            continue
        if version_q and version_q not in (d.get('version') or '').lower():
            continue
        if pkgmgr_q and pkgmgr_q not in (pkg.get('manager') or '').lower():
            continue
        online = (now - d.get('last_seen', 0)) < ttl
        if online_q in ('1', 'true') and not online:
            continue
        if online_q in ('0', 'false') and online:
            continue
        if monitored_q is True and d.get('monitored') is False:
            continue
        if monitored_q is False and d.get('monitored') is not False:
            continue
        if agentless_q is True and not d.get('agentless'):
            continue
        if agentless_q is False and d.get('agentless'):
            continue
        if quar_q is True and not d.get('quarantined'):
            continue
        if quar_q is False and d.get('quarantined'):
            continue
        if reboot_q and not si.get('reboot_required'):
            continue
        if failed_q and not (si.get('failed_units') or []):
            continue
        if kernel_q and not (((_kernel_hw.get(did) or {}).get('kernel') or {}).get('reboot_for_kernel')):
            continue
        pend = pkg.get('upgradable')
        if pending_gt is not None and not (isinstance(pend, int) and pend > pending_gt):
            continue
        if tp_q:
            tp = pkg.get('third_party') or {}
            if not any((v or {}).get('count') for v in tp.values()):
                continue
        if disk_gt is not None:
            busiest = max((m.get('percent', 0) for m in (si.get('mounts') or [])), default=None)
            if not (isinstance(busiest, (int, float)) and busiest > disk_gt):
                continue
        if mem_gt is not None:
            mp = si.get('mem_percent')
            if not (isinstance(mp, (int, float)) and mp > mem_gt):
                continue
        if offline_days is not None:
            ls = d.get('last_seen', 0)
            if not (ls and (now - ls) / 86400 > offline_days):
                continue
        # v4.1.0: resource thresholds (cpu/swap percent, 1-min loadavg).
        if cpu_gt is not None:
            cp = si.get('cpu_percent')
            if not (isinstance(cp, (int, float)) and cp > cpu_gt):
                continue
        if swap_gt is not None:
            sp = si.get('swap_percent')
            if not (isinstance(sp, (int, float)) and sp > swap_gt):
                continue
        if load_gt is not None:
            la = si.get('loadavg_1m')
            if not (isinstance(la, (int, float)) and la > load_gt):
                continue
        if inode_gt is not None:
            busiest_i = max((m.get('inode_percent', 0) for m in (si.get('mounts') or [])
                             if isinstance(m.get('inode_percent'), (int, float))), default=None)
            if not (isinstance(busiest_i, (int, float)) and busiest_i > inode_gt):
                continue
        if fd_gt is not None:
            v = si.get('fd_percent')
            if not (isinstance(v, (int, float)) and v > fd_gt):
                continue
        if conntrack_gt is not None:
            v = si.get('conntrack_percent')
            if not (isinstance(v, (int, float)) and v > conntrack_gt):
                continue
        # v4.1.0: identity substrings (kernel release, platform/distro).
        if kernel_sub and kernel_sub not in (si.get('kernel') or '').lower():
            continue
        if platform_sub and platform_sub not in (si.get('platform') or '').lower():
            continue
        # v4.1.0: posture flags.
        if drift_q:
            ds = d.get('drift_state') or {}
            if not any(isinstance(s, dict) and s.get('status') == 'drifted'
                       and not s.get('ignored') for s in ds.values()):
                continue
        if mount_q and not (si.get('mount_issues') or []):
            continue
        if clock_q and not (si.get('clock') or {}).get('skewed'):
            continue
        if gw_q and (si.get('gateway') or {}).get('reachable', True):
            continue   # keep only hosts whose gateway is NOT reachable
        if oom_q:
            lt = si.get('last_oom_ts')
            if not (isinstance(lt, (int, float)) and (now - lt) < 86400):
                continue
        if portworld_q:
            if not any((p or {}).get('scope') == 'world'
                       for p in (si.get('listening_ports') or [])):
                continue
        if storage_q:
            pools = si.get('storage_health') or []
            if not any(isinstance(p, dict) and (p.get('state') or '')
                       and (p.get('state') or '').lower() not in _STORAGE_OK
                       for p in pools):
                continue
        # v4.1.0: core count.
        if cores_gt is not None:
            cc = si.get('cpu_count')
            if not (isinstance(cc, int) and cc > cores_gt):
                continue
        if cores_lt is not None:
            cc = si.get('cpu_count')
            if not (isinstance(cc, int) and cc < cores_lt):
                continue
        # v4.1.0: uptime in days, from last_boot (None if the host never reported it).
        if uptime_gt is not None or uptime_lt is not None:
            lb = si.get('last_boot')
            up_days = ((now - lb) / 86400.0) if isinstance(lb, (int, float)) and lb else None
            if uptime_gt is not None and not (up_days is not None and up_days > uptime_gt):
                continue
            if uptime_lt is not None and not (up_days is not None and up_days < uptime_lt):
                continue
        # v4.1.0: a failed systemd timer.
        if timer_q and not any(isinstance(t, dict) and t.get('failed')
                               for t in (si.get('timers') or [])):
            continue
        # v4.1.0: container state (stopped / restarting), from the containers store.
        if cstopped_q or crestart_q:
            entry = cstore.get(did) if isinstance(cstore, dict) else None
            summ = (containers_mod.summarise((entry or {}).get('items') or [])
                    if isinstance(entry, dict) else {})
            if cstopped_q and not (summ.get('stopped') or 0):
                continue
            if crestart_q and not (summ.get('restarting') or 0):
                continue
        # v4.1.0: security/hardware posture flags.
        if brute_q and did not in brute_active:
            continue
        if smart_q and not (hw_store.get(did) or {}).get('_smart_failed'):
            continue
        if ups_q and not (hw_store.get(did) or {}).get('_ups_on_battery'):
            continue
        if temp_q and not (hw_store.get(did) or {}).get('_temp_high'):
            continue
        matched_pkg = None
        if has_pkg:
            installed = (pkg_store.get(did) or {}).get('packages') or []
            hits = [p for p in installed if has_pkg in (p.get('name') or '').lower()]
            if not hits:
                continue
            # v3.13.0: surface the matched package name + INSTALLED VERSION so a
            # "has package X" query answers "which version" without a second look.
            matched_pkg = ', '.join(
                f"{p.get('name')} {p.get('version', '')}".strip() for p in hits[:3])
            if len(hits) > 3:
                matched_pkg += f' +{len(hits) - 3} more'
        if integ and _agent_integrity_status(d, canonical, SERVER_VERSION) != integ:
            continue
        if cve_min is not None and (cve.get(did, 0) < cve_min):
            continue
        _cpu = si.get('cpu_percent')
        _mem = si.get('mem_percent')
        rows.append({'device_id': did, 'name': d.get('name', did),
                     'group': d.get('group', ''), 'os': d.get('os', ''),
                     'version': d.get('version', ''),
                     'online': online,
                     'pending': pend if isinstance(pend, int) else None,
                     'pkg_match': matched_pkg,
                     # v4.1.0: surface the live resource values too.
                     'cpu': _cpu if isinstance(_cpu, (int, float)) else None,
                     'mem': _mem if isinstance(_mem, (int, float)) else None,
                     'cve_high': cve.get(did, 0) if cve is not None else None})
    rows.sort(key=lambda r: r['name'].lower())
    # v4.1.0: CSV / XML export of the filtered set (honours every filter above).
    # PDF is produced client-side via the standalone print page (fleet-query.html),
    # which fetches this same endpoint as JSON — so the strict CSP isn't broken.
    if fmt in ('csv', 'xml'):
        _fleet_query_export(rows, fmt)
    respond(200, {'total': len(rows), 'devices': rows})


def _fleet_query_bytes(rows, fmt):
    """Render fleet-query rows as CSV or XML bytes. Pure (unit-testable);
    returns (data, content_type, filename)."""
    cols = [('name', 'Device'), ('group', 'Group'), ('os', 'OS'),
            ('version', 'Agent'), ('online', 'Online'), ('pending', 'Pending'),
            ('cpu', 'CPU%'), ('mem', 'Mem%'), ('cve_high', 'CVE'),
            ('pkg_match', 'Matched package')]
    ts = time.strftime('%Y%m%d-%H%M%S')
    if fmt == 'csv':
        import csv as _csv
        import io as _io
        buf = _io.StringIO()
        w = _csv.writer(buf)
        w.writerow([label for _k, label in cols])
        for r in rows:
            w.writerow([_csv_safe('yes' if r.get('online') else 'no') if k == 'online'
                        else _csv_safe(r.get(k) if r.get(k) is not None else '')
                        for k, _label in cols])
        return buf.getvalue().encode(), 'text/csv', f'fleet-query-{ts}.csv'
    from xml.etree.ElementTree import Element, SubElement, tostring
    root = Element('FleetQuery')
    root.set('generated', time.strftime('%Y-%m-%dT%H:%M:%S', time.localtime()))
    root.set('serverVersion', SERVER_VERSION)
    root.set('total', str(len(rows)))
    devs = SubElement(root, 'Devices')
    for r in rows:
        de = SubElement(devs, 'Device')
        de.set('id', str(r.get('device_id', '')))
        SubElement(de, 'Name').text = str(r.get('name', ''))
        SubElement(de, 'Group').text = str(r.get('group', ''))
        SubElement(de, 'OS').text = str(r.get('os', ''))
        SubElement(de, 'Agent').text = str(r.get('version', ''))
        SubElement(de, 'Online').text = 'true' if r.get('online') else 'false'
        for k in ('pending', 'cpu', 'mem', 'cve_high'):
            if r.get(k) is not None:
                SubElement(de, k).text = str(r.get(k))
        if r.get('pkg_match'):
            SubElement(de, 'MatchedPackage').text = str(r.get('pkg_match'))
    data = ('<?xml version="1.0" encoding="UTF-8"?>\n'
            + tostring(root, encoding='unicode')).encode('utf-8')
    return data, 'application/xml', f'fleet-query-{ts}.xml'


def _fleet_query_export(rows, fmt):
    """Stream the fleet-query result set as CSV or XML (mirrors the patch-report
    export). Exits via sys.exit after writing — never returns."""
    data, ctype, fname = _fleet_query_bytes(rows, fmt)
    print("Status: 200 OK")
    print(f"Content-Type: {ctype}")
    print(f"Content-Disposition: attachment; filename={fname}")
    print(f"Content-Length: {len(data)}")
    print("Cache-Control: no-store")
    print("X-Content-Type-Options: nosniff")
    print()
    sys.stdout.flush()
    sys.stdout.buffer.write(data)
    sys.stdout.buffer.flush()
    sys.exit(0)


def handle_patch_catalog():
    """GET /api/patch-catalog — fleet-wide pending updates aggregated BY PACKAGE.

    The Patches page is device-centric ("host X has N pending"); this is the
    inverse view ops act on for a rollout: "package P is pending on N hosts, and
    here they are". Built from the agent-reported upgradable package names.
    Devices on an older agent (count but no names) are reported separately so the
    view is honest about coverage. Auth: require_auth."""
    require_auth()
    devices = load(DEVICES_FILE) or {}
    devices = _scope_filter_devices(devices)  # v3.5.0 RBAC v2
    cve_fixable = _cve_fixable_by_device()
    catalog = {}          # package -> set(device_name)
    no_detail = []        # devices with a pending count but no name list
    cve_hosts = 0
    # v3.4.2: aggregate third-party (flatpak/snap/pip/npm) updates by manager.
    third_party = {}   # manager -> {'hosts': set, 'packages': {pkg: set(host)}}
    for dev_id, dev in devices.items():
        # Patch INVENTORY — include unmonitored hosts (the device-level Patches
        # table flags them with a 'silent' badge off the row's `monitored` field);
        # only alerting is gated.
        if not isinstance(dev, dict):
            continue
        pkg = (dev.get('sysinfo') or {}).get('packages') or {}
        names = pkg.get('upgradable_names')
        nm = dev.get('name', dev_id)
        if isinstance(names, list) and names:
            for n in names:
                catalog.setdefault(n, set()).add(nm)
        elif isinstance(pkg.get('upgradable'), int) and pkg['upgradable'] > 0:
            no_detail.append(nm)
        tp = pkg.get('third_party')
        if isinstance(tp, dict):
            for mgr, ent in tp.items():
                if not isinstance(ent, dict) or not ent.get('count'):
                    continue
                slot = third_party.setdefault(mgr, {'hosts': set(), 'packages': {}})
                slot['hosts'].add(nm)
                for pn in (ent.get('names') or []):
                    slot['packages'].setdefault(pn, set()).add(nm)
        if cve_fixable.get(dev_id):
            cve_hosts += 1
    rows = [{'package': n, 'count': len(hosts), 'devices': sorted(hosts)[:60]}
            for n, hosts in catalog.items()]
    rows.sort(key=lambda r: (-r['count'], r['package'].lower()))
    tp_out = []
    for mgr, slot in sorted(third_party.items()):
        pkgs = sorted(({'package': p, 'count': len(h)} for p, h in slot['packages'].items()),
                      key=lambda r: (-r['count'], r['package'].lower()))[:50]
        tp_out.append({'manager': mgr, 'hosts': len(slot['hosts']), 'packages': pkgs})
    respond(200, {
        'generated_ts':          int(time.time()),
        'packages':              rows,
        'total_packages':        len(rows),
        'devices_without_detail': sorted(no_detail),
        'cve_fixable_hosts':     cve_hosts,
        'third_party':           tp_out,
    })


# ─────────────────────────────────────────────────────────────────────────────
# v3.4.2: staged / ring rollouts (canary → pilot → broad)
# ─────────────────────────────────────────────────────────────────────────────
# A rollout pushes ONE action (an OS package upgrade, or a saved script) to the
# fleet in ordered RINGS. Ring N is dispatched, its devices are watched until
# they verify, and only then is ring N+1 released — manually, or automatically
# when auto_promote is set. This is the orchestration layer over the existing
# command queue + the v3.4.2 post-deploy verification (`_upgrade_verify_status`).
#
# No new webhook events: state changes land on the rollout's own history + the
# audit log, and the dedicated Rollouts page polls for progress. Advancement is
# driven by `_rollout_tick()` from the cheap-when-not-due periodic block, and
# lazily on GET so the UI always sees fresh state. Storage (rollouts.json):
#   {'rollouts': [ {id, name, action, rings:[...], rings_state:[...], state, ...} ]}
_ROLLOUT_VERIFY_MIN_DEFAULT = 30      # minutes to allow a ring to verify
_ROLLOUT_VERIFY_MIN_MAX     = 1440
_ROLLOUT_TICK_INTERVAL      = 20      # seconds between periodic advances
_last_rollout_tick          = [0.0]




























# ─────────────────────────────────────────────────────────────────────────────
# v3.4.2: CIS-style compliance baselines
# ─────────────────────────────────────────────────────────────────────────────
# A named baseline is a set of pass/fail CHECKS evaluated against each device's
# reported sysinfo (+ CVE / agent-integrity data). Each check returns True
# (pass), False (fail), or None (not applicable / no data). The fleet compliance
# score is the severity-weighted pass ratio over applicable checks. A daily
# sample feeds a trend sparkline. Disabled checks live in config
# (`compliance_baseline.disabled`). No agent change — checks reuse existing data.
_CIS_SEVERITY_WEIGHT = {'high': 5, 'medium': 3, 'low': 1}


def _cis_checks():
    """The built-in Linux baseline. Each entry: (id, title, severity, fn) where
    fn(ctx) -> True|False|None. ctx carries the device + precomputed facts."""
    def _patches(ctx):
        pend = ((ctx['sysinfo'].get('packages')) or {}).get('upgradable')
        return None if not isinstance(pend, int) else pend == 0
    def _reboot(ctx):
        si = ctx['sysinfo']
        return None if 'reboot_required' not in si else not si.get('reboot_required')
    def _failed_units(ctx):
        fu = ctx['sysinfo'].get('failed_units')
        return None if fu is None else len(fu) == 0
    def _disk(ctx):
        d = ctx['sysinfo'].get('disk_percent')
        return None if not isinstance(d, (int, float)) else d < 90
    def _swap(ctx):
        s = ctx['sysinfo'].get('swap_percent')
        return None if not isinstance(s, (int, float)) else s < 80
    def _cve(ctx):
        return ctx['cve_high'] == 0 if ctx['cve_high'] is not None else None
    def _integrity(ctx):
        st = ctx['integrity']
        return None if st in (None, 'unknown', 'na') else st == 'verified'
    return [
        ('cis-patches',   'No pending package updates',          'high',   _patches),
        ('cis-reboot',    'No pending reboot',                   'medium', _reboot),
        ('cis-failed',    'No failed systemd units',             'medium', _failed_units),
        ('cis-disk',      'Root filesystem under 90% used',      'high',   _disk),
        ('cis-swap',      'Swap usage under 80%',                'low',    _swap),
        ('cis-cve',       'No critical/high CVEs',               'high',   _cve),
        ('cis-integrity', 'Agent binary matches signed build',  'medium', _integrity),
    ]


def _cis_disabled():
    cb = (load(CONFIG_FILE) or {}).get('compliance_baseline') or {}
    return set(cb.get('disabled') or [])


# v3.14.0 #31: one-click remediation for the telemetry-derived CIS checks. Only
# checks with a clean, well-supported fix are remediable; the rest stay advisory
# (auto-fixing a full disk or high swap is host-specific and risky). EVERY
# remediation is queued through _queue_command, so per-device quarantine, 4-eyes
# approval (reboot), the queue cap, and audit all apply — and the handler only
# runs it on a device whose operator has set remediation_enabled (explicit
# per-host opt-in, default off).
def _cis_remediation(check_id, dev):
    """Return {label, command} for a failed check, or None if not remediable."""
    mgr = ((dev.get('sysinfo') or {}).get('packages') or {}).get('manager')
    upgrade = {'apt': 'apt-get -y upgrade', 'dnf': 'dnf upgrade --refresh -y',
               'zypper': 'zypper --non-interactive update'}.get(mgr)
    pkg = {'label': 'Install pending updates',
           'command': f'exec:{upgrade}'} if upgrade else None
    return {
        'cis-reboot':  {'label': 'Reboot host', 'command': 'reboot'},
        'cis-failed':  {'label': 'Clear failed units', 'command': 'exec:systemctl reset-failed'},
        'cis-patches': pkg,
        'cis-cve':     pkg,
    }.get(check_id)


def _cis_remediable_ids(dev):
    """The set of check ids that have an available remediation for this device."""
    return {cid for cid in ('cis-reboot', 'cis-failed', 'cis-patches', 'cis-cve')
            if _cis_remediation(cid, dev)}


def handle_compliance_remediate():
    """POST /api/compliance/remediate {device_id, check_id} — queue the fix for a
    failed CIS check on one device. Admin-only; RBAC-scoped; requires the device
    to have remediation_enabled (per-host opt-in). The fix is queued through
    _queue_command, which applies quarantine + 4-eyes approval (reboot) + audit
    + the command cap, so this inherits every existing safety gate."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    dev_id = _sanitize_str(str(body.get('device_id', '')), 64)
    check_id = _sanitize_str(str(body.get('check_id', '')), 40)
    devices = load(DEVICES_FILE) or {}
    dev = devices.get(dev_id)
    if not dev:
        respond(404, {'error': 'Device not found'})
    if dev_id not in _scope_filter_devices(devices):
        respond(403, {'error': 'Out of scope'})
    if not dev.get('remediation_enabled'):
        respond(403, {'error': 'Automatic remediation is not enabled for this '
                               'device. Turn it on in the device settings first.'})
    rem = _cis_remediation(check_id, dev)
    if not rem:
        respond(400, {'error': 'No automatic remediation is available for this check.'})
    audit_log(actor, 'compliance_remediate',
              f'dev={dev_id} check={check_id} cmd={rem["command"]}')
    # W2-39: a remediation always requires 4-eyes when change-approval is on —
    # a fix mutates a host's hardened state, so it shouldn't slip through just
    # because its command kind isn't in the gated set.
    _queue_command(dev_id, rem['command'], actor, force_approval=True)   # responds + exits


def _compute_compliance(devices=None):
    """Evaluate the active baseline across monitored devices. Returns the full
    report dict (per-check counts, per-device results, fleet score)."""
    devices = devices if devices is not None else (load(DEVICES_FILE) or {})
    disabled = _cis_disabled()
    checks = [c for c in _cis_checks() if c[0] not in disabled]
    canonical = _get_agent_sha256()
    cve_counts = {}
    for did, rec in (load(CVE_FINDINGS_FILE) or {}).items():
        cve_counts[did] = sum(1 for f in (rec or {}).get('findings') or []
                              if str(f.get('severity', '')).lower() in ('critical', 'high'))
    per_check = {cid: {'pass': 0, 'fail': 0, 'na': 0,
                       'title': title, 'severity': sev, 'failing': []}
                 for cid, title, sev, _ in checks}
    dev_results = []
    tot_w = tot_pass_w = 0
    counted_devices = 0
    for did, dev in devices.items():
        if not isinstance(dev, dict) or dev.get('monitored') is False or dev.get('agentless'):
            continue
        sysinfo = dev.get('sysinfo') or {}
        if not sysinfo:
            continue
        counted_devices += 1
        ctx = {'dev': dev, 'sysinfo': sysinfo,
               'cve_high': cve_counts.get(did),
               'integrity': _agent_integrity_status(dev, canonical, SERVER_VERSION)}
        passed = applicable = 0
        fails = []
        for cid, title, sev, fn in checks:
            try:
                res = fn(ctx)
            except Exception:
                res = None
            w = _CIS_SEVERITY_WEIGHT.get(sev, 1)
            if res is None:
                per_check[cid]['na'] += 1
                continue
            applicable += 1
            tot_w += w
            if res:
                per_check[cid]['pass'] += 1
                passed += 1
                tot_pass_w += w
            else:
                per_check[cid]['fail'] += 1
                fails.append(cid)
                if len(per_check[cid]['failing']) < 60:
                    per_check[cid]['failing'].append(dev.get('name', did))
        dev_results.append({
            'device_id': did, 'name': dev.get('name', did),
            'group': dev.get('group', ''),
            'passed': passed, 'applicable': applicable,
            'pct': round(100 * passed / applicable) if applicable else None,
            'fails': fails,
            # v3.14.0 #31: which failing checks can be one-click remediated, and
            # whether this host has opted in to remediation.
            'remediation_enabled': bool(dev.get('remediation_enabled')),
            'remediable': sorted(set(fails) & _cis_remediable_ids(dev)),
        })
    score = round(100 * tot_pass_w / tot_w) if tot_w else None
    dev_results.sort(key=lambda r: (r['pct'] if r['pct'] is not None else 101))
    return {
        'generated_ts': int(time.time()),
        'score': score,
        'devices_evaluated': counted_devices,
        'checks': [{'id': cid, **{k: v for k, v in per_check[cid].items()}}
                   for cid, _, _, _ in checks],
        'devices': dev_results,
    }


def handle_compliance_baseline():
    """GET /api/compliance/baseline — evaluate the active CIS-style baseline."""
    require_auth()
    # v3.5.0 RBAC v2: evaluate only the caller's in-scope devices.
    rep = _compute_compliance(_scope_filter_devices(load(DEVICES_FILE) or {}))
    rep['history'] = ((load(COMPLIANCE_HIST_FILE) or {}).get('fleet') or [])[-90:]
    rep['available_checks'] = [{'id': cid, 'title': t, 'severity': s}
                               for cid, t, s, _ in _cis_checks()]
    rep['disabled'] = sorted(_cis_disabled())
    respond(200, rep)


def _maybe_sample_compliance(now=None):
    """Record at most one fleet compliance-% sample per UTC day (mirrors
    _maybe_sample_health). Best-effort; never raises."""
    now = int(now or time.time())
    import datetime as _dt
    day = _dt.datetime.fromtimestamp(now, _dt.timezone.utc).strftime('%Y-%m-%d')
    # v5.8.0 (PERF): read-only pre-gate before the write lock (see
    # _maybe_sample_health) — avoids a cold-blob rewrite on every request.
    _ch = load(COMPLIANCE_HIST_FILE) or {}
    _cf = _ch.get('fleet') or []
    if _cf and _cf[-1].get('date') == day:
        return
    try:
        with _LockedUpdate(COMPLIANCE_HIST_FILE) as store:
            fleet = store.setdefault('fleet', [])
            if fleet and fleet[-1].get('date') == day:
                return
            score = _compute_compliance().get('score')
            if score is None:
                return
            fleet.append({'date': day, 'ts': now, 'score': score})
            store['fleet'] = fleet[-180:]
    except Exception as e:
        sys.stderr.write(f'[remotepower] compliance sample failed: {e}\n')


# ─────────────────────────────────────────────────────────────────────────────
# v3.4.2: OpenSCAP (oscap) deep compliance scans
# ─────────────────────────────────────────────────────────────────────────────
# The lightweight CIS baseline scores what every heartbeat already reports; this
# is the auditor-grade complement. The operator queues a scan (a profile like
# 'cis' / 'stig' / 'pci-dss'); the agent runs `oscap xccdf eval` against its SSG
# datastream and POSTs a compact result (score, pass/fail tallies, failed rule
# ids). oscap runs on the endpoint, so there is no new server dependency, and it
# degrades gracefully when oscap / SCAP content is absent. Storage (scap.json):
#   {dev_id: {available, profile, score, pass, fail, counts, failed_rules, ts}}
_SCAP_PROFILES = ('cis', 'cis_level1_server', 'cis_level1_workstation',
                  'cis_level2_server', 'cis_level2_workstation', 'stig', 'pci-dss',
                  'anssi_bp28_high', 'standard', 'ospp')


def handle_scap_scan():
    """POST /api/scap/scan — queue an OpenSCAP scan on the target device(s).
    Body: {device_id|device_ids|group|tag, profile}. Sets a one-shot flag the
    agent reads on its next heartbeat. Auth: 'upgrade' permission (a privileged
    fleet action), scoped."""
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    ids = _resolve_targets(body)
    if not ids:
        respond(400, {'error': 'No valid device targets'})
    actor = require_perm('patch', ids)
    profile = _sanitize_str(body.get('profile', 'cis'), 80) or 'cis'
    with _LockedUpdate(DEVICES_FILE) as devices:
        for did in ids:
            dev = devices.get(did)
            if dev:
                dev['force_scap_scan'] = True
                dev['scap_profile'] = profile
    audit_log(actor, 'scap_scan', f'targets={len(ids)} profile={profile}')
    respond(200, {'ok': True, 'queued': len(ids), 'profile': profile})


def handle_scap_report():
    """POST /api/scap/report — agent submits an OpenSCAP scan result.
    Authenticated by device_id + token (like /api/packages)."""
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    dev_id = str(body.get('device_id', '')).strip()
    dev_token = str(body.get('token', '')).strip()
    if not _validate_id(dev_id):
        respond(403, {'error': 'Unauthorized device'})
    devices = load(DEVICES_FILE)
    dev = devices.get(dev_id)
    if not dev or not _device_token_ok(dev, dev_token):
        respond(403, {'error': 'Unauthorized device'})
    rec = {
        'ts': int(time.time()),
        'profile': _sanitize_str(body.get('profile', ''), 80),
        'available': bool(body.get('available')),
        'reason': _sanitize_str(body.get('reason', ''), 200),
        'datastream': _sanitize_str(body.get('datastream', ''), 120),
    }
    # v3.4.2: the profiles this host's datastream actually offers, so the UI can
    # present only the ones that exist for the fleet's OSes (Debian SSG has no
    # cis/pci-dss/ospp — those ship in RHEL's scap-security-guide).
    aprofs = body.get('available_profiles')
    if isinstance(aprofs, list):
        rec['available_profiles'] = [_sanitize_str(str(p), 80) for p in aprofs[:40] if p]
    if rec['available']:
        sc = body.get('score')
        rec['score'] = round(float(sc), 1) if isinstance(sc, (int, float)) else None
        counts = body.get('counts') if isinstance(body.get('counts'), dict) else {}
        rec['counts'] = {k: int(v) for k, v in counts.items()
                         if isinstance(v, int) and 0 <= v <= 100000}
        rec['pass'] = rec['counts'].get('pass', 0)
        rec['fail'] = rec['counts'].get('fail', 0)
        rec['failed_rules'] = []
        for r in (body.get('failed_rules') or [])[:200]:
            if isinstance(r, dict):
                rec['failed_rules'].append({
                    'id': _sanitize_str(r.get('id', ''), 200),
                    'severity': _sanitize_str(r.get('severity', 'unknown'), 16),
                })
    # v3.4.2: store the full HTML report (gzipped, base64 over the wire) so the
    # operator can download it. Kept on disk (one file per device, overwritten by
    # the latest scan), not in scap.json — it's large. Best-effort.
    rec['has_report'] = False
    gz_b64 = body.get('report_html_gz')
    if rec.get('available') and isinstance(gz_b64, str) and gz_b64:
        try:
            import base64 as _b64
            raw_gz = _b64.b64decode(gz_b64, validate=True)
            if 0 < len(raw_gz) <= 30 * 1024 * 1024:
                SCAP_REPORTS_DIR.mkdir(parents=True, exist_ok=True)
                # dev_id is validated [A-Za-z0-9_-]; safe as a filename.
                (SCAP_REPORTS_DIR / f'{dev_id}.html.gz').write_bytes(raw_gz)
                rec['has_report'] = True
                rec['report_ts'] = rec['ts']
                rb = body.get('report_bytes')
                if isinstance(rb, int) and rb > 0:
                    rec['report_bytes'] = rb
        except Exception as e:
            sys.stderr.write(f'[remotepower] scap report store failed {dev_id}: {e}\n')
    with _LockedUpdate(SCAP_FILE) as store:
        store[dev_id] = rec
    respond(200, {'ok': True})


def handle_scap_report_download(dev_id):
    """GET /api/scap/<dev_id>/report — download the full OpenSCAP/usg HTML report
    for one device's latest scan. Auth: require_auth + device scope. Serves the
    stored gzip, decompressed, as text/html."""
    require_auth()
    if not _validate_id(dev_id):
        respond(404, {'error': 'invalid device id'}); return
    _scope_block_device(dev_id)   # v3.5.0 RBAC v2: per-device read scope
    path = SCAP_REPORTS_DIR / f'{dev_id}.html.gz'
    if not path.exists():
        respond(404, {'error': 'no report on file for this device'}); return
    try:
        import gzip as _gz
        html = _gz.decompress(path.read_bytes())
    except Exception as e:
        respond(500, {'error': f'report read failed: {e}'}); return
    devices = load(DEVICES_FILE) or {}
    name = (devices.get(dev_id) or {}).get('name', dev_id)
    safe = re.sub(r'[^A-Za-z0-9_.-]', '_', str(name))
    print("Status: 200 OK")
    print("Content-Type: text/html; charset=utf-8")
    print(f"Content-Length: {len(html)}")
    print(f'Content-Disposition: inline; filename="scap-report-{safe}.html"')
    print("Cache-Control: no-store")
    print("X-Content-Type-Options: nosniff")
    # v3.13.0 hardening: this HTML is supplied verbatim by the (device-token-
    # authenticated) agent. Don't rely solely on the global nginx CSP — emit a
    # self-contained sandboxed CSP so a compromised agent can't land stored XSS
    # in the operator's session even if the upstream policy is ever loosened.
    # OpenSCAP/usg reports are static tables with inline CSS, so they still
    # render; only scripts/forms/same-origin access are neutralised.
    print("Content-Security-Policy: default-src 'none'; img-src 'self' data:; "
          "style-src 'unsafe-inline'; font-src data:; sandbox;")
    print("X-Frame-Options: DENY")
    print()
    sys.stdout.flush()
    sys.stdout.buffer.write(html)
    sys.stdout.buffer.flush()
    sys.exit(0)


def handle_scap_overview():
    """GET /api/scap — latest OpenSCAP result per (in-scope) device + summary."""
    require_auth()
    scope = _caller_scope()
    devices = load(DEVICES_FILE) or {}
    store = load(SCAP_FILE) or {}
    rows = []
    for did, rec in store.items():
        dev = devices.get(did)
        if not dev:
            continue
        if scope is not None and not _device_in_scope(scope, dev):
            continue
        row = {
            'device_id': did, 'name': dev.get('name', did),
            'group': dev.get('group', ''),
            **{k: rec.get(k) for k in ('ts', 'profile', 'available', 'reason',
                                       'score', 'pass', 'fail', 'datastream')},
            'failed_top': (rec.get('failed_rules') or [])[:20],
            'has_report': bool(rec.get('has_report')),
            'report_bytes': rec.get('report_bytes'),
        }
        # Defensive: an older agent reports available=True with score 0 / pass 0 /
        # fail 0 when a profile evaluated no applicable rules (e.g. the Debian SSG
        # 'standard' profile). A 0% there is meaningless — present it as
        # not-applicable so the table doesn't show a scary 0%. Newer agents
        # already send available=False with a reason.
        if row.get('available') and not (row.get('pass') or 0) and not (row.get('fail') or 0):
            row['available'] = False
            row['score'] = None
            row['reason'] = row.get('reason') or (
                f"profile '{row.get('profile') or '?'}' evaluated no applicable rules "
                f"on this host")
        rows.append(row)
    rows.sort(key=lambda r: (r.get('score') if isinstance(r.get('score'), (int, float)) else 999))
    scored = [r['score'] for r in rows if isinstance(r.get('score'), (int, float))]
    # Offer profiles that are actually supported across the (in-scope) fleet:
    # the union of what each host reported its datastream contains. Until any
    # host has reported (first scan), fall back to the built-in superset so the
    # dropdown isn't empty. This stops operators picking pci-dss/cis on a
    # Debian-only fleet where those profiles don't exist.
    supported = set()
    for did, rec in store.items():
        dev = devices.get(did)
        if not dev or (scope is not None and not _device_in_scope(scope, dev)):
            continue
        for p in (rec.get('available_profiles') or []):
            supported.add(p)
    profiles = sorted(supported) if supported else list(_SCAP_PROFILES)
    respond(200, {
        'devices': rows,
        'profiles': profiles,
        'all_profiles': list(_SCAP_PROFILES),
        'avg_score': round(sum(scored) / len(scored), 1) if scored else None,
        'scanned': len(rows),
    })


def handle_inventory_search():
    """GET /api/inventory/search?q=<name>&op=<lt|le|eq|ge|gt|any>&version=<v>&exact=0|1

    Find which hosts have a package — e.g. "which hosts run openssl < 3.0.2".
    Searches the stored package inventory (packages.json). Name match is a
    case-insensitive substring unless ?exact=1. The optional version filter is
    best-effort (per the device's ecosystem). Auth: require_auth."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    q = (qs.get('q') or [''])[0].strip().lower()
    if not q:
        respond(200, {'query': '', 'results': [], 'total': 0, 'truncated': False})
    exact = (qs.get('exact') or ['0'])[0] == '1'
    op = (qs.get('op') or ['any'])[0].strip().lower()
    target = (qs.get('version') or [''])[0].strip()
    store = load(PACKAGES_FILE) or {}
    devices = load(DEVICES_FILE) or {}
    devices = _scope_filter_devices(devices)  # v3.5.0 RBAC v2
    CAP = 2000
    results = []
    truncated = False
    for dev_id, entry in store.items():
        if dev_id not in devices:
            continue   # v3.5.0 RBAC v2: out of caller scope
        eco = (entry or {}).get('ecosystem', '')
        dname = (devices.get(dev_id) or {}).get('name', dev_id)
        for p in (entry or {}).get('packages') or []:
            name = p.get('name') or ''
            nl = name.lower()
            if (nl == q) if exact else (q in nl):
                ver = p.get('version') or ''
                if not _inventory_version_match(ver, op, target, eco):
                    continue
                results.append({'device_id': dev_id, 'device_name': dname,
                                'package': name, 'version': ver})
                if len(results) >= CAP:
                    truncated = True
                    break
        if truncated:
            break
    results.sort(key=lambda r: (r['package'].lower(), r['device_name'].lower()))
    respond(200, {'query': q, 'op': op, 'version': target,
                  'results': results, 'total': len(results),
                  'truncated': truncated})


def handle_inventory_catalog():
    """GET /api/inventory/catalog?q=<substr> — the "software center": every
    installed package across the (in-scope) fleet, aggregated to one row per
    package with the set of installed versions and how many hosts run each.
    Answers "what's installed and which versions" at a glance. Auth: require_auth."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    q = (qs.get('q') or [''])[0].strip().lower()
    store = load(PACKAGES_FILE) or {}
    devices = _scope_filter_devices(load(DEVICES_FILE) or {})
    # package -> {version -> set(device_id)}
    agg = {}
    for dev_id, entry in store.items():
        if dev_id not in devices:
            continue
        for p in (entry or {}).get('packages') or []:
            name = p.get('name') or ''
            if not name or (q and q not in name.lower()):
                continue
            ver = (p.get('version') or '').strip() or '—'
            agg.setdefault(name, {}).setdefault(ver, set()).add(dev_id)
    CAP = 1000
    def _dname(did):
        return (devices.get(did) or {}).get('name', did)
    rows = []
    for name, vers in agg.items():
        hosts = set()
        for s in vers.values():
            hosts |= s
        # versions sorted by host count desc, capped so one row can't explode.
        # host_names answers "WHERE is it installed" (capped per version).
        vlist = sorted(
            ({'version': v, 'hosts': len(s),
              'host_names': sorted(_dname(d) for d in list(s)[:25])}
             for v, s in vers.items()),
            key=lambda x: -x['hosts'])[:8]
        rows.append({'package': name, 'versions': vlist,
                     'version_count': len(vers), 'hosts': len(hosts)})
    truncated = len(rows) > CAP
    # Most-deployed first, then most-version-fragmented (interesting for ops).
    rows.sort(key=lambda r: (-r['hosts'], -r['version_count'], r['package'].lower()))
    respond(200, {'query': q, 'packages': rows[:CAP],
                  'total': len(rows), 'truncated': truncated})


def _upgrade_verify_status(dev, now):
    """v3.4.2: did a queued upgrade actually take? Compares the pending-update
    count snapshotted when the upgrade was queued against the latest count.
    Returns 'ok' (dropped), 'stalled' (unchanged after >1h), 'pending', or None
    (no recent upgrade / nothing to verify). Cleared implicitly once the marker
    ages out (7 days). A fresh package scan (force_package_scan) re-evaluates
    it; the patch report exposes a "Re-check" button that triggers one."""
    qa = dev.get('upgrade_queued_at')
    if not qa or (now - qa) > 7 * 86400:
        return None
    before = dev.get('upgrade_pending_before')
    cur = ((dev.get('sysinfo') or {}).get('packages') or {}).get('upgradable')
    online = (now - (dev.get('last_seen') or 0)) < get_online_ttl()
    aged = (now - qa) > 3600
    # v3.9.0: no usable baseline count from queue time (it was unknown then —
    # the agent hadn't reported a patch count), OR nothing was pending (a
    # fleet-wide upgrade hits already-patched hosts). Either way the before/after
    # comparison can't run, so there's nothing to verify — don't sit on
    # "verifying…" forever (this is what wedged hosts whose count was None).
    if not isinstance(before, int) or before <= 0:
        return None
    # v3.9.0: agent hasn't re-reported a current package count yet. Keep waiting,
    # but if the host has been online for over an hour with still no fresh count,
    # give up quietly rather than hang the badge — a re-scan can be forced.
    if not isinstance(cur, int):
        return None if (online and aged) else 'pending'
    if cur < before:
        return 'ok'
    # v3.9.0: if the host is offline the upgrade command may still be sitting
    # undelivered in its queue, or it simply hasn't re-reported its package
    # count yet. Either way we haven't *heard* that it failed — keep it
    # 'pending' rather than wrongly declaring "didn't take".
    if not online:
        return 'pending'
    if aged:
        return 'stalled'
    return 'pending'


def handle_patch_report():
    """Return detailed patch information across all devices."""
    require_auth()
    devices = load(DEVICES_FILE)
    devices = _scope_filter_devices(devices)  # v3.5.0 RBAC v2
    snmp_data = load(SNMP_DATA_FILE)   # v3.4.0: Synology DSM update status
    cve_fixable = _cve_fixable_by_device()   # v3.4.1: CVE↔patch cross-link
    now = int(time.time())
    report = {
        'generated_at': now,
        'server_version': SERVER_VERSION,
        'devices': [],
        'summary': {
            'total_devices': len(devices),
            'devices_with_patches': 0,
            'devices_fully_patched': 0,
            'devices_no_data': 0,
            'total_pending_patches': 0,
            # v3.4.1: total critical/high CVEs across the fleet that a patch fixes.
            'cve_fixable_total': 0,
        }
    }
    # v6.0.1 perf: hoist the fleet-wide command-output store out of the per-device
    # loop — it was deep-copied once per device (O(N) × whole store).
    all_cmd_outputs = load(CMD_OUTPUT_FILE)
    for dev_id, dev in devices.items():
        si = dev.get('sysinfo', {})
        pkg = si.get('packages', {})
        upgradable = pkg.get('upgradable')
        security_updates = pkg.get('security_updates')   # v5.0.0: distro-flagged
        pkg_manager = pkg.get('manager', 'unknown')
        is_online = (now - dev.get('last_seen', 0)) < get_online_ttl()

        # v3.3.4: RouterOS firmware updates show here too. For a
        # routeros-enabled device with a cached check, derive upgradable
        # from installed-vs-latest so it flows through the same status +
        # summary logic as Linux package updates.
        firmware = None
        ros_cfg = dev.get('routeros') or {}
        ros_upd = dev.get('routeros_update') or {}
        if ros_cfg.get('enabled') and ros_upd.get('installed'):
            inst, latest = ros_upd.get('installed'), ros_upd.get('latest')
            firmware = {'installed': inst, 'latest': latest}
            upgradable = 1 if (latest and inst and latest != inst) else (0 if latest else None)
            pkg_manager = 'routeros'
            if dev.get('agentless'):
                is_online = _agentless_online(dev)

        # v3.4.0: OPNsense firmware/update status shows here too, same as
        # RouterOS. Cached on the device as opnsense_update when the card is
        # viewed or "Check for updates" runs. updates_available (0 = current)
        # is the authoritative count from OPNsense's own status/package lists.
        opn_cfg = dev.get('opnsense') or {}
        opn_upd = dev.get('opnsense_update') or {}
        if opn_cfg.get('enabled') and opn_upd:
            inst, latest = opn_upd.get('installed'), opn_upd.get('latest')
            firmware = {'installed': inst, 'latest': latest}
            ua = opn_upd.get('updates_available')
            upgradable = (ua if isinstance(ua, int)
                          else (1 if (latest and inst and latest != inst)
                                else (0 if inst else None)))
            pkg_manager = 'opnsense'
            if dev.get('agentless'):
                is_online = _agentless_online(dev)

        # v3.4.0: Synology DSM update status. The SNMP poller already reads
        # DSM version + upgradeAvailable (Synology MIB 1.3.6.1.4.1.6574.*)
        # and persists it to snmp_data.json, so we read it straight from
        # there — no live fetch. (Note: the Synology MIB exposes no
        # "reboot required" OID, so reboot status isn't available here.)
        syno_sys = (snmp_data.get(dev_id, {}).get('synology') or {}).get('system') or {}
        if syno_sys.get('dsm_version') or syno_sys.get('upgrade'):
            up = syno_sys.get('upgrade')
            firmware = {'installed': syno_sys.get('dsm_version'), 'latest': None}
            upgradable = (1 if up == 'available'
                          else (0 if up == 'unavailable' else None))
            pkg_manager = 'synology'
            if dev.get('agentless'):
                is_online = _agentless_online(dev)

        entry = {
            'device_id': dev_id,
            'name': dev.get('name', dev_id),
            'hostname': dev.get('hostname', ''),
            'group': dev.get('group', ''),
            'tags': dev.get('tags', []),
            'os': dev.get('os', ''),
            'online': is_online,
            # v5.8.0: unmonitored-data-visibility principle — the Patches view
            # SHOWS unmonitored hosts but must FLAG them (the row renderer paints a
            # "silent" badge off this, like the metrics/SNMP/exposure tables).
            'monitored': dev.get('monitored') is not False,
            'last_seen': dev.get('last_seen', 0),
            'pkg_manager': pkg_manager,
            'upgradable': upgradable,
            'security_updates': security_updates,
            'firmware': firmware,
            'patch_status': 'unknown',
            # reboot_required: True when /run/reboot-required exists on the host
            # (Debian/Ubuntu); False or absent on other distros / older agents.
            'reboot_required': bool(si.get('reboot_required', False)),
            # v3.4.1: how many outstanding critical/high CVEs a patch would fix.
            'cve_fixable': cve_fixable.get(dev_id, 0),
            # v3.4.2: post-deploy verification status (ok/stalled/pending/None).
            'upgrade_verify': _upgrade_verify_status(dev, now),
        }

        if upgradable is None or not is_online:
            entry['patch_status'] = 'no_data'
            report['summary']['devices_no_data'] += 1
        elif upgradable == 0:
            entry['patch_status'] = 'fully_patched'
            report['summary']['devices_fully_patched'] += 1
        else:
            entry['patch_status'] = 'patches_available'
            report['summary']['devices_with_patches'] += 1
            report['summary']['total_pending_patches'] += upgradable

        # Recent exec history for patch commands
        outputs = all_cmd_outputs.get(dev_id, [])
        patch_cmds = [o for o in outputs if any(kw in o.get('cmd', '')
                      for kw in ('apt', 'dnf', 'pacman', 'upgrade', 'update'))]
        entry['recent_patch_commands'] = patch_cmds[-5:]

        report['devices'].append(entry)

    # Patch percentage: only among ONLINE devices that have reported data
    online_with_data = report['summary']['devices_fully_patched'] + report['summary']['devices_with_patches']
    patched = report['summary']['devices_fully_patched']
    report['summary']['online_with_data'] = online_with_data
    report['summary']['patch_percentage'] = round((patched / online_with_data * 100) if online_with_data > 0 else 0, 1)

    report['summary']['cve_fixable_total'] = sum(cve_fixable.values())
    report['devices'].sort(key=lambda x: (-(x.get('upgradable') or 0), x['name'].lower()))
    respond(200, report)


def handle_patch_report_device(dev_id):
    """Return detailed patch report for a single device."""
    require_auth()
    _scope_block_device(dev_id)   # v3.5.0 RBAC v2
    if not _validate_id(dev_id): respond(404, {'error': 'Device not found'})
    devices = load(DEVICES_FILE)
    if dev_id not in devices: respond(404, {'error': 'Device not found'})
    dev = devices[dev_id]
    now = int(time.time())
    si = dev.get('sysinfo', {})
    pkg = si.get('packages', {})
    upgradable = pkg.get('upgradable')
    security_updates = pkg.get('security_updates')   # v5.0.0: distro-flagged
    is_online = (now - dev.get('last_seen', 0)) < get_online_ttl()

    # All exec output related to patching
    outputs = load(CMD_OUTPUT_FILE).get(dev_id, [])
    patch_cmds = [o for o in outputs if any(kw in o.get('cmd', '')
                  for kw in ('apt', 'dnf', 'pacman', 'upgrade', 'update', 'yum'))]

    # Metrics history
    metrics = load(METRICS_FILE).get(dev_id, [])

    report = {
        'device_id': dev_id,
        'name': dev.get('name', dev_id),
        'hostname': dev.get('hostname', ''),
        'group': dev.get('group', ''),
        'tags': dev.get('tags', []),
        'os': dev.get('os', ''),
        'online': is_online,
        'last_seen': dev.get('last_seen', 0),
        'enrolled': dev.get('enrolled', 0),
        'version': dev.get('version', ''),
        'pkg_manager': pkg.get('manager', 'unknown'),
        'upgradable': upgradable,
        'security_updates': security_updates,
        'patch_status': 'no_data' if upgradable is None else ('fully_patched' if upgradable == 0 else 'patches_available'),
        'uptime': si.get('uptime', ''),
        'platform': si.get('platform', ''),
        'patch_history': patch_cmds[-20:],
        'latest_metrics': metrics[-10:] if metrics else [],
    }
    respond(200, report)


def _filter_devices_for_export():
    """Filter devices by query params: group, device_id."""
    from urllib.parse import parse_qs
    qs = parse_qs(_env('QUERY_STRING', ''))
    group_filter = qs.get('group', [''])[0].strip()
    device_filter = qs.get('device_id', [''])[0].strip()
    devices = load(DEVICES_FILE)
    filtered = {}
    for dev_id, dev in devices.items():
        if group_filter and dev.get('group', '') != group_filter:
            continue
        if device_filter and dev_id != device_filter:
            continue
        filtered[dev_id] = dev
    return filtered


def _csv_safe(value):
    """Neutralize CSV/spreadsheet formula injection. A cell whose first char is
    one of = + - @ (or a leading tab/CR that a parser may strip back to one of
    those) is treated as a formula by Excel/Sheets/LibreOffice. Prefix a single
    quote so the cell is rendered as literal text. Non-string values pass
    through unchanged (numbers can't carry a formula)."""
    if not isinstance(value, str) or not value:
        return value
    if value[0] in ('=', '+', '-', '@', '\t', '\r'):
        return "'" + value
    return value


def handle_patch_report_csv():
    """Return patch report as CSV."""
    require_auth()
    devices = _filter_devices_for_export()
    now = int(time.time())
    import csv, io
    buf = io.StringIO()
    writer = csv.writer(buf)
    writer.writerow(['Device', 'Hostname', 'Group', 'OS', 'Online', 'Pkg Manager',
                     'Pending Updates', 'Security Updates', 'Patch Status', 'Last Seen'])
    for dev_id, dev in sorted(devices.items(), key=lambda x: x[1].get('name', '').lower()):
        si = dev.get('sysinfo', {})
        pkg = si.get('packages', {})
        upgradable = pkg.get('upgradable')
        security_updates = pkg.get('security_updates')   # v5.0.0: distro-flagged
        is_online = (now - dev.get('last_seen', 0)) < get_online_ttl()
        status = 'no_data' if (upgradable is None or not is_online) else ('fully_patched' if upgradable == 0 else 'patches_available')
        last_seen_str = time.strftime('%Y-%m-%d %H:%M:%S', time.localtime(dev.get('last_seen', 0))) if dev.get('last_seen') else 'never'
        writer.writerow([
            _csv_safe(dev.get('name', dev_id)), _csv_safe(dev.get('hostname', '')),
            _csv_safe(dev.get('group', '')), _csv_safe(dev.get('os', '')),
            'yes' if is_online else 'no',
            _csv_safe(pkg.get('manager', 'unknown')), upgradable if upgradable is not None else 'N/A',
            security_updates if security_updates is not None else 'N/A',
            status, last_seen_str
        ])
    data = buf.getvalue().encode()
    ts = time.strftime('%Y%m%d-%H%M%S')
    print("Status: 200 OK")
    print("Content-Type: text/csv")
    print(f"Content-Disposition: attachment; filename=patch-report-{ts}.csv")
    print(f"Content-Length: {len(data)}")
    print("Cache-Control: no-store")
    print("X-Content-Type-Options: nosniff")
    print()
    sys.stdout.flush()
    sys.stdout.buffer.write(data)
    sys.stdout.buffer.flush()
    sys.exit(0)


def handle_patch_report_xml():
    """Return patch report as XML."""
    require_auth()
    devices = _filter_devices_for_export()
    now = int(time.time())
    from xml.etree.ElementTree import Element, SubElement, tostring
    root = Element('PatchReport')
    root.set('generated', time.strftime('%Y-%m-%dT%H:%M:%S', time.localtime(now)))
    root.set('serverVersion', SERVER_VERSION)
    summary = SubElement(root, 'Summary')
    total = len(devices)
    patched = 0; pending = 0; no_data = 0; with_patches = 0
    devs_el = SubElement(root, 'Devices')
    for dev_id, dev in sorted(devices.items(), key=lambda x: x[1].get('name', '').lower()):
        si = dev.get('sysinfo', {})
        pkg = si.get('packages', {})
        upgradable = pkg.get('upgradable')
        security_updates = pkg.get('security_updates')   # v5.0.0: distro-flagged
        is_online = (now - dev.get('last_seen', 0)) < get_online_ttl()
        d_el = SubElement(devs_el, 'Device')
        d_el.set('id', dev_id)
        SubElement(d_el, 'Name').text = dev.get('name', dev_id)
        SubElement(d_el, 'Hostname').text = dev.get('hostname', '')
        SubElement(d_el, 'Group').text = dev.get('group', '')
        SubElement(d_el, 'OS').text = dev.get('os', '')
        SubElement(d_el, 'Online').text = str(is_online).lower()
        SubElement(d_el, 'PkgManager').text = pkg.get('manager', 'unknown')
        SubElement(d_el, 'PendingUpdates').text = str(upgradable) if upgradable is not None else 'N/A'
        SubElement(d_el, 'SecurityUpdates').text = str(security_updates) if security_updates is not None else 'N/A'
        if upgradable is None or not is_online: status = 'no_data'; no_data += 1
        elif upgradable == 0: status = 'fully_patched'; patched += 1
        else: status = 'patches_available'; with_patches += 1; pending += upgradable
        SubElement(d_el, 'PatchStatus').text = status
    SubElement(summary, 'TotalDevices').text = str(total)
    SubElement(summary, 'FullyPatched').text = str(patched)
    SubElement(summary, 'WithPatches').text = str(with_patches)
    SubElement(summary, 'NoData').text = str(no_data)
    SubElement(summary, 'TotalPendingPatches').text = str(pending)
    online_with_data = patched + with_patches
    SubElement(summary, 'OnlineWithData').text = str(online_with_data)
    SubElement(summary, 'PatchPercentage').text = str(round((patched / online_with_data * 100) if online_with_data > 0 else 0, 1))
    xml_str = tostring(root, encoding='unicode')
    data = ('<?xml version="1.0" encoding="UTF-8"?>\n' + xml_str).encode('utf-8')
    ts = time.strftime('%Y%m%d-%H%M%S')
    print("Status: 200 OK")
    print("Content-Type: application/xml")
    print(f"Content-Disposition: attachment; filename=patch-report-{ts}.xml")
    print(f"Content-Length: {len(data)}")
    print("Cache-Control: no-store")
    print("X-Content-Type-Options: nosniff")
    print()
    sys.stdout.flush()
    sys.stdout.buffer.write(data)
    sys.stdout.buffer.flush()
    sys.exit(0)


# ── v6.1.1: package-repo snapshot & promotion ledger ─────────────────────────
# Scoped down from "mirror an APT/YUM/Chocolatey repo" to what's actually
# buildable without a new agent-side per-package version-pinned-install
# capability (the agent's auto-patch dispatch is one fixed `upgrade` command
# per package manager today — see _autopatch_queue/_SCHED_UPGRADE_CMD — it
# has no protocol for "install pkg=EXACT_VERSION" yet). What ships instead:
# freeze the fleet's current installed-package state into a named, immutable
# snapshot (reusing PACKAGES_FILE, the same data patch-report already reads);
# diff two snapshots; "promote" one to a tag as a REFERENCE point; and report
# DRIFT of that tag's devices away from the promoted snapshot. This is
# real-and-honest reproducibility/audit tooling on its own — TRUE version-
# pinned enforcement (installing exactly the snapshot's versions) still needs
# that new agent-side capability and remains a separate, larger follow-up
# (docs/feature-buildout-scoping-internal.md #4). What DOES ship
# (docs/master-improvement-scoping-internal.md #80, this session): a coarser
# but real and honest form of enforcement achievable with the EXISTING agent
# protocol — a promoted (pinned) tag is excluded from auto-patch dispatch
# entirely (_autopatch_target_devices/_pinned_patch_tags), for the flat
# (non-ringed) policy path. "Pin" means "hold this tag's versions by pausing
# auto-patch for it", not "force-install the snapshot's exact versions" —
# an honest middle ground, not the full pin semantics the item name implies.
# Staged/ringed rollouts (a separate target-resolution path,
# _rollout_resolve_ring) are NOT covered — a real remaining gap.
MAX_PATCH_SNAPSHOTS = 200


def _ps_build_entries():
    """{pkg_name: newest version seen} merged across every (scope-visible)
    device's PACKAGES_FILE entry — the same source patch-report reads."""
    devices = _scope_filter_devices(load(DEVICES_FILE) or {})
    store = load(PACKAGES_FILE) or {}
    newest = {}
    for dev_id, rec in store.items():
        if dev_id not in devices:
            continue
        for pkg in (rec.get('packages') or []):
            name, version = pkg.get('name'), pkg.get('version')
            if not name or not version:
                continue
            if name not in newest or _pkg_version_key(version) > _pkg_version_key(newest[name]):
                newest[name] = version
    return newest


def _pkg_version_key(v):
    """Best-effort sortable key for a package version string — splits on the
    first run of digits per dot-segment so '1.10' sorts after '1.9' (a plain
    string compare would put '1.10' before '1.9'). Not a full Debian/RPM
    version-compare (epochs, ~, etc.) — good enough for 'which is newer' on
    the common case, and ties just keep whichever was seen first, which is
    fine for a fleet-wide snapshot (any device's version is a legitimate
    answer to "what's currently running somewhere")."""
    parts = re.split(r'[.\-+~]', str(v))
    key = []
    for p in parts:
        m = re.match(r'(\d+)', p)
        key.append(int(m.group(1)) if m else -1)
        key.append(p)
    return key


def handle_patch_snapshots():
    """GET /api/patch-snapshots — list (metadata only, no full entry list —
       keep it light; GET the single-snapshot route for entries).
       POST /api/patch-snapshots {name} — freeze the current fleet package
       state into a new named snapshot."""
    if method() == 'GET':
        require_auth()
        snaps = load(PATCH_SNAPSHOTS_FILE) or {}
        out = [{'id': sid, 'name': s.get('name', ''), 'created': s.get('created', 0),
                'created_by': s.get('created_by', ''), 'entry_count': s.get('entry_count', 0),
                'promoted_tag': s.get('promoted_tag')}
               for sid, s in snaps.items()]
        out.sort(key=lambda s: s['created'], reverse=True)
        respond(200, {'ok': True, 'snapshots': out})
        return
    actor = require_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    name = _sanitize_str(body.get('name', ''), 80).strip()
    if not name:
        respond(400, {'error': 'name required'})
    entries = _ps_build_entries()
    sid = secrets.token_hex(8)
    with _LockedUpdate(PATCH_SNAPSHOTS_FILE) as snaps:
        if len(snaps) >= MAX_PATCH_SNAPSHOTS:
            respond(400, {'error': f'snapshot limit reached (max {MAX_PATCH_SNAPSHOTS})'})
        snaps[sid] = {'id': sid, 'name': name, 'created': int(time.time()),
                     'created_by': actor, 'entry_count': len(entries), 'entries': entries,
                     'promoted_tag': None}
    audit_log(actor, 'patch_snapshot_create', detail=f'{name} ({len(entries)} packages)')
    respond(201, {'ok': True, 'id': sid, 'entry_count': len(entries)})


def handle_patch_snapshot_get(sid):
    """GET /api/patch-snapshots/{id} — full entries."""
    require_auth()
    if not _validate_id(sid):
        respond(404, {'error': 'Snapshot not found'})
    snaps = load(PATCH_SNAPSHOTS_FILE) or {}
    s = snaps.get(sid)
    if not s:
        respond(404, {'error': 'Snapshot not found'})
    respond(200, {'ok': True, 'id': sid, 'name': s.get('name', ''), 'created': s.get('created', 0),
                  'created_by': s.get('created_by', ''), 'promoted_tag': s.get('promoted_tag'),
                  'entries': s.get('entries') or {}})


def handle_patch_snapshot_delete(sid):
    """DELETE /api/patch-snapshots/{id} — admin (a promoted snapshot is a
    reference point other reports key off; deleting it is a real change)."""
    actor = require_admin_auth()
    if method() != 'DELETE':
        respond(405, {'error': 'Method not allowed'})
    if not _validate_id(sid):
        respond(404, {'error': 'Snapshot not found'})
    with _LockedUpdate(PATCH_SNAPSHOTS_FILE) as snaps:
        if sid not in snaps:
            respond(404, {'error': 'Snapshot not found'})
        name = snaps[sid].get('name', '')
        del snaps[sid]
    audit_log(actor, 'patch_snapshot_delete', detail=f'{sid} ({name})')
    respond(200, {'ok': True})


def handle_patch_snapshot_promote(sid):
    """POST /api/patch-snapshots/{id}/promote {tag} — mark this snapshot as
    the reference state for `tag` (a device tag/group name). Promoting a new
    snapshot to a tag already in use supersedes the old one for that tag —
    "promotion" here is a pointer, not a queue; only the latest matters for
    the drift report. tag=null clears the promotion (POST {} demotes)."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    if not _validate_id(sid):
        respond(404, {'error': 'Snapshot not found'})
    body = get_json_obj()
    tag = _sanitize_str(body.get('tag', ''), 64).strip() or None
    with _LockedUpdate(PATCH_SNAPSHOTS_FILE) as snaps:
        s = snaps.get(sid)
        if not s:
            respond(404, {'error': 'Snapshot not found'})
        # a tag promotes to exactly one snapshot -- clear it from any other
        if tag:
            for other_id, other in snaps.items():
                if other_id != sid and other.get('promoted_tag') == tag:
                    other['promoted_tag'] = None
        s['promoted_tag'] = tag
    audit_log(actor, 'patch_snapshot_promote', detail=f'{sid} -> tag={tag}')
    respond(200, {'ok': True, 'promoted_tag': tag})


def handle_patch_snapshot_diff():
    """GET /api/patch-snapshots/diff?a=<id>&b=<id> — set-diff between two
    snapshots' package/version maps."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    a_id = (qs.get('a', [''])[0] or '').strip()
    b_id = (qs.get('b', [''])[0] or '').strip()
    snaps = load(PATCH_SNAPSHOTS_FILE) or {}
    a, b = snaps.get(a_id), snaps.get(b_id)
    if not a or not b:
        respond(404, {'error': 'both a and b must be existing snapshot ids'})
    a_entries, b_entries = a.get('entries') or {}, b.get('entries') or {}
    added = sorted(set(b_entries) - set(a_entries))
    removed = sorted(set(a_entries) - set(b_entries))
    changed = sorted(pkg for pkg in (set(a_entries) & set(b_entries))
                     if a_entries[pkg] != b_entries[pkg])
    respond(200, {'ok': True,
                  'added': [{'pkg': p, 'version': b_entries[p]} for p in added],
                  'removed': [{'pkg': p, 'version': a_entries[p]} for p in removed],
                  'changed': [{'pkg': p, 'from': a_entries[p], 'to': b_entries[p]} for p in changed]})


def handle_patch_snapshot_drift(sid):
    """GET /api/patch-snapshots/{id}/drift — for devices carrying the
    snapshot's promoted tag (all scope-visible devices if it isn't promoted
    to one), report which installed packages differ from what was pinned.
    Read-only reporting — does not touch auto-patch dispatch (see the module
    docstring above for why enforcement is out of scope for this feature)."""
    require_auth()
    if not _validate_id(sid):
        respond(404, {'error': 'Snapshot not found'})
    snaps = load(PATCH_SNAPSHOTS_FILE) or {}
    s = snaps.get(sid)
    if not s:
        respond(404, {'error': 'Snapshot not found'})
    pinned = s.get('entries') or {}
    tag = s.get('promoted_tag')
    devices = _scope_filter_devices(load(DEVICES_FILE) or {})
    if tag:
        devices = {k: v for k, v in devices.items() if tag in (v.get('tags') or [])}
    pkg_store = load(PACKAGES_FILE) or {}
    out = []
    for dev_id, dev in devices.items():
        installed = {p.get('name'): p.get('version')
                    for p in (pkg_store.get(dev_id, {}).get('packages') or [])
                    if p.get('name') and p.get('version')}
        mismatches = [{'pkg': pkg, 'pinned': pinver, 'installed': installed[pkg]}
                     for pkg, pinver in pinned.items()
                     if pkg in installed and installed[pkg] != pinver]
        if mismatches:
            out.append({'device_id': dev_id, 'device_name': dev.get('name', dev_id),
                        'mismatches': mismatches})
    respond(200, {'ok': True, 'snapshot_id': sid, 'tag': tag,
                  'devices_checked': len(devices), 'devices_drifted': len(out), 'drift': out})


# ── v3.4.1: fleet posture report ───────────────────────────────────────────────
# One report that binds together the four posture surfaces operators otherwise
# read on separate pages — patches, CVEs, health score, and compliance — so a
# single export (or scheduled email) captures "how is the fleet doing right now".

def _build_fleet_report(site_id=None):
    """Assemble the fleet (or single-site) posture report from data RemotePower
    already holds.

    Reuses the existing single-source-of-truth helpers (_fleet_health,
    _compliance_facts/compliance.build_report, the CVE findings store) rather
    than recomputing, so the report can never disagree with the live pages.
    When `site_id` is given, devices / patches / SLA / CVE / health are scoped to
    that site; compliance stays fleet-wide (tagged `scope: fleet`)."""
    devices = load(DEVICES_FILE) or {}
    if site_id is not None:
        devices = {k: v for k, v in devices.items()
                   if isinstance(v, dict) and (v.get('site') or '') == site_id}
    # v5.7.0 (SECURITY): confine the report to the caller's role scope + tenant.
    # Reached from handle_fleet_report / handle_evidence_pack after require_auth;
    # without this a group/tag/site-scoped operator (or, under multi-tenancy, a
    # tenant user) got fleet-wide device names, worst-10 health, and CVE/patch/
    # SLA aggregates. Mirrors handle_fleet_health's re-filter.
    _pre_scope_n = len(devices)
    devices = _scope_filter_devices(devices)
    # `site_ids` restricts the CVE + health rosters below. Use the visible id set
    # whenever a site filter is active OR the caller's scope/tenant actually
    # trimmed the fleet; None (all findings) only for a fully-unscoped admin, so
    # the admin path is byte-for-byte unchanged.
    _caller_restricted = len(devices) != _pre_scope_n
    site_ids = (set(devices) if (site_id is not None or _caller_restricted)
                else None)
    now = int(time.time())
    ttl = get_online_ttl()
    online = sum(1 for d in devices.values()
                 if isinstance(d, dict) and (now - d.get('last_seen', 0)) < ttl)

    with_patches = 0
    total_pending = 0
    for d in devices.values():
        up = ((d.get('sysinfo') or {}).get('packages') or {}).get('upgradable')
        if isinstance(up, int) and up > 0:
            with_patches += 1
            total_pending += up

    cve = {'critical': 0, 'high': 0, 'medium': 0, 'low': 0, 'devices_affected': 0}
    # v3.4.2: apply the per-device CVE ignore list exactly like the live CVE
    # page (handle_cve_findings) so the posture report can't over-count by the
    # ignored set. Iterate items() to keep the device id apply_ignore_list needs.
    cve_ignore = load(CVE_IGNORE_FILE) or {}
    for did, rec in (load(CVE_FINDINGS_FILE) or {}).items():
        if site_ids is not None and did not in site_ids:
            continue
        affected = False
        findings = (rec or {}).get('findings') or []
        for f in cve_scanner.apply_ignore_list(findings, cve_ignore, did):
            if f.get('ignored'):
                continue
            sev = str(f.get('severity', '')).lower()
            if sev in cve:
                cve[sev] += 1
                affected = True
        if affected:
            cve['devices_affected'] += 1

    health = _fleet_health()
    if site_ids is not None:
        # Scope the health roster + recompute the headline score/grade/counts.
        hdevs = [d for d in health['devices'] if d.get('device_id') in site_ids]
        hscore = round(sum(d['score'] for d in hdevs) / len(hdevs)) if hdevs else 100
        health = {
            'score': hscore, 'grade': _health_grade(hscore), 'devices': hdevs,
            'counts': {'critical': sum(d.get('critical', 0) for d in hdevs),
                       'warning':  sum(d.get('warning', 0) for d in hdevs),
                       'info':     sum(d.get('info', 0) for d in hdevs)},
        }
    comp = compliance.build_report(_compliance_facts())
    comp['generated_ts'] = now
    if site_id is not None:
        comp['scope'] = 'fleet'   # compliance frameworks are graded fleet-wide

    # v3.4.1: fleet uptime % over the last 30 days (SLA headline).
    uptime = load(UPTIME_FILE) or {}
    win = now - 30 * 86400
    sla_pcts = []
    for did, d in devices.items():
        if not isinstance(d, dict) or d.get('monitored') is False:
            continue
        pct, _down, covered = _uptime_pct((uptime.get(did) or {}).get('events') or [], win, now)
        if covered and pct is not None:
            sla_pcts.append(pct)
    fleet_uptime = round(sum(sla_pcts) / len(sla_pcts), 3) if sla_pcts else None

    out = {
        'generated_ts':   now,
        'server_version': SERVER_VERSION,
        'server_name':    get_server_name(),
        'devices':        {'total': len(devices), 'online': online,
                           'offline': len(devices) - online},
        'sla':            {'days': 30, 'fleet_uptime_pct': fleet_uptime},
        'patches':        {'devices_with_patches': with_patches,
                           'total_pending': total_pending,
                           # W1-33: hosts currently past a patch-SLA deadline
                           'sla_violations': len(_eval_patch_sla(
                               devices, _config_ro(), dict(load(PATCH_AGE_FILE) or {}),
                               now)[1])},
        'cve':            cve,
        'health':         {'score': health['score'], 'grade': health['grade'],
                           'worst': health['devices'][:10]},
        'attention':      health['counts'],
        'compliance':     comp,
    }
    if site_id is not None:
        out['site_id'] = site_id
        out['site_name'] = ((load(SITES_FILE) or {}).get(site_id) or {}).get('name', site_id)
    return out


# v3.14.0: custom report builder — selectable sections + saved definitions.
_REPORT_SECTIONS = ('devices', 'sla', 'patches', 'cve', 'health', 'attention', 'compliance')


def _filter_report_sections(report, sections):
    """Keep report metadata + only the requested sections (empty/None = all)."""
    keep = set(sections or ()) & set(_REPORT_SECTIONS)
    if not keep:
        return report
    out = {k: report[k] for k in ('generated_ts', 'server_version', 'server_name') if k in report}
    out['sections'] = sorted(keep)
    for k in _REPORT_SECTIONS:
        if k in keep and k in report:
            out[k] = report[k]
    return out


def _fleet_report_csv_bytes(report):
    """Flatten the posture report into a single summary CSV (Section,Metric,Value)."""
    import csv, io
    buf = io.StringIO()
    w = csv.writer(buf)
    w.writerow(['Section', 'Metric', 'Value'])
    d = report['devices']
    w.writerow(['Devices', 'Total', d['total']])
    w.writerow(['Devices', 'Online', d['online']])
    w.writerow(['Devices', 'Offline', d['offline']])
    w.writerow(['Health', 'Fleet score', report['health']['score']])
    w.writerow(['Health', 'Grade', report['health']['grade']])
    a = report['attention']
    w.writerow(['Attention', 'Critical', a.get('critical', 0)])
    w.writerow(['Attention', 'Warning', a.get('warning', 0)])
    w.writerow(['Attention', 'Info', a.get('info', 0)])
    p = report['patches']
    w.writerow(['Patches', 'Devices with patches', p['devices_with_patches']])
    w.writerow(['Patches', 'Total pending', p['total_pending']])
    for sev in ('critical', 'high', 'medium', 'low'):
        w.writerow(['CVE', sev.capitalize(), report['cve'][sev]])
    w.writerow(['CVE', 'Devices affected', report['cve']['devices_affected']])
    for fw, fwrep in (report['compliance'].get('frameworks') or {}).items():
        w.writerow(['Compliance', fw.upper() + ' pass %',
                    fwrep.get('score') if fwrep.get('score') is not None else 'N/A'])
    w.writerow([])
    w.writerow(['Worst devices', 'Score', 'Critical/Warning'])
    for dev in report['health']['worst']:
        w.writerow([dev['device_name'], dev['score'],
                    f"{dev['critical']}/{dev['warning']}"])
    return buf.getvalue().encode()


def handle_fleet_report():
    """GET /api/report/fleet?format=json|csv — fleet posture report.

    Auth: require_auth (read-only summary, no secrets). The printable view is the
    static report.html page, which fetches this JSON and renders a light document
    with external CSS/JS (CSP-clean) for the browser's Print / Save-as-PDF."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    fmt = (qs.get('format') or ['json'])[0].lower()
    report = _build_fleet_report()
    # v3.14.0: optional ?sections=devices,cve,health filter (custom reports).
    sections = (qs.get('sections') or [''])[0]
    if sections:
        report = _filter_report_sections(report, [s.strip() for s in sections.split(',') if s.strip()])
    if fmt == 'csv':
        data = _fleet_report_csv_bytes(report)
        ts = time.strftime('%Y%m%d-%H%M%S')
        print("Status: 200 OK")
        print("Content-Type: text/csv")
        print(f"Content-Disposition: attachment; filename=fleet-report-{ts}.csv")
        print(f"Content-Length: {len(data)}")
        print("Cache-Control: no-store")
        print("X-Content-Type-Options: nosniff")
        print()
        sys.stdout.flush()
        sys.stdout.buffer.write(data)
        sys.stdout.buffer.flush()
        sys.exit(0)
    respond(200, report)


def handle_site_report(site_id):
    """GET /api/report/site/{site_id}?format=json|csv — per-site (customer)
    posture report: the same fleet report scoped to one site. RBAC-scoped — a
    caller can only pull a site whose devices fall within their scope."""
    require_auth()
    if not isinstance((load(SITES_FILE) or {}).get(site_id), dict):
        respond(404, {'error': 'site not found'})
    # v5.0.1 (SECURITY): a whole-SITE posture report requires site-level scope.
    # The old check only rejected sites-typed scopes, so a group/tag/host-scoped
    # operator (non-None scope of another type) fell through and pulled the full
    # site's device names/health/CVE/SLA — cross-scope leak. Now: unrestricted
    # ('all', scope is None) OR a sites-scope that covers this site; else 403.
    scope = _caller_scope()
    if scope is not None and not (
            scope.get('type') == 'sites' and site_id in (scope.get('values') or [])):
        respond(403, {'error': 'site outside your role scope'})
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    fmt = (qs.get('format') or ['json'])[0].lower()
    report = _build_fleet_report(site_id=site_id)
    if fmt == 'csv':
        data = _fleet_report_csv_bytes(report)
        ts = time.strftime('%Y%m%d-%H%M%S')
        print("Status: 200 OK")
        print("Content-Type: text/csv")
        print(f"Content-Disposition: attachment; filename=site-report-{_site_slugify(report.get('site_name', site_id))}-{ts}.csv")
        print(f"Content-Length: {len(data)}")
        print("Cache-Control: no-store")
        print("X-Content-Type-Options: nosniff")
        print()
        sys.stdout.flush()
        sys.stdout.buffer.write(data)
        sys.stdout.buffer.flush()
        sys.exit(0)
    respond(200, report)


def handle_evidence_pack():
    """GET /api/report/evidence?days=N — a compliance EVIDENCE PACK (admin-only).

    Bundles the data an auditor asks for into one downloadable JSON document: the
    current fleet posture report (health, patches, CVE, CIS compliance, uptime),
    the compliance-baseline trend, and an audit-log excerpt for the period — all
    from data RemotePower already holds, no recompute. The act of generating it is
    itself audit-logged."""
    actor = require_admin_or_auditor_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    try:
        days = int((qs.get('days') or ['90'])[0])
    except ValueError:
        days = 90
    days = max(1, min(366, days))
    now = int(time.time())
    since = now - days * 86400
    comp_hist = [s for s in ((load(COMPLIANCE_HIST_FILE) or {}).get('fleet') or [])
                 if isinstance(s, dict) and int(s.get('ts', 0) or 0) >= since][-days:]
    audit = [e for e in ((load(AUDIT_LOG_FILE) or {}).get('entries') or [])
             if isinstance(e, dict) and int(e.get('ts', 0) or 0) >= since]
    pack = {
        'schema':         'remotepower.evidence.v1',
        'generated_ts':   now,
        'generated_by':   actor,
        'server_name':    get_server_name(),
        'server_version': SERVER_VERSION,
        'period_days':    days,
        'period_start':   since,
        'posture':        _build_fleet_report(),
        'compliance_history': comp_hist,
        'audit_excerpt':  audit[-2000:],   # cap so the pack can't balloon
        'audit_count':    len(audit),
    }
    # v5.4.1 (C4): tamper-evidence signature over the canonical pack (computed
    # before the `signature` field is added; verify = recompute over the pack
    # minus `signature`). Closes the "evidence exports are unsigned" gap.
    pack['signature'] = {
        'alg': 'hmac-sha256',
        'value': _export_sign(json.dumps(pack, sort_keys=True, separators=(',', ':'))),
    }
    audit_log(actor, 'evidence_pack_generated', detail=f'period={days}d entries={len(audit)}')
    fmt = (qs.get('format') or ['json'])[0].lower()
    if fmt == 'download':
        data = json.dumps(pack, indent=2).encode('utf-8')
        ts = time.strftime('%Y%m%d-%H%M%S')
        print("Status: 200 OK")
        print("Content-Type: application/json")
        print(f"Content-Disposition: attachment; filename=evidence-pack-{ts}.json")
        print(f"Content-Length: {len(data)}")
        print("Cache-Control: no-store")
        print("X-Content-Type-Options: nosniff")
        print()
        sys.stdout.flush()
        sys.stdout.buffer.write(data)
        sys.stdout.buffer.flush()
        sys.exit(0)
    respond(200, pack)


def _render_report_email(report):
    """Plain-text body + subject for a (possibly section-filtered) fleet report."""
    # v3.14.0: tolerate custom reports that omit sections — default each to {}.
    d = report.get('devices') or {}
    h = report.get('health') or {}
    a = report.get('attention') or {}
    p = report.get('patches') or {}
    c = report.get('cve') or {}
    sla = report.get('sla') or {}
    when = time.strftime('%Y-%m-%d %H:%M', time.localtime(report.get('generated_ts', int(time.time()))))
    subject = f"{report.get('server_name', 'RemotePower')} fleet report"
    if h:
        subject += f" — health {h.get('score', '?')}/100 ({h.get('grade', '?')})"
    lines = [
        f"{report.get('server_name', 'RemotePower')} — fleet posture report",
        f"Generated {when}  ·  RemotePower {report.get('server_version', '')}",
        "",
    ]
    if h:
        lines.append(f"Fleet health score : {h.get('score', '?')}/100 ({h.get('grade', '?')})")
    if d:
        lines.append(f"Devices            : {d.get('total',0)} total, {d.get('online',0)} online, "
                     f"{d.get('offline',0)} offline")
    if a:
        lines.append(f"Needs attention    : {a.get('critical',0)} critical, "
                     f"{a.get('warning',0)} warning, {a.get('info',0)} info")
    if sla and sla.get('fleet_uptime_pct') is not None:
        lines.append(f"SLA uptime ({sla.get('days',30)}d) : {sla.get('fleet_uptime_pct')}%")
    if p:
        lines.append(f"Patches            : {p.get('devices_with_patches',0)} device(s) pending, "
                     f"{p.get('total_pending',0)} update(s) total")
    if c:
        lines.append(f"CVEs               : {c.get('critical',0)} critical, {c.get('high',0)} high, "
                     f"{c.get('medium',0)} medium ({c.get('devices_affected',0)} device(s) affected)")
    lines.append("")
    if h.get('worst'):
        lines.append("Lowest-scoring devices:")
        for dev in h['worst'][:5]:
            lines.append(f"  - {dev['device_name']}: {dev['score']}/100 "
                         f"({dev['critical']} crit, {dev['warning']} warn)")
        lines.append("")
    fws = (report.get('compliance') or {}).get('frameworks') or {}
    if fws:
        lines.append("Compliance:")
        for fw, rep in fws.items():
            pct = rep.get('score') if rep.get('score') is not None else 'N/A'
            lines.append(f"  - {fw.upper()}: {pct}% controls passing")
    return subject, "\n".join(lines)


def _maybe_send_scheduled_report():
    """Heartbeat hook: send the fleet report on its configured cron schedule.

    Mirrors _maybe_run_scheduled_backup's cheap-gate pattern. Config lives in
    config.json under `report_schedule` ({enabled, cron, recipients}). The
    once-per-minute claim is done under a file lock so concurrent heartbeats in
    the same matching minute don't each fire an email."""
    cfg = load(CONFIG_FILE) or {}
    rs = cfg.get('report_schedule') or {}
    if not rs.get('enabled'):
        return
    cron = rs.get('cron')
    if not cron or not _valid_cron(cron):
        return
    now = int(time.time())
    if not _cron_matches(cron, now):
        return
    current_minute = now // 60
    state_file = DATA_DIR / 'report_schedule_state.json'
    # Claim the minute atomically; bail if another heartbeat already sent.
    with _LockedUpdate(state_file) as state:
        if state.get('last_fired_minute') == current_minute:
            return
        state['last_fired_minute'] = current_minute
        state['last_run'] = now
    recipients = rs.get('recipients') or _smtp_recipients_list(cfg)
    if not recipients:
        return
    try:
        report = _build_fleet_report()
        subject, body = _render_report_email(report)
        smtp_notifier.send_email(cfg, recipients, subject, body,
                                 html_body=smtp_notifier.brand_html(cfg, subject, body))
        _log_email('fleet_report', recipients, 'ok', '')
    except smtp_notifier.SmtpError as e:
        _log_email('fleet_report', recipients, 'error', str(e))
    except Exception as e:
        sys.stderr.write(f'[remotepower] scheduled report failed: {e}\n')


def handle_report_schedule_get():
    """GET /api/report/schedule — current scheduled-report config + last run."""
    require_auth()
    cfg = load(CONFIG_FILE) or {}
    rs = dict(cfg.get('report_schedule') or {})
    state_file = DATA_DIR / 'report_schedule_state.json'
    state = load(state_file) if backend_exists(state_file) else {}
    respond(200, {
        'enabled':    bool(rs.get('enabled')),
        'cron':       rs.get('cron', ''),
        'recipients': rs.get('recipients') or [],
        'last_run':   state.get('last_run') or 0,
    })


def handle_report_schedule_set():
    """PUT /api/report/schedule — configure the scheduled report. Admin-only."""
    actor = require_admin_auth()
    if method() != 'PUT':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    enabled = bool(body.get('enabled'))
    cron = str(body.get('cron', '')).strip()
    if enabled and not _valid_cron(cron):
        respond(400, {'error': 'invalid cron expression (5 fields: min hour dom month dow)'})
    raw_recips = body.get('recipients') or []
    if not isinstance(raw_recips, list):
        respond(400, {'error': 'recipients must be a list'})
    recipients = [_sanitize_str(r, 254) for r in raw_recips
                  if isinstance(r, str) and '@' in r][:50]
    with _LockedUpdate(CONFIG_FILE) as cfg:
        cfg['report_schedule'] = {
            'enabled':    enabled,
            'cron':       cron,
            'recipients': recipients,
        }
    audit_log(actor, 'report_schedule_set',
              f'enabled={enabled} cron="{cron}" recipients={len(recipients)}')
    respond(200, {'ok': True, 'enabled': enabled, 'cron': cron,
                  'recipients': recipients})


# ─── v3.14.0: custom report builder — saved report definitions ───────────────
MAX_REPORT_DEFS = 30


def _clean_report_def(body):
    """Validate a report definition payload → cleaned dict (or None)."""
    if not isinstance(body, dict):
        return None
    name = _sanitize_str(str(body.get('name', '')), 64).strip()
    if not name:
        return None
    sections = [s for s in (body.get('sections') or []) if s in _REPORT_SECTIONS]
    fmt = str(body.get('format', 'json')).lower()
    if fmt not in ('json', 'csv'):
        fmt = 'json'
    cron = _sanitize_str(str(body.get('cron', '')), 64).strip()
    enabled = bool(body.get('enabled'))
    if enabled and cron and not _valid_cron(cron):
        return 'badcron'
    recipients = [_sanitize_str(r, 254) for r in (body.get('recipients') or [])
                  if isinstance(r, str) and '@' in r][:50]
    return {
        'id':         _sanitize_str(str(body.get('id', '')), 16) or secrets.token_hex(6),
        'name':       name,
        'sections':   sections or list(_REPORT_SECTIONS),
        'format':     fmt,
        'cron':       cron,
        'enabled':    enabled,
        'recipients': recipients,
    }


def handle_report_defs_list():
    """GET /api/report/definitions — saved custom report definitions."""
    require_auth()
    cfg = load(CONFIG_FILE) or {}
    respond(200, {'definitions': cfg.get('report_definitions') or [],
                  'available_sections': list(_REPORT_SECTIONS)})


def handle_report_defs_save():
    """POST /api/report/definitions — create/update a report definition. Admin."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    cleaned = _clean_report_def(get_json_body())
    if cleaned == 'badcron':
        respond(400, {'error': 'invalid cron expression'})
    if not cleaned:
        respond(400, {'error': 'name is required'})
    with _LockedUpdate(CONFIG_FILE) as cfg:
        defs = cfg.get('report_definitions') or []
        defs = [d for d in defs if d.get('id') != cleaned['id']]
        defs.append(cleaned)
        if len(defs) > MAX_REPORT_DEFS:
            respond(400, {'error': f'too many report definitions (max {MAX_REPORT_DEFS})'})
        cfg['report_definitions'] = defs
    audit_log(actor, 'report_def_save', f"name={cleaned['name']} sections={len(cleaned['sections'])}")
    respond(200, {'ok': True, 'definition': cleaned})


def handle_report_def_delete(def_id):
    """DELETE /api/report/definitions/<id> — remove a report definition. Admin."""
    actor = require_admin_auth()
    if method() != 'DELETE':
        respond(405, {'error': 'Method not allowed'})
    found = False
    with _LockedUpdate(CONFIG_FILE) as cfg:
        defs = cfg.get('report_definitions') or []
        new = [d for d in defs if d.get('id') != def_id]
        found = len(new) != len(defs)
        cfg['report_definitions'] = new
    if not found:
        respond(404, {'error': 'definition not found'})
    audit_log(actor, 'report_def_delete', f'id={def_id}')
    respond(200, {'ok': True})


def _maybe_send_report_definitions():
    """Heartbeat hook: send each enabled custom report on its own cron. Shares
    the once-per-minute claim pattern, keyed per definition id."""
    cfg = load(CONFIG_FILE) or {}
    defs = cfg.get('report_definitions') or []
    if not defs:
        return
    now = int(time.time())
    current_minute = now // 60
    state_file = DATA_DIR / 'report_schedule_state.json'
    for d in defs:
        if not d.get('enabled') or not d.get('cron') or not _valid_cron(d['cron']):
            continue
        if not _cron_matches(d['cron'], now):
            continue
        claim_key = 'def_' + str(d.get('id'))
        with _LockedUpdate(state_file) as state:
            if state.get(claim_key) == current_minute:
                continue
            state[claim_key] = current_minute
        recipients = d.get('recipients') or _smtp_recipients_list(cfg)
        if not recipients:
            continue
        try:
            report = _filter_report_sections(_build_fleet_report(), d.get('sections'))
            subject, body = _render_report_email(report)
            subject = f"[{d.get('name')}] " + subject
            smtp_notifier.send_email(cfg, recipients, subject, body,
                                     html_body=smtp_notifier.brand_html(cfg, subject, body))
            _log_email('fleet_report', recipients, 'ok', d.get('name', ''))
        except smtp_notifier.SmtpError as e:
            _log_email('fleet_report', recipients, 'error', str(e))
        except Exception as e:
            sys.stderr.write(f"[remotepower] custom report '{d.get('name')}' failed: {e}\n")



def handle_audit_log():
    require_admin_or_auditor_auth()
    al = load(AUDIT_LOG_FILE)
    respond(200, _paginate_list(list(reversed(al.get('entries', [])))))


def _audit_chain_walk(entries):
    """Walk the A2 hash-chain; return (links_checked, broken_at_index|None).
    The first chained entry is the trusted anchor (its predecessor may have been
    trimmed/archived); every later entry is recomputed from its predecessor."""
    checked, broken_at, prev = 0, None, None
    for i, e in enumerate(entries):
        h = e.get('_hash')
        if h is None:
            prev = None   # pre-chain (legacy) entry — reset the anchor
            continue
        if prev is not None:
            checked += 1
            if not hmac.compare_digest(_audit_entry_hash(prev, e), h):
                broken_at = i
                break
        prev = h
    return checked, broken_at


def handle_audit_log_verify():
    """GET /api/audit-log/verify — walk the A2 hash-chain; report tampering."""
    require_admin_or_auditor_auth()
    entries = (load(AUDIT_LOG_FILE) or {}).get('entries', [])
    checked, broken_at = _audit_chain_walk(entries)
    respond(200, {'ok': broken_at is None, 'entries': len(entries),
                  'verified': checked, 'broken_at': broken_at,
                  # v6.1.1: current signing generation + how many rotations
                  # have happened, so the UI can show it without a second call.
                  'key_version': _audit_hmac_active_version(),
                  'key_rotations': len(load(AUDIT_HMAC_ROTATIONS_FILE) or {})})


def _rotate_audit_hmac_key(actor):
    """Core audit-chain HMAC-key rotation — mints a new generation. Split out
    from handle_audit_hmac_rotate so run_audit_hmac_rotation_if_due (a cadence
    sweep with no request in flight) can call the same logic without going
    through require_admin_auth()/respond(). Returns the new version int."""
    with _LockedUpdate(AUDIT_HMAC_ROTATIONS_FILE) as rotations:
        versions = [int(k) for k in rotations if str(k).isdigit()]
        new_version = (max(versions) if versions else 1) + 1
        rotations[str(new_version)] = {'key_hex': os.urandom(32).hex(),
                                       'created': int(time.time())}
    audit_log(actor, 'audit_hmac_rotate', detail=f'rotated to generation {new_version}')
    return new_version


def handle_audit_hmac_rotate():
    """POST /api/audit/rotate-hmac-key — mint a new audit-chain HMAC generation.
    v6.1.1, closes part of gap C9/C4 (docs/feature-buildout-scoping-internal.md
    #3): periodic rotation bounds the blast radius of a leaked key to entries
    signed since the last rotation, WITHOUT invalidating any prior entry's
    verifiability — each entry is checked against the generation that actually
    signed it (its own `_kv` field, see _audit_entry_hash), not the current one.
    The old generation is retained forever (never deleted, never needed to be
    memorised/copied anywhere) so historical entries keep verifying."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    new_version = _rotate_audit_hmac_key(actor)
    respond(200, {'ok': True, 'version': new_version})


def run_audit_hmac_rotation_if_due():
    """Heartbeat cadence hook: automatically rotate the audit-chain HMAC key
    on a configurable interval (config: audit_hmac_auto_rotate_days, default 0
    = off, so existing installs are unaffected until an admin opts in).
    docs/master-improvement-scoping-internal.md #26 — the manual rotation
    (handle_audit_hmac_rotate, above) already existed; this automates it the
    same way run_scan_schedules_if_due automates a manual action. Uses the
    real request-free _rotate_audit_hmac_key core, never the handler."""
    _ro = _config_ro()   # v5.8.0 (PERF): no-deepcopy not-due gate
    days = int(_ro.get('audit_hmac_auto_rotate_days', 0) or 0)
    if days <= 0:
        return
    try:
        rotations = load(AUDIT_HMAC_ROTATIONS_FILE) or {}
    except Exception:
        rotations = {}
    last = 0
    for v in rotations.values():
        if isinstance(v, dict):
            last = max(last, int(v.get('created', 0) or 0))
    if not last:
        # No rotation has ever happened — generation 1's real file mtime
        # (audit_hmac.key is a genuine on-disk file, not a KV storage key,
        # same exception class as STORAGE_MARKER_FILE / export_sign.key) is
        # the honest "last rotation" reference point.
        try:
            kf = DATA_DIR / 'audit_hmac.key'
            last = int(kf.stat().st_mtime) if kf.exists() else 0
        except OSError:
            last = 0
    now = int(time.time())
    if last and (now - last) < days * 86400:
        return
    try:
        _rotate_audit_hmac_key('system:auto-rotate')
    except Exception as e:
        sys.stderr.write(f'[remotepower] audit_hmac auto-rotate failed: {e}\n')


def handle_audit_log_archive():
    """GET /api/audit-log/archive — v4.3.0: download the gzipped JSONL archive of
    evicted (age/count-bounded) audit entries. The live log is bounded; this is
    the retained tail that compliance dives need, previously reachable only via
    shell access to DATA_DIR. Admin only; the download is itself audited.
    404 (JSON) when nothing has been archived yet."""
    actor = require_admin_or_auditor_auth()
    arch = DATA_DIR / 'audit_log_archive.jsonl.gz'
    if not arch.exists() or arch.stat().st_size == 0:
        respond(404, {'error': 'no archived audit entries yet'})
    stamp = time.strftime('%Y%m%d-%H%M%S', time.gmtime())
    fname = f'remotepower-audit-archive-{stamp}.jsonl.gz'
    audit_log(actor, 'audit_archive_download', fname)
    # v5.4.1 (C4): tamper-evidence signature over the archive bytes, emitted as a
    # header so a verifier can confirm the download wasn't altered. The archive is
    # the bounded evicted tail, so reading it whole to sign is cheap.
    try:
        _arch_bytes = arch.read_bytes()
        _arch_sig = _export_sign(_arch_bytes)
    except OSError:
        respond(404, {'error': 'no archived audit entries yet'})
    print("Status: 200 OK")
    print("Content-Type: application/gzip")
    print(f'Content-Disposition: attachment; filename="{fname}"')
    print(f"X-RP-Signature: hmac-sha256={_arch_sig}")
    print("Cache-Control: no-store")
    print("X-Content-Type-Options: nosniff")
    print()
    sys.stdout.flush()
    sys.stdout.buffer.write(_arch_bytes)
    sys.stdout.buffer.flush()
    return


def handle_security_posture():
    """GET /api/security-posture — v4.2.0 (A6): grade the live config against a
    secure-defaults checklist so operators can see (and fix) what's not hardened."""
    require_admin_or_auditor_auth()
    cfg = load(CONFIG_FILE) or {}
    users = load(USERS_FILE) or {}
    checks = []

    def add(key, label, ok, detail, hint, fix_tab=None):
        # v4.3.0: fix_tab names the Settings tab that fixes this row so the UI
        # can render the hint as a one-click link instead of a config-key name.
        checks.append({'key': key, 'label': label,
                       'status': 'ok' if ok else 'warn', 'detail': detail,
                       'hint': hint, 'fix_tab': fix_tab})

    roles = cfg.get('mfa_required_roles') or []
    add('mfa_enforced', 'MFA enforced for admins', 'admin' in roles,
        f'required roles: {", ".join(roles) or "none"}',
        'Turn on "Require MFA for admin accounts" under Settings → Security → Account guardrails.', fix_tab='security')
    admins = [u for u, d in users.items() if isinstance(d, dict) and d.get('role') == 'admin']
    no_mfa = [u for u in admins
              if not (users[u].get('totp_secret') or users[u].get('webauthn_credentials'))]
    add('admin_mfa', 'All admins have MFA (TOTP or passkey)', admins and not no_mfa,
        f'{len(admins) - len(no_mfa)}/{len(admins)} have MFA',
        'Enrol TOTP or a passkey for every admin (My Account → 2FA / Passkeys; '
        'the Users table shows who is missing one).')
    add('apikey_expiry', 'API keys expire by default', int(cfg.get('apikey_default_expiry_days') or 0) > 0,
        f'default: {cfg.get("apikey_default_expiry_days") or "never"}',
        'Set a default expiry (e.g. 90 days) under Settings → Security → Account guardrails.', fix_tab='security')
    add('session_cap', 'Concurrent-session cap set', int(cfg.get('max_sessions_per_user') or 0) > 0,
        f'cap: {cfg.get("max_sessions_per_user") or "unlimited"}',
        'Set a per-user session cap (e.g. 5) under Settings → Security → Account guardrails.', fix_tab='security')
    default_pw = any(isinstance(d, dict) and d.get('must_change_password') for d in users.values())
    add('default_password', 'No accounts on a default password', not default_pw,
        'change-required account present' if default_pw else 'all changed',
        'Have flagged users change their password.')
    # Sweep fix: this guard blocks link-local / cloud-metadata targets (RFC1918
    # is allowed by design — the product targets the LAN), and it defaults ON;
    # the old row read the key without the default and claimed RFC1918, so an
    # unconfigured install showed a false warning.
    _wbl = bool(cfg.get('webhook_block_local', True))
    add('webhook_block_local', 'Webhook SSRF guard (cloud metadata / link-local)', _wbl,
        'on' if _wbl else 'off',
        'Re-enable it under Settings → Security → Account guardrails.', fix_tab='security')
    fwd = bool(cfg.get('audit_forward_enabled') or cfg.get('siem_enabled'))
    add('audit_forward', 'Audit/events forwarded to a SIEM', fwd,
        'configured' if fwd else 'not configured',
        'Configure under Settings → Security → Audit log forwarding (or SIEM event streaming).', fix_tab='security')
    _worm_p = (cfg.get('audit_worm_path') or '').strip()
    add('audit_worm', 'Append-only (WORM) audit sink', bool(_worm_p),
        _worm_p or 'not configured',
        'Set an append-only audit sink path under Settings → Security → Audit log '
        'forwarding (make it immutable with chattr +a / a WORM mount).', fix_tab='security')
    add('secrets_scan', 'Secrets-on-disk scanning enabled', bool(cfg.get('secrets_scan_enabled')),
        'on' if cfg.get('secrets_scan_enabled') else 'off',
        'Enable under Settings → Security → Secrets-on-disk scanning.', fix_tab='security')
    add('audit_retention', 'Audit-log retention ≥ 30 days', int(cfg.get('audit_log_retention_days') or 90) >= 30,
        f'{cfg.get("audit_log_retention_days") or 90}d', 'Keep audit retention at 30+ days.')
    # v4.2.0 sweep: chain integrity as a posture row — tamper-evidence that
    # only surfaces when someone clicks "Verify" isn't really evidence.
    _chk, _broken = _audit_chain_walk((load(AUDIT_LOG_FILE) or {}).get('entries', []))
    add('audit_chain', 'Audit-log hash-chain intact', _broken is None,
        f'{_chk} links verified' if _broken is None else f'BROKEN at entry #{_broken}',
        'Investigate immediately — audit entries were altered or removed.')
    # v5.4.1 enterprise-hardening controls surfaced on the posture page.
    _pml = int(cfg.get('password_min_length') or 0)
    add('password_policy', 'Password policy enforced', _pml > 0,
        f'min length {_pml}' + (', classes' if cfg.get('password_require_classes') else '')
        + (', breach-check' if cfg.get('password_breach_check') else '') if _pml else 'off',
        'Set a minimum length (12+ recommended) under Settings → Security → Password policy.',
        fix_tab='security')
    _idle = int(cfg.get('idle_timeout_minutes') or 0)
    add('idle_timeout', 'Idle session timeout set', _idle > 0,
        f'{_idle} min' if _idle else 'off',
        'Set an idle timeout (e.g. 30 min) under Settings → Security.', fix_tab='security')
    _idp = bool(cfg.get('oidc_enabled') or cfg.get('saml_enabled'))
    if _idp:   # SSO-only only matters once an IdP is configured
        add('sso_only', 'SSO-only login enforced', bool(cfg.get('sso_only')),
            'on' if cfg.get('sso_only') else 'local passwords still accepted',
            'Enable SSO-only (with a break-glass account) under Settings → Security.',
            fix_tab='security')
    # Exports are always signed now — an informational always-ok row.
    add('signed_exports', 'Compliance exports are signed',
        (DATA_DIR / 'export_sign.key').exists() or True,
        'evidence pack + audit archive carry an HMAC-SHA256 signature',
        'No action needed.')
    _offsite = ((cfg.get('backup') or {}).get('offsite_dir') or '').strip()
    add('backup_offsite', 'Backups mirrored off-host', bool(_offsite),
        _offsite or 'local-host only',
        'Set an off-host backup destination (an NFS/SMB/sshfs mount) under '
        'Settings → Maintenance → Backup, and test-restore it.', fix_tab='maintenance')
    _cfg_enc_armed = bool(_config_master_key())
    add('config_secrets_encrypted', 'Config secrets encrypted at rest', _cfg_enc_armed,
        'armed (RP_CONFIG_KEY set)' if _cfg_enc_armed else 'plaintext at rest',
        'Set the RP_CONFIG_KEY environment variable (a stable, high-entropy '
        'secret, like RP_BACKUP_PASSPHRASE) — or RP_CONFIG_KEY_CMD to fetch it '
        'from Vault/KMS — so every secret-bearing config value (SMTP/OIDC/LDAP/'
        'SIEM, ACME DNS credentials, webhook tokens, AI api_key, integration '
        'secrets) is AES-GCM encrypted in config.json.')
    ok = sum(1 for c in checks if c['status'] == 'ok')
    respond(200, {'checks': checks, 'score': ok, 'total': len(checks)})


def handle_rotate_export_key():
    """POST /api/security/rotate-export-key — v5.4.1 (C9): rotate the export-signing
    key. New evidence packs / audit-archive downloads sign with the fresh key;
    artefacts already issued keep their original signature (verify each against the
    file as it was downloaded). Admin only; audited."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    kf = DATA_DIR / 'export_sign.key'
    try:
        if kf.exists():
            kf.unlink()
    except OSError as e:
        respond(500, {'error': f'could not rotate: {e}'})
    _export_signing_key()   # regenerate immediately at 0600
    audit_log(actor, 'export_key_rotated', 'export-signing key rotated')
    respond(200, {'ok': True, 'message': 'Export-signing key rotated. New exports use the new key.'})


# ── v4.2.0 (A1): WebAuthn / passkeys ─────────────────────────────────────────
# Phishing-resistant MFA + passwordless login via py_webauthn (optional dep —
# the feature is simply unavailable when the library isn't installed).

_WEBAUTHN_MOD = None


def _webauthn():
    global _WEBAUTHN_MOD
    if _WEBAUTHN_MOD is None:
        try:
            import webauthn_auth as _wam
            _WEBAUTHN_MOD = _wam
        except Exception:
            _WEBAUTHN_MOD = False
    return _WEBAUTHN_MOD or None


def _webauthn_rp():
    """(rp_id, origin) for the ceremony — derived from the request host, or the
    config overrides (webauthn_rp_id / webauthn_origin) behind a proxy."""
    cfg = load(CONFIG_FILE) or {}
    host_full = _env('HTTP_HOST', '')
    host = host_full.split(':')[0]
    rp_id = cfg.get('webauthn_rp_id') or host
    proto = (_env('HTTP_X_FORWARDED_PROTO')
             or ('https' if _env('HTTPS') in ('on', '1') else 'http'))
    origin = cfg.get('webauthn_origin') or f'{proto}://{host_full}'
    return rp_id, origin


def _webauthn_put_challenge(username, challenge, kind):
    now = int(time.time())
    with _LockedUpdate(WEBAUTHN_CHALLENGES_FILE) as st:
        for k in list(st.keys()):   # prune expired
            if not isinstance(st[k], dict) or now - st[k].get('ts', 0) > 300:
                del st[k]
        st[f'{kind}:{username}'] = {'challenge': challenge, 'ts': now}


def _webauthn_take_challenge(username, kind):
    rec = None
    with _LockedUpdate(WEBAUTHN_CHALLENGES_FILE) as st:
        rec = st.pop(f'{kind}:{username}', None)
    if not isinstance(rec, dict) or int(time.time()) - rec.get('ts', 0) > 300:
        return None
    return rec.get('challenge')


def _webauthn_feature_on(cfg=None):
    """Passkeys are ON by default once the library is present; an operator can
    kill the feature with webauthn_enabled=false in config. Checked by every
    ceremony handler (not just cosmetically) so disabling it actually revokes
    passwordless login + new registrations."""
    cfg = cfg if cfg is not None else (load(CONFIG_FILE) or {})
    return bool(cfg.get('webauthn_enabled', True))


def _webauthn_lib_usable():
    """True when a passkey assertion can actually be performed right now
    (library installed AND feature not disabled). handle_login uses this to
    decide whether it may demand a WebAuthn step-up."""
    wa = _webauthn()
    return bool(wa and wa.available()) and _webauthn_feature_on()


def _webauthn_guard():
    wa = _webauthn()
    if not wa or not wa.available():
        respond(503, {'error': 'WebAuthn is not available on this server '
                               '(py_webauthn not installed)'})
    if not _webauthn_feature_on():
        respond(403, {'error': 'passkeys are disabled by the administrator'})
    return wa


def handle_webauthn_available():
    """GET /api/webauthn/available — is the library present + feature enabled?"""
    require_auth()
    wa = _webauthn()
    respond(200, {'available': bool(wa and wa.available()) and _webauthn_feature_on(),
                  'enabled': _webauthn_feature_on()})


def handle_webauthn_register_begin():
    user = require_auth()
    wa = _webauthn_guard()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    rp_id, _ = _webauthn_rp()
    creds = ((load(USERS_FILE) or {}).get(user) or {}).get('webauthn_credentials') or []
    opts_json, challenge = wa.registration_options(
        rp_id, 'RemotePower', user, user, [c['id'] for c in creds])
    _webauthn_put_challenge(user, challenge, 'reg')
    respond(200, json.loads(opts_json))


def handle_webauthn_register_complete():
    user = require_auth()
    wa = _webauthn_guard()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    name = _sanitize_str(str(body.get('name', 'passkey')), 64) or 'passkey'
    challenge = _webauthn_take_challenge(user, 'reg')
    if not challenge:
        respond(400, {'error': 'no pending registration (expired — try again)'})
    rp_id, origin = _webauthn_rp()
    try:
        res = wa.registration_verify(body.get('credential'), challenge, origin, rp_id)
    except Exception as e:
        respond(400, {'error': f'registration verification failed: {str(e)[:140]}'})
    with _LockedUpdate(USERS_FILE) as users:
        u = users.get(user) or {}
        creds = u.get('webauthn_credentials') or []
        if any(c.get('id') == res['credential_id'] for c in creds):
            respond(409, {'error': 'credential already registered'})
        creds.append({'id': res['credential_id'], 'public_key': res['public_key'],
                      'sign_count': res['sign_count'], 'name': name,
                      'created': int(time.time())})
        u['webauthn_credentials'] = creds
        users[user] = u
    audit_log(user, 'webauthn_register', f'name={name}')
    respond(200, {'ok': True})


def handle_webauthn_credentials_list():
    user = require_auth()
    creds = ((load(USERS_FILE) or {}).get(user) or {}).get('webauthn_credentials') or []
    respond(200, {'credentials': [{'id': c['id'], 'name': c.get('name', 'passkey'),
                                   'created': c.get('created', 0)} for c in creds]})


def handle_webauthn_credential_delete(cid):
    user = require_auth()
    if method() != 'DELETE':
        respond(405, {'error': 'Method not allowed'})
    cid = _sanitize_str(str(cid), 512)
    removed = False
    with _LockedUpdate(USERS_FILE) as users:
        u = users.get(user) or {}
        creds = u.get('webauthn_credentials') or []
        new = [c for c in creds if c.get('id') != cid]
        if len(new) != len(creds):
            u['webauthn_credentials'] = new
            users[user] = u
            removed = True
    if removed:
        audit_log(user, 'webauthn_credential_delete', f'id={cid[:16]}…')
    respond(200, {'ok': True, 'removed': removed})


def handle_webauthn_login_begin():
    wa = _webauthn_guard()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    # Unauthenticated → same per-IP budget as password login (shared bucket).
    if not _ip_ratelimit('login', _get_client_ip(), 20, window=60):
        time.sleep(0.5)
        respond(429, {'error': 'Too many attempts — wait a minute'})
    username = _sanitize_str(str((get_json_obj()).get('username', '')), 64)
    creds = ((load(USERS_FILE) or {}).get(username) or {}).get('webauthn_credentials') or []
    rp_id, _ = _webauthn_rp()
    # Anti-enumeration: unknown users / users without passkeys get a normal-
    # looking challenge with an empty allow-list (the assertion can never
    # complete — no challenge is stored), instead of a distinguishable 404
    # that leaks which usernames exist and which of them hold passkeys.
    opts_json, challenge = wa.authentication_options(rp_id, [c['id'] for c in creds])
    if creds:
        _webauthn_put_challenge(username, challenge, 'auth')
    respond(200, json.loads(opts_json))


def handle_webauthn_login_complete():
    wa = _webauthn_guard()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    # v4.3.0: same per-IP budget as password login + the begin step.
    if not _ip_ratelimit('login', _get_client_ip(), 20, window=60):
        time.sleep(0.5)
        respond(429, {'error': 'Too many attempts — wait a minute'})
    body = get_json_obj()
    username = _sanitize_str(str(body.get('username', '')), 64)
    cred = body.get('credential') or {}
    challenge = _webauthn_take_challenge(username, 'auth')
    if not challenge:
        respond(400, {'error': 'no pending authentication (expired — try again)'})
    u = (load(USERS_FILE) or {}).get(username) or {}
    if u.get('disabled'):
        respond(403, {'error': 'account disabled'})
    cred_id = cred.get('id') if isinstance(cred, dict) else None
    match = next((c for c in (u.get('webauthn_credentials') or []) if c.get('id') == cred_id), None)
    if not match:
        respond(400, {'error': 'unknown credential'})
    rp_id, origin = _webauthn_rp()
    try:
        res = wa.authentication_verify(cred, challenge, origin, rp_id,
                                       match['public_key'], match.get('sign_count', 0))
    except Exception as e:
        respond(400, {'error': f'authentication failed: {str(e)[:140]}'})
    # sign-count regression → a cloned authenticator; refuse the login.
    prev = int(match.get('sign_count', 0) or 0)
    if res['new_sign_count'] and prev and res['new_sign_count'] <= prev:
        audit_log(username, 'webauthn_signcount_regression', 'possible cloned authenticator')
        respond(403, {'error': 'authenticator sign-count regression — refused'})
    with _LockedUpdate(USERS_FILE) as users:
        uu = users.get(username) or {}
        for c in uu.get('webauthn_credentials') or []:
            if c.get('id') == cred_id:
                c['sign_count'] = res['new_sign_count']
        users[username] = uu
    # v4.2.0 sweep: honour remember-me like password login does — the UI was
    # storing "remembered" passkey sessions that still expired on the short TTL.
    token = _mint_session(username, remember_me=bool(body.get('remember_me')))
    audit_log(username, 'login_webauthn', 'passkey login')
    respond(200, {'ok': True, 'token': token, 'role': u.get('role', 'admin'),
                  'username': username,
                  'must_change_password': bool(u.get('must_change_password')),
                  'must_enroll_mfa': _mfa_enrollment_required(u)})


# ── v4.2.0 (B1): SAML 2.0 SP single-sign-on ────────────────────────────────
# Enterprise SSO via the vetted pysaml2 library + the xmlsec1 binary (BOTH
# optional — the feature reports unavailable and the handlers 503 when either is
# missing, so nothing about existing auth changes until an operator opts in).
# Mirrors the OIDC flow (handle_oidc_*): SP-initiated redirect → IdP → signed
# assertion POSTed to the ACS → verify → provision/mint → hash-fragment token
# redirect. pysaml2 does ALL signature/audience/expiry verification; we add
# InResponseTo / one-time-use replay protection via the outstanding-request store.

_SAML_MOD = None


def _saml():
    global _SAML_MOD
    if _SAML_MOD is None:
        try:
            import saml_auth as _sam
            _SAML_MOD = _sam
        except Exception:
            _SAML_MOD = False
    return _SAML_MOD or None


def _saml_base_url():
    """Public base URL (scheme://host) — same proxy-aware derivation as OIDC."""
    host = _env('HTTP_HOST', '').strip()
    scheme = 'https' if _env('HTTPS', 'on') in ('on', '1', 'true') else 'http'
    fwd = _env('HTTP_X_FORWARDED_PROTO', '').strip().lower()
    if fwd in ('http', 'https'):
        scheme = fwd
    return f'{scheme}://{host}'


def _saml_cfg():
    """Return the full config IF SAML is enabled AND fully configured, else None."""
    cfg = load(CONFIG_FILE) or {}
    if not cfg.get('saml_enabled'):
        return None
    needed = ('saml_idp_entity_id', 'saml_idp_sso_url', 'saml_idp_x509_cert')
    if not all(str(cfg.get(k) or '').strip() for k in needed):
        return None
    return cfg


def _saml_guard():
    sm = _saml()
    if not sm or not sm.available():
        respond(503, {'error': 'SAML is not available on this server '
                               '(pysaml2 and/or the xmlsec1 binary are not installed)'})
    return sm


def _saml_put_request(req_id):
    if not req_id:
        return
    now = int(time.time())
    with _LockedUpdate(SAML_REQUESTS_FILE) as st:
        for k in list(st.keys()):   # prune expired (10-min TTL)
            if not isinstance(st[k], dict) or now - st[k].get('ts', 0) > 600:
                del st[k]
        st[req_id] = {'ts': now}


def _saml_outstanding():
    """All currently-outstanding (non-expired) AuthnRequest ids as the pysaml2
    outstanding dict {req_id: came_from}; pysaml2 checks the response's
    InResponseTo against these keys (rejecting unsolicited/replayed)."""
    now = int(time.time())
    out = {}
    with _LockedUpdate(SAML_REQUESTS_FILE) as st:
        for k in list(st.keys()):
            if not isinstance(st[k], dict) or now - st[k].get('ts', 0) > 600:
                del st[k]
            else:
                out[k] = '/'
    return out


def _saml_consume_request(req_id):
    """One-time-use: drop a consumed request id so the same assertion can't be
    replayed within its validity window."""
    if not req_id:
        return
    with _LockedUpdate(SAML_REQUESTS_FILE) as st:
        st.pop(req_id, None)


def _saml_username_for(name_id, attrs, cfg):
    """Pick a stable username: the configured attribute if present, else NameID."""
    attr = str(cfg.get('saml_attr_username') or '').strip()
    if attr and attrs.get(attr):
        v = attrs[attr]
        if isinstance(v, list):
            v = v[0] if v else ''
        return _sanitize_str(str(v), 64)
    return _sanitize_str(str(name_id or ''), 64)


def _saml_role_for(attrs, cfg):
    """Map SAML group attributes to a role (mirrors _oidc_role_for). v5.4.1 (D5):
    honours the sso_group_roles matrix; legacy saml_admin_group still → admin;
    safe default is viewer."""
    groups = attrs.get(str(cfg.get('saml_attr_groups') or 'groups')) or attrs.get('roles') or []
    return _role_from_groups(groups, cfg, 'saml_admin_group')


def handle_saml_available():
    """GET /api/saml/available — library+binary present, and SAML configured?"""
    require_auth()
    sm = _saml()
    respond(200, {'available': bool(sm and sm.available()),
                  'enabled': bool(_saml_cfg())})


def handle_saml_metadata():
    """GET /api/saml/metadata — SP metadata XML to hand to the IdP (public)."""
    sm = _saml_guard()
    cfg = _saml_cfg()
    if not cfg:
        respond(503, {'error': 'SAML is not configured on this server'})
    try:
        xml = sm.metadata_xml(cfg, _saml_base_url())
    except Exception as e:
        respond(500, {'error': f'metadata generation failed: {str(e)[:140]}'})
    sys.stdout.write('Status: 200 OK\r\n')
    sys.stdout.write('Content-Type: application/samlmetadata+xml\r\n')
    sys.stdout.write('Cache-Control: no-store\r\n\r\n')
    sys.stdout.write(xml)
    sys.exit(0)


def handle_saml_login():
    """GET /api/auth/saml/login — SP-initiated SSO: 302 to the IdP (public)."""
    sm = _saml_guard()
    cfg = _saml_cfg()
    if not cfg:
        respond(503, {'error': 'SAML is not configured on this server'})
    try:
        redirect_url, req_id = sm.login_redirect(cfg, _saml_base_url())
    except Exception as e:
        respond(500, {'error': f'SAML login init failed: {str(e)[:140]}'})
    _saml_put_request(req_id)
    print('Status: 302 Found')
    print(f'Location: {redirect_url}')
    print('Cache-Control: no-store')
    print()
    sys.exit(0)


def handle_saml_acs():
    """POST /api/auth/saml/acs — Assertion Consumer Service. pysaml2 verifies the
    signature/audience/expiry; we enforce InResponseTo + one-time-use, then
    provision and mint a session, redirecting with the token in the URL hash
    (exactly like the OIDC callback so the SPA picks it up identically)."""
    sm = _saml_guard()
    # v4.3.0: per-IP rate limit on the unauthenticated, crypto-verifying ACS.
    if not _ip_ratelimit('sso', _get_client_ip(), 30, window=60):
        time.sleep(0.5)
        respond(429, {'error': 'Too many SSO attempts — wait a minute'})
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    cfg = _saml_cfg()
    if not cfg:
        respond(503, {'error': 'SAML is not configured on this server'})
    # The IdP POSTs application/x-www-form-urlencoded with SAMLResponse + RelayState.
    form = urllib.parse.parse_qs(get_body().decode('utf-8', errors='replace'))
    saml_response = (form.get('SAMLResponse', [''])[0] or '').strip()
    if not saml_response:
        respond(400, {'error': 'missing SAMLResponse'})
    outstanding = _saml_outstanding()
    if not outstanding and not cfg.get('saml_allow_unsolicited'):
        respond(400, {'error': 'no outstanding SAML request (replay or unsolicited response)'})
    try:
        res = sm.parse_response(cfg, _saml_base_url(), saml_response, outstanding)
    except Exception as e:
        audit_log('?', 'login_saml_failed', f'verification failed: {str(e)[:120]}')
        respond(400, {'error': f'SAML response rejected: {str(e)[:140]}'})
    _saml_consume_request(res.get('in_response_to'))   # one-time-use → replay guard
    username = _saml_username_for(res.get('name_id'), res.get('attributes') or {}, cfg)
    if not username:
        respond(400, {'error': 'SAML assertion has no usable username'})
    role = _saml_role_for(res.get('attributes') or {}, cfg)
    user = _provision_or_promote_user(username, role, {
        'saml_name_id': _sanitize_str(str(res.get('name_id') or ''), 128),
    }, 'saml')
    token = _mint_session(username, extra={'saml': True})
    audit_log(username, 'login_saml',
              f'authenticated via SAML (nameid={str(res.get("name_id"))[:64]})')
    safe_token = urllib.parse.quote(token, safe='')
    print('Status: 302 Found')
    print(f'Location: /#saml_token={safe_token}&role={user.get("role", "viewer")}'
          f'&username={urllib.parse.quote(username)}')
    print('Cache-Control: no-store')
    print()
    sys.exit(0)


def handle_audit_log_clear():
    actor = require_admin_auth()
    if method() != 'DELETE': respond(405, {'error': 'Method not allowed'})
    # v4.2.0 (A2): gate the wipe behind an admin-password re-prompt, and write an
    # immutable pre-wipe archive so a clear can never silently destroy evidence.
    pw = str((get_json_obj()).get('password', ''))
    u = (load(USERS_FILE) or {}).get(actor) or {}
    stored = u.get('password_hash', '') or ''
    # v4.8.0: report the precise reason instead of a single ambiguous
    # "password required" that read as "the button did nothing" when a password
    # WAS given but didn't match. A local password is one we can actually verify
    # (bcrypt / PBKDF2); an SSO/OIDC- or passkey-provisioned admin carries a
    # sentinel hash that never matches, so call that case out specifically.
    has_local_pw = stored.startswith('$2') or stored.startswith('pbkdf2$')
    if not pw:
        respond(403, {'error': 'Enter your admin password to confirm clearing the audit log.'})
    if not has_local_pw:
        respond(403, {'error': 'This account has no local password — you sign in via SSO or a passkey. '
                               'Clearing the audit log requires a local admin password: set one under '
                               'My Account, or use an admin account that has one.'})
    if not verify_password(pw, stored):
        respond(403, {'error': 'Incorrect admin password.'})
    try:
        import gzip
        cur = load(AUDIT_LOG_FILE) or {}
        arch = DATA_DIR / f'audit_log_prewipe_{int(time.time())}.jsonl.gz'
        with gzip.open(str(arch), 'wt') as f:
            for e in cur.get('entries', []):
                f.write(json.dumps(e) + '\n')
    except Exception as _aw:
        sys.stderr.write(f'[remotepower] pre-wipe audit archive failed: {_aw}\n')
    save(AUDIT_LOG_FILE, {'entries': []})
    # Log the clear itself as the first new (chained) entry
    audit_log(actor, 'clear_audit_log', 'audit log cleared (pre-wipe archived)')
    respond(200, {'ok': True})


# ── v3.2.0 (B1): alerts inbox ───────────────────────────────────────────────

def _alerts_summary(alerts):
    """Lightweight counts used by Home/sidebar badges."""
    out = {'open': 0, 'acknowledged': 0, 'resolved': 0,
           'by_severity': {'critical': 0, 'high': 0, 'medium': 0, 'low': 0}}
    for a in alerts:
        if a.get('resolved_at'):
            out['resolved'] += 1
        elif a.get('acknowledged_at'):
            out['acknowledged'] += 1
            sev = a.get('severity') or 'medium'
            out['by_severity'][sev] = out['by_severity'].get(sev, 0) + 1
        else:
            out['open'] += 1
            sev = a.get('severity') or 'medium'
            out['by_severity'][sev] = out['by_severity'].get(sev, 0) + 1
    return out


# v4.1.0: events that are plausibly downstream of a host being offline /
# unreachable — when a device_offline alert is open for a host, these fold
# under it as symptoms in the grouped inbox instead of reading as a storm.
# DERIVED from EVENT_REGISTRY's `symptom` flags: events foldable under a
# device_offline root cause in the grouped inbox.
ALERT_SYMPTOM_EVENTS = frozenset(
    ev for ev, spec in EVENT_REGISTRY.items() if spec.get('symptom'))


def _annotate_alert_correlation(alerts):
    """Tag each alert with host-level root-cause correlation, in place.

    For every host that has an OPEN ``device_offline`` alert, that alert is
    flagged ``_root_cause`` and the host's open symptom alerts (see
    ALERT_SYMPTOM_EVENTS) get ``_symptom_of`` = the offline alert's id, so the
    grouped inbox can fold a storm into one incident. Pure annotation — adds
    only ``_root_cause`` / ``_symptom_of`` keys; never changes alert state.
    Returns the same list. Open = no ack/resolve at the time of listing.
    """
    def _is_open(a):
        return not a.get('acknowledged_at') and not a.get('resolved_at')
    roots = {}   # device_id -> offline alert id
    for a in alerts:
        if (a.get('event') == 'device_offline' and a.get('device_id')
                and _is_open(a)):
            # earliest open offline per host wins as the root
            roots.setdefault(a['device_id'], a.get('id'))
    for a in alerts:
        did = a.get('device_id')
        if not did or did not in roots:
            continue
        if a.get('id') == roots[did]:
            a['_root_cause'] = True
        elif a.get('event') in ALERT_SYMPTOM_EVENTS and _is_open(a):
            a['_symptom_of'] = roots[did]
    return alerts


# v5.8.0 (B1.2): map an alert's `event` to a mitigation playbook kind so the
# Alerts page can show the same "Fix" affordance the dashboard needs-attention
# feed already has. Keys are alert event names; values are _MITIGATE_PLAYBOOKS
# keys. metric_* alerts resolve by their payload `metric` field (cpu/mem/swap/
# disk). Only tagged when a device_id is present (playbooks act on a host).
_EVENT_TO_MITIGATION = {
    'patch_alert':          'patches',
    'disk_predict_fail':    'disk',
    'smart_failure':        'hardware',
    'config_drift':         'drift',
    'drift_detected':       'drift',
    'service_down':         'service_down',
    'reboot_required':      'reboot',
    'failed_unit':          'failed_units',
    'timer_failed':         'failed_units',
    'brute_force_detected': 'brute_force',
    'cve_found':            'cve',
    'container_stopped':    'container',
    'container_restarting': 'container',
    'av_infected':          'av_posture',
    'av_warning':           'av_posture',
    'backup_stale':         'backup',
    'backup_verify_failed': 'backup',
    'ssh_key_added':        'ssh_key',
    'new_port_detected':    'new_port',
    'log_alert':            'log_alert',
}
_METRIC_TO_MITIGATION = {'cpu': 'cpu', 'memory': 'memory', 'mem': 'memory',
                         'swap': 'swap', 'disk': 'disk'}


def _annotate_alert_mitigation(alerts):
    """Tag each open alert with `mitigation_kind` (+ `mitigation_target`) when a
    remediation playbook applies to its event AND it names a device. Mirrors the
    needs-attention tagging (see the `_mitigable_kinds` loop) so the Alerts page
    and the dashboard feed offer the same Fix button. Backend-only; the frontend
    just renders when the field is present."""
    playbooks = _MITIGATE_PLAYBOOKS if '_MITIGATE_PLAYBOOKS' in globals() else {}
    for a in alerts:
        if not isinstance(a, dict) or a.get('resolved_at') or not a.get('device_id'):
            continue
        event = a.get('event') or ''
        p = a.get('payload') or {}
        kind = _EVENT_TO_MITIGATION.get(event)
        if event in ('metric_warning', 'metric_critical'):
            kind = _METRIC_TO_MITIGATION.get(str(p.get('metric') or '').lower())
        if not kind or kind not in playbooks:
            continue
        a['mitigation_kind'] = kind
        # service_down carries the unit name as the target; others don't need one.
        tgt = p.get('unit') or p.get('target') or p.get('service')
        if tgt:
            a['mitigation_target'] = tgt


def _alert_kb_map():
    """W1-23: config `alert_runbooks` maps an event name (or 'check:<check_id>'
    for a custom check) → a KB article id. Returns {} fast when unset / KB off."""
    m = _config_ro().get('alert_runbooks') or {}
    return m if isinstance(m, dict) else {}


def _annotate_alert_kb(alerts):
    """Tag each alert with `kb_link` {id, title} when its event (or its custom
    check) is mapped to a knowledge-base article in `alert_runbooks`. Read-time
    only — nothing is stored on the alert; the frontend renders a 'Runbook'
    link when present. No-op unless KB is enabled and a mapping exists."""
    mapping = _alert_kb_map()
    if not mapping or not _kb_enabled():
        return
    titles = {a.get('id'): (a.get('title') or '')
              for a in ((load(KB_FILE) or {}).get('articles') or [])}
    for a in alerts:
        if not isinstance(a, dict):
            continue
        event = a.get('event') or ''
        aid = mapping.get(event)
        if not aid:
            cid = (a.get('payload') or {}).get('check_id')
            if cid:
                aid = mapping.get('check:' + str(cid))
        if aid and aid in titles:
            a['kb_link'] = {'id': aid, 'title': titles[aid]}


def handle_alerts_list():
    """GET /api/alerts?status=open|ack|resolved|all&limit=N

    Returns newest first. `status` filter:
      - open      → no ack, no resolve  (default)
      - ack       → ack present, not resolved
      - resolved  → resolved
      - all       → everything
    """
    user = require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', ''))
    status = (qs.get('status', ['open'])[0] or 'open').lower()
    try:
        limit = max(1, min(1000, int(qs.get('limit', ['200'])[0])))
    except ValueError:
        limit = 200
    al = load(ALERTS_FILE)
    all_alerts = al.get('alerts', [])
    # v3.5.0 RBAC v2: a scoped role only sees alerts for its in-scope devices
    # (alerts with no device_id — fleet-level — stay visible).
    _scope = _caller_scope()
    if _scope is not None:
        _devs = load(DEVICES_FILE) or {}
        all_alerts = [a for a in all_alerts
                      if not a.get('device_id')
                      or _device_in_scope(_scope, _devs.get(a.get('device_id'), {}))]
    if status == 'all':
        filtered = list(all_alerts)
    elif status == 'ack':
        filtered = [a for a in all_alerts
                    if a.get('acknowledged_at') and not a.get('resolved_at')]
    elif status == 'resolved':
        filtered = [a for a in all_alerts if a.get('resolved_at')]
    else:  # open
        filtered = [a for a in all_alerts
                    if not a.get('acknowledged_at') and not a.get('resolved_at')]
    # v3.12.0: My Account → "My acked alerts" — only those this user acked.
    if (qs.get('mine', [''])[0] or '').lower() in ('1', 'true', 'yes'):
        filtered = [a for a in filtered if a.get('acknowledged_by') == user]
    filtered.reverse()  # newest first
    page = filtered[:limit]
    _annotate_alert_correlation(page)   # v4.1.0: host root-cause folding
    _annotate_alert_mitigation(page)    # v5.8.0 (B1.2): Fix-button tagging
    _annotate_alert_kb(page)            # W1-23: KB-runbook link tagging
    respond(200, {
        'alerts': page,
        'total':  len(filtered),
        'summary': _alerts_summary(all_alerts),
        # v4.1.0 (#56): tells the UI whether to prompt for an optional comment
        # when acking. Default on.
        'ack_comment_enabled': bool(_config_ro().get('ack_comment_enabled', True)),
    })


def _check_alert_mutation_perm():
    """v3.3.0 C4: gate alert ack/unack/resolve on a config flag.

    Default behaviour (viewers_can_ack_alerts=True) is unchanged from
    prior versions — any logged-in user may mutate alert state, which
    matches how operators run noisy NA queues collaboratively. When
    deployments want strict least-privilege (viewers genuinely read-
    only), they set viewers_can_ack_alerts=false and these mutations
    require admin.
    """
    cfg = load(CONFIG_FILE) or {}
    if cfg.get('viewers_can_ack_alerts', True):
        return require_auth()
    return require_admin_auth()


def _may_touch_alert_state():
    """True if the current caller may ack/resolve an alert as a SIDE EFFECT of a
    ticket action. Mirrors _check_alert_mutation_perm's policy but does NOT raise:
    when a deployment sets viewers_can_ack_alerts=false (strict least-privilege),
    the ticket op itself stays allowed but its alert side-effect is suppressed
    unless the caller is admin. (Default viewers_can_ack_alerts=true → always True.)
    """
    cfg = load(CONFIG_FILE) or {}
    if cfg.get('viewers_can_ack_alerts', True):
        return True
    _u, role = verify_token(get_token_from_request())
    return bool(_resolve_role(role).get('admin'))


def _fire_ack_webhooks(alert, user):
    """v3.12.0: fire every webhook destination flagged `on_ack` with the FULL
    alert record when it's acknowledged — the ITSM bridge (open a ticket /
    notify). Opt-in per destination, so it bypasses the per-event and
    min-priority filters. Best-effort; never raises into the ack response."""
    try:
        cfg = load(CONFIG_FILE)
    except Exception:
        return
    dests = [d for d in (cfg.get('webhook_urls') or [])
             if isinstance(d, dict) and d.get('on_ack')
             and d.get('enabled', True) and (d.get('url') or '').strip()]
    if not dests:
        return
    p = alert.get('payload') or {}
    payload = {
        'alert_id':        alert.get('id'),
        # v4.1.0 (#54): stable, human-readable id ('alertid_000001') so ITSM /
        # ticket systems can correlate the ack back to a durable reference.
        # `alert_id` (random internal key) is kept for backward compatibility.
        'alertid':         alert.get('alertid'),
        'event':           alert.get('event'),
        'severity':        alert.get('severity'),
        'title':           alert.get('title'),
        'device_id':       alert.get('device_id'),
        'device_name':     alert.get('device_name'),
        'created_at':      alert.get('ts'),
        'acknowledged_by': user,
        'acknowledged_at': alert.get('acknowledged_at'),
        'ack_note':        alert.get('ack_note', ''),
        # the original event payload fields (host/unit/cve_id/…)
        **{k: v for k, v in p.items() if k not in ('device_id', 'device_name')},
        '_server_name':    get_server_name(),
    }
    title = f"Alert acknowledged: {alert.get('title') or alert.get('event') or 'alert'}"[:256]
    message = (f"Acknowledged by {user}: {alert.get('title') or alert.get('event') or 'alert'} "
               f"(severity {alert.get('severity', '?')})")
    ticket = None
    for dest in dests:
        # Clear the normal filters — on_ack is an explicit opt-in.
        d = {**dest, 'events': None, 'min_priority': None}
        try:
            res = _dispatch_one_webhook('alert_acked', d, payload, message, title, 1)
            # v5.0.0: first ITSM destination that opened a ticket wins the link.
            if res and isinstance(res, dict) and res.get('ticket_ref') and not ticket:
                ticket = res
        except Exception as e:
            _log_webhook('alert_acked', dest.get('url', '?'), 'error',
                         f'{type(e).__name__}: {str(e)[:200]}')
    # v5.0.0: persist the opened ticket's ref/url on the alert so the UI links it.
    if ticket and alert.get('id'):
        try:
            with _LockedUpdate(ALERTS_FILE) as store:
                for a in (store.get('alerts') or []):
                    if isinstance(a, dict) and a.get('id') == alert.get('id'):
                        a['ticket_ref'] = ticket['ticket_ref'][:128]
                        a['ticket_url'] = (ticket.get('ticket_url') or '')[:512]
                        break
        except Exception:
            pass


# ── v3.12.0: My Account (per-user identity, avatar, settings) ────────────────

def handle_me():
    """GET /api/me — the current user's identity, role + granted permissions,
    2FA status, default SSH username, and whether an avatar is set. Powers the
    top-right account menu + the My Account page."""
    require_auth()
    user, role = verify_token(get_token_from_request())
    if not user:
        respond(401, {'error': 'not authenticated'})
    u = (load(USERS_FILE) or {}).get(user) or {}
    perms = _resolve_role(role)
    prefs = u.get('ui_prefs') or {}
    # v6.1.1 (#17/#15): resolve the caller's own tenant's branding override,
    # falling back to the instance-wide brand_name/brand_accent when unset
    # (or when tenancy isn't in play at all — the default tenant record
    # normally carries no override, so this is a no-op for the common case).
    _tenant_id = _user_tenant(user)
    _tenant_rec = _load_tenants().get(_tenant_id) or {}
    _cfg = load(CONFIG_FILE) or {}
    _brand_name = _tenant_rec.get('brand_name') or _cfg.get('brand_name', '')
    _brand_accent = _tenant_rec.get('brand_accent') or _cfg.get('brand_accent', '')
    respond(200, {
        'username':             user,
        'role':                 role,
        'admin':                perms['admin'],
        'permissions':          sorted(perms['permissions']),
        'scope':                perms.get('scope') or {'type': 'all'},
        'totp_enabled':         bool(u.get('totp_secret')),
        'default_ssh_username': prefs.get('default_ssh_username', ''),
        'has_avatar':           bool(u.get('avatar_mime')) and _avatar_path(user).exists(),
        'ldap':                 bool(u.get('ldap_dn')),
        'created':              u.get('created'),
        'must_change_password': bool(u.get('must_change_password')),
        'must_enroll_mfa': _mfa_enrollment_required(u),   # v4.2.0 (A3)
        # v3.14.0: per-account sidebar favorites, so they follow the user
        # across devices/browsers instead of living only in localStorage.
        'favorites':            _clean_favorites(u.get('favorites')),
        # v3.14.0 (#26): saved interface language (UI-only i18n). Default English.
        'lang':                 u.get('lang') if u.get('lang') in SUPPORTED_LANGS else 'en',
        # v3.14.0 (#24): tenant the user belongs to (foundation; 'default' for all
        # until per-tenant isolation lands).
        'tenant':               _user_tenant(user),
        # v3.14.0 (#45): in-app white-label branding, applied early by the UI.
        # v6.1.1 (#17/#15): now resolves the caller's tenant's OWN override
        # first (see above) -- the pre-auth login page has no tenant to
        # resolve yet, so it always shows the instance-wide brand.
        'brand':                {'name': _brand_name, 'accent': _brand_accent},
    })


_AVATAR_MAGIC = (
    (b'\x89PNG\r\n\x1a\n', 'image/png'),
    (b'\xff\xd8\xff',      'image/jpeg'),
    (b'GIF87a',            'image/gif'),
    (b'GIF89a',            'image/gif'),
)


def _avatar_mime(data):
    """Return the image MIME type from magic bytes, or None if not a supported
    image (png / jpeg / gif / webp). Never trusts a client-sent content type."""
    for magic, mime in _AVATAR_MAGIC:
        if data.startswith(magic):
            return mime
    if data[:4] == b'RIFF' and data[8:12] == b'WEBP':
        return 'image/webp'
    return None


def _avatar_path(user):
    safe = re.sub(r'[^A-Za-z0-9._-]', '_', str(user))[:64] or 'user'
    return AVATARS_DIR / f'{safe}.img'


def _serve_avatar(user):
    u = (load(USERS_FILE) or {}).get(user) or {}
    mime = u.get('avatar_mime')
    p = _avatar_path(user)
    if not mime or not p.exists():
        respond(404, {'error': 'no avatar'})
    data = p.read_bytes()
    print("Status: 200 OK"); print(f"Content-Type: {mime}")
    print(f"Content-Length: {len(data)}"); print("Cache-Control: no-store")
    print("X-Content-Type-Options: nosniff"); print()
    sys.stdout.flush(); sys.stdout.buffer.write(data); sys.stdout.buffer.flush()
    sys.exit(0)


def handle_me_avatar():
    """GET/POST/DELETE /api/me/avatar — the current user's profile picture.
    Stored as a validated image file in AVATARS_DIR/<user>.img (file on disk,
    outside the JSON/SQLite store) with the MIME recorded in the user record."""
    require_auth()
    user, _role = verify_token(get_token_from_request())
    if not user:
        respond(401, {'error': 'not authenticated'})
    m = method()
    if m == 'GET':
        _serve_avatar(user)
        return
    if m == 'POST':
        data = get_body()
        if not data:
            respond(400, {'error': 'empty body — POST the raw image bytes'})
        if len(data) > MAX_AVATAR_BYTES:
            respond(413, {'error': f'image too large (max {MAX_AVATAR_BYTES // 1024} KB)'})
        mime = _avatar_mime(data)
        if not mime:
            respond(400, {'error': 'not a valid image (png, jpeg, gif or webp)'})
        try:
            AVATARS_DIR.mkdir(parents=True, exist_ok=True, mode=0o700)
            _avatar_path(user).write_bytes(data)
        except OSError as e:
            respond(500, {'error': f'could not store avatar: {e}'})
        with _LockedUpdate(USERS_FILE) as users:
            if user in users:
                users[user]['avatar_mime'] = mime
        audit_log(user, 'avatar_set', f'{len(data)} bytes {mime}')
        respond(200, {'ok': True, 'mime': mime})
        return
    if m == 'DELETE':
        try:
            _avatar_path(user).unlink(missing_ok=True)
        except OSError:
            pass
        with _LockedUpdate(USERS_FILE) as users:
            if user in users:
                users[user].pop('avatar_mime', None)
        audit_log(user, 'avatar_clear', '')
        respond(200, {'ok': True})
        return
    respond(405, {'error': 'Method not allowed'})


def _session_id(token):
    """Stable, non-reversible handle for a session token — exposed to the UI so
    the raw token (the secret) never leaves the server."""
    return hashlib.sha256(token.encode()).hexdigest()[:16]


def handle_me_sessions():
    """GET /api/me/sessions — the current user's active login sessions.

    Session tokens only (not API keys). The raw token is never returned; each
    session is identified by a one-way `id` used for revocation.
    """
    require_auth()
    user, _role = verify_token(get_token_from_request())
    if not user:
        respond(401, {'error': 'not authenticated'})
    cur = _session_id(get_token_from_request())
    now = int(time.time())
    out = []
    for tok, e in (load(TOKENS_FILE) or {}).items():
        if not isinstance(e, dict) or e.get('user') != user:
            continue
        ttl = e.get('ttl', TOKEN_TTL)
        if now - int(e.get('created', 0)) > ttl:
            continue  # expired but not yet swept
        out.append({
            'id':       _key_session_id(tok),
            'current':  _key_session_id(tok) == cur,
            'ip':       _sanitize_str(str(e.get('ip', '')), 64),
            'ua':       _sanitize_str(str(e.get('ua', '')), 256),
            'created':  int(e.get('created', 0)),
            'last_seen': int(e.get('last_seen', e.get('created', 0))),
        })
    out.sort(key=lambda s: s['last_seen'], reverse=True)
    respond(200, {'sessions': out, 'count': len(out)})


def handle_me_session_revoke(sid):
    """DELETE /api/me/sessions/<id> — revoke one of the current user's sessions
    by its one-way id. A user can only revoke their own sessions."""
    user = require_auth()
    if method() != 'DELETE':
        respond(405, {'error': 'Method not allowed'})
    revoked = False
    with _LockedUpdate(TOKENS_FILE) as tokens:
        for tok in list(tokens.keys()):
            e = tokens.get(tok)
            if isinstance(e, dict) and e.get('user') == user and _key_session_id(tok) == sid:
                del tokens[tok]
                revoked = True
                break
    if not revoked:
        respond(404, {'error': 'session not found'})
    audit_log(user, 'session_revoke', f'id={sid}')
    respond(200, {'ok': True})


def handle_me_sessions_revoke_others():
    """POST /api/me/sessions/revoke-others — revoke all of the current user's
    sessions except the one making this request."""
    user = require_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    cur = _session_id(get_token_from_request())
    n = 0
    with _LockedUpdate(TOKENS_FILE) as tokens:
        for tok in list(tokens.keys()):
            e = tokens.get(tok)
            if isinstance(e, dict) and e.get('user') == user and _key_session_id(tok) != cur:
                del tokens[tok]
                n += 1
    audit_log(user, 'session_revoke_others', f'count={n}')
    respond(200, {'ok': True, 'revoked': n})


