    audit_log(user, 'alert_ack', f'id={alert_id}' + (f' note={note[:80]}' if note else ''))
    # Fire ack webhooks AFTER releasing the lock (HTTP POSTs are slow).
    _fire_ack_webhooks(acked_alert, user)
