def _public_action_page(title, message):
    """Emit a tiny self-contained sandboxed HTML page for a public one-click
    action endpoint (alert ack/resolve email links). Exits the process."""
    import html as _h
    doc = (
        '<!doctype html><meta charset="utf-8">'
        '<meta name="viewport" content="width=device-width,initial-scale=1">'
        '<title>' + _h.escape(title) + '</title>'
        '<div style="font-family:-apple-system,Segoe UI,Roboto,Arial,sans-serif;'
        'max-width:480px;margin:12vh auto;padding:24px;text-align:center;color:#16181d">'
        '<div style="font-size:20px;font-weight:700;margin-bottom:10px">'
        + _h.escape(title) + '</div>'
        '<div style="font-size:15px;line-height:1.6;color:#41474f">'
        + _h.escape(message) + '</div></div>'
    ).encode('utf-8')
    print("Status: 200 OK")
    print("Content-Type: text/html; charset=utf-8")
    print(f"Content-Length: {len(doc)}")
    print("Cache-Control: no-store")
    print("X-Content-Type-Options: nosniff")
    print("Content-Security-Policy: default-src 'none'; style-src 'unsafe-inline'; sandbox;")
    print("X-Frame-Options: DENY")
    print()
    sys.stdout.flush()
    sys.stdout.buffer.write(doc)
    sys.stdout.buffer.flush()
    sys.exit(0)


def handle_alert_act():
    """GET /api/alerts/act?a=&op=ack|resolve&s= — PUBLIC one-click alert action
    from a signed email link (W1-21). No login; the HMAC signature is the
    capability. Idempotent: acking/resolving an already-closed alert just reports
    the current state. Renders a tiny HTML page (opened in a browser)."""
    if method() != 'GET':
        respond(405, {'error': 'Method not allowed'})
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    aid = (qs.get('a') or [''])[0]
    op = (qs.get('op') or [''])[0]
    sig = (qs.get('s') or [''])[0]
    if op not in ('ack', 'resolve') or not aid:
        _public_action_page('Invalid link', 'This action link is not valid.')
    if not hmac.compare_digest(sig, _alert_act_sig(aid, op)):
        _public_action_page('Invalid link', 'This action link is not valid or has expired.')
    now = int(time.time())
    found = False
    state = ''
    with _LockedUpdate(ALERTS_FILE) as store:
        a = next((x for x in store.get('alerts', []) if x.get('id') == aid), None)
        if a:
            found = True
            if a.get('resolved_at'):
                state = 'resolved'
            elif op == 'ack':
                if a.get('acknowledged_at'):
                    state = 'acked'
                else:
                    a['acknowledged_by'] = 'email-link'
                    a['acknowledged_at'] = now
                    state = 'ack-done'
            else:   # resolve
                a['resolved_by'] = 'email-link'
                a['resolved_at'] = now
                if not a.get('acknowledged_at'):
                    a['acknowledged_by'] = 'email-link'
                    a['acknowledged_at'] = now
                state = 'resolve-done'
    if not found:
        _public_action_page('Not found', 'That alert no longer exists.')
    audit_log('email-link', 'alert_' + op, f'id={aid} via=email state={state}')
    _MSG = {
        'resolved':      'This alert is already resolved.',
        'acked':         'This alert was already acknowledged.',
        'ack-done':      'Alert acknowledged. Thank you.',
        'resolve-done':  'Alert resolved. Thank you.',
    }
    _public_action_page('Done', _MSG.get(state, 'Done.'))


def _alert_resolution_how(a):
    """Classify how a resolved alert was closed (for the MTTR timeline)."""
    rb = a.get('resolved_by')
    if rb == 'auto':
        return 'auto'           # a recover event auto-resolved it
    if rb == 'exposure-mute':
        return 'muted'
    if rb:
        return 'manual'         # an operator resolved it (rb is a username)
    return 'unknown'


def handle_alert_resolution_stats():
    """GET /api/alerts/resolution-stats?days=N — time-to-resolution (MTTR) and
    time-to-ack (MTTA) analytics over recently-resolved alerts: overall mean /
    median, a per-host breakdown, and a timeline of how each was resolved
    (auto / manual / muted, by whom, with the ack/resolve note). Read-only.

    Pairs with the ack-webhook: 'manual' rows carry the operator who acked /
    resolved, so you can see who closed what and how fast."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    try:
        days = int(qs.get('days', ['30'])[0] or '30')
    except ValueError:
        days = 30
    days = max(1, min(365, days))
    cutoff = int(time.time()) - days * 86400
    store = load(ALERTS_FILE) or {}
    alerts = store.get('alerts', []) if isinstance(store, dict) else []
    resolved = [a for a in alerts if isinstance(a, dict) and a.get('resolved_at')
                and int(a.get('resolved_at') or 0) >= cutoff]
    mttrs, mttas, per_host, timeline = [], [], {}, []
    for a in resolved:
        ts = int(a.get('ts') or 0)
        rat = int(a.get('resolved_at') or 0)
        aat = int(a.get('acknowledged_at') or 0)
        mttr = max(0, rat - ts) if ts else None
        mtta = max(0, aat - ts) if (ts and aat) else None
        if mttr is not None:
            mttrs.append(mttr)
        if mtta is not None:
            mttas.append(mtta)
        host = a.get('device_name') or a.get('device_id') or 'fleet'
        h = per_host.setdefault(host, {'host': host, 'count': 0, '_sum': 0, '_n': 0})
        h['count'] += 1
        if mttr is not None:
            h['_sum'] += mttr
            h['_n'] += 1
        timeline.append({
            'id': a.get('id'), 'alertid': a.get('alertid'), 'title': a.get('title'),
            'severity': a.get('severity'), 'event': a.get('event'), 'host': host,
            'ts': ts, 'resolved_at': rat, 'mttr': mttr,
            'how': _alert_resolution_how(a), 'resolved_by': a.get('resolved_by'),
            'acknowledged_by': a.get('acknowledged_by'),
            'note': a.get('resolve_note') or a.get('ack_note') or '',
        })
    timeline.sort(key=lambda x: x['resolved_at'], reverse=True)

    def _mean(xs):
        return int(sum(xs) / len(xs)) if xs else 0

    def _median(xs):
        if not xs:
            return 0
        s = sorted(xs)
        n = len(s)
        return s[n // 2] if n % 2 else (s[n // 2 - 1] + s[n // 2]) // 2

    hosts = sorted(per_host.values(), key=lambda x: -x['count'])
    for h in hosts:
        h['mttr_mean'] = int(h['_sum'] / h['_n']) if h['_n'] else 0
        h.pop('_sum', None)
        h.pop('_n', None)
    respond(200, {
        'days': days, 'resolved_count': len(resolved),
        'mttr_mean': _mean(mttrs), 'mttr_median': _median(mttrs), 'mtta_mean': _mean(mttas),
        'hosts': hosts[:50], 'timeline': timeline[:100],
    })


def handle_alert_resolve(alert_id):
    """POST /api/alerts/<id>/resolve — manual close (auto-resolve runs via recover events)."""
    user = _check_alert_mutation_perm()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    note = _sanitize_str(body.get('note', ''), 256)
    found = False
    try:
        with _LockedUpdate(ALERTS_FILE) as store:
            for a in store.get('alerts', []):
                if a.get('id') == alert_id:
                    if a.get('resolved_at'):
                        respond(409, {'error': 'alert already resolved'})
                    now = int(time.time())
                    a['resolved_by'] = user
                    a['resolved_at'] = now
                    if not a.get('acknowledged_at'):
                        # Resolve implies ack
                        a['acknowledged_by'] = user
                        a['acknowledged_at'] = now
                    if note:
                        a['resolve_note'] = note
                    found = True
                    break
    except Exception as e:
        respond(500, {'error': str(e)})
    if not found:
        respond(404, {'error': 'alert not found'})
    audit_log(user, 'alert_resolve', f'id={alert_id}' + (f' note={note[:80]}' if note else ''))
    respond(200, {'ok': True})


# ── v5.6.0: alert mutes + tuning ────────────────────────────────────────────
# A mute silences one exact (host, event): no inbox row, no webhook, no
# needs-attention — but fleet_events keeps recording it, so the Monitoring →
# Tuning page can still surface the noisiest sources and let you lift a mute.
# Permanent until removed. Muting is an admin tuning action; listing is open to
# any authenticated user (the Tuning page is read-for-all, mute-for-admins).

def handle_alert_mutes():
    """GET /api/alert-mutes — list mutes (auth). POST — add one (admin).
    POST body: {device_id, event[, device_name]} OR {alert_id} (the X button on
    an alert row derives device+event from the alert)."""
    if method() == 'GET':
        require_auth()
        respond(200, {'ok': True, 'mutes': _alert_mutes_load()['mutes']})
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    actor = require_admin_auth()
    body = get_json_obj()
    device_id = _sanitize_str(body.get('device_id', ''), 64).strip()
    event = _sanitize_str(body.get('event', ''), 64).strip()
    device_name = _sanitize_str(body.get('device_name', ''), 128).strip()
    alert_id = _sanitize_str(body.get('alert_id', ''), 64).strip()
    if alert_id and not (device_id and event):
        a = next((x for x in (load(ALERTS_FILE) or {}).get('alerts', [])
                  if x.get('id') == alert_id), None)
        if not a:
            respond(404, {'error': 'alert not found'})
        device_id = device_id or (a.get('device_id') or '')
        event = event or (a.get('event') or '')
        device_name = device_name or (a.get('device_name') or '')
    if not device_id or not event:
        respond(400, {'error': 'device_id and event are required (or a resolvable alert_id)'})
    data = _alert_mutes_load()
    existing = next((m for m in data['mutes']
                     if m.get('device_id') == device_id and m.get('event') == event), None)
    if existing:
        mute_id = existing['id']     # idempotent — already muted
    else:
        if len(data['mutes']) >= MAX_ALERT_MUTES:
            respond(400, {'error': 'alert-mute limit reached'})
        mute = {'id': secrets.token_urlsafe(8), 'device_id': device_id,
                'device_name': device_name, 'event': event,
                'created': int(time.time()), 'created_by': actor}
        data['mutes'].append(mute)
        save(ALERT_MUTES_FILE, data)
        mute_id = mute['id']
        audit_log(actor, 'alert_mute_add', detail=f'device={device_id} event={event}')
    # Clear the noise now: resolve any currently-open alerts matching the mute.
    resolved = 0
    with _LockedUpdate(ALERTS_FILE) as store:
        now = int(time.time())
        for a in store.get('alerts', []):
            if (a.get('device_id') == device_id and a.get('event') == event
                    and not a.get('resolved_at')):
                a['resolved_by'] = 'muted'
                a['resolved_at'] = now
                if not a.get('acknowledged_at'):
                    a['acknowledged_by'] = actor
                    a['acknowledged_at'] = now
                resolved += 1
    respond(200, {'ok': True, 'id': mute_id, 'resolved': resolved})


def handle_alert_mute_delete(mute_id):
    """DELETE /api/alert-mutes/{id} (admin) — lift a mute."""
    actor = require_admin_auth()
    if method() != 'DELETE':
        respond(405, {'error': 'Method not allowed'})
    data = _alert_mutes_load()
    n = len(data['mutes'])
    data['mutes'] = [m for m in data['mutes'] if m.get('id') != mute_id]
    if len(data['mutes']) == n:
        respond(404, {'error': 'mute not found'})
    save(ALERT_MUTES_FILE, data)
    audit_log(actor, 'alert_mute_delete', detail=f'mute={mute_id}')
    respond(200, {'ok': True})


def handle_alert_tuning():
    """GET /api/alert-tuning?days=N — the noisiest (host, event) pairs and event
    sources from fleet_events (the timeline), each flagged with its mute state.
    Powers the Monitoring → Tuning page."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    try:
        days = int((qs.get('days') or ['30'])[0])
    except ValueError:
        days = 30
    days = max(1, min(days, 365))
    cutoff = int(time.time()) - days * 86400
    events = (load(FLEET_EVENTS_FILE) or {}).get('events') or []
    pair_counts = {}     # (device_id, device_name, event) -> count
    src_counts = {}      # event -> count
    for e in events:
        if not isinstance(e, dict) or int(e.get('ts', 0) or 0) < cutoff:
            continue
        ev = e.get('event') or ''
        p = e.get('payload') or {}
        if not ev or not _alert_severity(ev, p):   # only alert-able events are "noise"
            continue
        src_counts[ev] = src_counts.get(ev, 0) + 1
        dev_id = p.get('device_id') or ''
        if dev_id:
            key = (dev_id, p.get('device_name') or dev_id, ev)
            pair_counts[key] = pair_counts.get(key, 0) + 1
    muted = _alert_mute_set()

    def _dname(dev_id, fallback=''):
        # fleet_events rarely carry device_name → resolve the live hostname so
        # the page shows "tviapp01", not the opaque device id.
        try:
            d = device_get(dev_id) or {}
        except Exception:
            d = {}
        return d.get('name') or fallback or dev_id

    pairs = [{'device_id': k[0], '_fallback': k[1], 'event': k[2], 'count': c,
              'muted': (k[0], k[2]) in muted} for k, c in pair_counts.items()]
    pairs.sort(key=lambda x: x['count'], reverse=True)
    top = pairs[:10]
    for p in top:
        p['device_name'] = _dname(p['device_id'], p.pop('_fallback'))
    sources = sorted(({'event': ev, 'count': c} for ev, c in src_counts.items()),
                     key=lambda x: x['count'], reverse=True)
    mutes = []
    for m in _alert_mutes_load()['mutes']:
        mm = dict(m)
        mm['device_name'] = _dname(m.get('device_id', ''), m.get('device_name', ''))
        mutes.append(mm)
    respond(200, {'ok': True, 'days': days, 'noisy': top,
                  'sources': sources[:10], 'mutes': mutes})


def handle_alerts_bulk_resolve():
    """POST /api/alerts/bulk-resolve — admin-only, resolves matching open/ack alerts.

    Body: {ids: [...]} or {event: 'device_offline', device_id: '...'}
    Used by the Alerts page "Resolve selected" button.
    """
    user = require_admin_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    ids = body.get('ids') or []
    if not isinstance(ids, list) or not ids:
        respond(400, {'error': 'ids list required'})
    ids_set = {str(i) for i in ids}
    resolved = 0
    try:
        with _LockedUpdate(ALERTS_FILE) as store:
            now = int(time.time())
            for a in store.get('alerts', []):
                if a.get('id') in ids_set and not a.get('resolved_at'):
                    a['resolved_by'] = user
                    a['resolved_at'] = now
                    if not a.get('acknowledged_at'):
                        a['acknowledged_by'] = user
                        a['acknowledged_at'] = now
                    resolved += 1
    except Exception as e:
        respond(500, {'error': str(e)})
    audit_log(user, 'alert_bulk_resolve', f'count={resolved}')
    respond(200, {'ok': True, 'resolved': resolved})


def handle_alerts_bulk_ack():
    """POST /api/alerts/bulk-ack — v4.1.0 (#53): acknowledge several alerts at
    once from the Alerts page "Ack selected" button.

    Body: {ids: [...], note: optional comment applied to all}

    Same permission gate as single ack (`viewers_can_ack_alerts`), unlike
    bulk-resolve which is admin-only — acking is the lower-privilege action.
    Each newly-acked alert fires the on_ack webhook (so #54's `alertid` and
    the #56 note flow through identically to a single ack)."""
    user = _check_alert_mutation_perm()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    ids = body.get('ids') or []
    if not isinstance(ids, list) or not ids:
        respond(400, {'error': 'ids list required'})
    note = _sanitize_str(body.get('note', ''), 256)
    ids_set = {str(i) for i in ids}
    acked_alerts = []
    try:
        with _LockedUpdate(ALERTS_FILE) as store:
            now = int(time.time())
            for a in store.get('alerts', []):
                # Only ack rows that are open (not resolved, not already acked),
                # so re-running over a mixed selection is idempotent.
                if (a.get('id') in ids_set and not a.get('resolved_at')
                        and not a.get('acknowledged_at')):
                    a['acknowledged_by'] = user
                    a['acknowledged_at'] = now
                    if note:
                        a['ack_note'] = note
                    acked_alerts.append(dict(a))   # snapshot for the webhook
    except Exception as e:
        respond(500, {'error': str(e)})
    audit_log(user, 'alert_bulk_ack', f'count={len(acked_alerts)}'
              + (f' note={note[:80]}' if note else ''))
    # Fire ack webhooks AFTER releasing the lock (HTTP POSTs are slow).
    for a in acked_alerts:
        _fire_ack_webhooks(a, user)
    respond(200, {'ok': True, 'acked': len(acked_alerts)})


def handle_alerts_summary():
    """GET /api/alerts/summary — small counts payload for sidebar badge."""
    require_auth()
    al = load(ALERTS_FILE)
    respond(200, _alerts_summary(al.get('alerts', [])))


def handle_board():
    """v5.0.0 (T6): ``GET /api/board?by=group|site|tag`` — NOC status-board data.
    Scope-filtered and computed server-side so it stays SMALL on a 1000-node
    fleet: group/site/tag ROLLUP tiles + a capped problem-host strip + totals —
    never 1000 raw tiles."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    by = (qs.get('by') or ['group'])[0]
    if by not in ('group', 'site', 'tag'):
        by = 'group'
    now = int(time.time())
    try:
        ttl = get_online_ttl()
    except Exception:
        ttl = 180
    devices = _scope_filter_devices(load(DEVICES_FILE) or {})
    # Open high/critical alerts → which hosts read as 'warn' (online but alerting).
    alerted = {}
    try:
        for a in (load(ALERTS_FILE) or {}).get('alerts', []):
            if a.get('resolved_at'):
                continue
            did = a.get('device_id')
            if did and str(a.get('severity', '')).lower() in ('critical', 'high'):
                alerted.setdefault(did, a.get('title') or a.get('event') or 'alert')
    except Exception:
        pass

    def _status(did, d):
        if d.get('monitored') is False:
            return 'idle'
        if d.get('agentless'):
            online = _agentless_online(d)
        else:
            ls = d.get('last_seen', 0)
            online = bool(ls) and (now - ls) < ttl
        if not online:
            return 'down'
        return 'warn' if did in alerted else 'ok'

    totals = {'total': 0, 'ok': 0, 'down': 0, 'warn': 0, 'idle': 0, 'agentless': 0}
    tiles = {}
    problems = []
    for did, d in devices.items():
        if not isinstance(d, dict):
            continue
        st = _status(did, d)
        totals['total'] += 1
        totals[st] += 1
        if d.get('agentless'):
            totals['agentless'] += 1
        if st in ('down', 'warn') and len(problems) < 80:
            problems.append({'id': did, 'name': d.get('name', did), 'status': st,
                             'reason': 'offline' if st == 'down' else alerted.get(did, 'alert')})
        if by == 'tag':
            keys = [t for t in (d.get('tags') or []) if t] or ['(untagged)']
        elif by == 'site':
            keys = [d.get('site_id') or d.get('site') or '(no site)']
        else:
            keys = [d.get('group') or '(no group)']
        for k in keys:
            t = tiles.setdefault(str(k), {'key': str(k), 'name': str(k),
                                          'total': 0, 'ok': 0, 'down': 0, 'warn': 0, 'idle': 0})
            t['total'] += 1
            t[st] += 1
    tile_list = list(tiles.values())
    tile_list.sort(key=lambda t: (-t['down'], -t['warn'], -t['total']))
    tile_list = tile_list[:120]
    problems.sort(key=lambda p: 0 if p['status'] == 'down' else 1)
    respond(200, {'by': by, 'totals': totals, 'tiles': tile_list, 'problems': problems})


def handle_network_metrics():
    """v5.0.0: ``GET /api/network-metrics?by=fleet|group|tag|site`` — per-device
    network throughput (RX/TX bits/sec from the agent's `network_io` samples),
    scope-filtered and optionally rolled up by group / tag / site (a site
    represents a customer). Fleet-wide totals + the top talkers + rollup tiles.

    Telemetry view: shows unmonitored / decommissioned hosts too (flagged), per
    the unmonitored-data-visibility principle — only alerting suppresses them."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    by = (qs.get('by') or ['fleet'])[0]
    _site_names = {sid: (st.get('name') or sid)
                   for sid, st in (load(SITES_FILE) or {}).items()
                   if isinstance(st, dict)}
    if by not in ('fleet', 'group', 'tag', 'site'):
        by = 'fleet'
    devices = _scope_filter_devices(load(DEVICES_FILE) or {})

    def _dev_io(d):
        rx = tx = 0
        ifaces = []
        for nio in ((d.get('sysinfo') or {}).get('network_io') or []):
            if not isinstance(nio, dict):
                continue
            r = int(nio.get('rx_bps') or 0)
            t = int(nio.get('tx_bps') or 0)
            rx += r
            tx += t
            ifaces.append({'iface': nio.get('iface', ''), 'rx_bps': r, 'tx_bps': t})
        ifaces.sort(key=lambda i: -(i['rx_bps'] + i['tx_bps']))
        return rx, tx, ifaces[:12]

    rows = []
    totals = {'rx_bps': 0, 'tx_bps': 0, 'devices': 0, 'reporting': 0}
    tiles = {}
    for did, d in devices.items():
        if not isinstance(d, dict):
            continue
        rx, tx, ifaces = _dev_io(d)
        reporting = bool(ifaces)
        totals['devices'] += 1
        if reporting:
            totals['reporting'] += 1
        totals['rx_bps'] += rx
        totals['tx_bps'] += tx
        _sid = d.get('site_id') or d.get('site') or ''
        rows.append({
            'id': did, 'name': d.get('name', did), 'group': d.get('group', ''),
            # display NAME, not the raw site id (the id leaked into the
            # per-device throughput table)
            'site': _site_names.get(_sid, _sid) if _sid else '',
            'tags': d.get('tags') or [], 'rx_bps': rx, 'tx_bps': tx,
            'ifaces': ifaces, 'reporting': reporting,
            'monitored': d.get('monitored', True) is not False,
            'decommissioned': bool(d.get('decommissioned')),
        })
        if by != 'fleet':
            if by == 'tag':
                keys = [t for t in (d.get('tags') or []) if t] or ['(untagged)']
            elif by == 'site':
                keys = [_sid or '(no site)']
            else:
                keys = [d.get('group') or '(no group)']
            for k in keys:
                _nm = _site_names.get(str(k), str(k)) if by == 'site' else str(k)
                ti = tiles.setdefault(str(k), {'key': str(k), 'name': _nm,
                                               'rx_bps': 0, 'tx_bps': 0, 'devices': 0})
                ti['rx_bps'] += rx
                ti['tx_bps'] += tx
                ti['devices'] += 1

    rows.sort(key=lambda r: -(r['rx_bps'] + r['tx_bps']))
    rows = rows[:300]
    tile_list = sorted(tiles.values(), key=lambda t: -(t['rx_bps'] + t['tx_bps']))[:120]
    respond(200, {'by': by, 'totals': totals, 'tiles': tile_list, 'devices': rows})


def handle_nav_counts():
    """GET /api/nav-counts — tiny per-sidebar-group "needs attention" counts for
    the group-header badges. Scope-filtered, best-effort, cheap (three small
    reads on a 60s cadence). Each is shown only when > 0.

      fleet      → offline monitored devices
      monitoring → monitors currently down (latest result per target)
      security   → critical CVE findings on monitored hosts

    v4.2.0 sweep (perf): also carries the alerts-summary counts and the
    pending-MCP-confirmations count, so the sidebar's 60s badge poll is ONE
    CGI spawn per tab instead of three (/alerts/summary + /confirmations +
    /nav-counts each paid interpreter start + full import).
    """
    require_auth()
    try:
        _nc_role = verify_token(get_token_from_request())[1] or 'viewer'
    except Exception:
        _nc_role = 'viewer'
    now = int(time.time())
    # v4.10.0 (perf): file-cache the badge counts for ~15s, keyed by the caller's
    # scope (the counts are scope-filtered). At fleet scale this collapses every
    # operator's 60s sidebar poll from N full-fleet reads to one recompute per
    # scope per 15s. Busted when any source file changes. Mirrors
    # _fleet_risk_cached, and uses backend_mtime/backend_exists so the cache
    # is live on the SQLite/Postgres backend too (a raw .exists()/.stat() left
    # it permanently cold under a DB backend — this is the prod default).
    _nc_admin = bool(_resolve_role(_nc_role).get('admin'))
    try:
        _nc_scope = _caller_scope()
        _nc_skey = ('all' if _nc_scope is None
                    else hashlib.md5(json.dumps(_nc_scope, sort_keys=True).encode(),
                                     usedforsecurity=False).hexdigest()[:12])
    except Exception:
        _nc_skey = 'x'
    _nc_skey += '_a' if _nc_admin else '_n'
    _nc_cache = DATA_DIR / f'nav_counts_cache_{_nc_skey}.json'
    try:
        if backend_exists(_nc_cache):
            _cmt = backend_mtime(_nc_cache)
            if (time.time() - _cmt) < 15:
                _fresh = True
                for _src in (DEVICES_FILE, MON_HIST_FILE, CVE_FINDINGS_FILE,
                             ALERTS_FILE, CONFIRMATIONS_FILE, CMDS_FILE,
                             TICKETS_FILE):
                    try:
                        if backend_mtime(_src) > _cmt:
                            _fresh = False
                            break
                    except Exception:
                        pass
                if _fresh:
                    _c = load(_nc_cache)
                    if isinstance(_c, dict):
                        respond(200, _c)
                        return
    except Exception:
        pass
    try:
        ttl = get_online_ttl()
    except Exception:
        ttl = 180
    devices = _scope_filter_devices(load(DEVICES_FILE) or {})
    offline = 0
    for did, d in devices.items():
        if not isinstance(d, dict) or d.get('monitored') is False:
            continue
        if d.get('agentless'):
            if not _agentless_online(d):
                offline += 1
        else:
            ls = d.get('last_seen', 0)
            if not ls or (now - ls) >= ttl:
                offline += 1
    down = 0
    try:
        cut = now - 3600
        for v in (load(MON_HIST_FILE) or {}).values():
            if (isinstance(v, list) and v and isinstance(v[-1], dict)
                    and (v[-1].get('ts') or 0) >= cut and not v[-1].get('ok')):
                down += 1
    except Exception:
        pass
    crit = 0
    try:
        ids = set(devices)
        for did, rec in (load(CVE_FINDINGS_FILE) or {}).items():
            if did not in ids:
                continue
            crit += sum(1 for f in (rec or {}).get('findings') or []
                        if str(f.get('severity', '')).lower() == 'critical')
    except Exception:
        pass
    out = {'fleet': offline, 'monitoring': down, 'security': crit}
    # v5.6.0: RemotePower's OWN control-plane health for the top-bar pill —
    # storage reachable + config loads + disk headroom on the data dir. This is
    # deliberately distinct from the fleet vitals above: the pill is green unless
    # the SERVER itself is unhealthy, not when a monitored device has an alert.
    # Cheap (one statvfs); returns only check names, no fleet or sensitive data.
    try:
        _sh_fail = []
        try:
            _sh_cfg = load(CONFIG_FILE)
            if not isinstance(_sh_cfg, dict):
                _sh_fail.append('Config')
                _sh_cfg = {}
        except Exception:
            _sh_fail.append('Storage')
            _sh_cfg = {}
        try:
            _st = os.statvfs(str(DATA_DIR))
            _tot = _st.f_blocks * _st.f_frsize
            _free = _st.f_bavail * _st.f_frsize
            _used = (1 - _free / _tot) * 100 if _tot else 0
            try:
                _thr = int(_sh_cfg.get('disk_watchdog_pct', 85))
            except (TypeError, ValueError):
                _thr = 85
            if _thr > 0 and _used >= _thr:
                _sh_fail.append('Disk space')
        except Exception:
            _sh_fail.append('Disk space')
        out['site_health'] = {'healthy': not _sh_fail,
                              'issues': len(_sh_fail), 'failing': _sh_fail}
    except Exception:
        pass
    try:
        out['alerts'] = _alerts_summary((load(ALERTS_FILE) or {}).get('alerts', []))
    except Exception:
        pass
    # v5.5.0: carry the open-ticket count so the sidebar Tickets badge stays live
    # on the 60s poll (it used to only refresh on a full dashboard load → the
    # badge lingered after a ticket was resolved until the user reloaded).
    try:
        if _tickets_enabled():
            out['tickets_open'] = sum(
                1 for t in ((load(TICKETS_FILE) or {}).get('tickets') or [])
                if t.get('status') in ('ongoing', 'pending_customer', 'pending_internal'))
        else:
            out['tickets_open'] = 0
    except Exception:
        pass
    if _resolve_role(_nc_role).get('admin'):
        # Read-only pending count (no prune here — the Confirmations page's
        # own loader keeps doing the locked prune + expiry events).
        # v4.6.0 (SECURITY): resolved-role gate, not a string denylist (a custom
        # role is neither 'viewer' nor 'mcp' → must not see admin-only counts).
        try:
            arr = (load(CONFIRMATIONS_FILE) or {}).get('confirmations', [])
            out['confirmations_pending'] = sum(
                1 for c in arr
                if isinstance(c, dict) and c.get('status') == 'pending'
                and now - (c.get('requested_at') or 0) <= CONFIRMATION_TTL_SEC)
        except Exception:
            pass
        # v5.0.0 (#U4): total commands waiting to be delivered to agents, so the
        # Command Queue nav item can show a live "N pending" badge.
        try:
            cmds = load(CMDS_FILE) or {}
            out['commands_pending'] = sum(len(v) for v in cmds.values()
                                          if isinstance(v, list))
        except Exception:
            pass
    try:
        save(_nc_cache, out)
    except Exception:
        pass
    respond(200, out)


# ─────────────────────────────────────────────────────────────────────────────
# v3.4.2: on-call schedule + escalation policy
# ─────────────────────────────────────────────────────────────────────────────
# An alert that nobody acknowledges should get louder, not sit silent. An
# escalation policy is a list of tiers ({after_minutes}); a periodic tick
# re-notifies the configured webhook destinations for any open, unacknowledged
# alert that has aged past a tier it hasn't fired yet, naming the current on-call
# person. The on-call schedule is a simple contact rotation (N days each). No new
# webhook event — escalation re-fires the original alert's event through the
# existing channel fan-out, so it lands wherever that alert already routes.
_last_escalation_tick = [0.0]
_ESCALATION_INTERVAL = 60   # seconds


def _oncall_index(now, anchor, period_s, n):
    """Rotation index for `now` given the anchor (start) time and period. Before
    the anchor, the first person holds it (index 0)."""
    if now < anchor:
        return 0
    return int((now - anchor) // period_s) % n


def _oncall_at(cfg, now=None):
    """Resolve the on-call contact for `now`, honouring (in priority order):
      1. a dated OVERRIDE window (handoff / swap) that covers `now`;
      2. an anchored rotation SCHEDULE (who is on call THIS week — deterministic
         from an anchor date + rotation length, not wall-clock modulo);
      3. the legacy stateless modulo rotation (backwards compatible).
    Returns '' when on-call isn't configured/enabled."""
    oc = (cfg or {}).get('oncall') or {}
    if not oc.get('enabled'):
        return ''
    contacts = [c for c in (oc.get('contacts') or []) if c]
    now = int(now or time.time())

    # 1. Overrides win — a specific dated assignment.
    for ov in (oc.get('overrides') or []):
        if not isinstance(ov, dict):
            continue
        who = ov.get('contact')
        try:
            start = int(ov.get('start') or 0)
            end = int(ov.get('end') or 0)
        except (TypeError, ValueError):
            continue
        if who and start <= now < end:
            return who

    # 2. Anchored schedule.
    anchor = oc.get('anchor')
    if contacts and anchor:
        try:
            anchor = int(anchor)
            days = max(1, int(oc.get('rotation_days') or 7))
        except (TypeError, ValueError):
            anchor = None
        if anchor:
            return contacts[_oncall_index(now, anchor, days * 86400, len(contacts))]

    # 3. Legacy stateless modulo (unchanged).
    if not contacts:
        return ''
    try:
        days = max(1, int(oc.get('rotation_days') or 7))
    except (TypeError, ValueError):
        days = 7
    return contacts[(now // (days * 86400)) % len(contacts)]


def _oncall_upcoming(cfg, now=None, count=4):
    """The next `count` handoffs as [{start, contact}] from the anchored
    schedule (empty if no anchor/contacts). Overrides are listed separately by
    the handler; this is the base rotation timeline."""
    oc = (cfg or {}).get('oncall') or {}
    contacts = [c for c in (oc.get('contacts') or []) if c]
    anchor = oc.get('anchor')
    if not (oc.get('enabled') and contacts and anchor):
        return []
    try:
        anchor = int(anchor)
        days = max(1, int(oc.get('rotation_days') or 7))
    except (TypeError, ValueError):
        return []
    now = int(now or time.time())
    period = days * 86400
    # Start of the current rotation slot.
    slot = anchor if now < anchor else anchor + ((now - anchor) // period) * period
    out = []
    for k in range(count):
        start = slot + k * period
        idx = _oncall_index(start, anchor, period, len(contacts))
        out.append({'start': start, 'contact': contacts[idx]})
    return out


def _oncall_now(cfg, now=None):
    """Back-compat shim — the current on-call contact string. Delegates to the
    calendar-aware resolver (overrides → anchored schedule → legacy modulo)."""
    return _oncall_at(cfg, now)


def _escalation_tick(now=None):
    """Re-notify open, unacknowledged alerts that have aged past an escalation
    tier. Idempotent per (alert, tier) via the alert's `escalated_tiers` list.
    Best-effort; never raises into the caller."""
    now = int(now or time.time())
    try:
        cfg = load(CONFIG_FILE) or {}
        esc = cfg.get('escalation') or {}
        if not esc.get('enabled'):
            return
        tiers = sorted(
            [t for t in (esc.get('tiers') or []) if isinstance(t, dict)],
            key=lambda t: int(t.get('after_minutes') or 0))
        if not tiers:
            return
        sevs = esc.get('severities') or ['critical', 'high']
        oncall = _oncall_now(cfg, now)
        fired_any = False
        pending_sends = []   # (event, payload, msg) — fired AFTER the lock releases
        with _LockedUpdate(ALERTS_FILE) as store:
            for a in store.get('alerts', []):
                if a.get('acknowledged_at') or a.get('resolved_at'):
                    continue
                if a.get('severity') not in sevs:
                    continue
                age_min = (now - int(a.get('ts') or now)) / 60.0
                done = set(a.get('escalated_tiers') or [])
                for i, tier in enumerate(tiers):
                    if i in done:
                        continue
                    try:
                        after = int(tier.get('after_minutes') or 0)
                    except (TypeError, ValueError):
                        after = 0
                    if age_min < after:
                        continue
                    msg = (f"ESCALATION tier {i + 1} — unacknowledged {int(age_min)}m: "
                           f"{a.get('title', a.get('event', 'alert'))}"
                           + (f" · on-call: {oncall}" if oncall else ""))
                    # v5.0.1 (lock-nesting fix): buffer the send; fire it AFTER
                    # the ALERTS_FILE lock releases. _send_webhook_to_url →
                    # _dlq_record opens WEBHOOK_DLQ_FILE's own _LockedUpdate; under
                    # SQLite a nested BEGIN IMMEDIATE errors and the failed-delivery
                    # DLQ row was silently dropped (un-retryable missed escalation).
                    pending_sends.append((a.get('event', 'alert_escalated'),
                                          dict(a.get('payload') or {}), msg,
                                          tier.get('target') or ''))   # v5.4.1 (G2)
                    done.add(i)
                    fired_any = True
                a['escalated_tiers'] = sorted(done)
            if not fired_any:
                # nothing changed — avoid an unnecessary write
                raise _NoEscalationChange()
    except _NoEscalationChange:
        pass
    except Exception as e:
        sys.stderr.write(f'[remotepower] escalation tick failed: {e}\n')
        return
    # Fire the buffered escalation webhooks OUTSIDE the ALERTS_FILE lock so a
    # delivery failure's DLQ write (its own _LockedUpdate) isn't nested. Empty
    # when nothing escalated.
    for _ev, _pl, _msg, _tgt in pending_sends:
        try:
            _send_webhook_to_url(_ev, _pl, _msg, cfg,
                                 only_dest_ids=({_tgt} if _tgt else None))   # v5.4.1 (G2)
        except Exception:
            pass


class _NoEscalationChange(Exception):
    """Sentinel to abort the _LockedUpdate write when nothing escalated."""


def _escalation_tick_if_due():
    now = time.time()
    if now - _last_escalation_tick[0] < _ESCALATION_INTERVAL:
        return
    _last_escalation_tick[0] = now
    _escalation_tick()


def handle_oncall():
    """GET /api/oncall — current on-call contact, the next handoffs, active/
    upcoming overrides, and the rotation + escalation cfg."""
    require_auth()
    cfg = load(CONFIG_FILE) or {}
    now = int(time.time())
    oc = cfg.get('oncall') or {}
    respond(200, {
        'current':  _oncall_now(cfg, now),
        # v5.8.0 (B3.3): the next 4 rotation handoffs (empty unless an anchored
        # schedule is set) + any override windows still in effect / upcoming.
        'upcoming': _oncall_upcoming(cfg, now, count=4),
        'overrides': [o for o in (oc.get('overrides') or [])
                      if isinstance(o, dict) and (o.get('end') or 0) > now],
        'oncall': oc or {'enabled': False, 'contacts': [], 'rotation_days': 7},
        'escalation': cfg.get('escalation') or {'enabled': False, 'tiers': [], 'severities': ['critical', 'high']},
    })


def handle_setup_status():
    """GET /api/setup-status — onboarding checklist for Settings → Install. Each
    step reflects the live state (done / todo) so a fresh operator can see what's
    left to configure. Read-only; auth: require_auth."""
    user = require_auth()
    cfg = load(CONFIG_FILE) or {}
    users = load(USERS_FILE) or {}
    devices = load(DEVICES_FILE) or {}

    pw_done = bool(users) and not any(u.get('must_change_password') for u in users.values())
    notif_done = bool((cfg.get('webhook_url') or '').strip()
                      or (cfg.get('webhook_urls') or [])
                      or (cfg.get('smtp_enabled') and cfg.get('smtp_host')))
    backup_done = bool(cfg.get('backup'))
    twofa_done = bool((users.get(user) or {}).get('totp_secret'))
    n_dev = sum(1 for d in devices.values() if isinstance(d, dict))

    steps = [
        {'id': 'admin-password', 'title': 'Set a strong admin password',
         'detail': 'Change the seeded/default admin credentials before going further.',
         'page': 'users', 'required': True, 'done': pw_done},
        {'id': 'first-device', 'title': 'Enroll your first device',
         'detail': 'Install the agent on a host and enroll it with a PIN, or add an agentless device.',
         'page': 'devices', 'required': True, 'done': n_dev > 0,
         'count': n_dev},
        {'id': 'notifications', 'title': 'Configure a notification channel',
         'detail': 'Add a webhook (Slack/Discord/ntfy/PagerDuty) or SMTP email so alerts reach you.',
         'page': 'settings', 'tab': 'notifs', 'required': False, 'done': notif_done},
        {'id': 'backups', 'title': 'Enable scheduled backups',
         'detail': 'Turn on automatic config/state backups so you can recover the server.',
         'page': 'settings', 'tab': 'advanced', 'required': False, 'done': backup_done},
        {'id': 'two-factor', 'title': 'Turn on two-factor auth for your account',
         'detail': 'Add TOTP 2FA to your own login for defence in depth.',
         'page': 'settings', 'tab': 'security', 'required': False, 'done': twofa_done},
    ]
    done = sum(1 for s in steps if s['done'])
    req_left = [s['title'] for s in steps if s['required'] and not s['done']]
    respond(200, {'steps': steps, 'done': done, 'total': len(steps),
                  'complete': done == len(steps), 'required_remaining': req_left})


def handle_alerts_clear():
    """DELETE /api/alerts?scope=resolved|all — admin-only purge.

    scope=resolved (default) → drop every entry with resolved_at set.
                                Keeps open + acknowledged rows.
    scope=all      → drop EVERY row regardless of state. The
                                operator gets a confirmation prompt
                                in the UI before this fires.

    Audit-logged in both cases. Same posture as the audit-log clear
    endpoint: state lives in alerts.json + audit_log records the act.
    """
    actor = require_admin_auth()
    if method() != 'DELETE': respond(405, {'error': 'Method not allowed'})
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    scope = (qs.get('scope', ['resolved'])[0] or 'resolved').lower()
    if scope not in ('resolved', 'all'):
        respond(400, {'error': 'scope must be "resolved" or "all"'})
    removed = 0
    try:
        with _LockedUpdate(ALERTS_FILE) as store:
            arr = store.get('alerts', [])
            if scope == 'all':
                removed = len(arr)
                store['alerts'] = []
            else:
                kept = [a for a in arr if not a.get('resolved_at')]
                removed = len(arr) - len(kept)
                store['alerts'] = kept
    except Exception as e:
        respond(500, {'error': str(e)})
    audit_log(actor, 'alerts_clear', f'scope={scope} removed={removed}')
    respond(200, {'ok': True, 'removed': removed, 'scope': scope})


# ── v3.2.0 (B2): inbound webhooks ───────────────────────────────────────────

_VALID_SEVERITIES = ('critical', 'high', 'medium', 'low')


def _generate_inbound_token():
    """Token format: rpwi_<32 hex>. Prefix lets ops grep it in payloads/logs."""
    return 'rpwi_' + secrets.token_hex(16)


def _resolve_inbound_device(token_cfg, body):
    """Return (device_id, device_name) for an inbound payload, or ('', '').

    Resolution order:
      1. Token has scope_device_id pinned → that wins.
      2. Body carries `device` (name match against devices.json).
      3. Body carries `device_id` (direct match).
    """
    pinned = token_cfg.get('scope_device_id')
    if pinned:
        d = load(DEVICES_FILE).get(pinned) or {}
        return pinned, d.get('name', '')
    if isinstance(body, dict):
        dev_id_in = body.get('device_id')
        if dev_id_in:
            d = load(DEVICES_FILE).get(dev_id_in) or {}
            if d:
                return dev_id_in, d.get('name', '')
        dev_name = body.get('device') or body.get('hostname')
        if dev_name:
            devs = load(DEVICES_FILE)
            for did, d in devs.items():
                if (d.get('name') == dev_name
                        or d.get('hostname') == dev_name):
                    return did, d.get('name', '')
    return '', ''


def handle_inbound_webhook(token_str):
    """POST /api/webhook/in/<token>

    Receives a generic alert payload from an external system. Writes the
    alert to the inbox (B1) and to fleet_events. Does NOT fan out to
    outbound webhook destinations — that would double-deliver when the
    source already sent the alert to those same destinations.

    No auth header is required — the token in the URL IS the auth.

    Body shape (all fields optional except severity + title):
      {
        "source":   "grafana" | "alertmanager" | ...,
        "severity": "critical" | "high" | "medium" | "low",
        "title":    "Alert title",
        "body":     "Longer description",
        "device":   "tviweb01" (hostname or .name match) | null,
        "device_id": "d-xxxxx" (explicit match) | null,
        "links":    [{ "url": "...", "label": "..." }, ...]
      }
    """
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})

    cfg = load(INBOUND_WEBHOOKS_FILE)
    tokens = cfg.get('tokens', [])
    token_str = (token_str or '').strip()
    if not token_str or not token_str.startswith('rpwi_'):
        _log_inbound('alert', '', '', '401', 'invalid token format')
        respond(401, {'error': 'invalid token'})
    match = None
    for t in tokens:
        if hmac.compare_digest(t.get('token', ''), token_str) and t.get('enabled', True):
            match = t
            break
    if not match:
        _log_inbound('alert', '', '', '401', 'invalid or disabled token')
        respond(401, {'error': 'invalid or disabled token'})
    # v3.2.0 (B6): a syslog-kind token must not be used at the alert URL
    if (match.get('kind') or 'alert') != 'alert':
        _log_inbound('alert', match.get('id'), match.get('label'),
                     '400', f'wrong url for {match.get("kind")} token')
        respond(400, {'error': f'this token is a {match.get("kind")} token — use the corresponding URL'})

    body = get_json_obj()
    if not isinstance(body, dict):
        _log_inbound('alert', match.get('id'), match.get('label'),
                     '400', 'body must be JSON object')
        respond(400, {'error': 'body must be a JSON object'})

    severity = (body.get('severity') or 'medium').lower()
    if severity not in _VALID_SEVERITIES:
        severity = 'medium'
    title = _sanitize_str(body.get('title', ''), 256)
    if not title:
        _log_inbound('alert', match.get('id'), match.get('label'),
                     '400', 'title required')
        respond(400, {'error': 'title required'})

    dev_id, dev_name = _resolve_inbound_device(match, body)
    source = _sanitize_str(body.get('source') or match.get('label') or 'inbound', 64)

    # Build alert directly. We bypass fire_webhook() to avoid fanning out to
    # outbound destinations (the source likely already delivered to them).
    summary = {
        'device_id':         dev_id or None,
        'device_name':       dev_name or None,
        'source':            source,
        'severity':          severity,
        'inbound_token_id':  match.get('id'),
        'inbound_source':    source,
    }
    if body.get('body'):
        summary['body'] = _sanitize_str(body.get('body'), 1024)
    links = body.get('links')
    if isinstance(links, list):
        safe_links = []
        for ln in links[:5]:
            if isinstance(ln, dict) and ln.get('url'):
                # Scheme-validate (http/https only, no javascript:/file:) so a
                # future renderer that makes these clickable can't be tricked
                # into emitting a hostile href — same guard the operator
                # quick-links and CVE ref-links use.
                clean_url = _validate_link_url(ln.get('url'))
                if not clean_url:
                    continue
                safe_links.append({
                    'url':   clean_url,
                    'label': _sanitize_str(ln.get('label', 'link'), 64),
                })
        if safe_links:
            summary['links'] = safe_links

    alert = {
        'id':              'a-' + os.urandom(6).hex(),
        # v4.1.0 (#54): stable operator-facing id, stamped under the lock below.
        'alertid':         None,
        'ts':              int(time.time()),
        'event':           'inbound',
        'severity':        severity,
        'title':           title,
        'device_id':       dev_id or None,
        'device_name':     dev_name or '',
        'payload':         summary,
        'source':          'inbound',
        'acknowledged_by': None,
        'acknowledged_at': None,
        'resolved_by':     None,
        'resolved_at':     None,
    }
    try:
        with _LockedUpdate(ALERTS_FILE) as store:
            arr = store.setdefault('alerts', [])
            _assign_alertid(store, alert)
            arr.append(alert)
            if len(arr) > MAX_ALERTS:
                del arr[:-MAX_ALERTS]
    except Exception as e:
        respond(500, {'error': f'failed to record alert: {e}'})

    # Also record in fleet_events for the activity panel
    try:
        _record_fleet_event('inbound', {
            'device_id':   dev_id,
            'device_name': dev_name,
            'source':      source,
            'severity':    severity,
        })
    except Exception:
        pass

    # Bump token stats
    try:
        with _LockedUpdate(INBOUND_WEBHOOKS_FILE) as store:
            for t in store.get('tokens', []):
                if hmac.compare_digest(t.get('token', ''), token_str):
                    t['last_seen'] = int(time.time())
                    t['hit_count'] = int(t.get('hit_count', 0)) + 1
                    break
    except Exception:
        pass

    # Audit log — actor is the token label so the operator sees which token fired
    audit_log(f'inbound:{match.get("label", match.get("id", "?"))}',
              'inbound_webhook',
              f'severity={severity} title={title[:80]} device={dev_name or "-"}')

    _log_inbound('alert', match.get('id'), match.get('label'), '200',
                 f'severity={severity} dev={dev_name or "-"}')
    respond(200, {'ok': True, 'alert_id': alert['id']})


def handle_inbound_webhooks_list():
    """GET /api/inbound-webhooks — admin-only. Returns tokens without secret."""
    require_admin_auth()
    cfg = load(INBOUND_WEBHOOKS_FILE)
    redacted = []
    for t in cfg.get('tokens', []):
        copy = {k: v for k, v in t.items() if k != 'token'}
        copy['token_preview'] = (t.get('token') or '')[:12] + '…'
        redacted.append(copy)
    respond(200, {'tokens': redacted})


def handle_inbound_webhooks_create():
    """POST /api/inbound-webhooks — admin-only. Returns token ONCE.

    Body: {label, scope_device_id?, scope_tag?, kind?}
      kind='alert' (default) → receive URL is /api/webhook/in/<token>
      kind='syslog' (v3.2.0 B6) → receive URL is /api/syslog/in/<token>
    """
    actor = require_admin_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    label = _sanitize_str(body.get('label', ''), 64)
    if not label:
        respond(400, {'error': 'label required'})
    scope_dev = _sanitize_str(body.get('scope_device_id', ''), 64) or None
    scope_tag = _sanitize_str(body.get('scope_tag', ''), 64) or None
    kind = _sanitize_str(body.get('kind', 'alert'), 16) or 'alert'
    if kind not in ('alert', 'syslog', 'snmp_trap'):
        respond(400, {'error': 'kind must be "alert", "syslog" or "snmp_trap"'})
    token = _generate_inbound_token()
    entry = {
        'id':                'iwh_' + os.urandom(4).hex(),
        'label':             label,
        'token':             token,
        'kind':              kind,
        'scope_device_id':   scope_dev,
        'scope_tag':         scope_tag,
        'enabled':           True,
        'created_by':        actor,
        'created_at':        int(time.time()),
        'last_seen':         None,
        'hit_count':         0,
    }
    try:
        with _LockedUpdate(INBOUND_WEBHOOKS_FILE) as store:
            store.setdefault('tokens', []).append(entry)
    except Exception as e:
        respond(500, {'error': str(e)})
    audit_log(actor, 'inbound_webhook_create',
              f'id={entry["id"]} label={label} kind={kind}')
    # Returned ONCE — store it now or you lose it.
    respond(200, {'ok': True, 'token': token, 'id': entry['id'], 'kind': kind})


def handle_inbound_webhook_revoke(token_id):
    """DELETE /api/inbound-webhooks/<id> — admin-only."""
    actor = require_admin_auth()
    if method() != 'DELETE': respond(405, {'error': 'Method not allowed'})
    found = False
    try:
        with _LockedUpdate(INBOUND_WEBHOOKS_FILE) as store:
            arr = store.get('tokens', [])
            for i, t in enumerate(arr):
                if t.get('id') == token_id:
                    arr.pop(i)
                    found = True
                    break
    except Exception as e:
        respond(500, {'error': str(e)})
    if not found:
        respond(404, {'error': 'token not found'})
    audit_log(actor, 'inbound_webhook_revoke', f'id={token_id}')
    respond(200, {'ok': True})


def handle_inbound_webhook_toggle(token_id):
    """PATCH /api/inbound-webhooks/<id> — admin-only.

    v3.3.0: accepts `enabled`, `label`, `scope_device_id`, `scope_tag`.
    Any field omitted from the body is left unchanged. The opaque
    token secret cannot be edited — operators revoke + create new
    when they need to rotate.
    """
    actor = require_admin_auth()
    if method() != 'PATCH': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    found = False
    changes = []
    try:
        with _LockedUpdate(INBOUND_WEBHOOKS_FILE) as store:
            for t in store.get('tokens', []):
                if t.get('id') == token_id:
                    if 'enabled' in body:
                        t['enabled'] = bool(body['enabled'])
                        changes.append(f'enabled={t["enabled"]}')
                    if 'label' in body:
                        t['label'] = _sanitize_str(str(body.get('label', '')), 64)
                        changes.append(f'label={t["label"][:40]}')
                    if 'scope_device_id' in body:
                        sd = str(body['scope_device_id'] or '').strip()
                        if sd and not _validate_id(sd):
                            respond(400, {'error': 'invalid scope_device_id'})
                        t['scope_device_id'] = sd
                        changes.append(f'scope_device_id={sd}')
                    if 'scope_tag' in body:
                        st = _sanitize_str(str(body.get('scope_tag', '')), 64)
                        t['scope_tag'] = st
                        changes.append(f'scope_tag={st}')
                    found = True
                    break
    except Exception as e:
        respond(500, {'error': str(e)})
    if not found:
        respond(404, {'error': 'token not found'})
    audit_log(actor, 'inbound_webhook_edit',
              f'id={token_id} ' + ' '.join(changes))
    respond(200, {'ok': True})


# ── v3.2.0 (B6): syslog HTTP ingestion ──────────────────────────────────────
# rsyslog-omhttp or fluent-bit or curl can POST log lines here. Token
# scope determines the target device. Lines append to log_watch.json
# under the synthetic 'syslog' unit and run through the existing
# per-device + global log_alert rule engine.

_SYSLOG_PRI_RE = re.compile(r'^<(\d+)>')
_SYSLOG_MAX_LINE = 2048
_SYSLOG_MAX_LINES_PER_POST = 200


def _parse_syslog_line(raw):
    """Extract (severity_level, message) from a syslog line.

    Accepts RFC 3164 and RFC 5424 prefixes — the <PRI> facility*8+severity
    number at the start. PRI must be in the legal 0..191 range (24
    facilities × 8 severities). Returns severity 0..7 (emerg..debug) and
    the remainder of the line. If no <PRI> or the PRI is out of range,
    the whole input is treated as the message and severity defaults to
    6 (info).
    """
    s = raw.rstrip('\r\n')[:_SYSLOG_MAX_LINE]
    m = _SYSLOG_PRI_RE.match(s)
    if not m:
        return 6, s
    try:
        pri = int(m.group(1))
    except ValueError:
        return 6, s
    # PRI = facility (0..23) * 8 + severity (0..7) ⇒ legal 0..191
    if pri < 0 or pri > 191:
        return 6, s   # Malformed — keep the line whole, sev=info
    sev = pri & 0x07
    return sev, s[m.end():].lstrip()


def _eval_syslog_rules(dev_id, dev, new_lines):
    """Run new_lines through per-device + global log_watch rules under
    unit='syslog' and fire log_alert for any that cross threshold.

    Mirrors handle_log_submit's _eval_rules but inline + scoped to the
    'syslog' unit so we don't drag the journal-specific virtual-unit
    logic into syslog ingestion.
    """
    per_device_rules = dev.get('log_watch') or []
    global_rules = (load(LOG_RULES_GLOBAL_FILE).get('rules') or [])

    fired_keys = set()
    name = dev.get('name', dev_id)

    def _eval(rules, scope):
        for rule in rules:
            rule_unit = rule.get('unit', '')
            # Wildcards skip — same as journal path (would generate noise)
            if rule_unit not in ('syslog',):
                continue
            pattern = rule.get('pattern', '')
            key = (scope, 'syslog', pattern)
            if key in fired_keys:
                continue
            try:
                rx = re.compile(pattern)
            except re.error:
                continue
            ex_pat = rule.get('exclude_pattern', '')
            ex_rx = None
            if ex_pat:
                try:
                    ex_rx = re.compile(ex_pat)
                except re.error:
                    pass
            matches = [ln for ln in new_lines
                       if rx.search(ln) and (not ex_rx or not ex_rx.search(ln))]
            try:
                threshold = int(rule.get('threshold', 1))
            except (TypeError, ValueError):
                threshold = 1
            severity = str(rule.get('severity', 'WARN')).upper()
            if severity not in ('OK', 'WARN', 'CRIT'):
                severity = 'WARN'
            if len(matches) >= threshold:
                fired_keys.add(key)
                if severity != 'OK':
                    wb_payload = {
                        'device_id': dev_id,
                        'name':      name,
                        'unit':      'syslog',
                        'pattern':   pattern,
                        'count':     len(matches),
                        'sample':    matches[:3],
                        'scope':     scope,
                        'severity':  severity,
                    }
                    tmpl = rule.get('display_template')
                    if tmpl:
                        wb_payload['display_template'] = tmpl
                    fire_webhook('log_alert', wb_payload)

    _eval(per_device_rules, 'device')
    _eval(global_rules, 'global')


def handle_syslog_in(token_str):
    """POST /api/syslog/in/<token>

    Accepts either:
      Content-Type: application/json     → body {"lines": ["...", ...]}
      Content-Type: text/plain (default) → newline-separated lines

    Both are appended to log_watch.json under unit='syslog' for the
    device the token scopes to. Existing log_watch rules with
    unit='syslog' will fire log_alert just like journal-derived rules.
    """
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})

    cfg = load(INBOUND_WEBHOOKS_FILE)
    tokens = cfg.get('tokens', [])
    token_str = (token_str or '').strip()
    if not token_str or not token_str.startswith('rpwi_'):
        _log_inbound('syslog', '', '', '401', 'invalid token format')
        respond(401, {'error': 'invalid token'})
    match = None
    for t in tokens:
        if hmac.compare_digest(t.get('token', ''), token_str) and t.get('enabled', True):
            match = t
            break
    if not match:
        _log_inbound('syslog', '', '', '401', 'invalid or disabled token')
        respond(401, {'error': 'invalid or disabled token'})
    if (match.get('kind') or 'alert') != 'syslog':
        _log_inbound('syslog', match.get('id'), match.get('label'),
                     '400', f'wrong url for {match.get("kind", "alert")} token')
        respond(400, {'error': f'this token is a {match.get("kind", "alert")} token — use the corresponding URL'})

    dev_id = match.get('scope_device_id')
    if not dev_id:
        _log_inbound('syslog', match.get('id'), match.get('label'),
                     '400', 'token not pinned to device')
        respond(400, {'error': 'syslog tokens must be pinned to a device — recreate with scope_device_id'})
    devs = load(DEVICES_FILE)
    dev = devs.get(dev_id)
    if not dev:
        _log_inbound('syslog', match.get('id'), match.get('label'),
                     '404', 'target device deleted')
        respond(404, {'error': 'token target device no longer exists'})

    # Parse body: JSON first, then plain text fallback
    raw_lines = []
    content_type = (_env('CONTENT_TYPE', '') or '').lower()
    if 'json' in content_type:
        body = get_json_body()   # accepts EITHER {lines:[...]} OR a bare JSON array of lines
        if isinstance(body, dict) and isinstance(body.get('lines'), list):
            raw_lines = [str(x) for x in body['lines'][:_SYSLOG_MAX_LINES_PER_POST]]
        elif isinstance(body, list):
            raw_lines = [str(x) for x in body[:_SYSLOG_MAX_LINES_PER_POST]]
    if not raw_lines:
        # Plain-text fallback — read stdin directly
        try:
            content_length = int(_env('CONTENT_LENGTH', '0') or 0)
        except ValueError:
            content_length = 0
        if content_length > 0:
            raw = _read_request_body(min(content_length, 256 * 1024)).decode('utf-8', errors='replace')
            for line in raw.split('\n')[:_SYSLOG_MAX_LINES_PER_POST]:
                line = line.strip()
                if line:
                    raw_lines.append(line)

    if not raw_lines:
        _log_inbound('syslog', match.get('id'), match.get('label'),
                     '400', 'no lines in body')
        respond(400, {'error': 'no lines provided'})

    # Parse + store
    now = int(time.time())
    new_entries = []
    new_msgs = []
    for raw in raw_lines:
        sev, msg = _parse_syslog_line(raw)
        if not msg:
            continue
        new_entries.append({'ts': now, 'line': msg, 'sev': sev,
                             'source': 'syslog'})
        new_msgs.append(msg)

    if new_entries:
        try:
            with _LockedUpdate(LOG_WATCH_FILE) as store:
                dev_buf = store.setdefault(dev_id, {'units': {}, 'updated_at': now})
                units_buf = dev_buf.setdefault('units', {})
                syslog_buf = units_buf.setdefault('syslog', [])
                syslog_buf.extend(new_entries)
                # Age-bound: drop entries older than LOG_BUFFER_TTL
                cutoff = now - LOG_BUFFER_TTL
                syslog_buf[:] = [e for e in syslog_buf if e.get('ts', 0) >= cutoff]
                dev_buf['updated_at'] = now
        except Exception as e:
            respond(500, {'error': f'log buffer write failed: {e}'})

    # Run rules on the new lines
    try:
        _eval_syslog_rules(dev_id, dev, new_msgs)
    except Exception as e:
        sys.stderr.write(f'[remotepower] syslog rule eval failed: {e}\n')

    # Bump token stats
    try:
        with _LockedUpdate(INBOUND_WEBHOOKS_FILE) as store:
            for t in store.get('tokens', []):
                if t.get('token') == token_str:
                    t['last_seen'] = now
                    t['hit_count'] = int(t.get('hit_count', 0)) + 1
                    break
    except Exception:
        pass

    _log_inbound('syslog', match.get('id'), match.get('label'), '200',
                 f'lines={len(new_entries)} dev={dev.get("name", dev_id)}')
    respond(200, {'ok': True, 'lines_received': len(new_entries)})


def handle_snmp_trap_in(token_str):
    """POST /api/snmp/trap/<token>

    Accepts JSON traps forwarded by an snmptrapd handler script:
      {"traps": [{"oid": "...", "value": "...", "agent": "...", "type": "..."}]}
    or a single {"oid": ..., "value": ...}. Stdlib has no SNMP/ASN.1 decoder and
    pysnmp is not a dependency, so the decode happens in the trapd handler which
    POSTs JSON here. Stored per-device in snmp_traps.json and raised as a
    coalesced snmp_trap_received alert (no identity field -> one open alert/host).
    """
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    cfg = load(INBOUND_WEBHOOKS_FILE)
    tokens = cfg.get('tokens', [])
    token_str = (token_str or '').strip()
    if not token_str or not token_str.startswith('rpwi_'):
        _log_inbound('snmp_trap', '', '', '401', 'invalid token format')
        respond(401, {'error': 'invalid token'})
    match = None
    for t in tokens:
        if hmac.compare_digest(t.get('token', ''), token_str) and t.get('enabled', True):
            match = t
            break
    if not match:
        _log_inbound('snmp_trap', '', '', '401', 'invalid or disabled token')
        respond(401, {'error': 'invalid or disabled token'})
    if (match.get('kind') or 'alert') != 'snmp_trap':
        _log_inbound('snmp_trap', match.get('id'), match.get('label'), '400',
                     f'wrong url for {match.get("kind", "alert")} token')
        respond(400, {'error': f'this token is a {match.get("kind", "alert")} token — use the corresponding URL'})
    dev_id = match.get('scope_device_id')
    if not dev_id:
        _log_inbound('snmp_trap', match.get('id'), match.get('label'), '400', 'token not pinned to device')
        respond(400, {'error': 'snmp_trap tokens must be pinned to a device'})
    devs = load(DEVICES_FILE)
    dev = devs.get(dev_id)
    if not dev:
        _log_inbound('snmp_trap', match.get('id'), match.get('label'), '404', 'target device deleted')
        respond(404, {'error': 'token target device no longer exists'})

    body = get_json_body()   # accepts {traps:[...]}, a single trap dict, OR a bare JSON array
    raw = []
    if isinstance(body, dict) and isinstance(body.get('traps'), list):
        raw = body['traps'][:50]
    elif isinstance(body, dict) and (body.get('oid') or body.get('value')):
        raw = [body]
    elif isinstance(body, list):
        raw = body[:50]
    now = int(time.time())
    new_traps = []
    for tr in raw:
        if not isinstance(tr, dict):
            continue
        new_traps.append({
            'ts':    now,
            'oid':   _sanitize_str(str(tr.get('oid', '')), 256),
            'value': _sanitize_str(str(tr.get('value', '')), 512),
            'type':  _sanitize_str(str(tr.get('type', '')), 64),
            'agent': _sanitize_str(str(tr.get('agent', '')), 128),
        })
    if not new_traps:
        _log_inbound('snmp_trap', match.get('id'), match.get('label'), '400', 'no traps in body')
        respond(400, {'error': 'no traps provided (expect {"traps":[{oid,value}]})'})

    try:
        with _LockedUpdate(SNMP_TRAPS_FILE) as store:
            buf = store.setdefault(dev_id, [])
            buf.extend(new_traps)
            cutoff = now - LOG_BUFFER_TTL
            buf[:] = [e for e in buf if e.get('ts', 0) >= cutoff][-200:]
    except Exception as e:
        respond(500, {'error': f'trap store write failed: {e}'})

    # Coalesced per-host alert (fired AFTER the trap-store lock; fire_webhook
    # takes its own locks — never nest).
    try:
        first = new_traps[0]
        fire_webhook('snmp_trap_received', {
            'device_id': dev_id, 'name': dev.get('name', dev_id),
            'count': len(new_traps), 'oid': first.get('oid', ''),
            'value': first.get('value', ''),
        })
    except Exception as e:
        sys.stderr.write(f'[remotepower] snmp_trap_received fire failed dev={dev_id}: {e}\n')

    try:
        with _LockedUpdate(INBOUND_WEBHOOKS_FILE) as store:
            for t in store.get('tokens', []):
                if t.get('token') == token_str:
                    t['last_seen'] = now
                    t['hit_count'] = int(t.get('hit_count', 0)) + 1
                    break
    except Exception:
        pass

    _log_inbound('snmp_trap', match.get('id'), match.get('label'), '200',
                 f'traps={len(new_traps)} dev={dev.get("name", dev_id)}')
    respond(200, {'ok': True, 'traps_received': len(new_traps)})


# ── v3.2.0 (A1): MCP Stage 4 — write tools + confirmation flow ──────────────

def _prune_confirmations(store):
    """Drop expired pending confirmations from the ledger in-place and RETURN the
    list of expired payloads (device_name resolved) so the CALLER can fire
    `mcp_confirmation_expired` AFTER its _LockedUpdate block exits.

    v4.7.0 fix (lock-nesting class): firing fire_webhook() here — while the
    caller still holds _LockedUpdate(CONFIRMATIONS_FILE) — nests fire_webhook's
    own _LockedUpdate under the SQLite single-connection backend → OperationalError
    → the alert/webhook/fleet-event is silently swallowed. A `load()` read is
    lock-safe, so device_name lookup stays here; only the fire moves out.
    """
    now = int(time.time())
    arr = store.get('confirmations', [])
    expired_payloads = []
    keep = []
    for c in arr:
        if c.get('status') == 'pending' and now - c.get('requested_at', 0) > CONFIRMATION_TTL_SEC:
            c['status'] = 'expired'
            c['decided_at'] = now
            expired_payloads.append({
                'confirmation_id': c.get('id'),
                'action':          c.get('action'),
                'device_id':       c.get('device_id'),
                'requested_by':    c.get('requested_by'),
                'ai_host':         c.get('ai_host'),
                'ai_prompt':       c.get('ai_prompt'),
            })
        keep.append(c)
    # Count-bound trim
    if len(keep) > MAX_CONFIRMATIONS:
        keep = keep[-MAX_CONFIRMATIONS:]
    store['confirmations'] = keep
    if expired_payloads:
        devs = load(DEVICES_FILE) or {}
        for payload in expired_payloads:
            payload['device_name'] = (devs.get(payload.get('device_id')) or {}).get('name', '')
    return expired_payloads


def _fire_expired_confirmations(expired_payloads):
    """Fire mcp_confirmation_expired for each pruned confirmation. MUST be called
    AFTER the _LockedUpdate block exits (see _prune_confirmations)."""
    for payload in expired_payloads or []:
        try:
            fire_webhook('mcp_confirmation_expired', payload)
        except Exception as e:
            sys.stderr.write(f'[remotepower] mcp_confirmation_expired fire failed: {e}\n')


def _create_confirmation(action, device_id, params, actor, ai_host, ai_prompt):
    """Append a pending confirmation; return its id. Locks the file."""
    conf_id = 'cf_' + os.urandom(6).hex()
    entry = {
        'id':            conf_id,
        'action':        action,
        'device_id':     device_id,
        'params':        params or {},
        'requested_by':  actor,
        'requested_at':  int(time.time()),
        'ai_host':       ai_host,
        'ai_prompt':     ai_prompt,
        'status':        'pending',
        'decided_by':    None,
        'decided_at':    None,
    }
    with _LockedUpdate(CONFIRMATIONS_FILE) as store:
        _expired = _prune_confirmations(store)
        store.setdefault('confirmations', []).append(entry)
    _fire_expired_confirmations(_expired)   # fire AFTER the lock (nesting-safe)
    audit_log(actor, 'mcp_confirmation_requested',
              f'action={action} device={device_id} id={conf_id}',
              ai_host=ai_host, ai_prompt=ai_prompt)
    return conf_id


def _mcp_execute(action, device_id, params, actor, ai_host, ai_prompt):
    """Run the MCP action immediately. Does NOT call respond() — caller does."""
    devs = load(DEVICES_FILE)
    dev = devs.get(device_id) or {}
    dev_name = dev.get('name', device_id)

    # v3.8.0: actions that queue a command to a host must target a device that
    # still exists and is not quarantined. A maker-checker request parked while
    # the device was healthy could otherwise be approved after the device was
    # deleted (orphaned queue entry) or quarantined (command would still run).
    if action in ('reboot_device', 'run_saved_script', 'exec_command', 'queue_command'):
        if device_id not in devs:
            return {'ok': False, 'error': 'device not found'}
        if _device_quarantined(devs[device_id]):
            return {'ok': False, 'error': 'device is quarantined'}

    if action == 'reboot_device':
        cmds = load(CMDS_FILE)
        cmds.setdefault(device_id, [])
        if 'reboot' not in cmds[device_id]:
            cmds[device_id].append('reboot')
        save(CMDS_FILE, cmds)
        log_command(actor, device_id, dev_name, 'reboot')
        fire_webhook('command_queued', {
            'device_id': device_id, 'name': dev_name,
            'command': 'reboot', 'actor': actor,
        })

    elif action == 'run_saved_script':
        script_id = (params or {}).get('script_id') or ''
        scripts = load(SCRIPTS_FILE)
        # scripts.json is a dict keyed by script id
        script = scripts.get(script_id)
        if not script:
            return {'ok': False, 'error': f'script_id "{script_id}" not found'}
        body = script.get('body') or ''
        if not body.strip():
            return {'ok': False, 'error': 'script has empty body'}
        # Queue as an exec command — same shape as the dashboard's "Run script"
        cmd_str = 'exec:' + body
        with _LockedUpdate(CMDS_FILE) as cmds:
            cmds.setdefault(device_id, []).append(cmd_str)
        log_command(actor, device_id, dev_name,
                    f'exec(script:{script.get("name") or script_id})')
        fire_webhook('command_queued', {
            'device_id': device_id, 'name': dev_name,
            'command': f'exec:script:{script.get("name") or script_id}',
            'actor': actor,
        })

    elif action == 'force_package_scan':
        with _LockedUpdate(DEVICES_FILE) as d:
            if device_id in d:
                d[device_id]['force_package_scan'] = True

    elif action == 'force_acme_rescan':
        with _LockedUpdate(DEVICES_FILE) as d:
            if device_id in d:
                d[device_id]['force_acme_rescan'] = True

    elif action == 'exec_command':
        # v3.7.0: maker-checker — a destructive shell command approved by a
        # second admin. params['command'] is the full queued string.
        cmd = (params or {}).get('command') or ''
        if not cmd:
            return {'ok': False, 'error': 'no command to run'}
        # v3.8.0: re-check the device allowlist/denylist at approval time too —
        # the device's allowed_commands may have tightened since the request was
        # parked. Strip the exec: prefix to match the allowlist's command form.
        _bare = cmd[5:] if cmd.startswith('exec:') else cmd
        if device_id in devs:
            _ok, _reason = _check_exec_allowlist(device_id, _bare, devs)
            if not _ok:
                return {'ok': False, 'error': _reason}
        queued = cmd if cmd.startswith(('exec:', 'reboot', 'shutdown')) else 'exec:' + cmd
        with _LockedUpdate(CMDS_FILE) as cmds:
            cmds.setdefault(device_id, [])
            if queued not in cmds[device_id]:
                cmds[device_id].append(queued)
        log_command(actor, device_id, dev_name, queued[:200])
        fire_webhook('command_queued', {
            'device_id': device_id, 'name': dev_name, 'command': queued, 'actor': actor,
        })

    elif action == 'proxmox_lifecycle':
        # v3.14.0 (#33): a destructive Proxmox VM/CT action approved by a second
        # admin. device_id is the vmid; params carries guest_type/action/params.
        p = params or {}
        cfg2 = load(CONFIG_FILE) or {}
        if not cfg2.get('proxmox_lifecycle_enabled'):
            return {'ok': False, 'error': 'Proxmox lifecycle actions are disabled'}
        try:
            _pc2 = proxmox_client.config_from(cfg2)
            _pc2 = {**_pc2, 'node': proxmox_client.find_guest_node(
                _pc2, device_id, p.get('guest_type') or '')}
            upid = proxmox_client.lifecycle(_pc2,
                                            p.get('guest_type'), device_id,
                                            p.get('action'), p.get('params') or {})
        except proxmox_client.ProxmoxError as e:
            return {'ok': False, 'error': str(e)}
        return {'ok': True, 'task': upid, 'detail': p.get('label', '')}

    elif action == 'queue_command':
        # v3.14.0: a risky queued command (reboot/shutdown/update/upgrade/
        # container/uninstall) approved by a second admin. params['command'] is
        # the full queued string.
        cmd = (params or {}).get('command') or ''
        if not cmd:
            return {'ok': False, 'error': 'no command to queue'}
        with _LockedUpdate(CMDS_FILE) as cmds:
            cmds.setdefault(device_id, [])
            if cmd not in cmds[device_id]:
                cmds[device_id].append(cmd)
        log_command(actor, device_id, dev_name, str(cmd)[:200])
        fire_webhook('command_queued', {
            'device_id': device_id, 'name': dev_name, 'command': cmd, 'actor': actor,
        })

    else:
        return {'ok': False, 'error': f'unknown action "{action}"'}

    # Audit log with MCP attribution
    audit_log(actor, f'mcp_{action}',
              f'device={device_id} name={dev_name}',
              ai_host=ai_host, ai_prompt=ai_prompt)
    return {'ok': True, 'action': action, 'device_id': device_id}


def _mcp_validate_params(action, params):
    """Pre-execution parameter validation for MCP write tools.

    Returns an error string if params are invalid, None if OK.

    Runs BEFORE the confirmation queue branch so a bad script_id doesn't
    park a doomed confirmation indefinitely (the operator approves, the
    execution fails, the operator gets a useless error). Validation
    failures should always be caller bugs returned immediately as 400.
    """
    if action == 'run_saved_script':
        script_id = (params or {}).get('script_id') or ''
        if not script_id:
            return 'run_saved_script requires script_id'
        scripts = load(SCRIPTS_FILE)
        if script_id not in scripts:
            return f'script_id "{script_id}" not found in library'
    # Other actions have no pre-validation (just need device_id which
    # is checked upstream).
    return None


def _mcp_handle(action, destructive):
    """Common entry for all 4 MCP write tools.

    destructive=True → respect device.require_confirmation; may return 202.
    destructive=False → always execute immediately.
    """
    user = require_mcp_action(action)
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    device_id = (body.get('device_id') or '').strip()
    if not device_id or not _validate_id(device_id):
        respond(400, {'error': 'valid device_id required'})
    devs = load(DEVICES_FILE)
    if device_id not in devs:
        respond(404, {'error': 'device not found'})
    ai_host, ai_prompt = get_mcp_attribution()

    params = {k: v for k, v in body.items() if k != 'device_id'}

    # v3.2.0 follow-up: validate action-specific params BEFORE deciding
    # whether to queue a confirmation. Found via live testing — bogus
    # script_id used to return 202 with a confirmation_id, then fail
    # silently when the operator approved.
    param_err = _mcp_validate_params(action, params)
    if param_err:
        respond(400, {'ok': False, 'error': param_err})

    if destructive and devs[device_id].get('require_confirmation', True):
        conf_id = _create_confirmation(action, device_id, params, user,
                                       ai_host, ai_prompt)
        respond(202, {
            'ok': True,
            'status': 'pending_confirmation',
            'confirmation_id': conf_id,
            'message': ('Operator approval required. The action is queued '
                        'but will not run until an admin approves it in '
                        'the dashboard (Confirmations).'),
        })

    # Immediate execution path
    result = _mcp_execute(action, device_id, params, user, ai_host, ai_prompt)
    if result.get('ok'):
        respond(200, result)
    else:
        respond(400, result)


def handle_mcp_reboot_device():
    _mcp_handle('reboot_device', destructive=True)


def handle_mcp_run_saved_script():
    _mcp_handle('run_saved_script', destructive=True)


def handle_mcp_force_package_scan():
    _mcp_handle('force_package_scan', destructive=False)


def handle_mcp_force_acme_rescan():
    _mcp_handle('force_acme_rescan', destructive=False)


# ── Confirmation queue endpoints (admin-only, called from the dashboard) ────

def handle_confirmations_list():
    """GET /api/confirmations — admin sees pending MCP confirmations."""
    require_admin_auth()
    # Prune expired while we read
    with _LockedUpdate(CONFIRMATIONS_FILE) as store:
        _expired = _prune_confirmations(store)
        arr = list(store.get('confirmations', []))
    _fire_expired_confirmations(_expired)   # fire AFTER the lock (nesting-safe)
    arr.reverse()
    # Add device_name + script_name for display
    devs = load(DEVICES_FILE)
    scripts = load(SCRIPTS_FILE)
    out = []
    for c in arr:
        d = devs.get(c.get('device_id'), {}) or {}
        c2 = dict(c)
        c2['device_name'] = d.get('name', '')
        sid = (c.get('params') or {}).get('script_id')
        if sid and sid in scripts:
            c2['script_name'] = scripts[sid].get('name', sid)
        out.append(c2)
    respond(200, {'confirmations': out})


def handle_confirmation_approve(conf_id):
    """POST /api/confirmations/<id>/approve — admin runs the action."""
    actor = require_admin_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    entry = None
    _expired = []
    with _LockedUpdate(CONFIRMATIONS_FILE) as store:
        _expired = _prune_confirmations(store)
        for c in store.get('confirmations', []):
            if c.get('id') == conf_id:
                entry = c
                break
        if not entry:
            respond(404, {'error': 'confirmation not found'})
        if entry.get('status') != 'pending':
            respond(409, {'error': f'confirmation already {entry.get("status")}'})
        # v3.7.0 maker-checker: a different admin must approve. The requester
        # cannot sign off their own change unless the operator disables the
        # separation-of-duties guard.
        _cfg_app = load(CONFIG_FILE) or {}
        if _cfg_app.get('change_approval_no_self', True) and entry.get('requested_by') == actor:
            respond(403, {'error': 'You requested this change; a different admin must approve it.'})
        entry['status'] = 'approved'
        entry['decided_by'] = actor
        entry['decided_at'] = int(time.time())
    _fire_expired_confirmations(_expired)   # fire AFTER the lock (nesting-safe)
    # Execute outside the lock
    result = _mcp_execute(
        entry['action'], entry['device_id'], entry.get('params') or {},
        actor=f'mcp:{entry["requested_by"]} (approved by {actor})',
        ai_host=entry.get('ai_host'),
        ai_prompt=entry.get('ai_prompt'),
    )
    if not result.get('ok'):
        # Roll back the status flag so the operator can see what failed
        with _LockedUpdate(CONFIRMATIONS_FILE) as store:
            for c in store.get('confirmations', []):
                if c.get('id') == conf_id:
                    c['status'] = 'failed'
                    c['error'] = result.get('error', '')
                    break
        respond(500, {'ok': False, 'error': result.get('error', 'execution failed')})
    respond(200, {'ok': True, 'result': result})


def handle_confirmations_clear():
    """DELETE /api/confirmations — remove all resolved (non-pending) entries."""
    actor = require_admin_auth()
    if method() != 'DELETE': respond(405, {'error': 'Method not allowed'})
    removed = 0
    with _LockedUpdate(CONFIRMATIONS_FILE) as store:
        before = store.get('confirmations', [])
        kept = [c for c in before if c.get('status') == 'pending']
        removed = len(before) - len(kept)
        store['confirmations'] = kept
    audit_log(actor, 'mcp_confirmations_cleared', f'removed={removed}')
    respond(200, {'ok': True, 'removed': removed})


def handle_confirmation_reject(conf_id):
    """POST /api/confirmations/<id>/reject — admin declines the action."""
    actor = require_admin_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    note = _sanitize_str(body.get('note', ''), 256)
    found = False
    with _LockedUpdate(CONFIRMATIONS_FILE) as store:
        for c in store.get('confirmations', []):
            if c.get('id') == conf_id:
                if c.get('status') != 'pending':
                    respond(409, {'error': f'confirmation already {c.get("status")}'})
                c['status'] = 'rejected'
                c['decided_by'] = actor
                c['decided_at'] = int(time.time())
                if note:
                    c['reject_note'] = note
                found = True
                break
    if not found:
        respond(404, {'error': 'confirmation not found'})
    audit_log(actor, 'mcp_confirmation_rejected',
              f'id={conf_id}' + (f' note={note[:80]}' if note else ''))
    respond(200, {'ok': True})


# ── v3.2.0 (B3): OIDC SSO ──────────────────────────────────────────────────

_OIDC_STATE_TTL = 600   # 10 minutes
_OIDC_METADATA_CACHE = {}  # issuer → (expiry_ts, metadata_dict)


def _b64url_decode(s):
    """Decode a JWT-style base64url (no padding) chunk to bytes."""
    s = s.replace('-', '+').replace('_', '/')
    s += '=' * (-len(s) % 4)
    import base64
    return base64.b64decode(s)


def _decode_id_token(id_token):
    """Parse a JWT payload without signature verification.

    The id_token arrives over a back-channel HTTPS POST to the IdP's token
    endpoint that we authenticated with our client_secret — the channel
    integrity is what we trust. This matches RFC 6749 §10.12 and is the
    same posture every confidential-client OIDC library takes by default.
    For tighter posture (front-channel id_tokens or implicit flow), a
    JWKS-based signature check would be required; we explicitly do not
    support those flows.
    """
    parts = id_token.split('.')
    if len(parts) != 3:
        raise ValueError('malformed id_token')
    payload = json.loads(_b64url_decode(parts[1]).decode('utf-8'))
    return payload


def _oidc_assert_safe_url(url, what='OIDC endpoint'):
    """SSRF guard for OIDC back-channel fetches. The issuer is admin-configured,
    but the discovery document's endpoints (token / userinfo / jwks) come from
    the IdP, so a hostile or compromised IdP could still point them at the cloud
    metadata service (169.254.169.254). Reject non-http(s) URLs and any target
    that resolves to a link-local / metadata / unspecified address; RFC1918 and
    loopback stay allowed so internal and dev IdPs keep working — the same policy
    the webhook sender uses. Raises ValueError (callers turn it into a 5xx)."""
    parsed = urllib.parse.urlparse(url or '')
    if parsed.scheme not in ('http', 'https'):
        raise ValueError(f'{what} must be an http(s) URL')
    if _url_targets_local_or_meta(parsed, allow_loopback=True):
        raise ValueError(f'{what} resolves to a blocked (metadata/link-local) address')


def _oidc_discover(issuer):
    """Fetch + cache the IdP's /.well-known/openid-configuration."""
    now = int(time.time())
    cached = _OIDC_METADATA_CACHE.get(issuer)
    if cached and cached[0] > now:
        return cached[1]
    url = issuer.rstrip('/') + '/.well-known/openid-configuration'
    _oidc_assert_safe_url(url, 'OIDC issuer')   # SSRF guard
    req = urllib.request.Request(url, headers={'Accept': 'application/json'})
    # v3.8.0: connect-time peer revalidation closes the DNS-rebinding window
    # between _oidc_assert_safe_url's resolve and this fetch.
    _ctx = _get_ssl_context() if url.lower().startswith('https') else None
    opener = _ssrf_safe_opener(allow_loopback=True, ssl_ctx=_ctx, no_redirect=True)
    with opener.open(req, timeout=10) as resp:
        meta = json.loads(resp.read().decode('utf-8'))
    _OIDC_METADATA_CACHE[issuer] = (now + 3600, meta)
    return meta


def _oidc_redirect_uri():
    """Build the public callback URL from the current request context."""
    host = _env('HTTP_HOST', '').strip()
    scheme = 'https' if _env('HTTPS', 'on') in ('on', '1', 'true') else 'http'
    fwd_scheme = _env('HTTP_X_FORWARDED_PROTO', '').strip().lower()
    if fwd_scheme in ('http', 'https'):
        scheme = fwd_scheme
    return f'{scheme}://{host}/api/auth/oidc/callback'


def handle_oidc_test():
    """POST /api/auth/oidc/test — admin-only.

    Validates the saved OIDC config by fetching the discovery document
    and reporting the four key endpoints (authorize / token / userinfo /
    jwks) along with the issuer name. Bypasses the cache so the report
    always reflects what the server can reach RIGHT NOW.
    """
    actor = require_admin_auth()
    if method() != 'POST': respond(405, {'error': 'Method not allowed'})
    cfg = load(CONFIG_FILE) or {}
    issuer = (cfg.get('oidc_issuer') or '').strip()
    if not issuer:
        respond(400, {'ok': False,
                      'error': 'oidc_issuer not set in config'})
    # Drop the cache so we test the actual reachable state, not last
    # successful discovery.
    try:
        _OIDC_METADATA_CACHE.clear()
    except Exception:
        pass
    try:
        meta = _oidc_discover(issuer)
    except urllib.error.HTTPError as e:
        respond(502, {'ok': False,
                      'error': f'IdP returned HTTP {e.code}: {e.reason}',
                      'issuer': issuer})
    except Exception as e:
        respond(502, {'ok': False,
                      'error': f'{e.__class__.__name__}: {e}',
                      'issuer': issuer})

    report = {
        'ok':       True,
        'issuer':   meta.get('issuer') or issuer,
        'endpoints': {
            'authorization': meta.get('authorization_endpoint'),
            'token':         meta.get('token_endpoint'),
            'userinfo':      meta.get('userinfo_endpoint'),
            'jwks':          meta.get('jwks_uri'),
        },
        'scopes_supported':         meta.get('scopes_supported'),
        'grant_types_supported':    meta.get('grant_types_supported'),
        'response_types_supported': meta.get('response_types_supported'),
        'redirect_uri_needed':      _oidc_redirect_uri(),
        'client_secret_set':        bool(cfg.get('oidc_client_secret')),
        'client_id_set':            bool(cfg.get('oidc_client_id')),
    }
    # Flag the most common misconfigurations
    warnings = []
    if not report['endpoints']['authorization']:
        warnings.append('authorization_endpoint missing from discovery')
    if not report['endpoints']['token']:
        warnings.append('token_endpoint missing from discovery')
    if not report['client_id_set']:
        warnings.append('oidc_client_id not configured')
    if not report['client_secret_set']:
        warnings.append('oidc_client_secret not configured')
    if report['scopes_supported'] and 'openid' not in report['scopes_supported']:
        warnings.append("issuer doesn't advertise the 'openid' scope")
    report['warnings'] = warnings
    audit_log(actor, 'oidc_test', f'issuer={issuer} ok=True')
    respond(200, report)


def handle_oidc_start():
    """GET /api/auth/oidc/start — initiate the OIDC authorization code flow.

    Generates state + nonce, stores them server-side, then 302-redirects
    the user to the IdP's authorize endpoint. Returns 503 if OIDC is not
    configured.
    """
    cfg = load(CONFIG_FILE) or {}
    if not (cfg.get('oidc_enabled') and cfg.get('oidc_issuer') and cfg.get('oidc_client_id')):
        respond(503, {'error': 'OIDC is not configured on this server'})

    try:
        meta = _oidc_discover(cfg['oidc_issuer'])
    except Exception as e:
        sys.stderr.write(f'[remotepower] OIDC discovery failed: {e}\n')
        respond(502, {'error': 'OIDC issuer unreachable',
                      'detail': str(e)[:240]})
    authorize_url = meta.get('authorization_endpoint')
    if not authorize_url:
        respond(502, {'error': 'OIDC issuer metadata missing authorization_endpoint'})

    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)
    expires_at = int(time.time()) + _OIDC_STATE_TTL
    redirect_uri = _oidc_redirect_uri()
    # Persist the state → nonce + redirect_uri mapping
    try:
        with _LockedUpdate(OIDC_STATES_FILE) as store:
            for k in list(store.keys()):
                if not isinstance(store[k], dict) or store[k].get('expires_at', 0) <= int(time.time()):
                    del store[k]
            store[state] = {
                'nonce':        nonce,
                'redirect_uri': redirect_uri,
                'expires_at':   expires_at,
            }
    except Exception as e:
        respond(500, {'error': f'state store failed: {e}'})

    scopes = (cfg.get('oidc_scopes') or 'openid profile email groups').strip()
    params = {
        'response_type': 'code',
        'client_id':     cfg['oidc_client_id'],
        'redirect_uri':  redirect_uri,
        'scope':         scopes,
        'state':         state,
        'nonce':         nonce,
    }
    full_url = authorize_url + '?' + urllib.parse.urlencode(params)
    print('Status: 302 Found')
    print(f'Location: {full_url}')
    print('Cache-Control: no-store')
    print()
    sys.exit(0)


def _oidc_role_for(claims, cfg):
    """Map an id_token claim set to a RemotePower role. v5.4.1 (D5): honours the
    sso_group_roles matrix; legacy oidc_admin_group still → admin; viewer default."""
    groups = claims.get('groups') or claims.get('roles') or []
    return _role_from_groups(groups, cfg, 'oidc_admin_group')


def _oidc_username_for(claims):
    """Pick a stable username from id_token claims."""
    for key in ('preferred_username', 'email', 'sub'):
        v = claims.get(key)
        if v:
            return _sanitize_str(str(v), 64)
    return ''


def handle_oidc_callback():
    """GET /api/auth/oidc/callback?code=...&state=...

    Validates state, exchanges the code at the token endpoint, decodes
    the id_token, looks up or creates the local user, mints a session
    token, and redirects to the dashboard with the token in the URL hash.
    """
    # v4.3.0: per-IP rate limit on the unauthenticated OIDC callback.
    if not _ip_ratelimit('sso', _get_client_ip(), 30, window=60):
        time.sleep(0.5)
        respond(429, {'error': 'Too many SSO attempts — wait a minute'})
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    err = (qs.get('error', [''])[0] or '').strip()
    if err:
        desc = (qs.get('error_description', [''])[0] or '')[:240]
        sys.stderr.write(f'[remotepower] OIDC IdP returned error={err} desc={desc}\n')
        # Redirect back to login with an error message
        print('Status: 302 Found')
        print(f'Location: /?oidc_error={urllib.parse.quote(err)}')
        print()
        sys.exit(0)

    code = (qs.get('code', [''])[0] or '').strip()
    state = (qs.get('state', [''])[0] or '').strip()
    if not code or not state:
        respond(400, {'error': 'code and state are required'})

    # Validate state
    stored = None
    try:
        with _LockedUpdate(OIDC_STATES_FILE) as store:
            for k in list(store.keys()):
                if not isinstance(store[k], dict) or store[k].get('expires_at', 0) <= int(time.time()):
                    del store[k]
            if state in store:
                stored = store.pop(state)
    except Exception as e:
        respond(500, {'error': f'state lookup failed: {e}'})
    if not stored:
        respond(400, {'error': 'invalid or expired state'})

    cfg = load(CONFIG_FILE) or {}
    if not (cfg.get('oidc_enabled') and cfg.get('oidc_issuer') and
            cfg.get('oidc_client_id') and cfg.get('oidc_client_secret')):
        respond(503, {'error': 'OIDC is not configured on this server'})

    try:
        meta = _oidc_discover(cfg['oidc_issuer'])
    except Exception as e:
        respond(502, {'error': 'OIDC issuer unreachable', 'detail': str(e)[:240]})

    token_endpoint = meta.get('token_endpoint')
    if not token_endpoint:
        respond(502, {'error': 'OIDC issuer metadata missing token_endpoint'})
    try:
        _oidc_assert_safe_url(token_endpoint, 'OIDC token endpoint')   # SSRF guard
    except ValueError as e:
        respond(502, {'error': str(e)})

    # Exchange code for tokens
    data = urllib.parse.urlencode({
        'grant_type':    'authorization_code',
        'code':          code,
        'redirect_uri':  stored.get('redirect_uri') or _oidc_redirect_uri(),
        'client_id':     cfg['oidc_client_id'],
        'client_secret': cfg['oidc_client_secret'],
    }).encode('utf-8')
    req = urllib.request.Request(token_endpoint, data=data,
                                  headers={
                                      'Content-Type': 'application/x-www-form-urlencoded',
                                      'Accept':       'application/json',
                                  })
    try:
        # v3.8.0: connect-time peer revalidation (anti-rebinding) for the
        # back-channel token exchange — the token_endpoint comes from the IdP.
        _ctx = _get_ssl_context() if token_endpoint.lower().startswith('https') else None
        _opener = _ssrf_safe_opener(allow_loopback=True, ssl_ctx=_ctx, no_redirect=True)
        with _opener.open(req, timeout=15) as resp:
            token_resp = json.loads(resp.read().decode('utf-8'))
    except urllib.error.HTTPError as e:
        # The error body from a token endpoint can echo back the client_secret
        # or a partial token — never write it to the server log. Log only the
        # OAuth `error`/`error_description` codes (safe per RFC 6749 §5.2), and
        # return just the code to the caller.
        err_code = ''
        try:
            _parsed = json.loads(e.read().decode('utf-8', errors='replace') or '{}')
            if isinstance(_parsed, dict):
                err_code = _sanitize_str(str(_parsed.get('error', '')), 64)
        except Exception:
            pass
        sys.stderr.write(f'[remotepower] OIDC token exchange failed: HTTP {e.code}'
                         + (f' ({err_code})' if err_code else '') + '\n')
        respond(502, {'error': f'token exchange failed: HTTP {e.code}',
                      'detail': err_code or 'see IdP'})
    except Exception as e:
        respond(502, {'error': f'token exchange failed: {e}'})

    id_token = token_resp.get('id_token')
    if not id_token:
        respond(502, {'error': 'IdP did not return id_token'})

    try:
        claims = _decode_id_token(id_token)
    except Exception as e:
        respond(502, {'error': f'id_token decode failed: {e}'})

    if claims.get('nonce') != stored.get('nonce'):
        respond(400, {'error': 'nonce mismatch — possible replay attack'})

    # v3.13.0 hardening: cheap standard-claim checks on top of the back-channel
    # (client_secret-authenticated, TLS, SSRF-guarded) trust. Even without full
    # JWKS signature validation these reject a replayed expired token, a token
    # from a different issuer, and cross-RP token confusion (wrong audience).
    _now = int(time.time())
    _exp = claims.get('exp')
    if isinstance(_exp, (int, float)) and _now > _exp + 120:   # 120s clock skew
        respond(400, {'error': 'id_token expired'})
    _iss = str(claims.get('iss') or '').rstrip('/')
    _want_iss = str(cfg.get('oidc_issuer') or '').rstrip('/')
    if _want_iss and _iss and _iss != _want_iss:
        respond(400, {'error': 'id_token issuer mismatch'})
    _aud = claims.get('aud')
    _cid = cfg['oidc_client_id']
    _aud_ok = (_aud == _cid) or (isinstance(_aud, list) and _cid in _aud)
    if _aud is not None and not _aud_ok:
        respond(400, {'error': 'id_token audience mismatch'})

    username = _oidc_username_for(claims)
    if not username:
        respond(400, {'error': 'id_token has no usable username claim'})

    role = _oidc_role_for(claims, cfg)

    # Provision/promote + mint a session via the shared SSO helpers.
    user = _provision_or_promote_user(username, role, {
        'oidc_subject': _sanitize_str(str(claims.get('sub') or ''), 128),
        'oidc_email':   _sanitize_str(str(claims.get('email') or ''), 128),
    }, 'oidc')
    token = _mint_session(username, extra={'oidc': True})
    audit_log(username, 'login_oidc',
              f'authenticated via OIDC (sub={claims.get("sub", "?")[:64]})')

    # Redirect to the dashboard with the token in the URL hash so the
    # SPA can pick it up. Hash fragments are NOT sent to the server,
    # so the token never lands in nginx logs.
    safe_token = urllib.parse.quote(token, safe='')
    print('Status: 302 Found')
    print(f'Location: /#oidc_token={safe_token}&role={user.get("role", "viewer")}&username={urllib.parse.quote(username)}')
    print('Cache-Control: no-store')
    print()
    sys.exit(0)


# ── v3.2.0 (B5): SNMPv2c polling for agentless devices ─────────────────────

def _device_snmp_target(dev):
    """Return (host, credentials, port) for an agentless device with SNMP
    configured, or None if it's missing fields / not enabled.

    `credentials` is the v2c community STRING, or (v5.8.0) a v3/USM creds
    DICT — snmp.snmp_get dispatches on the type, so every poll_* helper
    downstream works for both versions unchanged."""
    snmp_cfg = dev.get('snmp') or {}
    if not snmp_cfg.get('enabled'):
        return None
    host = dev.get('ip') or dev.get('hostname') or dev.get('host')
    try:
        port = int(snmp_cfg.get('port') or 161)
    except (TypeError, ValueError):
        port = 161
    if str(snmp_cfg.get('version') or '2c') == '3':
        community = {
            'user':        snmp_cfg.get('v3_user') or '',
            'auth_proto':  snmp_cfg.get('v3_auth_proto') or 'none',
            'auth_secret': snmp_cfg.get('v3_auth_secret') or '',
            'priv_proto':  snmp_cfg.get('v3_priv_proto') or 'none',
            'priv_secret': snmp_cfg.get('v3_priv_secret') or '',
            'context':     snmp_cfg.get('v3_context') or '',
        }
        if not community['user']:
            return None
    else:
        community = snmp_cfg.get('community') or ''
    if not host or not community:
        return None
    # v5.0.0 SSRF: SNMP was the one fleet outbound path with no IP classification.
    # Reject link-local / cloud-metadata / unspecified targets so a device IP can't
    # be used as a blind UDP:161 oracle against 169.254.169.254 etc. Loopback stays
    # ALLOWED on purpose — monitoring the server host's own snmpd over 127.0.0.1 is a
    # legitimate pattern (mirrors the allow_loopback default the notifier and other
    # outbound features use). RFC1918/LAN allowed (the design target). None → skip.
    try:
        if _url_targets_local_or_meta(urllib.parse.urlparse(f'snmp://{host}'), allow_loopback=True):
            sys.stderr.write(f"[remotepower] snmp: refusing link-local/metadata target {host!r}\n")
            return None
    except Exception:
        pass
    return (host, community, port)


def _snmp_os_label(entry):
    """A short OS string for an agentless device, derived from its SNMP data,
    so the Devices list OS column isn't blank. Prefers vendor specifics
    (Synology DSM, RouterOS, OPNsense/pfSense) then falls back to parsing
    sysDescr. Returns '' when there's nothing useful."""
    if not isinstance(entry, dict):
        return ''
    syn = (entry.get('synology') or {}).get('system') or {}
    if syn.get('dsm_version'):
        return ('Synology ' + str(syn['dsm_version']))[:60]   # "Synology DSM 7.3-86009"
    sd = (entry.get('sysDescr') or '').strip()
    if not sd:
        return ''
    low = sd.lower()
    if 'routeros' in low:
        # Use a dotted version (e.g. 7.14) — a bare integer would match the
        # board number (RB5009) instead of the RouterOS version.
        m = re.search(r'(\d+\.\d[\d.]*)', sd)
        return ('RouterOS ' + m.group(1)) if m else 'RouterOS'
    if 'opnsense' in low:
        return 'OPNsense'
    if 'pfsense' in low:
        return 'pfSense'
    toks = sd.split()
    if toks and toks[0] in ('FreeBSD', 'Linux', 'OpenBSD', 'NetBSD', 'Darwin', 'SunOS'):
        ver = ''
        if len(toks) > 2 and toks[2][:1].isdigit():
            ver = toks[2]
        elif len(toks) > 1 and toks[1][:1].isdigit():
            ver = toks[1]
        return (toks[0] + (' ' + ver if ver else '')).strip()[:60]
    return sd[:48]


def _do_snmp_poll(dev_id, dev):
    """Poll one device and update SNMP_DATA_FILE. Returns the per-device
    result dict that was stored (or the error record on failure).

    Doesn't raise — failures are recorded in the same dict under
    `last_error` so the UI can display them and the operator can debug
    without watching nginx logs.

    v3.2.0: edge-triggered `snmp_unreachable` / `snmp_recover` webhooks
    fire alongside the buffer write. Failure must hit a 2-poll threshold
    before unreachable fires (covers single-packet UDP loss). Unmonitored
    devices skip the webhook path — same posture as device_offline.

    v3.2.0 follow-up: also pulls hrProcessorTable + hrStorageTable +
    vendor MIB (Mikrotik) on every sweep so the Device Metrics view
    has real values for SNMP devices, and the existing threshold
    pipeline (metric_warning / metric_critical) can fire on those
    values. ifTable walking stays on the on-demand deep-poll — too
    heavy for the 5-minute sweep on big switches.
    """
    target = _device_snmp_target(dev)
    if not target:
        return None
    host, community, port = target
    name = dev.get('name', dev_id)
    is_monitored = dev.get('monitored', True)

    # Load previous state to detect transitions
    prev = (load(SNMP_DATA_FILE).get(dev_id) or {})
    prev_state = 'ok' if prev.get('last_ok') and not prev.get('last_error') else (
                 'fail' if prev.get('consecutive_fails', 0) > 0 else 'unknown')
    prev_fails = int(prev.get('consecutive_fails', 0))

    try:
        import snmp as snmp_mod
        result = snmp_mod.poll_system(host, community, port=port, timeout=2.0)
        # v3.2.0 follow-up: gather the lightweight extras alongside
        # sys-group. Each is a small bounded walk (max 24-64 entries) +
        # a few scalars — total adds 0.5-1.5 s per device per sweep.
        try:
            processors = snmp_mod.poll_processors(host, community, port=port, timeout=2.0)
        except Exception:
            processors = []
        try:
            storage = snmp_mod.poll_hr_storage(host, community, port=port, timeout=2.0)
        except Exception:
            storage = []
        sys_obj = result.get('sysObjectID') or ''
        vendor = {}
        if sys_obj.startswith('1.3.6.1.4.1.14988'):
            try:
                vendor = snmp_mod.poll_mikrotik(host, community, port=port, timeout=2.0)
            except Exception:
                vendor = {}
        # UCD-SNMP — present on net-snmp boxes (Linux, FreeBSD/OPNsense),
        # empty on Mikrotik/proprietary. Cheap (single GET of ~12 OIDs).
        try:
            ucd = snmp_mod.poll_ucd_snmp(host, community, port=port, timeout=2.0)
        except Exception:
            ucd = {}
        # v3.3.4: Synology DSM health. Probed unconditionally (one cheap GET
        # of the system scalars) — DSM runs net-snmp so its sysObjectID
        # doesn't identify it; poll_synology returns {} for non-Synology and
        # only then walks the disk/RAID tables.
        try:
            synology = snmp_mod.poll_synology(host, community, port=port, timeout=2.0)
        except Exception:
            synology = {}
        now = int(time.time())
        entry = {
            'host':         host,
            'port':         port,
            'last_ok':      now,
            'last_error':   None,
            'consecutive_fails': 0,
            'sysDescr':     result.get('sysDescr'),
            'sysObjectID':  result.get('sysObjectID'),
            'sysUpTime':    result.get('sysUpTime'),
            'sysContact':   result.get('sysContact'),
            'sysName':      result.get('sysName'),
            'sysLocation':  result.get('sysLocation'),
            'processors':   processors,
            'storage':      storage,
            'vendor':       vendor,
            'synology':     synology,
        }
        # Threshold pipeline — fires metric_warning/critical/recovered
        # events through the existing webhook + alerts inbox plumbing.
        try:
            process_snmp_metric_thresholds(dev_id, dev, entry)
        except Exception as e:
            sys.stderr.write(f'[remotepower] snmp threshold proc failed: {e}\n')
        # v3.14.0 fix: record SNMP CPU/mem/disk to the metric time-series so
        # agentless SNMP devices get trend graphs like agent hosts. Collected for
        # every polled device (the agent path records regardless of monitored).
        try:
            _record_snmp_metrics(dev_id, entry)
        except Exception as e:
            sys.stderr.write(f'[remotepower] snmp metric record failed: {e}\n')
        # Recover transition: previously failing → now ok
        if prev_state == 'fail' and is_monitored:
            try:
                fire_webhook('snmp_recover', {
                    'device_id': dev_id, 'device_name': name, 'host': host,
                    'sys_name':  result.get('sysName') or name,
                })
            except Exception as e:
                sys.stderr.write(f'[remotepower] snmp_recover fire failed: {e}\n')
    except Exception as e:
        now = int(time.time())
        new_fails = prev_fails + 1
        entry = {
            **{k: prev.get(k) for k in (
                'sysDescr', 'sysObjectID', 'sysUpTime', 'sysContact',
                'sysName', 'sysLocation') if k in prev},
            'host':       host,
            'port':       port,
            # Preserve the most recent last_ok so the UI can show "polled OK 2h ago"
            'last_ok':    prev.get('last_ok'),
            'last_error': f'{e.__class__.__name__}: {e}'[:240],
            'last_fail':  now,
            'consecutive_fails': new_fails,
        }
        # Unreachable transition: fires once on the Nth consecutive failure.
        # Single packet loss → no alert. Sustained → one alert, then quiet
        # until the recover transition. v4.3.0: N is configurable via
        # snmp_failures_before_alert (default 2 = unchanged), the SNMP sibling
        # of the monitor failures_before_alert flap-dampening knob.
        try:
            _snmp_need = max(2, min(72, int(_config_ro().get('snmp_failures_before_alert', 2) or 2)))
        except (TypeError, ValueError):
            _snmp_need = 2
        if is_monitored and prev_fails == _snmp_need - 1 and new_fails == _snmp_need:
            try:
                fire_webhook('snmp_unreachable', {
                    'device_id': dev_id, 'device_name': name, 'host': host,
                    'error':     entry['last_error'],
                })
            except Exception as ferr:
                sys.stderr.write(f'[remotepower] snmp_unreachable fire failed: {ferr}\n')
        # Dead transition: 6 hours of sustained failure (72 cycles at 5min
        # cadence). The original `snmp_unreachable` alert is still in the
        # inbox at severity=high; this one fires at severity=critical so
        # silence at this stage is impossible to miss. Fires once at the
        # crossing — _SNMP_DEAD_THRESHOLD = 72.
        if is_monitored and prev_fails == _SNMP_DEAD_THRESHOLD - 1 \
                and new_fails == _SNMP_DEAD_THRESHOLD:
            hours = (new_fails * SNMP_POLL_INTERVAL) // 3600
            try:
                fire_webhook('snmp_dead', {
                    'device_id': dev_id, 'device_name': name, 'host': host,
                    'hours':     hours,
                    'error':     entry['last_error'],
                })
            except Exception as ferr:
                sys.stderr.write(f'[remotepower] snmp_dead fire failed: {ferr}\n')
    try:
        with _LockedUpdate(SNMP_DATA_FILE) as store:
            store[dev_id] = entry
    except Exception:
        pass
    # v3.4.0: fill the OS column for agentless devices from SNMP (they have no
    # agent to report it). Refresh on agentless devices (keeps e.g. DSM version
    # current) but never clobber an agent/operator-provided os.
    try:
        os_label = _snmp_os_label(entry)
        if os_label and (dev.get('agentless') or not (dev.get('os') or '').strip()):
            with _LockedUpdate(DEVICES_FILE) as dstore:
                d = dstore.get(dev_id)
                if (d is not None and (d.get('agentless') or not (d.get('os') or '').strip())
                        and d.get('os') != os_label):
                    d['os'] = os_label
    except Exception:
        pass
    return entry


def run_snmp_polls_if_due():
    """Poll every SNMP-enabled agentless device once per SNMP_POLL_INTERVAL.

    Called from main() on every CGI request, same cheap-when-not-due
    pattern as run_monitors_if_due. The next-due timestamp lives in
    CONFIG_FILE under `last_snmp_poll`.
    """
    now = int(time.time())
    last = int(_config_ro().get('last_snmp_poll', 0))   # v5.8.0 (PERF): no-deepcopy gate
    if (now - last) < SNMP_POLL_INTERVAL:
        return
    devs = load(DEVICES_FILE)
    # v3.2.0 follow-up: poll EVERY device with SNMP enabled, including
    # unmonitored ones. The alert-fire path inside _do_snmp_poll respects
    # the monitored flag (no webhook fire for unmonitored), so the data
    # still collects — operators get rolling uptime, sysName, last-poll
    # status — but pages stay silent. Same posture the agent's metric
    # pipeline takes for unmonitored hosts (collect data, skip thresholds).
    targets = [(did, d) for did, d in devs.items()
               if _device_snmp_target(d) is not None]
    if not targets:
        return
    # Bump the marker BEFORE polling so a parallel CGI doesn't double-fire
    cfg = load(CONFIG_FILE)
    cfg['last_snmp_poll'] = now
    save(CONFIG_FILE, cfg)
    for dev_id, dev in targets:
        try:
            _do_snmp_poll(dev_id, dev)
        except Exception as e:
            sys.stderr.write(f'[remotepower] snmp poll failed for {dev_id}: {e}\n')


# ── v3.3.4: container image-update detection ───────────────────────────────
#
# Notify-only freshness check: compare each container's pulled image digest
# (repo_digest, captured by the agent) against the registry's current digest
# for the same tag. Server-side and deduped across the fleet, so the same
# lscr.io image on five hosts is one registry call and Docker Hub's rate
# limit is one central budget. Registry client lives in image_registry.py.

def _image_scan_enabled(cfg):
    # Default on — passive freshness is the feature's point. Operators set
    # image_updates_enabled=false to stop the server reaching out to registries.
    return bool(cfg.get('image_updates_enabled', True))


def _collect_fleet_images():
    """Unique {ref -> {image, tag, local_digests:set}} across all devices.

    ``ref`` is ``image:tag``. Only images the agent reported a repo_digest
    for are included — no digest means there's nothing to compare, so we
    skip rather than guess.
    """
    store = load(CONTAINERS_FILE) or {}
    images = {}
    for dev_id, rec in store.items():
        if not isinstance(rec, dict):
            continue
        for c in rec.get('items', []) or []:
            if not isinstance(c, dict):
                continue
            local = (c.get('repo_digest') or '').strip()
            image = (c.get('image') or '').strip()
            tag = (c.get('tag') or '').strip() or 'latest'
            if not local.startswith('sha256:') or not image:
                continue
            ref = f'{image}:{tag}'
            entry = images.setdefault(
                ref, {'image': image, 'tag': tag,
                      'local_digests': set(), 'devices': set()})
            entry['local_digests'].add(local)
            entry['devices'].add(dev_id)
    return images


def run_image_scan_if_due():
    """Refresh registry digests for stale-image detection, when due.

    Same cheap-when-not-due pattern as run_snmp_polls_if_due; the marker
    lives in CONFIG_FILE under ``last_image_scan``. Bounded per run (cap +
    wall-time budget + short per-call timeout) so a heartbeat is never held
    hostage to a slow or rate-limited registry.
    """
    _ro = _config_ro()   # v5.8.0 (PERF): no-deepcopy not-due gate
    if not _image_scan_enabled(_ro):
        return
    interval = max(3600, int(_ro.get('image_scan_interval', IMAGE_SCAN_INTERVAL)))
    now = int(time.time())
    last = int(_ro.get('last_image_scan', 0))
    if (now - last) < interval:
        return
    fleet = _collect_fleet_images()
    if not fleet:
        return
    # Bump the marker BEFORE the network work so a parallel CGI doesn't
    # double-sweep (mirrors run_snmp_polls_if_due).
    cfg = load(CONFIG_FILE)
    cfg['last_image_scan'] = now
    save(CONFIG_FILE, cfg)
    _scan_images(list(fleet.keys()), fleet, cfg, force=False)


def _scan_images(refs, fleet, cfg, force=False):
    """Resolve registry digests for ``refs`` and update the cache.

    ``force`` re-checks every ref (ignoring the per-image interval) and uses
    a larger cap/budget for an operator-triggered "scan now". Returns the
    number of images actually checked.
    """
    store = load(IMAGE_UPDATES_FILE) or {}
    images = store.get('images') or {}
    ignores = load(IMAGE_IGNORE_FILE) or {}
    creds_by_registry = cfg.get('registry_credentials') or {}
    block_local = bool(cfg.get('webhook_block_local', True))
    now = int(time.time())
    interval = max(3600, int(cfg.get('image_scan_interval', IMAGE_SCAN_INTERVAL)))
    max_items = 50 if force else IMAGE_SCAN_MAX_PER_RUN
    budget = 30 if force else IMAGE_SCAN_BUDGET_SEC

    def _last_checked(ref):
        return int((images.get(ref) or {}).get('last_checked', 0))

    if force:
        due = list(refs)
    else:
        due = [r for r in refs if (now - _last_checked(r)) >= interval]
    due.sort(key=_last_checked)          # never-checked (0) first, then oldest
    due = due[:max_items]

    checked = 0
    started = time.time()
    for ref in due:
        if (time.time() - started) > budget:
            break
        meta = fleet.get(ref) or {}
        parsed = image_registry_mod.parse_image_ref(meta.get('image'), meta.get('tag'))
        entry = images.setdefault(ref, {})
        entry['last_checked'] = now
        if not parsed:
            entry['last_error'] = 'unparseable image reference'
            continue
        registry, repository, tag = parsed
        url = image_registry_mod.manifest_url(registry, repository, tag)
        # SSRF guard — reuse the webhook check so a crafted image ref can't
        # aim the server at a link-local / metadata address.
        if block_local:
            try:
                if _url_targets_local_or_meta(urllib.parse.urlparse(url),
                                              allow_loopback=False):
                    entry['last_error'] = 'blocked: registry resolves to a local/meta address'
                    continue
            except Exception:
                pass
        # Pass the SSRF-safe opener + a url_guard down into the registry client
        # so *every* fetch it makes — the manifest AND the bearer-token realm
        # (which the registry controls via Www-Authenticate) — re-validates the
        # connected peer IP, refuses 3xx redirects, and pre-flights the realm
        # URL. Without this a malicious registry could 302 the manifest fetch to
        # 169.254.169.254, rebind DNS between the pre-flight and the connect, or
        # hand back a realm that exfiltrates configured Basic creds. When the
        # operator has turned off local blocking we keep the no-redirect opener
        # but skip IP enforcement (mirrors the manifest pre-flight above).
        _img_opener = _ssrf_safe_opener(
            allow_loopback=not block_local, ssl_ctx=_get_ssl_context(),
            no_redirect=True, enforce_ip=block_local)
        _img_guard = ((lambda u: _url_targets_local_or_meta(
            urllib.parse.urlparse(u), allow_loopback=False)) if block_local else None)
        creds = creds_by_registry.get(registry)
        try:
            dig = image_registry_mod.remote_digest(
                registry, repository, tag, creds=creds,
                timeout=IMAGE_SCAN_HTTP_TIMEOUT,
                opener=_img_opener, url_guard=_img_guard)
            entry['registry'] = registry
            entry['registry_digest'] = dig or ''
            entry['last_error'] = '' if dig else 'no digest returned'
            checked += 1
            if dig:
                _maybe_fire_image_alert(ref, meta, registry, dig, entry, ignores)
        except Exception as e:
            entry['last_error'] = f'{e.__class__.__name__}: {e}'[:200]
    store['images'] = images
    store['last_full_scan'] = now
    save(IMAGE_UPDATES_FILE, store)
    return checked


def _image_ignored(ref, registry_digest, ignores):
    """True if ``ref`` is currently ignored ("accept this version").

    An entry suppresses the image while the registry digest still matches
    the one the operator accepted (``acked_digest``). An empty acked_digest
    is a blanket mute. A *newer* upstream digest no longer matches, so the
    image re-surfaces — the operator accepted that version, not the next.
    """
    e = ignores.get(ref)
    if not e:
        return False
    acked = (e.get('acked_digest') or '').strip()
    if not acked:
        return True
    return acked == (registry_digest or '')


def _maybe_fire_image_alert(ref, meta, registry, registry_digest, entry, ignores):
    """Fire (or auto-resolve) the image-update alert for one ref, debounced.

    Stale = some host's pulled digest differs from the registry's current
    one. We alert once per registry digest (``alerted_digest`` on the cache
    entry, persisted across CGI processes), re-alert when upstream publishes
    a newer digest, and fire the ``image_updated`` recover once every host
    has caught up. Ignored ("accepted") refs never alert.
    """
    if _image_ignored(ref, registry_digest, ignores):
        return
    local_digests = meta.get('local_digests') or set()
    stale = any(ld != registry_digest for ld in local_digests)
    payload = {
        'image':       meta.get('image', ''),
        'tag':         meta.get('tag', ''),
        'registry':    registry,
        'hosts_count': len(meta.get('devices') or ()),
    }
    if stale:
        if entry.get('alerted_digest') != registry_digest:
            try:
                fire_webhook('image_update_available', payload)
            except Exception:
                pass
            entry['alerted_digest'] = registry_digest
    elif entry.get('alerted_digest'):
        try:
            fire_webhook('image_updated', payload)
        except Exception:
            pass
        entry['alerted_digest'] = ''


def _image_stale(local_digest, registry_digest):
    """Canonical container-staleness test: a known registry digest that
    differs from the locally-running digest. Shared by the fleet Image
    Updates view and the per-device containers endpoint (v3.14.0) so the
    two never disagree. A missing digest on either side → not stale
    (locally-built / not-yet-checked images don't count as updates)."""
    local = (local_digest or '').strip()
    reg = (registry_digest or '').strip()
    return bool(reg and local and local != reg)


def _image_update_view():
    """Per-image rows joining the registry-digest cache against live
    container digests.

    Includes every running image, not just registry-checkable ones:
    locally-built / loaded images (no reported digest) appear as explicit
    ``local`` rows rather than silently vanishing. Ignored ("accepted")
    refs are flagged and don't count as updates. Staleness is derived here
    so the cache never holds stale host lists.
    """
    images = (load(IMAGE_UPDATES_FILE) or {}).get('images') or {}
    ignores = load(IMAGE_IGNORE_FILE) or {}
    cstore = load(CONTAINERS_FILE) or {}
    devs = load(DEVICES_FILE) or {}

    # One pass over every container: group by ref, remember hosts, and note
    # whether any host reported a registry digest (else it's a local image).
    refs = {}
    for dev_id, rec in cstore.items():
        if not isinstance(rec, dict):
            continue
        dname = (devs.get(dev_id) or {}).get('name') or dev_id
        for c in rec.get('items', []) or []:
            if not isinstance(c, dict):
                continue
            image = (c.get('image') or '').strip()
            if not image:
                continue
            tag = (c.get('tag') or '').strip() or 'latest'
            local = (c.get('repo_digest') or '').strip()
            ref = f'{image}:{tag}'
            e = refs.setdefault(ref, {'image': image, 'tag': tag,
                                      'hosts': [], 'any_digest': False})
            e['hosts'].append({
                'device_id': dev_id, 'device_name': dname,
                'container': c.get('name') or '', 'local_digest': local,
                'compose_dir': c.get('compose_dir') or '',
            })
            if local.startswith('sha256:'):
                e['any_digest'] = True

    rows = []
    for ref, e in refs.items():
        cache = images.get(ref) or {}
        reg_dig = (cache.get('registry_digest') or '').strip()
        is_local = not e['any_digest']
        ign = ignores.get(ref)
        ignored = bool(ign) and _image_ignored(ref, reg_dig, ignores)
        update_available = False
        if is_local:
            for h in e['hosts']:
                h['stale'] = False
        else:
            for h in e['hosts']:
                h['stale'] = _image_stale(h['local_digest'], reg_dig)
                update_available = update_available or h['stale']
        if ignored:
            update_available = False
        rows.append({
            'image': e['image'], 'tag': e['tag'], 'ref': ref,
            'local': is_local,
            'registry': cache.get('registry', ''),
            'registry_digest': reg_dig,
            'update_available': update_available,
            'ignored': ignored,
            'ignore_reason': (ign or {}).get('reason', '') if ignored else '',
            'checked': (not is_local) and (bool(reg_dig) or bool(cache.get('last_error'))),
            'last_checked': int(cache.get('last_checked', 0)),
            'last_error': cache.get('last_error', ''),
            'hosts': e['hosts'],
        })

    # Sort: actionable updates first, then unchecked, then up-to-date,
    # then local, then ignored — each group alphabetised by ref.
    def _rank(r):
        if r['update_available']:
            return 0
        if r['ignored']:
            return 4
        if r['local']:
            return 3
        if r['registry_digest']:
            return 2
        return 1
    rows.sort(key=lambda r: (_rank(r), r['ref']))
    return rows


def handle_image_updates_get():
    """GET /api/image-updates — fleet-wide container-image freshness view."""
    require_auth()
    rows = _image_update_view()
    cfg = load(CONFIG_FILE)
    store = load(IMAGE_UPDATES_FILE) or {}
    summary = {
        'total':             len(rows),
        'updates_available': sum(1 for r in rows if r['update_available']),
        'unchecked':         sum(1 for r in rows
                                 if not r['checked'] and not r['local'] and not r['ignored']),
        'local':             sum(1 for r in rows if r['local']),
        'ignored':           sum(1 for r in rows if r['ignored']),
        'last_full_scan':    int(store.get('last_full_scan', 0)),
        'enabled':           _image_scan_enabled(cfg),
        'interval':          max(3600, int(cfg.get('image_scan_interval', IMAGE_SCAN_INTERVAL))),
    }
    respond(200, {'images': rows, 'summary': summary})


def handle_image_updates_scan():
    """POST /api/image-updates/scan — force a registry refresh now (admin)."""
    require_admin_auth()
    cfg = load(CONFIG_FILE)
    if not _image_scan_enabled(cfg):
        respond(400, {'error': 'image-update detection is disabled'})
    fleet = _collect_fleet_images()
    if not fleet:
        respond(200, {'ok': True, 'checked': 0,
                      'note': 'no container images with digests reported yet'})
    checked = _scan_images(list(fleet.keys()), fleet, cfg, force=True)
    cfg2 = load(CONFIG_FILE)
    cfg2['last_image_scan'] = int(time.time())
    save(CONFIG_FILE, cfg2)
    respond(200, {'ok': True, 'checked': checked})


_IMAGE_REF_RE = re.compile(r'^[A-Za-z0-9][A-Za-z0-9._/:@-]{0,599}$')


def handle_image_ignore_add():
    """POST /api/image-updates/ignore — accept an image's current version.

    Body: {ref, reason?}. Records the registry digest currently known for
    that ref as ``acked_digest`` (empty if not scanned yet → blanket mute),
    so the image is suppressed until a *newer* upstream digest appears.
    """
    actor = require_admin_auth()
    body = get_json_obj()
    ref = _sanitize_str(body.get('ref', ''), 600, allow_empty=False)
    reason = _sanitize_str(body.get('reason', ''), 256)
    if not ref or not _IMAGE_REF_RE.match(ref):
        respond(400, {'error': 'valid image ref (image:tag) required'})
    images = (load(IMAGE_UPDATES_FILE) or {}).get('images') or {}
    acked = (images.get(ref) or {}).get('registry_digest', '') or ''
    ignores = load(IMAGE_IGNORE_FILE) or {}
    ignores[ref] = {
        'acked_digest': acked,
        'reason':       reason,
        'actor':        actor,
        'ts':           int(time.time()),
    }
    save(IMAGE_IGNORE_FILE, ignores)
    audit_log(actor, 'image_ignore_add',
              detail=f'{ref} acked={acked[:19]} reason={reason[:80]}')
    respond(200, {'ok': True, 'ignored': ref})


def handle_image_ignore_remove():
    """DELETE /api/image-updates/ignore — stop ignoring an image. Body: {ref}."""
    actor = require_admin_auth()
    body = get_json_obj()
    ref = _sanitize_str(body.get('ref', ''), 600, allow_empty=False)
    ignores = load(IMAGE_IGNORE_FILE) or {}
    if ref in ignores:
        del ignores[ref]
        save(IMAGE_IGNORE_FILE, ignores)
        audit_log(actor, 'image_ignore_remove', detail=ref)
    respond(200, {'ok': True})


# ── v3.3.4: docker-compose stacks (upload + deploy) ────────────────────────
#
# Lifecycle-core: upload/paste a compose file as a named "stack" targeted at
# a device, then up / down / redeploy. Deploying is gated behind the
# device's compose_enabled opt-in (default off), admin-only, and audited —
# it runs an arbitrary compose file as root on the host. The agent fetches
# the YAML itself (POST /api/compose/fetch, device-token auth) so the file
# (and any secrets in it) never lands in the command queue/log; the run goes
# through argv (no shell), and status comes back via the normal command-
# output channel (the compose_deploy hook in handle_heartbeat).

_STACK_NAME_RE = re.compile(r'^[a-z0-9][a-z0-9_-]{0,63}$')
COMPOSE_YAML_MAX = 128 * 1024
_COMPOSE_ACTIONS = ('up', 'down', 'redeploy')


def _compose_status_from(action, rc):
    if rc != 0:
        return 'error'
    return 'down' if action == 'down' else 'up'   # up / redeploy → up


# ── v5.1.0: app catalog — one-click deploy of curated compose templates ──────
# A curated set of popular, self-contained homelab apps. "Deploy" instantiates
# the template as a compose STACK (reusing compose_stacks.json) and triggers the
# existing, audited compose_deploy path — so the agent fetches + runs the YAML
# exactly as for a hand-authored stack. No new agent code, no new privilege.
APP_CATALOG = (
    {'id': 'uptime-kuma', 'name': 'Uptime Kuma', 'category': 'Monitoring',
     'description': 'Self-hosted uptime monitor with a clean status dashboard.',
     'port': 3001,
     'yaml': ('services:\n  uptime-kuma:\n    image: louislam/uptime-kuma:1\n'
              '    container_name: uptime-kuma\n    restart: unless-stopped\n'
              '    ports:\n      - "3001:3001"\n    volumes:\n'
              '      - uptime-kuma:/app/data\nvolumes:\n  uptime-kuma:\n')},
    {'id': 'it-tools', 'name': 'IT-Tools', 'category': 'Utilities',
     'description': 'A handy collection of developer / sysadmin tools in one page.',
     'port': 8080,
     'yaml': ('services:\n  it-tools:\n    image: corentinth/it-tools:latest\n'
              '    container_name: it-tools\n    restart: unless-stopped\n'
              '    ports:\n      - "8080:80"\n')},
    {'id': 'dozzle', 'name': 'Dozzle', 'category': 'Monitoring',
     'description': 'Real-time Docker container log viewer in the browser.',
     'port': 8888,
     'yaml': ('services:\n  dozzle:\n    image: amir20/dozzle:latest\n'
              '    container_name: dozzle\n    restart: unless-stopped\n'
              '    ports:\n      - "8888:8080"\n    volumes:\n'
              '      - /var/run/docker.sock:/var/run/docker.sock:ro\n')},
    {'id': 'linkding', 'name': 'Linkding', 'category': 'Productivity',
     'description': 'Minimal self-hosted bookmark manager.',
     'port': 9090,
     'yaml': ('services:\n  linkding:\n    image: sissbruecker/linkding:latest\n'
              '    container_name: linkding\n    restart: unless-stopped\n'
              '    ports:\n      - "9090:9090"\n    volumes:\n'
              '      - linkding:/etc/linkding/data\nvolumes:\n  linkding:\n')},
    {'id': 'whoami', 'name': 'whoami', 'category': 'Utilities',
     'description': 'Tiny test service that echoes request info — handy to verify a deploy.',
     'port': 8088,
     'yaml': ('services:\n  whoami:\n    image: traefik/whoami:latest\n'
              '    container_name: whoami\n    restart: unless-stopped\n'
              '    ports:\n      - "8088:80"\n')},
)
_APP_CATALOG_BY_ID = {a['id']: a for a in APP_CATALOG}


def _custom_apps():
    """Admin-added catalog entries — stored as a dict {id: app}; returned as a list."""
    raw = load(APP_CATALOG_CUSTOM_FILE) or {}
    return [a for a in raw.values() if isinstance(a, dict) and a.get('id')]


def _app_catalog_all():
    """Curated apps + admin-added custom apps (custom ones flagged `custom:True`)."""
    apps = [dict(a) for a in APP_CATALOG]
    apps.extend({**a, 'custom': True} for a in _custom_apps())
    return apps


def _app_by_id(app_id):
    tpl = _APP_CATALOG_BY_ID.get(app_id)
    if tpl:
        return dict(tpl)
    return next((dict(a) for a in _custom_apps() if a.get('id') == app_id), None)


def handle_app_catalog():
    """GET /api/app-catalog — the curated + custom template list (incl. YAML for preview)."""
    require_auth()
    respond(200, {'apps': _app_catalog_all()})


def handle_app_catalog_custom_add():
    """POST /api/app-catalog/custom — add a custom app to the catalog (admin only).
    Body {name, yaml, category?, description?, port?}. The compose YAML is stored as
    a template; deploying it still rides the audited, permission-gated compose path
    (so this only manages the shared catalog, it never runs anything). Idempotent on
    a slugified id derived from the name (re-adding updates the entry)."""
    actor = require_admin_auth()
    body = get_json_obj()
    name = _sanitize_str(body.get('name', ''), 64, allow_empty=False)
    yaml = body.get('yaml', '')
    if not isinstance(yaml, str) or 'services:' not in yaml:
        respond(400, {'error': 'compose YAML is required and must contain a "services:" block'})
    if len(yaml) > COMPOSE_YAML_MAX:
        respond(400, {'error': f'compose YAML is too large ({COMPOSE_YAML_MAX // 1024} KB max)'})
    category = _sanitize_str(body.get('category', '') or 'Custom', 32, allow_empty=True) or 'Custom'
    description = _sanitize_str(body.get('description', ''), 240, allow_empty=True) or ''
    try:
        port = int(body.get('port') or 0) or None
    except (TypeError, ValueError):
        port = None
    if port is not None and not (1 <= port <= 65535):
        respond(400, {'error': 'port must be 1–65535'})
    # slugify the name into a stable id; the id is reused as the compose stack
    # name, so it must satisfy _STACK_NAME_RE. Never collide with a curated id.
    slug = re.sub(r'[^a-z0-9]+', '-', name.lower()).strip('-')[:48] or 'app'
    if slug in _APP_CATALOG_BY_ID:
        slug = 'custom-' + slug
    if not _STACK_NAME_RE.match(slug):
        respond(400, {'error': 'could not derive a valid id from that name'})
    entry = {'id': slug, 'name': name, 'category': category,
             'description': description, 'port': port, 'yaml': yaml}
    with _LockedUpdate(APP_CATALOG_CUSTOM_FILE) as apps:
        apps[slug] = entry
    audit_log(actor, 'app_catalog_custom_add', f'{slug} ({name})')
    respond(200, {'ok': True, 'id': slug})


def handle_app_catalog_custom_delete():
    """POST /api/app-catalog/custom/delete {id} — remove a custom app (admin only).
    Curated apps cannot be removed."""
    actor = require_admin_auth()
    app_id = _sanitize_str(get_json_obj().get('id', ''), 64, allow_empty=False)
    if app_id in _APP_CATALOG_BY_ID:
        respond(400, {'error': 'built-in catalog apps cannot be removed'})
    with _LockedUpdate(APP_CATALOG_CUSTOM_FILE) as apps:
        if app_id not in apps:
            respond(404, {'error': 'unknown custom app'})
        del apps[app_id]
    audit_log(actor, 'app_catalog_custom_delete', app_id)
    respond(200, {'ok': True})


def handle_app_catalog_deploy():
    """POST /api/app-catalog/deploy {device_id, app_id} — instantiate a catalog
    template as a compose stack and queue its deploy. Idempotent: redeploys an
    existing same-named stack on that device. Gated on `containers`, scope- and
    compose_enabled-checked, audited; the deploy itself rides the proven
    compose_deploy command path."""
    actor = require_perm('containers')
    body = get_json_obj()
    app_id = _sanitize_str(body.get('app_id', ''), 64)
    device_id = _sanitize_str(body.get('device_id', ''), 64, allow_empty=False)
    tpl = _app_by_id(app_id)
    if not tpl:
        respond(404, {'error': 'unknown app'})
    devices = load(DEVICES_FILE)
    if device_id not in devices:
        respond(404, {'error': 'device not found'})
    _scope_block_device(device_id)
    if not devices[device_id].get('compose_enabled', False):
        respond(403, {'error': 'compose deploys are disabled on this device — enable them first'})
    name, yaml = tpl['id'], tpl['yaml']
    with _LockedUpdate(COMPOSE_STACKS_FILE) as stacks:
        existing = next((sid for sid, st in stacks.items()
                         if st.get('device_id') == device_id and st.get('name') == name), None)
        if existing:
            stack_id, action = existing, 'redeploy'
            stacks[stack_id].update({'yaml': yaml, 'status': 'deploying',
                                     'last_action': action, 'last_action_ts': int(time.time())})
        else:
            stack_id, action = 's-' + os.urandom(6).hex(), 'up'
            stacks[stack_id] = {
                'name': name, 'device_id': device_id, 'yaml': yaml, 'app_id': app_id,
                'status': 'deploying', 'created_by': actor, 'created_ts': int(time.time()),
                'last_action': action, 'last_action_ts': int(time.time()),
                'last_rc': None, 'last_output': '',
            }
    audit_log(actor, 'app_catalog_deploy', f'{app_id} dev={device_id} ({action})')
    _queue_command_batch([device_id], f'compose_deploy:{action}:{stack_id}', actor)
    respond(200, {'ok': True, 'id': stack_id, 'action': action})


def handle_compose_stacks_list():
    """GET /api/compose/stacks — list stacks (metadata only, no YAML)."""
    require_auth()
    stacks = load(COMPOSE_STACKS_FILE) or {}
    devs = load(DEVICES_FILE) or {}
    items = []
    for sid, s in stacks.items():
        dev = devs.get(s.get('device_id')) or {}
        items.append({
            'id':              sid,
            'name':            s.get('name', ''),
            'device_id':       s.get('device_id', ''),
            'device_name':     dev.get('name') or s.get('device_id', ''),
            'compose_enabled': bool(dev.get('compose_enabled', False)),
            'status':          s.get('status', 'created'),
            'last_action':     s.get('last_action', ''),
            'last_action_ts':  int(s.get('last_action_ts', 0)),
            'last_rc':         s.get('last_rc'),
            'created_by':      s.get('created_by', ''),
            'created_ts':      int(s.get('created_ts', 0)),
        })
    items.sort(key=lambda x: (x['device_name'], x['name']))
    respond(200, {'stacks': items})


def handle_compose_stack_get(stack_id):
    """GET /api/compose/stacks/<id> — full stack incl. YAML + last output."""
    require_admin_auth()
    s = (load(COMPOSE_STACKS_FILE) or {}).get(stack_id)
    if not s:
        respond(404, {'error': 'stack not found'})
    out = dict(s)
    out['id'] = stack_id
    respond(200, out)


def handle_compose_stack_create():
    """POST /api/compose/stacks — create a stack {name, device_id, yaml}."""
    actor = require_admin_auth()
    body = get_json_obj()
    name = _sanitize_str(body.get('name', ''), 64).lower()
    device_id = _sanitize_str(body.get('device_id', ''), 64, allow_empty=False)
    yaml = body.get('yaml', '')
    if not _STACK_NAME_RE.match(name or ''):
        respond(400, {'error': 'name must be lowercase [a-z0-9_-], up to 64 chars'})
    if not isinstance(yaml, str) or not yaml.strip():
        respond(400, {'error': 'compose yaml required'})
    if len(yaml) > COMPOSE_YAML_MAX:
        respond(400, {'error': f'compose file too large (>{COMPOSE_YAML_MAX} bytes)'})
    if 'services:' not in yaml:
        respond(400, {'error': 'does not look like a compose file (no "services:" key)'})
    devices = load(DEVICES_FILE)
    if device_id not in devices:
        respond(404, {'error': 'device not found'})
    stacks = load(COMPOSE_STACKS_FILE) or {}
    for s in stacks.values():
        if s.get('device_id') == device_id and s.get('name') == name:
            respond(409, {'error': f'a stack named "{name}" already exists on this device'})
    stack_id = 's-' + os.urandom(6).hex()
    stacks[stack_id] = {
        'name': name, 'device_id': device_id, 'yaml': yaml,
        'status': 'created', 'created_by': actor, 'created_ts': int(time.time()),
        'last_action': '', 'last_action_ts': 0, 'last_rc': None, 'last_output': '',
    }
    save(COMPOSE_STACKS_FILE, stacks)
    audit_log(actor, 'compose_stack_create', f'{name} dev={device_id}')
    respond(200, {'ok': True, 'id': stack_id})


def handle_compose_stack_delete(stack_id):
    """DELETE /api/compose/stacks/<id> — drop the stored definition (admin).

    Does NOT tear down running containers — run "down" first if you want
    that. We only forget the stack."""
    actor = require_admin_auth()
    stacks = load(COMPOSE_STACKS_FILE) or {}
    if stack_id in stacks:
        name = stacks[stack_id].get('name', '')
        del stacks[stack_id]
        save(COMPOSE_STACKS_FILE, stacks)
        audit_log(actor, 'compose_stack_delete', f'{name} ({stack_id})')
    respond(200, {'ok': True})


def handle_compose_stack_action(stack_id):
    """POST /api/compose/stacks/<id>/action {action} — queue up/down/redeploy."""
    actor = require_perm('containers')   # v3.12.0 RBAC: was admin-only
    body = get_json_obj()
    action = _sanitize_str(body.get('action', ''), 16).lower()
    if action not in _COMPOSE_ACTIONS:
        respond(400, {'error': f'action must be one of {_COMPOSE_ACTIONS}'})
    stacks = load(COMPOSE_STACKS_FILE) or {}
    s = stacks.get(stack_id)
    if not s:
        respond(404, {'error': 'stack not found'})
    device_id = s.get('device_id')
    _scope_block_device(device_id)       # a scoped role can't act on a foreign device's stack
    dev = device_get(device_id)
    if not dev:
        respond(404, {'error': 'target device not found'})
    if not dev.get('compose_enabled', False):
        respond(403, {'error': 'compose deploys are disabled on this device — enable them first'})
    s['status'] = 'deploying'
    s['last_action'] = action
    s['last_action_ts'] = int(time.time())
    save(COMPOSE_STACKS_FILE, stacks)
    # _queue_command_batch queues without responding (unlike _queue_command);
    # the agent fetches the YAML itself via /api/compose/fetch.
    _queue_command_batch([device_id], f'compose_deploy:{action}:{stack_id}', actor)
    audit_log(actor, 'compose_stack_action', f'{action} {s.get("name")} dev={device_id}')
    respond(200, {'ok': True, 'queued': action})


def handle_compose_fetch():
    """POST /api/compose/fetch {device_id, token, stack_id} — agent fetches a
    stack's YAML with its device token. Kept off the command queue so the
    compose file never lands in the command log."""
    body = get_json_obj()
    device_id = str(body.get('device_id', '')).strip()
    token = str(body.get('token', '')).strip()
    stack_id = str(body.get('stack_id', '')).strip()
    dev = device_get(device_id)
    if not dev or not _device_token_ok(dev, token):
        respond(403, {'error': 'Unauthorized device'})
    s = (load(COMPOSE_STACKS_FILE) or {}).get(stack_id)
    if not s or s.get('device_id') != device_id:
        respond(404, {'error': 'stack not found for this device'})
    respond(200, {'ok': True, 'name': s.get('name', ''), 'yaml': s.get('yaml', '')})


def _routeros_target(dev):
    """(host:port, user, password, verify) for a RouterOS-enabled device, or
    None. Host comes from the device's ip/hostname; creds + port live in the
    device's `routeros` config block."""
    cfg = dev.get('routeros') or {}
    if not cfg.get('enabled'):
        return None
    host = dev.get('ip') or dev.get('hostname') or dev.get('host')
    user = cfg.get('username') or ''
    password = cfg.get('password') or ''
    if not host or not user:
        return None
    port = int(cfg.get('port') or 443)
    # v4.4.0 (SECURITY): SSRF pre-flight on the RouterOS REST host. These
    # handlers are reachable by any authenticated user (incl. viewer), and the
    # module fetched https://{host}/rest with no anti-rebinding check. Block
    # loopback + link-local/cloud-metadata (allow_loopback=False) while still
    # permitting the RFC1918 LAN address a real router lives on.
    if _url_targets_local_or_meta(urllib.parse.urlparse(f'https://{host}'),
                                  allow_loopback=False):
        return None
    return (f'{host}:{port}', user, password, bool(cfg.get('verify', False)))


def _routeros_redacted(dev):
    cfg = dev.get('routeros') or {}
    return {
        'enabled':      bool(cfg.get('enabled')),
        'username':     cfg.get('username') or '',
        'has_password': bool(cfg.get('password')),
        'port':         int(cfg.get('port') or 443),
        'verify':       bool(cfg.get('verify', False)),
    }


def handle_device_routeros(dev_id):
    """GET /api/devices/<id>/routeros — redacted config + (if enabled) a live
    RouterOS REST overview. PATCH — admin; save {enabled, username, password,
    port, verify} (empty password preserves the stored one). v7+ REST."""
    if not _validate_id(dev_id):
        respond(400, {'error': 'invalid device id'})
    devs = load(DEVICES_FILE)
    if dev_id not in devs:
        respond(404, {'error': 'device not found'})
    m = method()
    if m == 'GET':
        require_auth()
        dev = devs[dev_id]
        redacted = _routeros_redacted(dev)
        tgt = _routeros_target(dev)
        if not tgt:
            respond(200, {'config': redacted, 'overview': None})
        host, user, password, verify = tgt
        import routeros as routeros_mod
        ov, err = None, None
        try:
            ov = routeros_mod.overview(host, user, password, verify=verify)
        except Exception as e:
            err = str(e)[:200]
        resp = {'config': redacted, 'overview': ov}
        if err:
            resp['error'] = err
        respond(200, resp)
    elif m == 'PATCH':
        actor = require_admin_auth()
        body = get_json_obj()
        with _LockedUpdate(DEVICES_FILE) as store:
            dev = store.get(dev_id) or {}
            rc = dict(dev.get('routeros') or {})
            if 'enabled' in body:
                rc['enabled'] = bool(body['enabled'])
            if 'username' in body:
                rc['username'] = _sanitize_str(str(body['username']), 64)
            if 'password' in body:
                pw = str(body['password'])
                if pw:                       # empty preserves existing
                    rc['password'] = pw[:128]
            if 'port' in body:
                try:
                    p = int(body['port'])
                    if 1 <= p <= 65535:
                        rc['port'] = p
                except (TypeError, ValueError):
                    respond(400, {'error': 'port must be 1..65535'})
            if 'verify' in body:
                rc['verify'] = bool(body['verify'])
            if rc.get('enabled') and not rc.get('username'):
                respond(400, {'error': 'username required when RouterOS is enabled'})
            if rc.get('enabled') and not rc.get('password'):
                respond(400, {'error': 'password required when RouterOS is enabled'})
            dev['routeros'] = rc
            store[dev_id] = dev
        audit_log(actor, 'device_routeros_config',
                  f'dev={dev_id} enabled={rc.get("enabled")} user={rc.get("username")}')
        respond(200, {'ok': True, 'config': _routeros_redacted({'routeros': rc})})
    else:
        respond(405, {'error': 'Method not allowed'})


