# ─── v1.7.0: CVE scanner + package inventory ──────────────────────────────────

def _sanitize_package_entry(entry):
    """Sanitize one {name,version,arch} dict from agent payload."""
    if not isinstance(entry, dict):
        return None
    name = _sanitize_str(entry.get('name', ''), 128, allow_empty=False)
    version = _sanitize_str(entry.get('version', ''), 64, allow_empty=False)
    arch = _sanitize_str(entry.get('arch', ''), 16)
    if not name or not version:
        return None
    # Package names / versions are alphanum + common punctuation
    if not re.match(r'^[A-Za-z0-9][A-Za-z0-9._+\-:~]{0,127}$', name):
        return None
    if not re.match(r'^[A-Za-z0-9][A-Za-z0-9._+\-:~]{0,63}$', version):
        return None
    return {'name': name, 'version': version, 'arch': arch}


def handle_packages_submit():
    """POST /api/packages — agent submits its installed package list."""
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})

    body = get_json_obj()
    dev_id    = str(body.get('device_id', '')).strip()
    dev_token = str(body.get('token', '')).strip()
    if not _validate_id(dev_id):
        respond(403, {'error': 'Unauthorized device'})

    devices = load(DEVICES_FILE)
    dev = devices.get(dev_id)
    if not dev or not _device_token_ok(dev, dev_token):
        respond(403, {'error': 'Unauthorized device'})

    raw_pkgs = body.get('packages') or []
    if not isinstance(raw_pkgs, list):
        respond(400, {'error': 'packages must be a list'})
    if len(raw_pkgs) > MAX_PACKAGE_LIST:
        raw_pkgs = raw_pkgs[:MAX_PACKAGE_LIST]

    packages = []
    for entry in raw_pkgs:
        safe = _sanitize_package_entry(entry)
        if safe:
            packages.append(safe)

    pkg_manager = _sanitize_str(body.get('pkg_manager', ''), 16)
    hint = body.get('ecosystem_hint') or {}
    safe_hint = {
        'ID':         _sanitize_str(hint.get('ID', ''), 32),
        'VERSION_ID': _sanitize_str(hint.get('VERSION_ID', ''), 16),
        'ID_LIKE':    _sanitize_str(hint.get('ID_LIKE', ''), 64),
    }

    ecosystem = cve_scanner.detect_ecosystem(safe_hint, pkg_manager)

    store = load(PACKAGES_FILE)
    new_hash = cve_scanner.packages_hash(packages)
    existing = store.get(dev_id, {})
    store[dev_id] = {
        'hash':         new_hash,
        'collected_at': int(time.time()),
        'ecosystem':    ecosystem or '',
        'pkg_manager':  pkg_manager,
        'count':        len(packages),
        'packages':     packages,
        # v3.4.1: structured os-release for EOL detection. The agent already
        # sends these in ecosystem_hint; persisting them avoids an agent change.
        'os_id':        safe_hint['ID'],
        'version_id':   safe_hint['VERSION_ID'],
    }
    save(PACKAGES_FILE, store)

    # v3.11.0: evaluate the fleet software policy against this push.
    try:
        _eval_software_policy(dev_id, dev.get('name', dev_id),
                              packages, dev.get('tags') or [])
    except Exception as e:
        sys.stderr.write(f"[remotepower] software policy eval failed "
                         f"dev={dev_id}: {e}\n")

    changed = existing.get('hash') != new_hash
    respond(200, {
        'ok':              True,
        'ecosystem':       ecosystem or 'unsupported',
        'packages_stored': len(packages),
        'changed':         changed,
        'scan_suggested':  changed and bool(ecosystem),
    })


# ─── v3.11.0: fleet software policy ──────────────────────────────────────────
# A policy is a list of rules evaluated against each device's installed
# package list (already collected every ~6h). Three rule types:
#   banned      — package must NOT be installed
#   required    — package MUST be installed
#   min_version — if installed, version must be >= the configured minimum
# Each rule may be scoped to one or more device tags; an unscoped rule
# applies fleet-wide. Violations are persisted per device and a
# software_policy_violation event fires edge-triggered (once per new
# violation key), so a steady-state breach doesn't re-alert every push.

def _software_policy():
    """Load the policy doc; always returns a dict with a 'rules' list."""
    doc = load(SOFTWARE_POLICY_FILE) if backend_exists(SOFTWARE_POLICY_FILE) else {}
    if not isinstance(doc, dict):
        doc = {}
    rules = doc.get('rules')
    doc['rules'] = rules if isinstance(rules, list) else []
    return doc


def _ver_key(v):
    """Coarse version → comparable tuple of ints. Splits on any non-digit
    run; good enough for the common 'openssh >= 9.0' style minimums. A
    version with no digits sorts lowest."""
    parts = re.findall(r'\d+', str(v or ''))
    return tuple(int(x) for x in parts) if parts else (-1,)


def _eval_software_policy(dev_id, dev_name, packages, tags):
    """Evaluate the policy for one device, persist its violations, and fire
    software_policy_violation for any newly-introduced violation."""
    policy = _software_policy()
    rules = policy.get('rules') or []
    store = load(SOFTWARE_VIOLATIONS_FILE) if backend_exists(SOFTWARE_VIOLATIONS_FILE) else {}
    if not isinstance(store, dict):
        store = {}
    if not rules:
        if store.pop(dev_id, None) is not None:
            save(SOFTWARE_VIOLATIONS_FILE, store)
        return []

    tagset = {str(t) for t in (tags or [])}
    installed = {}
    for p in (packages or []):
        if isinstance(p, dict) and p.get('name'):
            installed[str(p['name'])] = str(p.get('version', '') or '')

    violations = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        pkg = str(rule.get('package', '') or '').strip()
        rtype = rule.get('type')
        if not pkg or rtype not in ('banned', 'required', 'min_version'):
            continue
        rtags = {str(t) for t in (rule.get('tags') or [])}
        if rtags and not (rtags & tagset):
            continue   # rule scoped to tags this device doesn't carry
        rid = rule.get('id') or f'{rtype}:{pkg}'
        if rtype == 'banned' and pkg in installed:
            violations.append({'rule_id': rid, 'type': rtype, 'package': pkg,
                               'expected': 'not installed',
                               'found': installed[pkg] or 'installed',
                               'detail': f'banned package {pkg} is installed',
                               'note': _sanitize_str(rule.get('note', ''), 200)})
        elif rtype == 'required' and pkg not in installed:
            violations.append({'rule_id': rid, 'type': rtype, 'package': pkg,
                               'expected': 'installed', 'found': 'missing',
                               'detail': f'required package {pkg} is missing',
                               'note': _sanitize_str(rule.get('note', ''), 200)})
        elif rtype == 'min_version' and pkg in installed:
            want = str(rule.get('version', '') or '')
            have = installed[pkg]
            if want and _ver_key(have) < _ver_key(want):
                violations.append({'rule_id': rid, 'type': rtype, 'package': pkg,
                                   'expected': f'>= {want}', 'found': have or '?',
                                   'detail': f'{pkg} {have or "?"} is below minimum {want}',
                                   'note': _sanitize_str(rule.get('note', ''), 200)})

    prev_keys = {v.get('rule_id') for v in (store.get(dev_id, {}) or {}).get('violations', [])}
    for v in violations:
        if v['rule_id'] not in prev_keys:
            try:
                fire_webhook('software_policy_violation', {
                    'device_id': dev_id, 'name': dev_name,
                    'rule': v['rule_id'], 'package': v['package'],
                    'detail': v['detail'],
                })
            except Exception:
                pass

    if violations:
        store[dev_id] = {'name': dev_name, 'checked_at': int(time.time()),
                         'violations': violations}
    else:
        store.pop(dev_id, None)
    save(SOFTWARE_VIOLATIONS_FILE, store)
    return violations


def _reeval_software_policy_all():
    """Re-evaluate every device with stored packages (called after the
    policy is edited so the violations view reflects the new ruleset)."""
    pkgstore = load(PACKAGES_FILE) if backend_exists(PACKAGES_FILE) else {}
    devices = load(DEVICES_FILE)
    total = 0
    for dev_id, rec in (pkgstore or {}).items():
        dev = devices.get(dev_id) or {}
        try:
            v = _eval_software_policy(dev_id, dev.get('name', dev_id),
                                      rec.get('packages') or [], dev.get('tags') or [])
            total += len(v)
        except Exception:
            pass
    return total


def handle_software_policy():
    """GET  /api/software-policy        — the ruleset
       POST /api/software-policy        — replace the ruleset (admin)
       GET  /api/software-policy/violations — current fleet violations"""
    require_auth()
    m = method()
    if m == 'GET':
        respond(200, _software_policy())
    elif m == 'POST':
        require_admin_auth()
        body = get_json_obj()
        rules_in = body.get('rules')
        if not isinstance(rules_in, list):
            respond(400, {'error': 'rules must be a list'})
        clean = []
        for r in rules_in[:500]:
            if not isinstance(r, dict):
                continue
            rtype = r.get('type')
            pkg = _sanitize_str(r.get('package', ''), 128)
            if rtype not in ('banned', 'required', 'min_version') or not pkg:
                continue
            entry = {
                'id':      _sanitize_str(r.get('id', '') or f'{rtype}:{pkg}', 64),
                'type':    rtype,
                'package': pkg,
                'note':    _sanitize_str(r.get('note', ''), 200),
            }
            if rtype == 'min_version':
                entry['version'] = _sanitize_str(r.get('version', ''), 32)
            tg = r.get('tags')
            if isinstance(tg, list):
                entry['tags'] = [_sanitize_str(t, 48) for t in tg[:20] if isinstance(t, str) and t]
            clean.append(entry)
        save(SOFTWARE_POLICY_FILE, {'rules': clean, 'updated_at': int(time.time())})
        audit_log(current_username() or 'unknown', 'software_policy_save',
                  detail=f'{len(clean)} rules')
        affected = _reeval_software_policy_all()
        respond(200, {'ok': True, 'rules': len(clean), 'violations': affected})
    else:
        respond(405, {'error': 'Method not allowed'})


def handle_software_policy_violations():
    """GET /api/software-policy/violations — flat list of current violations."""
    require_auth()
    store = load(SOFTWARE_VIOLATIONS_FILE) if backend_exists(SOFTWARE_VIOLATIONS_FILE) else {}
    out = []
    for dev_id, rec in (store or {}).items():
        for v in (rec.get('violations') or []):
            out.append({'device_id': dev_id, 'device': rec.get('name', dev_id),
                        'checked_at': rec.get('checked_at'), **v})
    respond(200, {'violations': out, 'count': len(out)})


# ─── v3.11.0: attack-surface exposure + storage health rollups ───────────────

def handle_exposure_overview():
    """GET /api/exposure — fleet-wide listening-socket inventory with the
    bind-scope each agent reported. ?scope=world filters to world-reachable."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    want = (qs.get('scope', [''])[0] or '').strip().lower()
    _cfg = load(CONFIG_FILE) or {}
    audit_enabled = bool(_cfg.get('port_audit_enabled', False))
    mutes = _cfg.get('exposure_mutes') or []
    devices = load(DEVICES_FILE)
    rows = []
    counts = {'world': 0, 'lan': 0, 'local': 0, 'unknown': 0}
    for dev_id, d in (devices or {}).items():
        # Telemetry/inventory view — unmonitored hosts still SHOW their data
        # (only alerting is suppressed for them), flagged so the UI can badge it.
        for p in ((d.get('sysinfo') or {}).get('listening_ports') or []):
            scope = p.get('scope') or 'unknown'
            counts[scope] = counts.get(scope, 0) + 1
            if want and scope != want:
                continue
            rows.append({
                'device_id': dev_id, 'device': d.get('name', dev_id),
                'monitored': d.get('monitored') is not False,
                'proto': p.get('proto', 'tcp'), 'port': p.get('port'),
                'process': p.get('process', ''), 'addr': p.get('addr', ''),
                'scope': scope,
                'muted': _exposure_muted(p.get('process'), p.get('proto', 'tcp'),
                                         p.get('port'), mutes, dev_id),
            })
    rows.sort(key=lambda r: ({'world': 0, 'lan': 1, 'local': 2}.get(r['scope'], 3),
                             r['device'], r['port'] or 0))
    respond(200, {'ports': rows, 'counts': counts, 'count': len(rows),
                  'audit_enabled': audit_enabled, 'mutes': mutes})


def handle_exposure_mute():
    """POST /api/exposure/mute — add or remove a surgical exposure-mute rule.

    Body: {action: 'add'|'remove', process?, proto?, port?}. Adding a rule
    silences future new_port_detected / port_exposed_world for matching sockets
    and resolves any matching open alerts in one move. Admin-only, audited."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'}); return
    body = get_json_obj()
    action = body.get('action', 'add')
    if action not in ('add', 'remove'):
        respond(400, {'error': "action must be 'add' or 'remove'"}); return
    rule = {}
    if body.get('device_id'):
        rule['device_id'] = _sanitize_str(body['device_id'], 64)
    if body.get('process'):
        rule['process'] = _sanitize_str(body['process'], 64)
    if body.get('proto'):
        rule['proto'] = _sanitize_str(body['proto'], 8)
    if body.get('port') not in (None, ''):
        try:
            rule['port'] = int(body['port'])
        except (TypeError, ValueError):
            respond(400, {'error': 'port must be an integer'}); return
    if not rule:
        respond(400, {'error': 'specify at least one of device / process / proto / port'})
        return
    with _LockedUpdate(CONFIG_FILE) as cfg:
        mutes = cfg.get('exposure_mutes') or []
        if action == 'remove':
            mutes = [m for m in mutes if m != rule]
        elif rule not in mutes:
            mutes.append(rule)
        cfg['exposure_mutes'] = mutes[:200]
    resolved = 0
    if action == 'add':
        resolved = _resolve_alerts_for_events(_EXPOSURE_ALERT_EVENTS, match_rule=rule)
    audit_log(actor, 'exposure_mute', detail=f'{action} {rule}')
    respond(200, {'ok': True, 'mutes': mutes, 'resolved': resolved})


def handle_storage_overview():
    """GET /api/storage — fleet-wide ZFS/mdadm/btrfs pool health."""
    require_auth()
    devices = load(DEVICES_FILE)
    rows = []
    degraded = 0
    _BAD = ('degraded', 'faulted', 'offline', 'unavail', 'removed',
            'suspended', 'error', 'fail')
    for dev_id, d in (devices or {}).items():
        # Telemetry view — show unmonitored hosts' pools too (alerting only is
        # suppressed for them), flagged for the UI.
        for p in ((d.get('sysinfo') or {}).get('storage_health') or []):
            st = (p.get('state') or '').lower()
            bad = any(b in st for b in _BAD)
            if bad:
                degraded += 1
            kind = p.get('kind', '')
            # The actionable target for maintenance commands: a zpool is named by
            # its pool, a btrfs fs by a mountpoint. mdraid has no run-actions.
            target = p.get('name') if kind == 'zfs' else (p.get('mount') or '')
            rows.append({
                'device_id': dev_id, 'device': d.get('name', dev_id),
                'monitored': d.get('monitored') is not False,
                'pool': p.get('name'), 'kind': kind,
                'state': p.get('state', ''), 'capacity': p.get('capacity'),
                'scrub': p.get('scrub', ''), 'degraded': bad,
                'target': target, 'online': (int(time.time()) - d.get('last_seen', 0)) < get_online_ttl(),
            })
    rows.sort(key=lambda r: (0 if r['degraded'] else 1, r['device'], r['pool'] or ''))
    respond(200, {'pools': rows, 'degraded': degraded, 'count': len(rows)})


# ─── v3.14.0: fleet thermal roll-up ("hottest hosts") ────────────────────────
# Mirrors handle_storage_overview: one row per host with its hottest sensor, so
# temperatures are answerable fleet-wide instead of only inside one device's
# drawer. Reads the per-device hardware.json the agent already reports — no agent
# or schema change. Thresholds match the device-drawer temps (>=75 °C = hot).
THERMAL_HOT_C = 75.0
THERMAL_CRIT_C = 85.0


def handle_fleet_thermal():
    """GET /api/fleet/thermal — hottest-host roll-up across the fleet."""
    require_auth()
    devices = load(DEVICES_FILE) or {}
    hw_all = load(HARDWARE_FILE) or {}
    temp_hist = load(THERMAL_HIST_FILE) or {}
    rows = []
    hot = 0
    for dev_id, d in devices.items():
        # Telemetry view — unmonitored hosts still appear (alerting only is
        # suppressed for them); the row carries a `monitored` flag for the UI.
        hw = hw_all.get(dev_id) or {}
        hottest = None  # (temp_c, label, kind, crit_c)
        sensors = 0
        detail = []      # per-sensor breakdown (hover); capped below
        gpu_extra = None  # fan/util/power, carried when a GPU is the hottest sensor
        for t in (hw.get('temps') or []):
            c = t.get('current_c')
            if not isinstance(c, (int, float)):
                continue
            sensors += 1
            cr = t.get('crit_c') if isinstance(t.get('crit_c'), (int, float)) else None
            lbl = str(t.get('label') or 'sensor')
            detail.append({'label': lbl, 'temp': round(float(c), 1), 'type': 'sensor', 'crit': cr})
            if hottest is None or c > hottest[0]:
                hottest = (float(c), lbl, 'sensor', cr)
        for s in (hw.get('smart') or []):
            c = s.get('temperature_c')
            if not isinstance(c, (int, float)):
                continue
            sensors += 1
            lbl = str(s.get('device') or 'disk')
            detail.append({'label': lbl, 'temp': round(float(c), 1), 'type': 'disk', 'crit': None})
            if hottest is None or c > hottest[0]:
                hottest = (float(c), lbl, 'disk', None)
        for g in (hw.get('gpus') or []):    # v3.14.0: GPUs are sensors too
            c = g.get('temp_c')
            if not isinstance(c, (int, float)):
                continue
            sensors += 1
            lbl = str(g.get('name') or 'GPU')
            detail.append({'label': lbl, 'temp': round(float(c), 1), 'type': 'gpu', 'crit': None})
            if hottest is None or c > hottest[0]:
                hottest = (float(c), lbl, 'gpu', None)
                gpu_extra = {k: g.get(j) for k, j in
                             (('fan_pct', 'fan_pct'), ('util_pct', 'util_pct'), ('power_w', 'power_w'))
                             if isinstance(g.get(j), (int, float))} or None
        if hottest is None:
            continue  # host reports no temperatures — omit rather than show 0 °C
        max_c = round(hottest[0], 1)
        crit_c = hottest[3]
        headroom = round(crit_c - max_c, 1) if isinstance(crit_c, (int, float)) else None
        is_hot = max_c >= THERMAL_HOT_C
        if is_hot:
            hot += 1
        detail.sort(key=lambda x: -x['temp'])
        # v5.0.0: last ~48 samples (~4h at the hardware cadence) of the host's
        # hottest reading, for the Thermal-page trend sparkline.
        _samples = ((temp_hist.get(dev_id) or {}).get('samples') or [])[-48:]
        trend = [s['temp'] for s in _samples if isinstance(s.get('temp'), (int, float))]
        rows.append({
            'device_id': dev_id, 'device': d.get('name', dev_id),
            'monitored': d.get('monitored') is not False,
            'max_temp': max_c, 'sensor_label': hottest[1], 'sensor_type': hottest[2],
            'sensors': sensors, 'crit_c': crit_c, 'headroom': headroom,
            'detail': detail[:16], 'gpu': gpu_extra, 'trend': trend,
            'hot': is_hot, 'critical': max_c >= THERMAL_CRIT_C,
            'reported_at': hw.get('ts', 0),
        })
    rows.sort(key=lambda r: -r['max_temp'])
    respond(200, {'hosts': rows, 'count': len(rows), 'hot': hot})


# ─── v4.7.0: fleet GPU roll-up (NVIDIA + AMD) ────────────────────────────────
GPU_HOT_C = 85.0


def _gpu_display_name(g):
    """GPU name with a redundant leading vendor word stripped. nvidia-smi reports
    'NVIDIA GeForce RTX 4070 Ti SUPER' and the card already shows a vendor pill,
    so the raw name would read 'NVIDIA NVIDIA GeForce …'. Falls back to the raw
    name (or 'GPU') if stripping would leave nothing."""
    name = str(g.get('name') or 'GPU').strip()
    for pre in ('NVIDIA ', 'AMD ', 'Advanced Micro Devices, Inc. ',
                'Advanced Micro Devices ', 'ATI ', 'Intel '):
        if name.lower().startswith(pre.lower()) and len(name) > len(pre):
            return name[len(pre):].strip()
    return name


def handle_fleet_gpus():
    """GET /api/fleet/gpus — every GPU across the fleet, one row per GPU.

    Reads the per-device gpus the agent already reports in hardware.json (NVIDIA
    via nvidia-smi, AMD via rocm-smi or the amdgpu sysfs fallback) — no schema
    change. Hottest/busiest first; carries a fleet summary."""
    require_auth()
    devices = load(DEVICES_FILE) or {}
    hw_all = load(HARDWARE_FILE) or {}
    gpu_hist = load(GPU_HIST_FILE) or {}
    now = int(time.time())
    ttl = get_online_ttl()
    rows = []
    for dev_id, d in devices.items():
        # GPU inventory shows EVERY host with a GPU, including unmonitored ones
        # (e.g. a workstation you don't alert on) — this is a telemetry view, not
        # an alerting view, so don't hide them the way thermal/storage do.
        # `online` is COMPUTED from last_seen (it's never stored on the record),
        # the same way device_list / the network map do it.
        if d.get('agentless'):
            online = _agentless_online(d)
        else:
            online = (now - d.get('last_seen', 0)) < ttl
        hw = hw_all.get(dev_id) or {}
        dev_hist = gpu_hist.get(dev_id) or {}
        for gi, g in enumerate(hw.get('gpus') or []):
            if not isinstance(g, dict):
                continue
            mu, mt = g.get('mem_used_mb'), g.get('mem_total_mb')
            mem_pct = (round(100.0 * mu / mt, 1)
                       if isinstance(mu, (int, float)) and isinstance(mt, (int, float)) and mt else None)
            # Trend series for the card sparklines — last ~48 samples (~4h) of
            # temperature and utilisation, matched by GPU index.
            samples = ((dev_hist.get(str(gi)) or {}).get('samples') or [])[-48:]
            trend_temp = [s['temp'] for s in samples if isinstance(s.get('temp'), (int, float))]
            trend_util = [s['util'] for s in samples if isinstance(s.get('util'), (int, float))]
            rows.append({
                'device_id': dev_id, 'device': d.get('name', dev_id),
                'online': online,
                'monitored': d.get('monitored') is not False,
                'vendor': g.get('vendor', ''), 'name': _gpu_display_name(g),
                'util_pct': g.get('util_pct'), 'temp_c': g.get('temp_c'),
                'power_w': g.get('power_w'), 'fan_pct': g.get('fan_pct'),
                'mem_used_mb': mu, 'mem_total_mb': mt, 'mem_pct': mem_pct,
                'trend_temp': trend_temp, 'trend_util': trend_util,
            })
    rows.sort(key=lambda r: (-(r['temp_c'] or 0), -(r['util_pct'] or 0), str(r['device'])))
    summary = {
        'gpus': len(rows),
        'devices': len({r['device_id'] for r in rows}),
        'nvidia': sum(1 for r in rows if r['vendor'] == 'nvidia'),
        'amd': sum(1 for r in rows if r['vendor'] == 'amd'),
        'total_power_w': round(sum(r['power_w'] or 0 for r in rows), 1),
        'hot': sum(1 for r in rows if (r['temp_c'] or 0) >= GPU_HOT_C),
    }
    respond(200, {'gpus': rows, 'summary': summary})


def handle_fleet_power():
    """GET /api/fleet/power — UPS status + measured power draw per host.

    Watts come from the UPS load (ups.power_w) when available, else the sum of
    GPU power draw. Energy/cost is left to the client (a cost/kWh the operator
    sets) since tariffs vary; we return the instantaneous total watts."""
    require_auth()
    devices = load(DEVICES_FILE) or {}
    hw_all = load(HARDWARE_FILE) or {}
    rows = []
    total_w = 0.0
    on_battery = 0
    for dev_id, d in devices.items():
        # Telemetry view — unmonitored hosts still show power/UPS data (alerting
        # only is suppressed for them), flagged for the UI.
        hw = hw_all.get(dev_id) or {}
        ups_list = hw.get('ups') or []
        gpus = hw.get('gpus') or []
        ups_w = sum(u.get('power_w') or 0 for u in ups_list if isinstance(u, dict))
        gpu_w = sum(g.get('power_w') or 0 for g in gpus if isinstance(g, dict))
        watts = ups_w or gpu_w
        if not ups_list and not watts:
            continue  # nothing power-related reported — omit
        u0 = ups_list[0] if ups_list else {}
        status = str(u0.get('status', '')) if ups_list else ''
        ob = bool(ups_list) and ('OB' in status or 'BATT' in status.upper())
        if ob:
            on_battery += 1
        if watts:
            total_w += watts
        rows.append({
            'device_id':   dev_id, 'device': d.get('name', dev_id),
            'monitored':   d.get('monitored') is not False,
            'ups':         bool(ups_list),
            'ups_name':    str(u0.get('name', '')) if ups_list else '',
            'status':      status,
            'on_battery':  ob,
            'battery_pct': u0.get('battery_pct') if ups_list else None,
            'load_pct':    u0.get('load_pct') if ups_list else None,
            'runtime_s':   u0.get('runtime_s') if ups_list else None,
            'watts':       round(watts, 1) if watts else None,
            'watts_source': 'ups' if ups_w else ('gpu' if gpu_w else ''),
        })
    rows.sort(key=lambda r: (-(1 if r['on_battery'] else 0), -(r['watts'] or 0), r['device'].lower()))
    respond(200, {'hosts': rows, 'count': len(rows),
                  'total_watts': round(total_w, 1), 'on_battery': on_battery})


def _chargeback_breakdown(devices, hw_all):
    """v3.14.0 (#41): aggregate per-host power draw into per-group and per-tag
    totals + an estimated monthly kWh (rate-independent — the UI applies the
    operator's price/kWh). Same watt source as the Power page (UPS load else GPU
    draw). Pure → unit-testable."""
    hours_month = 24 * 30.44
    by_group, by_tag = {}, {}
    total_w, hosts = 0.0, 0
    for dev_id, d in (devices or {}).items():
        # Cost ALLOCATION deliberately excludes unmonitored hosts (you don't bill
        # devices you've opted out of managing) — distinct from data visibility:
        # the raw power telemetry is still shown on the Power page.
        if not isinstance(d, dict) or d.get('monitored') is False:
            continue
        hw = (hw_all or {}).get(dev_id) or {}
        ups_w = sum(u.get('power_w') or 0 for u in (hw.get('ups') or []) if isinstance(u, dict))
        gpu_w = sum(g.get('power_w') or 0 for g in (hw.get('gpus') or []) if isinstance(g, dict))
        watts = ups_w or gpu_w
        if not watts:
            continue
        total_w += watts
        hosts += 1
        g = by_group.setdefault(d.get('group') or 'ungrouped', {'hosts': 0, 'watts': 0.0})
        g['hosts'] += 1
        g['watts'] += watts
        for t in (d.get('tags') or [])[:20]:
            tg = by_tag.setdefault(str(t), {'hosts': 0, 'watts': 0.0})
            tg['hosts'] += 1
            tg['watts'] += watts

    def _rows(m):
        out = [{'name': k, 'hosts': v['hosts'], 'watts': round(v['watts'], 1),
                'kwh_month': round(v['watts'] / 1000.0 * hours_month, 1)}
               for k, v in m.items()]
        out.sort(key=lambda r: -r['watts'])
        return out

    return {'groups': _rows(by_group), 'tags': _rows(by_tag),
            'total': {'hosts': hosts, 'watts': round(total_w, 1),
                      'kwh_month': round(total_w / 1000.0 * hours_month, 1)}}


def handle_fleet_chargeback():
    """GET /api/fleet/chargeback — per-group / per-tag power & monthly kWh, for
    cost allocation. Scope-filtered; the price/kWh is applied client-side."""
    require_auth()
    devices = _scope_filter_devices(load(DEVICES_FILE) or {})
    respond(200, _chargeback_breakdown(devices, load(HARDWARE_FILE) or {}))


def handle_fleet_secrets():
    """GET /api/fleet/secrets — redacted secret findings across the fleet,
    scope-filtered. Values are never present (the agent strips them); each
    finding carries rule / path / masked preview / fingerprint. Auth: require_auth."""
    require_auth()
    store = load(SECRETS_FILE) or {}
    devices = _scope_filter_devices(load(DEVICES_FILE) or {})
    cfg = load(CONFIG_FILE) or {}
    muted = set(cfg.get('secrets_mutes') or [])
    host_mutes = set(cfg.get('secrets_host_mutes') or [])   # v4.1.0 (#55)
    out, total_active = [], 0
    for did, rec in store.items():
        if did not in devices:
            continue
        hmuted = did in host_mutes
        findings = [{**f, 'muted': hmuted or (f.get('fingerprint', '') in muted)}
                    for f in (rec.get('findings') or []) if isinstance(f, dict)]
        # A host-muted device contributes 0 to the active total.
        active = 0 if hmuted else sum(1 for f in findings if not f['muted'])
        total_active += active
        if findings:
            out.append({'device_id': did, 'name': (devices.get(did) or {}).get('name', did),
                        'ts': rec.get('ts'), 'active': active, 'host_muted': hmuted,
                        'findings': findings[:200]})
    out.sort(key=lambda r: r['active'], reverse=True)
    respond(200, {'devices': out, 'total_active': total_active,
                  'enabled': bool(cfg.get('secrets_scan_enabled'))})


def handle_secrets_mute():
    """POST /api/secrets/mute {fingerprint, unmute?} — mute (or unmute) a secret
    finding by fingerprint so it stops alerting / counting. Admin-only; the
    fingerprint is a sha256 prefix, never the secret itself. Audit-logged."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    fp = _sanitize_str(str(body.get('fingerprint', '')), 32).strip()
    if not fp:
        respond(400, {'error': 'fingerprint required'})
    unmute = bool(body.get('unmute'))
    with _LockedUpdate(CONFIG_FILE) as cfg:
        mutes = list(cfg.get('secrets_mutes') or [])
        if unmute:
            mutes = [m for m in mutes if m != fp]
        elif fp not in mutes:
            mutes.append(fp)
        cfg['secrets_mutes'] = mutes[:2000]
    audit_log(actor, 'secret_unmute' if unmute else 'secret_mute', f'fingerprint={fp}')
    respond(200, {'ok': True, 'muted': not unmute})


def handle_secrets_host_mute():
    """POST /api/secrets/host-mute {device_id, unmute?} — v4.1.0 (#55): mute an
    ENTIRE host under "Exposed secrets on disk" so none of its findings alert or
    count toward the total. Complements the per-fingerprint /api/secrets/mute.
    Admin-only; audit-logged. Findings are still stored and shown (flagged
    muted) — this only silences the noise for a host you've accepted."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    did = _sanitize_str(str(body.get('device_id', '')), 64).strip()
    if not did:
        respond(400, {'error': 'device_id required'})
    unmute = bool(body.get('unmute'))
    with _LockedUpdate(CONFIG_FILE) as cfg:
        mutes = list(cfg.get('secrets_host_mutes') or [])
        if unmute:
            mutes = [m for m in mutes if m != did]
        elif did not in mutes:
            mutes.append(did)
        cfg['secrets_host_mutes'] = mutes[:1000]
    # When muting, resolve this host's open secret_exposed alerts so the inbox
    # clears immediately (targeted to this device — the generic resolver can't
    # filter by host).
    if not unmute:
        try:
            with _LockedUpdate(ALERTS_FILE) as store:
                now = int(time.time())
                for a in store.get('alerts', []):
                    if (a.get('event') == 'secret_exposed'
                            and a.get('device_id') == did
                            and not a.get('resolved_at')):
                        a['resolved_at'] = now
                        a['resolved_by'] = 'secrets-host-mute'
        except Exception:
            pass
    audit_log(actor, 'secret_host_unmute' if unmute else 'secret_host_mute',
              f'device_id={did}')
    respond(200, {'ok': True, 'muted': not unmute})


# ─── v3.11.0: scheduled posture digest email ─────────────────────────────────

def _build_posture_digest():
    """Assemble (subject, plaintext body) summarising fleet posture from
    current state. Pure read — safe to call any time."""
    server_name = get_server_name()
    now = int(time.time())
    ttl = get_online_ttl()
    devices = load(DEVICES_FILE) or {}
    monitored = {k: v for k, v in devices.items() if v.get('monitored') is not False}
    offline, pending = [], 0
    reboots = []
    for did, d in monitored.items():
        if now - int(d.get('last_seen', 0) or 0) > ttl:
            offline.append(d.get('name', did))
        si = d.get('sysinfo') or {}
        up = (si.get('packages') or {}).get('upgradable')
        if isinstance(up, int):
            pending += up
        if si.get('reboot_required'):
            reboots.append(d.get('name', did))
    # CVE crit/high
    crit = high = 0
    try:
        cve = load(CVE_FINDINGS_FILE) or {} if backend_exists(CVE_FINDINGS_FILE) else {}
        for _did, rec in cve.items():
            findings = rec.get('findings') if isinstance(rec, dict) else rec
            for f in (findings or []):
                sev = (f.get('severity') or '').lower()
                if sev == 'critical':
                    crit += 1
                elif sev == 'high':
                    high += 1
    except Exception:
        pass
    # software-policy violations
    viol = 0
    try:
        sv = load(SOFTWARE_VIOLATIONS_FILE) or {} if backend_exists(SOFTWARE_VIOLATIONS_FILE) else {}
        viol = sum(len(r.get('violations') or []) for r in sv.values())
    except Exception:
        pass
    # degraded storage
    degraded = []
    try:
        ps = load(POSTURE_STATE_FILE) or {} if backend_exists(POSTURE_STATE_FILE) else {}
        _BAD = ('degraded', 'faulted', 'offline', 'unavail', 'error', 'fail')
        for did, st in ps.items():
            for nm, state in (st.get('pools') or {}).items():
                if any(b in (state or '') for b in _BAD):
                    nm_dev = (devices.get(did) or {}).get('name', did)
                    degraded.append(f'{nm_dev}:{nm}')
    except Exception:
        pass

    lines = [
        f'RemotePower fleet posture — {server_name}',
        time.strftime('%Y-%m-%d %H:%M:%S %Z'),
        '',
        f'Devices monitored : {len(monitored)}',
        f'Offline           : {len(offline)}' + (f'  ({", ".join(offline[:10])})' if offline else ''),
        f'Pending updates   : {pending}',
        f'Reboots required  : {len(reboots)}' + (f'  ({", ".join(reboots[:10])})' if reboots else ''),
        f'CVEs critical/high: {crit} / {high}',
        f'Software-policy violations: {viol}',
        f'Degraded storage  : {len(degraded)}' + (f'  ({", ".join(degraded[:10])})' if degraded else ''),
        '',
        'Open the dashboard for full detail.',
    ]
    subject = (f'[{server_name}] Fleet posture — {len(monitored)} devices, '
               f'{len(offline)} offline, {crit} critical CVEs')
    return subject, '\n'.join(lines)


def _send_posture_digest(cfg, reason='scheduled'):
    """Render and send the digest to the configured recipients. Returns the
    recipient count. Raises smtp_notifier.SmtpError on send failure."""
    recips = ([r for r in re.split(r'[,;\s]+', cfg.get('posture_digest_recipients', '') or '')
               if '@' in r] or _smtp_recipients_list(cfg))
    if not recips:
        raise smtp_notifier.SmtpError('no recipients configured')
    subject, body = _build_posture_digest()
    smtp_notifier.send_email(cfg, recips, subject, body)
    _log_email('posture_digest', recips, 'ok', reason)
    return len(recips)


def _run_posture_digest_if_due():
    """Opportunistic cadence check, mirroring ping_healthchecks_if_due."""
    cfg = _config()
    if not cfg.get('posture_digest_enabled'):
        return
    cadence = cfg.get('posture_digest_cadence', 'weekly')
    interval = 86400 if cadence == 'daily' else 7 * 86400
    now = int(time.time())
    last = int(cfg.get('last_posture_digest', 0) or 0)
    if now - last < interval:
        return
    try:
        n = _send_posture_digest(cfg, reason=cadence)
        with _locked_update(CONFIG_FILE) as c:
            c['last_posture_digest'] = now
        sys.stderr.write(f"[remotepower] posture digest sent to {n} recipient(s)\n")
    except Exception as e:
        sys.stderr.write(f"[remotepower] posture digest failed: {e}\n")


def handle_posture_digest_test():
    """POST /api/posture-digest/test — send the digest now (admin)."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    cfg = load(CONFIG_FILE)
    try:
        n = _send_posture_digest(cfg, reason=f'manual test by {actor}')
        audit_log(actor, 'posture_digest_test', f'sent to {n} recipient(s)')
        respond(200, {'ok': True, 'recipients': n})
    except smtp_notifier.SmtpError as e:
        respond(400, {'error': str(e)})
    except Exception as e:
        respond(500, {'error': f'{type(e).__name__}: {e}'})


def _detect_new_cve_and_fire_webhook(dev_id, devices, previous, current):
    """Fire webhook if new CVEs in the configured severity filter appeared since last scan."""
    if not is_webhook_event_enabled('cve_found'):
        return

    ignore_data = load(CVE_IGNORE_FILE)
    # v3.4.2: `previous` comes off disk (CVE_FINDINGS_FILE) and may be
    # hand-edited / malformed, so a finding missing vuln_id must not 500 the
    # whole /api/cve/scan. Use .get and drop falsy ids.
    prev_ids = {f.get('vuln_id') for f in previous if f.get('vuln_id')}
    severity_filter = set(get_cve_severity_filter())

    new_alerted = []
    for f in current:
        vid = f.get('vuln_id')
        if not vid or vid in prev_ids:
            continue
        if f.get('severity') not in severity_filter:
            continue
        ig = ignore_data.get(vid)
        if ig and (ig.get('scope') == 'global' or ig.get('scope') == dev_id):
            continue
        new_alerted.append(f)

    if not new_alerted:
        return

    dev = devices.get(dev_id, {})
    fire_webhook('cve_found', {
        'device_id':  dev_id,
        'name':       dev.get('name', dev_id),
        'count':      len(new_alerted),
        'critical':   sum(1 for f in new_alerted if f['severity'] == 'critical'),
        'high':       sum(1 for f in new_alerted if f['severity'] == 'high'),
        'sample':     [{'id': f['vuln_id'], 'pkg': f['package'], 'sev': f['severity']}
                       for f in new_alerted[:5]],
    })


def handle_cve_realert():
    """POST /api/cve/realert — re-raise cve_found for the CURRENT backlog.

    The normal cve_found alert is edge-triggered (fires only for findings new
    since the last scan), so once you clear/resolve those alerts the existing
    CVEs won't re-alert. This admin action fires cve_found now for every device
    whose current findings (in the configured severity filter, not ignored)
    are non-empty — useful after clearing the inbox or onboarding alerting on a
    fleet that already had findings."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    if not is_webhook_event_enabled('cve_found'):
        respond(400, {'error': 'cve_found alerting is disabled (Settings → Notifications)'})
    findings_all = load(CVE_FINDINGS_FILE) or {}
    devices = load(DEVICES_FILE) or {}
    ignore_data = load(CVE_IGNORE_FILE) or {}
    sev_filter = set(get_cve_severity_filter())
    fired = 0
    for dev_id, rec in findings_all.items():
        alerted = []
        for f in (rec or {}).get('findings') or []:
            vid = f.get('vuln_id')
            if not vid or f.get('severity') not in sev_filter:
                continue
            ig = ignore_data.get(vid)
            if ig and ig.get('scope') in ('global', dev_id):
                continue
            alerted.append(f)
        if not alerted:
            continue
        dev = devices.get(dev_id, {})
        fire_webhook('cve_found', {
            'device_id': dev_id, 'name': dev.get('name', dev_id),
            'count':     len(alerted),
            'critical':  sum(1 for f in alerted if f['severity'] == 'critical'),
            'high':      sum(1 for f in alerted if f['severity'] == 'high'),
            'sample':    [{'id': f['vuln_id'], 'pkg': f.get('package'), 'sev': f['severity']}
                          for f in alerted[:5]],
        })
        fired += 1
    audit_log(actor, 'cve_realert', f'{fired} device(s) re-alerted')
    respond(200, {'ok': True, 'devices': fired})


CVE_SCAN_STATUS_FILE = DATA_DIR / 'cve_scan_status.json'


def _close_inherited_fds(keep=(0, 1, 2)):
    """Close every inherited file descriptor except `keep` (default: stdio).

    The detached-worker grandchild must NOT hold the parent's open fds — above
    all the live client connection socket. Under the SCGI prefork worker
    (`api_worker.py`) the HTTP response travels over a socket on an fd >= 3
    (`conn.makefile()`), NOT stdout, so redirecting only 0/1/2 leaves the client
    socket open for the entire background job; nginx then keeps the browser
    request hanging until the worker exits (the long-standing "Scan all devices
    hangs the browser" bug — the old dup2-only path was written for plain CGI,
    where the response IS stdout, and silently failed under SCGI). Closing
    fds >= 3 here severs the client socket, the worker's listen socket, and any
    stale DB/file handles deterministically under every server model.

    `keep` must be a low, contiguous-from-0 set (the lone caller uses stdio); the
    /proc path honours it exactly, the closerange fallback closes above max(keep).
    """
    keep = set(keep)
    try:
        names = os.listdir('/proc/self/fd')
    except OSError:
        names = None
    if names is not None:
        # listdir's own dir fd is already closed by the time it returns; a stale
        # entry naming it just yields EBADF on close, which we ignore.
        for name in names:
            try:
                fd = int(name)
            except ValueError:
                continue
            if fd in keep:
                continue
            try:
                os.close(fd)
            except OSError:
                pass
        return
    # No /proc (non-Linux / restricted): bounded closerange fallback.
    try:
        import resource
        soft, _hard = resource.getrlimit(resource.RLIMIT_NOFILE)
        maxfd = soft if 0 < soft < 65536 else 4096
    except Exception:
        maxfd = 4096
    try:
        os.closerange((max(keep) + 1) if keep else 0, maxfd)
    except OSError:
        pass


def _run_detached(fn):
    """Run fn() in a fully-detached background process (double-fork + setsid),
    so a long job (e.g. a fleet-wide CVE scan) doesn't block the CGI worker.
    Falls back to running inline if fork isn't available. The grandchild drops
    EVERY inherited fd (the response/client socket included — see
    _close_inherited_fds) and the inherited per-request load cache + DB
    connection (sharing an inherited SQLite fd across a fork corrupts the DB)."""
    try:
        pid = os.fork()
    except (OSError, AttributeError):
        fn()                      # no fork support → run inline
        return
    if pid > 0:
        try:
            os.waitpid(pid, 0)    # reap the intermediate child (no zombie)
        except OSError:
            pass
        return                    # parent continues and responds
    # intermediate child
    try:
        os.setsid()
        if os.fork() > 0:
            os._exit(0)           # exit so the grandchild reparents to init
    except OSError:
        os._exit(1)
    # grandchild — the detached worker
    try:
        dn = os.open(os.devnull, os.O_RDWR)
        os.dup2(dn, 0); os.dup2(dn, 1); os.dup2(dn, 2)
        if dn > 2:
            os.close(dn)
    except OSError:
        pass
    # Sever EVERY other inherited fd — above all the live client connection
    # socket (SCGI worker) — so the response completes immediately instead of
    # nginx hanging the browser until this background job finishes.
    _close_inherited_fds()
    # Repoint Python's std streams at /dev/null so a stray write in the worker
    # can't reach a now-closed fd or the former client-socket object.
    try:
        sys.stdin = open(os.devnull, 'r')
        sys.stdout = open(os.devnull, 'w')
        sys.stderr = open(os.devnull, 'w')
    except OSError:
        pass
    try:
        _LOAD_CACHE.clear()       # don't trust the parent's per-request cache
        _m = _dbmod()
        if _m is not None and hasattr(_m, '_CONNS'):
            _m._CONNS.clear()     # force a fresh DB connection in this process
    except Exception:
        pass
    try:
        fn()
    except Exception:
        pass
    os._exit(0)


def _spawn_cve_scan(actor, target):
    """Launch the fleet CVE scan as a fully independent OS process.

    Uses subprocess.Popen with start_new_session=True so the scan is detached
    from the web worker's session/process-group and shares none of its fds or DB
    connection — it cannot run inline (the fork-fallback failure mode that froze
    the UI) and cannot keep the client socket open. Falls back to the in-process
    double-fork only if Popen genuinely can't start the child."""
    runner = str(Path(__file__).resolve().parent / 'cve_scan_runner.py')
    try:
        subprocess.Popen(
            [sys.executable, runner, str(actor or 'system'), str(target or '')],
            stdin=subprocess.DEVNULL, stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL, close_fds=True, start_new_session=True,
            env=dict(os.environ),            # carry RP_DATA_DIR + backend config
            cwd=str(Path(__file__).resolve().parent))
    except Exception as e:
        sys.stderr.write(f"[remotepower] cve-scan subprocess spawn failed, "
                         f"falling back to fork: {e}\n")
        _run_detached(lambda: _cve_scan_worker(actor, target))


def _cve_scan_worker(actor, target):
    """The fleet-wide CVE scan body — runs in the detached worker. Writes
    progress to CVE_SCAN_STATUS_FILE and the findings to CVE_FINDINGS_FILE."""
    store = load(PACKAGES_FILE) or {}
    findings_all = load(CVE_FINDINGS_FILE) or {}
    devices = load(DEVICES_FILE) or {}
    targets = [target] if target else list(store.keys())
    scanned = skipped = errors = 0
    total = len(targets)
    # v5.0.0 (#S1): for a FLEET scan (not a single device), prefetch the
    # deduplicated OSV results across every target in one sweep, so the per-device
    # scans below cost zero OSV calls. Single-device scans keep the direct path.
    osv_prefetch = None
    if not target and total > 1:
        try:
            _pf_store = {d: store[d] for d in targets if d in store}
            osv_prefetch = cve_scanner.prefetch_osv(_pf_store, DATA_DIR)
        except Exception as _pf:
            sys.stderr.write(f'[remotepower] OSV prefetch failed, per-device fallback: {_pf}\n')
            osv_prefetch = None
    for i, dev_id in enumerate(targets):
        entry = store.get(dev_id)
        if not entry or not entry.get('ecosystem'):
            skipped += 1
        else:
            result = cve_scanner.scan_device(dev_id, entry.get('packages') or [],
                                             entry['ecosystem'], DATA_DIR,
                                             cache_ttl=get_cve_cache_seconds(),
                                             osv_prefetch=osv_prefetch)
            if result.get('error') and not result.get('findings'):
                errors += 1
            else:
                previous = findings_all.get(dev_id, {}).get('findings') or []
                findings_all[dev_id] = result
                _detect_new_cve_and_fire_webhook(dev_id, devices, previous,
                                                 result.get('findings') or [])
                scanned += 1
        # checkpoint progress every few devices so the UI can show a bar
        if i % 3 == 0 or i == total - 1:
            save(CVE_SCAN_STATUS_FILE, {'running': i < total - 1, 'total': total,
                                            'done': i + 1, 'scanned': scanned,
                                            'skipped': skipped, 'errors': errors,
                                            'updated': int(time.time())}, non_blocking=True)
    save(CVE_FINDINGS_FILE, findings_all)
    save(CVE_SCAN_STATUS_FILE, {'running': False, 'total': total, 'done': total,
                                    'scanned': scanned, 'skipped': skipped,
                                    'errors': errors, 'updated': int(time.time()),
                                    'finished_at': int(time.time())}, non_blocking=True)
    audit_log(actor, 'cve_scan',
              detail=f'scanned={scanned} skipped={skipped} errors={errors} (background)')


def handle_cve_scan():
    """POST /api/cve/scan — queue a background scan for one or all devices.

    The scan runs in a detached process so the UI stays responsive; it returns
    202 immediately. Poll GET /api/cve/scan-status for progress."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj() if _env('CONTENT_LENGTH', '0') != '0' else {}
    target = body.get('device_id')
    if target is not None:
        target = str(target).strip()
        if not _validate_id(target):
            respond(400, {'error': 'Invalid device_id'})
    # Refuse to stack a second concurrent scan (stale >30 min markers ignored).
    st = load(CVE_SCAN_STATUS_FILE) or {}
    if st.get('running') and (int(time.time()) - (st.get('updated') or 0)) < 1800:
        respond(409, {'error': 'A scan is already running', 'status': st})
    total = 1 if target else len(load(PACKAGES_FILE) or {})
    save(CVE_SCAN_STATUS_FILE, {'running': True, 'total': total, 'done': 0,
                                    'scanned': 0, 'skipped': 0, 'errors': 0,
                                    'updated': int(time.time()),
                                    'started_at': int(time.time())}, non_blocking=True)
    _spawn_cve_scan(actor, target)
    respond(202, {'queued': True, 'total': total,
                  'message': 'Scan queued — running in the background.'})


def handle_cve_scan_status():
    """GET /api/cve/scan-status — progress of the background CVE scan."""
    require_auth()
    respond(200, load(CVE_SCAN_STATUS_FILE) or {'running': False})


# ─── v3.14.0: CVE prioritization (CISA KEV + FIRST EPSS) ─────────────────────

def _collect_finding_cve_ids():
    """All CVE ids (+ aliases) present in current findings — used to keep the
    cached EPSS map small (we only store scores for CVEs we actually have)."""
    ids = set()
    for entry in (load(CVE_FINDINGS_FILE) or {}).values():
        if not isinstance(entry, dict):
            continue
        for f in (entry.get('findings') or []):
            if not isinstance(f, dict):
                continue
            vid = f.get('vuln_id')
            if vid:
                ids.add(str(vid).upper())
            for a in (f.get('aliases') or []):
                if isinstance(a, str):
                    ids.add(a.upper())
    return ids


def _fetch_feed_bytes(url, timeout=30, allow_redirect=False):
    """Fetch an external prioritization feed through the SSRF-safe opener
    (peer-IP re-validated at connect; external-only).

    allow_redirect: the EPSS `*-current.csv.gz` URL serves the live scores via a
    same-host relative 302 to the dated file, so that fetch must follow one
    redirect. This stays SSRF-safe because the guard re-validates the peer IP at
    EVERY connect, including the redirected one (enforce_ip=True) — a redirect to
    an internal/rebound host is still blocked. We keep no-redirect for credentialed
    fetches elsewhere; these feeds carry no token to replay."""
    opener = _ssrf_safe_opener(allow_loopback=False, ssl_ctx=_get_ssl_context(),
                               no_redirect=not allow_redirect, enforce_ip=True)
    req = urllib.request.Request(url, headers={'User-Agent': f'RemotePower/{SERVER_VERSION}'})
    with opener.open(req, timeout=timeout) as resp:
        return resp.read()


def refresh_kev_epss_if_due(force=False):
    """Daily refresh of the CISA KEV catalog + FIRST EPSS scores. Cheap-when-
    not-due; degrades gracefully (keeps the last cache, and the CVE views fall
    back to plain CVSS) if a feed is unreachable.

    v4.2.0 sweep (perf): the slot is claimed under lock BEFORE fetching, and
    the multi-MB downloads run in a detached worker. Previously the unlucky
    request (worst case: an agent heartbeat) synchronously downloaded both
    feeds — up to ~60s stall — and every request arriving during that window
    also passed the stale gate, re-downloading in a daily thundering herd."""
    now = int(time.time())
    last = int(_config_ro().get('last_kev_epss_refresh', 0))
    if not force and (now - last) < KEV_EPSS_INTERVAL:
        return
    with _LockedUpdate(CONFIG_FILE) as cfg_w:
        last = int(cfg_w.get('last_kev_epss_refresh', 0))
        if not force and (now - last) < KEV_EPSS_INTERVAL:
            return        # another request claimed it while we waited
        cfg_w['last_kev_epss_refresh'] = now
    if force:
        _refresh_kev_epss_now()   # explicit operator action — synchronous result
    else:
        _run_detached(_refresh_kev_epss_now)


def _refresh_kev_epss_now():
    """The actual feed fetch + cache write (see refresh_kev_epss_if_due)."""
    store = load(KEV_EPSS_FILE) or {}
    # KEV — full catalog (small, ~1–2k CVEs).
    try:
        data = json.loads(_fetch_feed_bytes(KEV_FEED_URL).decode('utf-8'))
        kev = sorted({(v.get('cveID') or '').upper()
                      for v in data.get('vulnerabilities', []) if v.get('cveID')})
        store['kev'] = kev
        store['kev_error'] = ''
    except Exception as e:
        store['kev_error'] = str(e)[:200]
    # EPSS — gzipped CSV; keep only scores for CVEs we actually have findings
    # for. Stream-decompress line by line — materializing the whole feed was
    # ~150 MB of text plus a ~290k-element splitlines list.
    try:
        import io
        want = _collect_finding_cve_ids()
        epss = {}
        with gzip.GzipFile(fileobj=io.BytesIO(_fetch_feed_bytes(EPSS_FEED_URL, allow_redirect=True))) as gz:
            for raw in gz:
                line = raw.decode('utf-8', 'replace').strip()
                if not line or line[0] == '#' or line.startswith('cve,'):
                    continue
                parts = line.split(',')
                if len(parts) < 2:
                    continue
                cid = parts[0].upper()
                if want and cid not in want:
                    continue
                try:
                    epss[cid] = round(float(parts[1]), 4)
                except ValueError:
                    pass
        store['epss'] = epss
        store['epss_error'] = ''
    except Exception as e:
        store['epss_error'] = str(e)[:200]
    store['last_checked'] = int(time.time())
    save(KEV_EPSS_FILE, store)


def _kev_epss():
    """(kev_set, epss_map) from the cache — empty if never fetched."""
    s = load(KEV_EPSS_FILE) or {}
    return set(s.get('kev') or []), (s.get('epss') or {})


def _enrich_cve_findings(findings, kev, epss):
    """Stamp `kev` (bool) and `epss` (0–1 float) onto each finding by matching
    its vuln_id/aliases. Returns (kev_count, epss_max) for aggregation."""
    kev_count = 0
    epss_max = 0.0
    for f in findings:
        if not isinstance(f, dict):
            continue
        ids = [str(f.get('vuln_id') or '').upper()]
        ids += [str(a).upper() for a in (f.get('aliases') or []) if isinstance(a, str)]
        is_kev = any(i in kev for i in ids)
        score = 0.0
        for i in ids:
            if i in epss and epss[i] > score:
                score = epss[i]
        f['kev'] = is_kev
        f['epss'] = score
        if is_kev:
            kev_count += 1
        if score > epss_max:
            epss_max = score
    return kev_count, round(epss_max, 4)


def _campaign_matches_finding(camp, f):
    """W2-35: does a CVE finding fall within a campaign's scope?"""
    cid = str(f.get('cve_id') or f.get('id') or '')
    ids = camp.get('cve_ids') or []
    if ids:
        return cid in ids
    sevs = camp.get('severities') or []
    if sevs and str(f.get('severity', '')).lower() not in sevs:
        return False
    if camp.get('kev_only') and not (f.get('kev') or f.get('known_exploited')):
        return False
    return True


def _campaign_affected(camp, cve_all, cve_ignore, devices):
    """Return (affected_host_ids set, matching_finding_count) for a campaign over
    the current CVE state (ignored findings + stale hosts excluded)."""
    hosts, count = set(), 0
    for did, rec in (cve_all or {}).items():
        if did not in devices:
            continue
        for f in cve_scanner.apply_ignore_list((rec or {}).get('findings') or [],
                                               cve_ignore, did):
            if f.get('ignored'):
                continue
            if _campaign_matches_finding(camp, f):
                count += 1
                hosts.add(did)
    return hosts, count


def _campaign_public(camp, cve_all, cve_ignore, devices):
    hosts, count = _campaign_affected(camp, cve_all, cve_ignore, devices)
    return {
        'id': camp.get('id'), 'name': camp.get('name', ''),
        'owner': camp.get('owner', ''), 'cve_ids': camp.get('cve_ids') or [],
        'severities': camp.get('severities') or [], 'kev_only': bool(camp.get('kev_only')),
        'target_date': camp.get('target_date', ''), 'created_at': camp.get('created_at'),
        'completed_at': camp.get('completed_at'),
        'affected_hosts': len(hosts), 'finding_count': count,
        'samples': [{'ts': s.get('ts'), 'affected': s.get('affected')}
                    for s in (camp.get('samples') or [])][-60:],
    }


def handle_cve_campaigns():
    """GET /api/cve/campaigns — remediation campaigns with live affected counts.
    POST — create one (admin). A campaign scopes a set of CVEs (explicit ids OR a
    severity/KEV filter) with an owner + target date; the server tracks its
    affected-host burn-down."""
    if method() == 'GET':
        require_auth()
        cve_all = load(CVE_FINDINGS_FILE) or {}
        cve_ignore = load(CVE_IGNORE_FILE) or {}
        devices = load(DEVICES_FILE) or {}
        camps = (load(CVE_CAMPAIGNS_FILE) or {}).get('campaigns') or []
        rows = [_campaign_public(c, cve_all, cve_ignore, devices) for c in camps]
        rows.sort(key=lambda r: (r['completed_at'] is not None, -(r.get('created_at') or 0)))
        respond(200, {'ok': True, 'campaigns': rows})
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    actor = require_admin_auth()
    body = get_json_obj()
    name = _sanitize_str(str(body.get('name', '')), 120).strip()
    if not name:
        respond(400, {'error': 'name required'})
    cve_ids = [re.sub(r'[^A-Za-z0-9\-]', '', str(x))[:32]
               for x in (body.get('cve_ids') or [])[:500]]
    cve_ids = [c for c in cve_ids if c]
    sevs = [s for s in (str(x).lower() for x in (body.get('severities') or []))
            if s in ('critical', 'high', 'medium', 'low')]
    now = int(time.time())
    camp = {'id': 'camp_' + secrets.token_hex(5), 'name': name,
            'owner': _sanitize_str(str(body.get('owner') or actor), 64),
            'cve_ids': cve_ids, 'severities': sevs,
            'kev_only': bool(body.get('kev_only')),
            'target_date': re.sub(r'[^0-9\-]', '', str(body.get('target_date', '')))[:10],
            'created_at': now, 'completed_at': None, 'samples': []}
    with _LockedUpdate(CVE_CAMPAIGNS_FILE) as store:
        camps = store.setdefault('campaigns', [])
        if len(camps) >= 200:
            respond(400, {'error': 'campaign limit reached'})
        camps.append(camp)
    audit_log(actor, 'cve_campaign_create', f'id={camp["id"]} {name}')
    respond(200, {'ok': True, 'id': camp['id']})


def handle_cve_campaign(cid):
    """PATCH /api/cve/campaigns/{id} — edit (admin). DELETE — remove (admin)."""
    if method() == 'DELETE':
        actor = require_admin_auth()
        removed = False
        with _LockedUpdate(CVE_CAMPAIGNS_FILE) as store:
            before = store.get('campaigns') or []
            after = [c for c in before if c.get('id') != cid]
            removed = len(after) != len(before)
            store['campaigns'] = after
        if not removed:
            respond(404, {'error': 'campaign not found'})
        audit_log(actor, 'cve_campaign_delete', f'id={cid}')
        respond(200, {'ok': True})
    if method() not in ('PATCH', 'POST'):
        respond(405, {'error': 'Method not allowed'})
    actor = require_admin_auth()
    body = get_json_obj()
    found = False
    with _LockedUpdate(CVE_CAMPAIGNS_FILE) as store:
        camp = next((c for c in (store.get('campaigns') or []) if c.get('id') == cid), None)
        if camp:
            found = True
            if 'name' in body:
                camp['name'] = _sanitize_str(str(body['name']), 120) or camp['name']
            if 'owner' in body:
                camp['owner'] = _sanitize_str(str(body['owner']), 64)
            if 'target_date' in body:
                camp['target_date'] = re.sub(r'[^0-9\-]', '', str(body['target_date']))[:10]
    if not found:
        respond(404, {'error': 'campaign not found'})
    audit_log(actor, 'cve_campaign_update', f'id={cid}')
    respond(200, {'ok': True})


def run_cve_campaign_sample_if_due():
    """W2-35: once a day, append an affected-host sample to each open campaign
    (the burn-down) and fire campaign_completed when one first reaches zero.
    Cheap when there are no campaigns; webhooks fire AFTER the store save."""
    store0 = load(CVE_CAMPAIGNS_FILE) or {}
    camps0 = store0.get('campaigns') or []
    if not camps0:
        return
    now = int(time.time())
    if now - int(store0.get('_last_sample', 0) or 0) < CVE_CAMPAIGN_SAMPLE_INTERVAL:
        return
    cve_all = load(CVE_FINDINGS_FILE) or {}
    cve_ignore = load(CVE_IGNORE_FILE) or {}
    devices = load(DEVICES_FILE) or {}
    pending = []
    with _LockedUpdate(CVE_CAMPAIGNS_FILE) as store:
        store['_last_sample'] = now
        for camp in (store.get('campaigns') or []):
            hosts, _ = _campaign_affected(camp, cve_all, cve_ignore, devices)
            n = len(hosts)
            camp.setdefault('samples', []).append({'ts': now, 'affected': n})
            camp['samples'] = camp['samples'][-120:]
            if n == 0 and not camp.get('completed_at'):
                camp['completed_at'] = now
                pending.append({'campaign': camp.get('name', ''), 'id': camp.get('id')})
            elif n > 0 and camp.get('completed_at'):
                camp['completed_at'] = None   # regressed — reopen
    for p in pending:
        fire_webhook('campaign_completed', p)


def handle_my_notify_prefs():
    """GET/POST /api/my/notify-prefs — the CURRENT user's personal notification
    subscription (any authenticated user). Additive to the global channels; the
    webhook URL is write-only (returned as a boolean). Delivery respects the
    user's RBAC device visibility regardless of the scope filter set here."""
    user = require_auth()
    prefs_all = load(USER_NOTIFY_FILE) or {}
    if method() == 'GET':
        p = prefs_all.get(user) or {}
        respond(200, {'ok': True,
                      'enabled': bool(p.get('enabled')),
                      'webhook_configured': bool((p.get('webhook_url') or '').strip()),
                      'email': p.get('email', ''),
                      'min_priority': int(p.get('min_priority', 0) or 0),
                      'events': p.get('events') or [],
                      'scope_filter': p.get('scope_filter') or {'type': 'all'}})
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    existing = prefs_all.get(user) or {}
    out = {'enabled': bool(body.get('enabled'))}
    # webhook_url: blank keeps the existing one; explicit clear via clear_webhook
    if body.get('clear_webhook'):
        out['webhook_url'] = ''
    else:
        new_url = (body.get('webhook_url') or '').strip()
        if new_url:
            if not (new_url.startswith('http://') or new_url.startswith('https://')):
                respond(400, {'error': 'webhook_url must be http(s)://'})
            out['webhook_url'] = new_url[:512]
        elif existing.get('webhook_url'):
            out['webhook_url'] = existing['webhook_url']
    email = (body.get('email') or '').strip()
    out['email'] = _sanitize_str(email, 200) if '@' in email else ''
    try:
        out['min_priority'] = max(0, min(5, int(body.get('min_priority', 0))))
    except (TypeError, ValueError):
        out['min_priority'] = 0
    evs = body.get('events')
    if isinstance(evs, list):
        out['events'] = [_sanitize_str(str(e), 64) for e in evs[:100] if str(e).strip()]
    sf = body.get('scope_filter')
    if isinstance(sf, dict) and sf.get('type') in ('groups', 'tags', 'sites'):
        out['scope_filter'] = {'type': sf['type'],
                               'values': [_sanitize_str(str(v), 64) for v in (sf.get('values') or [])[:50] if str(v).strip()]}
    else:
        out['scope_filter'] = {'type': 'all'}
    with _LockedUpdate(USER_NOTIFY_FILE) as store:
        store[user] = out
    audit_log(user, 'notify_prefs_save', f'enabled={out["enabled"]}')
    respond(200, {'ok': True})


def handle_import_monitors():
    """POST /api/import/monitors — parse a Nagios / Uptime Kuma / Zabbix export
    into RemotePower monitors (admin). Dry-run by default (returns the proposal);
    with `apply: true`, validates + merges the proposed monitors into
    `config.monitors`, deduped by (type, target) against existing ones."""
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    actor = require_admin_auth()
    body = get_json_obj()
    content = str(body.get('content') or '')
    if not content.strip():
        respond(400, {'error': 'content is required'})
    if len(content) > 5 * 1024 * 1024:
        respond(400, {'error': 'content too large (max 5 MB)'})
    fmt = str(body.get('format') or '').lower() or None
    try:
        result = importers.parse(content, fmt)
    except ValueError as e:
        respond(400, {'error': str(e)})
    # Validate each proposed monitor's target the same way config-save does.
    valid = []
    for m in result['monitors']:
        tgt = _sanitize_monitor_target(m['type'], m['target'])
        if tgt is None:
            result['unmapped'].append({'name': m['label'],
                                       'reason': f'invalid target for {m["type"]}: {m["target"][:60]}'})
            continue
        m = dict(m, target=tgt)
        valid.append(m)
    if not body.get('apply'):
        respond(200, {'ok': True, 'dry_run': True, 'format': result['format'],
                      'monitors': valid, 'unmapped': result['unmapped']})
    # Apply: merge into config.monitors, dedup by (type, target).
    added = 0
    with _LockedUpdate(CONFIG_FILE) as cfg:
        existing = cfg.get('monitors') or []
        have = {(str(e.get('type')), str(e.get('target'))) for e in existing
                if isinstance(e, dict)}
        for m in valid:
            key = (m['type'], m['target'])
            if key in have:
                continue
            have.add(key)
            existing.append(m)
            added += 1
        cfg['monitors'] = existing
    audit_log(actor, 'import_monitors',
              f'format={result["format"]} added={added} unmapped={len(result["unmapped"])}')
    respond(200, {'ok': True, 'applied': True, 'format': result['format'],
                  'added': added, 'unmapped': result['unmapped']})


def handle_cve_findings():
    """GET /api/cve/findings — aggregate CVE report across all devices."""
    require_auth()
    findings_all = load(CVE_FINDINGS_FILE)
    ignore_data  = load(CVE_IGNORE_FILE)
    pkg_store    = load(PACKAGES_FILE)
    devices      = load(DEVICES_FILE)
    devices = _scope_filter_devices(devices)  # v3.5.0 RBAC v2
    now = int(time.time())

    kev, epss = _kev_epss()   # v3.14.0: KEV/EPSS prioritization overlay
    report = {
        'generated_at': now,
        'devices':      [],
        'summary':      {'critical': 0, 'high': 0, 'medium': 0, 'low': 0,
                         'unknown':  0, 'ignored':  0, 'kev': 0,
                         'devices_scanned': 0,
                         'devices_with_findings': 0,
                         'devices_unsupported': 0},
    }

    for dev_id, dev in devices.items():
        pkg_entry = pkg_store.get(dev_id) or {}
        ecosystem = pkg_entry.get('ecosystem', '')
        f_entry = findings_all.get(dev_id) or {}
        findings = f_entry.get('findings') or []
        kev_count, epss_max = _enrich_cve_findings(findings, kev, epss)
        summary = cve_scanner.summarize_findings(
            findings,
            {k for k, v in ignore_data.items()
             if v.get('scope') == 'global' or v.get('scope') == dev_id}
        )
        status = 'scanned'
        if not pkg_entry:
            status = 'no_packages'
        elif not ecosystem:
            status = 'unsupported'
            report['summary']['devices_unsupported'] += 1
        elif not f_entry:
            status = 'not_scanned'

        if f_entry:
            report['summary']['devices_scanned'] += 1
            if sum(summary[k] for k in ('critical', 'high', 'medium', 'low')) > 0:
                report['summary']['devices_with_findings'] += 1
            for k in ('critical', 'high', 'medium', 'low', 'unknown', 'ignored'):
                report['summary'][k] += summary[k]
            report['summary']['kev'] += kev_count

        report['devices'].append({
            'device_id':   dev_id,
            'name':        dev.get('name', dev_id),
            'group':       dev.get('group', ''),
            'os':          dev.get('os', ''),
            'ecosystem':   ecosystem or 'unsupported',
            'status':      status,
            'scanned_at':  f_entry.get('scanned_at', 0),
            'package_count': pkg_entry.get('count', 0),
            'counts':      summary,
            'kev':         kev_count,    # v3.14.0
            'epss_max':    epss_max,     # v3.14.0 (0–1)
        })

    # v3.14.0: prioritize by exploited-in-wild (KEV) → criticals → highs → EPSS.
    report['devices'].sort(
        key=lambda d: (-d.get('kev', 0), -d['counts']['critical'],
                       -d['counts']['high'], -d.get('epss_max', 0), d['name'].lower())
    )
    # v3.14.0 fix: surface the KEV/EPSS feed state so "why is there no KEV?" is
    # answerable — distinguishes "feed not loaded / errored" from "genuinely no
    # known-exploited CVEs on these hosts".
    _ke = load(KEV_EPSS_FILE) or {}
    report['kev_feed'] = {
        'kev_count':    len(kev),
        'epss_count':   len(epss),
        'last_checked': _ke.get('last_checked', 0),
        'kev_error':    _ke.get('kev_error', ''),
        'epss_error':   _ke.get('epss_error', ''),
    }
    respond(200, report)


def handle_cve_refresh_feeds():
    """POST /api/cve/refresh-feeds — force a KEV/EPSS refresh now (admin). Lets
    an operator populate the feeds immediately instead of waiting for the daily
    sweep, and see any feed error."""
    require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    try:
        refresh_kev_epss_if_due(force=True)
    except Exception as e:
        respond(502, {'error': f'Feed refresh failed: {str(e)[:200]}'})
    s = load(KEV_EPSS_FILE) or {}
    respond(200, {'ok': True, 'kev_count': len(s.get('kev') or []),
                  'epss_count': len(s.get('epss') or {}),
                  'kev_error': s.get('kev_error', ''),
                  'epss_error': s.get('epss_error', '')})


def handle_cve_device(dev_id):
    """GET /api/devices/{id}/cve — detailed findings for one device."""
    require_auth()
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})

    dev = device_get(dev_id)   # v4.3.0: single-row read
    if dev is None:
        respond(404, {'error': 'Device not found'})

    findings_all = load(CVE_FINDINGS_FILE)
    ignore_data  = load(CVE_IGNORE_FILE)
    pkg_store    = load(PACKAGES_FILE)

    f_entry   = findings_all.get(dev_id) or {}
    pkg_entry = pkg_store.get(dev_id) or {}
    findings  = f_entry.get('findings') or []
    findings  = cve_scanner.apply_ignore_list(findings, ignore_data, dev_id)
    _kev, _epss = _kev_epss()                       # v3.14.0
    _enrich_cve_findings(findings, _kev, _epss)     # stamp kev/epss per finding

    respond(200, {
        'device_id':      dev_id,
        'name':           dev.get('name', dev_id),
        'group':          dev.get('group', ''),
        'os':             dev.get('os', ''),
        'ecosystem':      pkg_entry.get('ecosystem', '') or 'unsupported',
        'scanned_at':     f_entry.get('scanned_at', 0),
        'packages_count': pkg_entry.get('count', 0),
        'collected_at':   pkg_entry.get('collected_at', 0),
        'findings':       findings,
        'error':          f_entry.get('error', ''),
    })


# ── v3.5.0: SBOM export (CycloneDX / SPDX, CVE-enriched) ─────────────────────
# Turns the package inventory we already collect into a portable SBOM document.
# CycloneDX carries the CVE findings natively (VEX-style vulnerabilities[]);
# SPDX attaches them as SECURITY ExternalRefs. Per-host download + a fleet ZIP.

def _sbom_format_from_query():
    """Resolve ?format=cyclonedx|spdx (default cyclonedx)."""
    from urllib.parse import parse_qs
    qs = parse_qs(_env('QUERY_STRING', ''))
    fmt = (qs.get('format', ['cyclonedx'])[0] or 'cyclonedx').strip().lower()
    if fmt in ('spdx', 'spdx-2.3', 'spdx23'):
        return 'spdx'
    return 'cyclonedx'


def _build_sbom_doc(dev_id, dev, fmt):
    """Assemble one device's SBOM dict. Shared by the per-host download and the
    fleet ZIP so the two never drift."""
    pkg_store = load(PACKAGES_FILE)
    findings_all = load(CVE_FINDINGS_FILE)
    ignore_data = load(CVE_IGNORE_FILE)
    pkg_entry = pkg_store.get(dev_id) or {}
    findings = (findings_all.get(dev_id) or {}).get('findings') or []
    findings = cve_scanner.apply_ignore_list(findings, ignore_data, dev_id)
    # v3.14.0: include running container images as SBOM components.
    containers = ((load(CONTAINERS_FILE) or {}).get(dev_id) or {}).get('items') or []
    dev = dict(dev); dev['id'] = dev_id
    if fmt == 'spdx':
        return sbom_mod.build_spdx(dev, pkg_entry, findings,
                                   server_version=SERVER_VERSION, containers=containers)
    return sbom_mod.build_cyclonedx(dev, pkg_entry, findings,
                                    server_version=SERVER_VERSION, containers=containers)


def _stream_json_download(obj, filename):
    """Serialise ``obj`` and emit it as a JSON file download. Terminates the
    request (mirrors the patch-report CSV/XML handlers)."""
    data = json.dumps(obj, indent=2, sort_keys=False).encode('utf-8')
    print("Status: 200 OK")
    print("Content-Type: application/json")
    print(f"Content-Disposition: attachment; filename={filename}")
    print(f"Content-Length: {len(data)}")
    print("Cache-Control: no-store")
    print("X-Content-Type-Options: nosniff")
    print()
    sys.stdout.flush()
    sys.stdout.buffer.write(data)
    sys.stdout.buffer.flush()
    sys.exit(0)


def _sbom_pkg_index(dev_id):
    """name -> version map of a device's installed packages (for SBOM diffs)."""
    entry = (load(PACKAGES_FILE).get(dev_id) or {})
    idx = {}
    for pk in (entry.get('packages') or []):
        n = pk.get('name'); v = pk.get('version')
        if n and v:
            idx[str(n)] = str(v)
    return idx, int(entry.get('collected_at', 0) or 0)


def handle_sbom_baseline(dev_id):
    """POST /api/devices/{id}/sbom/baseline — snapshot the current package set as
    the comparison baseline for future SBOM diffs. Admin-only, audited."""
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    actor = require_admin_auth()
    idx, collected = _sbom_pkg_index(dev_id)
    if not idx:
        respond(400, {'error': 'no package inventory yet — send the package list first'})
    now = int(time.time())
    with _LockedUpdate(SBOM_BASELINE_FILE) as store:
        store[dev_id] = {'captured_at': now, 'collected_at': collected, 'packages': idx}
    audit_log(actor, 'sbom_baseline', f'device={dev_id} packages={len(idx)}')
    respond(200, {'ok': True, 'captured_at': now, 'count': len(idx)})


def handle_sbom_diff(dev_id):
    """GET /api/devices/{id}/sbom/diff — diff the current package set against the
    stored baseline: added / removed / version-changed components."""
    if method() != 'GET':
        respond(405, {'error': 'Method not allowed'})
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    require_auth()
    base = (load(SBOM_BASELINE_FILE).get(dev_id) or {})
    if not base.get('packages'):
        respond(404, {'error': 'no baseline captured for this host — capture one first'})
    old = base['packages']
    new, _collected = _sbom_pkg_index(dev_id)
    added = sorted(({'name': n, 'version': new[n]} for n in new if n not in old),
                   key=lambda x: x['name'])
    removed = sorted(({'name': n, 'version': old[n]} for n in old if n not in new),
                     key=lambda x: x['name'])
    changed = sorted(({'name': n, 'from': old[n], 'to': new[n]} for n in new
                      if n in old and old[n] != new[n]), key=lambda x: x['name'])
    respond(200, {'baseline_at': base.get('captured_at', 0),
                  'added': added[:1000], 'removed': removed[:1000], 'changed': changed[:1000],
                  'counts': {'added': len(added), 'removed': len(removed), 'changed': len(changed)}})


def handle_sbom_device(dev_id):
    """GET /api/devices/{id}/sbom?format=cyclonedx|spdx — SBOM for one host."""
    require_auth()
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    devices = load(DEVICES_FILE)
    dev = devices.get(dev_id)
    if not dev:
        respond(404, {'error': 'Device not found'})
    fmt = _sbom_format_from_query()
    doc = _build_sbom_doc(dev_id, dev, fmt)
    _stream_json_download(doc, sbom_mod.filename_for(dev, fmt))


def handle_sbom_fleet():
    """GET /api/sbom?format=cyclonedx|spdx[&group=&device_id=] — a ZIP of
    per-host SBOMs across the (filtered) fleet."""
    require_auth()
    fmt = _sbom_format_from_query()
    devices = _filter_devices_for_export()
    import io, zipfile
    buf = io.BytesIO()
    used = set()
    with zipfile.ZipFile(buf, 'w', zipfile.ZIP_DEFLATED) as zf:
        for dev_id, dev in sorted(devices.items(), key=lambda x: (x[1].get('name', '') or '').lower()):
            doc = _build_sbom_doc(dev_id, dev, fmt)
            fn = sbom_mod.filename_for(dict(dev, id=dev_id), fmt)
            # de-dup filenames (two hosts named the same) by suffixing the id
            if fn in used:
                fn = fn.replace('.json', f'-{dev_id[:8]}.json')
            used.add(fn)
            zf.writestr(fn, json.dumps(doc, indent=2).encode('utf-8'))
    data = buf.getvalue()
    ts = time.strftime('%Y%m%d-%H%M%S')
    print("Status: 200 OK")
    print("Content-Type: application/zip")
    print(f"Content-Disposition: attachment; filename=fleet-sbom-{fmt}-{ts}.zip")
    print(f"Content-Length: {len(data)}")
    print("Cache-Control: no-store")
    print("X-Content-Type-Options: nosniff")
    print()
    sys.stdout.flush()
    sys.stdout.buffer.write(data)
    sys.stdout.buffer.flush()
    sys.exit(0)


def handle_cve_ignore_add():
    """POST /api/cve/ignore — mark a vuln as accepted risk."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})

    body     = get_json_obj()
    vuln_id  = _sanitize_str(body.get('vuln_id', ''), 64, allow_empty=False)
    reason   = _sanitize_str(body.get('reason', ''), 256)
    scope    = _sanitize_str(body.get('scope', 'global'), 64)
    if not vuln_id:
        respond(400, {'error': 'vuln_id required'})
    if scope != 'global' and not _validate_id(scope):
        respond(400, {'error': 'scope must be "global" or a valid device_id'})

    ignore_data = load(CVE_IGNORE_FILE)
    ignore_data[vuln_id] = {
        'scope':  scope,
        'reason': reason,
        'actor':  actor,
        'ts':     int(time.time()),
    }
    save(CVE_IGNORE_FILE, ignore_data)
    audit_log(actor, 'cve_ignore_add',
              detail=f'{vuln_id} scope={scope} reason={reason[:80]}')
    respond(200, {'ok': True, 'ignored': vuln_id})


def handle_cve_ignore_delete(vuln_id):
    """DELETE /api/cve/ignore/{vuln_id}"""
    actor = require_admin_auth()
    vuln_id = _sanitize_str(vuln_id, 64, allow_empty=False)
    if not vuln_id:
        respond(400, {'error': 'Invalid vuln_id'})
    ignore_data = load(CVE_IGNORE_FILE)
    if vuln_id in ignore_data:
        del ignore_data[vuln_id]
        save(CVE_IGNORE_FILE, ignore_data)
        audit_log(actor, 'cve_ignore_remove', detail=vuln_id)
    respond(200, {'ok': True})


def handle_cve_ignore_list():
    """GET /api/cve/ignore — list all active ignores."""
    require_auth()
    ignore_data = load(CVE_IGNORE_FILE)
    items = [{'vuln_id': k, **v} for k, v in ignore_data.items()]
    items.sort(key=lambda x: -x.get('ts', 0))
    respond(200, {'ignores': items})


# ─── v1.7.0: Prometheus metrics exporter ──────────────────────────────────────

def _ics_escape(s):
    return str(s or '').replace('\\', '\\\\').replace(';', '\\;') \
        .replace(',', '\\,').replace('\n', '\\n')


def _ics_dt(ts):
    import datetime as _dt
    return _dt.datetime.fromtimestamp(int(ts), _dt.timezone.utc).strftime('%Y%m%dT%H%M%SZ')


def _cron_to_ics(cron, now):
    """Best-effort (dtstart_ts, RRULE) for simple 5-field crons with a concrete
    minute and hour (daily / weekly / monthly). Returns None for patterns we
    can't cleanly map to an RRULE — those jobs are simply omitted from the feed
    (they still appear on the in-app Schedule page)."""
    parts = (cron or '').split()
    if len(parts) != 5:
        return None
    mn, hr, dom, mon, dow = parts
    if not (mn.isdigit() and hr.isdigit()):
        return None
    minute, hour = int(mn), int(hr)
    if not (0 <= minute < 60 and 0 <= hour < 24):
        return None
    import datetime as _dt
    base = _dt.datetime.fromtimestamp(now)
    cand = base.replace(hour=hour, minute=minute, second=0, microsecond=0)
    if dom == '*' and mon == '*' and dow == '*':
        if cand <= base:
            cand += _dt.timedelta(days=1)
        return int(cand.timestamp()), 'FREQ=DAILY'
    if dom == '*' and mon == '*' and dow.isdigit():
        days = ['SU', 'MO', 'TU', 'WE', 'TH', 'FR', 'SA']
        cron_dow = int(dow) % 7                 # cron: 0=Sun..6=Sat
        py_target = (cron_dow - 1) % 7          # python weekday: Mon=0..Sun=6
        ahead = (py_target - base.weekday()) % 7
        cand = (base + _dt.timedelta(days=ahead)).replace(
            hour=hour, minute=minute, second=0, microsecond=0)
        if cand <= base:
            cand += _dt.timedelta(days=7)
        return int(cand.timestamp()), f'FREQ=WEEKLY;BYDAY={days[cron_dow]}'
    if mon == '*' and dow == '*' and dom.isdigit():
        d = int(dom)
        try:
            cand = base.replace(day=d, hour=hour, minute=minute, second=0, microsecond=0)
        except ValueError:
            return None
        if cand <= base:
            mm = base.month % 12 + 1
            yy = base.year + (1 if base.month == 12 else 0)
            try:
                cand = base.replace(year=yy, month=mm, day=d, hour=hour,
                                    minute=minute, second=0, microsecond=0)
            except ValueError:
                return None
        return int(cand.timestamp()), f'FREQ=MONTHLY;BYMONTHDAY={d}'
    return None


def handle_schedule_ics(device_id=None):
    """GET /api/schedule.ics?token=<status_token> — calendar feed of scheduled
    jobs + maintenance windows as VEVENTs. Auth via the status token (so a
    calendar app that can't send headers can subscribe) or a normal session.

    One-shot jobs and maintenance windows render exactly; recurring jobs render
    with an RRULE for the common daily/weekly/monthly patterns."""
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    qs_token = (qs.get('token') or [''])[0]
    authed = False
    if qs_token:
        cfg_token = (load(CONFIG_FILE) or {}).get('status_token') or ''
        authed = _ct_token_eq(qs_token, cfg_token)
    else:
        token = get_token_from_request()
        if not token:
            auth = _env('HTTP_AUTHORIZATION', '')
            if auth.lower().startswith('bearer '):
                token = auth[7:].strip()
        username, _role = verify_token(token)
        authed = bool(username)
    if not authed:
        print('Status: 401 Unauthorized')
        print('Content-Type: text/plain; charset=utf-8')
        print('Cache-Control: no-store')
        print()
        print('Unauthorized')
        sys.exit(0)

    now = int(time.time())
    lines = ['BEGIN:VCALENDAR', 'VERSION:2.0',
             'PRODID:-//RemotePower//Schedule//EN', 'CALSCALE:GREGORIAN',
             f'X-WR-CALNAME:{_ics_escape(get_server_name())} schedule']

    def _vevent(uid, dtstart, summary, desc='', dtend=None, rrule=None):
        ev = ['BEGIN:VEVENT', f'UID:{_ics_escape(uid)}@remotepower',
              f'DTSTAMP:{_ics_dt(now)}', f'DTSTART:{dtstart}']
        if dtend:
            ev.append(f'DTEND:{dtend}')
        if rrule:
            ev.append(f'RRULE:{rrule}')
        ev.append(f'SUMMARY:{_ics_escape(summary)}')
        if desc:
            ev.append(f'DESCRIPTION:{_ics_escape(desc)}')
        ev.append('END:VEVENT')
        return ev

    for job in (load(SCHEDULE_FILE) or {}).get('jobs') or []:
        if device_id and job.get('device_id') != device_id:
            continue
        dn = job.get('device_name') or job.get('device_id', '')
        summ = f"{job.get('command', '')} — {dn}"
        if job.get('recurring') and job.get('cron'):
            mapped = _cron_to_ics(job['cron'], now)
            if mapped:
                ts0, rrule = mapped
                lines += _vevent(f"job-{job.get('id', '')}", _ics_dt(ts0), summ,
                                 f"Recurring: {job['cron']}", rrule=rrule)
        elif job.get('run_at'):
            lines += _vevent(f"job-{job.get('id', '')}", _ics_dt(job['run_at']),
                             summ, 'One-shot scheduled command',
                             dtend=_ics_dt(int(job['run_at']) + 900))

    for w in (load(MAINT_FILE) or {}).get('windows') or []:
        if device_id and not (w.get('scope') == 'device' and str(w.get('target')) == str(device_id)):
            continue
        if w.get('start') and w.get('end'):
            try:
                s = int(_parse_iso(w['start'])); e = int(_parse_iso(w['end']))
            except Exception:
                continue
            lines += _vevent(f"maint-{w.get('id', '')}", _ics_dt(s),
                             f"Maintenance: {w.get('reason', 'window')}",
                             f"Scope {w.get('scope', '')} {w.get('target', '')}".strip(),
                             dtend=_ics_dt(e))

    lines.append('END:VCALENDAR')
    body = ('\r\n'.join(lines) + '\r\n').encode('utf-8')
    print('Status: 200 OK')
    print('Content-Type: text/calendar; charset=utf-8')
    print('Content-Disposition: attachment; filename=remotepower-schedule.ics')
    print('Cache-Control: no-store')
    print(f'Content-Length: {len(body)}')
    print()
    sys.stdout.flush()
    sys.stdout.buffer.write(body)
    sys.stdout.buffer.flush()
    sys.exit(0)


def _build_metrics_ctx():
    """Assemble the context generate_metrics() needs. Shared by the /api/metrics
    scrape endpoint and the v3.14.0 metrics-push so the two never diverge."""
    now = int(time.time())
    cfg = load(CONFIG_FILE)
    mon_hist = load(MON_HIST_FILE)
    monitor_state = {}
    for label, entries in mon_hist.items():
        if entries:
            last = entries[-1]
            monitor_state[label] = {'up': bool(last.get('up', True)), 'last': last.get('ts', 0)}
    maint_active = 0
    for w in ((load(MAINT_FILE) or {}).get('windows') or []):
        try:
            if _window_active(w, now):
                maint_active += 1
        except Exception:
            pass
    return {
        'server_version':  SERVER_VERSION,
        'slo':             _compute_slo(),   # v5.4.1 (F3): SLO/error-budget gauges
        'control_uptime':  _control_uptime(),  # v5.4.1 (G3): observed self-availability
        'now':             now,
        'online_ttl':      get_online_ttl(),
        'devices':         load(DEVICES_FILE),
        'monitors':        cfg.get('monitors') or [],
        'monitor_state':   monitor_state,
        'schedule':        load(SCHEDULE_FILE),
        'pending_cmds':    load(CMDS_FILE),
        'webhook_log':     load(WEBHOOK_LOG_FILE),
        'webhook_log_cap': MAX_WEBHOOK_LOG,
        'cve_findings':    load(CVE_FINDINGS_FILE),
        'cve_ignore':      load(CVE_IGNORE_FILE),
        'services':        load(SERVICES_FILE),
        'maintenance_active_count': maint_active,
        'health':            _fleet_health(),
        'fleet_events':      load(FLEET_EVENTS_FILE),
        'cve_fixable_total': sum(_cve_fixable_by_device().values()),
    }


def handle_prometheus_metrics():
    """
    GET /api/metrics — Prometheus text exposition.

    Auth (any one of these works):
      • X-Token header — a logged-in operator scraping from their browser.
      • Authorization: Bearer <session-key> — same as X-Token.
      • ?token=<status_token> — the dedicated long-lived token shared
        with /api/status. Generated in Settings. The standard pattern
        for a Prometheus scrape config:

          scrape_configs:
            - job_name: 'remotepower'
              metrics_path: /api/metrics
              params:
                token: ['<status token>']
              static_configs:
                - targets: ['remote.example.com']
              scheme: https
    """
    # v3.3.0: accept the status_token via query string for Prometheus
    # scrape configs. Falls through to session-token auth otherwise.
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    qs_token = (qs.get('token') or [''])[0]
    if qs_token:
        cfg_token = (load(CONFIG_FILE) or {}).get('status_token') or ''
        if _ct_token_eq(qs_token, cfg_token):
            pass  # authenticated via status token, fall through to body
        else:
            print('Status: 401 Unauthorized')
            print('Content-Type: text/plain; charset=utf-8')
            print('Cache-Control: no-store')
            print()
            print('invalid status token')
            sys.exit(0)
    else:
        token = get_token_from_request()
        if not token:
            auth = _env('HTTP_AUTHORIZATION', '')
            if auth.lower().startswith('bearer '):
                token = auth[7:].strip()
        username, _role = verify_token(token)
        if not username:
            print('Status: 401 Unauthorized')
            print('Content-Type: text/plain; charset=utf-8')
            print('WWW-Authenticate: Bearer realm="remotepower"')
            print('Cache-Control: no-store')
            print()
            print('Unauthorized')
            sys.exit(0)

    # v4.4.0 (RELIABILITY): never let a single malformed store record 500 the
    # whole scrape — that breaks Prometheus monitoring fleet-wide. Degrade to a
    # minimal valid exposition plus a `remotepower_scrape_error` gauge the
    # operator can alert on. (generate_metrics also skips non-dict records
    # internally, so this is the belt to that suspenders.)
    try:
        body = prometheus_export.generate_metrics(_build_metrics_ctx())
        scrape_error = 0
    except Exception as e:
        sys.stderr.write(f'[remotepower] metrics scrape failed: {e}\n')
        body = f'remotepower_info{{version="{SERVER_VERSION}"}} 1\n'
        scrape_error = 1
    body += f'# HELP remotepower_scrape_error Whether the last scrape hit an internal error (1/0).\n'
    body += f'# TYPE remotepower_scrape_error gauge\n'
    body += f'remotepower_scrape_error {scrape_error}\n'

    print('Status: 200 OK')
    print('Content-Type: text/plain; version=0.0.4; charset=utf-8')
    print('Cache-Control: no-store')
    print()
    print(body)
    sys.exit(0)


# ─── v3.14.0: metrics push (Prometheus Pushgateway / remote target) ──────────
METRICS_PUSH_STATE_FILE = DATA_DIR / 'metrics_push_state.json'


def _maybe_push_metrics():
    """Periodically POST the Prometheus exposition to a configured Pushgateway
    (config `metrics_push` {enabled,url,interval,job}). Interval-gated and
    SSRF-safe; the slot is claimed atomically so concurrent heartbeats don't
    double-push. Errors are recorded, never raised onto the request path."""
    cfg = load(CONFIG_FILE) or {}
    mp = cfg.get('metrics_push') or {}
    if not mp.get('enabled') or not (mp.get('url') or '').strip():
        return
    interval = max(15, int(mp.get('interval') or 60))
    now = int(time.time())
    due = False
    with _LockedUpdate(METRICS_PUSH_STATE_FILE) as st:
        if now - int(st.get('last_push', 0)) >= interval:
            st['last_push'] = now
            due = True
    if not due:
        return
    err, status = '', 0
    try:
        body = prometheus_export.generate_metrics(_build_metrics_ctx()).encode('utf-8')
        job = re.sub(r'[^A-Za-z0-9_-]', '', str(mp.get('job') or 'remotepower'))[:64] or 'remotepower'
        push_url = f"{mp['url'].strip().rstrip('/')}/metrics/job/{job}"
        parsed = urllib.parse.urlparse(push_url)
        opener = _ssrf_safe_opener(allow_loopback=True,
                                   ssl_ctx=_get_ssl_context() if parsed.scheme == 'https' else None,
                                   no_redirect=True)
        req = urllib.request.Request(push_url, data=body, method='POST', headers={
            'Content-Type': 'text/plain; version=0.0.4; charset=utf-8',
            'User-Agent': f'RemotePower/{SERVER_VERSION}'})
        resp = opener.open(req, timeout=10)
        status = getattr(resp, 'status', 0) or 0
    except Exception as e:
        err = str(e)[:200]
    try:
        with _LockedUpdate(METRICS_PUSH_STATE_FILE) as st:
            st['last_status'] = status
            st['last_error'] = err
    except Exception:
        pass


def handle_metrics_push_get():
    """GET /api/metrics/push/config — current metrics-push config + last result."""
    require_auth()
    mp = dict((load(CONFIG_FILE) or {}).get('metrics_push') or {})
    st = load(METRICS_PUSH_STATE_FILE) if backend_exists(METRICS_PUSH_STATE_FILE) else {}
    respond(200, {'enabled': bool(mp.get('enabled')), 'url': mp.get('url', ''),
                  'interval': int(mp.get('interval') or 60),
                  'job': mp.get('job') or 'remotepower',
                  'last_push': st.get('last_push', 0),
                  'last_status': st.get('last_status', 0),
                  'last_error': st.get('last_error', '')})


def handle_metrics_push_set():
    """PUT /api/metrics/push/config — configure the metrics push. Admin-only."""
    actor = require_admin_auth()
    if method() != 'PUT':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    enabled = bool(body.get('enabled'))
    url = _sanitize_str(str(body.get('url', '')).strip(), 512)
    if enabled and not url:
        respond(400, {'error': 'A Pushgateway URL is required when enabled.'})
    if url and not re.match(r'^https?://', url):
        respond(400, {'error': 'url must be http(s)://'})
    interval = max(15, min(3600, int(body.get('interval') or 60)))
    job = re.sub(r'[^A-Za-z0-9_-]', '', str(body.get('job') or 'remotepower'))[:64] or 'remotepower'
    with _LockedUpdate(CONFIG_FILE) as cfg:
        cfg['metrics_push'] = {'enabled': enabled, 'url': url, 'interval': interval, 'job': job}
    audit_log(actor, 'metrics_push_set', f'enabled={enabled} url={url} interval={interval}')
    respond(200, {'ok': True, 'enabled': enabled, 'url': url, 'interval': interval, 'job': job})


# ─── v3.14.0 (#27): GitOps — desired-state config from a Git repo ───────────────
# RemotePower already has the *reconciliation* half of GitOps: drift profiles
# (named watched-file sets), tag/group assignments, and the drift engine that
# flags (and, where enabled, enforces) changes. What was missing is "Git as the
# source of truth". This layer periodically fetches a JSON manifest from a raw
# Git URL (SSRF-safe) and reconciles the drift profiles + assignments it owns to
# match it — so your watched-config policy lives in version control.
#
# Safety: this only manages WATCHED-FILE LISTS and their host assignments — never
# command execution or file *content* pushes. Actual host enforcement still goes
# through the existing per-device apply_enabled / enforce opt-in. It's admin-only,
# off by default, fetched through the anti-rebinding opener with a size cap, and
# only touches profiles/assignments it created (source == 'gitops') so it never
# clobbers ones an operator made by hand.
GITOPS_STATE_FILE = DATA_DIR / 'gitops_state.json'
GITOPS_MAX_MANIFEST_BYTES = 256 * 1024


def _gitops_reconcile(manifest, dry=False):
    """Reconcile gitops-owned drift profiles + assignments to `manifest`.
    Returns a summary dict. Pure-ish: only writes CONFIG_FILE when dry is False."""
    raw_profiles = manifest.get('profiles') if isinstance(manifest, dict) else None
    raw_assigns = manifest.get('assignments') if isinstance(manifest, dict) else None
    if not isinstance(raw_profiles, list):
        raise ValueError("manifest must be an object with a 'profiles' list")

    # Desired gitops profiles, keyed by name (the stable identity in Git).
    desired = {}
    skipped = []
    for p in raw_profiles[:100]:
        if not isinstance(p, dict):
            continue
        name = _sanitize_str(str(p.get('name', '')), 80).strip()
        if not name:
            continue
        desired[name] = _validate_drift_files(p.get('files'))
    # Desired assignments: {(scope_type, scope_value): profile_name}
    desired_assigns = []
    for a in (raw_assigns or [])[:500]:
        if not isinstance(a, dict):
            continue
        st = _sanitize_str(str(a.get('scope_type', '')), 16)
        sv = _sanitize_str(str(a.get('scope_value', '')), 128).strip()
        pn = _sanitize_str(str(a.get('profile', '')), 80).strip()
        if st in ('device', 'tag', 'group') and sv and pn in desired:
            desired_assigns.append((st, sv, pn))

    summary = {'added': 0, 'updated': 0, 'removed': 0,
               'assignments': len(desired_assigns), 'skipped': skipped, 'dry': dry}
    now = int(time.time())

    def _apply(cfg):
        dr = cfg.setdefault('drift', {})
        profs = dr.setdefault('profiles', [])
        # Index existing profiles by name; remember which are gitops-owned.
        by_name = {}
        for p in profs:
            if isinstance(p, dict) and p.get('name'):
                by_name[p['name']] = p
        # Upsert desired profiles.
        name_to_id = {}
        for name, files in desired.items():
            ex = by_name.get(name)
            if ex and ex.get('source') != 'gitops':
                # A hand-made profile owns this name — don't hijack it.
                skipped.append(name)
                if ex.get('id'):
                    name_to_id[name] = ex['id']
                continue
            if ex:
                if ex.get('files') != files:
                    ex['files'] = files
                    ex['updated'] = now
                    summary['updated'] += 1
                ex['source'] = 'gitops'
                name_to_id[name] = ex['id']
            else:
                pid = 'dp_' + secrets.token_urlsafe(8)
                profs.append({'id': pid, 'name': name, 'files': files,
                              'source': 'gitops', 'created': now, 'updated': now})
                name_to_id[name] = pid
                summary['added'] += 1
        # Remove gitops-owned profiles no longer in the manifest.
        keep = []
        removed_ids = set()
        for p in profs:
            if (isinstance(p, dict) and p.get('source') == 'gitops'
                    and p.get('name') not in desired):
                removed_ids.add(p.get('id'))
                summary['removed'] += 1
            else:
                keep.append(p)
        dr['profiles'] = keep
        # Reconcile gitops-owned assignments (leave manual ones untouched).
        assigns = [a for a in (dr.get('assignments') or [])
                   if not (isinstance(a, dict) and a.get('source') == 'gitops')]
        for st, sv, pn in desired_assigns:
            pid = name_to_id.get(pn)
            if not pid:
                continue
            # A manual assignment for this scope wins — don't double-assign.
            if any(isinstance(a, dict) and a.get('scope_type') == st
                   and a.get('scope_value') == sv for a in assigns):
                continue
            assigns.append({'scope_type': st, 'scope_value': sv,
                            'profile_id': pid, 'source': 'gitops'})
        dr['assignments'] = assigns

    if dry:
        # Reconcile against a deep copy so we report the diff without persisting.
        cfg_copy = json.loads(json.dumps(load(CONFIG_FILE) or {}))
        _apply(cfg_copy)
    else:
        with _LockedUpdate(CONFIG_FILE) as cfg:
            _apply(cfg)
    return summary


def _gitops_fetch_manifest(gc):
    """Fetch + parse the JSON manifest from the configured raw Git URL.
    SSRF-safe, size-capped. Returns the parsed object or raises."""
    url = (gc.get('url') or '').strip()
    if not url:
        raise ValueError('no manifest URL configured')
    if not re.match(r'^https?://', url):
        raise ValueError('url must be http(s)://')
    parsed = urllib.parse.urlparse(url)
    headers = {'User-Agent': f'RemotePower/{SERVER_VERSION}',
               'Accept': 'application/json, text/plain, */*'}
    tok = (gc.get('auth_header') or '').strip()
    if tok:
        headers['Authorization'] = tok
    opener = _ssrf_safe_opener(allow_loopback=True,
                               ssl_ctx=_get_ssl_context() if parsed.scheme == 'https' else None,
                               no_redirect=True)
    req = urllib.request.Request(url, headers=headers, method='GET')
    resp = opener.open(req, timeout=15)
    data = resp.read(GITOPS_MAX_MANIFEST_BYTES + 1)
    if len(data) > GITOPS_MAX_MANIFEST_BYTES:
        raise ValueError(f'manifest too large (max {GITOPS_MAX_MANIFEST_BYTES} bytes)')
    return json.loads(data.decode('utf-8'))


def _gitops_sync(actor='system', dry=False):
    """Fetch the manifest and reconcile. Records status; never raises onto the
    request path beyond returning {'ok': False, 'error': ...}."""
    gc = (load(CONFIG_FILE) or {}).get('gitops') or {}
    if not (gc.get('url') or '').strip():
        return {'ok': False, 'error': 'no manifest URL configured'}
    now = int(time.time())
    try:
        manifest = _gitops_fetch_manifest(gc)
        summary = _gitops_reconcile(manifest, dry=dry)
        result = {'ok': True, **summary}
        if not dry:
            with _LockedUpdate(GITOPS_STATE_FILE) as st:
                st['last_sync'] = now
                st['last_status'] = 'ok'
                st['last_error'] = ''
                st['last_summary'] = summary
            audit_log(actor, 'gitops_sync',
                      f"added={summary['added']} updated={summary['updated']} "
                      f"removed={summary['removed']} assigns={summary['assignments']}")
        return result
    except Exception as e:
        err = str(e)[:300]
        if not dry:
            try:
                with _LockedUpdate(GITOPS_STATE_FILE) as st:
                    st['last_sync'] = now
                    st['last_status'] = 'error'
                    st['last_error'] = err
            except Exception:
                pass
            audit_log(actor, 'gitops_sync_failed', err)
        return {'ok': False, 'error': err}


def _maybe_gitops_sync():
    """Periodic, interval-gated GitOps reconcile. Off unless enabled + URL set."""
    cfg = load(CONFIG_FILE) or {}
    gc = cfg.get('gitops') or {}
    if not gc.get('enabled') or not (gc.get('url') or '').strip():
        return
    interval = max(300, int(gc.get('interval') or 900))
    now = int(time.time())
    due = False
    with _LockedUpdate(GITOPS_STATE_FILE) as st:
        if now - int(st.get('last_attempt', 0)) >= interval:
            st['last_attempt'] = now
            due = True
    if due:
        _gitops_sync(actor='system', dry=False)


def handle_gitops_get():
    """GET /api/gitops — config (auth token masked) + last-sync status."""
    require_auth()
    gc = dict((load(CONFIG_FILE) or {}).get('gitops') or {})
    st = load(GITOPS_STATE_FILE) if backend_exists(GITOPS_STATE_FILE) else {}
    respond(200, {
        'enabled':       bool(gc.get('enabled')),
        'url':           gc.get('url', ''),
        'interval':      int(gc.get('interval') or 900),
        'auth_header_set': bool((gc.get('auth_header') or '').strip()),
        'last_sync':     st.get('last_sync', 0),
        'last_status':   st.get('last_status', ''),
        'last_error':    st.get('last_error', ''),
        'last_summary':  st.get('last_summary') or {},
    })


def handle_gitops_set():
    """PUT /api/gitops — configure GitOps sync (admin). Off by default."""
    actor = require_admin_auth()
    if method() != 'PUT':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    enabled = bool(body.get('enabled'))
    url = _sanitize_str(str(body.get('url', '')).strip(), 512)
    if enabled and not url:
        respond(400, {'error': 'A manifest URL is required when enabled.'})
    if url and not re.match(r'^https?://', url):
        respond(400, {'error': 'url must be http(s)://'})
    interval = max(300, min(86400, int(body.get('interval') or 900)))
    with _LockedUpdate(CONFIG_FILE) as cfg:
        gc = dict(cfg.get('gitops') or {})
        gc['enabled'] = enabled
        gc['url'] = url
        gc['interval'] = interval
        # auth_header: only overwrite when a non-empty value is sent; '' (or the
        # key absent) keeps the stored token; the sentinel '__clear__' wipes it.
        if 'auth_header' in body:
            v = str(body.get('auth_header') or '')
            if v == '__clear__':
                gc['auth_header'] = ''
            elif v.strip():
                gc['auth_header'] = _sanitize_str(v.strip(), 512)
        cfg['gitops'] = gc
    audit_log(actor, 'gitops_set', f'enabled={enabled} url={url} interval={interval}')
    respond(200, {'ok': True, 'enabled': enabled, 'url': url, 'interval': interval})


def handle_gitops_sync():
    """POST /api/gitops/sync[?dry=1] — sync now (admin). dry=1 reports the diff
    without writing."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', ''))
    dry = (qs.get('dry', ['0'])[0] in ('1', 'true', 'yes'))
    result = _gitops_sync(actor=actor, dry=dry)
    respond(200 if result.get('ok') else 400, result)


# ─── v1.8.0: Maintenance windows ───────────────────────────────────────────────

def _cron_match(expr, ts):
    """
    Very small cron evaluator — 5 fields, no ranges like 1-5, no `@reboot`.
    Supports *, */N, a,b,c, single integers. Matches the minute containing `ts`.
    """
    parts = (expr or '').split()
    if len(parts) != 5:
        return False
    tm = time.localtime(ts)
    # cron weekday: 0=Sun..6=Sat; Python tm_wday: 0=Mon..6=Sun. Convert.
    cron_wday = (tm.tm_wday + 1) % 7
    values = (tm.tm_min, tm.tm_hour, tm.tm_mday, tm.tm_mon, cron_wday)
    for spec, v in zip(parts, values):
        if not _cron_field_match(spec, v):
            return False
    return True


def _cron_field_match(spec, value):
    spec = spec.strip()
    if spec == '*':
        return True
    if spec.startswith('*/'):
        try:
            step = int(spec[2:])
            return step > 0 and value % step == 0
        except ValueError:
            return False
    for part in spec.split(','):
        part = part.strip()
        if not part:
            continue
        try:
            if int(part) == value:
                return True
        except ValueError:
            continue
    return False


def _window_active(window, now):
    """Return True if this maintenance window is active right now."""
    # One-shot: ISO-8601 start + end
    start = window.get('start')
    end   = window.get('end')
    if start and end:
        try:
            # Accept both '2026-05-10T22:00:00Z' and '2026-05-10T22:00:00+00:00'
            s = _parse_iso(start)
            e = _parse_iso(end)
            if s <= now <= e:
                return True
        except ValueError:
            pass
    # Recurring cron window
    cron = window.get('cron')
    dur  = int(window.get('duration', 0) or 0)
    if cron and dur > 0:
        # Check the current minute and each minute in the past `dur` seconds
        # to see if this cron expression matched at a time that's still within
        # its duration. We scan backwards in 60s steps — cheap and good enough.
        for i in range(0, dur, 60):
            probe = now - i
            if _cron_match(cron, probe):
                return True
    return False


def _parse_iso(s):
    """Parse ISO-8601 timestamp → unix ts. Supports 'Z' suffix and +HH:MM."""
    if s.endswith('Z'):
        s = s[:-1] + '+00:00'
    # Python 3.7+ handles the rest
    import datetime as _dt
    return int(_dt.datetime.fromisoformat(s).timestamp())


# Events that maintenance windows can suppress. A window is the operator saying
# "expect noise from these hosts now", so the set is broad; a per-window `events`
# list can NARROW it. v5.8.0 (B1.4): added the resource/drift/unit/reboot/
# container/backup churn that a patch or maintenance window predictably causes.
SUPPRESSIBLE_EVENTS = (
    'device_offline', 'device_online',
    'monitor_down',   'monitor_up',
    'service_down',   'service_up',
    'patch_alert',    'cve_found',
    'log_alert',
    # v5.8.0 (B1.4)
    'metric_warning', 'metric_critical',
    'config_drift',   'drift_detected',
    'failed_unit',    'timer_failed',
    'reboot_required',
    'container_stopped', 'container_restarting', 'containers_stale',
    'backup_stale',
)


def in_maintenance(event, payload):
    """
    Return {'reason': ...} if this (event, device) is under an active
    maintenance window, else None. Matches on:
      - payload['device_id']          → device-specific windows
      - device.group                   → group-wide windows
      - window.scope == 'global'       → fleet-wide windows
    """
    if event not in SUPPRESSIBLE_EVENTS:
        return None

    maint = load(MAINT_FILE)
    windows = maint.get('windows') or []
    if not windows:
        return None

    now = int(time.time())
    dev_id = payload.get('device_id', '')
    dev_group = ''
    if dev_id:
        devices = load(DEVICES_FILE)
        dev_group = (devices.get(dev_id, {}).get('group') or '')

    for w in windows:
        scope = (w.get('scope') or 'device').lower()
        # Decide if this window applies to this target
        applies = False
        if scope == 'global':
            applies = True
        elif scope == 'group' and dev_group and w.get('target') == dev_group:
            applies = True
        elif scope == 'device' and dev_id and w.get('target') == dev_id:
            applies = True
        if not applies:
            continue
        if _window_active(w, now):
            # Respect an optional per-window event list (defaults to all)
            allowed = w.get('events')
            if allowed and event not in allowed:
                continue
            return {
                'window_id': w.get('id', ''),
                'reason':    w.get('reason', 'maintenance window active'),
                'scope':     scope,
                'target':    w.get('target', ''),
            }
    return None


def _exec_gated(dev_id, dev, now=None):
    """v3.4.2: change-window gating. If a device is covered by one or more
    maintenance windows flagged ``gate_exec``, its exec/upgrade commands are HELD
    until one of those windows is active. Returns True == hold the command.
    Devices not covered by any gate_exec window are never gated (returns False),
    so this is opt-in per window and inert by default."""
    now = now or int(time.time())
    try:
        windows = (load(MAINT_FILE) or {}).get('windows') or []
    except Exception:
        return False
    dev_group = (dev or {}).get('group') or ''
    covered = False
    for w in windows:
        if not w.get('gate_exec'):
            continue
        scope = (w.get('scope') or 'device').lower()
        applies = (scope == 'global'
                   or (scope == 'group' and dev_group and w.get('target') == dev_group)
                   or (scope == 'device' and dev_id and w.get('target') == dev_id))
        if not applies:
            continue
        covered = True
        if _window_active(w, now):
            return False   # an applicable change-window is open → allow now
    return covered          # covered but none active → hold


def log_suppression(event, payload, info):
    """Append an entry to the maintenance-suppression audit trail."""
    try:
        log = load(MAINT_SUPPRESS_LOG)
        entries = log.get('entries') or []
        entries.append({
            'ts':         int(time.time()),
            'event':      event,
            'device_id':  payload.get('device_id', ''),
            'window_id':  info.get('window_id', ''),
            'reason':     info.get('reason', ''),
            'scope':      info.get('scope', ''),
        })
        entries = entries[-500:]  # keep last 500
        log['entries'] = entries
        save(MAINT_SUPPRESS_LOG, log)
    except Exception:
        pass


def handle_maintenance_list():
    """GET /api/maintenance — list all defined windows + currently active ones."""
    require_auth()
    maint = load(MAINT_FILE)
    windows = maint.get('windows') or []
    now = int(time.time())
    devices = load(DEVICES_FILE)
    out = []
    for w in windows:
        entry = {**w, 'active': _window_active(w, now)}
        # Resolve a device-scoped target id to a human label so the UI can
        # show the hostname instead of the opaque device id.
        if w.get('scope') == 'device':
            dev = devices.get(w.get('target'))
            if dev:
                entry['target_name'] = dev.get('name') or dev.get('hostname') or w.get('target')
        out.append(entry)
    out.sort(key=lambda x: (not x['active'], x.get('reason', '')))
    respond(200, {'windows': out})


def handle_maintenance_add():
    """POST /api/maintenance — create a window."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})

    body = get_json_obj()
    reason = _sanitize_str(body.get('reason', ''), 128)
    scope  = _sanitize_str(body.get('scope', 'device'), 16).lower()
    target = _sanitize_str(body.get('target', ''), 128)
    start  = _sanitize_str(body.get('start', ''), 32)
    end    = _sanitize_str(body.get('end', ''), 32)
    cron   = _sanitize_str(body.get('cron', ''), 64)

    try:
        duration = int(body.get('duration', 0) or 0)
    except (TypeError, ValueError):
        duration = 0

    events = body.get('events') or []
    if not isinstance(events, list):
        events = []
    events = [e for e in events if e in SUPPRESSIBLE_EVENTS][:10]

    if scope not in ('device', 'group', 'global'):
        respond(400, {'error': 'scope must be device, group, or global'})
    if scope == 'device' and not _validate_id(target):
        respond(400, {'error': 'device-scoped window requires a valid target device_id'})
    if scope == 'group' and not target:
        respond(400, {'error': 'group-scoped window requires a target group name'})

    # Must be either (start+end) or (cron+duration) — not both, not neither
    has_oneshot = bool(start and end)
    has_cron    = bool(cron and duration > 0)
    if has_oneshot == has_cron:
        respond(400, {'error': 'specify exactly one of (start+end) or (cron+duration)'})

    if has_oneshot:
        try:
            s = _parse_iso(start); e = _parse_iso(end)
            if e <= s:
                respond(400, {'error': 'end must be after start'})
        except ValueError:
            respond(400, {'error': 'invalid ISO-8601 timestamp'})

    if has_cron:
        if _cron_match(cron, int(time.time())) is False and len(cron.split()) != 5:
            respond(400, {'error': 'cron must have 5 space-separated fields'})
        if duration < 60 or duration > 86400 * 7:
            respond(400, {'error': 'duration must be 60..604800 seconds'})

    window = {
        'id':       secrets.token_hex(8),
        'reason':   reason,
        'scope':    scope,
        'target':   target,
        'start':    start,
        'end':      end,
        'cron':     cron,
        'duration': duration,
        'events':   events,
        # v3.4.2: when set, exec/upgrade commands for covered devices are HELD
        # until one of the device's gating windows is active (change-window
        # gating — distinct from the alert suppression above).
        'gate_exec': bool(body.get('gate_exec')),
        'created_by': actor,
        'created_at': int(time.time()),
    }

    maint = load(MAINT_FILE)
    windows = maint.get('windows') or []
    windows.append(window)
    maint['windows'] = windows
    save(MAINT_FILE, maint)
    audit_log(actor, 'maintenance_add',
              detail=f'id={window["id"]} scope={scope} target={target} reason={reason[:60]}')
    respond(200, {'ok': True, 'window': window})


def _validate_maintenance_body(body):
    """Shared validation for maintenance add + update. Returns the
    clean fields dict or calls respond() with an error."""
    if not isinstance(body, dict): body = {}  # non-dict (e.g. JSON array) → empty, not a 500
    reason = _sanitize_str(body.get('reason', ''), 128)
    scope  = _sanitize_str(body.get('scope', 'device'), 16).lower()
    target = _sanitize_str(body.get('target', ''), 128)
    start  = _sanitize_str(body.get('start', ''), 32)
    end    = _sanitize_str(body.get('end', ''), 32)
    cron   = _sanitize_str(body.get('cron', ''), 64)
    try:
        duration = int(body.get('duration', 0) or 0)
    except (TypeError, ValueError):
        duration = 0
    events = body.get('events') or []
    if not isinstance(events, list):
        events = []
    events = [e for e in events if e in SUPPRESSIBLE_EVENTS][:10]
    if scope not in ('device', 'group', 'global'):
        respond(400, {'error': 'scope must be device, group, or global'})
    if scope == 'device' and not _validate_id(target):
        respond(400, {'error': 'device-scoped window requires a valid target device_id'})
    if scope == 'group' and not target:
        respond(400, {'error': 'group-scoped window requires a target group name'})
    has_oneshot = bool(start and end)
    has_cron    = bool(cron and duration > 0)
    if has_oneshot == has_cron:
        respond(400, {'error': 'specify exactly one of (start+end) or (cron+duration)'})
    if has_oneshot:
        try:
            s = _parse_iso(start); e = _parse_iso(end)
            if e <= s:
                respond(400, {'error': 'end must be after start'})
        except ValueError:
            respond(400, {'error': 'invalid ISO-8601 timestamp'})
    if has_cron:
        if _cron_match(cron, int(time.time())) is False and len(cron.split()) != 5:
            respond(400, {'error': 'cron must have 5 space-separated fields'})
        if duration < 60 or duration > 86400 * 7:
            respond(400, {'error': 'duration must be 60..604800 seconds'})
    return {
        'reason': reason, 'scope': scope, 'target': target,
        'start': start, 'end': end, 'cron': cron,
        'duration': duration, 'events': events,
        'gate_exec': bool(body.get('gate_exec')),
    }


def handle_maintenance_update(window_id):
    """PUT /api/maintenance/{id} — replace an existing window.

    v3.3.0: counterpart to POST/DELETE so the Maintenance Windows table
    can offer an Edit button. created_by + created_at + id preserved;
    every other field is overwritten by the validated payload.
    """
    actor = require_admin_auth()
    if method() != 'PUT':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_body()
    clean = _validate_maintenance_body(body)
    with _LockedUpdate(MAINT_FILE) as maint:
        windows = maint.get('windows') or []
        target_win = next((w for w in windows if w.get('id') == window_id), None)
        if not target_win:
            respond(404, {'error': 'maintenance window not found'})
        new_win = dict(target_win)  # preserve id/created_by/created_at
        new_win.update(clean)
        new_win['updated_by'] = actor
        new_win['updated_at'] = int(time.time())
        maint['windows'] = [w if w.get('id') != window_id else new_win for w in windows]
    audit_log(actor, 'maintenance_update',
              detail=f'id={window_id} scope={clean["scope"]} target={clean["target"]} '
                     f'reason={clean["reason"][:60]}')
    respond(200, {'ok': True, 'window': new_win})


def handle_maintenance_delete(window_id):
    """DELETE /api/maintenance/{id}"""
    actor = require_admin_auth()
    maint = load(MAINT_FILE)
    windows = maint.get('windows') or []
    remaining = [w for w in windows if w.get('id') != window_id]
    if len(remaining) == len(windows):
        respond(404, {'error': 'Window not found'})
    maint['windows'] = remaining
    save(MAINT_FILE, maint)
    audit_log(actor, 'maintenance_delete', detail=f'id={window_id}')
    respond(200, {'ok': True})


def handle_maintenance_suppressions():
    """GET /api/maintenance/suppressions — recent suppression audit trail."""
    require_auth()
    log = load(MAINT_SUPPRESS_LOG)
    respond(200, {'entries': (log.get('entries') or [])[-100:][::-1]})


# ─── v1.8.0: Service monitoring (agent-reported systemd units) ────────────────

def _sanitize_unit_name(name):
    """Allow systemd unit names: letters, digits, @.-_+ and must end in .service
    or have no dot. Just bound length and reject whitespace/path traversal."""
    if not isinstance(name, str):
        return None
    s = name.strip()[:128]
    if not s or not re.match(r'^[A-Za-z0-9][A-Za-z0-9._@+\-]{0,127}$', s):
        return None
    return s


def _sanitize_service_entry(entry):
    if not isinstance(entry, dict):
        return None
    unit   = _sanitize_unit_name(entry.get('unit', ''))
    if not unit:
        return None
    active = str(entry.get('active', 'unknown'))[:16]
    sub    = str(entry.get('sub', ''))[:32]
    since  = entry.get('since') or 0
    try:
        since = int(since)
    except (TypeError, ValueError):
        since = 0
    out = {'unit': unit, 'active': active, 'sub': sub, 'since': since}
    # v3.9.0: the agent resolves a watched alias to its canonical unit (e.g.
    # mysql.service → mariadb.service); keep it (validated) so the UI can show
    # what systemd actually matched. Only when it differs from the watched name.
    canonical = _sanitize_unit_name(entry.get('canonical', ''))
    if canonical and canonical != unit:
        out['canonical'] = canonical
    return out


def _record_service_transition(dev_id, unit, old_active, new_active, ts):
    """Append a transition to service_history.json keyed by (device,unit).

    v3.3.0: now under _LockedUpdate — concurrent heartbeats from different
    devices would otherwise stomp each other (last writer wins, transitions
    lost from disk)."""
    key = f'{dev_id}:{unit}'
    with _LockedUpdate(SERVICE_HIST_FILE) as hist:
        entries = hist.get(key) or []
        entries.append({'ts': ts, 'from': old_active, 'to': new_active})
        entries = entries[-MAX_SERVICE_HIST:]
        hist[key] = entries


def _fire_service_webhook(event, dev_id, unit, payload_extra=None):
    """Wrapper that fires service_up/service_down through fire_webhook."""
    devices = load(DEVICES_FILE)
    dev = devices.get(dev_id, {})
    payload = {
        'device_id': dev_id,
        'name':      dev.get('name', dev_id),
        'group':     dev.get('group', ''),
        'unit':      unit,
    }
    if payload_extra:
        payload.update(payload_extra)
    fire_webhook(event, payload)


def process_service_report(dev_id, services_payload):
    """
    Called from handle_heartbeat. Updates services.json, records transitions,
    fires webhooks on state changes.

    services_payload: [{unit, active, sub, since}, ...]
    """
    if not isinstance(services_payload, list):
        return

    now = int(time.time())
    clean = []
    for entry in services_payload[:MAX_SERVICES_PER_DEVICE]:
        e = _sanitize_service_entry(entry)
        if e:
            clean.append(e)
    if not clean:
        return

    # v3.3.0: was bare load/save — two agents heartbeating concurrently
    # would race and one of the writes was lost. _LockedUpdate scopes the
    # mutation under the file lock. Webhooks fire AFTER the lock releases
    # so a slow webhook destination can't hold the services.json lock
    # against subsequent heartbeats.
    transitions = []
    with _LockedUpdate(SERVICES_FILE) as store:
        prev_dev = store.get(dev_id) or {}
        prev_by_unit = {s['unit']: s for s in (prev_dev.get('services') or [])}

        for entry in clean:
            prev = prev_by_unit.get(entry['unit'])
            if not prev:
                continue  # first time we see this unit; no transition yet
            # Normalize: treat anything other than 'active' as "down" for alerting
            was_up = (prev.get('active') == 'active')
            is_up  = (entry['active'] == 'active')
            if was_up != is_up:
                transitions.append((entry, prev, is_up))

        store[dev_id] = {'updated_at': now, 'services': clean}

    # Fire transitions outside the lock to keep the hot path short.
    for entry, prev, is_up in transitions:
        _record_service_transition(
            dev_id, entry['unit'], prev.get('active'), entry['active'], now
        )
        event = 'service_up' if is_up else 'service_down'
        _fire_service_webhook(event, dev_id, entry['unit'], {
            'active':    entry['active'],
            'sub':       entry['sub'],
            'previous':  prev.get('active'),
        })


# ─── v1.11.4: container alerting ────────────────────────────────────────────
#
# Same shape as the service report processor: diff this heartbeat against the
# previous one and fire webhooks on transitions. The transitions we care about:
#
#   1. A previously-seen container is now missing or has a non-running status
#      → fire ``container_stopped``. Restart-during-the-poll-window is
#      indistinguishable from a real stop here (we'd need ``docker events``
#      for that), but the webhook lets the operator decide if it's noise.
#
#   2. ``restart_count`` climbed since the last report → fire
#      ``container_restarting``. Only meaningful for Kubernetes pods (Docker
#      ``ps`` doesn't expose it; agent reports 0). Threshold: ``delta >= 1``.
#
# We don't fire ``container_started`` for new entries, mirroring the
# service-up convention of "transitions back to a known state are quieter
# than transitions away from it." Add later if anyone asks.

# Threshold for the restart-count delta to fire the restarting webhook.
# A bare 1 is enough — if a pod restarted, that's something to know.
CONTAINER_RESTART_DELTA_THRESHOLD = 1


# ─── v1.11.10: metric threshold processing ──────────────────────────────────
#
# Fires metric_warning / metric_critical when a resource crosses its
# configured threshold, and metric_recovered when it drops below the
# warn threshold minus the recovery buffer (hysteresis to prevent
# webhook spam from values oscillating around the line).
#
# Per-metric notification state is stored under
# ``dev['metric_state']`` as a dict keyed by ``f"{kind}:{target}"``:
#
#     "disk:/var":   "critical"   — current alert level
#     "memory:":     "warning"
#     "cpu:":        "ok"          — explicit "no alert" state
#
# Transitions:
#   ok       → warning   : fire metric_warning
#   ok       → critical  : fire metric_critical (skip the warning fire)
#   warning  → critical  : fire metric_critical
#   critical → warning   : fire metric_warning  (downgrade)
#   any      → ok        : fire metric_recovered (when value drops below
#                          warn - recovery_buffer; one-shot)
#
# Thresholds resolution order (most-to-least specific):
#   1. devices[id]['metric_thresholds']['disk_per_mount'][path] for disk
#      with a specific mount path
#   2. devices[id]['metric_thresholds'][key] for that kind
#   3. config[key] (global override) — not implemented in v1.11.10 to
#      keep the surface small; per-device covers 95% of real cases.
#   4. DEFAULT_METRIC_THRESHOLDS[key] (the constants at the top of api.py)


def _resolve_metric_thresholds(dev, kind, target=''):
    """Return ``(warn, crit)`` for a given (kind, target) on this device.

    Args:
        dev: the device dict from devices.json.
        kind: one of 'disk', 'memory', 'swap', 'cpu'.
        target: for kind='disk' a mount path; otherwise empty.

    Returns:
        Tuple ``(warn, crit)``. Units are percent for disk/memory/swap,
        load-ratio for cpu.
    """
    overrides = (dev.get('metric_thresholds') or {}) if isinstance(dev, dict) else {}

    if kind == 'disk':
        # Per-mount overrides first
        per_mount = overrides.get('disk_per_mount') or {}
        if isinstance(per_mount, dict) and target in per_mount:
            entry = per_mount[target]
            if isinstance(entry, dict):
                w = entry.get('warn')
                c = entry.get('crit')
                if isinstance(w, (int, float)) and isinstance(c, (int, float)):
                    return float(w), float(c)
        # Per-device disk override
        w = overrides.get('disk_warn_percent', DEFAULT_METRIC_THRESHOLDS['disk_warn_percent'])
        c = overrides.get('disk_crit_percent', DEFAULT_METRIC_THRESHOLDS['disk_crit_percent'])
        return float(w), float(c)

    if kind == 'memory':
        return (float(overrides.get('mem_warn_percent', DEFAULT_METRIC_THRESHOLDS['mem_warn_percent'])),
                float(overrides.get('mem_crit_percent', DEFAULT_METRIC_THRESHOLDS['mem_crit_percent'])))
    if kind == 'swap':
        return (float(overrides.get('swap_warn_percent', DEFAULT_METRIC_THRESHOLDS['swap_warn_percent'])),
                float(overrides.get('swap_crit_percent', DEFAULT_METRIC_THRESHOLDS['swap_crit_percent'])))
    if kind == 'cpu':
        return (float(overrides.get('cpu_warn_load_ratio', DEFAULT_METRIC_THRESHOLDS['cpu_warn_load_ratio'])),
                float(overrides.get('cpu_crit_load_ratio', DEFAULT_METRIC_THRESHOLDS['cpu_crit_load_ratio'])))
    # v4.1.0: inode / file-descriptor / conntrack fullness — all percentages,
    # so they reuse the metric_warning/critical pipeline (no new event type).
    if kind == 'inode':
        return (float(overrides.get('inode_warn_percent', 85)),
                float(overrides.get('inode_crit_percent', 95)))
    if kind == 'fd':
        return (float(overrides.get('fd_warn_percent', 80)),
                float(overrides.get('fd_crit_percent', 95)))
    if kind == 'conntrack':
        return (float(overrides.get('conntrack_warn_percent', 80)),
                float(overrides.get('conntrack_crit_percent', 95)))
    return (None, None)


def _classify_metric(value, warn, crit):
    """Return 'critical' / 'warning' / 'ok' for a numeric value vs thresholds."""
    if value >= crit:
        return 'critical'
    if value >= warn:
        return 'warning'
    return 'ok'


def _metric_failures_before_alert():
    """v4.3.0: consecutive over-threshold heartbeats before a metric alert fires
    (the metrics sibling of the monitor / SNMP flap-dampening knob). 1 (default)
    = alert on the first breach, exactly as before."""
    try:
        return max(1, min(10, int(_config_ro().get('metric_failures_before_alert', 1) or 1)))
    except (TypeError, ValueError):
        return 1


def _metric_damp_hold(streaks, key, prev_level, new_level, need):
    """Return True if a FIRST breach (ok → warning/critical) should be HELD
    because it hasn't persisted for `need` consecutive heartbeats yet. Only the
    first breach off 'ok' is dampened — escalation (warning→critical),
    de-escalation and recovery are never delayed, so a genuine critical is never
    held back. Mutates the per-key streak map in place."""
    if need <= 1:
        return False
    if prev_level == 'ok' and new_level != 'ok':
        s = min(need, int(streaks.get(key, 0) or 0) + 1)
        streaks[key] = s
        return s < need
    # Not a first breach (escalation / de-escalation / recovery) — clear any
    # pending streak and let it through.
    streaks.pop(key, None)
    return False


def _below_recovery(value, warn):
    """True if value has dropped far enough below warn to fire 'recovered'.

    The absolute buffer is sized for percentage metrics (memory/disk/swap, on a
    0–100 scale). For a small *ratio* threshold like CPU load (warn ≈ 1.5), an
    absolute 5-point buffer makes `warn - buffer` negative and the condition
    unsatisfiable — so a CPU warning could never clear and stuck forever once
    tripped (v3.8.0 bugfix). Floor the recovery point at a 10% proportional
    band so it's always a sensible positive value; for percentage metrics the
    absolute buffer still wins (e.g. warn 80 → recover < 75), so their
    behaviour is unchanged.
    """
    recovery_point = max(warn - METRIC_RECOVERY_BUFFER, warn * 0.9)
    return value < recovery_point


def _metric_webhook_payload(event, dev_id, dev, kind, target, value, threshold,
                            extra=None):
    """Build the (event, payload) tuple for a metric_* webhook.

    Payload uses both `kind` (legacy webhook payload key) and `metric`
    (the canonical name the alerts inbox + alert-title formatter expect).
    `level` carries the human-readable severity word so _alert_severity
    can classify the alert without re-deriving it.
    """
    level = ('critical' if event == 'metric_critical' else
             'warning'  if event == 'metric_warning'  else 'ok')
    payload = {
        'device_id': dev_id,
        'name':      dev.get('name', dev_id),
        'group':     dev.get('group', ''),
        'kind':      kind,
        'metric':    kind,        # alias for alerts-inbox payload schema
        'target':    target,
        'value':     value,
        'threshold': threshold,
        'level':     level,
    }
    if extra:
        payload.update(extra)
    return event, payload


def _fire_metric_webhook(event, dev_id, dev, kind, target, value, threshold,
                         extra=None):
    """Fire a metric_* webhook immediately. In-lock callers must instead buffer
    via process_metric_thresholds and fire after the lock (see B2/lock-nesting)."""
    ev, payload = _metric_webhook_payload(event, dev_id, dev, kind, target, value, threshold, extra)
    fire_webhook(ev, payload)


def process_metric_thresholds(dev_id, dev, safe_si, defer=False):
    """Check each resource against its threshold and fire webhooks on transitions.

    Called from handle_heartbeat after sysinfo storage. Updates
    ``dev['metric_state']`` in place — caller is expected to save the
    devices file (it already does). Updates run before container processing
    so the state from this heartbeat is visible to the rest of the request.

    No-op cleanly when:
        - psutil isn't installed on the agent (no metrics in payload)
        - the device is in a maintenance window (alerts suppressed globally)
        - global metric webhooks are disabled in config
    """
    if not isinstance(safe_si, dict):
        return

    # Note: we deliberately don't check the per-event 'enabled' flag here —
    # fire_webhook() already does that. Suppressing earlier would skip the
    # state-tracking too, which means a transition during the disabled
    # window would be missed when re-enabled. Better to track always and
    # let fire_webhook decide whether to actually deliver.

    state = dev.get('metric_state') or {}
    if not isinstance(state, dict):
        state = {}
    # v4.3.0: per-key breach streak for flap dampening (see _metric_damp_hold).
    streaks = dev.get('metric_breach_streak') or {}
    if not isinstance(streaks, dict):
        streaks = {}
    need = _metric_failures_before_alert()

    # v4.8.0: buffer metric webhooks and return them so the caller fires them
    # AFTER its _DeviceUpdate lock releases. fire_webhook() takes its own
    # _LockedUpdate; nesting it inside the held DEVICES lock raises
    # OperationalError under the SQLite backend and the alert silently vanishes.
    # Shadowing the module-level firer keeps the call sites below unchanged.
    pending_webhooks = []

    def _emit(event, dev_id, dev, kind, target, value, threshold, extra=None):
        # Buffer when deferring (the caller fires after its lock releases);
        # otherwise fire immediately via the module-level helper (which callers
        # and tests may patch).
        if defer:
            pending_webhooks.append(
                _metric_webhook_payload(event, dev_id, dev, kind, target, value, threshold, extra))
        else:
            _fire_metric_webhook(event, dev_id, dev, kind, target, value, threshold, extra)

    def _check(kind, target, value):
        """Check one metric and fire webhooks on transition."""
        if value is None:
            return
        warn, crit = _resolve_metric_thresholds(dev, kind, target)
        if warn is None:
            return
        new_level = _classify_metric(value, warn, crit)
        key = f'{kind}:{target}'
        prev_level = state.get(key, 'ok')

        if new_level == prev_level:
            # No transition. Special-case: if currently in 'warning' state
            # and value has DROPPED below warn-buffer, fire metric_recovered.
            # This happens if the metric oscillates: it briefly went above
            # warn, came back. Standard hysteresis.
            if prev_level != 'ok' and _below_recovery(value, warn):
                _emit('metric_recovered', dev_id, dev, kind, target,
                                     value, warn)
                state[key] = 'ok'
                streaks.pop(key, None)
            elif new_level == 'ok':
                streaks.pop(key, None)   # steady-OK: clear any pending breach
            return

        # v4.3.0: flap dampening — hold a first ok→warn/crit breach until it
        # has persisted for `need` consecutive heartbeats (escalation, recovery
        # and de-escalation are never held).
        if _metric_damp_hold(streaks, key, prev_level, new_level, need):
            return

        # Transition. Fire the appropriate event.
        if new_level == 'critical':
            _emit('metric_critical', dev_id, dev, kind, target,
                                 value, crit)
        elif new_level == 'warning':
            _emit('metric_warning', dev_id, dev, kind, target,
                                 value, warn)
        else:  # new_level == 'ok'
            # Only fire recovered if we're below the buffer; otherwise stay
            # in 'warning' until value drops further. This is the classic
            # hysteresis: don't bounce between ok/warning.
            if _below_recovery(value, warn):
                _emit('metric_recovered', dev_id, dev, kind, target,
                                     value, warn)
            else:
                # Don't transition to 'ok' yet — the value is below warn but
                # within the recovery buffer. Stay in the previous level so
                # we don't fire 'recovered' prematurely.
                return
        state[key] = new_level

    # Memory
    _check('memory', '', safe_si.get('mem_percent'))
    # Swap
    _check('swap', '', safe_si.get('swap_percent'))
    # CPU as load ratio (loadavg / cpu_count)
    load = safe_si.get('loadavg_1m')
    cpu_count = safe_si.get('cpu_count', 1) or 1
    if isinstance(load, (int, float)) and load >= 0:
        # CPU "value" we compare to threshold is the load ratio itself.
        ratio = load / max(cpu_count, 1)
        # Threshold extras for the webhook payload
        warn, crit = _resolve_metric_thresholds(dev, 'cpu', '')
        new_level = _classify_metric(ratio, warn, crit)
        key = 'cpu:'
        prev_level = state.get(key, 'ok')
        if new_level != prev_level:
            transitioned = True
            # v4.3.0: hold a first ok→warn/crit breach until it persists `need`
            # heartbeats (escalation / recovery / de-escalation never held).
            if _metric_damp_hold(streaks, key, prev_level, new_level, need):
                transitioned = False
            elif new_level == 'critical':
                _emit('metric_critical', dev_id, dev, 'cpu', '',
                                     round(load, 2), crit, {'cpu_count': cpu_count})
            elif new_level == 'warning':
                _emit('metric_warning', dev_id, dev, 'cpu', '',
                                     round(load, 2), warn, {'cpu_count': cpu_count})
            elif _below_recovery(ratio, warn):
                _emit('metric_recovered', dev_id, dev, 'cpu', '',
                                     round(load, 2), warn, {'cpu_count': cpu_count})
            else:
                # Below warn but inside the recovery buffer — stay in the
                # previous level (hysteresis). Don't update state[key] here,
                # and crucially don't `return`: the disk loop below and the
                # final `dev['metric_state'] = state` still need to run.
                transitioned = False
            if transitioned:
                state[key] = new_level
        elif prev_level != 'ok' and _below_recovery(ratio, warn):
            _emit('metric_recovered', dev_id, dev, 'cpu', '',
                                 round(load, 2), warn, {'cpu_count': cpu_count})
            state[key] = 'ok'
            streaks.pop(key, None)
        elif new_level == 'ok':
            streaks.pop(key, None)   # steady-OK: clear any pending breach

    # Disks: per-mount if reported, fall back to legacy disk_percent for /
    mounts = safe_si.get('mounts') or []
    if mounts:
        # Track which keys are seen this report; orphan disk states (mount
        # was unmounted between reports) get silently cleaned up.
        seen_disk_keys = set()
        for m in mounts:
            path = m.get('path')
            pct = m.get('percent')
            if path and pct is not None:
                seen_disk_keys.add(f'disk:{path}')
                _check('disk', path, pct)
            # v4.1.0: inode exhaustion per mount (own kind, own thresholds).
            ip = m.get('inode_percent')
            if path and ip is not None:
                seen_disk_keys.add(f'inode:{path}')
                _check('inode', path, ip)
        # Clean orphans
        for key in list(state.keys()):
            if (key.startswith('disk:') or key.startswith('inode:')) \
                    and key not in seen_disk_keys:
                state.pop(key, None)
    elif safe_si.get('disk_percent') is not None:
        # Pre-v1.11.10 agent: only legacy root-disk metric. Treat as '/'.
        _check('disk', '/', safe_si['disk_percent'])

    # v4.1.0: file-descriptor + conntrack table fullness (host-wide, no target).
    _check('fd', '', safe_si.get('fd_percent'))
    _check('conntrack', '', safe_si.get('conntrack_percent'))

    dev['metric_state'] = state
    # v4.3.0: persist (or drop, when empty) the per-key breach-streak map.
    if streaks:
        dev['metric_breach_streak'] = streaks
    else:
        dev.pop('metric_breach_streak', None)
    # When defer=True the caller fires `pending_webhooks` AFTER releasing the
    # DEVICES lock (fire_webhook self-locks; nesting it drops the alert under
    # SQLite — the B2 lock-nesting class). When defer=False _emit already fired
    # each one inline, so this list is empty.
    return pending_webhooks


# ── v3.2.0 (B5 follow-up): threshold check for SNMP-polled devices ─────────

def _snmp_threshold_warn_crit(dev, kind):
    """Return (warn, crit) for an SNMP-derived metric. Uses per-device
    overrides under `metric_thresholds` if present, falls back to defaults.

    kind ∈ {'snmp_cpu', 'snmp_mem', 'snmp_disk', 'temp_cpu', 'temp_board'}.
    """
    overrides = (dev.get('metric_thresholds') or {}) if isinstance(dev, dict) else {}
    D = DEFAULT_METRIC_THRESHOLDS
    if kind == 'snmp_cpu':
        return (float(overrides.get('snmp_cpu_warn_percent',
                                     D['snmp_cpu_warn_percent'])),
                float(overrides.get('snmp_cpu_crit_percent',
                                     D['snmp_cpu_crit_percent'])))
    if kind == 'snmp_mem':
        # Re-use existing memory thresholds — same percent units
        return (float(overrides.get('mem_warn_percent', D['mem_warn_percent'])),
                float(overrides.get('mem_crit_percent', D['mem_crit_percent'])))
    if kind == 'snmp_disk':
        # Re-use existing disk thresholds — same percent units
        return (float(overrides.get('disk_warn_percent', D['disk_warn_percent'])),
                float(overrides.get('disk_crit_percent', D['disk_crit_percent'])))
    if kind in ('temp_cpu', 'temp_board'):
        return (float(overrides.get('temp_warn_celsius', D['temp_warn_celsius'])),
                float(overrides.get('temp_crit_celsius', D['temp_crit_celsius'])))
    return (None, None)


def _snmp_memory_used_pct(snmp_entry):
    """Pick memory used % from the polled storage table. Looks for the
    physical/main memory entry first; falls back to None."""
    for s in snmp_entry.get('storage') or []:
        descr = (s.get('descr') or '').lower()
        if descr in ('physical memory', 'main memory', 'memory'):
            return s.get('used_pct')
    return None


def _snmp_storage_mounts(snmp_entry):
    """List of filesystem-like storage entries (skip memory/swap/cache).
    Returns [{descr, used_pct}, ...]."""
    out = []
    for s in snmp_entry.get('storage') or []:
        descr = (s.get('descr') or '').strip()
        low = descr.lower()
        # Skip non-filesystem rows
        if not descr:
            continue
        if any(t in low for t in ('memory', 'swap', 'cached', 'buffer',
                                   'virtual', 'shared')):
            continue
        if 'system disk' in low or descr.startswith('/'):
            if s.get('used_pct') is not None:
                out.append({'descr': descr, 'used_pct': s['used_pct']})
            continue
        # Mikrotik exposes "system disk" — accept by descr having no leading /
        if s.get('used_pct') is not None:
            out.append({'descr': descr, 'used_pct': s['used_pct']})
    return out


def _snmp_cpu_avg_pct(snmp_entry):
    """Aggregate the per-core load %s into one number. None if no data."""
    procs = snmp_entry.get('processors') or []
    if not procs:
        return None
    loads = [p.get('load_pct') for p in procs if isinstance(p.get('load_pct'), (int, float))]
    if not loads:
        return None
    return sum(loads) / len(loads)


def _snmp_temp_celsius(snmp_entry, source='board'):
    """Pick a temperature value out of vendor MIB blocks.

    source='board' → Mikrotik mtxrHlBoardTemp (returned in tenths of °C)
    source='cpu'   → Mikrotik mtxrHlTemperature
    Returns None if not advertised.
    """
    v = snmp_entry.get('vendor') or {}
    key = 'mtxrHlBoardTemp' if source == 'board' else 'mtxrHlTemperature'
    raw = v.get(key)
    if isinstance(raw, (int, float)) and raw > 0:
        # Mikrotik returns tenths of degrees. 470 → 47.0 °C.
        return raw / 10.0
    return None


def _record_snmp_metrics(dev_id, snmp_entry):
    """v3.14.0 fix: append the polled SNMP CPU/memory/disk to the metric
    time-series (reusing _record_metrics, the same sink the agent heartbeat path
    uses) so SNMP-polled devices show trend graphs. disk_percent is the busiest
    storage mount; swap isn't an SNMP metric. No-op if nothing numeric polled."""
    cpu = _snmp_cpu_avg_pct(snmp_entry)
    mem = _snmp_memory_used_pct(snmp_entry)
    disks = [s['used_pct'] for s in _snmp_storage_mounts(snmp_entry)
             if isinstance(s.get('used_pct'), (int, float))]
    disk = max(disks) if disks else None
    if cpu is None and mem is None and disk is None:
        return
    _record_metrics(dev_id, {'cpu_percent': cpu, 'mem_percent': mem,
                             'disk_percent': disk, 'swap_percent': None})


def process_snmp_metric_thresholds(dev_id, dev, snmp_entry):
    """Run polled SNMP metrics through the threshold pipeline.

    Mirrors `process_metric_thresholds` (the agent path) for SNMP
    sources. Computes CPU %, memory %, disk % per storage, and hardware
    temperatures; classifies vs. per-device or default thresholds; and
    fires the SAME metric_warning / metric_critical / metric_recovered
    events the agent path fires. Result: SNMP-polled devices show up in
    the alerts inbox + outbound webhooks exactly like agent hosts.

    Updates dev['metric_state'] in place. Caller is responsible for
    persisting devices.json (the sweep below does so via _LockedUpdate).

    No-op cleanly for unmonitored devices — same posture as fire_webhook's
    suppression gate downstream.
    """
    if not dev.get('monitored', True):
        return

    # Pre-compute the polled measurements — these come from snmp_entry and don't
    # depend on the device record. (kind, target, value, kind_for_threshold)
    measurements = [
        ('snmp_cpu', '', _snmp_cpu_avg_pct(snmp_entry), 'snmp_cpu'),
        ('snmp_mem', '', _snmp_memory_used_pct(snmp_entry), 'snmp_mem'),
    ]
    disk_keys = set()
    for s in _snmp_storage_mounts(snmp_entry):
        measurements.append(('snmp_disk', s['descr'], s['used_pct'], 'snmp_disk'))
        disk_keys.add(f"snmp_disk:{s['descr']}")
    measurements.append(('temp_board', '', _snmp_temp_celsius(snmp_entry, source='board'), 'temp_board'))
    measurements.append(('temp_cpu', '', _snmp_temp_celsius(snmp_entry, source='cpu'), 'temp_cpu'))

    # v3.4.2 bugfix: resolve thresholds + read/modify metric_state against the
    # LIVE device record under the lock, not the `dev` snapshot the poll sweep
    # loaded once. The sweep is network-bound and can run for seconds across
    # many SNMP targets; a threshold saved mid-sweep was previously evaluated
    # against the stale snapshot for that whole cycle, persisting a spurious
    # alert until the next sweep ("re-saving fixes it"). Invalidate the per-
    # process load cache first so __enter__ re-reads from disk. Events are
    # collected and fired AFTER the lock (webhooks do network I/O — never hold
    # the devices lock across them).
    pending = []
    _invalidate_load_cache(DEVICES_FILE)
    with _LockedUpdate(DEVICES_FILE) as store:
        d = store.get(dev_id)
        if not isinstance(d, dict) or not d.get('monitored', True):
            return
        state = d.get('metric_state') or {}
        if not isinstance(state, dict):
            state = {}
        # v4.3.0: same flap dampening as the agent metric path.
        streaks = d.get('metric_breach_streak') or {}
        if not isinstance(streaks, dict):
            streaks = {}
        need = _metric_failures_before_alert()
        for kind, target, value, kft in measurements:
            if value is None:
                continue
            warn, crit = _snmp_threshold_warn_crit(d, kft)
            if warn is None:
                continue
            new_level = _classify_metric(value, warn, crit)
            key = f'{kind}:{target}'
            prev_level = state.get(key, 'ok')
            if new_level == prev_level:
                if prev_level != 'ok' and _below_recovery(value, warn):
                    pending.append(('metric_recovered', kind, target, value, warn))
                    state[key] = 'ok'
                    streaks.pop(key, None)
                elif new_level == 'ok':
                    streaks.pop(key, None)
                continue
            if _metric_damp_hold(streaks, key, prev_level, new_level, need):
                continue   # held — first breach hasn't persisted `need` cycles
            if new_level == 'critical':
                pending.append(('metric_critical', kind, target, value, crit))
            elif new_level == 'warning':
                pending.append(('metric_warning', kind, target, value, warn))
            elif _below_recovery(value, warn):
                pending.append(('metric_recovered', kind, target, value, warn))
            else:
                continue
            state[key] = new_level
        # Clean stale per-disk state (storage entry vanished).
        for k in list(state.keys()):
            if k.startswith('snmp_disk:') and k not in disk_keys:
                state.pop(k, None)
        d['metric_state'] = state
        if streaks:
            d['metric_breach_streak'] = streaks
        else:
            d.pop('metric_breach_streak', None)
        # v4.6.0 (BUGFIX): the v3.4.2 fix read live state under the lock but the
        # webhook below still used the stale pre-lock `dev` snapshot — so a
        # mid-sweep rename produced a webhook with the old name/group. Capture
        # the live record for the post-lock fire.
        live_dev = d

    for event, kind, target, value, ref in pending:
        _fire_metric_webhook(event, dev_id, live_dev, kind, target, value, ref,
                             extra={'source': 'snmp'})


def _container_is_running(status_str):
    """Return True if the agent-reported status string suggests "running".

    Mirrors :func:`containers_mod.summarise`'s permissive matching — different
    runtimes phrase status differently ("Up 2 hours", "running", "Ready").
    """
    s = (status_str or '').lower()
    return any(t in s for t in ('running', 'up ', 'up\t', 'ready'))


def _container_alert_excluded(name):
    """v4.2.0 (#4): skip container alerts for ephemeral pentest-scan containers
    (rp-scan-*) and any operator-configured name substrings
    (config 'container_alert_excludes' — a list of substrings)."""
    n = str(name or '')
    if n.startswith('rp-scan-'):
        return True
    try:
        for pat in _config_ro().get('container_alert_excludes') or []:
            p = str(pat).strip()
            if p and p in n:
                return True
    except Exception:
        pass
    return False


def _fire_container_webhook(event, dev_id, container_name, payload_extra=None):
    """Wrapper that fires container_stopped / container_restarting via fire_webhook."""
    dev = device_get(dev_id) or {}
    payload = {
        'device_id': dev_id,
        'name':      dev.get('name', dev_id),
        'group':     dev.get('group', ''),
        'container': container_name,
    }
    if payload_extra:
        payload.update(payload_extra)
    fire_webhook(event, payload)


def process_container_report(dev_id, normalised, now):
    """Diff a heartbeat's container list against the previous one and fire webhooks.

    Called from :func:`handle_heartbeat` *before* the new list overwrites the
    stored one. Side-effects: zero or more webhook fires. Storage is the
    caller's responsibility — we read CONTAINERS_FILE for the previous state
    but never write it.

    Args:
        dev_id: The reporting device ID.
        normalised: The new list of normalised container dicts (already
            passed through :func:`containers_mod.normalize_listing`).
        now: Current Unix timestamp.
    """
    if not isinstance(normalised, list):
        return

    # v5.0.0 (perf): O(1) per-device read of the previous container list instead
    # of load()ing the whole-fleet blob every heartbeat.
    prev_entry = _entity_read_one(CONTAINERS_FILE, dev_id, None) or {}
    prev_items = prev_entry.get('items') or []
    if not isinstance(prev_items, list):
        prev_items = []

    # First report ever for this device — nothing to diff against.
    # Skip transition detection but DO let storage proceed (caller's job).
    if not prev_items:
        return

    # Index by (runtime, name) to make k8s pods in different namespaces
    # collide-free, and to keep docker/podman containers separate even
    # when they happen to share a name.
    def _key(c):
        return (c.get('runtime', 'unknown'), c.get('namespace', ''), c.get('name', ''))

    new_by_key = {_key(c): c for c in normalised if c.get('name')}
    prev_by_key = {_key(c): c for c in prev_items if c.get('name')}

    # 1) Containers that disappeared or transitioned out of "running"
    for key, prev in prev_by_key.items():
        if _container_alert_excluded(prev.get('name', '')):
            continue  # ephemeral scan containers + operator name excludes
        prev_was_running = _container_is_running(prev.get('status'))
        if not prev_was_running:
            # v5.6.0: was stopped/exited last beat — did it come back? Fire
            # container_recovered so the open container_stopped alert auto-resolves
            # (matched per-container-name in _auto_resolve_alerts).
            cur = new_by_key.get(key)
            if cur is not None and _container_is_running(cur.get('status')):
                _fire_container_webhook('container_recovered', dev_id, prev.get('name', '?'), {
                    'runtime':   prev.get('runtime', 'unknown'),
                    'namespace': prev.get('namespace', ''),
                    'image':     cur.get('image', prev.get('image', '')),
                    'status':    cur.get('status', ''),
                })
            continue  # already-stopped containers don't generate stop noise
        cur = new_by_key.get(key)
        if cur is None:
            # vanished entirely — docker rm / kubectl delete pod / crashed and
            # was cleaned up by the runtime. Either way: alertable.
            _fire_container_webhook('container_stopped', dev_id, prev.get('name', '?'), {
                'runtime':         prev.get('runtime', 'unknown'),
                'namespace':       prev.get('namespace', ''),
                'image':           prev.get('image', ''),
                'previous_status': prev.get('status', ''),
                'status':          'gone',
            })
        elif not _container_is_running(cur.get('status')):
            # still listed, but no longer running (e.g. "Exited (1) 3s ago")
            _fire_container_webhook('container_stopped', dev_id, prev.get('name', '?'), {
                'runtime':         prev.get('runtime', 'unknown'),
                'namespace':       prev.get('namespace', ''),
                'image':           prev.get('image', ''),
                'previous_status': prev.get('status', ''),
                'status':          cur.get('status', ''),
            })

    # 2) Containers whose restart_count climbed since the last report.
    # v3.10.0: the agent now reports a real restart_count for docker/podman too
    # (a single batched `docker inspect` per heartbeat), so this fires fleet-wide
    # — not just for Kubernetes pods as it historically did.
    for key, cur in new_by_key.items():
        prev = prev_by_key.get(key)
        if not prev:
            continue
        try:
            cur_n = int(cur.get('restart_count', 0))
            prev_n = int(prev.get('restart_count', 0))
        except (TypeError, ValueError):
            continue
        delta = cur_n - prev_n
        if delta >= CONTAINER_RESTART_DELTA_THRESHOLD:
            # v4.2.0 sweep: honour the operator's exclude list here too — it
            # only covered the stopped/vanished loop, so an excluded container
            # still paged on restarts.
            if _container_alert_excluded(cur.get('name', '')):
                continue
            _fire_container_webhook('container_restarting', dev_id, cur.get('name', '?'), {
                'runtime':       cur.get('runtime', 'unknown'),
                'namespace':     cur.get('namespace', ''),
                'image':         cur.get('image', ''),
                'restart_count': cur_n,
                'delta':         delta,
            })


def get_container_stale_ttl():
    """Effective container-staleness TTL in seconds, clamped to a sane minimum.

    The default of 900s (15 min) gives comfortable headroom over the agent's
    5-minute container-report cadence. Operators can tune via the
    ``container_stale_ttl`` config key. Anything under 300s would alert on
    every brief network hiccup, so we floor at that.
    """
    try:
        v = int(_config().get('container_stale_ttl', containers_mod.DEFAULT_STALE_TTL))
    except (TypeError, ValueError):
        v = containers_mod.DEFAULT_STALE_TTL
    return max(300, v)


def check_container_webhooks():
    """Fire ``containers_stale`` for devices whose last container report is old.

    Called from :func:`main` on every CGI request, alongside
    :func:`check_offline_webhooks`. A device fires the webhook at most once
    per stale period — the ``containers_stale_notified`` flag is cleared in
    the heartbeat handler whenever fresh container data arrives.

    Devices that have never reported containers (no entry in
    ``containers.json``) are skipped — they probably just have no runtime
    installed. This is checked, not assumed: an entry with ``ts > 0``
    proves the device once had a runtime, so its silence now is a
    regression worth alerting on.
    """
    if not is_webhook_event_enabled('containers_stale'):
        return
    store = load(CONTAINERS_FILE)
    if not isinstance(store, dict) or not store:
        return
    devices = load(DEVICES_FILE)
    cfg = load(CONFIG_FILE)
    notified = cfg.get('containers_stale_notified') or {}
    if not isinstance(notified, dict):
        notified = {}
    ttl = get_container_stale_ttl()
    now = int(time.time())
    changed = False

    for dev_id, entry in store.items():
        if dev_id not in devices:
            continue
        dev = devices[dev_id]
        # Don't bother for devices the operator deliberately stopped monitoring.
        if not dev.get('monitored', True):
            continue
        # And don't fire while the device itself is offline — there's already
        # a device_offline webhook for that, no point double-paging.
        last_seen = dev.get('last_seen', 0)
        if (now - last_seen) > get_online_ttl():
            continue

        ts = entry.get('ts', 0) if isinstance(entry, dict) else 0
        stale = containers_mod.is_stale(ts, now, ttl)
        already = bool(notified.get(dev_id, False))

        if stale and not already:
            age = max(0, now - int(ts)) if ts else 0
            fire_webhook('containers_stale', {
                'device_id':    dev_id,
                'name':         dev.get('name', dev_id),
                'hostname':     dev.get('hostname', ''),
                'reported_at':  int(ts),
                'age_seconds':  age,
                'age_minutes':  age // 60,
                'ttl_minutes':  ttl // 60,
            })
            notified[dev_id] = True
            changed = True
        elif not stale and already:
            # Already cleared on heartbeat ingest, but keep this branch for
            # safety in case the heartbeat path missed it (e.g. config rewrite
            # race). v5.6.x: fire containers_current here too so the open
            # containers_stale alert auto-resolves (idempotent with the
            # heartbeat-path fire above).
            try:
                fire_webhook('containers_current', {
                    'device_id': dev_id,
                    'name':      dev.get('name', dev_id),
                })
            except Exception:
                pass
            notified[dev_id] = False
            changed = True

    if changed:
        cfg['containers_stale_notified'] = notified
        save(CONFIG_FILE, cfg)


def handle_services_get():
    """GET /api/services — all current service states across the fleet."""
    require_auth()
    store = load(SERVICES_FILE)
    devices = load(DEVICES_FILE)
    out = []
    for dev_id, dev in devices.items():
        entry = store.get(dev_id) or {}
        services = entry.get('services') or []
        up = sum(1 for s in services if s.get('active') == 'active')
        down = len(services) - up
        out.append({
            'device_id':  dev_id,
            'name':       dev.get('name', dev_id),
            'group':      dev.get('group', ''),
            'updated_at': entry.get('updated_at', 0),
            'total':      len(services),
            'up':         up,
            'down':       down,
            'services':   services,
        })
    out.sort(key=lambda d: (-d['down'], d['name'].lower()))
    respond(200, {'devices': out})


def handle_services_device(dev_id):
    """GET /api/devices/{id}/services"""
    require_auth()
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    devices = load(DEVICES_FILE)
    if dev_id not in devices:
        respond(404, {'error': 'Device not found'})

    store = load(SERVICES_FILE)
    hist  = load(SERVICE_HIST_FILE)
    log_buf = load(LOG_WATCH_FILE).get(dev_id) or {}
    entry = store.get(dev_id) or {}
    services = entry.get('services') or []

    enriched = []
    for s in services:
        key = f'{dev_id}:{s["unit"]}'
        enriched.append({
            **s,
            'history':  (hist.get(key) or [])[-10:],
            'log_tail': (log_buf.get('units') or {}).get(s['unit'], [])[-50:],
        })
    respond(200, {
        'device_id':  dev_id,
        'name':       devices[dev_id].get('name', dev_id),
        'updated_at': entry.get('updated_at', 0),
        'services':   enriched,
    })


def handle_services_config(dev_id):
    """
    GET/POST /api/devices/{id}/services/config
    Manages services_watched list on the device record.
    """
    actor = require_perm('services', [dev_id]) if method() == 'POST' else None  # v3.12.0 RBAC
    if not actor:
        require_auth()
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    devices = load(DEVICES_FILE)
    if dev_id not in devices:
        respond(404, {'error': 'Device not found'})

    if method() == 'GET':
        respond(200, {
            'services_watched': devices[dev_id].get('services_watched', []),
            'log_watch':        devices[dev_id].get('log_watch', []),
        })

    body = get_json_obj()
    raw = body.get('services_watched') or []
    if not isinstance(raw, list):
        respond(400, {'error': 'services_watched must be a list'})
    watched = []
    for name in raw[:MAX_SERVICES_PER_DEVICE]:
        unit = _sanitize_unit_name(name)
        if unit:
            watched.append(unit)

    # Optional: log_watch rules — [{unit | path, pattern, threshold, severity}]
    log_rules_raw = body.get('log_watch') or []
    log_rules = []
    if isinstance(log_rules_raw, list):
        for r in log_rules_raw[:10]:
            if not isinstance(r, dict):
                continue
            # v3.0.1: rule may specify either a systemd unit OR a file path.
            # Path-based rules tell the agent to tail the file and submit
            # new lines under the synthetic unit name 'file:<path>'.
            path_raw = (r.get('path') or '').strip()
            if path_raw:
                # Restrict to absolute filesystem paths; reject globs and
                # parent-traversal so a misconfigured rule can't grab anything
                # outside the intended directory.
                if (not path_raw.startswith('/')
                        or '..' in path_raw
                        or len(path_raw) > 512
                        or any(c in path_raw for c in '*?[]<>\n\r\t')):
                    continue
                synthetic_unit = f'file:{path_raw}'
                unit = synthetic_unit
                file_path = path_raw
            else:
                unit = _sanitize_unit_name(r.get('unit', ''))
                file_path = None
            pat  = _sanitize_str(r.get('pattern', ''), 128, allow_empty=False)
            try:
                thr = int(r.get('threshold', 1) or 1)
            except (TypeError, ValueError):
                thr = 1
            # v3.0.1: optional severity classification (OK/WARN/CRIT).
            # Defaults to WARN so existing rules keep firing as before.
            sev = str(r.get('severity', 'WARN')).upper()
            if sev not in ('OK', 'WARN', 'CRIT'):
                sev = 'WARN'
            ex_pat = _sanitize_str(r.get('exclude_pattern', ''), 128, allow_empty=True)
            tmpl, _tmpl_err = _validate_log_template(
                _sanitize_str(str(r.get('display_template', '')), 256, allow_empty=True))
            if unit and pat and 1 <= thr <= 100:
                # Sanity-check the regex compiles
                try:
                    re.compile(pat)
                except re.error:
                    continue
                if ex_pat:
                    try:
                        re.compile(ex_pat)
                    except re.error:
                        ex_pat = ''
                rule_clean = {'unit': unit, 'pattern': pat,
                              'threshold': thr, 'severity': sev}
                if file_path:
                    rule_clean['path'] = file_path
                if ex_pat:
                    rule_clean['exclude_pattern'] = ex_pat
                if tmpl:
                    rule_clean['display_template'] = tmpl
                log_rules.append(rule_clean)

    with _LockedUpdate(DEVICES_FILE) as devices:
        if dev_id in devices:
            devices[dev_id]['services_watched'] = watched
            devices[dev_id]['log_watch']        = log_rules
    audit_log(actor, 'services_config_update',
              detail=f'device={dev_id} watched={len(watched)} log_rules={len(log_rules)}')
    respond(200, {'ok': True, 'services_watched': watched, 'log_watch': log_rules})


# ─── v1.8.0: Log tail — called by agent with captured unit logs ───────────────

@functools.lru_cache(maxsize=32)
def _compiled_patterns_cached(patterns, flags=0):
    """Compile a tuple of operator-authored regex patterns once, memoized by
    the exact (patterns, flags) key — a config change is its own cache
    invalidation (new tuple → new key), so this needs no explicit busting.
    Invalid patterns are silently dropped, matching every existing inline
    try/except re.error call site this replaces. `patterns` MUST be a tuple
    (hashable) for lru_cache, not a list. master-improvement-scoping #9."""
    out = []
    for pat in patterns:
        try:
            out.append(re.compile(pat, flags))
        except re.error:
            pass
    return out


def handle_log_submit():
    """
    POST /api/logs — agent submits per-unit log lines (device-authenticated).
    Body: {device_id, token, units: {unit_name: [line, line, ...], ...}}

    v1.8.2:
      - Empty lines[] arrays are now preserved so quiet devices still register
        as "reporting" on the Logs page (previously they vanished entirely)
      - Evaluates both device.log_watch (per-device) AND global rules from
        log_rules_global.json (fleet-wide). Wildcard unit='*' matches any unit.
      - Dedupes alerts by (scope, unit, pattern) so a line that matches a
        per-device rule AND a global rule fires only once.
    """
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})

    body = get_json_obj()
    dev_id    = str(body.get('device_id', '')).strip()
    dev_token = str(body.get('token', '')).strip()
    if not _validate_id(dev_id):
        respond(403, {'error': 'Unauthorized device'})

    devices = load(DEVICES_FILE)
    dev = devices.get(dev_id)
    if not dev or not _device_token_ok(dev, dev_token):
        respond(403, {'error': 'Unauthorized device'})

    units_in = body.get('units') or {}
    if not isinstance(units_in, dict):
        respond(400, {'error': 'units must be an object'})

    now = int(time.time())
    log_store = load(LOG_WATCH_FILE)
    dev_buf = log_store.get(dev_id) or {'units': {}, 'updated_at': now}
    units_buf = dev_buf.get('units') or {}

    alerts_fired = []
    per_device_rules = dev.get('log_watch') or []
    global_rules = (load(LOG_RULES_GLOBAL_FILE).get('rules') or [])

    # v2.8.1: virtual log units (apt.history, nginx.access, kernel, etc.)
    # are new sources added for brute-force detection and log history.
    # They should NOT fire on wildcard unit='*' global rules that users
    # set up for service journal logs — the patterns don't apply and
    # produce noise. Only fire if the rule explicitly names the unit.
    _VIRTUAL_UNITS = {'apt.history', 'nginx.access', 'apache2.access', 'kernel'}

    # Track which (unit, pattern) pairs have already fired this submission — a
    # line matching both a per-device and a global rule with the same pattern
    # should produce one alert, not two.
    fired_keys = set()

    # master-improvement-scoping #9: this used to load config + recompile
    # every ignore pattern INSIDE the per-unit loop below despite the old
    # comment claiming "once per submission" — a device reporting N units
    # recompiled the whole ignore-pattern list N times per heartbeat. Hoisted
    # out to genuinely run once per submission; _compiled_patterns_cached
    # additionally memoizes across calls (keyed by the pattern tuple, so a
    # config change is its own cache-invalidation — no explicit bust needed).
    _cfg_ignore = load(CONFIG_FILE) or {}
    _ignore_pats = tuple(_cfg_ignore.get('log_ignore_patterns') or [])
    _ignore_res = _compiled_patterns_cached(_ignore_pats, re.IGNORECASE)

    for unit_raw, lines in units_in.items():
        unit = _sanitize_unit_name(unit_raw)
        if not isinstance(unit, str) or unit is None:
            continue
        if not isinstance(lines, list):
            continue

        clean_lines = []
        # v3.0.1: build a signature set of lines already in the buffer for
        # this unit. New lines whose signature matches are skipped, fixing
        # the apt.history re-submission bloat.
        existing_lines = units_buf.get(unit) or []
        existing_sigs = {e.get('sig') for e in existing_lines if isinstance(e, dict) and e.get('sig')}

        for line in lines[:MAX_LOG_LINES_PER_UNIT]:
            # v2.9.1: dmesg/kernel entries are submitted as dicts —
            # extract the 'message' field rather than rendering as Python repr
            if isinstance(line, dict):
                s = str(line.get('message') or line.get('line') or '').strip()[:1024]
            else:
                s = str(line)[:1024]
            if not s:
                continue
            # Apply global ignore patterns — skip matching lines entirely
            if _ignore_res and any(r.search(s) for r in _ignore_res):
                continue
            # v3.0.1: skip lines we've already ingested (content dedupe)
            sig = _line_signature(s)
            if sig in existing_sigs:
                continue
            existing_sigs.add(sig)
            # v3.0.1: use the line's own timestamp if it has one. Lines from
            # apt.history etc. carry an absolute date — without this, every
            # re-submission stamped them with `now` so they always looked new.
            line_ts = _extract_log_timestamp(s, unit, now)
            clean_lines.append({'ts': line_ts, 'line': s, 'sig': sig})

        combined = existing_lines + clean_lines
        # Trim by age — embedded timestamps mean old lines now get evicted
        # naturally rather than perpetually re-stamped to `now`.
        cutoff = now - LOG_BUFFER_TTL
        combined = [e for e in combined if e.get('ts', 0) >= cutoff]
        # v3.0.1: byte cap removed — was silently dropping nginx.access and
        # brute-force lines whenever apt.history bloat filled the buffer.
        # With content dedupe + embedded timestamps + TTL the buffer no
        # longer grows unboundedly on idle units.
        # v1.8.2: always keep the unit key, even if empty — so the device
        # appears on the Logs page as "watched, quiet in this window"
        units_buf[unit] = combined

        # Evaluate per-device rules first, then global
        def _eval_rules(rules, scope):
            for rule in rules:
                rule_unit = rule.get('unit', '')
                # Wildcard '*' matches any unit; otherwise exact match.
                # v2.8.1: wildcard rules skip virtual units (apt.history,
                # nginx.access, kernel) — users configure those rules for
                # systemd service journals, not file-based log sources.
                if rule_unit == '*':
                    if unit in _VIRTUAL_UNITS:
                        continue
                elif rule_unit != unit:
                    continue
                pattern = rule.get('pattern', '')
                key = (scope, unit, pattern)
                if key in fired_keys:
                    continue
                try:
                    rx = re.compile(pattern)
                except re.error:
                    continue
                ex_pat = rule.get('exclude_pattern', '')
                ex_rx = None
                if ex_pat:
                    try:
                        ex_rx = re.compile(ex_pat)
                    except re.error:
                        pass
                matches = [e['line'] for e in clean_lines
                           if rx.search(e['line']) and (not ex_rx or not ex_rx.search(e['line']))]
                threshold = rule.get('threshold', 1)
                try:
                    threshold = int(threshold)
                except (TypeError, ValueError):
                    threshold = 1
                # v3.0.1: severity classification (OK/WARN/CRIT)
                severity = str(rule.get('severity', 'WARN')).upper()
                if severity not in ('OK', 'WARN', 'CRIT'):
                    severity = 'WARN'
                if len(matches) >= threshold:
                    fired_keys.add(key)
                    alerts_fired.append({
                        'unit': unit, 'pattern': pattern,
                        'count': len(matches), 'scope': scope,
                        'severity': severity,
                    })
                    # OK rules don't fire webhooks — they're noise suppressors
                    # that confirm "this expected pattern is still present".
                    if severity != 'OK':
                        wb_payload = {
                            'device_id': dev_id,
                            'name':      dev.get('name', dev_id),
                            'unit':      unit,
                            'pattern':   pattern,
                            'count':     len(matches),
                            'sample':    matches[:3],
                            'scope':     scope,  # v1.8.2: 'device' | 'global'
                            'severity':  severity,  # v3.0.1
                        }
                        # v3.2.3 (#3): pass the rule's display_template
                        # along so renderers downstream (NA card, alert
                        # title, webhook subject) can format the event
                        # the way the operator wrote.
                        tmpl = rule.get('display_template')
                        if tmpl:
                            wb_payload['display_template'] = tmpl
                        fire_webhook('log_alert', wb_payload)

        _eval_rules(per_device_rules, 'device')
        _eval_rules(global_rules,     'global')

        # v2.8.0: brute-force detection on SSH and web access units
        if unit in (_SSH_UNITS | _WEB_UNITS) and clean_lines:
            try:
                _detect_brute_force(dev_id, dev.get('name', dev_id),
                                    unit, clean_lines)
            except Exception:
                pass

    dev_buf['units'] = units_buf
    dev_buf['updated_at'] = now
    log_store[dev_id] = dev_buf
    save(LOG_WATCH_FILE, log_store)

    respond(200, {'ok': True, 'alerts_fired': len(alerts_fired)})


def handle_log_search():
    """
    GET /api/logs/search?q=<pattern>&device=<id>&limit=<n>
    Searches the rolling buffer across devices. No indexing — just grep.
    """
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', ''))
    q       = (qs.get('q', [''])[0])[:128]
    device  = (qs.get('device', [''])[0])[:64]
    limit   = min(int(qs.get('limit', ['200'])[0] or 200), 1000)

    if not q:
        respond(400, {'error': 'q parameter is required'})

    try:
        rx = re.compile(q, re.IGNORECASE)
    except re.error as e:
        respond(400, {'error': f'invalid regex: {e}'})

    log_store = load(LOG_WATCH_FILE)
    devices = load(DEVICES_FILE)
    results = []

    target_devs = [device] if device else list(log_store.keys())
    for dev_id in target_devs:
        if dev_id not in devices:
            continue
        buf = log_store.get(dev_id) or {}
        units = buf.get('units') or {}
        dev_name = devices[dev_id].get('name', dev_id)
        for unit, lines in units.items():
            for entry in lines:
                if rx.search(entry.get('line', '')):
                    results.append({
                        'device_id': dev_id,
                        'name':      dev_name,
                        'unit':      unit,
                        'ts':        entry.get('ts', 0),
                        'line':      entry.get('line', ''),
                    })
                    if len(results) >= limit:
                        break
            if len(results) >= limit:
                break
        if len(results) >= limit:
            break

    results.sort(key=lambda r: -r['ts'])
    respond(200, {'query': q, 'count': len(results), 'results': results})


def handle_log_device(dev_id):
    """GET /api/devices/{id}/logs — full captured buffer for one device."""
    require_auth()
    if not _validate_id(dev_id):
        respond(404, {'error': 'Device not found'})
    devices = load(DEVICES_FILE)
    if dev_id not in devices:
        respond(404, {'error': 'Device not found'})
    log_store = load(LOG_WATCH_FILE)
    buf = log_store.get(dev_id) or {'units': {}, 'updated_at': 0}
    respond(200, {
        'device_id':  dev_id,
        'name':       devices[dev_id].get('name', dev_id),
        'updated_at': buf.get('updated_at', 0),
        'units':      buf.get('units', {}),
    })


# ─── v1.8.1: Log alert rules aggregate + live tail ───────────────────────────

def handle_log_rules():
    """GET /api/logs/rules — cross-fleet view of all per-device log_watch rules."""
    require_auth()
    devices = _scope_filter_devices(load(DEVICES_FILE))   # v3.5.0 RBAC v2
    out = []
    for dev_id, dev in devices.items():
        for rule in (dev.get('log_watch') or []):
            out.append({
                'device_id': dev_id,
                'device_name': dev.get('name', dev_id),
                'group':     dev.get('group', ''),
                'unit':      rule.get('unit', ''),
                'pattern':   rule.get('pattern', ''),
                'threshold': rule.get('threshold', 1),
            })
    out.sort(key=lambda r: (r['device_name'].lower(), r['unit']))
    respond(200, {'rules': out})


# ─── v1.8.2: Fleet-wide log alert rules ───────────────────────────────────────

def _validate_global_rule(body):
    """Return (clean_rule, error) — same shape whether valid or not."""
    if not isinstance(body, dict): body = {}  # non-dict (e.g. JSON array) → empty, not a 500
    # v3.0.1: rule may specify either a systemd unit OR a file path. Path
    # form tells the agent to tail the file; the synthetic unit name
    # becomes 'file:<path>'. Mutually exclusive with `unit`.
    path_raw = (str(body.get('path') or '')).strip()
    file_path = None
    if path_raw:
        if (not path_raw.startswith('/')
                or '..' in path_raw
                or len(path_raw) > 512
                or any(c in path_raw for c in '*?[]<>\n\r\t')):
            return None, 'invalid file path (must be absolute, no globs/traversal)'
        file_path = path_raw
        unit = f'file:{path_raw}'
    else:
        unit = _sanitize_str(body.get('unit', ''), 128, allow_empty=False)
    pattern = _sanitize_str(body.get('pattern', ''), 128, allow_empty=False)
    # Don't use `or 1` for threshold — we want to reject 0 explicitly rather
    # than coerce it to 1 silently, so the user gets a clear error.
    raw_threshold = body.get('threshold', 1)
    if raw_threshold is None or raw_threshold == '':
        raw_threshold = 1
    try:
        threshold = int(raw_threshold)
    except (TypeError, ValueError):
        return None, 'threshold must be an integer'
    # v3.0.1: severity classification — OK/WARN/CRIT — default WARN
    severity = str(body.get('severity', 'WARN')).upper()
    if severity not in ('OK', 'WARN', 'CRIT'):
        return None, 'severity must be OK, WARN, or CRIT'

    if not unit:
        return None, 'unit or path is required (use "*" for any unit)'
    # Allow '*' OR a valid unit name OR a 'file:<path>' synthetic unit
    if not file_path and unit != '*' and not _sanitize_unit_name(unit):
        return None, 'invalid unit name'
    if not pattern:
        return None, 'pattern is required'
    if not (1 <= threshold <= 100):
        return None, 'threshold must be 1..100'
    try:
        re.compile(pattern)
    except re.error as e:
        return None, f'invalid regex: {e}'
    exclude_pattern = _sanitize_str(body.get('exclude_pattern', ''), 128, allow_empty=True)
    if exclude_pattern:
        try:
            re.compile(exclude_pattern)
        except re.error as e:
            return None, f'invalid exclude regex: {e}'
    # v3.2.3 (#3): optional per-rule display template — strict allowlist
    # of placeholders, validated at save.
    template_raw = body.get('display_template', '')
    template_clean, tmpl_err = _validate_log_template(
        _sanitize_str(str(template_raw or ''), 256, allow_empty=True))
    if tmpl_err:
        return None, tmpl_err
    clean = {'unit': unit, 'pattern': pattern,
             'threshold': threshold, 'severity': severity}
    if file_path:
        clean['path'] = file_path
    if exclude_pattern:
        clean['exclude_pattern'] = exclude_pattern
    if template_clean:
        clean['display_template'] = template_clean
    return clean, None


def handle_log_rules_global_list():
    """GET /api/logs/rules/global — list fleet-wide rules."""
    require_auth()
    rules = (load(LOG_RULES_GLOBAL_FILE).get('rules') or [])
    rules = sorted(rules, key=lambda r: (r.get('unit', ''), r.get('pattern', '')))
    respond(200, {'rules': rules})


def handle_log_rules_global_add():
    """POST /api/logs/rules/global — create a fleet-wide rule."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})

    body = get_json_body()
    rule, err = _validate_global_rule(body)
    if err:
        respond(400, {'error': err})

    store = load(LOG_RULES_GLOBAL_FILE)
    rules = store.get('rules') or []
    # Dedup by (unit, pattern) — same rule can't exist twice
    for existing in rules:
        if existing.get('unit') == rule['unit'] and existing.get('pattern') == rule['pattern']:
            respond(409, {'error': 'rule with this unit+pattern already exists'})
    if len(rules) >= MAX_GLOBAL_LOG_RULES:
        respond(400, {'error': f'max {MAX_GLOBAL_LOG_RULES} global rules'})

    rule['id']         = secrets.token_hex(8)
    rule['created_by'] = actor
    rule['created_at'] = int(time.time())
    rules.append(rule)
    store['rules'] = rules
    save(LOG_RULES_GLOBAL_FILE, store)
    audit_log(actor, 'log_rule_global_add',
              detail=f'id={rule["id"]} unit={rule["unit"]} pattern={rule["pattern"][:60]}')
    respond(200, {'ok': True, 'rule': rule})


def handle_log_rules_global_update(rule_id):
    """PUT /api/logs/rules/global/{id} — replace an existing fleet-wide rule.

    v3.3.0: counterpart to the existing POST/DELETE so the Settings UI
    can offer an Edit button on each row. Body is the same shape as
    POST; id stays the same, created_by/created_at preserved, every
    other field is overwritten by the validated payload.
    """
    actor = require_admin_auth()
    if method() != 'PUT':
        respond(405, {'error': 'Method not allowed'})
    rule_id = _sanitize_str(rule_id, 32, allow_empty=False)
    if not rule_id:
        respond(400, {'error': 'invalid id'})
    body = get_json_body()
    rule, err = _validate_global_rule(body)
    if err:
        respond(400, {'error': err})
    with _LockedUpdate(LOG_RULES_GLOBAL_FILE) as store:
        rules = store.get('rules') or []
        target = next((r for r in rules if r.get('id') == rule_id), None)
        if not target:
            respond(404, {'error': 'rule not found'})
        # Preserve identity + provenance; overwrite everything else.
        rule['id']         = rule_id
        rule['created_by'] = target.get('created_by', actor)
        rule['created_at'] = target.get('created_at', int(time.time()))
        rule['updated_by'] = actor
        rule['updated_at'] = int(time.time())
        store['rules'] = [r if r.get('id') != rule_id else rule for r in rules]
    audit_log(actor, 'log_rule_global_update',
              detail=f'id={rule_id} unit={rule["unit"]} pattern={rule["pattern"][:60]}')
    respond(200, {'ok': True, 'rule': rule})


def handle_log_rules_global_delete(rule_id):
    """DELETE /api/logs/rules/global/{id}"""
    actor = require_admin_auth()
    rule_id = _sanitize_str(rule_id, 32, allow_empty=False)
    if not rule_id:
        respond(400, {'error': 'invalid id'})

    store = load(LOG_RULES_GLOBAL_FILE)
    rules = store.get('rules') or []
    remaining = [r for r in rules if r.get('id') != rule_id]
    if len(remaining) == len(rules):
        respond(404, {'error': 'rule not found'})
    store['rules'] = remaining
    save(LOG_RULES_GLOBAL_FILE, store)
    audit_log(actor, 'log_rule_global_delete', detail=f'id={rule_id}')
    respond(200, {'ok': True})


def handle_log_tail():
    """
    GET /api/logs/tail?since=<ts>&device=<id>&unit=<name>&limit=<n>
    Returns the newest lines across the fleet since a given unix ts.
    Use-case: live tail page, polls with monotonically-increasing `since`.
    """
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', ''))
    try:
        since = int(qs.get('since', ['0'])[0] or 0)
    except ValueError:
        since = 0
    device = (qs.get('device', [''])[0])[:64]
    unit   = (qs.get('unit',   [''])[0])[:128]
    try:
        limit = min(int(qs.get('limit', ['500'])[0] or 500), 2000)
    except ValueError:
        limit = 500

    log_store = load(LOG_WATCH_FILE)
    devices   = load(DEVICES_FILE)
    out = []
    newest_ts = since
    devices_reporting = 0
    total_lines = 0

    target_devs = [device] if device else list(log_store.keys())
    for dev_id in target_devs:
        if dev_id not in devices:
            continue
        buf = log_store.get(dev_id) or {}
        units = buf.get('units') or {}
        dev_name = devices[dev_id].get('name', dev_id)
        had_lines = False
        for u, lines in units.items():
            if unit and u != unit:
                continue
            for entry in lines:
                ts = entry.get('ts', 0)
                total_lines += 1
                if ts > since:
                    out.append({
                        'device_id': dev_id,
                        'name':      dev_name,
                        'unit':      u,
                        'ts':        ts,
                        'line':      entry.get('line', ''),
                    })
                    if ts > newest_ts:
                        newest_ts = ts
                    had_lines = True
        if had_lines or units:
            devices_reporting += 1

    out.sort(key=lambda r: r['ts'])
    if len(out) > limit:
        out = out[-limit:]  # keep the newest

    # For stats, compute totals across the whole buffer, not just new lines
    respond(200, {
        'lines':             out,
        'newest_ts':         newest_ts,
        'stats': {
            'total_lines':        total_lines,
            'devices_reporting':  devices_reporting,
        },
    })


# ─── v1.8.3: Shared calendar events ──────────────────────────────────────────

# Palette used by the UI — cap allowed colors to prevent CSS injection via
# arbitrary strings. The UI picker should present these same values.
ALLOWED_EVENT_COLORS = (
    'blue', 'green', 'amber', 'red', 'purple', 'teal', 'slate',
)
ALLOWED_RECUR = ('none', 'daily', 'weekly', 'monthly', 'yearly')


def _sanitize_event(body):
    """Sanitize a calendar event submission. Returns (clean, error)."""
    if not isinstance(body, dict): body = {}  # non-dict (e.g. JSON array) → empty, not a 500
    title = _sanitize_str(body.get('title', ''), 120, allow_empty=False)
    if not title:
        return None, 'title is required'
    description = _sanitize_str(body.get('description', ''), 2000)
    start = _sanitize_str(body.get('start', ''), 32, allow_empty=False)
    end   = _sanitize_str(body.get('end', ''), 32)
    if not start:
        return None, 'start is required (ISO-8601)'
    try:
        start_ts = _parse_iso(start)
    except ValueError:
        return None, 'invalid start timestamp'
    end_ts = None
    if end:
        try:
            end_ts = _parse_iso(end)
        except ValueError:
            return None, 'invalid end timestamp'
        if end_ts < start_ts:
            return None, 'end must be >= start'
    all_day = bool(body.get('all_day', False))
    color = _sanitize_str(body.get('color', 'blue'), 16)
    if color not in ALLOWED_EVENT_COLORS:
        color = 'blue'
    recur = _sanitize_str(body.get('recur', 'none'), 10)
    if recur not in ALLOWED_RECUR:
        recur = 'none'
    return {
        'title':       title,
        'description': description,
        'start':       start,
        'end':         end or start,
        'all_day':     all_day,
        'color':       color,
        'recur':       recur,
    }, None


def _expand_event(ev, from_ts, to_ts):
    """Yield occurrence dicts for ev within the [from_ts, to_ts] window.
    Single (non-recurring) events are yielded as-is when they overlap.
    Recurring events are expanded up to 500 occurrences per query window.
    """
    recur = ev.get('recur', 'none') or 'none'
    try:
        base_start_ts = _parse_iso(ev['start'])
        base_end_ts   = _parse_iso(ev['end']) if ev.get('end') else base_start_ts
    except (ValueError, KeyError):
        return
    duration = base_end_ts - base_start_ts

    if recur == 'none':
        if base_end_ts >= from_ts and base_start_ts <= to_ts:
            yield ev
        return

    import datetime as _dt
    import calendar as _cal_mod
    cur = _dt.datetime.fromtimestamp(base_start_ts, tz=_dt.timezone.utc)
    anchor_day = cur.day   # v6.0.1: clamp off the ORIGINAL day, not the chained
                           # (already-clamped) one — a monthly-31st event was
                           # pinned to the 28th forever after passing February.
    count = 0
    while count < 500:
        occ_start = cur.timestamp()
        if occ_start > to_ts:
            break
        occ_end = occ_start + duration
        if occ_end >= from_ts:
            occ = dict(ev)
            occ['start']        = cur.isoformat()
            occ['end']          = _dt.datetime.fromtimestamp(occ_end, tz=_dt.timezone.utc).isoformat()
            occ['is_recurring'] = True
            yield occ
        count += 1
        if recur == 'daily':
            cur += _dt.timedelta(days=1)
        elif recur == 'weekly':
            cur += _dt.timedelta(weeks=1)
        elif recur == 'monthly':
            m = cur.month + 1; y = cur.year
            if m > 12: m = 1; y += 1
            # replace day=1 first so a 31->short-month step can't raise, then set
            # the clamped anchor day.
            day = min(anchor_day, _cal_mod.monthrange(y, m)[1])
            cur = cur.replace(year=y, month=m, day=1).replace(day=day)
        elif recur == 'yearly':
            y = cur.year + 1
            day = min(anchor_day, _cal_mod.monthrange(y, cur.month)[1])
            cur = cur.replace(year=y, day=1).replace(day=day)
        else:
            break


def handle_calendar_list():
    """GET /api/calendar — list all events, optionally filtered by date range."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', ''))
    from_ts = 0
    to_ts   = 10 ** 10  # far future
    try:
        if qs.get('from'):
            from_ts = _parse_iso(qs['from'][0])
        if qs.get('to'):
            to_ts = _parse_iso(qs['to'][0])
    except ValueError:
        respond(400, {'error': 'invalid from/to timestamp'})

    store = load(CALENDAR_FILE)
    events = store.get('events') or []
    out = []
    for ev in events:
        for occ in _expand_event(ev, from_ts, to_ts):
            out.append(occ)
    out.sort(key=lambda e: e.get('start', ''))
    respond(200, {'events': out})


def _ics_unescape(s):
    return (str(s or '').replace('\\n', '\n').replace('\\N', '\n')
            .replace('\\,', ',').replace('\\;', ';').replace('\\\\', '\\'))


def _ics_to_iso(val):
    """Convert an iCalendar DTSTART/DTEND value (20240115, 20240115T130000,
    or 20240115T130000Z) to an ISO-8601 string _parse_iso accepts."""
    import datetime as _dt
    val = (val or '').strip()
    try:
        if 'T' in val:
            z = val.endswith('Z')
            dt = _dt.datetime.strptime(val[:-1] if z else val, '%Y%m%dT%H%M%S')
            return (dt.replace(tzinfo=_dt.timezone.utc).isoformat() if z
                    else dt.isoformat())
        return _dt.datetime.strptime(val[:8], '%Y%m%d').isoformat()
    except ValueError:
        return val


def _parse_ics_events(text):
    """Minimal iCalendar VEVENT parser (line-unfolding + DTSTART/DTEND/SUMMARY/
    DESCRIPTION/RRULE FREQ). Returns event dicts shaped for _sanitize_event."""
    unfolded = []
    for ln in str(text or '').replace('\r\n', '\n').replace('\r', '\n').split('\n'):
        if ln[:1] in (' ', '\t') and unfolded:
            unfolded[-1] += ln[1:]
        else:
            unfolded.append(ln)
    _FREQ = {'DAILY': 'daily', 'WEEKLY': 'weekly', 'MONTHLY': 'monthly', 'YEARLY': 'yearly'}
    events, cur = [], None
    for ln in unfolded:
        if ln.strip() == 'BEGIN:VEVENT':
            cur = {}
        elif ln.strip() == 'END:VEVENT':
            if cur and cur.get('start') and cur.get('title'):
                events.append(cur)
            cur = None
        elif cur is not None and ':' in ln:
            key_part, _, val = ln.partition(':')
            key = key_part.split(';')[0].upper()
            date_only = 'VALUE=DATE' in key_part.upper() and 'DATE-TIME' not in key_part.upper()
            val = _ics_unescape(val)
            if key == 'SUMMARY':
                cur['title'] = val[:120]
            elif key == 'DESCRIPTION':
                cur['description'] = val[:2000]
            elif key == 'DTSTART':
                cur['start'] = _ics_to_iso(val)
                if date_only or ('T' not in val):
                    cur['all_day'] = True
            elif key == 'DTEND':
                cur['end'] = _ics_to_iso(val)
            elif key == 'RRULE':
                for tok in val.split(';'):
                    if tok.upper().startswith('FREQ='):
                        cur['recur'] = _FREQ.get(tok.split('=', 1)[1].upper(), 'none')
    return events


def handle_calendar_ics():
    """GET /api/calendar.ics — export calendar events as an iCalendar feed."""
    require_auth()
    events = (load(CALENDAR_FILE) or {}).get('events') or []
    import datetime as _dt
    _RRULE = {'daily': 'FREQ=DAILY', 'weekly': 'FREQ=WEEKLY',
              'monthly': 'FREQ=MONTHLY', 'yearly': 'FREQ=YEARLY'}
    lines = ['BEGIN:VCALENDAR', 'VERSION:2.0',
             'PRODID:-//RemotePower//Calendar//EN', 'CALSCALE:GREGORIAN',
             f'X-WR-CALNAME:{_ics_escape(get_server_name())}']
    for ev in events:
        try:
            start_ts = _parse_iso(ev['start'])
            end_ts = _parse_iso(ev['end']) if ev.get('end') else start_ts
        except (ValueError, KeyError):
            continue
        lines += ['BEGIN:VEVENT',
                  f'UID:{ev.get("id", secrets.token_hex(8))}@remotepower',
                  f'DTSTAMP:{_ics_dt(ev.get("created_at") or start_ts)}']
        if ev.get('all_day'):
            lines += [f'DTSTART;VALUE=DATE:{_dt.datetime.fromtimestamp(start_ts, _dt.timezone.utc).strftime("%Y%m%d")}',
                      f'DTEND;VALUE=DATE:{_dt.datetime.fromtimestamp(end_ts, _dt.timezone.utc).strftime("%Y%m%d")}']
        else:
            lines += [f'DTSTART:{_ics_dt(start_ts)}', f'DTEND:{_ics_dt(end_ts)}']
        lines.append(f'SUMMARY:{_ics_escape(ev.get("title", ""))}')
        if ev.get('description'):
            lines.append(f'DESCRIPTION:{_ics_escape(ev["description"])}')
        rr = _RRULE.get(ev.get('recur'))
        if rr:
            lines.append(f'RRULE:{rr}')
        lines.append('END:VEVENT')
    lines.append('END:VCALENDAR')
    body = ('\r\n'.join(lines) + '\r\n').encode('utf-8')
    print("Status: 200 OK"); print("Content-Type: text/calendar; charset=utf-8")
    print("Content-Disposition: attachment; filename=remotepower-calendar.ics")
    print(f"Content-Length: {len(body)}"); print("Cache-Control: no-store"); print()
    sys.stdout.flush(); sys.stdout.buffer.write(body); sys.stdout.buffer.flush()
    sys.exit(0)


def handle_calendar_import():
    """POST /api/calendar/import — import VEVENTs from an iCalendar (.ics) body
    (raw text/calendar, or JSON {"ics": "..."}). Admin-only."""
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    raw = get_body()
    text = raw.decode('utf-8', 'replace') if raw else ''
    if text.lstrip().startswith('{'):
        try:
            text = (json.loads(text) or {}).get('ics', '') or ''
        except ValueError:
            pass
    if 'BEGIN:VEVENT' not in text:
        respond(400, {'error': 'no VEVENT found — is this a .ics file?'})
    store = load(CALENDAR_FILE)
    events = store.get('events') or []
    added = skipped = 0
    for ev in _parse_ics_events(text):
        if len(events) >= MAX_CALENDAR_EVENTS:
            break
        clean, err = _sanitize_event(ev)
        if err:
            skipped += 1
            continue
        clean['id'] = secrets.token_hex(8)
        clean['created_by'] = actor
        clean['created_at'] = int(time.time())
        events.append(clean)
        added += 1
    store['events'] = events
    save(CALENDAR_FILE, store)
    audit_log(actor, 'calendar_import', detail=f'{added} added, {skipped} skipped')
    respond(200, {'ok': True, 'imported': added, 'skipped': skipped})


def handle_calendar_add():
    """POST /api/calendar — create a new event."""
    actor = require_write_role('manage calendar events')
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_body()
    clean, err = _sanitize_event(body)
    if err:
        respond(400, {'error': err})

    store = load(CALENDAR_FILE)
    events = store.get('events') or []
    if len(events) >= MAX_CALENDAR_EVENTS:
        respond(400, {'error': f'max {MAX_CALENDAR_EVENTS} events'})
    clean['id']         = secrets.token_hex(8)
    clean['created_by'] = actor
    clean['created_at'] = int(time.time())
    events.append(clean)
    store['events'] = events
    save(CALENDAR_FILE, store)
    audit_log(actor, 'calendar_add', detail=f'id={clean["id"]} title={clean["title"][:60]}')
    respond(200, {'ok': True, 'event': clean})


def handle_calendar_update(event_id):
    """PUT /api/calendar/{id} — edit an existing event."""
    actor = require_write_role('manage calendar events')
    event_id = _sanitize_str(event_id, 32, allow_empty=False)
    if not event_id:
        respond(400, {'error': 'invalid id'})

    store = load(CALENDAR_FILE)
    events = store.get('events') or []
    idx = next((i for i, e in enumerate(events) if e.get('id') == event_id), -1)
    if idx < 0:
        respond(404, {'error': 'event not found'})

    body = get_json_body()
    clean, err = _sanitize_event(body)
    if err:
        respond(400, {'error': err})
    # Preserve id + created_by/at, merge in the new fields
    clean['id']         = event_id
    clean['created_by'] = events[idx].get('created_by', '')
    clean['created_at'] = events[idx].get('created_at', 0)
    clean['updated_by'] = actor
    clean['updated_at'] = int(time.time())
    events[idx] = clean
    store['events'] = events
    save(CALENDAR_FILE, store)
    audit_log(actor, 'calendar_update', detail=f'id={event_id}')
    respond(200, {'ok': True, 'event': clean})


def handle_calendar_delete(event_id):
    """DELETE /api/calendar/{id}"""
    actor = require_write_role('manage calendar events')
    event_id = _sanitize_str(event_id, 32, allow_empty=False)
    if not event_id:
        respond(400, {'error': 'invalid id'})

    store = load(CALENDAR_FILE)
    events = store.get('events') or []
    remaining = [e for e in events if e.get('id') != event_id]
    if len(remaining) == len(events):
        respond(404, {'error': 'event not found'})
    store['events'] = remaining
    save(CALENDAR_FILE, store)
    audit_log(actor, 'calendar_delete', detail=f'id={event_id}')
    respond(200, {'ok': True})


# ─── v1.8.3: Shared tasks board ───────────────────────────────────────────────

def _sanitize_task(body, require_all=True):
    """Sanitize a task submission. Returns (clean, error).
    If require_all=False, allows partial updates (used by /state endpoint)."""
    if not isinstance(body, dict): body = {}  # non-dict (e.g. JSON array) → empty, not a 500
    title = _sanitize_str(body.get('title', ''), 200, allow_empty=not require_all)
    if require_all and not title:
        return None, 'title is required'
    description = _sanitize_str(body.get('description', ''), 4000)
    state = _sanitize_str(body.get('state', 'upcoming'), 16)
    if state and state not in TASK_STATES:
        return None, f'state must be one of {", ".join(TASK_STATES)}'
    # Device linking is optional. Empty string = no device; otherwise must be valid.
    device_id = _sanitize_str(body.get('device_id', ''), 64)
    if device_id:
        if not _validate_id(device_id):
            return None, 'invalid device_id'
        devices = load(DEVICES_FILE)
        if device_id not in devices:
            return None, 'device_id not found'
    out = {}
    if title:
        out['title'] = title
    if 'description' in body:
        out['description'] = description
    if state:
        out['state'] = state
    if 'device_id' in body:
        out['device_id'] = device_id  # '' means explicit unlink
    return out, None


def handle_tasks_list():
    """GET /api/tasks — all tasks with optional state / device filter."""
    require_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', ''))
    state_filter  = (qs.get('state',  [''])[0])[:16]
    device_filter = (qs.get('device', [''])[0])[:64]

    store = load(TASKS_FILE)
    tasks = store.get('tasks') or []

    if state_filter and state_filter in TASK_STATES:
        tasks = [t for t in tasks if t.get('state') == state_filter]
    if device_filter:
        tasks = [t for t in tasks if t.get('device_id') == device_filter]

    # Enrich with device names for display (skip lookup if no tasks have devices)
    if any(t.get('device_id') for t in tasks):
        devices = load(DEVICES_FILE)
        for t in tasks:
            did = t.get('device_id')
            if did and did in devices:
                t['_device_name'] = devices[did].get('name', did)

    # Sort: newest first within each state, so kanban columns are fresh at top
    tasks.sort(key=lambda t: -t.get('updated_at', t.get('created_at', 0)))

    counts = {s: 0 for s in TASK_STATES}
    for t in tasks:
        s = t.get('state', 'upcoming')
        if s in counts:
            counts[s] += 1
    respond(200, {'tasks': tasks, 'counts': counts})


def handle_tasks_add():
    """POST /api/tasks — create."""
    actor = require_write_role('manage tasks')
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_body()
    clean, err = _sanitize_task(body, require_all=True)
    if err:
        respond(400, {'error': err})

    store = load(TASKS_FILE)
    tasks = store.get('tasks') or []
    if len(tasks) >= MAX_TASKS:
        respond(400, {'error': f'max {MAX_TASKS} tasks — close some first'})

    now = int(time.time())
    task = {
        'id':          secrets.token_hex(8),
        'title':       clean['title'],
        'description': clean.get('description', ''),
        'state':       clean.get('state', 'upcoming'),
        'device_id':   clean.get('device_id', ''),
        'created_by':  actor,
        'created_at':  now,
        'updated_at':  now,
    }
    tasks.append(task)
    store['tasks'] = tasks
    save(TASKS_FILE, store)
    audit_log(actor, 'task_add', detail=f'id={task["id"]} title={task["title"][:60]}')
    respond(200, {'ok': True, 'task': task})


def handle_tasks_update(task_id):
    """PUT /api/tasks/{id} — edit title/description/state/device."""
    actor = require_write_role('manage tasks')
    task_id = _sanitize_str(task_id, 32, allow_empty=False)
    if not task_id:
        respond(400, {'error': 'invalid id'})

    store = load(TASKS_FILE)
    tasks = store.get('tasks') or []
    idx = next((i for i, t in enumerate(tasks) if t.get('id') == task_id), -1)
    if idx < 0:
        respond(404, {'error': 'task not found'})

    body = get_json_body()
    clean, err = _sanitize_task(body, require_all=False)
    if err:
        respond(400, {'error': err})

    for k in ('title', 'description', 'state', 'device_id'):
        if k in clean:
            tasks[idx][k] = clean[k]
    tasks[idx]['updated_at'] = int(time.time())
    tasks[idx]['updated_by'] = actor
    store['tasks'] = tasks
    save(TASKS_FILE, store)
    audit_log(actor, 'task_update',
              detail=f'id={task_id} fields={",".join(sorted(clean.keys()))}')
    respond(200, {'ok': True, 'task': tasks[idx]})


def handle_tasks_delete(task_id):
    """DELETE /api/tasks/{id}"""
    actor = require_write_role('manage tasks')
    task_id = _sanitize_str(task_id, 32, allow_empty=False)
    if not task_id:
        respond(400, {'error': 'invalid id'})

    store = load(TASKS_FILE)
    tasks = store.get('tasks') or []
    remaining = [t for t in tasks if t.get('id') != task_id]
    if len(remaining) == len(tasks):
        respond(404, {'error': 'task not found'})
    store['tasks'] = remaining
    save(TASKS_FILE, store)
    audit_log(actor, 'task_delete', detail=f'id={task_id}')
    respond(200, {'ok': True})


