def _dispatch(pi, m):
    """Route (method, path) to its handler: the _EXACT_ROUTES table first,
    then the ordered _PATTERN_ROUTE_DEFS pattern table (data rows + bespoke
    code rows) — behaviour-identical to the ~300-branch elif chain it
    replaced (differential-proven over a 13k-probe corpus; guardrails in
    tests/test_router_table.py + tests/test_route_pattern_table.py)."""
    global _EXACT_ROUTES, _PATTERN_ROUTES
    if _EXACT_ROUTES is None:
        _EXACT_ROUTES = _build_exact_routes()
    _h = _EXACT_ROUTES.get((m, pi)) or _EXACT_ROUTES.get((None, pi))
    if _h is not None:
        _h(); return
    if _PATTERN_ROUTES is None:
        _PATTERN_ROUTES = _build_pattern_routes()
    for kind, methods, a, b, fn in _PATTERN_ROUTES:
        if kind == 'eq':
            if pi == a and (methods is None or m in methods):
                fn(); return
        elif kind == 'pat':
            if (methods is None or m in methods) and pi.startswith(a) \
                    and (not b or pi.endswith(b)):
                fn(pi[len(a):-len(b)] if b else pi[len(a):]); return
        elif fn(pi, m):    # 'code'
            return
    respond(404, {'error': 'Not found'})
def main():
    # v5.4.1 (keystone Stage A): reset per-request process-local state at the very
    # start. No-op under CGI (fresh process); the boundary a persistent app server
    # (Phase 5) will rely on so request B never sees request A's load()-cache /
    # correlation id. Cadence timers below are intentionally preserved.
    _begin_request()
    # v2.1.1: these per-request maintenance sweeps used to be wrapped in
    # bare `except Exception: pass` blocks. That silently swallowed every
    # error — including the ones an operator most needs to see: "why
    # didn't the offline webhook fire?" / "why isn't the schedule
    # running?". Now each one logs the exception traceback to stderr so
    # it lands in nginx's error log, but still doesn't propagate (the
    # CGI response itself must complete regardless of a maintenance
    # task failing).
    # v5.5.0 (keystone Stage D): when an out-of-band scheduler process owns the
    # maintenance cadence, the request path stops piggy-backing it. _safe wraps
    # EXCLUSIVELY the run_*_if_due sweeps below (request-critical calls like
    # _record_satellite/_enforce_* are invoked directly), so one early-return here
    # cleanly disables the whole request-piggyback cadence. Default OFF.
    _ext_sched = _external_scheduler_active()

    def _safe(fn, label, *args):
        if _ext_sched:
            return
        try:
            fn(*args)
        except Exception as exc:
            sys.stderr.write(
                f"[remotepower] {label} failed: {exc.__class__.__name__}: {exc}\n")
            traceback.print_exc(file=sys.stderr)
    # v3.3.0 flap-fix: peek at the request body if this is a heartbeat,
    # so check_offline_webhooks can exempt the device that's actively
    # proving it's alive. _peek_heartbeat_dev_id() reads the body
    # cached so the actual handler doesn't have to re-read.
    _hb_skip = _peek_heartbeat_dev_id()
    _safe(check_offline_webhooks, 'check_offline_webhooks', _hb_skip)
    # v1.11.4: container-data-stale sweep, mirroring the offline check.
    # Cheap (one CONTAINERS_FILE read + per-device timestamp compare).
    _safe(check_container_webhooks, 'check_container_webhooks')
    # v1.11.8: monitor checks used to only run when somebody opened
    # the Monitor page in the dashboard. Now they run on every CGI hit
    # but gated to the configured interval (default 300s). For low-
    # traffic servers this means monitors run whenever an agent
    # heartbeats — typically every 60s, so the gate kicks in and the
    # actual checks happen every interval.
    _safe(run_monitors_if_due, 'run_monitors_if_due')
    _safe(run_integrations_if_due, 'run_integrations_if_due')
    _safe(run_vpn_stats_if_due, 'run_vpn_stats_if_due')   # v5.2.0 WG Access
    # v4.8.0: poll the DMARC RUA mailbox over IMAP when due (no-op unless enabled).
    _safe(run_dmarc_imap_if_due, 'run_dmarc_imap_if_due')
    _safe(run_ticket_imap_if_due, 'run_ticket_imap_if_due')
    _safe(run_ticket_sla_if_due, 'run_ticket_sla_if_due')   # v5.3.0 SLA breach sweep
    _safe(run_ticket_schedules_if_due, 'run_ticket_schedules_if_due')  # W1-27 recurring
    _safe(run_invoice_reminders_if_due, 'run_invoice_reminders_if_due')  # W1-30 overdue reminders
    _safe(run_patch_sla_if_due, 'run_patch_sla_if_due')                  # W1-33 patch-compliance SLA
    _safe(run_webhook_digests_if_due, 'run_webhook_digests_if_due')      # W2-22 notification digest flush
    _safe(run_cve_campaign_sample_if_due, 'run_cve_campaign_sample_if_due')  # W2-35 campaign burn-down
    # v4.8.0: periodic IP-reputation (DNSBL) re-scan.
    _safe(run_reputation_scan_if_due, 'run_reputation_scan_if_due')
    # v4.9.0: periodic resolver-health re-check (latency / NXDOMAIN / failures).
    _safe(run_resolver_health_if_due, 'run_resolver_health_if_due')
    # v5.8.0: periodic TLS/DANE expiry re-probe (was cron-only — see the sweep).
    _safe(run_tls_scan_if_due, 'run_tls_scan_if_due')
    # W1-17: certificate-transparency watch (crt.sh, off unless domains set).
    _safe(run_ct_watch_if_due, 'run_ct_watch_if_due')
    # W4-16: mail SMTP→IMAP round-trip monitor (off unless mailflow.enabled).
    _safe(run_mailflow_if_due, 'run_mailflow_if_due')
    # v3.2.0 (B5): periodic SNMP polls for agentless devices. Same cheap-
    # when-not-due pattern as run_monitors_if_due; the work itself is
    # bounded (one UDP round trip per SNMP-enabled device, 2s timeout).
    _safe(run_snmp_polls_if_due, 'run_snmp_polls_if_due')
    # v3.3.4: ICMP reachability for agentless devices (icmp mode). Cheap-
    # when-not-due; check_offline_webhooks skips agentless so this owns
    # their up/down + offline/online alerts.
    _safe(run_agentless_reachability_if_due, 'run_agentless_reachability_if_due')
    # v3.3.4: refresh RouterOS firmware-update state for the Patches page.
    _safe(run_routeros_update_check_if_due, 'run_routeros_update_check_if_due')
    # v3.3.4: refresh registry digests for container image-update detection.
    # Cheap-when-not-due (12h sweep), bounded per run, deduped across fleet.
    _safe(run_image_scan_if_due, 'run_image_scan_if_due')
    # v3.14.0: daily refresh of CISA KEV + FIRST EPSS for CVE prioritization.
    _safe(refresh_kev_epss_if_due, 'refresh_kev_epss_if_due')
    # v3.14.0: predictive disk-failure alerting (edge-triggered, ~6h cadence).
    _safe(_maybe_check_disk_predictions, '_maybe_check_disk_predictions')
    # v3.14.0: push Prometheus metrics to a Pushgateway on its interval.
    _safe(_maybe_push_metrics, '_maybe_push_metrics')
    # W4-10: fold raw metric samples into hourly/daily roll-ups (hourly cadence).
    _safe(run_metric_rollup_if_due, 'run_metric_rollup_if_due')
    # W5-6: re-materialize smart-group membership (~60s cadence).
    _safe(run_smart_groups_if_due, 'run_smart_groups_if_due')
    # W5-2: detect duplicate IPs within defined subnets (edge-triggered).
    _safe(run_ipam_conflicts_if_due, 'run_ipam_conflicts_if_due')
    # W6-44: scheduled cloud inventory re-sync (opt-in; slow cadence).
    _safe(run_cloud_sync_if_due, 'run_cloud_sync_if_due')
    # W6-4: warranty auto-lookup → CMDB expiry (opt-in; cached per serial).
    _safe(run_warranty_lookup_if_due, 'run_warranty_lookup_if_due')
    _safe(_maybe_gitops_sync, '_maybe_gitops_sync')   # v3.14.0 (#27)
    _safe(process_schedule,    'process_schedule')
    # v3.6.0: cron-driven backup jobs + auto-patch policies
    _safe(process_backup_jobs, 'process_backup_jobs')
    _safe(process_autopatch,   'process_autopatch')
    # v3.4.1: send the scheduled fleet posture report when its cron is due.
    _safe(_maybe_send_scheduled_report, '_maybe_send_scheduled_report')
    # v3.14.0: custom report definitions, each on its own cron.
    _safe(_maybe_send_report_definitions, '_maybe_send_report_definitions')
    # v3.4.1: sample the fleet health score (once per UTC day) + fire
    # health_degraded / health_recovered alerts on threshold crossings.
    _safe(_maybe_sample_health, '_maybe_sample_health')
    _safe(_check_health_webhooks, '_check_health_webhooks')
    # v3.4.2: sample fleet compliance % (once per UTC day) for the trend chart,
    # and advance any running staged rollouts (cheap-when-none-running).
    _safe(_maybe_sample_compliance, '_maybe_sample_compliance')
    _safe(_rollout_tick_if_due, '_rollout_tick_if_due')
    # v3.4.2: re-notify unacknowledged alerts that have aged past a tier.
    _safe(_escalation_tick_if_due, '_escalation_tick_if_due')
    # v3.3.0: ping Healthchecks.io (or compatible) when configured.
    # External watchdog over the server itself — if RemotePower stops
    # serving requests, hc.io flips to red and pages someone.
    _safe(ping_healthchecks_if_due, 'ping_healthchecks_if_due')
    _safe(_run_posture_digest_if_due, '_run_posture_digest_if_due')
    # v3.12.0: SQLite WAL checkpoint (hourly) + weekly VACUUM/integrity_check.
    # No-op under the default JSON backend.
    _safe(_sqlite_maintenance_if_due, '_sqlite_maintenance_if_due')
    # v3.12.0: daily age-based purge for logs with a configured retention.
    _safe(_retention_sweep_if_due, '_retention_sweep_if_due')
    # v5.4.1 (G3): record an hourly control-plane "served a request" bucket.
    # Cheap (mtime-gated; writes at most once/hour) — feeds observed-availability.
    _safe(_record_self_alive, '_record_self_alive')

    # v2.0: gate mutations in read-only / demo mode. Cheap: one env var
    # read + a constant set membership check. Done before route dispatch
    # so every mutation handler is uniformly protected without needing
    # an assert_writable() call at the top of each one.
    # v3.12.0: if this request was relayed by a satellite, authenticate the
    # satellite (reject an unknown token) and stamp its last_seen. No-op for
    # direct agent/browser requests. NOT wrapped in _safe — an invalid-token
    # rejection (respond 401) must propagate, not be swallowed.
    _record_satellite()

    _enforce_read_only()

    # v3.0.2: CSRF defense-in-depth. The X-Token header is already
    # CSRF-safe because browsers require a CORS preflight for any
    # cross-origin request carrying a custom header, and we serve no
    # permissive Access-Control-Allow-Origin. This adds a same-origin
    # check on state-changing requests as belt-and-suspenders against
    # future regressions (e.g. an operator turning on permissive CORS
    # for an integration). API-key clients (CLI scripts, external
    # automation) typically send no Origin at all — those are
    # permitted; the check only rejects when an Origin/Referer IS sent
    # and points elsewhere.
    _enforce_same_origin()

    # v3.3.0: optional IP allowlist. Off by default; when on, blocks
    # all UI/API access except agent paths and loopback. The save path
    # for this config rejects edits that would lock the configurer out.
    _enforce_ip_allowlist()

    # v3.0.3: F2 — hard backstop for default-password admin accounts.
    # The warning banner from 2.3.2 nags but doesn't *force* anything;
    # an operator on the default password can ignore it and use the
    # full app. This interceptor blocks every endpoint except the
    # password-change route (and the bare server-info endpoint the
    # login page reads) until must_change_password is cleared.
    _enforce_password_change()
    _enforce_mfa_enrollment()   # v4.2.0 (A3)

    # v3.5.0 RBAC v2: block scoped roles from any out-of-scope /api/devices/<id>
    # request (read or write) at a single chokepoint, before route dispatch.
    _enforce_device_scope()

    pi = path_info(); m = method()

    # v4.3.0: time the handler and record it if it ran past the slow threshold.
    # try/finally so the timing fires on every exit path (normal HTTPError
    # short-circuit, real exception, or plain return) without altering control
    # flow — the HTTPError still propagates to the __main__ renderer. The
    # heartbeat path is excluded: it's high-frequency and would dominate the
    # ring without telling us anything actionable.
    _t0 = time.monotonic()
    try:
        _dispatch(pi, m)
    finally:
        try:
            _elapsed_ms = (time.monotonic() - _t0) * 1000.0
            if pi != '/api/heartbeat' and _elapsed_ms >= _slow_handler_threshold_ms():
                _record_slow_handler(pi, m, _elapsed_ms)
        except Exception:
            pass



# ─── v2.6.0: Host Configuration Management ───────────────────────────────────


def _validate_host_config_section(section, val):
    """Validate and sanitize a single host config section value.
    Returns the sanitized value or raises HTTPError on bad input."""
    if section in HOST_CONFIG_TEXT_SECTIONS:
        if not isinstance(val, str):
            respond(400, {'error': f'{section} must be a string'})
        if len(val.encode('utf-8', errors='replace')) > MAX_HOST_CONFIG_SECTION_SIZE:
            respond(400, {'error': f'{section} exceeds 64 KB limit'})
        if '\x00' in val:
            respond(400, {'error': f'{section} contains NUL bytes'})
        return val
    elif section == 'services':
        if not isinstance(val, list):
            respond(400, {'error': 'services must be a list of strings'})
        return [_sanitize_str(str(s), 128) for s in val[:200] if str(s).strip()]
    elif section == 'users':
        if not isinstance(val, list):
            respond(400, {'error': 'users must be a list'})
        out = []
        for u in val[:100]:
            if not isinstance(u, dict):
                continue
            name = _sanitize_str(u.get('name', ''), 64).strip()
            if not name:
                continue
            out.append({
                'name':            name,
                'shell':           _sanitize_str(u.get('shell', '/bin/bash'), 128),
                'groups':          [_sanitize_str(g, 64) for g in
                                    (u.get('groups') or [])[:30]],
                'authorized_keys': _sanitize_str(u.get('authorized_keys', ''), 16384),
            })
        return out
    elif section == 'groups':
        if not isinstance(val, list):
            respond(400, {'error': 'groups must be a list'})
        out = []
        for g in val[:100]:
            if not isinstance(g, dict):
                continue
            name = _sanitize_str(g.get('name', ''), 64).strip()
            if not name:
                continue
            gid = g.get('gid')
            out.append({
                'name': name,
                'gid':  int(gid) if isinstance(gid, int) and 0 < gid < 65536 else None,
            })
        return out
    respond(400, {'error': f'Unknown section: {section}'})


def _audit_host_config_drift(desired, current):
    """Compare desired vs current host config. Return list of sections with drift."""
    drifting = []
    for section in HOST_CONFIG_ALL_SECTIONS:
        if section not in desired:
            continue
        if section not in current:
            drifting.append(section)
            continue
        d = desired[section]
        c = current[section]
        if section in HOST_CONFIG_TEXT_SECTIONS:
            # Normalize line endings and trailing whitespace
            if d.strip().replace('\r\n', '\n') != c.strip().replace('\r\n', '\n'):
                drifting.append(section)
        elif section == 'services':
            # All desired services must be present in current enabled list
            d_set = set(d) if isinstance(d, list) else set()
            c_set = set(c) if isinstance(c, list) else set()
            if not d_set.issubset(c_set):
                drifting.append(section)
        elif section == 'users':
            c_map = {u['name']: u for u in (c or []) if isinstance(u, dict)}
            for u in (d or []):
                name = u.get('name')
                if name not in c_map:
                    drifting.append(section)
                    break
                cu = c_map[name]
                if u.get('shell') and u['shell'] != cu.get('shell'):
                    drifting.append(section)
                    break
                d_keys = u.get('authorized_keys', '').strip()
                c_keys = cu.get('authorized_keys', '').strip()
                if d_keys and d_keys != c_keys:
                    drifting.append(section)
                    break
                d_grps = set(u.get('groups') or [])
                c_grps = set(cu.get('groups') or [])
                if not d_grps.issubset(c_grps):
                    drifting.append(section)
                    break
        elif section == 'groups':
            c_names = {g['name'] for g in (c or []) if isinstance(g, dict)}
            for g in (d or []):
                if g.get('name') not in c_names:
                    drifting.append(section)
                    break
    return drifting


def _ingest_host_config_current(dev_id, dev_name, current):
    """Store current host config state reported by agent; run drift audit.

    Current state is written to DATA_DIR/host_config_current/<dev_id>.json
    rather than inside devices.json — it can be several hundred KB of file
    contents (repos, netplan, authorized_keys…) and would bloat devices.json,
    slowing every API call that reads it.
    """
    if not isinstance(current, dict):
        return
    now = int(time.time())

    # Persist current state to its own small file
    HOST_CONFIG_CURRENT_DIR.mkdir(exist_ok=True)
    current_path = HOST_CONFIG_CURRENT_DIR / f'{dev_id}.json'
    payload      = {'current': current, 'collected_at': now}
    save(current_path, payload)

    # Read desired config from devices.json and run drift audit
    with _locked_update(DEVICES_FILE) as devices:
        if dev_id not in devices:
            return
        hc      = devices[dev_id].setdefault('host_config', {})
        desired = hc.get('desired', {})
        if not desired:
            return
        drifting  = _audit_host_config_drift(desired, current)
        was_clean = not hc.get('drift', {}).get('sections')
        hc['drift'] = {
            'sections':   drifting,
            'checked_at': now,
            'clean':      not drifting,
        }
        # Store only the drift summary — NOT the full current state
        hc['current_collected_at'] = now

    # Edge-triggered: fire webhook only on first drift detection
    if drifting and was_clean:
        fire_webhook('config_drift', {
            'device_id': dev_id,
            'name':      dev_name,
            'sections':  drifting,
        })


def handle_device_host_config_get(dev_id):
    """GET /api/devices/:id/host-config — desired config + current state + drift."""
    require_auth()
    with _locked_update(DEVICES_FILE) as devices:
        if dev_id not in devices:
            respond(404, {'error': 'Device not found'})
        hc = devices[dev_id].get('host_config', {})
    # Current state lives in a separate per-device file — keeps devices.json small
    current_path = HOST_CONFIG_CURRENT_DIR / f'{dev_id}.json'
    current_data = {}
    collected_at = hc.get('current_collected_at')
    if backend_exists(current_path):
        try:
            raw = load(current_path) or {}
            current_data = raw.get('current', {})
            collected_at = raw.get('collected_at', collected_at)
        except Exception:
            pass
    respond(200, {
        'desired':              hc.get('desired', {}),
        'current':              current_data,
        'current_collected_at': collected_at,
        'drift':                hc.get('drift', {}),
        'desired_at':           hc.get('desired_at'),
        'apply_enabled':        bool(hc.get('apply_enabled', False)),
        'enforce':              bool(hc.get('enforce', False)),   # v3.7.0
    })


def handle_device_host_config_put(dev_id):
    """PUT /api/devices/:id/host-config — save desired host configuration."""
    actor = require_admin_auth()
    body = get_json_obj()
    if not isinstance(body, dict):
        respond(400, {'error': 'Expected JSON object'})

    desired = {}
    for section in HOST_CONFIG_ALL_SECTIONS:
        if section in body:
            desired[section] = _validate_host_config_section(section, body[section])

    # v3.4.0: optional per-device opt-in to ENFORCE (apply) the config — see
    # the heartbeat push gate. Updated only when the key is present.
    apply_enabled = body.get('apply_enabled')
    # v3.7.0: corrective enforcement — re-apply desired only when drift appears
    # (lighter than apply_enabled's every-heartbeat push). Updated only if sent.
    enforce_on_drift = body.get('enforce')

    with _locked_update(DEVICES_FILE) as devices:
        if dev_id not in devices:
            respond(404, {'error': 'Device not found'})
        hc = devices[dev_id].setdefault('host_config', {})
        hc['desired']    = desired
        hc['desired_at'] = int(time.time())
        if apply_enabled is not None:
            hc['apply_enabled'] = bool(apply_enabled)
        if enforce_on_drift is not None:
            hc['enforce'] = bool(enforce_on_drift)
        # Clear drift so it re-evaluates on next agent report
        hc.pop('drift', None)
        applied = bool(hc.get('apply_enabled'))
        enforced = bool(hc.get('enforce'))

    audit_log(actor, 'host_config_update',
              f'dev_id={dev_id} sections={list(desired.keys())} apply_enabled={applied} enforce={enforced}')
    respond(200, {'ok': True, 'apply_enabled': applied, 'enforce': enforced})


