def _acme_credential_env_prefix(provider: str) -> str:
    """Return the `export X=... Y=...` prefix for a given provider, or
    empty string if no credentials are stored. The prefix is injected
    into the queued acme.sh command so the agent sees the secrets in
    the spawned shell only — not as persistent env. Values are
    single-quoted; embedded single quotes are escaped.

    v3.3.0: lets RemotePower centrally manage DNS-01 credentials
    instead of asking the operator to edit ~/.acme.sh/account.conf
    on every device.
    """
    if provider not in ACME_DNS_CREDENTIAL_FIELDS:
        return ''
    cfg = load(CONFIG_FILE) or {}
    creds = (cfg.get('acme_dns_credentials') or {}).get(provider) or {}
    parts = []
    for field in ACME_DNS_CREDENTIAL_FIELDS[provider]:
        name = field['name']
        val = creds.get(name)
        if not val:
            continue
        # Single-quote and escape any embedded quotes
        escaped = str(val).replace("'", "'\"'\"'")
        parts.append(f"{name}='{escaped}'")
    if not parts:
        return ''
    return 'export ' + ' '.join(parts) + ' && '


def _scrub_acme_credentials(cmd: str) -> str:
    """Replace credential values in a queued acme.sh command with
    `***REDACTED***` for audit-log + UI display. Operators see the
    structure of the command but not the secret material."""
    if 'export ' not in cmd:
        return cmd
    out = cmd
    for provider, fields in ACME_DNS_CREDENTIAL_FIELDS.items():
        for f in fields:
            name = f['name']
            # Match: NAME='anything-up-to-trailing-quote'
            out = re.sub(
                rf"({re.escape(name)})='[^']*'",
                r"\1='***REDACTED***'",
                out,
            )
    return out


def _ingest_acme_state(dev_id, acme):
    """Persist the latest per-device acme.sh scan. acme is whatever the
    agent reported under payload['acme']."""
    if not _validate_id(dev_id):
        return
    # Bound — don't trust unbounded lists from the agent
    if not isinstance(acme, dict):
        return
    certs = acme.get('certs') or []
    if not isinstance(certs, list):
        certs = []
    safe_certs = []
    for c in certs[:200]:  # hard cap
        if not isinstance(c, dict):
            continue
        domain = _sanitize_str(str(c.get('domain', '')), 253)
        if not domain:
            continue
        alt_raw = c.get('alt_names') or []
        if not isinstance(alt_raw, list):
            alt_raw = []
        alt_names = [_sanitize_str(str(a), 253) for a in alt_raw[:50] if a]
        safe_certs.append({
            'domain':             domain,
            'alt_names':          alt_names,
            'is_wildcard':        bool(c.get('is_wildcard')),
            'challenge':          _sanitize_str(str(c.get('challenge', '')), 64),
            'is_dns_challenge':   bool(c.get('is_dns_challenge')),
            'dns_provider':       _sanitize_str(str(c.get('dns_provider', '')), 64),
            'dns_provider_label': _sanitize_str(str(c.get('dns_provider_label', '')), 128),
            'key_length':         _sanitize_str(str(c.get('key_length', '')), 16),
            'created_ts':         int(c['created_ts']) if isinstance(c.get('created_ts'), int) else None,
            'next_renew_ts':      int(c['next_renew_ts']) if isinstance(c.get('next_renew_ts'), int) else None,
            'created_str':        _sanitize_str(str(c.get('created_str', '')), 64),
            'next_renew_str':     _sanitize_str(str(c.get('next_renew_str', '')), 64),
            'reload_cmd':         _sanitize_str(str(c.get('reload_cmd', '')), 512),
            'cert_path':          _sanitize_str(str(c.get('cert_path', '')), 512),
            'key_path':           _sanitize_str(str(c.get('key_path', '')), 512),
            'fullchain_path':     _sanitize_str(str(c.get('fullchain_path', '')), 512),
        })
    record = {
        'available': bool(acme.get('available')),
        'home':      _sanitize_str(str(acme.get('home', '')), 256),
        'version':   _sanitize_str(str(acme.get('version', '')), 32),
        'updated_at': int(time.time()),
        'certs':     safe_certs,
    }
    # v5.6.x perf: single-row entity write (store is ENTITY-promoted; the
    # old non-dict guard rebound the yielded name and never persisted anyway).
    _entity_write_one(ACME_STATE_FILE, dev_id, record)


def _acme_log_path(dev_id, action_id):
    """File path for captured acme.sh stdout. action_id is the queued cmd id."""
    safe_did = re.sub(r'[^a-zA-Z0-9_-]', '_', str(dev_id))[:64]
    safe_act = re.sub(r'[^a-zA-Z0-9_-]', '_', str(action_id))[:64]
    return ACME_LOGS_DIR / f'{safe_did}__{safe_act}.log'


def _acme_validate_domain(domain):
    """Strict-ish domain validation. Allows wildcards via '*.example.com'."""
    if not isinstance(domain, str) or not domain or len(domain) > 253:
        return False
    # Wildcard: only as the leftmost label
    if domain.startswith('*.'):
        domain = domain[2:]
    # Standard FQDN regex: labels are 1-63 chars of [A-Za-z0-9-], no leading
    # or trailing hyphen. At least one dot.
    return bool(re.match(
        r'^(?=.{1,253}$)(?:[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?\.)+'
        r'[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?$',
        domain
    ))


def handle_acme_list():
    """GET /api/acme — fleet-wide cert overview, joined with device names."""
    require_auth()
    store   = load(ACME_STATE_FILE) or {}
    devices = load(DEVICES_FILE)    or {}
    now     = int(time.time())
    out = []
    for dev_id, dev in devices.items():
        rec = store.get(dev_id)
        if not rec:
            continue
        out.append({
            'device_id':   dev_id,
            'device_name': dev.get('name', dev_id),
            'available':   bool(rec.get('available')),
            'home':        rec.get('home', ''),
            'version':     rec.get('version', ''),
            'updated_at':  rec.get('updated_at', 0),
            'stale':       (now - (rec.get('updated_at') or 0)) > 4 * 3600,
            'cert_count':  len(rec.get('certs') or []),
            'certs':       rec.get('certs') or [],
        })
    out.sort(key=lambda r: r['device_name'].lower())
    respond(200, {'devices': out, 'providers': ACME_DNS_PROVIDERS})


def handle_acme_dns_credentials_get():
    """GET /api/acme/dns-credentials — list providers with credential
    metadata + which fields are currently set (boolean only, never
    the secret value).

    v3.3.0: centrally-managed DNS-01 credentials so the operator
    doesn't have to ssh into each device and edit
    ~/.acme.sh/account.conf.
    """
    require_admin_auth()
    cfg = load(CONFIG_FILE) or {}
    saved = cfg.get('acme_dns_credentials') or {}
    out = []
    for pkey, plabel in ACME_DNS_PROVIDERS.items():
        fields = ACME_DNS_CREDENTIAL_FIELDS.get(pkey)
        if not fields:
            continue
        provider_saved = saved.get(pkey) or {}
        ui_fields = []
        for f in fields:
            ui_fields.append({
                'name':     f['name'],
                'label':    f['label'],
                'required': bool(f.get('required')),
                'secret':   bool(f.get('secret')),
                'hint':     f.get('hint', ''),
                'set':      bool(provider_saved.get(f['name'])),
            })
        out.append({
            'provider': pkey,
            'label':    plabel,
            'fields':   ui_fields,
        })
    respond(200, {'providers': out})


def handle_acme_dns_credentials_set():
    """POST /api/acme/dns-credentials — save credentials for a single
    provider. Empty/missing string for a field means "leave
    unchanged" (so the UI can render masked placeholders without
    forcing re-entry on every save).

    Body: {provider: "dns_cf", credentials: {CF_Token: "...", ...}}.
    Sending an explicit null value clears the field.
    """
    actor = require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'})
    body = get_json_obj()
    provider = str(body.get('provider', '')).strip()
    if provider not in ACME_DNS_CREDENTIAL_FIELDS:
        respond(400, {'error': f'unknown provider {provider!r}'})
    new_creds = body.get('credentials') or {}
    if not isinstance(new_creds, dict):
        respond(400, {'error': 'credentials must be an object'})
    allowed_fields = {f['name']: f for f in ACME_DNS_CREDENTIAL_FIELDS[provider]}
    changed = []
    with _LockedUpdate(CONFIG_FILE) as cfg:
        store = cfg.setdefault('acme_dns_credentials', {})
        provider_store = store.setdefault(provider, {})
        for fname, val in new_creds.items():
            if fname not in allowed_fields:
                continue  # silently drop unknown keys
            if val is None:
                if fname in provider_store:
                    del provider_store[fname]
                    changed.append(fname)
                continue
            sval = _sanitize_str(str(val), 1024, allow_empty=True).strip()
            if not sval:
                continue  # blank = leave unchanged
            provider_store[fname] = sval
            changed.append(fname)
        # Prune the provider entry if all fields ended up empty
        if not provider_store:
            store.pop(provider, None)
    audit_log(actor, 'acme_dns_credentials_set',
              detail=f'provider={provider} fields={",".join(changed) or "(none)"}')
    respond(200, {'ok': True, 'updated_fields': changed})


# ══ v4.9.0: DNS dashboard — read/write DNS records via provider APIs ══════════
# Reuses the ACME DNS-01 credential store (config['acme_dns_credentials']) so a
# single scoped API token drives both cert issuance and this dashboard. Every
# endpoint is admin-only; writes are audit-logged. The provider clients live in
# dns_zones.py; api.py owns the SSRF-safe HTTP client (the same one integrations
# use — allow_loopback=False, no_redirect=True) + credential resolution.

def _dns_vault_key_optional():
    """A verified 32-byte vault key from the X-RP-Vault-Key request header, or
    None when no/invalid header or the vault isn't configured. Never raises —
    the vault is OPTIONAL for DNS: plaintext acme_dns_credentials is the fallback,
    and not every request carries (or needs) a vault key."""
    raw = _env('HTTP_X_RP_VAULT_KEY', '')
    if not raw:
        return None
    meta = _cmdb_get_vault_meta()
    if not cmdb_vault.is_configured(meta):
        return None
    try:
        key = cmdb_vault.parse_key_header(raw)
    except cmdb_vault.VaultError:
        return None
    return key if cmdb_vault.verify_key(key, meta) else None


def _dns_resolve_creds(spec, cfg, vault_key):
    """A provider's effective credentials: the plaintext acme_dns_credentials as
    a base, with any vault-encrypted dns_vault_creds decrypted ON TOP (vault
    wins) when an unlocked key is supplied. Returns (creds_dict, has_vault_blobs)."""
    creds = dict((cfg.get('acme_dns_credentials') or {}).get(spec.acme_provider) or {})
    vstore = (cfg.get('dns_vault_creds') or {}).get(spec.key) or {}
    if vstore and vault_key:
        for field, blob in vstore.items():
            if isinstance(blob, dict) and blob.get('ct'):
                try:
                    creds[field] = cmdb_vault.decrypt(vault_key, blob)
                except cmdb_vault.VaultError:
                    pass   # bad key/blob → fall through to whatever plaintext exists
    return creds, bool(vstore)


def _dns_make_provider(provider_key):
    """Build a live provider client. Credentials come from the plaintext ACME
    store and/or the CMDB vault (decrypted per-request with the X-RP-Vault-Key
    header — never persisted in clear). Short-circuits with 400/401 on unknown
    provider / missing creds / locked vault."""
    spec = dns_zones_mod.PROVIDERS.get(provider_key)
    if not spec:
        respond(400, {'error': f'unknown provider {provider_key!r}'})
    cfg = load(CONFIG_FILE) or {}
    vault_key = _dns_vault_key_optional()
    creds, has_vault = _dns_resolve_creds(spec, cfg, vault_key)
    if not creds:
        if has_vault and not vault_key:
            # 409 (not 401): the generic api() client logs out on 401 — a locked
            # vault is not an auth failure, so the UI must get the body instead.
            respond(409, {'error': f'{spec.label} credentials are stored in the vault — '
                                   f'unlock the vault to use them.',
                          'code': 'vault_locked', 'vault_locked': True})
        respond(400, {'error': f'No API credentials configured for {spec.label}. Set them '
                               f'under ACME → DNS credentials, or store them encrypted in '
                               f'the vault.',
                      'cred_hint': spec.cred_hint, 'acme_provider': spec.acme_provider})
    client = _SSRFIntegrationClient(spec.base_url, verify_tls=True,
                                    timeout=_INTEGRATION_HTTP_TIMEOUT_S)
    return spec(client, creds)


def _dns_target(body):
    """Resolve (provider, zone_id, zone_name) from a write request body."""
    prov = _dns_make_provider(str(body.get('provider', '')).strip())
    zone = str(body.get('zone', '')).strip()
    zone_name = str(body.get('zone_name', '')).strip()
    if not zone:
        respond(400, {'error': 'zone required'})
    return prov, zone, zone_name


def _dns_record_from_body(body):
    """Build + validate a normalised record dict from a write request body."""
    rtype = str(body.get('type', '')).strip().upper()
    if rtype not in dns_zones_mod.RECORD_TYPES:
        respond(400, {'error': f'unsupported record type {rtype!r}'})
    rec = {
        'type': rtype,
        'name': _sanitize_str(str(body.get('name', '')), 253, allow_empty=True).strip(),
        'content': _sanitize_str(str(body.get('content', '')), 8192, allow_empty=True).strip(),
        'ttl': dns_zones_mod._int(body.get('ttl'), 0),
    }
    if not rec['content']:
        respond(400, {'error': 'content required'})
    if body.get('priority') not in (None, ''):
        rec['priority'] = dns_zones_mod._int(body.get('priority'), 0)
    if 'proxied' in body:
        rec['proxied'] = bool(body.get('proxied'))
    return rec


def handle_dns_providers():
    """GET /api/dns/providers — provider catalog + where each provider's
    credentials live (plaintext ACME store and/or the encrypted CMDB vault) +
    the credential fields each provider accepts (for the vault-store form)."""
    require_admin_auth()
    cfg = load(CONFIG_FILE) or {}
    saved = cfg.get('acme_dns_credentials') or {}
    vault = cfg.get('dns_vault_creds') or {}
    out = []
    for p in dns_zones_mod.list_providers():
        fields = ACME_DNS_CREDENTIAL_FIELDS.get(p['acme_provider'], [])
        out.append({**p,
                    'creds_set': bool(saved.get(p['acme_provider'])),
                    'vault_set': bool(vault.get(p['key'])),
                    'cred_fields': [{'name': f['name'], 'label': f['label'],
                                     'secret': bool(f.get('secret'))} for f in fields]})
    # Agent devices — candidates for "Import from agent". List every device with
    # an agent (NOT agentless), regardless of whether the slow acme.sh scan has
    # reported yet (the harvest reads account.conf on demand). Flag which report
    # an acme.sh install + which are online, so the picker can hint.
    acme_state = load(ACME_STATE_FILE) or {}
    devs = load(DEVICES_FILE) or {}
    now = int(time.time())
    agent_devices = [{'id': did,
                      'name': d.get('name', did),
                      'online': (now - int(d.get('last_seen') or 0)) < 600,
                      'acme': bool((acme_state.get(did) or {}).get('available'))}
                     for did, d in devs.items()
                     if isinstance(d, dict) and d.get('group') != 'agentless']
    agent_devices.sort(key=lambda x: x['name'].lower())
    respond(200, {'providers': out,
                  'vault_configured': cmdb_vault.is_configured(_cmdb_get_vault_meta()),
                  'agent_devices': agent_devices})


def handle_dns_vault_creds_set():
    """POST /api/dns/vault-credentials — encrypt + store a provider's DNS API
    credentials in the CMDB vault, so NO plaintext is written to disk. Requires
    an unlocked vault (the X-RP-Vault-Key header). Body
    {provider, credentials:{<field>:<value>,...}}; a blank value leaves a field
    unchanged, an explicit null clears it. Admin-only, audit-logged."""
    actor = require_admin_auth()
    # Don't use _cmdb_require_unlocked here: it responds 401 on a locked vault,
    # and the generic api() client logs the user out on 401. Use 409 for vault
    # state so the UI gets the body and can prompt to unlock.
    meta = _cmdb_get_vault_meta()
    if not cmdb_vault.is_configured(meta):
        respond(409, {'error': 'vault not configured — set up the CMDB vault first',
                      'code': 'vault_not_configured'})
    try:
        key = cmdb_vault.parse_key_header(_env('HTTP_X_RP_VAULT_KEY', ''))
    except cmdb_vault.VaultError:
        respond(409, {'error': 'vault locked — unlock to store credentials',
                      'code': 'vault_locked'})
    if not cmdb_vault.verify_key(key, meta):
        respond(409, {'error': 'invalid vault key — unlock the vault',
                      'code': 'vault_locked'})
    body = get_json_obj()
    if not isinstance(body, dict):
        body = {}
    provider = str(body.get('provider', '')).strip()
    spec = dns_zones_mod.PROVIDERS.get(provider)
    if not spec:
        respond(400, {'error': f'unknown provider {provider!r}'})
    new_creds = body.get('credentials') or {}
    if not isinstance(new_creds, dict):
        respond(400, {'error': 'credentials must be an object'})
    allowed = {f['name'] for f in ACME_DNS_CREDENTIAL_FIELDS.get(spec.acme_provider, [])}
    changed = []
    with _LockedUpdate(CONFIG_FILE) as cfg:
        store = cfg.setdefault('dns_vault_creds', {})
        pstore = store.setdefault(provider, {})
        for fname, val in new_creds.items():
            if fname not in allowed:
                continue  # silently drop unknown keys
            if val is None:
                if fname in pstore:
                    del pstore[fname]; changed.append(fname)
                continue
            sval = _sanitize_str(str(val), 4096, allow_empty=True).strip()
            if not sval:
                continue  # blank = leave unchanged
            # encrypt() is pure crypto (no I/O, no nested lock) — safe in here
            pstore[fname] = cmdb_vault.encrypt(key, sval)
            changed.append(fname)
        if not pstore:
            store.pop(provider, None)
    audit_log(actor, 'dns_vault_credentials_set',
              detail=f'provider={provider} fields={",".join(changed) or "(none)"}')
    respond(200, {'ok': True, 'updated_fields': changed})


def _ingest_dns_creds_harvest(dev_id, harvest):
    """Store the DNS provider credentials an agent harvested from its acme.sh
    account.conf. ``harvest`` = {<ENV_NAME>: <value>} (e.g. {'CF_Token': '…'}).
    Each name is mapped to its provider via ACME_DNS_CREDENTIAL_FIELDS and saved
    into acme_dns_credentials (0600). The per-device pending flag is cleared
    either way (so a harvest that found nothing doesn't loop). Runs POST-lock —
    takes its own CONFIG/device locks. Returns a (provider, field) list for the
    caller's audit log (names only — never the secret values)."""
    field_to_provider = {}
    for prov, fields in ACME_DNS_CREDENTIAL_FIELDS.items():
        for f in fields:
            field_to_provider.setdefault(f['name'], prov)
    stored = []
    with _LockedUpdate(CONFIG_FILE) as cfg:
        if isinstance(harvest, dict) and harvest:
            store = cfg.setdefault('acme_dns_credentials', {})
            for name, val in harvest.items():
                prov = field_to_provider.get(str(name))
                if not prov or val in (None, ''):
                    continue
                sval = _sanitize_str(str(val), 4096, allow_empty=True).strip()
                if not sval:
                    continue
                store.setdefault(prov, {})[str(name)] = sval
                stored.append((prov, str(name)))
        # Transient result marker (provider NAMES only — no secrets) so the UI's
        # import poll can tell "delivered" from "still waiting" and react. Map the
        # ACME provider keys (dns_cf) to the DASHBOARD keys (cloudflare) the vault
        # import + dashboard use — only providers the dashboard supports.
        _acme_to_dash = {p.acme_provider: p.key for p in dns_zones_mod.PROVIDERS.values()}
        cfg.setdefault('dns_harvest_result', {})[dev_id] = {
            'ts': int(time.time()),
            'providers': sorted({_acme_to_dash[p] for p, _ in stored if p in _acme_to_dash}),
        }
    with _DeviceUpdate(dev_id) as devices:
        dev = devices.get(dev_id)
        if isinstance(dev, dict) and dev.pop('dns_harvest_pending', None) is not None:
            devices[dev_id] = dev
    return stored


def handle_dns_import_status():
    """GET /api/dns/import-from-agent/status?device_id=X — poll the one-shot
    harvest. Returns state: 'pending' (still waiting on the agent's next
    check-in), 'ready' (the agent delivered creds into acme_dns_credentials;
    `providers` lists them — the UI then encrypts them into the vault), or
    'empty' (the agent ran but found no DNS credentials). Reading a finished
    result consumes the marker. Admin-only."""
    require_admin_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    dev_id = (qs.get('device_id', [''])[0] or '').strip()
    dev = device_get(dev_id) or {}
    if dev.get('dns_harvest_pending'):
        respond(200, {'state': 'pending'})
    cfg = load(CONFIG_FILE) or {}
    result = (cfg.get('dns_harvest_result') or {}).get(dev_id)
    if not result:
        respond(200, {'state': 'pending'})    # not triggered yet / not delivered
    providers = result.get('providers') or []
    with _LockedUpdate(CONFIG_FILE) as c:      # consume the marker
        marks = c.get('dns_harvest_result')
        if isinstance(marks, dict):
            marks.pop(dev_id, None)
    respond(200, {'state': 'ready' if providers else 'empty', 'providers': providers})


def handle_dns_import_from_agent():
    """POST /api/dns/import-from-agent {device_id} — flag a device to harvest its
    acme.sh DNS credentials (SAVED_* in account.conf) on its next heartbeat and
    import them into acme_dns_credentials. The agent reads the secrets locally
    and returns them over the authenticated heartbeat — never via the
    command-output channel. One-shot, admin-only, audit-logged. From there, use
    'Import from config' to encrypt them into the vault and drop the plaintext."""
    actor = require_admin_auth()
    body = get_json_obj()
    if not isinstance(body, dict):
        body = {}
    dev_id = str(body.get('device_id', '')).strip()
    if not _validate_id(dev_id):
        respond(400, {'error': 'invalid device id'})
    if not device_get(dev_id):
        respond(404, {'error': 'unknown device'})
    with _DeviceUpdate(dev_id) as devices:
        dev = devices.get(dev_id)
        if not isinstance(dev, dict):
            respond(404, {'error': 'unknown device'})
        dev['dns_harvest_pending'] = True
        devices[dev_id] = dev
    audit_log(actor, 'dns_import_from_agent_requested', detail=f'device={dev_id}')
    respond(200, {'ok': True, 'queued': True,
                  'message': 'Queued — the device will report its DNS credentials on its '
                             'next heartbeat. Refresh in a moment.'})


def handle_dns_vault_import():
    """POST /api/dns/vault-credentials/import — encrypt a provider's EXISTING
    plaintext acme_dns_credentials into the vault, no re-typing. Body
    {provider, clear_plaintext?:bool}. With clear_plaintext the plaintext copy is
    removed afterwards so the credentials then exist ONLY encrypted. Requires an
    unlocked vault. Admin-only, audit-logged."""
    actor = require_admin_auth()
    meta = _cmdb_get_vault_meta()
    if not cmdb_vault.is_configured(meta):
        respond(409, {'error': 'vault not configured — set up the CMDB vault first',
                      'code': 'vault_not_configured'})
    try:
        key = cmdb_vault.parse_key_header(_env('HTTP_X_RP_VAULT_KEY', ''))
    except cmdb_vault.VaultError:
        respond(409, {'error': 'vault locked — unlock to import credentials',
                      'code': 'vault_locked'})
    if not cmdb_vault.verify_key(key, meta):
        respond(409, {'error': 'invalid vault key — unlock the vault', 'code': 'vault_locked'})
    body = get_json_obj()
    if not isinstance(body, dict):
        body = {}
    provider = str(body.get('provider', '')).strip()
    spec = dns_zones_mod.PROVIDERS.get(provider)
    if not spec:
        respond(400, {'error': f'unknown provider {provider!r}'})
    clear_plain = bool(body.get('clear_plaintext'))
    imported = []
    with _LockedUpdate(CONFIG_FILE) as cfg:
        plain = (cfg.get('acme_dns_credentials') or {}).get(spec.acme_provider) or {}
        if plain:
            store = cfg.setdefault('dns_vault_creds', {})
            pstore = store.setdefault(provider, {})
            for fname, val in plain.items():
                if val is None or val == '':
                    continue
                pstore[fname] = cmdb_vault.encrypt(key, str(val))
                imported.append(fname)
            if clear_plain:
                cfg['acme_dns_credentials'].pop(spec.acme_provider, None)
    if not imported:
        respond(400, {'error': f'No plaintext ACME credentials to import for {spec.label}. '
                               f'Add them under ACME → DNS credentials first.'})
    audit_log(actor, 'dns_vault_credentials_import',
              detail=f'provider={provider} fields={",".join(imported)} '
                     f'cleared_plaintext={clear_plain}')
    respond(200, {'ok': True, 'imported': imported, 'cleared_plaintext': clear_plain})


def handle_dns_zones():
    """GET /api/dns/zones?provider=cloudflare — list a provider's zones."""
    require_admin_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    prov = _dns_make_provider((qs.get('provider', [''])[0] or '').strip())
    try:
        zones = prov.list_zones()
    except dns_zones_mod.DNSError as e:
        respond(502, {'error': str(e)})
    respond(200, {'zones': zones})


def handle_dns_records():
    """GET /api/dns/records?provider=&zone=&zone_name= — records in one zone."""
    require_admin_auth()
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    prov = _dns_make_provider((qs.get('provider', [''])[0] or '').strip())
    zone = (qs.get('zone', [''])[0] or '').strip()
    zone_name = (qs.get('zone_name', [''])[0] or '').strip()
    if not zone:
        respond(400, {'error': 'zone required'})
    try:
        records = prov.list_records(zone, zone_name)
    except dns_zones_mod.DNSError as e:
        respond(502, {'error': str(e)})
    respond(200, {'records': records, 'zone': zone, 'zone_name': zone_name})


def _dns_resolve_args():
    """Validate the shared name/type query args for the resolve endpoints."""
    qs = urllib.parse.parse_qs(_env('QUERY_STRING', '') or '')
    name = (qs.get('name', [''])[0] or '').strip()
    rtype = (qs.get('type', ['A'])[0] or 'A').strip().upper()
    if not dns_resolve_mod.valid_name(name):
        respond(400, {'error': 'invalid DNS name'})
    if not dns_resolve_mod.valid_type(rtype):
        respond(400, {'error': f'unsupported record type {rtype!r}',
                      'types': list(dns_resolve_mod.RECORD_TYPES)})
    return qs, name, rtype


def handle_dns_resolve():
    """GET /api/dns/resolve?name=&type= — resolve a name live and show what the
    zone's authoritative nameservers serve vs. what public recursive resolvers
    return (surfaces drift between provider state and reality). Admin-only;
    read-only DNS queries against a fixed resolver allowlist (no user IPs)."""
    require_admin_auth()
    _qs, name, rtype = _dns_resolve_args()
    try:
        authoritative = dns_resolve_mod.resolve_authoritative(name, rtype)
        public = dns_resolve_mod.resolve_public(name, rtype)
    except Exception as e:                       # noqa: BLE001 — never 500 the page
        respond(502, {'error': f'resolution failed: {str(e)[:120]}'})
    respond(200, {'name': name, 'type': rtype,
                  'authoritative': authoritative, 'public': public})


def handle_dns_propagation():
    """GET /api/dns/propagation?name=&type=&expected= — poll public resolvers and
    report how many already serve the expected value ("propagated X/N"), e.g.
    right after editing a record. Admin-only; fixed resolver allowlist."""
    require_admin_auth()
    qs, name, rtype = _dns_resolve_args()
    expected = (qs.get('expected', [''])[0] or '').strip()[:512] or None
    try:
        result = dns_resolve_mod.propagation(name, rtype, expected)
    except Exception as e:                       # noqa: BLE001
        respond(502, {'error': f'propagation check failed: {str(e)[:120]}'})
    respond(200, {'name': name, 'type': rtype, 'expected': expected, **result})


def handle_dns_record_create():
    """POST /api/dns/records — create a record. Admin-only, audit-logged."""
    actor = require_admin_auth()
    body = get_json_obj()
    if not isinstance(body, dict):
        body = {}
    prov, zone, zone_name = _dns_target(body)
    rec = _dns_record_from_body(body)
    try:
        prov.create_record(zone, zone_name, rec)
    except dns_zones_mod.DNSError as e:
        respond(502, {'error': str(e)})
    audit_log(actor, 'dns_record_create',
              detail=f'provider={body.get("provider")} zone={zone_name or zone} '
                     f'{rec["type"]} {rec["name"]}')
    respond(200, {'ok': True})


def handle_dns_record_update():
    """POST /api/dns/records/update — edit a record. Admin-only, audit-logged."""
    actor = require_admin_auth()
    body = get_json_obj()
    if not isinstance(body, dict):
        body = {}
    prov, zone, zone_name = _dns_target(body)
    rec_id = str(body.get('id', '')).strip()
    if not rec_id:
        respond(400, {'error': 'record id required'})
    rec = _dns_record_from_body(body)
    try:
        prov.update_record(zone, zone_name, rec_id, rec)
    except dns_zones_mod.DNSError as e:
        respond(502, {'error': str(e)})
    audit_log(actor, 'dns_record_update',
              detail=f'provider={body.get("provider")} zone={zone_name or zone} '
                     f'{rec["type"]} {rec["name"]} id={rec_id}')
    respond(200, {'ok': True})


def handle_dns_record_delete():
    """POST /api/dns/records/delete — delete a record. Admin-only, audit-logged."""
    actor = require_admin_auth()
    body = get_json_obj()
    if not isinstance(body, dict):
        body = {}
    prov, zone, zone_name = _dns_target(body)
    rec_id = str(body.get('id', '')).strip()
    if not rec_id:
        respond(400, {'error': 'record id required'})
    rtype = str(body.get('type', '')).strip().upper()
    name = str(body.get('name', '')).strip()
    try:
        prov.delete_record(zone, zone_name, rec_id, name=name, rtype=rtype)
    except dns_zones_mod.DNSError as e:
        respond(502, {'error': str(e)})
    audit_log(actor, 'dns_record_delete',
              detail=f'provider={body.get("provider")} zone={zone_name or zone} '
                     f'{rtype} {name} id={rec_id}')
    respond(200, {'ok': True})


def handle_acme_detail(dev_id, domain):
    """GET /api/acme/<dev_id>/<domain> — single-cert detail + recent log files."""
    require_auth()
    _scope_block_device(dev_id)   # v3.5.0 RBAC v2
    if not _validate_id(dev_id):
        respond(404, {'error': 'invalid device id'}); return
    if not _acme_validate_domain(domain):
        respond(400, {'error': 'invalid domain'}); return
    store = load(ACME_STATE_FILE) or {}
    rec = store.get(dev_id)
    if not rec:
        respond(404, {'error': 'no acme state reported for device'}); return
    cert = next((c for c in (rec.get('certs') or []) if c.get('domain') == domain), None)
    if not cert:
        respond(404, {'error': 'cert not found in last scan'}); return
    # Walk ACME_LOGS_DIR for matching action logs (most-recent first, last 10)
    logs = []
    try:
        if ACME_LOGS_DIR.is_dir():
            safe_did = re.sub(r'[^a-zA-Z0-9_-]', '_', dev_id)[:64]
            for f in sorted(ACME_LOGS_DIR.iterdir(), key=lambda p: p.stat().st_mtime, reverse=True):
                # v3.0.1: only .log files are real action logs. Each has a
                # .meta.json sibling; without this filter the sidecar files
                # showed up as bogus "actions" named <id>.meta with NaN size,
                # and "View log" 404'd because no <id>.meta.log exists.
                if f.suffix != '.log':
                    continue
                if not f.name.startswith(f'{safe_did}__'):
                    continue
                try:
                    meta_path = f.with_suffix('.meta.json')
                    meta = json.loads(meta_path.read_text()) if meta_path.exists() else {}
                except Exception:
                    meta = {}
                if meta.get('domain') and meta.get('domain') != domain:
                    continue
                logs.append({
                    'id':       f.stem.split('__', 1)[-1] if '__' in f.stem else f.stem,
                    'ts':       int(meta.get('queued_at') or f.stat().st_mtime),
                    'action':   meta.get('action', ''),
                    'rc':       meta.get('rc'),
                    'size':     f.stat().st_size,
                })
                if len(logs) >= 10:
                    break
    except Exception:
        pass
    respond(200, {'cert': cert, 'logs': logs})


def handle_acme_log(dev_id, action_id):
    """GET /api/acme/<dev_id>/log/<action_id> — full captured stdout for one action."""
    require_auth()
    # Per-device read NOT under /api/devices/, so the dispatch guard
    # (_enforce_device_scope) doesn't cover it — block out-of-scope roles here.
    _scope_block_device(dev_id)
    if not _validate_id(dev_id):
        respond(404, {'error': 'invalid device id'}); return
    log_path = _acme_log_path(dev_id, action_id)
    if not log_path.is_file():
        respond(404, {'error': 'log not found'}); return
    try:
        # Cap at 256 KB just in case
        text = log_path.read_text(errors='replace')[:256 * 1024]
    except Exception as e:
        respond(500, {'error': f'failed to read log: {e}'}); return
    respond(200, {'content': text, 'size': log_path.stat().st_size})


def _acme_queue_command(dev_id, action, domain, cmd_str):
    """Queue an exec: command on the device, and stash a meta-file so the
    response handler can write the output into the right log slot."""
    actor = require_admin_auth()
    devices = load(DEVICES_FILE) or {}
    if dev_id not in devices:
        respond(404, {'error': 'device not found'}); return None
    action_id = secrets.token_hex(6)
    # Reserve the log file so it shows up in the detail view immediately
    try:
        ACME_LOGS_DIR.mkdir(parents=True, exist_ok=True)
    except Exception:
        pass
    log_path = _acme_log_path(dev_id, action_id)
    try:
        log_path.write_text('# pending — awaiting agent\n')
        meta_path = log_path.with_suffix('.meta.json')
        meta_path.write_text(json.dumps({
            'action':   action,
            'domain':   domain,
            'queued_at': int(time.time()),
            'actor':    actor,
        }))
    except Exception:
        pass
    # Queue the exec — output comes back through the standard command-output
    # ingestion path and gets re-pointed at the acme log in v3.0.1 (handled
    # in handle_command_output below).
    with _LockedUpdate(CMDS_FILE) as cmds:
        pending = cmds.get(dev_id) or []
        # Tag the command so we can detect its output and route it
        tagged = f'exec:#acme:{action_id}#{cmd_str}'
        pending.append(tagged)
        cmds[dev_id] = pending
    # v3.9.0: record it in the command history so it shows in the Command
    # Queue's "recently dispatched" log like every other queued command —
    # previously ACME actions waited in the queue invisibly.
    log_command(actor, dev_id, devices[dev_id].get('name', dev_id),
                f'acme: {action} {domain}')
    audit_log(actor, f'acme_{action}',
              detail=f'device={dev_id} domain={domain} action_id={action_id}')
    return {'ok': True, 'action_id': action_id}


def handle_acme_force_renew(dev_id, domain):
    """POST /api/acme/<dev_id>/<domain>/renew — queue acme.sh --renew --force."""
    require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'}); return
    if not _validate_id(dev_id) or not _acme_validate_domain(domain):
        respond(400, {'error': 'invalid device or domain'}); return
    store = load(ACME_STATE_FILE) or {}
    rec = store.get(dev_id) or {}
    home = rec.get('home') or '/root/.acme.sh'
    # Shell-escape domain via single quotes; domain is already validated against
    # a strict regex so this is paranoia, not the security boundary.
    safe_domain = domain.replace("'", "'\\''")
    # v4.4.0 (SECURITY): shlex.quote the agent-reported `home` path too — it was
    # interpolated raw inside the quotes, so a rogue/compromised agent could set
    # `home` to break out of the acme.sh invocation.
    acme_bin = shlex.quote(f'{home}/acme.sh')
    cmd = f"{acme_bin} --renew --force -d '{safe_domain}'"
    result = _acme_queue_command(dev_id, 'renew', domain, cmd)
    if result:
        respond(200, result)


def handle_acme_revoke(dev_id, domain):
    """POST /api/acme/<dev_id>/<domain>/revoke — queue acme.sh --revoke + --remove."""
    require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'}); return
    if not _validate_id(dev_id) or not _acme_validate_domain(domain):
        respond(400, {'error': 'invalid device or domain'}); return
    store = load(ACME_STATE_FILE) or {}
    rec = store.get(dev_id) or {}
    home = rec.get('home') or '/root/.acme.sh'
    safe_domain = domain.replace("'", "'\\''")
    acme_bin = shlex.quote(f'{home}/acme.sh')   # v4.4.0: quote agent-reported home
    # v4.10.0: acme.sh stores EC/ECC certs under <domain>_ecc/. Without --ecc,
    # --revoke/--remove look in the RSA dir, can't find the key, and fail with
    # "Only RSA or EC key is supported. keyfile=…/". Mirror the key type the last
    # scan recorded (Le_Keylength like 'ec-256'/'ec-384' → --ecc).
    cert = next((c for c in (rec.get('certs') or []) if c.get('domain') == domain), None)
    ecc = ' --ecc' if cert and str(cert.get('key_length', '')).startswith('ec-') else ''
    # --revoke tells LE the cert is no longer trusted; --remove drops the
    # local files so the next scan reflects the change.
    cmd = (f"{acme_bin} --revoke{ecc} -d '{safe_domain}' && "
           f"{acme_bin} --remove{ecc} -d '{safe_domain}'")
    result = _acme_queue_command(dev_id, 'revoke', domain, cmd)
    if result:
        respond(200, result)


def handle_acme_cancel(dev_id, action_id):
    """POST /api/acme/<dev_id>/cancel/<action_id>

    Three cases:
      1. Still in CMDS_FILE queue (agent hasn't picked it up yet) → remove
         it from the queue, mark meta as cancelled. Action will never run.
      2. Already running on the agent (sent in a previous heartbeat,
         agent hasn't reported back yet) → we can't unkill; mark meta as
         cancelled-after-dispatch so UI stops polling and shows the state.
      3. Already completed (meta has rc) → already not pending; return 409.
    """
    require_admin_auth()
    if not _validate_id(dev_id):
        respond(404, {'error': 'invalid device id'}); return
    if not re.match(r'^[a-zA-Z0-9_-]{1,64}$', action_id or ''):
        respond(400, {'error': 'invalid action id'}); return
    log_path = _acme_log_path(dev_id, action_id)
    meta_path = log_path.with_suffix('.meta.json')
    if not meta_path.exists():
        respond(404, {'error': 'action not found'}); return
    try:
        meta = json.loads(meta_path.read_text())
    except Exception as e:
        respond(500, {'error': f'meta read failed: {e}'}); return
    if meta.get('rc') is not None:
        respond(409, {'error': 'action already completed', 'rc': meta.get('rc')}); return
    # Try to find and remove from the pending command queue
    tag_needle = f'#acme:{action_id}#'
    removed_from_queue = False
    with _LockedUpdate(CMDS_FILE) as cmds:
        queue = cmds.get(dev_id) or []
        kept = [c for c in queue if tag_needle not in c]
        if len(kept) != len(queue):
            removed_from_queue = True
            if kept:
                cmds[dev_id] = kept
            else:
                cmds.pop(dev_id, None)
    # Mark meta as cancelled regardless. UI distinguishes via rc value:
    #   -3 = cancelled before dispatch (queue removal succeeded)
    #   -4 = cancelled after dispatch (queue removal failed, agent may
    #        still complete; if it does, the rc gets overwritten on
    #        next ingestion)
    now = int(time.time())
    actor = current_username() or 'unknown'
    meta['rc']            = -3 if removed_from_queue else -4
    meta['done_at']       = now
    meta['cancelled_at']  = now
    meta['cancelled_by']  = actor
    try:
        meta_path.write_text(json.dumps(meta))
        # Replace the placeholder log so the UI shows the cancellation
        # in the log viewer rather than an empty file.
        log_path.write_text(
            f'(Cancelled by {actor} at {time.strftime("%Y-%m-%d %H:%M:%S", time.localtime(now))}.\n'
            f' {"Removed from queue before dispatch." if removed_from_queue else "Already sent to agent — dispatch cannot be undone, but UI will stop polling."})\n')
    except Exception as e:
        respond(500, {'error': f'meta write failed: {e}'}); return
    audit_log(actor, 'acme_cancel',
              f'action={action_id} domain={meta.get("domain","?")} '
              f'queue_removed={removed_from_queue}')
    respond(200, {
        'ok':                True,
        'removed_from_queue': removed_from_queue,
        'rc':                meta['rc'],
    })


def handle_acme_ignore(dev_id, action_id):
    """POST /api/acme/<dev_id>/ignore/<action_id>

    Permanently remove the action's log + meta from disk. Used to clean up
    stuck-pending entries that can't be cancelled (queue already empty but
    agent never reported — happens if agent crashed mid-dispatch). Unlike
    cancel, this doesn't try to manage the queue cleanly — it just makes
    the row disappear from the UI.

    Admin-only, like every other ACME mutation (cancel / force-renew /
    revoke): this destroys on-disk action state + edits the command queue, so
    a read-only role (viewer / mcp / auditor / finance — all admitted by a bare
    require_auth) must NOT reach it. The audit log records what was removed.
    """
    require_admin_auth()
    if not _validate_id(dev_id):
        respond(404, {'error': 'invalid device id'}); return
    # v5.0.1 (SECURITY): this route isn't under /api/devices/, so the global
    # device-scope chokepoint doesn't cover it. Block cross-scope deletes the
    # same way the acme detail/log read siblings do (was an IDOR).
    _scope_block_device(dev_id)
    if not re.match(r'^[a-zA-Z0-9_-]{1,64}$', action_id or ''):
        respond(400, {'error': 'invalid action id'}); return
    log_path = _acme_log_path(dev_id, action_id)
    meta_path = log_path.with_suffix('.meta.json')
    if not log_path.exists() and not meta_path.exists():
        respond(404, {'error': 'action not found'}); return
    # Snapshot for audit before delete
    domain = action = '?'
    try:
        if meta_path.exists():
            meta = json.loads(meta_path.read_text())
            domain = meta.get('domain', '?')
            action = meta.get('action', '?')
    except Exception:
        pass
    # Also defensively remove from queue if still there
    tag_needle = f'#acme:{action_id}#'
    try:
        with _LockedUpdate(CMDS_FILE) as cmds:
            queue = cmds.get(dev_id) or []
            kept = [c for c in queue if tag_needle not in c]
            if len(kept) != len(queue):
                if kept: cmds[dev_id] = kept
                else: cmds.pop(dev_id, None)
    except Exception:
        pass
    # Delete files
    for p in (log_path, meta_path):
        try:
            if p.exists(): p.unlink()
        except Exception as e:
            sys.stderr.write(f"[remotepower] acme_ignore: failed to unlink {p}: {e}\n")
    actor = current_username() or 'unknown'
    audit_log(actor, 'acme_ignore',
              f'action={action_id} domain={domain} kind={action}')
    respond(200, {'ok': True})


def handle_acme_issue(dev_id):
    """POST /api/acme/<dev_id>/issue — issue a new cert. Body:
       {domain, alt_names?, dns_provider, key_length?, wildcard?}.
       Wildcard is implicit when domain or alt_name starts with '*.'."""
    require_admin_auth()
    if method() != 'POST':
        respond(405, {'error': 'Method not allowed'}); return
    if not _validate_id(dev_id):
        respond(400, {'error': 'invalid device id'}); return
    body = get_json_obj()
    domain = (body.get('domain') or '').strip().lower()
    if not _acme_validate_domain(domain):
        respond(400, {'error': 'invalid primary domain'}); return
    alt_names_raw = body.get('alt_names') or []
    if not isinstance(alt_names_raw, list):
        respond(400, {'error': 'alt_names must be a list'}); return
    alt_names = []
    for a in alt_names_raw[:20]:
        a = (a or '').strip().lower()
        if not _acme_validate_domain(a):
            respond(400, {'error': f'invalid alt name: {a}'}); return
        if a != domain and a not in alt_names:
            alt_names.append(a)
    dns_provider = (body.get('dns_provider') or '').strip()
    if dns_provider not in ACME_DNS_PROVIDERS:
        respond(400, {'error': f'unknown dns provider {dns_provider!r}'}); return
    key_length = str(body.get('key_length') or '4096').strip()
    if key_length not in ('2048', '3072', '4096', 'ec-256', 'ec-384'):
        respond(400, {'error': 'invalid key_length'}); return
    store = load(ACME_STATE_FILE) or {}
    rec = store.get(dev_id) or {}
    home = rec.get('home') or '/root/.acme.sh'
    # Build the acme.sh command. acme.sh accepts multiple -d for SAN.
    d_args = [f"-d '{d}'" for d in [domain, *alt_names]]
    # v3.3.0: inject DNS-provider credentials from the server's central
    # store so the operator doesn't have to edit ~/.acme.sh/account.conf
    # on every device. Empty prefix when no creds are stored — the agent
    # falls back to acme.sh's normal env/config-file lookup.
    cred_prefix = _acme_credential_env_prefix(dns_provider)
    acme_bin = shlex.quote(f'{home}/acme.sh')   # v4.4.0: quote agent-reported home
    cmd = (cred_prefix
           + f"{acme_bin} --issue --dns {dns_provider} "
           + f"{' '.join(d_args)} --keylength {key_length}")
    result = _acme_queue_command(dev_id, 'issue', domain, cmd)
    if result:
        respond(200, result)


# ── v3.0.1: Mitigation feature ────────────────────────────────────────────
# Each attention 'kind' that supports investigation maps to a hardcoded
# diagnostic command (read-only) and an optional standard-fix command
# (user-confirmed). All commands here are SERVER-DEFINED — no user input
# ever flows into the diagnostic shell. The AI gets to suggest a fix
# command, but it's shown in a preview that requires user confirmation
# before exec, and destructive operations require typing 'RUN'.

MITIGATE_LOGS_DIR = DATA_DIR / 'mitigate_logs'

# Hard denylist for AI-suggested commands. If a fix candidate from the AI
# matches any of these patterns, the run button is disabled — the user
# can still copy the command and run it manually if they really want to.
# This is defense-in-depth, NOT a sandbox: the operator is the final guard.
_MITIGATE_DENY_PATTERNS = (
    # rm -rf / followed by space, end-of-string, or *. `\b` after `/` doesn't
    # work because `/` is not a word character. We anchor to (?:\s|$|\*).
    r'\brm\s+-[rRf]+\s+/(?:\s|$|\*)',
    r'\bdd\s+.*of=/dev/(?:sd|nvme|xvd|vd|hd)', # writing to block devices
    r'\bmkfs\b',                        # filesystem create
    r'\bshred\s+/dev/',                 # wipe block device
    r':\(\)\s*\{.*:\s*\|\s*:&',         # fork bomb classic
    r'>\s*/dev/(?:sd|nvme|xvd|vd|hd)',  # redirect to block device
    r'\bchmod\s+(?:-R\s+)?(?:000|777)\s+/(?:\s|$)',  # chmod 000/777 /
    r'>\s*/etc/passwd\b',
    r'>\s*/etc/shadow\b',
    r'\bdrop\s+database\b',
)


def _mitigate_is_dangerous(cmd):
    """Return (is_dangerous, reason). Checks against the denylist."""
    if not cmd or not isinstance(cmd, str):
        return False, ''
    for pat in _MITIGATE_DENY_PATTERNS:
        try:
            if re.search(pat, cmd, re.IGNORECASE):
                return True, f'matches denylist pattern: {pat}'
        except re.error:
            continue
    return False, ''


def _mitigate_requires_confirmation(cmd):
    """Return True for commands that should require typing 'RUN' to execute.

    Less strict than the denylist — these are 'probably ok but user should
    look twice' operations: reboot, kill -9, systemctl stop, etc.
    """
    if not cmd or not isinstance(cmd, str):
        return False
    sensitive = (
        r'\breboot\b', r'\bshutdown\b', r'\bhalt\b', r'\bpoweroff\b',
        r'\bkill\s+-9\b', r'\bpkill\s+-9\b',
        r'\bsystemctl\s+(?:stop|disable|mask)\b',
        r'\biptables\s+-[FX]\b', r'\bnft\s+flush\b',
        r'\buserdel\b', r'\bgroupdel\b',
        r'\bapt-get\s+(?:purge|remove)\s+',
        r'\bdnf\s+(?:remove|erase)\s+',
        r'\bpacman\s+-R[^\s]*\s+',
        # Anything that pipes to sh or bash from a network source — very common
        # in AI-suggested "quick fix" answers from less-careful models.
        r'\bcurl\s+[^\|]+\|\s*(?:bash|sh)\b',
        r'\bwget\s+[^\|]+\|\s*(?:bash|sh)\b',
    )
    for pat in sensitive:
        try:
            if re.search(pat, cmd, re.IGNORECASE):
                return True
        except re.error:
            continue
    return False


# Playbook table. Each entry maps an attention kind to:
#   diagnostic: shell command, RUN BY THE AGENT. Server-defined, never
#               substituted with user input. Read-only by convention —
#               nothing here mutates state.
#   fix:       optional standard fix command (server-defined). If present,
#               shown as a pre-approved button next to the AI suggestion.
#   target_arg: how to interpolate per-alert detail (e.g. service name)
#               into the command. Hard-coded keys only, never raw user input.
#   ai_prompt_key: the system prompt key to use for AI analysis.
#   ai_default:    whether AI analysis runs automatically after diagnostic.
